CREATE OR REPLACE FUNCTION public.add_phase_gate(p_workflow_type workflow_type_enum, p_phase_name text, p_gate_name text, p_kind gate_kind_enum, p_eval_order integer DEFAULT 100)
 RETURNS phase_gate_assignments
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_row public.phase_gate_assignments;
BEGIN
  IF p_workflow_type IS NULL OR p_phase_name IS NULL OR p_gate_name IS NULL OR p_kind IS NULL THEN
    RAISE EXCEPTION 'add_phase_gate: all of workflow_type, phase_name, gate_name, kind required' USING ERRCODE='22000';
  END IF;

  INSERT INTO public.phase_gate_assignments (workflow_type, phase_name, gate_name, kind, eval_order)
  VALUES (p_workflow_type, p_phase_name, p_gate_name, p_kind, COALESCE(p_eval_order, 100))
  ON CONFLICT (workflow_type, phase_name, gate_name, kind) DO UPDATE SET
    eval_order = EXCLUDED.eval_order
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.list_phase_gates(p_workflow_type workflow_type_enum, p_phase_name text, p_kind gate_kind_enum)
 RETURNS TABLE(gate_name text, version text, description text, eval_order integer)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT gr.gate_name, gr.version, gr.description, pga.eval_order
    FROM public.phase_gate_assignments pga
    JOIN public.gate_registry gr ON gr.gate_name = pga.gate_name
   WHERE pga.workflow_type = p_workflow_type
     AND pga.phase_name    = p_phase_name
     AND pga.kind          = p_kind
   ORDER BY pga.eval_order, gr.gate_name;
$function$
;

CREATE OR REPLACE FUNCTION public.record_gate_decision(p_phase_state_id uuid, p_gate_name text, p_decision gate_decision_enum, p_reason text DEFAULT NULL::text, p_severity gate_hold_severity_enum DEFAULT NULL::gate_hold_severity_enum, p_side_phase text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_ctx     RECORD;
  v_audit   audit.audit_events;
  v_action  text;
  v_updated boolean := false;
  v_payload jsonb;
BEGIN
  IF p_phase_state_id IS NULL OR p_gate_name IS NULL OR p_decision IS NULL THEN
    RAISE EXCEPTION 'record_gate_decision: phase_state_id, gate_name, decision required' USING ERRCODE='22000';
  END IF;
  IF p_decision IN ('HOLD','ROUTE_TO_SIDE_PHASE') AND (p_reason IS NULL OR length(btrim(p_reason)) = 0) THEN
    RAISE EXCEPTION 'record_gate_decision: % requires non-empty reason', p_decision USING ERRCODE='22000';
  END IF;
  IF p_decision = 'ROUTE_TO_SIDE_PHASE' AND (p_side_phase IS NULL OR length(btrim(p_side_phase)) = 0) THEN
    RAISE EXCEPTION 'record_gate_decision: ROUTE_TO_SIDE_PHASE requires side_phase' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_ctx FROM public._resolve_phase_state_context(p_phase_state_id);
  IF v_ctx.run_id IS NULL THEN
    RAISE EXCEPTION 'record_gate_decision: phase_state_id % not found', p_phase_state_id USING ERRCODE='P0002';
  END IF;

  IF p_decision = 'ADVANCE' THEN
    v_action  := 'WORKFLOW_GATE_PASSED';
  ELSIF p_decision = 'HOLD' THEN
    v_action  := 'WORKFLOW_GATE_HOLD';
    UPDATE public.workflow_phase_states
       SET gate_decision = 'HOLD'::public.gate_decision_enum,
           updated_at    = clock_timestamp()
     WHERE id = p_phase_state_id;
    v_updated := true;
  ELSIF p_decision = 'ROUTE_TO_SIDE_PHASE' THEN
    v_action  := 'WORKFLOW_GATE_ROUTED_TO_SIDE_PHASE';
    UPDATE public.workflow_phase_states
       SET gate_decision = 'ROUTE_TO_SIDE_PHASE'::public.gate_decision_enum,
           updated_at    = clock_timestamp()
     WHERE id = p_phase_state_id;
    v_updated := true;
  END IF;

  v_payload := jsonb_build_object(
    'phase_state_id', p_phase_state_id,
    'gate_name',      p_gate_name,
    'decision',       p_decision::text,
    'reason',         p_reason,
    'severity',       p_severity::text,
    'side_phase',     p_side_phase,
    'context',        p_context
  );

  v_audit := audit.emit_audit(
    p_actor_kind     => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
    p_action         => v_action,
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_ctx.run_id,
    p_business_id    => v_ctx.business_id,
    p_organization_id=> v_ctx.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_actor_system   => CASE WHEN p_actor_user_id IS NULL THEN 'workflow_engine' ELSE NULL END,
    p_reason         => format('gate %s → %s', p_gate_name, p_decision),
    p_after_state    => v_payload
  );

  RETURN jsonb_build_object(
    'audit_event_id',       v_audit.event_id,
    'phase_state_updated',  v_updated,
    'decision',             p_decision::text
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_gate_threw(p_phase_state_id uuid, p_gate_name text, p_exception_message text, p_exception_detail jsonb DEFAULT NULL::jsonb, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_ctx   RECORD;
  v_audit audit.audit_events;
BEGIN
  IF p_phase_state_id IS NULL OR p_gate_name IS NULL OR p_exception_message IS NULL THEN
    RAISE EXCEPTION 'record_gate_threw: phase_state_id, gate_name, exception_message required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_ctx FROM public._resolve_phase_state_context(p_phase_state_id);
  IF v_ctx.run_id IS NULL THEN
    RAISE EXCEPTION 'record_gate_threw: phase_state_id % not found', p_phase_state_id USING ERRCODE='P0002';
  END IF;

  UPDATE public.workflow_phase_states
     SET gate_decision = 'HOLD'::public.gate_decision_enum,
         updated_at    = clock_timestamp()
   WHERE id = p_phase_state_id;

  v_audit := audit.emit_audit(
    p_actor_kind     => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
    p_action         => 'WORKFLOW_GATE_THREW',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_ctx.run_id,
    p_business_id    => v_ctx.business_id,
    p_organization_id=> v_ctx.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_actor_system   => CASE WHEN p_actor_user_id IS NULL THEN 'workflow_engine' ELSE NULL END,
    p_reason         => format('gate %s threw: %s', p_gate_name, p_exception_message),
    p_after_state    => jsonb_build_object(
      'phase_state_id',    p_phase_state_id,
      'gate_name',         p_gate_name,
      'decision',          'HOLD',
      'severity',          'BLOCKING',
      'exception_message', p_exception_message,
      'exception_detail',  p_exception_detail
    )
  );

  RETURN jsonb_build_object(
    'audit_event_id',      v_audit.event_id,
    'phase_state_updated', true,
    'decision',            'HOLD'
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.hold_phase(p_phase_state_id uuid, p_reason text, p_severity gate_hold_severity_enum DEFAULT 'BLOCKING'::gate_hold_severity_enum)
 RETURNS workflow_phase_states
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_state public.workflow_phase_states;
  v_run   public.workflow_runs;
BEGIN
  IF p_phase_state_id IS NULL OR p_reason IS NULL OR length(btrim(p_reason))=0 THEN
    RAISE EXCEPTION 'hold_phase: phase_state_id and reason required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_state FROM public.workflow_phase_states WHERE id = p_phase_state_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'hold_phase: phase_state % not found', p_phase_state_id USING ERRCODE='P0002'; END IF;
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = v_state.workflow_run_id FOR UPDATE;
  UPDATE public.workflow_phase_states
     SET status     = 'HOLDING'::public.phase_state_status_enum,
         updated_at = clock_timestamp()
   WHERE id = p_phase_state_id
   RETURNING * INTO v_state;
  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_PHASE_HOLDING',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('phase %s holding: %s', v_state.phase_name, p_reason),
    p_after_state    => jsonb_build_object(
      'run_id', v_run.id, 'phase_state_id', v_state.id,
      'phase_name', v_state.phase_name, 'reason', p_reason, 'severity', p_severity::text
    )
  );
  RETURN v_state;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_phase(p_phase_state_id uuid)
 RETURNS workflow_phase_states
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_state public.workflow_phase_states;
  v_run   public.workflow_runs;
BEGIN
  IF p_phase_state_id IS NULL THEN RAISE EXCEPTION 'complete_phase: phase_state_id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_state FROM public.workflow_phase_states WHERE id = p_phase_state_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'complete_phase: phase_state % not found', p_phase_state_id USING ERRCODE='P0002'; END IF;
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = v_state.workflow_run_id FOR UPDATE;
  IF v_state.status <> 'RUNNING' THEN
    RAISE EXCEPTION 'complete_phase: phase % is in status % (not RUNNING)', v_state.phase_name, v_state.status USING ERRCODE='P0001';
  END IF;
  UPDATE public.workflow_phase_states
     SET status = 'COMPLETED'::public.phase_state_status_enum,
         completed_at = clock_timestamp(),
         updated_at   = clock_timestamp()
   WHERE id = p_phase_state_id
   RETURNING * INTO v_state;
  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_PHASE_COMPLETED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('phase %s completed', v_state.phase_name),
    p_after_state    => jsonb_build_object(
      'run_id', v_run.id, 'phase_state_id', v_state.id,
      'phase_name', v_state.phase_name, 'completed_at', v_state.completed_at
    )
  );
  RETURN v_state;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.route_phase(p_phase_state_id uuid, p_side_phase_name text, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_orig       public.workflow_phase_states;
  v_side       public.workflow_phase_states;
  v_run        public.workflow_runs;
  v_max_order  integer;
BEGIN
  IF p_phase_state_id IS NULL OR p_side_phase_name IS NULL OR p_reason IS NULL OR length(btrim(p_side_phase_name))=0 OR length(btrim(p_reason))=0 THEN
    RAISE EXCEPTION 'route_phase: phase_state_id, side_phase_name, reason required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_orig FROM public.workflow_phase_states WHERE id = p_phase_state_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'route_phase: phase_state % not found', p_phase_state_id USING ERRCODE='P0002'; END IF;
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = v_orig.workflow_run_id FOR UPDATE;
  UPDATE public.workflow_phase_states
     SET status         = 'HOLDING'::public.phase_state_status_enum,
         gate_decision  = 'ROUTE_TO_SIDE_PHASE'::public.gate_decision_enum,
         updated_at     = clock_timestamp()
   WHERE id = p_phase_state_id
   RETURNING * INTO v_orig;
  SELECT COALESCE(MAX(phase_order), 0) INTO v_max_order
    FROM public.workflow_phase_states WHERE workflow_run_id = v_run.id;
  INSERT INTO public.workflow_phase_states (workflow_run_id, phase_name, phase_order, status)
  VALUES (v_run.id, p_side_phase_name, v_max_order + 1, 'PENDING'::public.phase_state_status_enum)
  RETURNING * INTO v_side;
  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_PHASE_ROUTED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('phase %s routed to side phase %s: %s', v_orig.phase_name, p_side_phase_name, p_reason),
    p_after_state    => jsonb_build_object(
      'run_id',                v_run.id,
      'original_phase_state',  v_orig.id,
      'original_phase_name',   v_orig.phase_name,
      'side_phase_state',      v_side.id,
      'side_phase_name',       p_side_phase_name,
      'reason',                p_reason
    )
  );
  RETURN jsonb_build_object(
    'original_phase_state', to_jsonb(v_orig),
    'side_phase_state',     to_jsonb(v_side)
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_run_progress(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run             public.workflow_runs;
  v_total           integer;
  v_completed       integer;
  v_current_phase   text;
  v_current_status  public.phase_state_status_enum;
  v_last_activity   timestamptz;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'NOT_FOUND', 'run_id', p_run_id);
  END IF;

  SELECT count(*) INTO v_total
    FROM public.workflow_phase_definitions
   WHERE workflow_type = v_run.workflow_type;

  SELECT count(*) INTO v_completed
    FROM public.workflow_phase_states
   WHERE workflow_run_id = p_run_id AND status = 'COMPLETED';

  SELECT phase_name, status INTO v_current_phase, v_current_status
    FROM public.workflow_phase_states
   WHERE workflow_run_id = p_run_id AND status IN ('RUNNING','HOLDING','PENDING')
   ORDER BY phase_order DESC
   LIMIT 1;

  SELECT max(updated_at) INTO v_last_activity
    FROM public.workflow_phase_states
   WHERE workflow_run_id = p_run_id;

  RETURN jsonb_build_object(
    'run_id',                p_run_id,
    'run_status',            v_run.status::text,
    'workflow_type',         v_run.workflow_type::text,
    'current_phase',         v_current_phase,
    'current_phase_status',  v_current_status::text,
    'phases_completed',      COALESCE(v_completed, 0),
    'total_phases',          COALESCE(v_total, 0),
    'blocking_issues_count', 0,  -- placeholder until B14
    'started_at',            v_run.started_at,
    'last_activity_at',      v_last_activity,
    'finalized_at',          v_run.finalized_at,
    'estimated_completion',  NULL  -- placeholder until heuristic sub-doc
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.begin_tool_invocation(p_phase_state_id uuid, p_tool_name text, p_input_hash text, p_dedup_key text, p_external_request_id text DEFAULT NULL::text, p_attempt_number integer DEFAULT 1)
 RETURNS tool_invocations
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_phase public.workflow_phase_states;
  v_inv   public.tool_invocations;
BEGIN
  IF p_phase_state_id IS NULL OR p_tool_name IS NULL THEN
    RAISE EXCEPTION 'begin_tool_invocation: phase_state_id and tool_name required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_phase FROM public.workflow_phase_states WHERE id = p_phase_state_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'begin_tool_invocation: phase_state % not found', p_phase_state_id USING ERRCODE='P0002'; END IF;

  INSERT INTO public.tool_invocations (
    workflow_run_id, phase_state_id, tool_name, attempt_number,
    input_hash, status, dedup_key, external_request_id, started_at
  ) VALUES (
    v_phase.workflow_run_id, p_phase_state_id, p_tool_name, COALESCE(p_attempt_number, 1),
    p_input_hash, 'PENDING'::public.tool_invocation_status_enum, p_dedup_key, p_external_request_id, clock_timestamp()
  )
  RETURNING * INTO v_inv;

  RETURN v_inv;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_tool_invocation(p_phase_state_id uuid, p_tool_name text, p_status tool_invocation_status_enum, p_attempt_number integer DEFAULT 1, p_input_hash text DEFAULT NULL::text, p_output_hash text DEFAULT NULL::text, p_dedup_key text DEFAULT NULL::text, p_external_request_id text DEFAULT NULL::text, p_error_summary text DEFAULT NULL::text, p_started_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_completed_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS tool_invocations
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_phase public.workflow_phase_states;
  v_run   public.workflow_runs;
  v_inv   public.tool_invocations;
BEGIN
  IF p_phase_state_id IS NULL OR p_tool_name IS NULL OR p_status IS NULL THEN
    RAISE EXCEPTION 'record_tool_invocation: phase_state_id, tool_name, status required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_phase FROM public.workflow_phase_states WHERE id = p_phase_state_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_tool_invocation: phase_state % not found', p_phase_state_id USING ERRCODE='P0002'; END IF;
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = v_phase.workflow_run_id;
  INSERT INTO public.tool_invocations (
    workflow_run_id, phase_state_id, tool_name, attempt_number,
    input_hash, output_hash, status, dedup_key, external_request_id,
    started_at, completed_at, error_summary
  ) VALUES (
    v_phase.workflow_run_id, p_phase_state_id, p_tool_name, COALESCE(p_attempt_number, 1),
    p_input_hash, p_output_hash, p_status, p_dedup_key, p_external_request_id,
    p_started_at, p_completed_at, p_error_summary
  )
  RETURNING * INTO v_inv;
  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_TOOL_INVOKED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('tool %s invoked (attempt %s, status=%s)', p_tool_name, COALESCE(p_attempt_number,1), p_status),
    p_after_state    => jsonb_build_object(
      'run_id',           v_run.id,
      'phase_state_id',   p_phase_state_id,
      'phase_name',       v_phase.phase_name,
      'tool_invocation_id', v_inv.id,
      'tool_name',        p_tool_name,
      'attempt_number',   COALESCE(p_attempt_number, 1),
      'status',           p_status::text,
      'input_hash',       p_input_hash,
      'output_hash',      p_output_hash,
      'dedup_key',        p_dedup_key
    )
  );
  RETURN v_inv;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.pick_next_phase(p_run_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run        public.workflow_runs;
  v_next_phase text;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RETURN NULL; END IF;

  -- First, any existing PENDING phase_state row (e.g., side phase created by route_phase)
  SELECT phase_name INTO v_next_phase
    FROM public.workflow_phase_states
   WHERE workflow_run_id = p_run_id AND status = 'PENDING'
   ORDER BY phase_order
   LIMIT 1;
  IF FOUND THEN RETURN v_next_phase; END IF;

  -- Otherwise, the next un-entered phase from the static definition sequence
  SELECT wpd.phase_name INTO v_next_phase
    FROM public.workflow_phase_definitions wpd
   WHERE wpd.workflow_type = v_run.workflow_type
     AND NOT EXISTS (
       SELECT 1 FROM public.workflow_phase_states wps
        WHERE wps.workflow_run_id = p_run_id
          AND wps.phase_name = wpd.phase_name
     )
   ORDER BY wpd.phase_order
   LIMIT 1;
  RETURN v_next_phase;
END;
$function$
;

