    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('tool %s dedup hit on key %s (cached from invocation %s)', p_tool_name, p_dedup_key, p_prior_invocation_id),
    p_after_state    => jsonb_build_object(
      'run_id',                v_run.id,
      'phase_state_id',        p_phase_state_id,
      'phase_name',            v_phase.phase_name,
      'tool_name',             p_tool_name,
      'dedup_key',             p_dedup_key,
      'prior_invocation_id',   p_prior_invocation_id,
      'prior_output_hash',     v_prior.output_hash,
      'prior_attempt_number',  v_prior.attempt_number
    )
  );

  RETURN jsonb_build_object('audit_event_id', v_audit.event_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fail_tool_invocation(p_invocation_id uuid, p_error_class tool_error_class_enum, p_error_summary text, p_error_detail jsonb DEFAULT '{}'::jsonb, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv          public.tool_invocations;
  v_tool         public.tool_registry;
  v_phase        public.workflow_phase_states;
  v_run          public.workflow_runs;
  v_will_retry   boolean := false;
  v_next_at      timestamptz;
  v_action_event text;
  v_severity     text;
  v_transition_result jsonb;
BEGIN
  IF p_invocation_id IS NULL OR p_error_class IS NULL OR p_error_summary IS NULL THEN
    RAISE EXCEPTION 'fail_tool_invocation: invocation_id, error_class, error_summary required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_inv FROM public.tool_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'fail_tool_invocation: invocation % not found', p_invocation_id USING ERRCODE='P0002'; END IF;
  IF v_inv.status NOT IN ('PENDING','RETRY_PENDING') THEN
    RAISE EXCEPTION 'fail_tool_invocation: invocation % is in status % (not failable)', p_invocation_id, v_inv.status USING ERRCODE='P0001';
  END IF;

  SELECT * INTO v_tool  FROM public.tool_registry WHERE tool_name = v_inv.tool_name;
  SELECT * INTO v_phase FROM public.workflow_phase_states WHERE id = v_inv.phase_state_id;
  SELECT * INTO v_run   FROM public.workflow_runs WHERE id = v_inv.workflow_run_id;

  -- Decide retry vs terminal
  v_will_retry := (
    p_error_class = 'TRANSIENT'
    AND v_inv.attempt_number < v_tool.retry_max_attempts
    AND v_tool.failure_semantics <> 'IDEMPOTENT_AT_MOST_ONCE'
  );

  IF v_will_retry THEN
    v_next_at := public.compute_next_retry_at(v_inv.attempt_number, v_tool.retry_backoff_base_ms, v_tool.retry_backoff_max_ms);
    UPDATE public.tool_invocations
       SET status        = 'RETRY_PENDING'::public.tool_invocation_status_enum,
           error_class   = p_error_class,
           error_summary = p_error_summary,
           next_retry_at = v_next_at,
           updated_at    = clock_timestamp()
     WHERE id = p_invocation_id
     RETURNING * INTO v_inv;

    PERFORM audit.emit_audit(
      p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
      p_action         => 'WORKFLOW_TOOL_RETRY_SCHEDULED',
      p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id     => v_run.id,
      p_business_id    => v_run.business_id,
      p_organization_id=> v_run.organization_id,
      p_actor_system   => 'workflow_engine',
      p_reason         => format('tool %s retry scheduled (attempt %s/%s, transient: %s)',
                                 v_inv.tool_name, v_inv.attempt_number, v_tool.retry_max_attempts, p_error_summary),
      p_after_state    => jsonb_build_object(
        'run_id',            v_run.id,
        'phase_state_id',    v_inv.phase_state_id,
        'tool_invocation_id', v_inv.id,
        'tool_name',         v_inv.tool_name,
        'attempt_number',    v_inv.attempt_number,
        'max_attempts',      v_tool.retry_max_attempts,
        'next_retry_at',     v_next_at,
        'error_class',       p_error_class::text,
        'error_summary',     p_error_summary,
        'error_detail',      p_error_detail
      )
    );

    RETURN jsonb_build_object(
      'ok',                     true,
      'will_retry',             true,
      'next_retry_at',          v_next_at,
      'attempts_remaining',     v_tool.retry_max_attempts - v_inv.attempt_number,
      'run_held',               false,
      'review_issue_requested', false,
      'severity',               NULL
    );
  END IF;

  -- Terminal path: mark FAILED, hold phase, transition run, emit error+review audits
  UPDATE public.tool_invocations
     SET status        = 'FAILED'::public.tool_invocation_status_enum,
         error_class   = p_error_class,
         error_summary = p_error_summary,
         completed_at  = clock_timestamp(),
         updated_at    = clock_timestamp(),
         next_retry_at = NULL
   WHERE id = p_invocation_id
   RETURNING * INTO v_inv;

  -- Hold phase
  IF v_phase.status <> 'HOLDING' THEN
    PERFORM public.hold_phase(v_inv.phase_state_id, format('tool failure: %s', v_inv.tool_name), 'BLOCKING'::public.gate_hold_severity_enum);
  END IF;

  -- Transition run to REVIEW_HOLD (SYSTEM allowed since review_hold_auto has no permission)
  IF v_run.status NOT IN ('REVIEW_HOLD','ABORTED','FINALIZED','FAILED','CANCELLED') THEN
    v_transition_result := public.transition_run(
      v_run.id, 'REVIEW_HOLD'::public.workflow_run_status_enum, p_actor_user_id,
      format('tool failure: %s', v_inv.tool_name), false, jsonb_build_object('error_class', p_error_class::text)
    );
  END IF;

  -- Error-class-specific audit
  IF p_error_class = 'TRANSIENT' THEN
    v_action_event := 'WORKFLOW_TOOL_FAILED_AFTER_RETRIES';
    v_severity     := 'HIGH';
  ELSIF p_error_class = 'FATAL' THEN
    v_action_event := 'WORKFLOW_TOOL_FATAL_ERROR';
    v_severity     := 'BLOCKING';
  ELSE
    v_action_event := 'WORKFLOW_TOOL_SCHEMA_ERROR';
    v_severity     := 'HIGH';
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => v_action_event,
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('tool %s terminal failure (%s): %s', v_inv.tool_name, p_error_class, p_error_summary),
    p_after_state    => jsonb_build_object(
      'run_id',            v_run.id,
      'phase_state_id',    v_inv.phase_state_id,
      'phase_name',        v_phase.phase_name,
      'tool_invocation_id', v_inv.id,
      'tool_name',         v_inv.tool_name,
      'attempt_number',    v_inv.attempt_number,
      'error_class',       p_error_class::text,
      'error_summary',     p_error_summary,
      'error_detail',      p_error_detail,
      'severity',          v_severity
    )
  );

  -- Review issue request (B14 placeholder)
  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_REVIEW_ISSUE_REQUESTED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('review issue for tool %s failure in phase %s', v_inv.tool_name, v_phase.phase_name),
    p_after_state    => jsonb_build_object(
      'run_id',           v_run.id,
      'phase_state_id',   v_inv.phase_state_id,
      'phase_name',       v_phase.phase_name,
      'tool_name',        v_inv.tool_name,
      'error_class',      p_error_class::text,
      'error_summary',    p_error_summary,
      'severity',         v_severity,
      'suggested_actions', CASE
        WHEN p_error_class = 'SCHEMA' THEN jsonb_build_array('Retry', 'Report bug', 'Abort')
        WHEN p_error_class = 'FATAL'  THEN jsonb_build_array('Abort')
        ELSE jsonb_build_array('Retry', 'Skip', 'Abort')
      END
    )
  );

  RETURN jsonb_build_object(
    'ok',                     true,
    'will_retry',             false,
    'next_retry_at',          NULL,
    'attempts_remaining',     0,
    'run_held',               true,
    'review_issue_requested', true,
    'severity',               v_severity
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_run_resumed_after_restart(p_run_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run   public.workflow_runs;
  v_audit audit.audit_events;
BEGIN
  IF p_run_id IS NULL THEN RAISE EXCEPTION 'record_run_resumed_after_restart: run_id required' USING ERRCODE='22000'; END IF;

  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_run_resumed_after_restart: run % not found', p_run_id USING ERRCODE='P0002'; END IF;
  IF public.is_terminal_state(v_run.status) THEN
    RAISE EXCEPTION 'record_run_resumed_after_restart: run % is terminal (%)', p_run_id, v_run.status USING ERRCODE='P0001';
  END IF;

  v_audit := audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_RESUMED_AFTER_RESTART',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('run %s resumed after restart: %s', p_run_id, COALESCE(p_reason, 'process startup')),
    p_after_state    => jsonb_build_object(
      'run_id',  v_run.id,
      'status',  v_run.status::text,
      'reason',  COALESCE(p_reason, 'process startup')
    )
  );

  RETURN jsonb_build_object('audit_event_id', v_audit.event_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_next_retry_at(p_attempt integer, p_base_ms integer, p_max_ms integer)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'pg_temp'
AS $function$
DECLARE
  v_ms double precision;
BEGIN
  IF p_attempt < 1 THEN p_attempt := 1; END IF;
  v_ms := p_base_ms * power(2::double precision, p_attempt - 1);
  IF v_ms > p_max_ms THEN v_ms := p_max_ms; END IF;
  RETURN clock_timestamp() + (v_ms || ' milliseconds')::interval;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reset_tool_for_retry(p_invocation_id uuid, p_actor_user_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv   public.tool_invocations;
  v_phase public.workflow_phase_states;
  v_run   public.workflow_runs;
  v_transition_result jsonb;
BEGIN
  IF p_invocation_id IS NULL OR p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'reset_tool_for_retry: invocation_id and actor_user_id required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_inv FROM public.tool_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'reset_tool_for_retry: invocation % not found', p_invocation_id USING ERRCODE='P0002'; END IF;
  IF v_inv.status <> 'FAILED' THEN
    RAISE EXCEPTION 'reset_tool_for_retry: invocation % is in status % (must be FAILED)', p_invocation_id, v_inv.status USING ERRCODE='P0001';
  END IF;
  SELECT * INTO v_phase FROM public.workflow_phase_states WHERE id = v_inv.phase_state_id;
  SELECT * INTO v_run   FROM public.workflow_runs WHERE id = v_inv.workflow_run_id;

  UPDATE public.tool_invocations
     SET status         = 'PENDING'::public.tool_invocation_status_enum,
         attempt_number = 1,
         error_summary  = NULL,
         error_class    = NULL,
         next_retry_at  = NULL,
         completed_at   = NULL,
         updated_at     = clock_timestamp()
   WHERE id = p_invocation_id
   RETURNING * INTO v_inv;

  UPDATE public.workflow_phase_states
     SET status = 'RUNNING'::public.phase_state_status_enum,
         updated_at = clock_timestamp()
   WHERE id = v_inv.phase_state_id;

  IF v_run.status = 'REVIEW_HOLD' THEN
    v_transition_result := public.transition_run(
      v_run.id, 'RUNNING'::public.workflow_run_status_enum, p_actor_user_id,
      COALESCE(p_reason, 'user requested retry'), false, '{}'::jsonb
    );
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'USER'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_TOOL_RETRY_REQUESTED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_reason         => format('user-requested retry of tool %s', v_inv.tool_name),
    p_after_state    => jsonb_build_object(
      'run_id',           v_run.id,
      'phase_state_id',   v_inv.phase_state_id,
      'tool_invocation_id', v_inv.id,
      'tool_name',        v_inv.tool_name,
      'reason',           p_reason
    )
  );

  RETURN jsonb_build_object('ok', true, 'invocation_id', v_inv.id, 'run_status', v_run.status::text);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.skip_held_tool(p_invocation_id uuid, p_actor_user_id uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv   public.tool_invocations;
  v_phase public.workflow_phase_states;
  v_run   public.workflow_runs;
BEGIN
  IF p_invocation_id IS NULL OR p_actor_user_id IS NULL OR p_reason IS NULL OR length(btrim(p_reason))=0 THEN
    RAISE EXCEPTION 'skip_held_tool: invocation_id, actor_user_id, reason required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_inv FROM public.tool_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'skip_held_tool: invocation % not found', p_invocation_id USING ERRCODE='P0002'; END IF;
  IF v_inv.status <> 'FAILED' THEN
    RAISE EXCEPTION 'skip_held_tool: invocation % is in status % (must be FAILED)', p_invocation_id, v_inv.status USING ERRCODE='P0001';
  END IF;

  SELECT * INTO v_phase FROM public.workflow_phase_states WHERE id = v_inv.phase_state_id;
  SELECT * INTO v_run   FROM public.workflow_runs WHERE id = v_inv.workflow_run_id;

  UPDATE public.tool_invocations
     SET status     = 'SKIPPED'::public.tool_invocation_status_enum,
         updated_at = clock_timestamp()
   WHERE id = p_invocation_id;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'USER'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_TOOL_SKIPPED_BY_USER',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_reason         => format('user skipped tool %s: %s', v_inv.tool_name, p_reason),
    p_after_state    => jsonb_build_object(
      'run_id',           v_run.id,
      'phase_state_id',   v_inv.phase_state_id,
      'tool_invocation_id', v_inv.id,
      'tool_name',        v_inv.tool_name,
      'reason',           p_reason
    )
  );

  RETURN jsonb_build_object('ok', true, 'invocation_id', v_inv.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_tool(p_tool_name text, p_version text, p_input_schema jsonb, p_output_schema jsonb, p_side_effect side_effect_class_enum, p_ai_tier ai_tier_enum, p_failure_semantics tool_failure_semantics_enum, p_dedup_key_generator_ref text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_retry_max_attempts integer DEFAULT 3, p_retry_backoff_base_ms integer DEFAULT 2000, p_retry_backoff_max_ms integer DEFAULT 60000)
 RETURNS tool_registry
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_row public.tool_registry;
BEGIN
  IF p_tool_name IS NULL OR length(btrim(p_tool_name)) = 0 THEN
    RAISE EXCEPTION 'register_tool: tool_name required' USING ERRCODE='22000';
  END IF;
  IF p_version IS NULL OR length(btrim(p_version)) = 0 THEN
    RAISE EXCEPTION 'register_tool: version required' USING ERRCODE='22000';
  END IF;
  IF p_input_schema IS NULL OR jsonb_typeof(p_input_schema) <> 'object' THEN
    RAISE EXCEPTION 'register_tool: input_schema must be jsonb object' USING ERRCODE='22000';
  END IF;
  IF p_output_schema IS NULL OR jsonb_typeof(p_output_schema) <> 'object' THEN
    RAISE EXCEPTION 'register_tool: output_schema must be jsonb object' USING ERRCODE='22000';
  END IF;

  INSERT INTO public.tool_registry (
    tool_name, version, input_schema, output_schema, side_effect, ai_tier, failure_semantics,
    dedup_key_generator_ref, description,
    retry_max_attempts, retry_backoff_base_ms, retry_backoff_max_ms
  ) VALUES (
    p_tool_name, p_version, p_input_schema, p_output_schema, p_side_effect, p_ai_tier, p_failure_semantics,
    p_dedup_key_generator_ref, p_description,
    COALESCE(p_retry_max_attempts, 3), COALESCE(p_retry_backoff_base_ms, 2000), COALESCE(p_retry_backoff_max_ms, 60000)
  )
  ON CONFLICT (tool_name) DO UPDATE SET
    version                 = EXCLUDED.version,
    input_schema            = EXCLUDED.input_schema,
    output_schema           = EXCLUDED.output_schema,
    side_effect             = EXCLUDED.side_effect,
    ai_tier                 = EXCLUDED.ai_tier,
    failure_semantics       = EXCLUDED.failure_semantics,
    dedup_key_generator_ref = EXCLUDED.dedup_key_generator_ref,
    description             = EXCLUDED.description,
    retry_max_attempts      = EXCLUDED.retry_max_attempts,
    retry_backoff_base_ms   = EXCLUDED.retry_backoff_base_ms,
    retry_backoff_max_ms    = EXCLUDED.retry_backoff_max_ms,
    updated_at              = clock_timestamp()
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'TOOL_REGISTRY_REGISTERED',
    p_subject_type => 'TOOL_REGISTRY'::audit.subject_type_enum,
    p_actor_system => 'engine.registerTool',
    p_reason       => format('tool %s v%s registered (side_effect=%s ai_tier=%s)', p_tool_name, p_version, p_side_effect, p_ai_tier),
    p_after_state  => jsonb_build_object(
      'tool_name', p_tool_name, 'version', p_version,
      'side_effect', p_side_effect, 'ai_tier', p_ai_tier,
      'failure_semantics', p_failure_semantics,
      'dedup_key_generator_ref', p_dedup_key_generator_ref,
      'retry_max_attempts', COALESCE(p_retry_max_attempts, 3),
      'retry_backoff_base_ms', COALESCE(p_retry_backoff_base_ms, 2000),
      'retry_backoff_max_ms', COALESCE(p_retry_backoff_max_ms, 60000)
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_run_manual(p_actor_user_id uuid, p_business_id uuid, p_workflow_type workflow_type_enum, p_period_start timestamp with time zone, p_period_end timestamp with time zone, p_principal_snapshot jsonb, p_parent_run_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_biz       public.business_entities;
  v_def_exists boolean;
  v_perm      jsonb;
  v_perm_dec  text;
  v_active    integer;
  v_run_id    uuid;
  v_reject_code text;
  v_reject_msg  text;
  v_is_adjustment boolean;
  v_specific_audit text;
  v_parent    public.workflow_runs;
  v_expected_parent_type public.workflow_type_enum;
BEGIN
  IF p_actor_user_id IS NULL OR p_business_id IS NULL OR p_workflow_type IS NULL
     OR p_period_start IS NULL OR p_period_end IS NULL OR p_principal_snapshot IS NULL THEN
    RAISE EXCEPTION 'trigger_run_manual: required params missing' USING ERRCODE='22000';
  END IF;

  v_is_adjustment := p_workflow_type IN ('OUT_ADJUSTMENT'::public.workflow_type_enum, 'IN_ADJUSTMENT'::public.workflow_type_enum);
  v_expected_parent_type := CASE p_workflow_type
                              WHEN 'OUT_ADJUSTMENT' THEN 'OUT_MONTHLY'::public.workflow_type_enum
                              WHEN 'IN_ADJUSTMENT'  THEN 'IN_MONTHLY'::public.workflow_type_enum
                              ELSE NULL
                            END;

  PERFORM public._acquire_trigger_lock(p_business_id, p_workflow_type);

  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    v_reject_code := 'BUSINESS_NOT_FOUND';
    v_reject_msg  := format('business %s not found', p_business_id);
  END IF;

  IF v_reject_code IS NULL THEN
    SELECT EXISTS(SELECT 1 FROM public.workflow_type_definitions WHERE workflow_type = p_workflow_type) INTO v_def_exists;
    IF NOT v_def_exists THEN
      v_reject_code := 'UNKNOWN_TYPE';
      v_reject_msg  := format('workflow_type %s not registered', p_workflow_type);
    END IF;
  END IF;

  IF v_reject_code IS NULL THEN
    v_perm := public.can_perform(
      p_actor_user_id   => p_actor_user_id,
      p_surface         => 'workflow_run',
      p_action          => 'execute',
      p_resource        => jsonb_build_object('workflow_type', p_workflow_type, 'business_id', p_business_id),
      p_business_id     => p_business_id,
      p_organization_id => v_biz.organization_id
    );
    v_perm_dec := v_perm->>'decision';
    IF v_perm_dec = 'DENY' THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg  := format('actor lacks permission workflow_run:execute (reason=%s)', v_perm->>'reason_code');
    ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg  := format('unexpected can_perform decision: %s', v_perm_dec);
    END IF;
  END IF;

  IF v_reject_code IS NULL AND v_is_adjustment AND p_parent_run_id IS NULL THEN
    v_reject_code := 'PARENT_REQUIRED';
    v_reject_msg  := format('adjustment workflow %s requires parent_run_id', p_workflow_type);
  END IF;

  -- P11: deep parent validation for adjustments
  IF v_reject_code IS NULL AND v_is_adjustment THEN
    SELECT * INTO v_parent FROM public.workflow_runs WHERE id = p_parent_run_id;
    IF NOT FOUND THEN
      v_reject_code := 'PARENT_NOT_FOUND';
      v_reject_msg  := format('parent_run_id %s not found', p_parent_run_id);
    ELSIF v_parent.business_id <> p_business_id THEN
      v_reject_code := 'PARENT_BUSINESS_MISMATCH';
      v_reject_msg  := format('parent run business %s ≠ target business %s', v_parent.business_id, p_business_id);
    ELSIF v_parent.workflow_type <> v_expected_parent_type THEN
      v_reject_code := 'PARENT_TYPE_MISMATCH';
      v_reject_msg  := format('parent run type %s ≠ expected %s for adjustment %s',
                              v_parent.workflow_type, v_expected_parent_type, p_workflow_type);
    ELSIF v_parent.status <> 'FINALIZED'::public.workflow_run_status_enum THEN
      v_reject_code := 'PARENT_NOT_FINALIZED';
      v_reject_msg  := format('parent run %s status is %s (must be FINALIZED)', p_parent_run_id, v_parent.status);
      v_specific_audit := 'WORKFLOW_ADJUSTMENT_REJECTED_PARENT_NOT_FINALIZED';
    ELSIF v_parent.finalized_at < clock_timestamp() - interval '6 years' THEN
      v_reject_code := 'PARENT_OUTSIDE_RETENTION';
      v_reject_msg  := format('parent run finalized at %s is outside the 6-year retention window', v_parent.finalized_at);
      v_specific_audit := 'WORKFLOW_ADJUSTMENT_REJECTED_OUTSIDE_RETENTION';
    END IF;
  END IF;

  IF v_reject_code IS NULL THEN
    IF v_is_adjustment THEN
      SELECT count(*) INTO v_active
        FROM public.workflow_runs
       WHERE business_id = p_business_id
         AND workflow_type = p_workflow_type
         AND parent_run_id IS NOT DISTINCT FROM p_parent_run_id
         AND status NOT IN ('FINALIZED'::public.workflow_run_status_enum,
                            'ABORTED'::public.workflow_run_status_enum,
                            'FAILED'::public.workflow_run_status_enum,
                            'CANCELLED'::public.workflow_run_status_enum);
      IF v_active > 0 THEN
        v_reject_code := 'DUPLICATE_ADJUSTMENT';
        v_reject_msg  := format('active adjustment exists for business %s + type %s + parent %s',
                                p_business_id, p_workflow_type, p_parent_run_id);
        v_specific_audit := 'WORKFLOW_RUN_REJECTED_DUPLICATE_ADJUSTMENT';
      END IF;
    ELSE
      SELECT count(*) INTO v_active
        FROM public.workflow_runs
       WHERE business_id = p_business_id
         AND workflow_type = p_workflow_type
         AND status NOT IN ('FINALIZED'::public.workflow_run_status_enum,
                            'ABORTED'::public.workflow_run_status_enum,
                            'FAILED'::public.workflow_run_status_enum,
                            'CANCELLED'::public.workflow_run_status_enum);
      IF v_active > 0 THEN
        v_reject_code := 'DUPLICATE_ACTIVE';
        v_reject_msg  := format('active run exists for business %s + type %s', p_business_id, p_workflow_type);
        v_specific_audit := 'WORKFLOW_RUN_REJECTED_DUPLICATE';
      END IF;
    END IF;
  END IF;

  IF v_reject_code IS NOT NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind     => 'USER'::audit.actor_kind_enum,
      p_action         => 'WORKFLOW_RUN_TRIGGER_REJECTED',
      p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id     => NULL,
      p_business_id    => p_business_id,
      p_organization_id=> v_biz.organization_id,
      p_actor_user_id  => p_actor_user_id,
      p_reason         => v_reject_msg,
      p_after_state    => jsonb_build_object(
        'rejection_code', v_reject_code, 'business_id', p_business_id,
        'workflow_type', p_workflow_type::text, 'trigger_kind', 'MANUAL',
        'parent_run_id', p_parent_run_id, 'context', p_context
      )
    );
    IF v_specific_audit IS NOT NULL THEN
      PERFORM audit.emit_audit(
        p_actor_kind     => 'USER'::audit.actor_kind_enum,
        p_action         => v_specific_audit,
        p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
        p_subject_id     => NULL,
        p_business_id    => p_business_id,
        p_organization_id=> v_biz.organization_id,
        p_actor_user_id  => p_actor_user_id,
        p_reason         => v_reject_msg,
        p_after_state    => jsonb_build_object(
          'rejection_code', v_reject_code, 'business_id', p_business_id,
          'workflow_type', p_workflow_type::text, 'parent_run_id', p_parent_run_id,
          'parent_finalized_at', CASE WHEN v_parent.id IS NOT NULL THEN to_jsonb(v_parent.finalized_at) ELSE NULL END
        )
      );
    END IF;
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code, 'message', v_reject_msg);
  END IF;

  INSERT INTO public.workflow_runs (
    organization_id, business_id, principal_snapshot, workflow_type,
    period_start, period_end, started_by, parent_run_id,
    trigger_kind, trigger_event_id
  ) VALUES (
    v_biz.organization_id, p_business_id, p_principal_snapshot, p_workflow_type,
    p_period_start, p_period_end, p_actor_user_id, p_parent_run_id,
    'MANUAL'::public.trigger_kind_enum, NULL
  )
  RETURNING id INTO v_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'USER'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_RUN_TRIGGERED_MANUAL',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run_id,
    p_business_id    => p_business_id,
    p_organization_id=> v_biz.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_reason         => format('manual trigger of %s for business %s', p_workflow_type, p_business_id),
    p_after_state    => jsonb_build_object(
      'run_id', v_run_id, 'workflow_type', p_workflow_type::text,
      'business_id', p_business_id, 'period_start', p_period_start,
      'period_end', p_period_end, 'parent_run_id', p_parent_run_id, 'trigger_kind', 'MANUAL'
    )
  );

  -- P11: emit adjustment-specific creation audit
  IF v_is_adjustment THEN
    PERFORM audit.emit_audit(
      p_actor_kind     => 'USER'::audit.actor_kind_enum,
      p_action         => 'WORKFLOW_ADJUSTMENT_CREATED',
      p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id     => v_run_id,
      p_business_id    => p_business_id,
      p_organization_id=> v_biz.organization_id,
      p_actor_user_id  => p_actor_user_id,
      p_reason         => format('adjustment %s created against parent %s', p_workflow_type, p_parent_run_id),
      p_after_state    => jsonb_build_object(
        'run_id', v_run_id, 'workflow_type', p_workflow_type::text,
        'parent_run_id', p_parent_run_id,
        'parent_finalized_at', v_parent.finalized_at,
        'retention_window_years', 6
      )
    );
  END IF;

  RETURN jsonb_build_object('ok', true, 'run_id', v_run_id, 'trigger_kind', 'MANUAL');
END;
$function$
;

CREATE OR REPLACE FUNCTION public._acquire_trigger_lock(p_business_id uuid, p_workflow_type workflow_type_enum)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_k bigint;
BEGIN
  v_k := hashtextextended(p_business_id::text || '|' || p_workflow_type::text, 0);
  PERFORM pg_advisory_xact_lock(v_k);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_coordinated_pair(p_run_id uuid)
 RETURNS SETOF workflow_runs
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT wr2.*
    FROM public.workflow_runs wr1
    JOIN public.workflow_runs wr2 ON wr2.trigger_event_id = wr1.trigger_event_id
                                  AND wr2.id <> wr1.id
   WHERE wr1.id = p_run_id
     AND wr1.trigger_event_id IS NOT NULL;
$function$
;

CREATE OR REPLACE FUNCTION public.record_shared_phase_coordination(p_run_id uuid, p_sibling_run_id uuid, p_phase_name text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run   public.workflow_runs;
  v_audit audit.audit_events;
BEGIN
  IF p_run_id IS NULL OR p_sibling_run_id IS NULL OR p_phase_name IS NULL THEN
    RAISE EXCEPTION 'record_shared_phase_coordination: all params required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_shared_phase_coordination: run % not found', p_run_id USING ERRCODE='P0002'; END IF;

  v_audit := audit.emit_audit(
    p_actor_kind     => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
    p_action         => 'WORKFLOW_SHARED_PHASE_COORDINATED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_actor_system   => CASE WHEN p_actor_user_id IS NULL THEN 'workflow_engine' ELSE NULL END,
    p_reason         => format('shared phase %s coordinated between runs %s and %s', p_phase_name, p_run_id, p_sibling_run_id),
    p_after_state    => jsonb_build_object(
      'run_id', p_run_id, 'sibling_run_id', p_sibling_run_id, 'phase_name', p_phase_name
    )
  );
  RETURN jsonb_build_object('audit_event_id', v_audit.event_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_check_adjustment_record_run_type()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_type public.workflow_type_enum;
BEGIN
  SELECT workflow_type INTO v_type FROM public.workflow_runs WHERE id = NEW.workflow_run_id;
  IF v_type IS NULL THEN
    RAISE EXCEPTION 'adjustment_records: workflow_run % not found', NEW.workflow_run_id USING ERRCODE='P0002';
  END IF;
  IF v_type NOT IN ('OUT_ADJUSTMENT','IN_ADJUSTMENT') THEN
    RAISE EXCEPTION 'adjustment_records: workflow_run % is type % (must be OUT_ADJUSTMENT or IN_ADJUSTMENT)', NEW.workflow_run_id, v_type
      USING ERRCODE='P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

