CREATE OR REPLACE FUNCTION public.check_adjustment_intake_gate(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_cnt integer;
BEGIN
  IF p_run_id IS NULL THEN
    RAISE EXCEPTION 'check_adjustment_intake_gate: run_id required' USING ERRCODE='22000';
  END IF;
  SELECT count(*) INTO v_cnt FROM public.adjustment_records WHERE workflow_run_id = p_run_id;
  IF v_cnt > 0 THEN
    RETURN jsonb_build_object('decision', 'ADVANCE', 'record_count', v_cnt);
  END IF;
  RETURN jsonb_build_object('decision', 'HOLD',
                            'reason', 'ADJUSTMENT_INTAKE: at least one adjustment_record with reason + delta is required',
                            'record_count', 0);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_adjustment_finalization_handoff(p_run_id uuid, p_actor_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run         public.workflow_runs;
  v_record_count integer;
  v_target_types text[];
  v_audit       audit.audit_events;
BEGIN
  IF p_run_id IS NULL OR p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'record_adjustment_finalization_handoff: run_id + actor required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_adjustment_finalization_handoff: run % not found', p_run_id USING ERRCODE='P0002'; END IF;
  IF v_run.workflow_type NOT IN ('OUT_ADJUSTMENT','IN_ADJUSTMENT') THEN
    RAISE EXCEPTION 'record_adjustment_finalization_handoff: run % is type % (must be adjustment)', p_run_id, v_run.workflow_type USING ERRCODE='P0001';
  END IF;

  SELECT count(*), array_agg(DISTINCT target_record_type::text)
    INTO v_record_count, v_target_types
    FROM public.adjustment_records WHERE workflow_run_id = p_run_id;

  v_audit := audit.emit_audit(
    p_actor_kind     => 'USER'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_ADJUSTMENT_FINALIZED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => p_run_id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_user_id  => p_actor_user_id,
    p_reason         => format('adjustment %s finalization handoff (%s records, types=%s)',
                               v_run.workflow_type, COALESCE(v_record_count, 0), v_target_types),
    p_after_state    => jsonb_build_object(
      'run_id',         p_run_id,
      'workflow_type',  v_run.workflow_type::text,
      'parent_run_id',  v_run.parent_run_id,
      'record_count',   COALESCE(v_record_count, 0),
      'target_types',   to_jsonb(COALESCE(v_target_types, ARRAY[]::text[])),
      'b15_handoff',    'pending — B15 will swap this stub with archive-additive write'
    )
  );
  RETURN jsonb_build_object('audit_event_id', v_audit.event_id, 'record_count', COALESCE(v_record_count, 0));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_tier_canonical_label(t ai_tier_enum)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE PARALLEL SAFE
AS $function$
  SELECT CASE t
           WHEN 'NONE'::public.ai_tier_enum         THEN 'TIER_1_NONE'
           WHEN 'LOCAL_LLM'::public.ai_tier_enum    THEN 'TIER_2_LOCAL_LLM'
           WHEN 'EXTERNAL_LLM'::public.ai_tier_enum THEN 'TIER_3_EXTERNAL_LLM'
         END;
$function$
;

CREATE OR REPLACE FUNCTION public.model_id_for_tier(t ai_tier_enum)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE PARALLEL SAFE
AS $function$
  SELECT CASE t
           WHEN 'NONE'::public.ai_tier_enum         THEN NULL
           WHEN 'LOCAL_LLM'::public.ai_tier_enum    THEN 'local-llm-default'
           WHEN 'EXTERNAL_LLM'::public.ai_tier_enum THEN 'anthropic-claude-eu-zero-retention'
         END;
$function$
;

CREATE OR REPLACE FUNCTION public.estimate_tier2_cost(p_business_id uuid, p_compute_seconds numeric DEFAULT NULL::numeric, p_latency_ms integer DEFAULT NULL::integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_business_rate numeric(14,6); v_currency text;
  v_hourly_rate numeric(14,6); v_source text; v_seconds numeric; v_cost numeric(14,6);
  c_system_default_rate constant numeric := 2.000000;
  c_system_default_currency constant text := 'EUR';
BEGIN
  IF p_business_id IS NULL THEN
    RAISE EXCEPTION 'estimate_tier2_cost: p_business_id required' USING ERRCODE = '22000';
  END IF;
  IF p_compute_seconds IS NULL AND p_latency_ms IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NO_COMPUTE_OR_LATENCY');
  END IF;
  IF p_compute_seconds IS NOT NULL AND p_compute_seconds < 0 THEN
    RAISE EXCEPTION 'estimate_tier2_cost: compute_seconds must be non-negative' USING ERRCODE = '22023';
  END IF;
  IF p_latency_ms IS NOT NULL AND p_latency_ms < 0 THEN
    RAISE EXCEPTION 'estimate_tier2_cost: latency_ms must be non-negative' USING ERRCODE = '22023';
  END IF;
  SELECT tier2_hourly_compute_rate, tier2_hourly_compute_rate_currency INTO v_business_rate, v_currency
    FROM public.business_ai_config WHERE business_id = p_business_id;
  IF v_business_rate IS NOT NULL THEN
    v_hourly_rate := v_business_rate; v_source := 'tier2_business_rate';
  ELSE
    v_hourly_rate := c_system_default_rate; v_currency := c_system_default_currency; v_source := 'tier2_system_default';
  END IF;
  IF p_compute_seconds IS NOT NULL THEN
    v_seconds := p_compute_seconds;
  ELSE
    v_seconds := p_latency_ms::numeric / 1000; v_source := 'tier2_fallback_latency';
  END IF;
  v_cost := (v_seconds / 3600) * v_hourly_rate;
  RETURN jsonb_build_object('ok', true, 'cost_estimate', v_cost, 'currency', v_currency,
    'source', v_source, 'hourly_rate', v_hourly_rate, 'compute_seconds_used', v_seconds);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_prompt_regression_failed(p_actor_user_id uuid, p_prompt_id text, p_version text, p_failed_cases jsonb, p_ci_run_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_count int; v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_prompt_id IS NULL OR p_version IS NULL OR p_failed_cases IS NULL THEN
    RAISE EXCEPTION 'record_prompt_regression_failed: required params missing' USING ERRCODE = '22000';
  END IF;
  IF jsonb_typeof(p_failed_cases) <> 'array' OR jsonb_array_length(p_failed_cases) = 0 THEN
    RAISE EXCEPTION 'record_prompt_regression_failed: p_failed_cases must be a non-empty array' USING ERRCODE = '22000';
  END IF;
  v_count := jsonb_array_length(p_failed_cases);
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'prompt_regression_runner';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'AI_PROMPT_REGRESSION_FAILED',
    p_subject_type => 'PROMPT'::audit.subject_type_enum,
    p_subject_id => NULL, p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_reason => format('prompt %s version %s failed regression (%s case(s))', p_prompt_id, p_version, v_count),
    p_after_state => jsonb_build_object(
      'prompt_id', p_prompt_id, 'version', p_version,
      'failed_case_count', v_count, 'failed_cases', p_failed_cases, 'ci_run_id', p_ci_run_id));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id, 'failed_case_count', v_count);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.route_ai_call(p_tool_name text, p_business_id uuid, p_workflow_run_id uuid DEFAULT NULL::uuid, p_calling_phase text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tool         public.tool_registry%ROWTYPE;
  v_cfg          public.business_ai_config%ROWTYPE;
  v_biz          public.business_entities%ROWTYPE;
  v_tier         public.ai_tier_enum;
  v_tier_label   text;
  v_model_id     text;
  v_tier_enabled boolean;
  v_decision     text;
  v_routing_reason text;
  v_audit_action text;
  v_audit_kind   audit.actor_kind_enum;
  v_actor_system text;
  v_audit_row    audit.audit_events;
BEGIN
  IF p_tool_name IS NULL OR p_business_id IS NULL THEN
    RAISE EXCEPTION 'route_ai_call: p_tool_name and p_business_id are required'
      USING ERRCODE = '22000';
  END IF;

  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'decision',       'ERROR',
      'error_code',     'BUSINESS_NOT_FOUND',
      'message',        format('business %s not found', p_business_id),
      'audit_event_id', NULL
    );
  END IF;

  SELECT * INTO v_tool FROM public.tool_registry WHERE tool_name = p_tool_name;
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'decision',       'ERROR',
      'error_code',     'TOOL_NOT_FOUND',
      'message',        format('tool %s not registered', p_tool_name),
      'audit_event_id', NULL
    );
  END IF;

  v_tier       := v_tool.ai_tier;
  v_tier_label := public.ai_tier_canonical_label(v_tier);

  SELECT * INTO v_cfg FROM public.business_ai_config WHERE business_id = p_business_id;

  IF v_tier = 'NONE'::public.ai_tier_enum THEN
    v_decision       := 'ALLOW';
    v_routing_reason := 'TIER_1_NO_AI';
    v_model_id       := NULL;
  ELSIF v_tier = 'LOCAL_LLM'::public.ai_tier_enum THEN
    v_tier_enabled := COALESCE(v_cfg.tier2_enabled, true);
    IF v_tier_enabled THEN
      v_decision       := 'ALLOW';
      v_routing_reason := 'TIER_MATCHED';
      v_model_id       := public.model_id_for_tier(v_tier);
    ELSE
      v_decision       := 'BLOCK';
      v_routing_reason := 'TIER_2_DISABLED_FOR_BUSINESS';
      v_model_id       := NULL;
    END IF;
  ELSIF v_tier = 'EXTERNAL_LLM'::public.ai_tier_enum THEN
    v_tier_enabled := COALESCE(v_cfg.tier3_enabled, true);
    IF v_tier_enabled THEN
      v_decision       := 'ALLOW';
      v_routing_reason := 'TIER_MATCHED';
      v_model_id       := public.model_id_for_tier(v_tier);
    ELSE
      v_decision       := 'BLOCK';
      v_routing_reason := 'TIER_3_DISABLED_FOR_BUSINESS';
      v_model_id       := NULL;
    END IF;
  ELSE
    RAISE EXCEPTION 'route_ai_call: unknown ai_tier %', v_tier USING ERRCODE = '22023';
  END IF;

  v_audit_action := CASE v_decision WHEN 'ALLOW' THEN 'AI_TIER_ROUTED' ELSE 'AI_TIER_BLOCKED' END;

  IF p_actor_user_id IS NULL THEN
    v_audit_kind   := 'SYSTEM'::audit.actor_kind_enum;
    v_actor_system := 'ai_router';
  ELSE
    v_audit_kind   := 'USER'::audit.actor_kind_enum;
    v_actor_system := NULL;
  END IF;

  v_audit_row := audit.emit_audit(
    p_actor_kind      => v_audit_kind,
    p_action          => v_audit_action,
    p_subject_type    => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id      => p_workflow_run_id,
    p_actor_user_id   => p_actor_user_id,
    p_actor_system    => v_actor_system,
    p_organization_id => v_biz.organization_id,
    p_business_id     => p_business_id,
    p_reason          => format('tool=%s tier=%s decision=%s reason=%s',
                                 p_tool_name, v_tier_label, v_decision, v_routing_reason),
    p_after_state     => jsonb_build_object(
      'tool_name',       p_tool_name,
      'tier',            v_tier::text,
      'tier_label',      v_tier_label,
      'decision',        v_decision,
      'routing_reason',  v_routing_reason,
      'model_id',        v_model_id,
      'calling_phase',   p_calling_phase,
      'workflow_run_id', p_workflow_run_id
    )
  );

  RETURN jsonb_build_object(
    'decision',       v_decision,
    'tier',           v_tier::text,
    'tier_label',     v_tier_label,
    'model_id',       v_model_id,
    'prompt_version', NULL,
    'routing_reason', v_routing_reason,
    'audit_event_id', v_audit_row.id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_gateway_minimize_payload(p_schema jsonb, p_input jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE PARALLEL SAFE
AS $function$
DECLARE
  v_props     jsonb;
  v_out       jsonb := '{}'::jsonb;
  v_key       text;
BEGIN
  IF p_input IS NULL OR jsonb_typeof(p_input) <> 'object' THEN
    RETURN p_input;
  END IF;
  v_props := p_schema -> 'properties';
  IF v_props IS NULL OR jsonb_typeof(v_props) <> 'object' THEN
    RETURN p_input;
  END IF;
  FOR v_key IN SELECT * FROM jsonb_object_keys(p_input) LOOP
    IF v_props ? v_key THEN
      v_out := v_out || jsonb_build_object(v_key, p_input -> v_key);
    END IF;
  END LOOP;
  RETURN v_out;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_business_ai_config(p_actor_user_id uuid, p_business_id uuid, p_tier2_enabled boolean, p_tier3_enabled boolean)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_biz         public.business_entities%ROWTYPE;
  v_perm        jsonb;
  v_perm_dec    text;
  v_before      public.business_ai_config%ROWTYPE;
  v_after       public.business_ai_config%ROWTYPE;
  v_reject_code text;
  v_reject_msg  text;
  v_audit_row   audit.audit_events;
BEGIN
  IF p_actor_user_id IS NULL OR p_business_id IS NULL
     OR p_tier2_enabled IS NULL OR p_tier3_enabled IS NULL THEN
    RAISE EXCEPTION 'update_business_ai_config: required params missing'
      USING ERRCODE = '22000';
  END IF;

  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    v_reject_code := 'BUSINESS_NOT_FOUND';
    v_reject_msg  := format('business %s not found', p_business_id);
  END IF;

  IF v_reject_code IS NULL THEN
    v_perm := public.can_perform(
      p_actor_user_id   => p_actor_user_id,
      p_surface         => 'business_ai_config',
      p_action          => 'update',
      p_resource        => jsonb_build_object('business_id', p_business_id),
      p_business_id     => p_business_id,
      p_organization_id => v_biz.organization_id
    );
    v_perm_dec := v_perm->>'decision';
    IF v_perm_dec = 'DENY' THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg  := format('actor lacks permission business_ai_config:update (reason=%s)',
                               v_perm->>'reason_code');
    ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg  := format('unexpected can_perform decision: %s', v_perm_dec);
    END IF;
  END IF;

  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind      => 'USER'::audit.actor_kind_enum,
      p_action          => 'AI_TIER_CONFIG_UPDATE_REJECTED',
      p_subject_type    => 'BUSINESS_AI_CONFIG'::audit.subject_type_enum,
      p_subject_id      => NULL,
      p_actor_user_id   => p_actor_user_id,
      p_business_id     => p_business_id,
      p_organization_id => v_biz.organization_id,
      p_reason          => v_reject_msg,
      p_after_state     => jsonb_build_object(
        'rejection_code', v_reject_code,
        'business_id',    p_business_id,
        'requested',      jsonb_build_object(
                            'tier2_enabled', p_tier2_enabled,
                            'tier3_enabled', p_tier3_enabled
                          )
      )
    );
    RETURN jsonb_build_object(
      'ok',             false,
      'reason',         v_reject_code,
      'message',        v_reject_msg,
      'audit_event_id', v_audit_row.id
    );
  END IF;

  SELECT * INTO v_before FROM public.business_ai_config WHERE business_id = p_business_id;

  INSERT INTO public.business_ai_config (
    business_id, tier2_enabled, tier3_enabled, updated_by_user_id, updated_at
  ) VALUES (
    p_business_id, p_tier2_enabled, p_tier3_enabled, p_actor_user_id, clock_timestamp()
  )
  ON CONFLICT (business_id) DO UPDATE
    SET tier2_enabled      = EXCLUDED.tier2_enabled,
        tier3_enabled      = EXCLUDED.tier3_enabled,
        updated_by_user_id = EXCLUDED.updated_by_user_id,
        updated_at         = EXCLUDED.updated_at
  RETURNING * INTO v_after;

  v_audit_row := audit.emit_audit(
    p_actor_kind      => 'USER'::audit.actor_kind_enum,
    p_action          => 'AI_TIER_CONFIG_UPDATED',
    p_subject_type    => 'BUSINESS_AI_CONFIG'::audit.subject_type_enum,
    p_subject_id      => v_after.id,
    p_actor_user_id   => p_actor_user_id,
    p_business_id     => p_business_id,
    p_organization_id => v_biz.organization_id,
    p_before_state    => CASE WHEN v_before.id IS NOT NULL THEN
                           jsonb_build_object(
                             'tier2_enabled', v_before.tier2_enabled,
                             'tier3_enabled', v_before.tier3_enabled
                           )
                         ELSE NULL END,
    p_after_state     => jsonb_build_object(
      'config_id',     v_after.id,
      'business_id',   p_business_id,
      'tier2_enabled', v_after.tier2_enabled,
      'tier3_enabled', v_after.tier3_enabled,
      'first_write',   v_before.id IS NULL
    ),
    p_reason          => format('business_ai_config %s for business %s',
                                 CASE WHEN v_before.id IS NULL THEN 'created' ELSE 'updated' END,
                                 p_business_id)
  );

  RETURN jsonb_build_object(
    'ok',             true,
    'config_id',      v_after.id,
    'business_id',    p_business_id,
    'tier2_enabled',  v_after.tier2_enabled,
    'tier3_enabled',  v_after.tier3_enabled,
    'first_write',    v_before.id IS NULL,
    'audit_event_id', v_audit_row.id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.current_redaction_policy_version()
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$ SELECT active_policy_version FROM public.redaction_active_policy WHERE id = 1; $function$
;

CREATE OR REPLACE FUNCTION public.estimate_tier3_cost(p_model_id text, p_input_tokens integer, p_output_tokens integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_row public.tier_3_pricing%ROWTYPE; v_cost numeric(14,6);
BEGIN
  IF p_model_id IS NULL OR p_input_tokens IS NULL OR p_output_tokens IS NULL THEN
    RAISE EXCEPTION 'estimate_tier3_cost: required params missing' USING ERRCODE = '22000';
  END IF;
  IF p_input_tokens < 0 OR p_output_tokens < 0 THEN
    RAISE EXCEPTION 'estimate_tier3_cost: token counts must be non-negative' USING ERRCODE = '22023';
  END IF;
  SELECT * INTO v_row FROM public.tier_3_pricing
    WHERE model_id = p_model_id AND effective_from <= clock_timestamp()
      AND (effective_until IS NULL OR effective_until > clock_timestamp())
    ORDER BY effective_from DESC LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NO_ACTIVE_RATE_FOR_MODEL', 'model_id', p_model_id);
  END IF;
  v_cost := (p_input_tokens::numeric * v_row.input_rate_per_mtok / 1000000)
          + (p_output_tokens::numeric * v_row.output_rate_per_mtok / 1000000);
  RETURN jsonb_build_object('ok', true, 'cost_estimate', v_cost, 'currency', v_row.currency,
    'rate_version', v_row.rate_version, 'input_rate_per_mtok', v_row.input_rate_per_mtok,
    'output_rate_per_mtok', v_row.output_rate_per_mtok);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_redaction(p_tier ai_tier_enum, p_payload jsonb, p_input_schema jsonb, p_policy_version text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_props        jsonb;
  v_out          jsonb := '{}'::jsonb;
  v_key          text;
  v_val          jsonb;
  v_val_text     text;
  v_field_kind   text;
  v_policy_row   public.redaction_policies%ROWTYPE;
  v_drops        jsonb := '{}'::jsonb;
  v_masks        jsonb := '{}'::jsonb;
  v_drop_count   int := 0;
  v_mask_count   int := 0;
  v_kept_count   int := 0;
  v_pii_field    text;
  v_pii_pattern  text;
BEGIN
  IF p_tier IS NULL OR p_payload IS NULL OR p_input_schema IS NULL OR p_policy_version IS NULL THEN
    RAISE EXCEPTION 'apply_redaction: required params missing' USING ERRCODE = '22000';
  END IF;
  IF p_tier = 'NONE'::public.ai_tier_enum THEN
    RAISE EXCEPTION 'apply_redaction: tier NONE not supported' USING ERRCODE = '22023';
  END IF;
  IF jsonb_typeof(p_payload) <> 'object' THEN
    RETURN jsonb_build_object('ok', true, 'redacted_payload', p_payload,
      'drop_count', 0, 'mask_count', 0, 'kept_count', 0,
      'drops_by_field_kind','{}'::jsonb,'masks_by_field_kind','{}'::jsonb);
  END IF;
  v_props := p_input_schema -> 'properties';
  FOR v_key IN SELECT * FROM jsonb_object_keys(p_payload) LOOP
    v_val := p_payload -> v_key;
    v_field_kind := v_props -> v_key ->> 'x_redaction_field_kind';
    IF v_field_kind IS NULL THEN
      v_out := v_out || jsonb_build_object(v_key, v_val);
      v_kept_count := v_kept_count + 1;
      CONTINUE;
    END IF;
    SELECT * INTO v_policy_row FROM public.redaction_policies
      WHERE policy_version = p_policy_version AND tier = p_tier
      AND field_kind = v_field_kind::public.redaction_field_kind_enum;
    IF NOT FOUND THEN
      v_drop_count := v_drop_count + 1;
      v_drops := jsonb_set(v_drops, ARRAY['MISSING_POLICY'],
                 to_jsonb(COALESCE((v_drops->>'MISSING_POLICY')::int, 0) + 1), true);
      CONTINUE;
    END IF;
    IF v_policy_row.default_action = 'DROP'::public.redaction_action_enum THEN
      v_drop_count := v_drop_count + 1;
      v_drops := jsonb_set(v_drops, ARRAY[v_field_kind],
                 to_jsonb(COALESCE((v_drops->>v_field_kind)::int, 0) + 1), true);
    ELSIF v_policy_row.default_action = 'MASK_FIXED'::public.redaction_action_enum THEN
      v_out := v_out || jsonb_build_object(v_key, '***');
      v_mask_count := v_mask_count + 1;
      v_masks := jsonb_set(v_masks, ARRAY[v_field_kind],
                 to_jsonb(COALESCE((v_masks->>v_field_kind)::int, 0) + 1), true);
    ELSIF v_policy_row.default_action = 'MASK_LAST_N'::public.redaction_action_enum THEN
      IF jsonb_typeof(v_val) = 'string' THEN
        v_val_text := v_val #>> '{}';
        IF v_field_kind IN ('IBAN','ACCOUNT_NUMBER','VAT_NUMBER') THEN
          v_out := v_out || jsonb_build_object(v_key,
            keys.mask_field(v_val_text, v_field_kind::keys.field_kind_enum));
        ELSE
          v_out := v_out || jsonb_build_object(v_key,
            CASE WHEN length(regexp_replace(v_val_text,'\s','','g'))
                       <= COALESCE(v_policy_row.action_param, 4) THEN '***'
                 ELSE '***' || right(regexp_replace(v_val_text,'\s','','g'),
                                     COALESCE(v_policy_row.action_param, 4))
            END);
        END IF;
      ELSE
        v_out := v_out || jsonb_build_object(v_key, '***');
      END IF;
      v_mask_count := v_mask_count + 1;
      v_masks := jsonb_set(v_masks, ARRAY[v_field_kind],
                 to_jsonb(COALESCE((v_masks->>v_field_kind)::int, 0) + 1), true);
    ELSIF v_policy_row.default_action = 'KEEP_IF_DECLARED'::public.redaction_action_enum THEN
      v_out := v_out || jsonb_build_object(v_key, v_val);
      v_kept_count := v_kept_count + 1;
      IF v_field_kind = 'FREE_TEXT_DESCRIPTION' AND jsonb_typeof(v_val) = 'string' THEN
        v_val_text := v_val #>> '{}';
        IF v_val_text ~ '\m[A-Z]{2}[0-9]{2}[A-Z0-9]{4,30}\M' THEN
          v_pii_field := v_key; v_pii_pattern := 'IBAN_LIKE'; EXIT;
        ELSIF v_val_text ~ '\m[0-9]{3}-[0-9]{2}-[0-9]{4}\M' THEN
          v_pii_field := v_key; v_pii_pattern := 'US_SSN'; EXIT;
        ELSIF v_val_text ~ '\m[0-9]{13,19}\M' THEN
          v_pii_field := v_key; v_pii_pattern := 'CREDIT_CARD_DIGITS'; EXIT;
        ELSIF v_val_text ~ '\m[0-9]{10,12}\M' THEN
          v_pii_field := v_key; v_pii_pattern := 'BANK_ACCOUNT_DIGITS'; EXIT;
        END IF;
      END IF;
    ELSE
      RAISE EXCEPTION 'apply_redaction: unknown action %', v_policy_row.default_action;
    END IF;
  END LOOP;
  IF v_pii_field IS NOT NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'PII_IN_NON_DECLARED_FIELD',
      'offending_field', v_pii_field, 'matched_pattern', v_pii_pattern);
  END IF;
  RETURN jsonb_build_object('ok', true, 'redacted_payload', v_out,
    'drop_count', v_drop_count, 'mask_count', v_mask_count, 'kept_count', v_kept_count,
    'drops_by_field_kind', v_drops, 'masks_by_field_kind', v_masks);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_gateway_invoke_begin(p_tool_name text, p_business_id uuid, p_input jsonb, p_workflow_run_id uuid DEFAULT NULL::uuid, p_calling_phase text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_biz             public.business_entities%ROWTYPE;
  v_tool            public.tool_registry%ROWTYPE;
  v_tier_label      text;
  v_schema_chk      jsonb;
  v_minimized       jsonb;
  v_dropped_undecl  int;
  v_policy_version  text;
  v_redact          jsonb;
  v_route           jsonb;
  v_route_dec       text;
  v_invocation_id   uuid;
  v_audit_kind      audit.actor_kind_enum;
  v_actor_system    text;
  v_audit_row       audit.audit_events;
BEGIN
  IF p_tool_name IS NULL OR p_business_id IS NULL OR p_input IS NULL THEN
    RAISE EXCEPTION 'ai_gateway_invoke_begin: p_tool_name, p_business_id, p_input required' USING ERRCODE = '22000';
  END IF;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'decision', 'ERROR', 'error_code', 'BUSINESS_NOT_FOUND',
      'message', format('business %s not found', p_business_id));
  END IF;
  SELECT * INTO v_tool FROM public.tool_registry WHERE tool_name = p_tool_name;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'decision', 'ERROR', 'error_code', 'TOOL_NOT_FOUND',
      'message', format('tool %s not registered', p_tool_name));
  END IF;
  IF v_tool.ai_tier = 'NONE'::public.ai_tier_enum THEN
    RETURN jsonb_build_object('ok', false, 'decision', 'ERROR', 'error_code', 'TIER_1_BYPASS_REQUIRED',
      'message', format('tool %s is Tier 1 (no AI); must not reach gateway', p_tool_name));
  END IF;
  v_tier_label     := public.ai_tier_canonical_label(v_tool.ai_tier);
  v_policy_version := public.current_redaction_policy_version();
  IF p_actor_user_id IS NULL THEN
    v_audit_kind := 'SYSTEM'::audit.actor_kind_enum; v_actor_system := 'ai_gateway';
  ELSE
    v_audit_kind := 'USER'::audit.actor_kind_enum; v_actor_system := NULL;
  END IF;

  v_schema_chk := public._jsonb_matches_schema(p_input, v_tool.input_schema);
  IF NOT (v_schema_chk->>'valid')::boolean THEN
    INSERT INTO public.ai_gateway_invocations (
      business_id, workflow_run_id, tool_name, tier, tier_label, model_id,
      calling_phase, actor_user_id, status, result_variant,
      input_received, error_detail, finalized_at, redaction_policy_version
    ) VALUES (
      p_business_id, p_workflow_run_id, p_tool_name, v_tool.ai_tier, v_tier_label, NULL,
      p_calling_phase, p_actor_user_id,
      'COMPLETED_SCHEMA_VIOLATION_INPUT'::public.ai_gateway_invocation_status_enum,
      'SCHEMA_VIOLATION_INPUT'::public.ai_gateway_result_variant_enum,
      p_input, v_schema_chk->'errors', clock_timestamp(), v_policy_version
    ) RETURNING id INTO v_invocation_id;
    v_audit_row := audit.emit_audit(
      p_actor_kind => v_audit_kind, p_action => 'AI_GATEWAY_VALIDATION_FAILED',
      p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
      p_subject_id => v_invocation_id, p_actor_user_id => p_actor_user_id,
      p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
      p_business_id => p_business_id,
      p_reason => format('input failed schema for tool %s', p_tool_name),
      p_after_state => jsonb_build_object('invocation_id', v_invocation_id,
        'tool_name', p_tool_name, 'variant', 'SCHEMA_VIOLATION_INPUT',
        'errors', v_schema_chk->'errors'));
    RETURN jsonb_build_object('ok', false, 'invocation_id', v_invocation_id,
      'result_variant', 'SCHEMA_VIOLATION_INPUT', 'errors', v_schema_chk->'errors',
      'audit_event_id', v_audit_row.id);
  END IF;

  v_minimized := public.ai_gateway_minimize_payload(v_tool.input_schema, p_input);
  v_dropped_undecl := (SELECT count(*) FROM jsonb_object_keys(p_input) AS k WHERE NOT (v_minimized ? k));
  IF v_dropped_undecl > 0 THEN
    PERFORM audit.emit_audit(
      p_actor_kind => v_audit_kind, p_action => 'AI_REDACTION_ALLOWLIST_DROP',
      p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
      p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
      p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
      p_business_id => p_business_id,
      p_reason => format('%s undeclared key(s) dropped for tool %s', v_dropped_undecl, p_tool_name),
      p_after_state => jsonb_build_object('tool_name', p_tool_name,
        'dropped_count', v_dropped_undecl,
        'dropped_keys', (SELECT jsonb_agg(k) FROM jsonb_object_keys(p_input) AS k WHERE NOT (v_minimized ? k))));
  END IF;

  v_redact := public.apply_redaction(v_tool.ai_tier, v_minimized, v_tool.input_schema, v_policy_version);
  IF NOT (v_redact->>'ok')::boolean THEN
    INSERT INTO public.ai_gateway_invocations (
      business_id, workflow_run_id, tool_name, tier, tier_label, model_id,
      calling_phase, actor_user_id, status, result_variant,
      input_received, minimized_input, error_detail, finalized_at, redaction_policy_version
    ) VALUES (
      p_business_id, p_workflow_run_id, p_tool_name, v_tool.ai_tier, v_tier_label, NULL,
      p_calling_phase, p_actor_user_id,
      'COMPLETED_REDACTION_REJECTED'::public.ai_gateway_invocation_status_enum,
      'REDACTION_REJECTED'::public.ai_gateway_result_variant_enum,
      p_input, v_minimized,
      jsonb_build_object('reason', v_redact->>'reason',
        'offending_field', v_redact->>'offending_field',
        'matched_pattern', v_redact->>'matched_pattern'),
      clock_timestamp(), v_policy_version
    ) RETURNING id INTO v_invocation_id;
    PERFORM audit.emit_audit(
      p_actor_kind => v_audit_kind, p_action => 'AI_REDACTION_REJECTED',
      p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
      p_subject_id => v_invocation_id, p_actor_user_id => p_actor_user_id,
      p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
      p_business_id => p_business_id,
      p_reason => format('redaction rejected for tool %s (reason=%s)', p_tool_name, v_redact->>'reason'),
      p_after_state => jsonb_build_object('invocation_id', v_invocation_id,
        'tool_name', p_tool_name, 'reason', v_redact->>'reason',
        'offending_field', v_redact->>'offending_field',
        'matched_pattern', v_redact->>'matched_pattern'));
    v_audit_row := audit.emit_audit(
      p_actor_kind => v_audit_kind, p_action => 'AI_PII_DETECTED_IN_NON_DECLARED_FIELD',
      p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
      p_subject_id => v_invocation_id, p_actor_user_id => p_actor_user_id,
      p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
      p_business_id => p_business_id,
      p_reason => format('PII pattern %s in field %s for tool %s - likely caller bug',
        v_redact->>'matched_pattern', v_redact->>'offending_field', p_tool_name),
      p_after_state => jsonb_build_object('invocation_id', v_invocation_id,
        'tool_name', p_tool_name,
        'offending_field', v_redact->>'offending_field',
        'matched_pattern', v_redact->>'matched_pattern'));
    RETURN jsonb_build_object('ok', false, 'invocation_id', v_invocation_id,
      'result_variant', 'REDACTION_REJECTED', 'reason', v_redact->>'reason',
      'offending_field', v_redact->>'offending_field',
      'matched_pattern', v_redact->>'matched_pattern',
      'audit_event_id', v_audit_row.id);
  END IF;

  v_minimized := v_redact->'redacted_payload';
  PERFORM audit.emit_audit(
    p_actor_kind => v_audit_kind, p_action => 'AI_REDACTION_APPLIED',
    p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
    p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
    p_business_id => p_business_id,
    p_reason => format('redaction applied for tool %s tier %s (drops=%s masks=%s kept=%s)',
      p_tool_name, v_tier_label, v_redact->>'drop_count', v_redact->>'mask_count', v_redact->>'kept_count'),
    p_after_state => jsonb_build_object('tool_name', p_tool_name,
      'tier', v_tool.ai_tier::text, 'policy_version', v_policy_version,
      'drop_count', (v_redact->>'drop_count')::int,
      'mask_count', (v_redact->>'mask_count')::int,
      'kept_count', (v_redact->>'kept_count')::int,
      'drops_by_field_kind', v_redact->'drops_by_field_kind',
      'masks_by_field_kind', v_redact->'masks_by_field_kind'));

  v_route := public.route_ai_call(p_tool_name => p_tool_name, p_business_id => p_business_id,
    p_workflow_run_id => p_workflow_run_id, p_calling_phase => p_calling_phase,
    p_actor_user_id => p_actor_user_id);
  v_route_dec := v_route->>'decision';

  IF v_route_dec = 'BLOCK' THEN
    INSERT INTO public.ai_gateway_invocations (
      business_id, workflow_run_id, tool_name, tier, tier_label, model_id,
      calling_phase, actor_user_id, status, result_variant,
      input_received, minimized_input, error_detail, finalized_at, redaction_policy_version
    ) VALUES (
      p_business_id, p_workflow_run_id, p_tool_name, v_tool.ai_tier, v_tier_label, NULL,
      p_calling_phase, p_actor_user_id,
      'COMPLETED_TIER_BLOCKED'::public.ai_gateway_invocation_status_enum,
      'TIER_BLOCKED'::public.ai_gateway_result_variant_enum,
      p_input, v_minimized,
      jsonb_build_object('routing_reason', v_route->>'routing_reason',
        'route_audit_event_id', v_route->>'audit_event_id'),
      clock_timestamp(), v_policy_version
    ) RETURNING id INTO v_invocation_id;
    RETURN jsonb_build_object('ok', false, 'invocation_id', v_invocation_id,
      'result_variant', 'TIER_BLOCKED', 'routing_reason', v_route->>'routing_reason',
      'audit_event_id', v_route->>'audit_event_id');
  ELSIF v_route_dec <> 'ALLOW' THEN
    RETURN jsonb_build_object('ok', false, 'decision', 'ERROR',
      'error_code', COALESCE(v_route->>'error_code', 'ROUTING_UNEXPECTED'),
      'message', format('routing returned unexpected decision: %s', v_route_dec),
      'route_envelope', v_route);
  END IF;

  INSERT INTO public.ai_gateway_invocations (
    business_id, workflow_run_id, tool_name, tier, tier_label, model_id, prompt_version,
    calling_phase, actor_user_id, status, input_received, minimized_input, redaction_policy_version
  ) VALUES (
    p_business_id, p_workflow_run_id, p_tool_name, v_tool.ai_tier, v_tier_label,
    v_route->>'model_id', v_route->>'prompt_version', p_calling_phase, p_actor_user_id,
    'PREPARED'::public.ai_gateway_invocation_status_enum, p_input, v_minimized, v_policy_version
  ) RETURNING id INTO v_invocation_id;

  v_audit_row := audit.emit_audit(
    p_actor_kind => v_audit_kind, p_action => 'AI_GATEWAY_INVOKED',
    p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
    p_subject_id => v_invocation_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
    p_business_id => p_business_id,
    p_reason => format('gateway invocation prepared for tool %s tier %s', p_tool_name, v_tier_label),
    p_after_state => jsonb_build_object('invocation_id', v_invocation_id,
      'tool_name', p_tool_name, 'tier', v_tool.ai_tier::text, 'tier_label', v_tier_label,
      'model_id', v_route->>'model_id', 'calling_phase', p_calling_phase,
      'workflow_run_id', p_workflow_run_id, 'redaction_policy_version', v_policy_version));

  RETURN jsonb_build_object('ok', true, 'invocation_id', v_invocation_id,
    'tier', v_tool.ai_tier::text, 'tier_label', v_tier_label,
    'model_id', v_route->>'model_id', 'prompt_version', v_route->>'prompt_version',
    'minimized_input', v_minimized, 'redaction_policy_version', v_policy_version,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ai_usage(p_organization_id uuid, p_business_id uuid, p_tool_name text, p_ai_tier ai_tier_enum, p_started_at timestamp with time zone, p_completed_at timestamp with time zone, p_latency_ms integer, p_validation_outcome ai_gateway_result_variant_enum, p_workflow_run_id uuid DEFAULT NULL::uuid, p_phase_state_id uuid DEFAULT NULL::uuid, p_gateway_invocation_id uuid DEFAULT NULL::uuid, p_prompt_id text DEFAULT NULL::text, p_prompt_version text DEFAULT NULL::text, p_policy_version text DEFAULT NULL::text, p_model_id text DEFAULT NULL::text, p_input_size_bytes integer DEFAULT NULL::integer, p_output_size_bytes integer DEFAULT NULL::integer, p_input_tokens integer DEFAULT NULL::integer, p_output_tokens integer DEFAULT NULL::integer, p_compute_seconds numeric DEFAULT NULL::numeric, p_gpu_seconds numeric DEFAULT NULL::numeric, p_redactions_applied jsonb DEFAULT '{}'::jsonb, p_cache_hit boolean DEFAULT false, p_error_kind text DEFAULT NULL::text, p_error_summary text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_estimator jsonb; v_cost numeric(14,6); v_currency text := 'EUR';
  v_rate_version text; v_record_id uuid; v_audit_row audit.audit_events;
BEGIN
  IF p_organization_id IS NULL OR p_business_id IS NULL OR p_tool_name IS NULL
     OR p_ai_tier IS NULL OR p_started_at IS NULL OR p_completed_at IS NULL
     OR p_latency_ms IS NULL OR p_validation_outcome IS NULL THEN
    RAISE EXCEPTION 'record_ai_usage: required params missing' USING ERRCODE = '22000';
  END IF;
  IF (p_error_kind IS NULL) <> (p_error_summary IS NULL) THEN
    RAISE EXCEPTION 'record_ai_usage: error_kind and error_summary must be both NULL or both non-NULL' USING ERRCODE = '22000';
  END IF;
  IF p_validation_outcome <> 'SUCCESS'::public.ai_gateway_result_variant_enum AND p_error_kind IS NULL THEN
    RAISE EXCEPTION 'record_ai_usage: non-SUCCESS outcomes require error_kind/error_summary' USING ERRCODE = '22000';
  END IF;
  IF p_cache_hit THEN
    v_cost := 0; v_currency := 'EUR'; v_rate_version := 'cache_hit';
  ELSIF p_validation_outcome <> 'SUCCESS'::public.ai_gateway_result_variant_enum THEN
    v_cost := 0; v_currency := 'EUR'; v_rate_version := NULL;
  ELSIF p_ai_tier = 'EXTERNAL_LLM'::public.ai_tier_enum THEN
    v_estimator := public.estimate_tier3_cost(p_model_id, COALESCE(p_input_tokens, 0), COALESCE(p_output_tokens, 0));
    IF (v_estimator->>'ok')::boolean IS NOT TRUE THEN
      v_cost := NULL; v_rate_version := NULL;
    ELSE
      v_cost := (v_estimator->>'cost_estimate')::numeric;
      v_currency := v_estimator->>'currency';
      v_rate_version := v_estimator->>'rate_version';
    END IF;
  ELSIF p_ai_tier = 'LOCAL_LLM'::public.ai_tier_enum THEN
    v_estimator := public.estimate_tier2_cost(p_business_id, p_compute_seconds, p_latency_ms);
    IF (v_estimator->>'ok')::boolean IS NOT TRUE THEN
      v_cost := NULL; v_rate_version := NULL;
    ELSE
      v_cost := (v_estimator->>'cost_estimate')::numeric;
      v_currency := v_estimator->>'currency';
      v_rate_version := v_estimator->>'source';
    END IF;
  ELSE
    RAISE EXCEPTION 'record_ai_usage: unsupported ai_tier %', p_ai_tier USING ERRCODE = '22023';
  END IF;

  INSERT INTO public.ai_usage_records (
    organization_id, business_id, workflow_run_id, phase_state_id, gateway_invocation_id,
    tool_name, prompt_id, prompt_version, policy_version, ai_tier, model_id,
    started_at, completed_at, latency_ms, input_size_bytes, output_size_bytes,
    input_tokens, output_tokens, compute_seconds, gpu_seconds,
    validation_outcome, redactions_applied, cost_estimate, cost_estimate_currency,
    cost_rate_version, cache_hit, error_kind, error_summary
  ) VALUES (
    p_organization_id, p_business_id, p_workflow_run_id, p_phase_state_id, p_gateway_invocation_id,
    p_tool_name, p_prompt_id, p_prompt_version, p_policy_version, p_ai_tier, p_model_id,
    p_started_at, p_completed_at, p_latency_ms, p_input_size_bytes, p_output_size_bytes,
    p_input_tokens, p_output_tokens, p_compute_seconds, p_gpu_seconds,
    p_validation_outcome, COALESCE(p_redactions_applied,'{}'::jsonb), v_cost, v_currency,
    v_rate_version, p_cache_hit, p_error_kind, p_error_summary
  ) RETURNING id INTO v_record_id;

  v_audit_row := audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'AI_USAGE_RECORDED',
    p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
    p_subject_id => p_gateway_invocation_id, p_actor_system => 'ai_usage_logger',
    p_organization_id => p_organization_id, p_business_id => p_business_id,
    p_reason => format('AI usage %s recorded for tier %s (outcome=%s)', v_record_id, p_ai_tier, p_validation_outcome),
    p_after_state => jsonb_build_object('usage_record_id', v_record_id, 'tool_name', p_tool_name,
      'ai_tier', p_ai_tier::text, 'model_id', p_model_id, 'validation_outcome', p_validation_outcome::text,
      'latency_ms', p_latency_ms, 'input_tokens', p_input_tokens, 'output_tokens', p_output_tokens,
      'compute_seconds', p_compute_seconds, 'cost_estimate', v_cost, 'currency', v_currency,
      'rate_version', v_rate_version, 'cache_hit', p_cache_hit));
  RETURN jsonb_build_object('ok', true, 'usage_record_id', v_record_id,
    'cost_estimate', v_cost, 'currency', v_currency, 'rate_version', v_rate_version,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.activate_redaction_policy(p_actor_user_id uuid, p_target_version text, p_is_rollback boolean DEFAULT false)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_perm jsonb; v_perm_dec text; v_exists boolean; v_prev text;
  v_reject_code text; v_reject_msg text; v_audit_row audit.audit_events; v_action_name text;
BEGIN
  IF p_actor_user_id IS NULL OR p_target_version IS NULL THEN
    RAISE EXCEPTION 'activate_redaction_policy: required params missing' USING ERRCODE = '22000';
  END IF;
  v_perm := public.can_perform(
    p_actor_user_id => p_actor_user_id, p_surface => 'redaction_policy',
    p_action => 'activate',
    p_resource => jsonb_build_object('target_version', p_target_version),
    p_business_id => NULL, p_organization_id => NULL);
  v_perm_dec := v_perm->>'decision';
  IF v_perm_dec = 'DENY' THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('actor lacks permission redaction_policy:activate (reason=%s)', v_perm->>'reason_code');
  ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT EXISTS(SELECT 1 FROM public.redaction_policies WHERE policy_version = p_target_version) INTO v_exists;
    IF NOT v_exists THEN
      v_reject_code := 'POLICY_VERSION_NOT_FOUND';
      v_reject_msg := format('redaction policy version %s has no rows', p_target_version);
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'AI_REDACTION_POLICY_ACTIVATE_REJECTED',
      p_subject_type => 'REDACTION_POLICY'::audit.subject_type_enum,
      p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
      p_reason => v_reject_msg,
      p_after_state => jsonb_build_object('rejection_code', v_reject_code,
        'target_version', p_target_version, 'is_rollback', p_is_rollback));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  SELECT active_policy_version INTO v_prev FROM public.redaction_active_policy WHERE id = 1;
  UPDATE public.redaction_active_policy
     SET active_policy_version = p_target_version, activated_at = clock_timestamp(),
         activated_by_user_id = p_actor_user_id, is_rollback = p_is_rollback
   WHERE id = 1;
  v_action_name := CASE WHEN p_is_rollback THEN 'AI_REDACTION_POLICY_ROLLED_BACK'
                                            ELSE 'AI_REDACTION_POLICY_ACTIVATED' END;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => v_action_name,
    p_subject_type => 'REDACTION_POLICY'::audit.subject_type_enum,
    p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
    p_before_state => jsonb_build_object('active_policy_version', v_prev),
    p_after_state => jsonb_build_object('active_policy_version', p_target_version,
      'is_rollback', p_is_rollback),
    p_reason => format('redaction policy active version %s -> %s (rollback=%s)',
      v_prev, p_target_version, p_is_rollback));
  RETURN jsonb_build_object('ok', true, 'previous_version', v_prev,
    'active_policy_version', p_target_version, 'is_rollback', p_is_rollback,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_prompt(p_actor_user_id uuid, p_prompt_id text, p_version text, p_purpose text, p_input_schema jsonb, p_output_schema jsonb, p_ai_tier ai_tier_enum, p_prompt_template_text text, p_content_hash text, p_test_cases jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_perm jsonb; v_perm_dec text; v_exists boolean;
  v_case_count int; v_adv_count int; v_case jsonb;
  v_reject_code text; v_reject_msg text; v_audit_row audit.audit_events;
BEGIN
  IF p_actor_user_id IS NULL OR p_prompt_id IS NULL OR p_version IS NULL
     OR p_purpose IS NULL OR p_input_schema IS NULL OR p_output_schema IS NULL
     OR p_ai_tier IS NULL OR p_prompt_template_text IS NULL
     OR p_content_hash IS NULL OR p_test_cases IS NULL THEN
    RAISE EXCEPTION 'register_prompt: required params missing' USING ERRCODE = '22000';
  END IF;
  v_perm := public.can_perform(
    p_actor_user_id => p_actor_user_id, p_surface => 'prompt_registry',
    p_action => 'register',
    p_resource => jsonb_build_object('prompt_id', p_prompt_id, 'version', p_version),
    p_business_id => NULL, p_organization_id => NULL);
  v_perm_dec := v_perm->>'decision';
  IF v_perm_dec = 'DENY' THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('actor lacks permission prompt_registry:register (reason=%s)', v_perm->>'reason_code');
  ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT EXISTS(SELECT 1 FROM public.prompt_registry WHERE prompt_id = p_prompt_id AND version = p_version) INTO v_exists;
    IF v_exists THEN
      v_reject_code := 'DUPLICATE_VERSION';
      v_reject_msg := format('prompt %s version %s already registered', p_prompt_id, p_version);
    END IF;
  END IF;
  IF v_reject_code IS NULL THEN
    IF jsonb_typeof(p_test_cases) <> 'array' THEN
      v_reject_code := 'TEST_CASES_NOT_ARRAY'; v_reject_msg := 'p_test_cases must be a JSON array';
    ELSE
      v_case_count := jsonb_array_length(p_test_cases);
      IF v_case_count < 5 THEN
        v_reject_code := 'TEST_CASES_INSUFFICIENT';
        v_reject_msg := format('spec requires >=5 test cases (got %s)', v_case_count);
      ELSE
        SELECT count(*) INTO v_adv_count FROM jsonb_array_elements(p_test_cases) AS c
          WHERE COALESCE((c->>'is_adversarial_anchor')::boolean, false);
        IF v_adv_count < 1 THEN
          v_reject_code := 'NO_ADVERSARIAL_ANCHOR';
          v_reject_msg := 'spec requires >=1 test case with is_adversarial_anchor=true';
        END IF;
      END IF;
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'AI_PROMPT_REGISTER_REJECTED',
      p_subject_type => 'PROMPT'::audit.subject_type_enum,
      p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
      p_reason => v_reject_msg,
      p_after_state => jsonb_build_object(
        'rejection_code', v_reject_code, 'prompt_id', p_prompt_id, 'version', p_version));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  INSERT INTO public.prompt_registry (
    prompt_id, version, purpose, input_schema, output_schema, ai_tier,
    prompt_template_text, content_hash, registered_by_user_id
  ) VALUES (
    p_prompt_id, p_version, p_purpose, p_input_schema, p_output_schema, p_ai_tier,
    p_prompt_template_text, p_content_hash, p_actor_user_id
  );
  FOR v_case IN SELECT jsonb_array_elements(p_test_cases) LOOP
    INSERT INTO public.prompt_test_cases (
      prompt_id, version, case_name, input, expected_output,
      must_contain_assertions, is_adversarial_anchor
    ) VALUES (
      p_prompt_id, p_version, v_case->>'case_name',
      v_case->'input', v_case->'expected_output',
      COALESCE(v_case->'must_contain_assertions', '[]'::jsonb),
      COALESCE((v_case->>'is_adversarial_anchor')::boolean, false)
    );
  END LOOP;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_PROMPT_REGISTERED',
    p_subject_type => 'PROMPT'::audit.subject_type_enum,
    p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
    p_reason => format('prompt %s version %s registered (%s test cases)',
                        p_prompt_id, p_version, v_case_count),
    p_after_state => jsonb_build_object(
      'prompt_id', p_prompt_id, 'version', p_version, 'ai_tier', p_ai_tier::text,
      'content_hash', p_content_hash, 'test_case_count', v_case_count,
      'adversarial_anchor_count', v_adv_count));
  RETURN jsonb_build_object('ok', true, 'prompt_id', p_prompt_id, 'version', p_version,
    'test_case_count', v_case_count, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.deploy_prompt(p_actor_user_id uuid, p_prompt_id text, p_version text, p_environment prompt_environment_enum, p_is_override boolean DEFAULT false, p_override_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_perm jsonb; v_perm_dec text; v_exists boolean;
  v_test_deploy timestamptz; v_soak_elapsed_interval interval;
  v_reject_code text; v_reject_msg text;
  v_audit_row audit.audit_events; v_action_name text; v_deploy_id uuid;
BEGIN
  IF p_actor_user_id IS NULL OR p_prompt_id IS NULL OR p_version IS NULL OR p_environment IS NULL THEN
    RAISE EXCEPTION 'deploy_prompt: required params missing' USING ERRCODE = '22000';
  END IF;
  IF p_is_override = true AND (p_override_reason IS NULL OR length(trim(p_override_reason)) = 0) THEN
    v_reject_code := 'MISSING_OVERRIDE_REASON';
    v_reject_msg := 'p_is_override=true requires a non-empty p_override_reason';
  END IF;
  IF v_reject_code IS NULL THEN
    v_perm := public.can_perform(
      p_actor_user_id => p_actor_user_id, p_surface => 'prompt_deployment',
      p_action => 'deploy',
      p_resource => jsonb_build_object('prompt_id', p_prompt_id, 'version', p_version, 'environment', p_environment::text),
      p_business_id => NULL, p_organization_id => NULL);
    v_perm_dec := v_perm->>'decision';
    IF v_perm_dec = 'DENY' THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg := format('actor lacks permission prompt_deployment:deploy (reason=%s)', v_perm->>'reason_code');
    ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
    END IF;
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT EXISTS(SELECT 1 FROM public.prompt_registry WHERE prompt_id = p_prompt_id AND version = p_version) INTO v_exists;
    IF NOT v_exists THEN
      v_reject_code := 'VERSION_NOT_FOUND';
      v_reject_msg := format('prompt %s version %s not registered', p_prompt_id, p_version);
    END IF;
  END IF;
  IF v_reject_code IS NULL AND p_environment = 'PRODUCTION'::public.prompt_environment_enum AND NOT p_is_override THEN
    SELECT MIN(deployed_at) INTO v_test_deploy FROM public.prompt_deployments
      WHERE prompt_id = p_prompt_id AND version = p_version AND environment = 'TEST'::public.prompt_environment_enum;
    IF v_test_deploy IS NULL THEN
      v_reject_code := 'SOAK_NOT_ELAPSED';
      v_reject_msg := format('prompt %s version %s never deployed to TEST; cannot promote without override', p_prompt_id, p_version);
    ELSIF (clock_timestamp() - v_test_deploy) < interval '7 days' THEN
      v_soak_elapsed_interval := clock_timestamp() - v_test_deploy;
      v_reject_code := 'SOAK_NOT_ELAPSED';
      v_reject_msg := format('soak window not elapsed (%s < 7 days); first TEST deploy %s', v_soak_elapsed_interval, v_test_deploy);
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'AI_PROMPT_DEPLOY_REJECTED',
      p_subject_type => 'PROMPT'::audit.subject_type_enum,
      p_subject_id => NULL, p_actor_user_id => p_actor_user_id, p_reason => v_reject_msg,
      p_after_state => jsonb_build_object(
        'rejection_code', v_reject_code, 'prompt_id', p_prompt_id, 'version', p_version,
        'environment', p_environment::text, 'is_override', p_is_override));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  UPDATE public.prompt_deployments SET is_current = false
    WHERE environment = p_environment AND prompt_id = p_prompt_id AND is_current = true;
  INSERT INTO public.prompt_deployments (
    prompt_id, version, environment, deployed_by_user_id,
    is_current, is_rollback, is_override, override_reason
  ) VALUES (
    p_prompt_id, p_version, p_environment, p_actor_user_id,
    true, false, p_is_override, p_override_reason
  ) RETURNING id INTO v_deploy_id;
  v_action_name := CASE WHEN p_is_override THEN 'AI_PROMPT_PROMOTION_OVERRIDE_USED' ELSE 'AI_PROMPT_DEPLOYED' END;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => v_action_name,
    p_subject_type => 'PROMPT'::audit.subject_type_enum,
    p_subject_id => v_deploy_id, p_actor_user_id => p_actor_user_id,
    p_reason => format('prompt %s version %s deployed to %s (override=%s)',
                        p_prompt_id, p_version, p_environment, p_is_override),
    p_after_state => jsonb_build_object(
      'deployment_id', v_deploy_id, 'prompt_id', p_prompt_id, 'version', p_version,
      'environment', p_environment::text, 'is_override', p_is_override,
      'override_reason', p_override_reason));
  RETURN jsonb_build_object('ok', true, 'deployment_id', v_deploy_id,
    'prompt_id', p_prompt_id, 'version', p_version,
    'environment', p_environment::text, 'is_override', p_is_override,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rollback_prompt(p_actor_user_id uuid, p_prompt_id text, p_environment prompt_environment_enum, p_target_version text, p_rollback_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_perm jsonb; v_perm_dec text; v_exists boolean; v_prev_version text;
  v_reject_code text; v_reject_msg text; v_audit_row audit.audit_events; v_deploy_id uuid;
BEGIN
  IF p_actor_user_id IS NULL OR p_prompt_id IS NULL OR p_environment IS NULL
     OR p_target_version IS NULL OR p_rollback_reason IS NULL
     OR length(trim(p_rollback_reason)) = 0 THEN
    RAISE EXCEPTION 'rollback_prompt: required params missing (rollback_reason non-empty required)' USING ERRCODE = '22000';
  END IF;
  v_perm := public.can_perform(
    p_actor_user_id => p_actor_user_id, p_surface => 'prompt_deployment', p_action => 'rollback',
    p_resource => jsonb_build_object('prompt_id', p_prompt_id, 'environment', p_environment::text, 'target_version', p_target_version),
    p_business_id => NULL, p_organization_id => NULL);
  v_perm_dec := v_perm->>'decision';
  IF v_perm_dec = 'DENY' THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('actor lacks permission prompt_deployment:rollback (reason=%s)', v_perm->>'reason_code');
  ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT EXISTS(SELECT 1 FROM public.prompt_registry WHERE prompt_id = p_prompt_id AND version = p_target_version) INTO v_exists;
    IF NOT v_exists THEN
      v_reject_code := 'VERSION_NOT_FOUND';
      v_reject_msg := format('prompt %s version %s not registered', p_prompt_id, p_target_version);
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_PROMPT_DEPLOY_REJECTED',
      p_subject_type => 'PROMPT'::audit.subject_type_enum,
      p_subject_id => NULL, p_actor_user_id => p_actor_user_id, p_reason => v_reject_msg,
      p_after_state => jsonb_build_object(
        'rejection_code', v_reject_code, 'prompt_id', p_prompt_id,
        'target_version', p_target_version, 'environment', p_environment::text, 'rollback', true));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  SELECT version INTO v_prev_version FROM public.prompt_deployments
    WHERE environment = p_environment AND prompt_id = p_prompt_id AND is_current = true;
  UPDATE public.prompt_deployments SET is_current = false
    WHERE environment = p_environment AND prompt_id = p_prompt_id AND is_current = true;
  INSERT INTO public.prompt_deployments (
    prompt_id, version, environment, deployed_by_user_id,
    is_current, is_rollback, rollback_reason
  ) VALUES (
    p_prompt_id, p_target_version, p_environment, p_actor_user_id,
    true, true, p_rollback_reason
  ) RETURNING id INTO v_deploy_id;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_PROMPT_ROLLED_BACK',
    p_subject_type => 'PROMPT'::audit.subject_type_enum,
    p_subject_id => v_deploy_id, p_actor_user_id => p_actor_user_id,
    p_before_state => jsonb_build_object('previous_version', v_prev_version),
    p_after_state => jsonb_build_object(
      'deployment_id', v_deploy_id, 'prompt_id', p_prompt_id, 'version', p_target_version,
      'environment', p_environment::text, 'rollback_reason', p_rollback_reason),
    p_reason => format('prompt %s in %s rolled back from %s to %s: %s',
                        p_prompt_id, p_environment, v_prev_version, p_target_version, p_rollback_reason));
  RETURN jsonb_build_object('ok', true, 'deployment_id', v_deploy_id,
    'prompt_id', p_prompt_id, 'environment', p_environment::text,
    'previous_version', v_prev_version, 'target_version', p_target_version,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_prompt(p_prompt_id text, p_version text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_row public.prompt_registry%ROWTYPE; v_cases jsonb;
BEGIN
  SELECT * INTO v_row FROM public.prompt_registry WHERE prompt_id = p_prompt_id AND version = p_version;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'VERSION_NOT_FOUND',
      'prompt_id', p_prompt_id, 'version', p_version);
  END IF;
  SELECT jsonb_agg(jsonb_build_object(
    'case_name', case_name, 'input', input, 'expected_output', expected_output,
    'must_contain_assertions', must_contain_assertions,
    'is_adversarial_anchor', is_adversarial_anchor) ORDER BY case_name)
    INTO v_cases FROM public.prompt_test_cases
    WHERE prompt_id = p_prompt_id AND version = p_version;
  RETURN jsonb_build_object('ok', true,
    'prompt_id', v_row.prompt_id, 'version', v_row.version, 'purpose', v_row.purpose,
    'input_schema', v_row.input_schema, 'output_schema', v_row.output_schema,
    'ai_tier', v_row.ai_tier::text, 'prompt_template_text', v_row.prompt_template_text,
    'content_hash', v_row.content_hash, 'registered_at', v_row.registered_at,
    'test_cases', COALESCE(v_cases, '[]'::jsonb));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.begin_drive_finder_run(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_root_folder_id text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_run_id uuid;
BEGIN
  IF p_root_folder_id IS NULL OR length(trim(p_root_folder_id)) = 0 THEN
    RAISE EXCEPTION 'ROOT_FOLDER_ID_REQUIRED' USING errcode='check_violation';
  END IF;
  INSERT INTO public.drive_finder_runs (
    organization_id, business_id, transaction_id, root_folder_id, status
  ) VALUES (
    p_organization_id, p_business_id, p_transaction_id, p_root_folder_id, 'STARTED'
  ) RETURNING id INTO v_run_id;
  RETURN jsonb_build_object(
    'decision','STARTED','run_id',v_run_id,
    'transaction_id',p_transaction_id,'root_folder_id',p_root_folder_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_drive_finder_folders_selected(p_run_id uuid, p_subfolder_count integer, p_buffer_days integer, p_subfolder_names text[] DEFAULT NULL::text[], p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
BEGIN
  IF p_subfolder_count IS NULL OR p_subfolder_count < 0 THEN
    RAISE EXCEPTION 'SUBFOLDER_COUNT_NONNEGATIVE' USING errcode='check_violation';
  END IF;
  SELECT organization_id, business_id, transaction_id
    INTO v_organization_id, v_business_id, v_transaction_id
  FROM public.drive_finder_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  UPDATE public.drive_finder_runs SET subfolders_selected_count = p_subfolder_count
  WHERE id = p_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DRIVE_FINDER_FOLDERS_SELECTED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=v_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='drive_finder',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'subfolder_count',p_subfolder_count,
      'buffer_days',p_buffer_days,'subfolder_names',to_jsonb(p_subfolder_names)
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','RECORDED','run_id',p_run_id,'subfolder_count',p_subfolder_count
  );
END;
$function$
;

