CREATE OR REPLACE FUNCTION public.record_ai_tier3_event(p_action text, p_business_id uuid, p_invocation_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_allowed text[] := ARRAY['TIER_3_INVOKED','TIER_3_RESPONSE_RECEIVED','TIER_3_FAILED','TIER_3_BYPASS_ATTEMPT_BLOCKED'];
  v_biz public.business_entities%ROWTYPE;
  v_audit_kind audit.actor_kind_enum;
  v_actor_system text;
  v_audit_row audit.audit_events;
BEGIN
  IF p_action IS NULL OR p_business_id IS NULL THEN
    RAISE EXCEPTION 'record_ai_tier3_event: p_action and p_business_id required' USING ERRCODE = '22000';
  END IF;
  IF NOT (p_action = ANY(v_allowed)) THEN
    RAISE EXCEPTION 'record_ai_tier3_event: invalid action % (allowed: %)', p_action, v_allowed USING ERRCODE = '22023';
  END IF;
  IF jsonb_typeof(COALESCE(p_payload,'{}'::jsonb)) <> 'object' THEN
    RAISE EXCEPTION 'record_ai_tier3_event: p_payload must be a JSON object' USING ERRCODE = '22000';
  END IF;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_ai_tier3_event: business % not found', p_business_id USING ERRCODE = '22023';
  END IF;
  IF p_actor_user_id IS NULL THEN
    v_audit_kind := 'SYSTEM'::audit.actor_kind_enum; v_actor_system := 'tier3_dispatcher';
  ELSE
    v_audit_kind := 'USER'::audit.actor_kind_enum; v_actor_system := NULL;
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_audit_kind, p_action => p_action,
    p_subject_type => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
    p_subject_id => p_invocation_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
    p_business_id => p_business_id,
    p_reason => format('%s for gateway invocation %s', p_action, p_invocation_id),
    p_after_state => COALESCE(p_payload,'{}'::jsonb) || jsonb_build_object('invocation_id', p_invocation_id));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id, 'action', p_action);
END;
$function$
;

