CREATE OR REPLACE FUNCTION public.record_drive_finder_result_found(p_run_id uuid, p_drive_file_id text, p_file_name text, p_subfolder_name text, p_discovery_confidence numeric, p_document_type document_type_enum DEFAULT 'INVOICE'::document_type_enum, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_existing_doc uuid; v_source_extid text; v_new_doc_id uuid;
BEGIN
  IF p_drive_file_id IS NULL OR length(trim(p_drive_file_id)) = 0 THEN
    RAISE EXCEPTION 'DRIVE_FILE_ID_REQUIRED' USING errcode='check_violation';
  END IF;
  IF p_discovery_confidence IS NULL OR p_discovery_confidence < 0 OR p_discovery_confidence > 1 THEN
    RAISE EXCEPTION 'DISCOVERY_CONFIDENCE_OUT_OF_RANGE' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id, transaction_id
    INTO v_organization_id, v_business_id, v_transaction_id
  FROM public.drive_finder_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  v_source_extid := 'drive:' || p_drive_file_id;

  SELECT document_id INTO v_existing_doc
  FROM public.document_source_links
  WHERE business_id = v_business_id AND source_kind = 'DRIVE'
    AND source_external_id = v_source_extid
  LIMIT 1;

  IF FOUND THEN
    INSERT INTO public.drive_finder_results (
      organization_id, business_id, run_id, drive_file_id, file_name,
      subfolder_name, outcome, document_id
    ) VALUES (
      v_organization_id, v_business_id, p_run_id, p_drive_file_id, p_file_name,
      p_subfolder_name, 'DUPLICATE_SOURCE', v_existing_doc
    );

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='DRIVE_FINDER_RESULT_DUPLICATE_SOURCE',
      p_subject_type:='DOCUMENT'::audit.subject_type_enum,
      p_subject_id:=v_existing_doc,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='drive_finder',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'run_id',p_run_id,'drive_file_id',p_drive_file_id,
        'existing_document_id',v_existing_doc
      ),
      p_reason:=NULL, p_request_context:=p_context
    );

    UPDATE public.drive_finder_runs SET duplicate_count = duplicate_count + 1
    WHERE id = p_run_id;

    RETURN jsonb_build_object(
      'decision','DUPLICATE_SOURCE','run_id',p_run_id,
      'document_id',v_existing_doc,'drive_file_id',p_drive_file_id
    );
  END IF;

  INSERT INTO public.documents (
    organization_id, business_id, source, document_type,
    original_filename, discovery_reason, discovery_confidence
  ) VALUES (
    v_organization_id, v_business_id, 'DRIVE', p_document_type,
    p_file_name, 'drive_finder:' || COALESCE(p_subfolder_name,'root'),
    p_discovery_confidence
  ) RETURNING id INTO v_new_doc_id;

  INSERT INTO public.document_source_links (
    organization_id, business_id, document_id, source_kind,
    source_external_id, discovery_reason
  ) VALUES (
    v_organization_id, v_business_id, v_new_doc_id, 'DRIVE',
    v_source_extid, 'drive_finder:' || COALESCE(p_subfolder_name,'root')
  );

  INSERT INTO public.drive_finder_results (
    organization_id, business_id, run_id, drive_file_id, file_name,
    subfolder_name, outcome, document_id, discovery_confidence
  ) VALUES (
    v_organization_id, v_business_id, p_run_id, p_drive_file_id, p_file_name,
    p_subfolder_name, 'FOUND', v_new_doc_id, p_discovery_confidence
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DRIVE_FINDER_RESULT_FOUND',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=v_new_doc_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='drive_finder',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'drive_file_id',p_drive_file_id,
      'file_name',p_file_name,'subfolder_name',p_subfolder_name,
      'discovery_confidence',p_discovery_confidence,'document_id',v_new_doc_id
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  UPDATE public.drive_finder_runs SET found_count = found_count + 1
  WHERE id = p_run_id;

  RETURN jsonb_build_object(
    'decision','FOUND','run_id',p_run_id,'document_id',v_new_doc_id,
    'drive_file_id',p_drive_file_id,'discovery_confidence',p_discovery_confidence
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_run_ai_usage(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_by_tier jsonb; v_total_cost numeric(14,6); v_currencies text[]; v_call_count int;
BEGIN
  IF p_workflow_run_id IS NULL THEN
    RAISE EXCEPTION 'get_run_ai_usage: p_workflow_run_id required' USING ERRCODE = '22000';
  END IF;
  SELECT jsonb_agg(jsonb_build_object(
    'ai_tier', ai_tier::text, 'call_count', call_count,
    'total_input_tokens', total_input_tokens, 'total_output_tokens', total_output_tokens,
    'total_compute_seconds', total_compute_seconds, 'total_latency_ms', total_latency_ms,
    'total_cost_estimate', total_cost_estimate, 'currency', currency
    ) ORDER BY ai_tier::text),
    COALESCE(sum(total_cost_estimate), 0),
    array_agg(DISTINCT currency),
    COALESCE(sum(call_count), 0)::int
    INTO v_by_tier, v_total_cost, v_currencies, v_call_count
    FROM public.ai_usage_run_totals WHERE workflow_run_id = p_workflow_run_id;
  RETURN jsonb_build_object('ok', true, 'workflow_run_id', p_workflow_run_id,
    'call_count', v_call_count, 'by_tier', COALESCE(v_by_tier, '[]'::jsonb),
    'total_cost_estimate', v_total_cost,
    'currencies', COALESCE(to_jsonb(v_currencies), '[]'::jsonb),
    'mixed_currency_warning', CASE WHEN array_length(v_currencies, 1) > 1 THEN true ELSE false END);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_cache_prune_for_run(p_workflow_run_id uuid, p_reason text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_pruned int; v_biz_id uuid; v_org_id uuid;
  v_kind audit.actor_kind_enum; v_system text; v_audit audit.audit_events;
BEGIN
  IF p_workflow_run_id IS NULL THEN
    RAISE EXCEPTION 'ai_cache_prune_for_run: p_workflow_run_id required' USING ERRCODE='22000';
  END IF;
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'ai_cache_prune_for_run: p_reason non-empty required' USING ERRCODE='22000';
  END IF;
  SELECT business_id, organization_id INTO v_biz_id, v_org_id
    FROM public.ai_cache WHERE workflow_run_id = p_workflow_run_id LIMIT 1;
  DELETE FROM public.ai_cache WHERE workflow_run_id = p_workflow_run_id;
  GET DIAGNOSTICS v_pruned = ROW_COUNT;
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'ai_cache_pruner';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'AI_CACHE_PRUNED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_system, p_organization_id => v_org_id,
    p_business_id => v_biz_id,
    p_reason => format('AI cache pruned for run %s: %s', p_workflow_run_id, p_reason),
    p_after_state => jsonb_build_object(
      'workflow_run_id', p_workflow_run_id,
      'pruned_count', v_pruned, 'reason', p_reason));
  RETURN jsonb_build_object('ok', true,
    'workflow_run_id', p_workflow_run_id,
    'pruned_count', v_pruned,
    'audit_event_id', v_audit.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_business_cost_ceiling(p_actor_user_id uuid, p_business_id uuid, p_default_ceiling_per_run numeric, p_warning_threshold_pct numeric DEFAULT NULL::numeric, p_ceiling_currency text DEFAULT NULL::text, p_tier_2_gating_enabled boolean DEFAULT NULL::boolean)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_biz public.business_entities%ROWTYPE; v_perm jsonb; v_perm_dec text;
  v_before public.business_ai_config%ROWTYPE; v_after public.business_ai_config%ROWTYPE;
  v_reject_code text; v_reject_msg text; v_audit_row audit.audit_events;
BEGIN
  IF p_actor_user_id IS NULL OR p_business_id IS NULL THEN
    RAISE EXCEPTION 'update_business_cost_ceiling: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_default_ceiling_per_run IS NOT NULL AND p_default_ceiling_per_run <= 0 THEN
    v_reject_code := 'CEILING_MUST_BE_POSITIVE';
    v_reject_msg := 'default_ceiling_per_run must be > 0 (NULL to disable)';
  END IF;
  IF v_reject_code IS NULL AND p_warning_threshold_pct IS NOT NULL
     AND (p_warning_threshold_pct <= 0 OR p_warning_threshold_pct > 100) THEN
    v_reject_code := 'WARNING_PCT_OUT_OF_RANGE';
    v_reject_msg := 'warning_threshold_pct must be in (0, 100]';
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
    IF NOT FOUND THEN
      v_reject_code := 'BUSINESS_NOT_FOUND';
      v_reject_msg := format('business %s not found', p_business_id);
    END IF;
  END IF;
  IF v_reject_code IS NULL THEN
    v_perm := public.can_perform(p_actor_user_id => p_actor_user_id,
      p_surface => 'business_ai_config', p_action => 'update_cost_ceiling',
      p_resource => jsonb_build_object('business_id', p_business_id),
      p_business_id => p_business_id, p_organization_id => v_biz.organization_id);
    v_perm_dec := v_perm->>'decision';
    IF v_perm_dec = 'DENY' THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg := format('actor lacks permission (reason=%s)', v_perm->>'reason_code');
    ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'AI_COST_CONFIG_UPDATE_REJECTED',
      p_subject_type => 'BUSINESS_AI_CONFIG'::audit.subject_type_enum,
      p_subject_id => NULL, p_actor_user_id => p_actor_user_id,
      p_business_id => p_business_id, p_organization_id => v_biz.organization_id,
      p_reason => v_reject_msg,
      p_after_state => jsonb_build_object('rejection_code', v_reject_code,
        'business_id', p_business_id,
        'requested', jsonb_build_object(
          'default_ceiling_per_run', p_default_ceiling_per_run,
          'warning_threshold_pct', p_warning_threshold_pct,
          'ceiling_currency', p_ceiling_currency,
          'tier_2_gating_enabled', p_tier_2_gating_enabled)));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  SELECT * INTO v_before FROM public.business_ai_config WHERE business_id = p_business_id;
  INSERT INTO public.business_ai_config (
    business_id, default_ceiling_per_run, warning_threshold_pct, ceiling_currency,
    tier_2_gating_enabled, cost_ceiling_updated_at, cost_ceiling_updated_by_user_id,
    updated_by_user_id, updated_at
  ) VALUES (
    p_business_id, p_default_ceiling_per_run,
    COALESCE(p_warning_threshold_pct, 80.00),
    COALESCE(p_ceiling_currency, 'EUR'),
    COALESCE(p_tier_2_gating_enabled, false),
    clock_timestamp(), p_actor_user_id, p_actor_user_id, clock_timestamp()
  )
  ON CONFLICT (business_id) DO UPDATE
    SET default_ceiling_per_run = EXCLUDED.default_ceiling_per_run,
        warning_threshold_pct = COALESCE(EXCLUDED.warning_threshold_pct, public.business_ai_config.warning_threshold_pct),
        ceiling_currency = COALESCE(EXCLUDED.ceiling_currency, public.business_ai_config.ceiling_currency),
        tier_2_gating_enabled = COALESCE(EXCLUDED.tier_2_gating_enabled, public.business_ai_config.tier_2_gating_enabled),
        cost_ceiling_updated_at = clock_timestamp(),
        cost_ceiling_updated_by_user_id = EXCLUDED.cost_ceiling_updated_by_user_id,
        updated_at = clock_timestamp(),
        updated_by_user_id = EXCLUDED.updated_by_user_id
  RETURNING * INTO v_after;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_COST_CONFIG_UPDATED',
    p_subject_type => 'BUSINESS_AI_CONFIG'::audit.subject_type_enum,
    p_subject_id => v_after.id, p_actor_user_id => p_actor_user_id,
    p_business_id => p_business_id, p_organization_id => v_biz.organization_id,
    p_before_state => CASE WHEN v_before.id IS NOT NULL THEN
      jsonb_build_object('default_ceiling_per_run', v_before.default_ceiling_per_run,
        'warning_threshold_pct', v_before.warning_threshold_pct,
        'ceiling_currency', v_before.ceiling_currency,
        'tier_2_gating_enabled', v_before.tier_2_gating_enabled)
      ELSE NULL END,
    p_after_state => jsonb_build_object('business_id', p_business_id,
      'default_ceiling_per_run', v_after.default_ceiling_per_run,
      'warning_threshold_pct', v_after.warning_threshold_pct,
      'ceiling_currency', v_after.ceiling_currency,
      'tier_2_gating_enabled', v_after.tier_2_gating_enabled),
    p_reason => format('business_ai_config cost ceiling updated for business %s', p_business_id));
  RETURN jsonb_build_object('ok', true, 'business_id', p_business_id,
    'default_ceiling_per_run', v_after.default_ceiling_per_run,
    'warning_threshold_pct', v_after.warning_threshold_pct,
    'ceiling_currency', v_after.ceiling_currency,
    'tier_2_gating_enabled', v_after.tier_2_gating_enabled,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.start_statement_dedup(p_statement_upload_id uuid, p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_norm_done boolean;
  v_run_id uuid := public.gen_uuid_v7();
BEGIN
  IF p_statement_upload_id IS NULL OR p_workflow_run_id IS NULL THEN
    RAISE EXCEPTION 'start_statement_dedup: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id FOR SHARE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'start_statement_dedup: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  SELECT EXISTS (
    SELECT 1 FROM public.statement_normalization_runs
    WHERE statement_upload_id = v_upload.id
      AND status = 'COMPLETED'::public.statement_normalization_status_enum
  ) INTO v_norm_done;
  IF NOT v_norm_done THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NORMALIZATION_NOT_COMPLETED');
  END IF;
  BEGIN
    INSERT INTO public.statement_dedup_runs
      (id, statement_upload_id, business_id, bank_account_id, organization_id,
       workflow_run_id, status, started_at, created_at, updated_at)
    VALUES
      (v_run_id, v_upload.id, v_upload.business_id, v_upload.bank_account_id,
       v_upload.organization_id, p_workflow_run_id, 'STARTED',
       clock_timestamp(), clock_timestamp(), clock_timestamp());
  EXCEPTION WHEN unique_violation THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'DEDUP_ALREADY_IN_PROGRESS', 'statement_upload_id', v_upload.id);
  END;
  RETURN jsonb_build_object('ok', true, 'dedup_run_id', v_run_id, 'statement_upload_id', v_upload.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_run_cost_ceiling_state(p_workflow_run_id uuid, p_business_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_existing public.ai_cost_ceiling_runs%ROWTYPE; v_cfg public.business_ai_config%ROWTYPE; v_new public.ai_cost_ceiling_runs%ROWTYPE;
BEGIN
  IF p_workflow_run_id IS NULL OR p_business_id IS NULL THEN
    RAISE EXCEPTION 'ensure_run_cost_ceiling_state: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_existing FROM public.ai_cost_ceiling_runs WHERE workflow_run_id = p_workflow_run_id;
  IF FOUND THEN
    RETURN jsonb_build_object('ok', true, 'created', false,
      'effective_ceiling', v_existing.effective_ceiling, 'currency', v_existing.currency);
  END IF;
  SELECT * INTO v_cfg FROM public.business_ai_config WHERE business_id = p_business_id;
  IF NOT FOUND OR v_cfg.default_ceiling_per_run IS NULL THEN
    RETURN jsonb_build_object('ok', true, 'created', false, 'no_ceiling', true);
  END IF;
  INSERT INTO public.ai_cost_ceiling_runs (workflow_run_id, business_id, original_ceiling,
    effective_ceiling, warning_threshold_pct, currency, tier_2_gating_enabled)
  VALUES (p_workflow_run_id, p_business_id, v_cfg.default_ceiling_per_run,
    v_cfg.default_ceiling_per_run, v_cfg.warning_threshold_pct,
    v_cfg.ceiling_currency, v_cfg.tier_2_gating_enabled)
  RETURNING * INTO v_new;
  RETURN jsonb_build_object('ok', true, 'created', true,
    'workflow_run_id', v_new.workflow_run_id,
    'effective_ceiling', v_new.effective_ceiling,
    'warning_threshold_pct', v_new.warning_threshold_pct,
    'currency', v_new.currency,
    'tier_2_gating_enabled', v_new.tier_2_gating_enabled);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_statement_upload(p_actor_user_id uuid, p_business_id uuid, p_bank_account_id uuid, p_file_id text, p_file_hash text, p_file_format statement_file_format_enum, p_provider text, p_declared_period_start date, p_declared_period_end date, p_original_filename text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_biz public.business_entities%ROWTYPE; v_ba public.bank_accounts%ROWTYPE;
  v_perm jsonb; v_perm_dec text; v_reject_code text; v_reject_msg text;
  v_audit_row audit.audit_events; v_upload_id uuid;
  v_existing public.statement_uploads%ROWTYPE;
BEGIN
  IF p_actor_user_id IS NULL OR p_business_id IS NULL OR p_bank_account_id IS NULL
     OR p_file_id IS NULL OR p_file_hash IS NULL OR p_file_format IS NULL
     OR p_provider IS NULL OR p_declared_period_start IS NULL
     OR p_declared_period_end IS NULL OR p_original_filename IS NULL THEN
    RAISE EXCEPTION 'complete_statement_upload: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_file_hash !~ '^[0-9a-f]{64}$' THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'INVALID_HASH_FORMAT',
      'message', 'file_hash must be 64-char lowercase SHA-256 hex');
  END IF;
  IF p_provider NOT IN ('REVOLUT') THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'UNKNOWN_PROVIDER',
      'message', format('provider %s not supported in MVP', p_provider));
  END IF;
  IF p_declared_period_end < p_declared_period_start THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'INVALID_PERIOD');
  END IF;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('ok', false, 'reason', 'BUSINESS_NOT_FOUND'); END IF;
  SELECT * INTO v_ba FROM public.bank_accounts WHERE id = p_bank_account_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('ok', false, 'reason', 'BANK_ACCOUNT_NOT_FOUND'); END IF;
  IF v_ba.business_id <> p_business_id THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'BANK_ACCOUNT_TENANT_MISMATCH');
  END IF;
  v_perm := public.can_perform(p_actor_user_id => p_actor_user_id,
    p_surface => 'workflow_run', p_action => 'execute',
    p_resource => jsonb_build_object('action', 'statement_upload', 'bank_account_id', p_bank_account_id),
    p_business_id => p_business_id, p_organization_id => v_biz.organization_id);
  v_perm_dec := v_perm->>'decision';
  IF v_perm_dec = 'DENY' THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('actor lacks permission workflow_run:execute (reason=%s)', v_perm->>'reason_code');
  ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
    v_reject_code := 'PERMISSION_DENIED';
    v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'STATEMENT_UPLOAD_REJECTED_PERMISSION',
      p_subject_type => 'BANK_ACCOUNT'::audit.subject_type_enum,
      p_subject_id => p_bank_account_id, p_actor_user_id => p_actor_user_id,
      p_business_id => p_business_id, p_organization_id => v_biz.organization_id,
      p_reason => v_reject_msg,
      p_after_state => jsonb_build_object('rejection_code', v_reject_code,
        'bank_account_id', p_bank_account_id, 'file_hash', p_file_hash,
        'file_format', p_file_format::text));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  BEGIN
    INSERT INTO public.statement_uploads (
      organization_id, business_id, bank_account_id,
      file_id, file_hash, file_format, provider, original_filename,
      declared_period_start, declared_period_end,
      upload_status, uploaded_by
    ) VALUES (
      v_biz.organization_id, p_business_id, p_bank_account_id,
      p_file_id, p_file_hash, p_file_format, p_provider, p_original_filename,
      p_declared_period_start, p_declared_period_end,
      'UPLOADED'::public.statement_upload_status_enum, p_actor_user_id
    ) RETURNING id INTO v_upload_id;
  EXCEPTION WHEN unique_violation THEN
    SELECT * INTO v_existing FROM public.statement_uploads
      WHERE bank_account_id = p_bank_account_id AND file_hash = p_file_hash;
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'STATEMENT_UPLOAD_REJECTED_DUPLICATE_HASH',
      p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
      p_subject_id => v_existing.id, p_actor_user_id => p_actor_user_id,
      p_business_id => p_business_id, p_organization_id => v_biz.organization_id,
      p_reason => format('duplicate file_hash on bank_account %s (existing upload %s)', p_bank_account_id, v_existing.id),
      p_after_state => jsonb_build_object('rejection_code', 'DUPLICATE_HASH',
        'bank_account_id', p_bank_account_id, 'file_hash', p_file_hash,
        'existing_upload_id', v_existing.id, 'existing_uploaded_at', v_existing.uploaded_at,
        'attempted_filename', p_original_filename));
    RETURN jsonb_build_object('ok', false, 'reason', 'DUPLICATE_HASH',
      'existing_upload_id', v_existing.id, 'audit_event_id', v_audit_row.id);
  END;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'STATEMENT_UPLOAD_COMPLETED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_upload_id, p_actor_user_id => p_actor_user_id,
    p_business_id => p_business_id, p_organization_id => v_biz.organization_id,
    p_reason => format('statement upload %s landed for bank_account %s (%s file)', v_upload_id, p_bank_account_id, p_file_format),
    p_after_state => jsonb_build_object('upload_id', v_upload_id,
      'bank_account_id', p_bank_account_id, 'file_id', p_file_id, 'file_hash', p_file_hash,
      'file_format', p_file_format::text, 'provider', p_provider,
      'declared_period_start', p_declared_period_start, 'declared_period_end', p_declared_period_end,
      'original_filename', p_original_filename, 'upload_status', 'UPLOADED'));
  RETURN jsonb_build_object('ok', true, 'upload_id', v_upload_id,
    'upload_status', 'UPLOADED', 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_run_cost_ceiling(p_workflow_run_id uuid, p_business_id uuid, p_ai_tier ai_tier_enum, p_projected_cost_delta numeric)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_state public.ai_cost_ceiling_runs%ROWTYPE; v_biz public.business_entities%ROWTYPE;
  v_current_spend numeric(14,6); v_projected_total numeric(14,6); v_warning_floor numeric(14,6);
  v_decision text; v_audit_row audit.audit_events;
  v_warning_emitted_now boolean := false; v_is_first_hit boolean := false;
  v_filter_tier_2 boolean;
BEGIN
  IF p_workflow_run_id IS NULL OR p_business_id IS NULL OR p_ai_tier IS NULL OR p_projected_cost_delta IS NULL THEN
    RAISE EXCEPTION 'check_run_cost_ceiling: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_projected_cost_delta < 0 THEN
    RAISE EXCEPTION 'check_run_cost_ceiling: projected_cost_delta must be non-negative' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_state FROM public.ai_cost_ceiling_runs WHERE workflow_run_id = p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision', 'ALLOW', 'no_ceiling', true);
  END IF;
  IF p_ai_tier = 'LOCAL_LLM'::public.ai_tier_enum AND NOT v_state.tier_2_gating_enabled THEN
    RETURN jsonb_build_object('decision', 'ALLOW', 'tier_2_tracked_not_gated', true,
      'effective_ceiling', v_state.effective_ceiling, 'currency', v_state.currency);
  END IF;
  v_filter_tier_2 := v_state.tier_2_gating_enabled;
  SELECT COALESCE(SUM(cost_estimate), 0) INTO v_current_spend
    FROM public.ai_usage_records WHERE workflow_run_id = p_workflow_run_id
      AND validation_outcome = 'SUCCESS'::public.ai_gateway_result_variant_enum
      AND cache_hit = false
      AND (v_filter_tier_2 = true OR ai_tier <> 'LOCAL_LLM'::public.ai_tier_enum);
  v_projected_total := v_current_spend + p_projected_cost_delta;
  v_warning_floor := v_state.effective_ceiling * v_state.warning_threshold_pct / 100;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF v_projected_total < v_warning_floor THEN
    v_decision := 'ALLOW';
  ELSIF v_projected_total < v_state.effective_ceiling THEN
    v_decision := 'WARNING';
    IF v_state.warning_emitted_at IS NULL THEN
      UPDATE public.ai_cost_ceiling_runs SET warning_emitted_at = clock_timestamp(), updated_at = clock_timestamp()
        WHERE workflow_run_id = p_workflow_run_id;
      PERFORM audit.emit_audit(
        p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'AI_COST_WARNING',
        p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
        p_subject_id => p_workflow_run_id, p_actor_system => 'ai_cost_ceiling',
        p_organization_id => v_biz.organization_id, p_business_id => p_business_id,
        p_reason => format('AI cost ≥ %s%% of ceiling for run %s',
          v_state.warning_threshold_pct, p_workflow_run_id),
        p_after_state => jsonb_build_object('workflow_run_id', p_workflow_run_id,
          'current_spend', v_current_spend, 'projected_total', v_projected_total,
          'warning_floor', v_warning_floor, 'effective_ceiling', v_state.effective_ceiling,
          'currency', v_state.currency, 'triggering_tier', p_ai_tier::text));
      v_warning_emitted_now := true;
    END IF;
  ELSE
    IF v_state.first_override_granted_at IS NULL THEN
      v_decision := 'BLOCKED';
      v_is_first_hit := (v_state.first_ceiling_hit_at IS NULL);
    ELSE
      v_decision := 'REQUIRES_STEP_UP';
      v_is_first_hit := false;
    END IF;
    UPDATE public.ai_cost_ceiling_runs
      SET first_ceiling_hit_at = COALESCE(first_ceiling_hit_at, clock_timestamp()),
          last_ceiling_hit_at = clock_timestamp(), updated_at = clock_timestamp()
      WHERE workflow_run_id = p_workflow_run_id;
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'AI_COST_CEILING_HIT',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id => p_workflow_run_id, p_actor_system => 'ai_cost_ceiling',
      p_organization_id => v_biz.organization_id, p_business_id => p_business_id,
      p_reason => format('AI cost ceiling hit on run %s (first_hit=%s, decision=%s)',
        p_workflow_run_id, v_is_first_hit, v_decision),
      p_after_state => jsonb_build_object('workflow_run_id', p_workflow_run_id,
        'is_first_hit', v_is_first_hit, 'decision', v_decision,
        'current_spend', v_current_spend, 'projected_total', v_projected_total,
        'effective_ceiling', v_state.effective_ceiling,
        'override_count', v_state.override_count, 'currency', v_state.currency,
        'triggering_tier', p_ai_tier::text));
  END IF;
  RETURN jsonb_build_object('decision', v_decision,
    'current_spend', v_current_spend, 'projected_total', v_projected_total,
    'effective_ceiling', v_state.effective_ceiling,
    'original_ceiling', v_state.original_ceiling,
    'warning_threshold_pct', v_state.warning_threshold_pct,
    'warning_floor', v_warning_floor, 'currency', v_state.currency,
    'warning_emitted_now', v_warning_emitted_now,
    'is_first_hit', v_is_first_hit, 'override_count', v_state.override_count);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.classify_and_record_dedup_row(p_dedup_run_id uuid, p_normalized_row_id uuid, p_soft_window_days integer DEFAULT 30, p_amount_tolerance_cents integer DEFAULT 1, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.statement_dedup_runs%ROWTYPE;
  v_norm public.statement_normalized_rows%ROWTYPE;
  v_existing_class public.statement_dedup_row_classifications%ROWTYPE;
  v_match_exact public.transactions%ROWTYPE;
  v_match_within public.statement_dedup_row_classifications%ROWTYPE;
  v_match_soft public.transactions%ROWTYPE;
  v_classification_id uuid := public.gen_uuid_v7();
  v_transaction_id uuid;
  v_review_issue_id uuid;
  v_matched_tx_id uuid;
  v_matched_tx_upload_id uuid;
  v_within_batch boolean := false;
  v_dedup_status public.transaction_dedup_status_enum;
  v_audit_action text;
  v_source_row_index int;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
  v_card_payload jsonb; v_issue_type text; v_title text; v_description text;
  v_signed_amount numeric;
BEGIN
  IF p_dedup_run_id IS NULL OR p_normalized_row_id IS NULL THEN
    RAISE EXCEPTION 'classify_and_record_dedup_row: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_run FROM public.statement_dedup_runs WHERE id = p_dedup_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'classify_and_record_dedup_row: dedup_run % not found', p_dedup_run_id USING ERRCODE='02000';
  END IF;
  IF v_run.status <> 'STARTED'::public.statement_dedup_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'DEDUP_NOT_STARTED', 'current_status', v_run.status::text);
  END IF;
  SELECT * INTO v_existing_class FROM public.statement_dedup_row_classifications
    WHERE dedup_run_id = p_dedup_run_id AND normalized_row_id = p_normalized_row_id;
  IF FOUND THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'dedup_status', v_existing_class.dedup_status::text,
      'transaction_id', v_existing_class.transaction_id,
      'review_issue_id', v_existing_class.review_issue_id,
      'matched_transaction_id', v_existing_class.matched_transaction_id,
      'matched_within_batch', v_existing_class.matched_within_batch);
  END IF;
  SELECT * INTO v_norm FROM public.statement_normalized_rows WHERE id = p_normalized_row_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'classify_and_record_dedup_row: normalized_row % not found', p_normalized_row_id USING ERRCODE='02000';
  END IF;
  IF v_norm.statement_upload_id <> v_run.statement_upload_id THEN
    RAISE EXCEPTION 'classify_and_record_dedup_row: normalized_row belongs to a different upload (% vs %)',
      v_norm.statement_upload_id, v_run.statement_upload_id USING ERRCODE='22023';
  END IF;

  v_signed_amount := CASE v_norm.direction
                       WHEN 'OUT'::public.transaction_direction_enum THEN -v_norm.amount
                       ELSE v_norm.amount
                     END;

  SELECT * INTO v_match_exact FROM public.transactions
    WHERE business_id = v_run.business_id AND bank_account_id = v_run.bank_account_id
      AND source_row_hash = v_norm.source_row_hash LIMIT 1;
  IF FOUND THEN
    v_dedup_status := 'DUPLICATE_EXACT'; v_matched_tx_id := v_match_exact.id;
    v_matched_tx_upload_id := v_match_exact.statement_upload_id;
    v_audit_action := 'TRANSACTION_DEDUP_EXACT_DUPLICATE';
  ELSE
    SELECT c.* INTO v_match_within FROM public.statement_dedup_row_classifications c
      JOIN public.statement_normalized_rows n ON n.id = c.normalized_row_id
      WHERE c.dedup_run_id = p_dedup_run_id AND c.dedup_status = 'NEW'
        AND n.source_row_hash = v_norm.source_row_hash LIMIT 1;
    IF FOUND THEN
      v_dedup_status := 'DUPLICATE_EXACT'; v_matched_tx_id := v_match_within.transaction_id;
      v_matched_tx_upload_id := v_run.statement_upload_id;
      v_audit_action := 'TRANSACTION_DEDUP_EXACT_DUPLICATE';
    ELSE
      SELECT * INTO v_match_soft FROM public.transactions
        WHERE business_id = v_run.business_id AND bank_account_id = v_run.bank_account_id
          AND transaction_fingerprint = v_norm.transaction_fingerprint LIMIT 1;
      IF FOUND THEN
        v_matched_tx_id := v_match_soft.id;
        v_matched_tx_upload_id := v_match_soft.statement_upload_id;
        IF abs(v_match_soft.transaction_date - v_norm.transaction_date) <= p_soft_window_days
           AND abs(round((abs(v_match_soft.amount) - v_norm.amount) * 100)::int) <= p_amount_tolerance_cents THEN
          v_dedup_status := 'DUPLICATE_PROBABLE'; v_audit_action := 'TRANSACTION_DEDUP_PROBABLE_DUPLICATE';
        ELSE
          v_dedup_status := 'NEEDS_REVIEW'; v_audit_action := 'TRANSACTION_DEDUP_NEEDS_REVIEW';
        END IF;
      ELSE
        v_dedup_status := 'NEW'; v_audit_action := 'TRANSACTION_DEDUP_NEW';
      END IF;
    END IF;
  END IF;

  IF v_matched_tx_upload_id IS NOT NULL AND v_matched_tx_upload_id = v_run.statement_upload_id THEN
    v_within_batch := true;
  END IF;

  SELECT COALESCE(MIN(p.source_row_index), 0) INTO v_source_row_index
    FROM public.statement_parsed_rows p WHERE p.id = ANY (v_norm.parsed_row_ids);

  IF v_dedup_status = 'NEW' THEN
    v_transaction_id := public.gen_uuid_v7();
    INSERT INTO public.transactions
      (id, organization_id, business_id, bank_account_id, statement_upload_id,
       source_row_index, source_row_hash, transaction_fingerprint,
       transaction_date, booking_date, amount, currency, direction,
       transaction_type, normalized_description, counterparty_name,
       counterparty_identifier_masked, counterparty_identifier_encrypted, reference,
       fx_paired_legs, dedup_status, secondary_tags,
       classification_status, match_status, ledger_status, review_status,
       created_at, updated_at)
    VALUES
      (v_transaction_id, v_run.organization_id, v_run.business_id, v_run.bank_account_id,
       v_run.statement_upload_id, v_source_row_index, v_norm.source_row_hash, v_norm.transaction_fingerprint,
       v_norm.transaction_date, v_norm.booking_date, v_signed_amount, v_norm.currency, v_norm.direction,
       COALESCE(v_norm.transaction_type_candidate, 'UNKNOWN'::public.transaction_type_enum),
       v_norm.normalized_description, v_norm.counterparty_name,
       v_norm.counterparty_identifier_masked, v_norm.counterparty_identifier_encrypted, v_norm.reference,
       v_norm.fx_paired_legs, 'NEW'::public.transaction_dedup_status_enum, '[]'::jsonb,
       'PENDING'::public.transaction_classification_status_enum,
       'UNMATCHED'::public.transaction_match_status_enum,
       'PENDING'::public.transaction_ledger_status_enum,
       'NONE'::public.transaction_review_status_enum,
       clock_timestamp(), clock_timestamp());
  ELSIF v_dedup_status IN ('DUPLICATE_PROBABLE','NEEDS_REVIEW') THEN
    v_review_issue_id := public.gen_uuid_v7();
    IF v_dedup_status = 'DUPLICATE_PROBABLE' THEN
      v_issue_type := 'bank_pipeline.duplicate_probable';
      v_title := 'Possible duplicate bank statement row';
      v_description := format('A row in this statement upload matches an existing transaction (fingerprint %s). Confirm whether to keep the new row, mark it as a duplicate, or edit and confirm.',
                              left(v_norm.transaction_fingerprint, 12));
    ELSE
      v_issue_type := 'bank_pipeline.duplicate_needs_review';
      v_title := 'Ambiguous duplicate bank statement row';
      v_description := format('A row in this statement upload has the same fingerprint as an existing transaction but differs in date or amount beyond the auto-dedup tolerance. Manual review required.');
    END IF;
    v_card_payload := jsonb_build_object(
      'normalized_row_id', v_norm.id, 'statement_upload_id', v_run.statement_upload_id,
      'source_row_index', v_source_row_index,
      'candidate', jsonb_build_object(
        'transaction_date', v_norm.transaction_date, 'amount', v_norm.amount,
        'currency', v_norm.currency, 'direction', v_norm.direction::text,
        'description', v_norm.normalized_description, 'counterparty', v_norm.counterparty_name),
      'matched_transaction', jsonb_build_object(
        'id', v_match_soft.id, 'transaction_date', v_match_soft.transaction_date,
        'amount', v_match_soft.amount, 'currency', v_match_soft.currency),
      'dedup_status', v_dedup_status::text);
    INSERT INTO public.review_issues
      (id, organization_id, business_id, workflow_run_id, transaction_id,
       issue_type, issue_group, severity,
       plain_language_title, plain_language_description,
       card_payload_json, card_content_tier_used, card_content_fallback_applied,
       status, created_at, updated_at)
    VALUES
      (v_review_issue_id, v_run.organization_id, v_run.business_id, v_run.workflow_run_id,
       v_matched_tx_id,
       v_issue_type, 'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
       'MEDIUM'::public.review_issue_severity_enum,
       v_title, v_description,
       v_card_payload, 'NONE'::public.review_issue_card_content_tier_enum, false,
       'OPEN'::public.review_issue_status_enum,
       clock_timestamp(), clock_timestamp());
  END IF;

  INSERT INTO public.statement_dedup_row_classifications
    (id, dedup_run_id, normalized_row_id, dedup_status,
     transaction_id, review_issue_id, matched_transaction_id,
     matched_within_batch, classified_at)
  VALUES
    (v_classification_id, p_dedup_run_id, p_normalized_row_id, v_dedup_status,
     v_transaction_id, v_review_issue_id, v_matched_tx_id,
     v_within_batch, clock_timestamp());

  IF v_dedup_status = 'NEW' THEN
    UPDATE public.statement_dedup_runs SET new_count = new_count + 1, updated_at = clock_timestamp() WHERE id = p_dedup_run_id;
  ELSIF v_dedup_status = 'DUPLICATE_EXACT' THEN
    UPDATE public.statement_dedup_runs SET exact_duplicate_count = exact_duplicate_count + 1, updated_at = clock_timestamp() WHERE id = p_dedup_run_id;
  ELSIF v_dedup_status = 'DUPLICATE_PROBABLE' THEN
    UPDATE public.statement_dedup_runs SET probable_duplicate_count = probable_duplicate_count + 1, updated_at = clock_timestamp() WHERE id = p_dedup_run_id;
  ELSIF v_dedup_status = 'NEEDS_REVIEW' THEN
    UPDATE public.statement_dedup_runs SET needs_review_count = needs_review_count + 1, updated_at = clock_timestamp() WHERE id = p_dedup_run_id;
  END IF;

  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_dedup';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => v_audit_action,
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_run.statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_run.organization_id, p_business_id => v_run.business_id,
    p_after_state => jsonb_build_object(
      'dedup_run_id', v_run.id, 'normalized_row_id', v_norm.id,
      'transaction_id', v_transaction_id, 'review_issue_id', v_review_issue_id,
      'matched_transaction_id', v_matched_tx_id, 'matched_within_batch', v_within_batch,
      'dedup_status', v_dedup_status::text, 'source_row_index', v_source_row_index,
      'transaction_fingerprint', v_norm.transaction_fingerprint,
      'signed_amount', v_signed_amount),
    p_reason => format('dedup: %s (row %s)', v_dedup_status::text, v_source_row_index));

  RETURN jsonb_build_object('ok', true,
    'dedup_status', v_dedup_status::text,
    'transaction_id', v_transaction_id,
    'review_issue_id', v_review_issue_id,
    'matched_transaction_id', v_matched_tx_id,
    'matched_within_batch', v_within_batch,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.request_cost_ceiling_override(p_actor_user_id uuid, p_workflow_run_id uuid, p_business_id uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_biz public.business_entities%ROWTYPE; v_audit_row audit.audit_events;
BEGIN
  IF p_actor_user_id IS NULL OR p_workflow_run_id IS NULL OR p_business_id IS NULL
     OR p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'request_cost_ceiling_override: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'request_cost_ceiling_override: business % not found', p_business_id USING ERRCODE='22023';
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_COST_OVERRIDE_REQUESTED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_organization_id => v_biz.organization_id, p_business_id => p_business_id,
    p_reason => p_reason,
    p_after_state => jsonb_build_object('workflow_run_id', p_workflow_run_id, 'requested_reason', p_reason));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.grant_cost_ceiling_override(p_actor_user_id uuid, p_workflow_run_id uuid, p_business_id uuid, p_step_up_token_id uuid, p_extended_ceiling numeric DEFAULT NULL::numeric, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_biz public.business_entities%ROWTYPE; v_perm jsonb; v_perm_dec text;
  v_state public.ai_cost_ceiling_runs%ROWTYPE; v_step_up record;
  v_new_ceiling numeric(14,6); v_reject_code text; v_reject_msg text; v_audit_row audit.audit_events;
BEGIN
  IF p_actor_user_id IS NULL OR p_workflow_run_id IS NULL OR p_business_id IS NULL OR p_step_up_token_id IS NULL THEN
    RAISE EXCEPTION 'grant_cost_ceiling_override: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'grant_cost_ceiling_override: reason non-empty required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    v_reject_code := 'BUSINESS_NOT_FOUND';
    v_reject_msg := format('business %s not found', p_business_id);
  END IF;
  IF v_reject_code IS NULL THEN
    v_perm := public.can_perform(p_actor_user_id => p_actor_user_id,
      p_surface => 'ai_cost_override', p_action => 'grant',
      p_resource => jsonb_build_object('workflow_run_id', p_workflow_run_id),
      p_business_id => p_business_id, p_organization_id => v_biz.organization_id);
    v_perm_dec := v_perm->>'decision';
    IF v_perm_dec = 'DENY' THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg := format('actor lacks permission (reason=%s)', v_perm->>'reason_code');
    ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP') THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg := format('unexpected can_perform decision: %s', v_perm_dec);
    END IF;
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT * INTO v_state FROM public.ai_cost_ceiling_runs WHERE workflow_run_id = p_workflow_run_id;
    IF NOT FOUND THEN
      v_reject_code := 'NO_CEILING_FOR_RUN';
      v_reject_msg := format('run %s has no ceiling state', p_workflow_run_id);
    END IF;
  END IF;
  IF v_reject_code IS NULL THEN
    SELECT * INTO v_step_up FROM public.consume_step_up_token(
      p_token_id => p_step_up_token_id, p_business_id => p_business_id,
      p_surface => 'ai_cost_override', p_action_id => NULL);
    IF NOT v_step_up.consumed THEN
      v_reject_code := 'STEP_UP_FAILED';
      v_reject_msg := format('step-up token consumption failed: %s', v_step_up.reason);
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_COST_OVERRIDE_DENIED',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
      p_organization_id => v_biz.organization_id, p_business_id => p_business_id,
      p_reason => v_reject_msg,
      p_after_state => jsonb_build_object('rejection_code', v_reject_code,
        'workflow_run_id', p_workflow_run_id,
        'requested_extended_ceiling', p_extended_ceiling, 'requested_reason', p_reason));
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code,
      'message', v_reject_msg, 'audit_event_id', v_audit_row.id);
  END IF;
  v_new_ceiling := COALESCE(p_extended_ceiling, v_state.effective_ceiling + v_state.original_ceiling);
  IF v_new_ceiling <= v_state.effective_ceiling THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_COST_OVERRIDE_DENIED',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
      p_organization_id => v_biz.organization_id, p_business_id => p_business_id,
      p_reason => format('extended_ceiling (%s) must exceed current (%s)', v_new_ceiling, v_state.effective_ceiling),
      p_after_state => jsonb_build_object('rejection_code', 'CEILING_NOT_INCREASED',
        'workflow_run_id', p_workflow_run_id,
        'effective_ceiling', v_state.effective_ceiling, 'requested', v_new_ceiling));
    RETURN jsonb_build_object('ok', false, 'reason', 'CEILING_NOT_INCREASED',
      'audit_event_id', v_audit_row.id);
  END IF;
  UPDATE public.ai_cost_ceiling_runs
    SET effective_ceiling = v_new_ceiling, override_count = override_count + 1,
        first_override_granted_at = COALESCE(first_override_granted_at, clock_timestamp()),
        last_override_granted_at = clock_timestamp(),
        last_override_granted_by_user_id = p_actor_user_id, updated_at = clock_timestamp()
    WHERE workflow_run_id = p_workflow_run_id;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'AI_COST_OVERRIDE_GRANTED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_organization_id => v_biz.organization_id, p_business_id => p_business_id,
    p_before_state => jsonb_build_object('effective_ceiling', v_state.effective_ceiling,
      'override_count', v_state.override_count),
    p_after_state => jsonb_build_object('workflow_run_id', p_workflow_run_id,
      'effective_ceiling', v_new_ceiling, 'override_count', v_state.override_count + 1,
      'step_up_token_id', p_step_up_token_id, 'reason', p_reason),
    p_reason => format('AI cost ceiling override granted for run %s (%s → %s)',
      p_workflow_run_id, v_state.effective_ceiling, v_new_ceiling));
  RETURN jsonb_build_object('ok', true, 'workflow_run_id', p_workflow_run_id,
    'previous_effective_ceiling', v_state.effective_ceiling,
    'new_effective_ceiling', v_new_ceiling,
    'override_count', v_state.override_count + 1, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.deny_cost_ceiling_override(p_actor_user_id uuid, p_workflow_run_id uuid, p_business_id uuid, p_reason text)
