;

CREATE OR REPLACE FUNCTION public.make_ai_cache_key(p_tool_name text, p_prompt_id text, p_prompt_version text, p_policy_version text, p_input jsonb)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE PARALLEL SAFE
 SET search_path TO 'public', 'audit', 'extensions', 'pg_temp'
AS $function$
DECLARE v_canonical text;
BEGIN
  IF p_tool_name IS NULL OR p_input IS NULL THEN
    RAISE EXCEPTION 'make_ai_cache_key: p_tool_name and p_input required' USING ERRCODE='22000';
  END IF;
  v_canonical := p_tool_name || E'\x1f'
              || COALESCE(p_prompt_id, '')      || E'\x1f'
              || COALESCE(p_prompt_version, '') || E'\x1f'
              || COALESCE(p_policy_version, '') || E'\x1f'
              || audit.canonical_jsonb(p_input);
  RETURN encode(extensions.digest(v_canonical, 'sha256'), 'hex');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_run_cost_ceiling_state(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_state public.ai_cost_ceiling_runs%ROWTYPE; v_current_spend_t3 numeric(14,6); v_current_spend_all numeric(14,6);
BEGIN
  IF p_workflow_run_id IS NULL THEN
    RAISE EXCEPTION 'get_run_cost_ceiling_state: p_workflow_run_id required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_state FROM public.ai_cost_ceiling_runs WHERE workflow_run_id = p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', true, 'no_ceiling', true, 'workflow_run_id', p_workflow_run_id);
  END IF;
  SELECT COALESCE(SUM(cost_estimate), 0) INTO v_current_spend_t3
    FROM public.ai_usage_records WHERE workflow_run_id = p_workflow_run_id
      AND validation_outcome = 'SUCCESS'::public.ai_gateway_result_variant_enum
      AND cache_hit = false AND ai_tier <> 'LOCAL_LLM'::public.ai_tier_enum;
  SELECT COALESCE(SUM(cost_estimate), 0) INTO v_current_spend_all
    FROM public.ai_usage_records WHERE workflow_run_id = p_workflow_run_id
      AND validation_outcome = 'SUCCESS'::public.ai_gateway_result_variant_enum
      AND cache_hit = false;
  RETURN jsonb_build_object('ok', true,
    'workflow_run_id', v_state.workflow_run_id, 'business_id', v_state.business_id,
    'original_ceiling', v_state.original_ceiling, 'effective_ceiling', v_state.effective_ceiling,
    'warning_threshold_pct', v_state.warning_threshold_pct, 'currency', v_state.currency,
    'tier_2_gating_enabled', v_state.tier_2_gating_enabled,
    'current_spend_tier_3', v_current_spend_t3, 'current_spend_all_tiers', v_current_spend_all,
    'gated_spend', CASE WHEN v_state.tier_2_gating_enabled THEN v_current_spend_all ELSE v_current_spend_t3 END,
    'warning_emitted_at', v_state.warning_emitted_at,
    'first_ceiling_hit_at', v_state.first_ceiling_hit_at,
    'last_ceiling_hit_at', v_state.last_ceiling_hit_at,
    'override_count', v_state.override_count,
    'first_override_granted_at', v_state.first_override_granted_at,
    'last_override_granted_at', v_state.last_override_granted_at);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_cache_lookup(p_workflow_run_id uuid, p_business_id uuid, p_organization_id uuid, p_cache_key text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_row public.ai_cache%ROWTYPE; v_kind audit.actor_kind_enum; v_system text; v_audit audit.audit_events;
BEGIN
  IF p_workflow_run_id IS NULL OR p_business_id IS NULL OR p_organization_id IS NULL OR p_cache_key IS NULL THEN
    RAISE EXCEPTION 'ai_cache_lookup: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_row FROM public.ai_cache
    WHERE workflow_run_id = p_workflow_run_id AND cache_key = p_cache_key FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', true, 'hit', false);
  END IF;
  UPDATE public.ai_cache SET hit_count = hit_count + 1, last_hit_at = clock_timestamp()
    WHERE id = v_row.id RETURNING * INTO v_row;
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'ai_cache';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'AI_CACHE_HIT',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_system, p_organization_id => p_organization_id,
    p_business_id => p_business_id,
    p_reason => format('AI cache hit on run %s (cache_id %s, hit_count %s)',
      p_workflow_run_id, v_row.id, v_row.hit_count),
    p_after_state => jsonb_build_object(
      'cache_id', v_row.id, 'workflow_run_id', p_workflow_run_id,
      'cache_key', v_row.cache_key, 'tool_name', v_row.tool_name,
      'prompt_id', v_row.prompt_id, 'prompt_version', v_row.prompt_version,
      'policy_version', v_row.policy_version, 'hit_count', v_row.hit_count));
  RETURN jsonb_build_object('ok', true, 'hit', true,
    'cache_id', v_row.id, 'response', v_row.response,
    'tool_name', v_row.tool_name, 'prompt_id', v_row.prompt_id,
    'prompt_version', v_row.prompt_version, 'policy_version', v_row.policy_version,
    'hit_count', v_row.hit_count, 'audit_event_id', v_audit.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_cache_store(p_workflow_run_id uuid, p_business_id uuid, p_organization_id uuid, p_cache_key text, p_tool_name text, p_response jsonb, p_prompt_id text DEFAULT NULL::text, p_prompt_version text DEFAULT NULL::text, p_policy_version text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_id uuid; v_kind audit.actor_kind_enum; v_system text; v_audit audit.audit_events;
BEGIN
  IF p_workflow_run_id IS NULL OR p_business_id IS NULL OR p_organization_id IS NULL
     OR p_cache_key IS NULL OR p_tool_name IS NULL OR p_response IS NULL THEN
    RAISE EXCEPTION 'ai_cache_store: required params missing' USING ERRCODE='22000';
  END IF;
  IF jsonb_typeof(p_response) <> 'object' THEN
    RAISE EXCEPTION 'ai_cache_store: p_response must be a JSON object' USING ERRCODE='22023';
  END IF;
  INSERT INTO public.ai_cache (
    organization_id, business_id, workflow_run_id, cache_key,
    tool_name, prompt_id, prompt_version, policy_version, response
  ) VALUES (
    p_organization_id, p_business_id, p_workflow_run_id, p_cache_key,
    p_tool_name, p_prompt_id, p_prompt_version, p_policy_version, p_response
  )
  ON CONFLICT (workflow_run_id, cache_key) DO NOTHING
  RETURNING id INTO v_id;
  IF v_id IS NULL THEN
    RETURN jsonb_build_object('ok', true, 'stored', false, 'reason', 'ALREADY_CACHED');
  END IF;
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'ai_cache';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'AI_CACHE_STORED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_system, p_organization_id => p_organization_id,
    p_business_id => p_business_id,
    p_reason => format('AI cache stored on run %s (cache_id %s, tool %s)',
      p_workflow_run_id, v_id, p_tool_name),
    p_after_state => jsonb_build_object(
      'cache_id', v_id, 'workflow_run_id', p_workflow_run_id,
      'cache_key', p_cache_key, 'tool_name', p_tool_name,
      'prompt_id', p_prompt_id, 'prompt_version', p_prompt_version,
      'policy_version', p_policy_version));
  RETURN jsonb_build_object('ok', true, 'stored', true,
    'cache_id', v_id, 'audit_event_id', v_audit.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_plain_language_event(p_action text, p_business_id uuid, p_workflow_run_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_allowed text[] := ARRAY['PLAIN_LANGUAGE_GENERATED','PLAIN_LANGUAGE_GENERATION_FAILED','PLAIN_LANGUAGE_FALLBACK_USED'];
  v_biz public.business_entities%ROWTYPE;
  v_audit_kind audit.actor_kind_enum; v_actor_system text;
  v_audit_row audit.audit_events;
BEGIN
  IF p_action IS NULL OR p_business_id IS NULL THEN
    RAISE EXCEPTION 'record_plain_language_event: p_action and p_business_id required' USING ERRCODE = '22000';
  END IF;
  IF NOT (p_action = ANY(v_allowed)) THEN
    RAISE EXCEPTION 'record_plain_language_event: invalid action % (allowed: %)', p_action, v_allowed USING ERRCODE = '22023';
  END IF;
  IF jsonb_typeof(COALESCE(p_payload,'{}'::jsonb)) <> 'object' THEN
    RAISE EXCEPTION 'record_plain_language_event: p_payload must be a JSON object' USING ERRCODE = '22000';
  END IF;
  SELECT * INTO v_biz FROM public.business_entities WHERE id = p_business_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_plain_language_event: business % not found', p_business_id USING ERRCODE = '22023';
  END IF;
  IF p_actor_user_id IS NULL THEN
    v_audit_kind := 'SYSTEM'::audit.actor_kind_enum; v_actor_system := 'plain_language';
  ELSE
    v_audit_kind := 'USER'::audit.actor_kind_enum; v_actor_system := NULL;
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_audit_kind, p_action => p_action,
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_actor_system, p_organization_id => v_biz.organization_id,
    p_business_id => p_business_id,
    p_reason => format('%s for workflow run %s', p_action, p_workflow_run_id),
    p_after_state => COALESCE(p_payload,'{}'::jsonb) || jsonb_build_object('workflow_run_id', p_workflow_run_id));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id, 'action', p_action);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.start_end_scan(p_workflow_run_id uuid, p_business_id uuid, p_organization_id uuid, p_is_rescan boolean DEFAULT false, p_affected_entity_kind text DEFAULT NULL::text, p_affected_entity_ids uuid[] DEFAULT NULL::uuid[], p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_scan_id uuid; v_kind audit.actor_kind_enum; v_system text; v_audit_row audit.audit_events;
BEGIN
  IF p_workflow_run_id IS NULL OR p_business_id IS NULL OR p_organization_id IS NULL THEN
    RAISE EXCEPTION 'start_end_scan: required params missing' USING ERRCODE='22000';
  END IF;
  INSERT INTO public.end_scan_runs (workflow_run_id, business_id, organization_id,
    is_rescan, affected_entity_kind, affected_entity_ids)
  VALUES (p_workflow_run_id, p_business_id, p_organization_id,
    p_is_rescan, p_affected_entity_kind, p_affected_entity_ids)
  RETURNING id INTO v_scan_id;
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'end_scan';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'END_SCAN_STARTED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_workflow_run_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_system, p_organization_id => p_organization_id,
    p_business_id => p_business_id,
    p_reason => format('End-scan %sstarted for run %s',
      CASE WHEN p_is_rescan THEN 're-' ELSE '' END, p_workflow_run_id),
    p_after_state => jsonb_build_object(
      'scan_id', v_scan_id, 'workflow_run_id', p_workflow_run_id,
      'is_rescan', p_is_rescan, 'affected_entity_kind', p_affected_entity_kind,
      'affected_entity_ids', COALESCE(to_jsonb(p_affected_entity_ids), 'null'::jsonb)));
  RETURN jsonb_build_object('ok', true, 'scan_id', v_scan_id,
    'is_rescan', p_is_rescan, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_end_scan_check(p_scan_id uuid, p_check_name text, p_finding_count integer DEFAULT 0, p_deterministic boolean DEFAULT true, p_duration_ms integer DEFAULT NULL::integer, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_scan public.end_scan_runs%ROWTYPE; v_kind audit.actor_kind_enum; v_system text; v_audit_row audit.audit_events;
BEGIN
  IF p_scan_id IS NULL OR p_check_name IS NULL THEN
    RAISE EXCEPTION 'record_end_scan_check: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_check_name !~ '^[a-z][a-z0-9_]*\.[a-z][a-z0-9_]*$' THEN
    RAISE EXCEPTION 'record_end_scan_check: check_name must be namespaced; got %', p_check_name USING ERRCODE='22023';
  END IF;
  IF p_finding_count < 0 THEN
    RAISE EXCEPTION 'record_end_scan_check: finding_count must be non-negative' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_scan FROM public.end_scan_runs WHERE id = p_scan_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_end_scan_check: scan % not found', p_scan_id USING ERRCODE='22023';
  END IF;
  IF v_scan.status <> 'STARTED'::public.end_scan_status_enum THEN
    RAISE EXCEPTION 'record_end_scan_check: scan % in terminal state %', p_scan_id, v_scan.status USING ERRCODE='22023';
  END IF;
  UPDATE public.end_scan_runs SET checks_ran_count = checks_ran_count + 1 WHERE id = p_scan_id;
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'end_scan';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'END_SCAN_CHECK_RAN',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => v_scan.workflow_run_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_scan.organization_id, p_business_id => v_scan.business_id,
    p_reason => format('end-scan check %s ran (%s findings)', p_check_name, p_finding_count),
    p_after_state => jsonb_build_object('scan_id', p_scan_id,
      'workflow_run_id', v_scan.workflow_run_id, 'check_name', p_check_name,
      'finding_count', p_finding_count, 'deterministic', p_deterministic,
      'duration_ms', p_duration_ms));
  RETURN jsonb_build_object('ok', true, 'scan_id', p_scan_id,
    'checks_ran_count', v_scan.checks_ran_count + 1, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.raise_end_scan_issue(p_scan_id uuid, p_issue_type text, p_issue_group review_issue_group_enum, p_severity review_issue_severity_enum, p_plain_language_title text, p_plain_language_description text, p_recommended_action text DEFAULT NULL::text, p_transaction_id uuid DEFAULT NULL::uuid, p_document_id uuid DEFAULT NULL::uuid, p_match_record_id uuid DEFAULT NULL::uuid, p_draft_ledger_entry_id uuid DEFAULT NULL::uuid, p_card_payload_json jsonb DEFAULT '{}'::jsonb, p_card_content_tier_used review_issue_card_content_tier_enum DEFAULT 'NONE'::review_issue_card_content_tier_enum, p_card_content_fallback_applied boolean DEFAULT false, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_scan public.end_scan_runs%ROWTYPE; v_issue_id uuid; v_sev_key text; v_counts jsonb;
  v_kind audit.actor_kind_enum; v_system text; v_audit_row audit.audit_events;
BEGIN
  IF p_scan_id IS NULL OR p_issue_type IS NULL OR p_issue_group IS NULL OR p_severity IS NULL
     OR p_plain_language_title IS NULL OR p_plain_language_description IS NULL THEN
    RAISE EXCEPTION 'raise_end_scan_issue: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_issue_type !~ '^[a-z][a-z0-9_]*\.[a-z][a-z0-9_]*$' THEN
    RAISE EXCEPTION 'raise_end_scan_issue: issue_type must be namespaced; got %', p_issue_type USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_scan FROM public.end_scan_runs WHERE id = p_scan_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'raise_end_scan_issue: scan % not found', p_scan_id USING ERRCODE='22023';
  END IF;
  IF v_scan.status <> 'STARTED'::public.end_scan_status_enum THEN
    RAISE EXCEPTION 'raise_end_scan_issue: scan % in terminal state %', p_scan_id, v_scan.status USING ERRCODE='22023';
  END IF;
  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id,
    transaction_id, document_id, match_record_id, draft_ledger_entry_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action,
    card_payload_json, card_content_tier_used, card_content_fallback_applied, status
  ) VALUES (
    v_scan.organization_id, v_scan.business_id, v_scan.workflow_run_id,
    p_transaction_id, p_document_id, p_match_record_id, p_draft_ledger_entry_id,
    p_issue_type, p_issue_group, p_severity,
    p_plain_language_title, p_plain_language_description, p_recommended_action,
    COALESCE(p_card_payload_json, '{}'::jsonb),
    p_card_content_tier_used, p_card_content_fallback_applied,
    'OPEN'::public.review_issue_status_enum
  ) RETURNING id INTO v_issue_id;
  v_sev_key := p_severity::text;
  v_counts := v_scan.severity_counts;
  v_counts := jsonb_set(v_counts, ARRAY[v_sev_key],
    to_jsonb(COALESCE((v_counts->>v_sev_key)::int, 0) + 1), true);
  UPDATE public.end_scan_runs SET finding_count = finding_count + 1, severity_counts = v_counts WHERE id = p_scan_id;
  IF p_actor_user_id IS NULL THEN
    v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'end_scan';
  ELSE
    v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'END_SCAN_ISSUE_RAISED',
    p_subject_type => 'REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id => v_issue_id, p_actor_user_id => p_actor_user_id,
    p_actor_system => v_system, p_organization_id => v_scan.organization_id,
    p_business_id => v_scan.business_id,
    p_reason => format('end-scan issue raised: %s (%s)', p_issue_type, p_severity),
    p_after_state => jsonb_build_object('issue_id', v_issue_id, 'scan_id', p_scan_id,
      'workflow_run_id', v_scan.workflow_run_id, 'issue_type', p_issue_type,
      'issue_group', p_issue_group::text, 'severity', p_severity::text,
      'fallback_applied', p_card_content_fallback_applied));
  RETURN jsonb_build_object('ok', true, 'review_issue_id', v_issue_id,
    'finding_count', v_scan.finding_count + 1, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_match_score(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_document_id uuid, p_signal_breakdown jsonb, p_match_score numeric, p_match_level match_level_enum, p_match_method match_method_enum DEFAULT 'DETERMINISTIC_RULE'::match_method_enum, p_match_reason_plain_language text DEFAULT NULL::text, p_matched_by_system text DEFAULT 'matching_engine'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_existing_rejection_id uuid; v_match_record_id uuid; v_requires_confirm boolean;
BEGIN
  IF p_match_score IS NULL OR p_match_score < 0 OR p_match_score > 1 THEN
    RAISE EXCEPTION 'MATCH_SCORE_OUT_OF_RANGE' USING errcode='check_violation';
  END IF;
  IF jsonb_typeof(COALESCE(p_signal_breakdown,'{}'::jsonb)) <> 'object' THEN
    RAISE EXCEPTION 'SIGNAL_BREAKDOWN_MUST_BE_OBJECT' USING errcode='check_violation';
  END IF;

  SELECT id INTO v_existing_rejection_id
  FROM public.match_rejection_memory
  WHERE business_id = p_business_id
    AND transaction_id = p_transaction_id
    AND document_id = p_document_id
  LIMIT 1;

  IF FOUND THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='MATCHING_REJECTION_SUPPRESSED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='matching_engine',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'transaction_id', p_transaction_id,
        'document_id', p_document_id,
        'rejection_record_id', v_existing_rejection_id
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
    RETURN jsonb_build_object(
      'decision','SUPPRESSED','reason','PAIR_IN_REJECTION_MEMORY',
      'transaction_id', p_transaction_id, 'document_id', p_document_id,
      'rejection_record_id', v_existing_rejection_id
    );
  END IF;

  v_requires_confirm := (p_match_level <> 'EXACT');

  INSERT INTO public.match_records (
    organization_id, business_id, transaction_id, document_id,
    match_level, match_method, match_score, match_signals,
    match_status, requires_user_confirmation,
    match_reason_plain_language, matched_by_system
  ) VALUES (
    p_organization_id, p_business_id, p_transaction_id, p_document_id,
    p_match_level, p_match_method, p_match_score,
    COALESCE(p_signal_breakdown,'{}'::jsonb),
    CASE p_match_level
      WHEN 'EXACT'           THEN 'MATCHED_AUTO_HIGH_CONFIDENCE'::public.match_record_status_enum
      WHEN 'STRONG_PROBABLE' THEN 'MATCHED_NEEDS_CONFIRMATION'::public.match_record_status_enum
      ELSE                        'POSSIBLE_MATCH'::public.match_record_status_enum
    END,
    v_requires_confirm,
    p_match_reason_plain_language, p_matched_by_system
  )
  RETURNING id INTO v_match_record_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_SCORE_COMPUTED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'match_record_id', v_match_record_id, 'document_id', p_document_id,
      'signal_breakdown', COALESCE(p_signal_breakdown,'{}'::jsonb),
      'match_score', p_match_score
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_LEVEL_ASSIGNED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=v_match_record_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'match_level', p_match_level, 'match_method', p_match_method,
      'transaction_id', p_transaction_id, 'document_id', p_document_id,
      'requires_user_confirmation', v_requires_confirm
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','RECORDED','match_record_id', v_match_record_id,
    'match_level', p_match_level, 'match_score', p_match_score,
    'requires_user_confirmation', v_requires_confirm
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_end_scan(p_scan_id uuid, p_terminal_status end_scan_status_enum, p_actor_user_id uuid DEFAULT NULL::uuid, p_failure_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_scan public.end_scan_runs%ROWTYPE; v_action text;
  v_kind audit.actor_kind_enum; v_system text; v_audit_row audit.audit_events;
BEGIN
  IF p_scan_id IS NULL OR p_terminal_status IS NULL THEN
    RAISE EXCEPTION 'complete_end_scan: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_terminal_status = 'STARTED'::public.end_scan_status_enum THEN
    RAISE EXCEPTION 'complete_end_scan: cannot transition to STARTED' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_scan FROM public.end_scan_runs WHERE id = p_scan_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'complete_end_scan: scan % not found', p_scan_id USING ERRCODE='22023';
  END IF;
  IF v_scan.status <> 'STARTED'::public.end_scan_status_enum THEN
    RAISE EXCEPTION 'complete_end_scan: scan % already in terminal state %', p_scan_id, v_scan.status USING ERRCODE='22023';
  END IF;
  UPDATE public.end_scan_runs SET status = p_terminal_status, completed_at = clock_timestamp() WHERE id = p_scan_id;
  IF p_terminal_status IN ('COMPLETED'::public.end_scan_status_enum, 'FAILED'::public.end_scan_status_enum) THEN
    v_action := CASE p_terminal_status WHEN 'COMPLETED' THEN 'END_SCAN_COMPLETED' WHEN 'FAILED' THEN 'END_SCAN_FAILED' END;
    IF p_actor_user_id IS NULL THEN
      v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'end_scan';
    ELSE
      v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL;
    END IF;
    v_audit_row := audit.emit_audit(
      p_actor_kind => v_kind, p_action => v_action,
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
      p_subject_id => v_scan.workflow_run_id,
      p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
      p_organization_id => v_scan.organization_id, p_business_id => v_scan.business_id,
      p_reason => format('end-scan %s for run %s (%s findings)',
        lower(p_terminal_status::text), v_scan.workflow_run_id, v_scan.finding_count),
      p_after_state => jsonb_build_object('scan_id', p_scan_id,
        'workflow_run_id', v_scan.workflow_run_id, 'status', p_terminal_status::text,
        'finding_count', v_scan.finding_count, 'severity_counts', v_scan.severity_counts,
        'checks_ran_count', v_scan.checks_ran_count, 'failure_reason', p_failure_reason));
  END IF;
  RETURN jsonb_build_object('ok', true, 'scan_id', p_scan_id,
    'status', p_terminal_status::text, 'finding_count', v_scan.finding_count,
    'severity_counts', v_scan.severity_counts,
    'audit_event_id', COALESCE(v_audit_row.id, NULL));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_matching_cross_currency_fx_resolved(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_document_id uuid, p_rate_source text, p_rate numeric, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  IF p_rate_source NOT IN ('fx_paired_legs','ecb_fallback') THEN
    RAISE EXCEPTION 'RATE_SOURCE_MUST_BE_FX_PAIRED_LEGS_OR_ECB_FALLBACK' USING errcode='check_violation';
  END IF;
  IF p_rate IS NULL OR p_rate <= 0 THEN
    RAISE EXCEPTION 'RATE_MUST_BE_POSITIVE' USING errcode='check_violation';
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_CROSS_CURRENCY_FX_RESOLVED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'transaction_id', p_transaction_id, 'document_id', p_document_id,
      'rate_source', p_rate_source, 'rate', p_rate
    ),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN jsonb_build_object(
    'decision','RECORDED','transaction_id',p_transaction_id,
    'document_id',p_document_id,'rate_source',p_rate_source,'rate',p_rate
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_matching_cross_period_candidate_found(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_document_id uuid, p_days_offset integer, p_context jsonb DEFAULT '{}'::jsonb)
