 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_row public.statement_parsed_rows%ROWTYPE;
  v_run public.statement_parse_runs%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_parsed_row_id IS NULL OR p_fields_below_threshold IS NULL OR p_threshold IS NULL THEN
    RAISE EXCEPTION 'flag_low_confidence_parsed_row: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_threshold < 0 OR p_threshold > 1 THEN
    RAISE EXCEPTION 'flag_low_confidence_parsed_row: threshold must be in [0,1] (got %)', p_threshold USING ERRCODE='22023';
  END IF;
  IF array_length(p_fields_below_threshold, 1) IS NULL THEN
    RAISE EXCEPTION 'flag_low_confidence_parsed_row: fields_below_threshold must not be empty' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_row FROM public.statement_parsed_rows WHERE id = p_parsed_row_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'flag_low_confidence_parsed_row: row % not found', p_parsed_row_id USING ERRCODE='02000';
  END IF;
  IF v_row.parser_confidence IS DISTINCT FROM 'LOW' THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'ROW_NOT_LOW_CONFIDENCE', 'parser_confidence', v_row.parser_confidence);
  END IF;
  SELECT * INTO v_run FROM public.statement_parse_runs WHERE id = v_row.parse_run_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_pdf_parser';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_PDF_PARSE_LOW_CONFIDENCE_ROW',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_row.statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_run.organization_id, p_business_id => v_run.business_id,
    p_after_state => jsonb_build_object('parsed_row_id', v_row.id,
      'parse_run_id', v_row.parse_run_id,
      'statement_upload_id', v_row.statement_upload_id,
      'source_row_index', v_row.source_row_index,
      'fields_below_threshold', to_jsonb(p_fields_below_threshold),
      'threshold', p_threshold),
    p_reason => format('PDF parsed row %s: %s field(s) below threshold %s',
                       v_row.source_row_index, array_length(p_fields_below_threshold, 1), p_threshold));
  RETURN jsonb_build_object('ok', true, 'parsed_row_id', v_row.id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_pdf_ocr_completed(p_parse_run_id uuid, p_page_count integer, p_cost_cents integer, p_artifact_path text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.statement_parse_runs%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_parse_run_id IS NULL OR p_page_count IS NULL OR p_cost_cents IS NULL THEN
    RAISE EXCEPTION 'record_pdf_ocr_completed: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_page_count < 0 OR p_cost_cents < 0 THEN
    RAISE EXCEPTION 'record_pdf_ocr_completed: page_count and cost_cents must be >= 0' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_run FROM public.statement_parse_runs WHERE id = p_parse_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_pdf_ocr_completed: parse_run % not found', p_parse_run_id USING ERRCODE='02000';
  END IF;
  IF v_run.ocr_started_at IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'OCR_NOT_STARTED');
  END IF;
  IF v_run.ocr_completed_at IS NOT NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'OCR_ALREADY_COMPLETED', 'ocr_completed_at', v_run.ocr_completed_at);
  END IF;
  UPDATE public.statement_parse_runs
    SET ocr_page_count = p_page_count, ocr_cost_cents = p_cost_cents,
        ocr_artifact_path = p_artifact_path, ocr_completed_at = clock_timestamp(),
        updated_at = clock_timestamp()
    WHERE id = p_parse_run_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_pdf_parser';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_PDF_OCR_COMPLETED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_run.statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_run.organization_id, p_business_id => v_run.business_id,
    p_after_state => jsonb_build_object('parse_run_id', v_run.id,
      'ocr_processor_id', v_run.ocr_processor_id,
      'ocr_processor_version', v_run.ocr_processor_version,
      'page_count', p_page_count, 'cost_cents', p_cost_cents,
      'ocr_artifact_path', p_artifact_path),
    p_reason => format('Document AI OCR completed: %s page(s), %s cents', p_page_count, p_cost_cents));
  RETURN jsonb_build_object('ok', true, 'parse_run_id', v_run.id,
    'page_count', p_page_count, 'cost_cents', p_cost_cents,
    'ocr_processor_id', v_run.ocr_processor_id,
    'ocr_processor_version', v_run.ocr_processor_version,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_normalized_transaction(p_normalization_run_id uuid, p_parsed_row_ids uuid[], p_transaction_date date, p_amount numeric, p_currency text, p_direction transaction_direction_enum, p_normalized_description text, p_source_row_hash text, p_transaction_fingerprint text, p_booking_date date DEFAULT NULL::date, p_counterparty_name text DEFAULT NULL::text, p_counterparty_identifier_masked text DEFAULT NULL::text, p_counterparty_identifier_encrypted bytea DEFAULT NULL::bytea, p_reference text DEFAULT NULL::text, p_transaction_type_candidate transaction_type_enum DEFAULT NULL::transaction_type_enum, p_fx_paired_legs jsonb DEFAULT NULL::jsonb, p_normalization_confidence text DEFAULT 'HIGH'::text, p_extraction_method text DEFAULT 'DETERMINISTIC'::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.statement_normalization_runs%ROWTYPE;
  v_row_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_normalization_run_id IS NULL OR p_parsed_row_ids IS NULL OR p_transaction_date IS NULL
     OR p_amount IS NULL OR p_currency IS NULL OR p_direction IS NULL
     OR p_normalized_description IS NULL OR p_source_row_hash IS NULL OR p_transaction_fingerprint IS NULL THEN
    RAISE EXCEPTION 'record_normalized_transaction: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_run FROM public.statement_normalization_runs WHERE id = p_normalization_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_normalized_transaction: run % not found', p_normalization_run_id USING ERRCODE='02000';
  END IF;
  IF v_run.status <> 'STARTED'::public.statement_normalization_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NORMALIZATION_NOT_STARTED', 'current_status', v_run.status::text);
  END IF;
  BEGIN
    INSERT INTO public.statement_normalized_rows
      (id, normalization_run_id, statement_upload_id, business_id, organization_id,
       parsed_row_ids, transaction_date, booking_date, amount, currency, direction,
       transaction_type_candidate, normalized_description, counterparty_name,
       counterparty_identifier_masked, counterparty_identifier_encrypted, reference,
       source_row_hash, transaction_fingerprint, fx_paired_legs,
       normalization_confidence, extraction_method, created_at)
    VALUES
      (v_row_id, p_normalization_run_id, v_run.statement_upload_id, v_run.business_id, v_run.organization_id,
       p_parsed_row_ids, p_transaction_date, p_booking_date, p_amount, p_currency, p_direction,
       p_transaction_type_candidate, p_normalized_description, p_counterparty_name,
       p_counterparty_identifier_masked, p_counterparty_identifier_encrypted, p_reference,
       p_source_row_hash, p_transaction_fingerprint, p_fx_paired_legs,
       p_normalization_confidence, p_extraction_method, clock_timestamp());
  EXCEPTION WHEN unique_violation THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'DUPLICATE_FINGERPRINT_IN_RUN',
      'transaction_fingerprint', p_transaction_fingerprint);
  END;
  UPDATE public.statement_normalization_runs
    SET normalized_count = normalized_count + 1, updated_at = clock_timestamp()
    WHERE id = p_normalization_run_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_normalizer';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'TRANSACTION_NORMALIZED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_run.statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_run.organization_id, p_business_id => v_run.business_id,
    p_after_state => jsonb_build_object(
      'normalized_row_id', v_row_id, 'normalization_run_id', v_run.id,
      'parsed_row_ids', to_jsonb(p_parsed_row_ids),
      'transaction_date', p_transaction_date,
      'amount', p_amount, 'currency', p_currency, 'direction', p_direction::text,
      'transaction_type_candidate', p_transaction_type_candidate::text,
      'source_row_hash', p_source_row_hash,
      'transaction_fingerprint', p_transaction_fingerprint,
      'normalization_confidence', p_normalization_confidence,
      'extraction_method', p_extraction_method),
    p_reason => format('normalized %s %s -> %s (fingerprint %s)',
                       p_direction::text, p_amount, p_currency, left(p_transaction_fingerprint, 12)));
  RETURN jsonb_build_object('ok', true, 'normalized_row_id', v_row_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_pdf_parsed_row(p_parse_run_id uuid, p_source_row_index integer, p_provider_native jsonb, p_date_text text, p_amount_text text, p_currency text, p_direction_hint parsed_row_direction_hint_enum, p_parser_confidence text, p_extraction_confidence_per_field jsonb DEFAULT NULL::jsonb, p_description_text text DEFAULT NULL::text, p_reference_text text DEFAULT NULL::text, p_counterparty_text text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.statement_parse_runs%ROWTYPE;
  v_row_id uuid := public.gen_uuid_v7();
BEGIN
  IF p_parse_run_id IS NULL OR p_source_row_index IS NULL OR p_provider_native IS NULL
     OR p_date_text IS NULL OR p_amount_text IS NULL OR p_currency IS NULL
     OR p_parser_confidence IS NULL THEN
    RAISE EXCEPTION 'record_pdf_parsed_row: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_parser_confidence NOT IN ('HIGH','LOW') THEN
    RAISE EXCEPTION 'record_pdf_parsed_row: parser_confidence must be HIGH or LOW (got %)', p_parser_confidence USING ERRCODE='22023';
  END IF;
  IF p_extraction_confidence_per_field IS NOT NULL AND jsonb_typeof(p_extraction_confidence_per_field) <> 'object' THEN
    RAISE EXCEPTION 'record_pdf_parsed_row: extraction_confidence_per_field must be an object' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_run FROM public.statement_parse_runs WHERE id = p_parse_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_pdf_parsed_row: parse_run % not found', p_parse_run_id USING ERRCODE='02000';
  END IF;
  IF v_run.status <> 'STARTED'::public.statement_parse_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'PARSE_RUN_NOT_STARTED', 'current_status', v_run.status::text);
  END IF;
  IF v_run.parser_file_format <> 'PDF'::public.statement_file_format_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'PARSE_RUN_NOT_PDF', 'parser_file_format', v_run.parser_file_format::text);
  END IF;
  BEGIN
    INSERT INTO public.statement_parsed_rows
      (id, parse_run_id, statement_upload_id, source_row_index, provider_native,
       date_text, amount_text, currency, description_text, reference_text,
       counterparty_text, direction_hint, extraction_confidence_per_field,
       parser_confidence, created_at)
    VALUES
      (v_row_id, p_parse_run_id, v_run.statement_upload_id, p_source_row_index,
       p_provider_native, p_date_text, p_amount_text, p_currency,
       p_description_text, p_reference_text, p_counterparty_text,
       p_direction_hint, p_extraction_confidence_per_field,
       p_parser_confidence, clock_timestamp());
  EXCEPTION WHEN unique_violation THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'DUPLICATE_ROW_INDEX',
      'parse_run_id', p_parse_run_id, 'source_row_index', p_source_row_index);
  END;
  UPDATE public.statement_parse_runs
    SET row_count = row_count + 1, updated_at = clock_timestamp()
    WHERE id = p_parse_run_id;
  RETURN jsonb_build_object('ok', true, 'parsed_row_id', v_row_id, 'parser_confidence', p_parser_confidence);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.start_statement_normalization(p_statement_upload_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_run_id uuid := public.gen_uuid_v7();
BEGIN
  IF p_statement_upload_id IS NULL THEN
    RAISE EXCEPTION 'start_statement_normalization: p_statement_upload_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id FOR SHARE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'start_statement_normalization: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  IF v_upload.upload_status <> 'PARSED'::public.statement_upload_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'UPLOAD_NOT_IN_PARSED_STATE',
      'current_status', v_upload.upload_status::text);
  END IF;
  BEGIN
    INSERT INTO public.statement_normalization_runs
      (id, statement_upload_id, business_id, organization_id, status, started_at, created_at, updated_at)
    VALUES
      (v_run_id, v_upload.id, v_upload.business_id, v_upload.organization_id, 'STARTED',
       clock_timestamp(), clock_timestamp(), clock_timestamp());
  EXCEPTION WHEN unique_violation THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NORMALIZATION_ALREADY_IN_PROGRESS',
      'statement_upload_id', v_upload.id);
  END;
  RETURN jsonb_build_object('ok', true,
    'normalization_run_id', v_run_id, 'statement_upload_id', v_upload.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_fx_pair_resolved(p_normalization_run_id uuid, p_normalized_row_id uuid, p_parsed_row_id_out uuid, p_parsed_row_id_in uuid, p_fx_paired_legs jsonb, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.statement_normalization_runs%ROWTYPE;
  v_row public.statement_normalized_rows%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_normalization_run_id IS NULL OR p_normalized_row_id IS NULL
     OR p_parsed_row_id_out IS NULL OR p_parsed_row_id_in IS NULL OR p_fx_paired_legs IS NULL THEN
    RAISE EXCEPTION 'record_fx_pair_resolved: required params missing' USING ERRCODE='22000';
  END IF;
  IF jsonb_typeof(p_fx_paired_legs) <> 'object' THEN
    RAISE EXCEPTION 'record_fx_pair_resolved: fx_paired_legs must be an object' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_run FROM public.statement_normalization_runs WHERE id = p_normalization_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_fx_pair_resolved: run % not found', p_normalization_run_id USING ERRCODE='02000';
  END IF;
  IF v_run.status <> 'STARTED'::public.statement_normalization_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NORMALIZATION_NOT_STARTED', 'current_status', v_run.status::text);
  END IF;
  SELECT * INTO v_row FROM public.statement_normalized_rows WHERE id = p_normalized_row_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_fx_pair_resolved: normalized_row % not found', p_normalized_row_id USING ERRCODE='02000';
  END IF;
  IF v_row.transaction_type_candidate IS DISTINCT FROM 'FX_EXCHANGE'::public.transaction_type_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'ROW_NOT_FX_EXCHANGE',
      'transaction_type_candidate', v_row.transaction_type_candidate::text);
  END IF;
  IF NOT (p_parsed_row_id_out = ANY (v_row.parsed_row_ids))
     OR NOT (p_parsed_row_id_in = ANY (v_row.parsed_row_ids)) THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'PARSED_ROWS_DO_NOT_MATCH_NORMALIZED_ROW',
      'normalized_parsed_row_ids', to_jsonb(v_row.parsed_row_ids),
      'requested_out', p_parsed_row_id_out, 'requested_in', p_parsed_row_id_in);
  END IF;
  UPDATE public.statement_normalization_runs
    SET fx_pair_count = fx_pair_count + 1, updated_at = clock_timestamp()
    WHERE id = p_normalization_run_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_normalizer';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_NORMALIZATION_FX_PAIR_RESOLVED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_run.statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_run.organization_id, p_business_id => v_run.business_id,
    p_after_state => jsonb_build_object(
      'normalization_run_id', v_run.id, 'normalized_row_id', p_normalized_row_id,
      'parsed_row_id_out', p_parsed_row_id_out, 'parsed_row_id_in', p_parsed_row_id_in,
      'fx_paired_legs', p_fx_paired_legs),
    p_reason => format('FX pair resolved: out=%s in=%s rate=%s',
                       p_fx_paired_legs->'leg_out'->>'currency',
                       p_fx_paired_legs->'leg_in'->>'currency',
                       p_fx_paired_legs->>'rate'));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id);
END;
$function$
;

