CREATE OR REPLACE FUNCTION public.accept_statement_upload(p_statement_upload_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_expected int;
  v_with_pdf int;
  v_missing int;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_statement_upload_id IS NULL THEN
    RAISE EXCEPTION 'accept_statement_upload: p_statement_upload_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads
    WHERE id = p_statement_upload_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'accept_statement_upload: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  IF v_upload.upload_status = 'ACCEPTED'::public.statement_upload_status_enum THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true, 'current_status', 'ACCEPTED');
  END IF;
  IF v_upload.upload_status <> 'PARSED'::public.statement_upload_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'UPLOAD_NOT_IN_PARSED_STATE',
      'current_status', v_upload.upload_status::text);
  END IF;

  SELECT count(*) INTO v_expected FROM public.transactions
    WHERE statement_upload_id = v_upload.id
      AND dedup_status = 'NEW'::public.transaction_dedup_status_enum;
  SELECT count(DISTINCT t.id) INTO v_with_pdf FROM public.transactions t
    JOIN public.evidence_pdfs e ON e.transaction_id = t.id
    WHERE t.statement_upload_id = v_upload.id
      AND t.dedup_status = 'NEW'::public.transaction_dedup_status_enum;
  v_missing := v_expected - v_with_pdf;

  IF v_missing > 0 THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'INCOMPLETE_EVIDENCE_COVERAGE',
      'expected_count', v_expected, 'with_pdf_count', v_with_pdf, 'missing_count', v_missing);
  END IF;

  UPDATE public.statement_uploads
    SET upload_status = 'ACCEPTED'::public.statement_upload_status_enum,
        updated_at = clock_timestamp()
    WHERE id = v_upload.id;

  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'evidence_pdf_generator';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_UPLOAD_ACCEPTED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => v_upload.id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_upload.organization_id, p_business_id => v_upload.business_id,
    p_before_state => jsonb_build_object('upload_status', 'PARSED'),
    p_after_state => jsonb_build_object(
      'upload_status', 'ACCEPTED', 'new_tx_count', v_expected, 'evidence_pdf_count', v_with_pdf),
    p_reason => format('upload accepted: %s NEW transactions all have evidence PDFs', v_expected));

  RETURN jsonb_build_object('ok', true,
    'statement_upload_id', v_upload.id,
    'new_tx_count', v_expected, 'evidence_pdf_count', v_with_pdf,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ingestion_phase_started(p_workflow_run_id uuid, p_statement_upload_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_gate jsonb;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_workflow_run_id IS NULL OR p_statement_upload_id IS NULL THEN
    RAISE EXCEPTION 'record_ingestion_phase_started: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_ingestion_phase_started: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  v_gate := public.evaluate_ingestion_entry(p_statement_upload_id);
  IF (v_gate->>'passed')::bool IS NOT TRUE THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'ENTRY_GATE_NOT_PASSED', 'gate_envelope', v_gate);
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'workflow_engine';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'INGESTION_PHASE_STARTED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => p_statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_upload.organization_id, p_business_id => v_upload.business_id,
    p_after_state => jsonb_build_object(
      'workflow_run_id', p_workflow_run_id,
      'statement_upload_id', p_statement_upload_id,
      'entry_gate', v_gate),
    p_reason => format('INGESTION phase started for upload %s', p_statement_upload_id));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ingestion_phase_completed(p_workflow_run_id uuid, p_statement_upload_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_gate jsonb;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_workflow_run_id IS NULL OR p_statement_upload_id IS NULL THEN
    RAISE EXCEPTION 'record_ingestion_phase_completed: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_ingestion_phase_completed: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  v_gate := public.evaluate_ingestion_exit(p_statement_upload_id);
  IF (v_gate->>'passed')::bool IS NOT TRUE THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'EXIT_GATE_NOT_PASSED', 'gate_envelope', v_gate);
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'workflow_engine';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'INGESTION_PHASE_COMPLETED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => p_statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_upload.organization_id, p_business_id => v_upload.business_id,
    p_after_state => jsonb_build_object(
      'workflow_run_id', p_workflow_run_id,
      'statement_upload_id', p_statement_upload_id,
      'exit_gate', v_gate),
    p_reason => format('INGESTION phase completed for upload %s (new_tx=%s)',
                       p_statement_upload_id, v_gate->>'new_tx_count'));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id, 'gate_envelope', v_gate);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_partial_upload_detected(p_statement_upload_id uuid, p_workflow_run_id uuid, p_parse_warning_summary jsonb, p_anchor_transaction_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_anchor uuid := p_anchor_transaction_id;
  v_existing uuid;
  v_review_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_statement_upload_id IS NULL OR p_workflow_run_id IS NULL OR p_parse_warning_summary IS NULL THEN
    RAISE EXCEPTION 'record_partial_upload_detected: required params missing' USING ERRCODE='22000';
  END IF;
  IF jsonb_typeof(p_parse_warning_summary) <> 'object' THEN
    RAISE EXCEPTION 'record_partial_upload_detected: parse_warning_summary must be an object' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_partial_upload_detected: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  SELECT id INTO v_existing FROM public.review_issues
    WHERE business_id = v_upload.business_id
      AND issue_type = 'bank_pipeline.partial_upload'
      AND card_payload_json->>'statement_upload_id' = p_statement_upload_id::text
    LIMIT 1;
  IF v_existing IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true, 'review_issue_id', v_existing);
  END IF;
  IF v_anchor IS NULL THEN
    SELECT id INTO v_anchor FROM public.transactions
      WHERE statement_upload_id = p_statement_upload_id
      ORDER BY source_row_index ASC LIMIT 1;
  END IF;
  IF v_anchor IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NO_TRANSACTIONS_TO_ANCHOR',
      'statement_upload_id', p_statement_upload_id);
  END IF;
  UPDATE public.statement_uploads
    SET parse_warnings = COALESCE(parse_warnings, '[]'::jsonb) || jsonb_build_array(p_parse_warning_summary),
        updated_at = clock_timestamp()
    WHERE id = p_statement_upload_id;
  INSERT INTO public.review_issues
    (id, organization_id, business_id, workflow_run_id, transaction_id,
     issue_type, issue_group, severity,
     plain_language_title, plain_language_description,
     card_payload_json, card_content_tier_used, card_content_fallback_applied,
     status, created_at, updated_at)
  VALUES
    (v_review_id, v_upload.organization_id, v_upload.business_id, p_workflow_run_id, v_anchor,
     'bank_pipeline.partial_upload',
     'MISSING_DOCUMENTS'::public.review_issue_group_enum,
     'HIGH'::public.review_issue_severity_enum,
     'Partial upload detected — some rows could not be read',
     'The bank statement appears to be incomplete or truncated. The pipeline processed the rows it could read. Review the warning summary and choose: re-upload the complete file, accept what was processed, or contact support.',
     jsonb_build_object(
       'statement_upload_id', p_statement_upload_id,
       'anchor_transaction_id', v_anchor,
       'parse_warning_summary', p_parse_warning_summary),
     'NONE'::public.review_issue_card_content_tier_enum, false,
     'OPEN'::public.review_issue_status_enum,
     clock_timestamp(), clock_timestamp());
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'bank_pipeline_partial_upload';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_PARTIAL_UPLOAD_DETECTED',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => p_statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_upload.organization_id, p_business_id => v_upload.business_id,
    p_after_state => jsonb_build_object(
      'statement_upload_id', p_statement_upload_id,
      'review_issue_id', v_review_id,
      'anchor_transaction_id', v_anchor,
      'parse_warning_summary', p_parse_warning_summary),
    p_reason => format('partial upload detected on %s: %s warning(s)',
                       p_statement_upload_id,
                       coalesce(jsonb_array_length(p_parse_warning_summary->'warnings'), 0)));
  RETURN jsonb_build_object('ok', true,
    'review_issue_id', v_review_id,
    'anchor_transaction_id', v_anchor,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ingestion_phase_holding(p_workflow_run_id uuid, p_statement_upload_id uuid, p_holding_at_tool text, p_hold_reason text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_workflow_run_id IS NULL OR p_statement_upload_id IS NULL
     OR p_holding_at_tool IS NULL OR p_hold_reason IS NULL THEN
    RAISE EXCEPTION 'record_ingestion_phase_holding: required params missing' USING ERRCODE='22000';
  END IF;
  IF length(p_hold_reason) = 0 OR length(p_hold_reason) > 2000 THEN
    RAISE EXCEPTION 'record_ingestion_phase_holding: hold_reason length must be 1..2000' USING ERRCODE='22023';
  END IF;
  IF p_holding_at_tool NOT IN ('bank_pipeline.parse_csv','bank_pipeline.parse_pdf',
                                'bank_pipeline.normalize','bank_pipeline.dedupe',
                                'bank_pipeline.generate_evidence_pdfs') THEN
    RAISE EXCEPTION 'record_ingestion_phase_holding: holding_at_tool not a known INGESTION tool (got %)', p_holding_at_tool
      USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_ingestion_phase_holding: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'workflow_engine';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'INGESTION_PHASE_HOLDING',
    p_subject_type => 'STATEMENT_UPLOAD'::audit.subject_type_enum,
    p_subject_id => p_statement_upload_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_upload.organization_id, p_business_id => v_upload.business_id,
    p_after_state => jsonb_build_object(
      'workflow_run_id', p_workflow_run_id,
      'statement_upload_id', p_statement_upload_id,
      'holding_at_tool', p_holding_at_tool,
      'hold_reason', p_hold_reason),
    p_reason => format('INGESTION phase HOLDING at %s: %s', p_holding_at_tool, left(p_hold_reason, 200)));
  RETURN jsonb_build_object('ok', true, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_row_outside_declared_period(p_transaction_id uuid, p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_upload public.statement_uploads%ROWTYPE;
  v_existing uuid;
  v_review_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_workflow_run_id IS NULL THEN
    RAISE EXCEPTION 'record_row_outside_declared_period: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_row_outside_declared_period: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = v_tx.statement_upload_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_row_outside_declared_period: upload % not found', v_tx.statement_upload_id USING ERRCODE='02000';
  END IF;
  IF v_tx.transaction_date BETWEEN v_upload.declared_period_start AND v_upload.declared_period_end THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'ROW_WITHIN_DECLARED_PERIOD',
      'transaction_date', v_tx.transaction_date,
      'declared_period_start', v_upload.declared_period_start,
      'declared_period_end', v_upload.declared_period_end);
  END IF;
  SELECT id INTO v_existing FROM public.review_issues
    WHERE transaction_id = p_transaction_id AND issue_type = 'bank_pipeline.row_outside_declared_period'
    LIMIT 1;
  IF v_existing IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true, 'review_issue_id', v_existing);
  END IF;
  INSERT INTO public.review_issues
    (id, organization_id, business_id, workflow_run_id, transaction_id,
     issue_type, issue_group, severity,
     plain_language_title, plain_language_description,
     card_payload_json, card_content_tier_used, card_content_fallback_applied,
     status, created_at, updated_at)
  VALUES
    (v_review_id, v_tx.organization_id, v_tx.business_id, p_workflow_run_id, p_transaction_id,
     'bank_pipeline.row_outside_declared_period',
     'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
     'MEDIUM'::public.review_issue_severity_enum,
     'Transaction date is outside the declared statement period',
     format('This transaction (dated %s) falls outside the declared statement period (%s to %s). Confirm to include it, or exclude it from this period — either way the row remains in the database.',
            v_tx.transaction_date, v_upload.declared_period_start, v_upload.declared_period_end),
     jsonb_build_object(
       'transaction_id', p_transaction_id,
       'statement_upload_id', v_upload.id,
       'transaction_date', v_tx.transaction_date,
       'declared_period_start', v_upload.declared_period_start,
       'declared_period_end', v_upload.declared_period_end),
     'NONE'::public.review_issue_card_content_tier_enum, false,
     'OPEN'::public.review_issue_status_enum,
     clock_timestamp(), clock_timestamp());
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'bank_pipeline_period_validation';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_ROW_OUTSIDE_DECLARED_PERIOD',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'statement_upload_id', v_upload.id,
      'review_issue_id', v_review_id,
      'transaction_date', v_tx.transaction_date,
      'declared_period_start', v_upload.declared_period_start,
      'declared_period_end', v_upload.declared_period_end),
    p_reason => format('row %s dated %s outside declared period [%s, %s]',
                       p_transaction_id, v_tx.transaction_date,
                       v_upload.declared_period_start, v_upload.declared_period_end));
  RETURN jsonb_build_object('ok', true,
    'review_issue_id', v_review_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.emit_statement_upload_completed_event(p_statement_upload_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_event_id uuid := public.gen_uuid_v7();
  v_existing public.statement_upload_events_outbox%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_statement_upload_id IS NULL THEN
    RAISE EXCEPTION 'emit_statement_upload_completed_event: p_statement_upload_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'UPLOAD_NOT_FOUND',
      'statement_upload_id', p_statement_upload_id);
  END IF;
  INSERT INTO public.statement_upload_events_outbox
    (event_id, statement_upload_id, organization_id, business_id, bank_account_id,
     declared_period_start, declared_period_end, file_format, provider,
     actor_user_id, status, emitted_at)
  VALUES
    (v_event_id, v_upload.id, v_upload.organization_id, v_upload.business_id, v_upload.bank_account_id,
     v_upload.declared_period_start, v_upload.declared_period_end, v_upload.file_format, v_upload.provider,
     p_actor_user_id, 'PENDING', clock_timestamp())
  ON CONFLICT (statement_upload_id) DO NOTHING
  RETURNING event_id INTO v_event_id;
  IF v_event_id IS NULL THEN
    SELECT * INTO v_existing FROM public.statement_upload_events_outbox WHERE statement_upload_id = p_statement_upload_id;
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'event_id', v_existing.event_id, 'status', v_existing.status::text);
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_upload_trigger';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_UPLOAD_EVENT_EMITTED',
    p_subject_type => 'TRIGGER_EVENT'::audit.subject_type_enum,
    p_subject_id => v_event_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_upload.organization_id, p_business_id => v_upload.business_id,
    p_after_state => jsonb_build_object(
      'event_id', v_event_id, 'event_kind', 'STATEMENT_UPLOAD_COMPLETED',
      'statement_upload_id', v_upload.id, 'bank_account_id', v_upload.bank_account_id,
      'declared_period_start', v_upload.declared_period_start,
      'declared_period_end', v_upload.declared_period_end,
      'file_format', v_upload.file_format::text, 'provider', v_upload.provider,
      'actor_user_id', p_actor_user_id),
    p_reason => format('STATEMENT_UPLOAD_COMPLETED event emitted: event_id=%s upload=%s', v_event_id, v_upload.id));
  RETURN jsonb_build_object('ok', true, 'event_id', v_event_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.exclude_transaction_from_period(p_transaction_id uuid, p_exclusion_reason text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_exclusion_reason IS NULL THEN
    RAISE EXCEPTION 'exclude_transaction_from_period: required params missing' USING ERRCODE='22000';
  END IF;
  IF length(p_exclusion_reason) = 0 OR length(p_exclusion_reason) > 2000 THEN
    RAISE EXCEPTION 'exclude_transaction_from_period: exclusion_reason length must be 1..2000' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'exclude_transaction_from_period: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  IF v_tx.period_excluded_at IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'period_excluded_at', v_tx.period_excluded_at);
  END IF;
  UPDATE public.transactions
    SET period_excluded_at = clock_timestamp(), updated_at = clock_timestamp()
    WHERE id = p_transaction_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'bank_pipeline_period_validation';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'TRANSACTION_EXCLUDED_FROM_PERIOD',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'statement_upload_id', v_tx.statement_upload_id,
      'period_excluded_at', clock_timestamp(),
      'exclusion_reason', p_exclusion_reason),
    p_reason => format('transaction %s excluded from declared period: %s',
                       p_transaction_id, left(p_exclusion_reason, 200)));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.consume_statement_upload_completed_event(p_event_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_evt public.statement_upload_events_outbox%ROWTYPE;
  v_processed boolean;
  v_run_id uuid;
  v_created_runs uuid[] := '{}';
  v_types_enabled text[] := '{}';
  v_out_disabled boolean; v_in_disabled boolean;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
  v_workflow_type public.workflow_type_enum;
BEGIN
  IF p_event_id IS NULL THEN
    RAISE EXCEPTION 'consume_statement_upload_completed_event: p_event_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_evt FROM public.statement_upload_events_outbox WHERE event_id = p_event_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'EVENT_NOT_FOUND', 'event_id', p_event_id);
  END IF;
  SELECT EXISTS (SELECT 1 FROM public.trigger_events_processed WHERE event_id = p_event_id::text) INTO v_processed;
  IF v_processed THEN
    IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_upload_trigger';
    ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
    v_audit_row := audit.emit_audit(
      p_actor_kind => v_kind, p_action => 'STATEMENT_UPLOAD_EVENT_REPLAY_NOOP',
      p_subject_type => 'TRIGGER_EVENT'::audit.subject_type_enum,
      p_subject_id => p_event_id,
      p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
      p_organization_id => v_evt.organization_id, p_business_id => v_evt.business_id,
      p_after_state => jsonb_build_object(
        'event_id', p_event_id,
        'created_run_ids', to_jsonb(v_evt.created_run_ids)),
      p_reason => format('replay noop on event %s', p_event_id));
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'event_id', p_event_id,
      'created_run_ids', to_jsonb(v_evt.created_run_ids),
      'audit_event_id', v_audit_row.id);
  END IF;
  SELECT EXISTS (SELECT 1 FROM public.business_workflow_config
    WHERE business_id = v_evt.business_id
      AND workflow_type = 'OUT_MONTHLY'::public.workflow_type_enum
      AND (enabled_phases IS NULL OR enabled_phases = '[]'::jsonb)) INTO v_out_disabled;
  SELECT EXISTS (SELECT 1 FROM public.business_workflow_config
    WHERE business_id = v_evt.business_id
      AND workflow_type = 'IN_MONTHLY'::public.workflow_type_enum
      AND (enabled_phases IS NULL OR enabled_phases = '[]'::jsonb)) INTO v_in_disabled;
  IF NOT v_out_disabled THEN
    v_workflow_type := 'OUT_MONTHLY'::public.workflow_type_enum;
    v_run_id := public.gen_uuid_v7();
    INSERT INTO public.workflow_runs
      (id, organization_id, business_id, workflow_type, principal_snapshot,
       period_start, period_end, trigger_kind, trigger_event_id, status,
       summary_json, created_at, updated_at)
    VALUES
      (v_run_id, v_evt.organization_id, v_evt.business_id, v_workflow_type,
       jsonb_build_object('actor_user_id', v_evt.actor_user_id,
                          'event_id', v_evt.event_id,
                          'statement_upload_id', v_evt.statement_upload_id),
       v_evt.declared_period_start::timestamptz,
       (v_evt.declared_period_end + 1)::timestamptz,
       'EVENT'::public.trigger_kind_enum, p_event_id::text, 'CREATED',
       '{}'::jsonb, clock_timestamp(), clock_timestamp());
    v_created_runs := v_created_runs || ARRAY[v_run_id];
    v_types_enabled := v_types_enabled || ARRAY['OUT_MONTHLY'];
  END IF;
  IF NOT v_in_disabled THEN
    v_workflow_type := 'IN_MONTHLY'::public.workflow_type_enum;
    v_run_id := public.gen_uuid_v7();
    INSERT INTO public.workflow_runs
      (id, organization_id, business_id, workflow_type, principal_snapshot,
       period_start, period_end, trigger_kind, trigger_event_id, status,
       summary_json, created_at, updated_at)
    VALUES
      (v_run_id, v_evt.organization_id, v_evt.business_id, v_workflow_type,
       jsonb_build_object('actor_user_id', v_evt.actor_user_id,
                          'event_id', v_evt.event_id,
                          'statement_upload_id', v_evt.statement_upload_id),
       v_evt.declared_period_start::timestamptz,
       (v_evt.declared_period_end + 1)::timestamptz,
       'EVENT'::public.trigger_kind_enum, p_event_id::text, 'CREATED',
       '{}'::jsonb, clock_timestamp(), clock_timestamp());
    v_created_runs := v_created_runs || ARRAY[v_run_id];
    v_types_enabled := v_types_enabled || ARRAY['IN_MONTHLY'];
  END IF;
  INSERT INTO public.trigger_events_processed
    (event_id, event_kind, business_id, organization_id, period_start, period_end,
     created_run_ids, payload, processed_at)
  VALUES
    (p_event_id::text, 'STATEMENT_UPLOAD_COMPLETED',
     v_evt.business_id, v_evt.organization_id,
     v_evt.declared_period_start::timestamptz,
     (v_evt.declared_period_end + 1)::timestamptz,
     v_created_runs,
     jsonb_build_object(
       'statement_upload_id', v_evt.statement_upload_id,
       'bank_account_id', v_evt.bank_account_id,
       'declared_period_start', v_evt.declared_period_start,
       'declared_period_end', v_evt.declared_period_end,
       'file_format', v_evt.file_format::text,
       'provider', v_evt.provider,
       'workflow_types_created', to_jsonb(v_types_enabled)),
     clock_timestamp());
  UPDATE public.statement_upload_events_outbox
    SET status = 'CONSUMED'::public.statement_upload_event_status_enum,
        consumed_at = clock_timestamp(),
        created_run_ids = v_created_runs
    WHERE event_id = p_event_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_upload_trigger';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_UPLOAD_EVENT_CONSUMED',
    p_subject_type => 'TRIGGER_EVENT'::audit.subject_type_enum,
    p_subject_id => p_event_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_evt.organization_id, p_business_id => v_evt.business_id,
    p_after_state => jsonb_build_object(
      'event_id', p_event_id,
      'statement_upload_id', v_evt.statement_upload_id,
      'created_run_ids', to_jsonb(v_created_runs),
      'workflow_types_enabled', to_jsonb(v_types_enabled),
      'out_disabled', v_out_disabled,
      'in_disabled', v_in_disabled),
    p_reason => format('consumed event %s: created %s run(s) [%s]',
                       p_event_id, coalesce(array_length(v_created_runs, 1), 0),
                       array_to_string(v_types_enabled, ',')));
  RETURN jsonb_build_object('ok', true,
    'event_id', p_event_id,
    'created_run_ids', to_jsonb(v_created_runs),
    'workflow_types_enabled', to_jsonb(v_types_enabled),
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_statement_upload_preview(p_statement_upload_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_upload public.statement_uploads%ROWTYPE;
  v_first_date date; v_last_date date;
  v_total_count int; v_outside_period_count int;
  v_warning_count int;
BEGIN
  IF p_statement_upload_id IS NULL THEN
    RAISE EXCEPTION 'get_statement_upload_preview: p_statement_upload_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_upload FROM public.statement_uploads WHERE id = p_statement_upload_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'get_statement_upload_preview: upload % not found', p_statement_upload_id USING ERRCODE='02000';
  END IF;
  SELECT min(transaction_date), max(transaction_date), count(*),
         count(*) FILTER (WHERE transaction_date < v_upload.declared_period_start
                             OR transaction_date > v_upload.declared_period_end)
    INTO v_first_date, v_last_date, v_total_count, v_outside_period_count
    FROM public.transactions
    WHERE statement_upload_id = p_statement_upload_id;
  v_warning_count := COALESCE(jsonb_array_length(v_upload.parse_warnings), 0);
  RETURN jsonb_build_object(
    'statement_upload_id', v_upload.id,
    'upload_status', v_upload.upload_status::text,
    'declared_period_start', v_upload.declared_period_start,
    'declared_period_end', v_upload.declared_period_end,
    'first_transaction_date', v_first_date,
    'last_transaction_date', v_last_date,
    'total_transaction_count', COALESCE(v_total_count, 0),
    'outside_period_count', COALESCE(v_outside_period_count, 0),
    'partial_upload_warning_count', v_warning_count);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.lookup_recurring_vendor_signal(p_business_id uuid, p_counterparty_signature text)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_confirmations int;
BEGIN
  IF p_business_id IS NULL OR p_counterparty_signature IS NULL THEN
    RETURN 0.0::numeric;
  END IF;
  SELECT confirmations_count INTO v_confirmations
  FROM public.recurring_vendor_memory
  WHERE business_id = p_business_id AND counterparty_signature = p_counterparty_signature
  LIMIT 1;
  IF v_confirmations IS NULL THEN RETURN 0.0::numeric; END IF;
  IF v_confirmations >= 3 THEN RETURN 0.88::numeric; END IF;
  IF v_confirmations = 2 THEN RETURN 0.72::numeric; END IF;
  IF v_confirmations = 1 THEN RETURN 0.60::numeric; END IF;
  RETURN 0.0::numeric;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_statement_upload_event_handler_failed(p_event_id uuid, p_error_category text, p_error_message text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_evt public.statement_upload_events_outbox%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_event_id IS NULL OR p_error_category IS NULL OR p_error_message IS NULL THEN
    RAISE EXCEPTION 'record_statement_upload_event_handler_failed: required params missing' USING ERRCODE='22000';
  END IF;
  IF length(p_error_message) = 0 OR length(p_error_message) > 2000 THEN
    RAISE EXCEPTION 'record_statement_upload_event_handler_failed: error_message length must be 1..2000' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_evt FROM public.statement_upload_events_outbox WHERE event_id = p_event_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'EVENT_NOT_FOUND', 'event_id', p_event_id);
  END IF;
  UPDATE public.statement_upload_events_outbox
    SET status = 'FAILED'::public.statement_upload_event_status_enum,
        failed_at = clock_timestamp(),
        last_error_category = p_error_category,
        last_error_message = p_error_message
    WHERE event_id = p_event_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'statement_upload_trigger';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'STATEMENT_UPLOAD_EVENT_HANDLER_FAILED',
    p_subject_type => 'TRIGGER_EVENT'::audit.subject_type_enum,
    p_subject_id => p_event_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_evt.organization_id, p_business_id => v_evt.business_id,
    p_after_state => jsonb_build_object(
      'event_id', p_event_id,
      'error_category', p_error_category,
      'error_message', p_error_message),
    p_reason => format('event handler failed on %s: %s — %s',
                       p_event_id, p_error_category, left(p_error_message, 200)));
  RETURN jsonb_build_object('ok', true, 'event_id', p_event_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_pipeline_fixture_ran(p_fixture_name text, p_test_run_id text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_fixture public.pipeline_fixtures%ROWTYPE;
  v_run_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_fixture_name IS NULL OR p_test_run_id IS NULL OR length(p_test_run_id) = 0 THEN
    RAISE EXCEPTION 'record_pipeline_fixture_ran: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_fixture FROM public.pipeline_fixtures WHERE name = p_fixture_name;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'FIXTURE_NOT_FOUND', 'fixture_name', p_fixture_name);
  END IF;
  IF v_fixture.removed_at IS NOT NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'FIXTURE_REMOVED',
      'fixture_name', p_fixture_name, 'removed_at', v_fixture.removed_at);
  END IF;
  INSERT INTO public.pipeline_fixture_runs
    (id, fixture_name, test_run_id, status, started_at, actor_user_id)
  VALUES
    (v_run_id, p_fixture_name, p_test_run_id, 'RAN', clock_timestamp(), p_actor_user_id);
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'pipeline_fixture_runner';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'PIPELINE_FIXTURE_RAN',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => v_run_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_after_state => jsonb_build_object(
      'fixture_run_id', v_run_id,
      'fixture_name', p_fixture_name,
      'test_run_id', p_test_run_id,
      'format', v_fixture.format::text),
    p_reason => format('pipeline fixture ran: %s (test_run=%s)', p_fixture_name, p_test_run_id));
  RETURN jsonb_build_object('ok', true, 'fixture_run_id', v_run_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_pipeline_fixture_passed(p_fixture_run_id uuid, p_duration_ms integer, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.pipeline_fixture_runs%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_fixture_run_id IS NULL OR p_duration_ms IS NULL THEN
    RAISE EXCEPTION 'record_pipeline_fixture_passed: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_duration_ms < 0 THEN
    RAISE EXCEPTION 'record_pipeline_fixture_passed: duration_ms must be >= 0' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_run FROM public.pipeline_fixture_runs WHERE id = p_fixture_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_pipeline_fixture_passed: fixture_run % not found', p_fixture_run_id USING ERRCODE='02000';
  END IF;
  IF v_run.status <> 'RAN'::public.pipeline_fixture_run_status_enum THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NOT_IN_RAN_STATE', 'current_status', v_run.status::text);
  END IF;
  UPDATE public.pipeline_fixture_runs
    SET status = 'PASSED'::public.pipeline_fixture_run_status_enum,
        duration_ms = p_duration_ms, completed_at = clock_timestamp()
    WHERE id = p_fixture_run_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'pipeline_fixture_runner';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'PIPELINE_FIXTURE_PASSED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => p_fixture_run_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_after_state => jsonb_build_object(
      'fixture_run_id', p_fixture_run_id,
      'fixture_name', v_run.fixture_name,
      'test_run_id', v_run.test_run_id,
      'duration_ms', p_duration_ms),
    p_reason => format('pipeline fixture %s passed in %s ms', v_run.fixture_name, p_duration_ms));
  RETURN jsonb_build_object('ok', true, 'fixture_run_id', p_fixture_run_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

