CREATE OR REPLACE FUNCTION public.record_pipeline_fixture_removed(p_fixture_name text, p_removal_reason text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_fixture public.pipeline_fixtures%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_fixture_name IS NULL OR p_removal_reason IS NULL THEN
    RAISE EXCEPTION 'record_pipeline_fixture_removed: required params missing' USING ERRCODE='22000';
  END IF;
  IF length(p_removal_reason) = 0 OR length(p_removal_reason) > 2000 THEN
    RAISE EXCEPTION 'record_pipeline_fixture_removed: removal_reason length must be 1..2000' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_fixture FROM public.pipeline_fixtures WHERE name = p_fixture_name FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'FIXTURE_NOT_FOUND', 'fixture_name', p_fixture_name);
  END IF;
  IF v_fixture.removed_at IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'fixture_name', p_fixture_name, 'removed_at', v_fixture.removed_at);
  END IF;
  UPDATE public.pipeline_fixtures
    SET removed_at = clock_timestamp(),
        removed_by_user_id = p_actor_user_id,
        removal_reason = p_removal_reason,
        updated_at = clock_timestamp()
    WHERE name = p_fixture_name;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'pipeline_fixture_runner';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'PIPELINE_FIXTURE_REMOVED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id => NULL,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_after_state => jsonb_build_object(
      'fixture_name', p_fixture_name,
      'removal_reason', p_removal_reason,
      'removed_by_user_id', p_actor_user_id),
    p_reason => format('pipeline fixture %s removed: %s', p_fixture_name, left(p_removal_reason, 200)));
  RETURN jsonb_build_object('ok', true, 'fixture_name', p_fixture_name, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.upsert_classification_rule(p_actor_user_id uuid, p_business_id uuid, p_rule_kind classification_rule_kind_enum, p_rule_predicate jsonb, p_assigned_type transaction_type_enum, p_assigned_tag text DEFAULT NULL::text, p_priority integer DEFAULT 100, p_rule_id uuid DEFAULT NULL::uuid, p_organization_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_decision text; v_can jsonb; v_rule_id uuid;
  v_action_audit text;
  v_audit_row audit.audit_events;
  v_existing public.classification_rules%ROWTYPE;
  v_business_resolved uuid; v_org_resolved uuid;
BEGIN
  IF p_rule_kind IS NULL OR p_rule_predicate IS NULL OR p_assigned_type IS NULL THEN
    RAISE EXCEPTION 'upsert_classification_rule: required params missing' USING ERRCODE='22000';
  END IF;
  IF jsonb_typeof(p_rule_predicate) <> 'object' THEN
    RAISE EXCEPTION 'upsert_classification_rule: rule_predicate must be an object' USING ERRCODE='22023';
  END IF;
  IF p_priority < 0 THEN
    RAISE EXCEPTION 'upsert_classification_rule: priority must be >= 0' USING ERRCODE='22023';
  END IF;
  IF (p_business_id IS NULL) <> (p_organization_id IS NULL) THEN
    RAISE EXCEPTION 'upsert_classification_rule: business_id and organization_id must both be set or both NULL' USING ERRCODE='22023';
  END IF;

  v_can := public.can_perform(
    p_actor_user_id, 'classification_rule',
    CASE WHEN p_rule_id IS NULL THEN 'CREATE' ELSE 'UPDATE' END,
    jsonb_build_object('business_id', p_business_id, 'rule_kind', p_rule_kind::text,
      'assigned_type', p_assigned_type::text,
      'scope', CASE WHEN p_business_id IS NULL THEN 'GLOBAL' ELSE 'BUSINESS' END),
    p_business_id, p_organization_id);
  v_decision := v_can->>'decision';
  IF v_decision <> 'ALLOW' THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'CLASSIFICATION_RULE_MUTATION_DENIED',
      p_subject_type => 'BUSINESS'::audit.subject_type_enum,
      p_subject_id => p_business_id,
      p_actor_user_id => p_actor_user_id,
      p_organization_id => p_organization_id, p_business_id => p_business_id,
      p_reason => format('policy %s for %s classification rule', v_decision,
                         CASE WHEN p_rule_id IS NULL THEN 'CREATE' ELSE 'UPDATE' END),
      p_after_state => jsonb_build_object('decision', v_decision,
        'rule_kind', p_rule_kind::text, 'rule_id', p_rule_id));
    RETURN jsonb_build_object('ok', false, 'reason', 'POLICY_DENIED',
      'decision', v_decision, 'audit_event_id', v_audit_row.id);
  END IF;

  IF p_rule_id IS NULL THEN
    v_rule_id := public.gen_uuid_v7();
    INSERT INTO public.classification_rules
      (id, organization_id, business_id, rule_kind, rule_predicate,
       assigned_type, assigned_tag, priority, enabled, created_at, updated_at, created_by_user_id)
    VALUES
      (v_rule_id, p_organization_id, p_business_id, p_rule_kind, p_rule_predicate,
       p_assigned_type, p_assigned_tag, p_priority, true,
       clock_timestamp(), clock_timestamp(), p_actor_user_id);
    v_action_audit := 'CLASSIFICATION_RULE_CREATED';
    v_business_resolved := p_business_id; v_org_resolved := p_organization_id;
  ELSE
    SELECT * INTO v_existing FROM public.classification_rules WHERE id = p_rule_id FOR UPDATE;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'upsert_classification_rule: rule % not found', p_rule_id USING ERRCODE='02000';
    END IF;
    UPDATE public.classification_rules
      SET rule_kind = p_rule_kind, rule_predicate = p_rule_predicate,
          assigned_type = p_assigned_type, assigned_tag = p_assigned_tag,
          priority = p_priority, updated_at = clock_timestamp()
      WHERE id = p_rule_id;
    v_rule_id := p_rule_id; v_action_audit := 'CLASSIFICATION_RULE_UPDATED';
    v_business_resolved := v_existing.business_id; v_org_resolved := v_existing.organization_id;
  END IF;

  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => v_action_audit,
    p_subject_type => 'BUSINESS'::audit.subject_type_enum,
    p_subject_id => v_business_resolved,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_org_resolved, p_business_id => v_business_resolved,
    p_after_state => jsonb_build_object(
      'rule_id', v_rule_id, 'business_id', v_business_resolved,
      'scope', CASE WHEN v_business_resolved IS NULL THEN 'GLOBAL' ELSE 'BUSINESS' END,
      'rule_kind', p_rule_kind::text, 'assigned_type', p_assigned_type::text,
      'assigned_tag', p_assigned_tag, 'priority', p_priority,
      'rule_predicate', p_rule_predicate),
    p_reason => format('classification rule %s: kind=%s type=%s priority=%s',
                       CASE WHEN p_rule_id IS NULL THEN 'created' ELSE 'updated' END,
                       p_rule_kind::text, p_assigned_type::text, p_priority));
  RETURN jsonb_build_object('ok', true, 'rule_id', v_rule_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.disable_classification_rule(p_actor_user_id uuid, p_rule_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_rule public.classification_rules%ROWTYPE;
  v_can jsonb; v_decision text;
  v_audit_row audit.audit_events;
BEGIN
  IF p_rule_id IS NULL THEN
    RAISE EXCEPTION 'disable_classification_rule: p_rule_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_rule FROM public.classification_rules WHERE id = p_rule_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'disable_classification_rule: rule % not found', p_rule_id USING ERRCODE='02000';
  END IF;
  IF NOT v_rule.enabled THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true, 'rule_id', p_rule_id);
  END IF;
  v_can := public.can_perform(
    p_actor_user_id, 'classification_rule', 'DISABLE',
    jsonb_build_object('rule_id', p_rule_id, 'business_id', v_rule.business_id,
                       'scope', CASE WHEN v_rule.business_id IS NULL THEN 'GLOBAL' ELSE 'BUSINESS' END),
    v_rule.business_id, v_rule.organization_id);
  v_decision := v_can->>'decision';
  IF v_decision <> 'ALLOW' THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'CLASSIFICATION_RULE_MUTATION_DENIED',
      p_subject_type => 'BUSINESS'::audit.subject_type_enum,
      p_subject_id => v_rule.business_id,
      p_actor_user_id => p_actor_user_id,
      p_organization_id => v_rule.organization_id, p_business_id => v_rule.business_id,
      p_reason => format('policy %s for DISABLE classification rule %s', v_decision, p_rule_id),
      p_after_state => jsonb_build_object('decision', v_decision, 'rule_id', p_rule_id));
    RETURN jsonb_build_object('ok', false, 'reason', 'POLICY_DENIED',
      'decision', v_decision, 'audit_event_id', v_audit_row.id);
  END IF;
  UPDATE public.classification_rules
    SET enabled = false, updated_at = clock_timestamp()
    WHERE id = p_rule_id;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum,
    p_action => 'CLASSIFICATION_RULE_DISABLED',
    p_subject_type => 'BUSINESS'::audit.subject_type_enum,
    p_subject_id => v_rule.business_id,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_rule.organization_id, p_business_id => v_rule.business_id,
    p_after_state => jsonb_build_object(
      'rule_id', p_rule_id, 'business_id', v_rule.business_id,
      'rule_kind', v_rule.rule_kind::text,
      'scope', CASE WHEN v_rule.business_id IS NULL THEN 'GLOBAL' ELSE 'BUSINESS' END),
    p_reason => format('classification rule %s disabled', p_rule_id));
  RETURN jsonb_build_object('ok', true, 'rule_id', p_rule_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.lookup_vendor_memory(p_business_id uuid, p_counterparty_signature text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_row public.recurring_vendor_memory%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
  v_confidence numeric;
BEGIN
  IF p_business_id IS NULL OR p_counterparty_signature IS NULL
     OR length(p_counterparty_signature) = 0 THEN
    RAISE EXCEPTION 'lookup_vendor_memory: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_row FROM public.recurring_vendor_memory
    WHERE business_id = p_business_id
      AND counterparty_signature = p_counterparty_signature
      AND status = 'ACTIVE'::public.vendor_memory_status_enum
    LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('hit', false,
      'business_id', p_business_id, 'counterparty_signature', p_counterparty_signature);
  END IF;
  v_confidence := public.vendor_memory_confidence_for_count(v_row.confirmations_count);
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_layer2';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'VENDOR_MEMORY_HIT',
    p_subject_type => 'BUSINESS'::audit.subject_type_enum,
    p_subject_id => p_business_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_row.organization_id, p_business_id => p_business_id,
    p_after_state => jsonb_build_object(
      'vendor_memory_id', v_row.id,
      'business_id', p_business_id,
      'counterparty_signature', p_counterparty_signature,
      'suggested_type', v_row.suggested_type::text,
      'suggested_tag', v_row.suggested_tag,
      'confirmations_count', v_row.confirmations_count,
      'confidence', v_confidence),
    p_reason => format('vendor memory hit: business=%s signature=%s confidence=%s',
                       p_business_id, p_counterparty_signature, v_confidence));
  RETURN jsonb_build_object(
    'hit', true,
    'vendor_memory_id', v_row.id,
    'suggested_type', v_row.suggested_type::text,
    'suggested_tag', v_row.suggested_tag,
    'confirmations_count', v_row.confirmations_count,
    'confidence', v_confidence,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_rule_matched(p_transaction_id uuid, p_rule_id uuid, p_confidence numeric, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_rule public.classification_rules%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_rule_id IS NULL OR p_confidence IS NULL THEN
    RAISE EXCEPTION 'record_classification_rule_matched: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_confidence < 0 OR p_confidence > 1 THEN
    RAISE EXCEPTION 'record_classification_rule_matched: confidence must be in [0,1] (got %)', p_confidence USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_rule_matched: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  SELECT * INTO v_rule FROM public.classification_rules WHERE id = p_rule_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_rule_matched: rule % not found', p_rule_id USING ERRCODE='02000';
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_layer1';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'CLASSIFICATION_RULE_MATCHED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id, 'rule_id', p_rule_id,
      'confidence', p_confidence,
      'rule_kind', v_rule.rule_kind::text,
      'assigned_type', v_rule.assigned_type::text,
      'assigned_tag', v_rule.assigned_tag,
      'rule_scope', CASE WHEN v_rule.business_id IS NULL THEN 'GLOBAL' ELSE 'BUSINESS' END),
    p_reason => format('classification rule matched: tx=%s rule=%s confidence=%s',
                       p_transaction_id, p_rule_id, p_confidence));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'rule_id', p_rule_id,
    'assigned_type', v_rule.assigned_type::text,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.confirm_vendor_memory(p_business_id uuid, p_organization_id uuid, p_counterparty_signature text, p_suggested_type transaction_type_enum, p_suggested_tag text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_existing public.recurring_vendor_memory%ROWTYPE;
  v_id uuid := public.gen_uuid_v7();
  v_new_count int;
  v_was_created boolean := false;
  v_promoted boolean := false;
  v_audit_row audit.audit_events;
  v_audit_promo audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_business_id IS NULL OR p_organization_id IS NULL
     OR p_counterparty_signature IS NULL OR length(p_counterparty_signature) = 0
     OR p_suggested_type IS NULL THEN
    RAISE EXCEPTION 'confirm_vendor_memory: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_existing FROM public.recurring_vendor_memory
    WHERE business_id = p_business_id
      AND counterparty_signature = p_counterparty_signature
      AND status = 'ACTIVE'::public.vendor_memory_status_enum
    FOR UPDATE;
  IF FOUND THEN
    v_new_count := v_existing.confirmations_count + 1;
    UPDATE public.recurring_vendor_memory
      SET confirmations_count = v_new_count,
          last_confirmation_at = clock_timestamp(),
          suggested_type = p_suggested_type,
          suggested_tag = p_suggested_tag,
          updated_at = clock_timestamp()
      WHERE id = v_existing.id;
    v_id := v_existing.id;
    IF v_existing.confirmations_count = 2 AND v_new_count = 3 THEN
      v_promoted := true;
    END IF;
  ELSE
    INSERT INTO public.recurring_vendor_memory
      (id, organization_id, business_id, counterparty_signature,
       suggested_type, suggested_tag, confirmations_count,
       first_seen_at, last_confirmation_at, status, created_at, updated_at)
    VALUES
      (v_id, p_organization_id, p_business_id, p_counterparty_signature,
       p_suggested_type, p_suggested_tag, 1,
       clock_timestamp(), clock_timestamp(), 'ACTIVE'::public.vendor_memory_status_enum,
       clock_timestamp(), clock_timestamp());
    v_new_count := 1;
    v_was_created := true;
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_layer2';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind,
    p_action => CASE WHEN v_was_created THEN 'VENDOR_MEMORY_CREATED' ELSE 'VENDOR_MEMORY_CONFIRMED' END,
    p_subject_type => 'BUSINESS'::audit.subject_type_enum,
    p_subject_id => p_business_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => p_organization_id, p_business_id => p_business_id,
    p_after_state => jsonb_build_object(
      'vendor_memory_id', v_id,
      'counterparty_signature', p_counterparty_signature,
      'suggested_type', p_suggested_type::text,
      'suggested_tag', p_suggested_tag,
      'confirmations_count', v_new_count,
      'was_created', v_was_created),
    p_reason => format('vendor memory %s: %s count=%s',
                       CASE WHEN v_was_created THEN 'created' ELSE 'confirmed' END,
                       p_counterparty_signature, v_new_count));
  IF v_promoted THEN
    v_audit_promo := audit.emit_audit(
      p_actor_kind => v_kind, p_action => 'VENDOR_MEMORY_PROMOTED_TO_HIGH',
      p_subject_type => 'BUSINESS'::audit.subject_type_enum,
      p_subject_id => p_business_id,
      p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
      p_organization_id => p_organization_id, p_business_id => p_business_id,
      p_after_state => jsonb_build_object(
        'vendor_memory_id', v_id,
        'counterparty_signature', p_counterparty_signature,
        'suggested_type', p_suggested_type::text,
        'confirmations_count', v_new_count,
        'new_confidence', 0.88),
      p_reason => format('vendor memory promoted to HIGH: %s reached 3 confirmations',
                         p_counterparty_signature));
  END IF;
  RETURN jsonb_build_object('ok', true,
    'vendor_memory_id', v_id,
    'confirmations_count', v_new_count,
    'was_created', v_was_created,
    'promoted_to_high', v_promoted,
    'confidence', public.vendor_memory_confidence_for_count(v_new_count),
    'audit_event_id', v_audit_row.id,
    'promotion_audit_event_id', CASE WHEN v_promoted THEN v_audit_promo.id ELSE NULL END);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_rule_conflict(p_transaction_id uuid, p_workflow_run_id uuid, p_conflicting_rule_ids uuid[], p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_review_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_workflow_run_id IS NULL OR p_conflicting_rule_ids IS NULL THEN
    RAISE EXCEPTION 'record_classification_rule_conflict: required params missing' USING ERRCODE='22000';
  END IF;
  IF COALESCE(array_length(p_conflicting_rule_ids, 1), 0) < 2 THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'INSUFFICIENT_CONFLICTING_RULES',
      'conflicting_count', COALESCE(array_length(p_conflicting_rule_ids, 1), 0));
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_rule_conflict: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  INSERT INTO public.review_issues
    (id, organization_id, business_id, workflow_run_id, transaction_id,
     issue_type, issue_group, severity,
     plain_language_title, plain_language_description,
     card_payload_json, card_content_tier_used, card_content_fallback_applied,
     status, created_at, updated_at)
  VALUES
    (v_review_id, v_tx.organization_id, v_tx.business_id, p_workflow_run_id, p_transaction_id,
     'classification.rule_conflict',
     'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
     'MEDIUM'::public.review_issue_severity_enum,
     'Conflicting classification rules matched this transaction',
     'Multiple classification rules matched this transaction with different assigned types. The transaction will not be auto-classified until you resolve the conflict — review the matched rules and choose which one applies.',
     jsonb_build_object(
       'transaction_id', p_transaction_id,
       'conflicting_rule_ids', to_jsonb(p_conflicting_rule_ids),
       'conflicting_rule_count', array_length(p_conflicting_rule_ids, 1)),
     'NONE'::public.review_issue_card_content_tier_enum, false,
     'OPEN'::public.review_issue_status_enum,
     clock_timestamp(), clock_timestamp());
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_layer1';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'CLASSIFICATION_RULE_CONFLICT',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'review_issue_id', v_review_id,
      'conflicting_rule_ids', to_jsonb(p_conflicting_rule_ids)),
    p_reason => format('classification rule conflict on tx %s: %s rules',
                       p_transaction_id, array_length(p_conflicting_rule_ids, 1)));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'review_issue_id', v_review_id,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

