CREATE OR REPLACE FUNCTION public.get_classification_rules_for_business(p_business_id uuid)
 RETURNS SETOF classification_rules
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT * FROM public.classification_rules
  WHERE enabled = true AND (business_id IS NULL OR business_id = p_business_id)
  ORDER BY priority ASC, created_at ASC;
$function$
;

CREATE OR REPLACE FUNCTION public.vendor_memory_confidence_for_count(p_confirmations_count integer)
 RETURNS numeric
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_confirmations_count <= 0 THEN 0.0::numeric
    WHEN p_confirmations_count = 1 THEN 0.60::numeric
    WHEN p_confirmations_count = 2 THEN 0.72::numeric
    ELSE 0.88::numeric
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.raise_duplicate_pattern_detected(p_organization_id uuid, p_business_id uuid, p_pattern_kind text, p_primary_id uuid, p_related_ids uuid[], p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue_type text; v_subject_type audit.subject_type_enum;
  v_existing_issue_id uuid; v_review_issue_id uuid;
  v_anchor_txn_id uuid; v_anchor_doc_id uuid;
BEGIN
  IF p_pattern_kind NOT IN ('document_used_multiple_times','transaction_multi_match') THEN
    RAISE EXCEPTION 'PATTERN_KIND_INVALID' USING errcode='check_violation';
  END IF;
  IF p_primary_id IS NULL THEN
    RAISE EXCEPTION 'PRIMARY_ID_REQUIRED' USING errcode='check_violation';
  END IF;
  IF p_related_ids IS NULL OR array_length(p_related_ids, 1) IS NULL THEN
    RAISE EXCEPTION 'RELATED_IDS_REQUIRED' USING errcode='check_violation';
  END IF;

  IF p_pattern_kind = 'document_used_multiple_times' THEN
    v_issue_type := 'matching.document_used_multiple_times';
    v_subject_type := 'DOCUMENT'::audit.subject_type_enum;
    v_anchor_doc_id := p_primary_id;
  ELSE
    v_issue_type := 'matching.transaction_multi_match';
    v_subject_type := 'TRANSACTION'::audit.subject_type_enum;
    v_anchor_txn_id := p_primary_id;
  END IF;

  IF p_pattern_kind = 'document_used_multiple_times' THEN
    SELECT id INTO v_existing_issue_id FROM public.review_issues
    WHERE business_id = p_business_id AND issue_type = v_issue_type
      AND document_id = p_primary_id
      AND status = 'OPEN'::public.review_issue_status_enum
    LIMIT 1;
  ELSE
    SELECT id INTO v_existing_issue_id FROM public.review_issues
    WHERE business_id = p_business_id AND issue_type = v_issue_type
      AND transaction_id = p_primary_id
      AND status = 'OPEN'::public.review_issue_status_enum
    LIMIT 1;
  END IF;

  IF v_existing_issue_id IS NOT NULL THEN
    RETURN jsonb_build_object(
      'decision','ALREADY_RAISED', 'review_issue_id', v_existing_issue_id,
      'pattern_kind', p_pattern_kind, 'primary_id', p_primary_id
    );
  END IF;

  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id,
    transaction_id, document_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action,
    card_payload_json
  ) VALUES (
    p_organization_id, p_business_id, p_workflow_run_id,
    v_anchor_txn_id, v_anchor_doc_id,
    v_issue_type,
    'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
    'HIGH'::public.review_issue_severity_enum,
    CASE WHEN p_pattern_kind = 'document_used_multiple_times'
         THEN 'A document is attached to multiple transactions'
         ELSE 'A transaction has multiple unrelated matches' END,
    CASE WHEN p_pattern_kind = 'document_used_multiple_times'
         THEN 'The same document is matched to several transactions but none are part of a confirmed split-payment group. Confirm whether this is a legitimate split, reject one of the matches, or mark the document as a duplicate.'
         ELSE 'This transaction has more than one match record pointing at different documents, with no confirmed split-payment group tying them together. Pick the right match, mark as a legitimate multi-match, or edit the matches.' END,
    CASE WHEN p_pattern_kind = 'document_used_multiple_times'
         THEN 'Confirm as split-payment, reject a match, or mark as duplicate'
         ELSE 'Pick the right match, mark as legitimate multi-match, or edit' END,
    jsonb_build_object(
      'pattern_kind', p_pattern_kind,
      'primary_id', p_primary_id,
      'related_ids', to_jsonb(p_related_ids),
      'related_count', array_length(p_related_ids, 1)
    )
  ) RETURNING id INTO v_review_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_DUPLICATE_PATTERN_DETECTED',
    p_subject_type:=v_subject_type,
    p_subject_id:=p_primary_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'pattern_kind', p_pattern_kind, 'primary_id', p_primary_id,
      'related_ids', to_jsonb(p_related_ids),
      'review_issue_id', v_review_issue_id
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','RAISED', 'review_issue_id', v_review_issue_id,
    'pattern_kind', p_pattern_kind, 'primary_id', p_primary_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.revoke_vendor_memory(p_vendor_memory_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_row public.recurring_vendor_memory%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_vendor_memory_id IS NULL THEN
    RAISE EXCEPTION 'revoke_vendor_memory: p_vendor_memory_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_row FROM public.recurring_vendor_memory WHERE id = p_vendor_memory_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'VENDOR_MEMORY_NOT_FOUND',
      'vendor_memory_id', p_vendor_memory_id);
  END IF;
  IF v_row.status = 'REVOKED'::public.vendor_memory_status_enum THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'vendor_memory_id', p_vendor_memory_id);
  END IF;
  UPDATE public.recurring_vendor_memory
    SET status = 'REVOKED'::public.vendor_memory_status_enum,
        updated_at = clock_timestamp()
    WHERE id = p_vendor_memory_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_layer2';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'VENDOR_MEMORY_REVOKED',
    p_subject_type => 'BUSINESS'::audit.subject_type_enum,
    p_subject_id => v_row.business_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_row.organization_id, p_business_id => v_row.business_id,
    p_after_state => jsonb_build_object(
      'vendor_memory_id', p_vendor_memory_id,
      'counterparty_signature', v_row.counterparty_signature,
      'previous_confirmations_count', v_row.confirmations_count,
      'previous_suggested_type', v_row.suggested_type::text),
    p_reason => format('vendor memory revoked: %s (prior count=%s)',
                       v_row.counterparty_signature, v_row.confirmations_count));
  RETURN jsonb_build_object('ok', true,
    'vendor_memory_id', p_vendor_memory_id,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_income_match(p_transaction_id uuid, p_invoice_id uuid, p_outcome income_match_outcome_enum, p_workflow_run_id uuid, p_has_reference_match boolean DEFAULT false, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid;
  v_direction public.transaction_direction_enum;
  v_new_match_status public.transaction_match_status_enum;
  v_review_issue_id uuid;
  v_review_group public.review_issue_group_enum;
  v_review_severity public.review_issue_severity_enum;
  v_review_title text; v_review_desc text; v_review_action text;
  v_audit_action text;
BEGIN
  SELECT organization_id, business_id, direction
    INTO v_organization_id, v_business_id, v_direction
  FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','TRANSACTION_NOT_FOUND','transaction_id',p_transaction_id);
  END IF;

  CASE p_outcome
    WHEN 'FULL_MATCH' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_FULL_MATCH';
      IF p_has_reference_match THEN
        v_new_match_status := 'MATCHED_AUTO_CONFIRMED';
      ELSE
        v_new_match_status := 'MATCHED_PROPOSED';
        v_review_group:='NEEDS_CONFIRMATION'; v_review_severity:='MEDIUM';
        v_review_title:='Confirm income match';
        v_review_desc :='The amount matches an outstanding invoice but the payment reference does not. Please confirm this is the right invoice.';
        v_review_action:='Review and confirm or reject the matched invoice';
      END IF;
    WHEN 'PARTIAL_PAYMENT' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_PARTIAL_PAYMENT';
      v_new_match_status:='MATCHED_PROPOSED';
      v_review_group:='NEEDS_CONFIRMATION'; v_review_severity:='MEDIUM';
      v_review_title:='Partial payment on invoice';
      v_review_desc :='This incoming payment is less than the invoice total. Confirm to mark the invoice as partially paid.';
      v_review_action:='Confirm partial payment allocation';
    WHEN 'OVERPAYMENT' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_OVERPAYMENT';
      v_new_match_status:='MATCHED_PROPOSED';
      v_review_group:='NEEDS_CONFIRMATION'; v_review_severity:='MEDIUM';
      v_review_title:='Overpayment received';
      v_review_desc :='This payment exceeds the invoice total. Confirm to mark the invoice as overpaid, and choose whether to issue a credit note for the surplus.';
      v_review_action:='Confirm overpayment and decide on credit note';
    WHEN 'MULTIPLE_INVOICES_ONE_PAYMENT' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_MULTIPLE_INVOICES_ONE_PAYMENT';
      v_new_match_status:='MATCHED_PROPOSED';
      v_review_group:='NEEDS_CONFIRMATION'; v_review_severity:='MEDIUM';
      v_review_title:='One payment covers multiple invoices';
      v_review_desc :='Several outstanding invoices sum to this payment amount. Confirm the allocation across invoices.';
      v_review_action:='Confirm multi-invoice allocation';
    WHEN 'ONE_INVOICE_MULTIPLE_PAYMENTS' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_ONE_INVOICE_MULTIPLE_PAYMENTS';
      v_new_match_status:='MATCHED_AUTO_CONFIRMED';
    WHEN 'NO_MATCH' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_NO_MATCH';
      v_new_match_status:='UNMATCHED';
    WHEN 'POSSIBLE_REFUND_OR_TRANSFER' THEN
      v_audit_action := 'INCOME_MATCHING_OUTCOME_POSSIBLE_REFUND_OR_TRANSFER';
      v_new_match_status:='MATCHED_PROPOSED';
      v_review_group:='POSSIBLE_WRONG_MATCH'; v_review_severity:='MEDIUM';
      v_review_title:='Possible refund or internal transfer';
      v_review_desc :='This incoming amount looks like a refund of a prior outgoing payment, or an internal transfer. Consider reclassifying the transaction type.';
      v_review_action:='Confirm invoice match, or reclassify as REFUND_IN / INTERNAL_TRANSFER';
  END CASE;

  UPDATE public.transactions
    SET income_match_outcome = p_outcome,
        matched_invoice_id   = CASE WHEN p_outcome='NO_MATCH' THEN NULL ELSE p_invoice_id END,
        match_status         = v_new_match_status,
        updated_at           = clock_timestamp()
  WHERE id = p_transaction_id;

  IF v_review_group IS NOT NULL THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action,
      card_payload_json
    ) VALUES (
      v_organization_id, v_business_id, p_workflow_run_id, p_transaction_id,
      'income_matching.' || lower(p_outcome::text),
      v_review_group, v_review_severity,
      v_review_title, v_review_desc, v_review_action,
      jsonb_build_object('outcome',p_outcome,'invoice_id',p_invoice_id,'has_reference_match',p_has_reference_match)
    ) RETURNING id INTO v_review_issue_id;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:=v_audit_action,
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='income_matching_engine',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'outcome',p_outcome,'invoice_id',p_invoice_id,
      'has_reference_match',p_has_reference_match,
      'new_match_status',v_new_match_status,
      'review_issue_id',v_review_issue_id,
      'workflow_run_id',p_workflow_run_id),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision', CASE WHEN v_new_match_status='MATCHED_AUTO_CONFIRMED' THEN 'AUTO_CONFIRMED'
                     WHEN v_new_match_status='UNMATCHED' THEN 'NO_MATCH'
                     ELSE 'NEEDS_REVIEW' END,
    'transaction_id', p_transaction_id,
    'invoice_id', CASE WHEN p_outcome='NO_MATCH' THEN NULL ELSE p_invoice_id END,
    'outcome', p_outcome,
    'match_status', v_new_match_status,
    'review_issue_id', v_review_issue_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_invoice_lifecycle_transitioned(p_organization_id uuid, p_business_id uuid, p_invoice_id uuid, p_new_status text, p_transaction_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
