CREATE OR REPLACE FUNCTION public.record_ai_classification_failed(p_transaction_id uuid, p_workflow_run_id uuid, p_error_category text, p_error_message text, p_gateway_invocation_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_review_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_workflow_run_id IS NULL OR p_error_category IS NULL OR p_error_message IS NULL THEN
    RAISE EXCEPTION 'record_ai_classification_failed: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_error_category NOT IN ('SCHEMA_VIOLATION','MODEL_ERROR','COST_CEILING_REACHED','GATEWAY_TIMEOUT','LAYER3_DISABLED','OTHER') THEN
    RAISE EXCEPTION 'record_ai_classification_failed: unknown error_category %', p_error_category USING ERRCODE='22023';
  END IF;
  IF length(p_error_message) = 0 OR length(p_error_message) > 2000 THEN
    RAISE EXCEPTION 'record_ai_classification_failed: error_message length must be 1..2000' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_ai_classification_failed: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  INSERT INTO public.review_issues
    (id, organization_id, business_id, workflow_run_id, transaction_id,
     issue_type, issue_group, severity,
     plain_language_title, plain_language_description,
     card_payload_json, card_content_tier_used, card_content_fallback_applied,
     status, created_at, updated_at)
  VALUES
    (v_review_id, v_tx.organization_id, v_tx.business_id, p_workflow_run_id, p_transaction_id,
     'classification.ai_fallback_failed',
     'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
     'MEDIUM'::public.review_issue_severity_enum,
     'AI classification could not propose a type',
     format('The AI fallback classifier (Layer 3) was unable to suggest a transaction type (%s). Please classify this transaction manually.', p_error_category),
     jsonb_build_object(
       'transaction_id', p_transaction_id,
       'gateway_invocation_id', p_gateway_invocation_id,
       'error_category', p_error_category,
       'error_message', p_error_message),
     'NONE'::public.review_issue_card_content_tier_enum, false,
     'OPEN'::public.review_issue_status_enum,
     clock_timestamp(), clock_timestamp());
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_layer3';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'AI_CLASSIFICATION_FAILED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'review_issue_id', v_review_id,
      'gateway_invocation_id', p_gateway_invocation_id,
      'error_category', p_error_category,
      'error_message', p_error_message),
    p_reason => format('AI classification failed on tx %s: %s — %s',
                       p_transaction_id, p_error_category, left(p_error_message, 200)));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id,
    'review_issue_id', v_review_id,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_active_taxonomy_for_business(p_business_id uuid)
 RETURNS tag_taxonomy_versions
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT v.* FROM public.business_tag_taxonomy_assignments a
  JOIN public.tag_taxonomy_versions v ON v.id = a.tag_taxonomy_version_id
  WHERE a.business_id = p_business_id
  UNION ALL
  SELECT * FROM public.tag_taxonomy_versions
  WHERE is_default = true
    AND NOT EXISTS (SELECT 1 FROM public.business_tag_taxonomy_assignments WHERE business_id = p_business_id)
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.get_default_tag_for_type(p_business_id uuid, p_transaction_type transaction_type_enum)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_active public.tag_taxonomy_versions;
  v_tag text;
BEGIN
  SELECT * INTO v_active FROM public.get_active_taxonomy_for_business(p_business_id);
  IF NOT FOUND THEN RETURN NULL; END IF;
  SELECT (entry->>'tag_name') INTO v_tag
    FROM jsonb_array_elements(v_active.definition) AS entry
    WHERE entry->>'transaction_type' = p_transaction_type::text
      AND COALESCE((entry->>'is_type_default')::boolean, false) = true
    LIMIT 1;
  RETURN v_tag;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_tag_against_taxonomy(p_business_id uuid, p_tag_name text, p_transaction_type transaction_type_enum)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_active public.tag_taxonomy_versions;
  v_entry_matches_type boolean;
  v_custom_match text;
BEGIN
  IF p_business_id IS NULL OR p_tag_name IS NULL OR p_transaction_type IS NULL THEN
    RAISE EXCEPTION 'validate_tag_against_taxonomy: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_active FROM public.get_active_taxonomy_for_business(p_business_id);
  IF FOUND THEN
    SELECT EXISTS (
      SELECT 1 FROM jsonb_array_elements(v_active.definition) AS entry
      WHERE entry->>'tag_name' = p_tag_name
        AND entry->>'transaction_type' = p_transaction_type::text
    ) INTO v_entry_matches_type;
    IF v_entry_matches_type THEN
      RETURN jsonb_build_object('valid', true, 'source', 'TAXONOMY',
        'taxonomy_version_id', v_active.id);
    END IF;
  END IF;
  SELECT tag_name INTO v_custom_match FROM public.business_custom_tags
    WHERE business_id = p_business_id
      AND tag_name = p_tag_name
      AND mapped_transaction_type = p_transaction_type;
  IF v_custom_match IS NOT NULL THEN
    RETURN jsonb_build_object('valid', true, 'source', 'CUSTOM');
  END IF;
  RETURN jsonb_build_object('valid', false,
    'reason', 'TAG_NOT_IN_TAXONOMY_OR_CUSTOM',
    'tag_name', p_tag_name,
    'transaction_type', p_transaction_type::text);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_tag_assigned(p_transaction_id uuid, p_primary_tag text, p_source classification_method_enum, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_validation jsonb;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_primary_tag IS NULL OR p_source IS NULL THEN
    RAISE EXCEPTION 'record_tag_assigned: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_tag_assigned: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  v_validation := public.validate_tag_against_taxonomy(v_tx.business_id, p_primary_tag, v_tx.transaction_type);
  IF (v_validation->>'valid')::bool IS NOT TRUE THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'TAG_NOT_VALID_FOR_TYPE',
      'validation', v_validation);
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'tag_system';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'TAG_ASSIGNED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'primary_tag', p_primary_tag,
      'source', p_source::text,
      'tag_source', v_validation->>'source'),
    p_reason => format('tag assigned: tx=%s tag=%s source=%s',
                       p_transaction_id, p_primary_tag, p_source::text));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'primary_tag', p_primary_tag,
    'tag_source', v_validation->>'source', 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_secondary_tag_added(p_transaction_id uuid, p_tag_name text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_already boolean;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_tag_name IS NULL OR length(p_tag_name) = 0 THEN
    RAISE EXCEPTION 'record_secondary_tag_added: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_secondary_tag_added: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  SELECT EXISTS (SELECT 1 FROM jsonb_array_elements_text(COALESCE(v_tx.secondary_tags, '[]'::jsonb)) AS t WHERE t = p_tag_name)
    INTO v_already;
  IF v_already THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
      'transaction_id', p_transaction_id, 'tag_name', p_tag_name);
  END IF;
  UPDATE public.transactions
    SET secondary_tags = COALESCE(secondary_tags, '[]'::jsonb) || jsonb_build_array(p_tag_name),
        updated_at = clock_timestamp()
    WHERE id = p_transaction_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'tag_system';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'SECONDARY_TAG_ADDED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object('transaction_id', p_transaction_id, 'tag_name', p_tag_name),
    p_reason => format('secondary tag added: tx=%s tag=%s', p_transaction_id, p_tag_name));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'tag_name', p_tag_name,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

