    p_subject_id => v_tag.business_id,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_tag.organization_id, p_business_id => v_tag.business_id,
    p_after_state => jsonb_build_object(
      'custom_tag_id', p_custom_tag_id,
      'tag_name', v_tag.tag_name,
      'mapped_transaction_type', v_tag.mapped_transaction_type::text,
      'retirement_reason', p_retirement_reason),
    p_reason => format('custom tag retired: %s (%s)', v_tag.tag_name, left(p_retirement_reason, 200)));
  RETURN jsonb_build_object('ok', true,
    'custom_tag_id', p_custom_tag_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_custom_tag(p_actor_user_id uuid, p_custom_tag_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tag public.business_custom_tags%ROWTYPE;
  v_can jsonb; v_decision text;
  v_audit_row audit.audit_events;
  v_name_now_taken boolean;
BEGIN
  IF p_custom_tag_id IS NULL THEN
    RAISE EXCEPTION 'restore_custom_tag: p_custom_tag_id is required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tag FROM public.business_custom_tags WHERE id = p_custom_tag_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'restore_custom_tag: tag % not found', p_custom_tag_id USING ERRCODE='02000';
  END IF;
  IF v_tag.retired_at IS NULL THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true, 'custom_tag_id', p_custom_tag_id);
  END IF;
  v_can := public.can_perform(
    p_actor_user_id, 'business_custom_tag', 'RESTORE',
    jsonb_build_object('custom_tag_id', p_custom_tag_id),
    v_tag.business_id, v_tag.organization_id);
  v_decision := v_can->>'decision';
  IF v_decision <> 'ALLOW' THEN
    v_audit_row := audit.emit_audit(
      p_actor_kind => 'USER'::audit.actor_kind_enum,
      p_action => 'CUSTOM_TAG_MUTATION_DENIED',
      p_subject_type => 'BUSINESS'::audit.subject_type_enum,
      p_subject_id => v_tag.business_id,
      p_actor_user_id => p_actor_user_id,
      p_organization_id => v_tag.organization_id, p_business_id => v_tag.business_id,
      p_reason => format('policy %s for RESTORE custom tag %s', v_decision, p_custom_tag_id),
      p_after_state => jsonb_build_object('decision', v_decision, 'custom_tag_id', p_custom_tag_id));
    RETURN jsonb_build_object('ok', false, 'reason', 'POLICY_DENIED',
      'decision', v_decision, 'audit_event_id', v_audit_row.id);
  END IF;
  SELECT EXISTS (
    SELECT 1 FROM public.business_custom_tags
    WHERE business_id = v_tag.business_id
      AND LOWER(tag_name) = LOWER(v_tag.tag_name)
      AND id <> p_custom_tag_id
      AND retired_at IS NULL
  ) INTO v_name_now_taken;
  IF v_name_now_taken THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NAME_NOW_TAKEN', 'tag_name', v_tag.tag_name);
  END IF;
  UPDATE public.business_custom_tags
    SET retired_at = NULL, retired_by_user_id = NULL, retirement_reason = NULL
    WHERE id = p_custom_tag_id;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum,
    p_action => 'CUSTOM_TAG_RESTORED',
    p_subject_type => 'BUSINESS'::audit.subject_type_enum,
    p_subject_id => v_tag.business_id,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_tag.organization_id, p_business_id => v_tag.business_id,
    p_after_state => jsonb_build_object(
      'custom_tag_id', p_custom_tag_id,
      'tag_name', v_tag.tag_name,
      'mapped_transaction_type', v_tag.mapped_transaction_type::text),
    p_reason => format('custom tag restored: %s', v_tag.tag_name));
  RETURN jsonb_build_object('ok', true,
    'custom_tag_id', p_custom_tag_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_auto_confirm_threshold(p_business_id uuid, p_transaction_type transaction_type_enum)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_row public.classification_auto_confirm_thresholds%ROWTYPE;
BEGIN
  SELECT * INTO v_row FROM public.classification_auto_confirm_thresholds
    WHERE business_id = p_business_id AND transaction_type = p_transaction_type LIMIT 1;
  IF FOUND THEN
    IF v_row.never_auto_confirm THEN RETURN NULL; END IF;
    RETURN v_row.threshold;
  END IF;
  SELECT * INTO v_row FROM public.classification_auto_confirm_thresholds
    WHERE business_id IS NULL AND transaction_type = p_transaction_type LIMIT 1;
  IF NOT FOUND THEN RETURN NULL; END IF;
  IF v_row.never_auto_confirm THEN RETURN NULL; END IF;
  RETURN v_row.threshold;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.merge_layer_confidence(p_l1_conf numeric, p_l1_type transaction_type_enum, p_l2_conf numeric, p_l2_type transaction_type_enum, p_l3_conf numeric, p_l3_type transaction_type_enum)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_winner_type public.transaction_type_enum;
  v_winner_conf numeric;
  v_other_types_count int;
  v_agreeing_count int;
  v_base_conf numeric;
  v_merged numeric;
  v_boost boolean := false;
  v_penalty boolean := false;
  v_contributing text[] := '{}';
BEGIN
  IF p_l1_conf IS NULL AND p_l2_conf IS NULL AND p_l3_conf IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NO_LAYER_RESULTS');
  END IF;
  v_winner_conf := -1;
  IF p_l1_conf IS NOT NULL THEN
    v_contributing := v_contributing || ARRAY['L1'];
    IF p_l1_conf > v_winner_conf THEN v_winner_conf := p_l1_conf; v_winner_type := p_l1_type; END IF;
  END IF;
  IF p_l2_conf IS NOT NULL THEN
    v_contributing := v_contributing || ARRAY['L2'];
    IF p_l2_conf > v_winner_conf THEN v_winner_conf := p_l2_conf; v_winner_type := p_l2_type; END IF;
  END IF;
  IF p_l3_conf IS NOT NULL THEN
    v_contributing := v_contributing || ARRAY['L3'];
    IF p_l3_conf > v_winner_conf THEN v_winner_conf := p_l3_conf; v_winner_type := p_l3_type; END IF;
  END IF;
  v_agreeing_count := 0;
  IF p_l1_conf IS NOT NULL AND p_l1_type = v_winner_type THEN v_agreeing_count := v_agreeing_count + 1; END IF;
  IF p_l2_conf IS NOT NULL AND p_l2_type = v_winner_type THEN v_agreeing_count := v_agreeing_count + 1; END IF;
  IF p_l3_conf IS NOT NULL AND p_l3_type = v_winner_type THEN v_agreeing_count := v_agreeing_count + 1; END IF;
  v_other_types_count := 0;
  IF p_l1_conf IS NOT NULL AND p_l1_type <> v_winner_type THEN v_other_types_count := v_other_types_count + 1; END IF;
  IF p_l2_conf IS NOT NULL AND p_l2_type <> v_winner_type THEN v_other_types_count := v_other_types_count + 1; END IF;
  IF p_l3_conf IS NOT NULL AND p_l3_type <> v_winner_type THEN v_other_types_count := v_other_types_count + 1; END IF;
  v_base_conf := v_winner_conf;
  v_merged := v_base_conf;
  IF v_agreeing_count >= 2 THEN
    v_merged := LEAST(0.95, v_merged + 0.10);
    v_boost := true;
  END IF;
  IF v_other_types_count >= 1 THEN
    v_merged := GREATEST(0.0, v_merged - 0.10);
    v_penalty := true;
  END IF;
  RETURN jsonb_build_object(
    'ok', true, 'chosen_type', v_winner_type::text,
    'base_confidence', v_base_conf, 'merged_confidence', v_merged,
    'agreement_boost_applied', v_boost, 'disagreement_penalty_applied', v_penalty,
    'agreeing_count', v_agreeing_count, 'other_types_count', v_other_types_count,
    'contributing_layers', to_jsonb(v_contributing));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_auto_confirmed(p_transaction_id uuid, p_merged_confidence numeric, p_chosen_type transaction_type_enum, p_classification_method classification_method_enum, p_chosen_tag text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_threshold numeric;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_merged_confidence IS NULL OR p_chosen_type IS NULL OR p_classification_method IS NULL THEN
    RAISE EXCEPTION 'record_classification_auto_confirmed: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_merged_confidence < 0 OR p_merged_confidence > 1 THEN
    RAISE EXCEPTION 'record_classification_auto_confirmed: merged_confidence must be in [0,1]' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_auto_confirmed: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  v_threshold := public.get_auto_confirm_threshold(v_tx.business_id, p_chosen_type);
  IF v_threshold IS NULL OR p_merged_confidence < v_threshold THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'THRESHOLD_NOT_MET',
      'merged_confidence', p_merged_confidence, 'threshold', v_threshold,
      'chosen_type', p_chosen_type::text);
  END IF;
  UPDATE public.transactions
    SET transaction_type = p_chosen_type,
        system_tag = COALESCE(p_chosen_tag, system_tag),
        classification_status = 'CONFIRMED'::public.transaction_classification_status_enum,
        classification_confidence = p_merged_confidence,
        classification_method = p_classification_method,
        updated_at = clock_timestamp()
    WHERE id = p_transaction_id;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_confidence';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'CLASSIFICATION_AUTO_CONFIRMED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'chosen_type', p_chosen_type::text, 'chosen_tag', p_chosen_tag,
      'merged_confidence', p_merged_confidence, 'threshold', v_threshold,
      'classification_method', p_classification_method::text),
    p_reason => format('classification auto-confirmed: tx=%s type=%s confidence=%s threshold=%s',
                       p_transaction_id, p_chosen_type::text, p_merged_confidence, v_threshold));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'chosen_type', p_chosen_type::text,
    'merged_confidence', p_merged_confidence, 'threshold', v_threshold,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_needs_confirmation(p_transaction_id uuid, p_workflow_run_id uuid, p_merged_confidence numeric, p_chosen_type transaction_type_enum, p_classification_method classification_method_enum, p_chosen_tag text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_threshold numeric; v_gap numeric;
  v_severity public.review_issue_severity_enum;
  v_review_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_workflow_run_id IS NULL OR p_merged_confidence IS NULL
     OR p_chosen_type IS NULL OR p_classification_method IS NULL THEN
    RAISE EXCEPTION 'record_classification_needs_confirmation: required params missing' USING ERRCODE='22000';
  END IF;
  IF p_merged_confidence < 0 OR p_merged_confidence > 1 THEN
    RAISE EXCEPTION 'record_classification_needs_confirmation: merged_confidence must be in [0,1]' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_needs_confirmation: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  v_threshold := public.get_auto_confirm_threshold(v_tx.business_id, p_chosen_type);
  v_gap := COALESCE(v_threshold, 1.0) - p_merged_confidence;
  IF v_gap <= 0 THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'CONFIDENCE_AT_OR_ABOVE_THRESHOLD',
      'merged_confidence', p_merged_confidence, 'threshold', v_threshold);
  END IF;
  IF v_gap <= 0.10 THEN v_severity := 'LOW'::public.review_issue_severity_enum;
  ELSIF v_gap <= 0.30 THEN v_severity := 'MEDIUM'::public.review_issue_severity_enum;
  ELSE v_severity := 'HIGH'::public.review_issue_severity_enum; END IF;
  UPDATE public.transactions
    SET transaction_type = p_chosen_type,
        system_tag = COALESCE(p_chosen_tag, system_tag),
        classification_status = 'NEEDS_CONFIRMATION'::public.transaction_classification_status_enum,
        classification_confidence = p_merged_confidence,
        classification_method = p_classification_method,
        updated_at = clock_timestamp()
    WHERE id = p_transaction_id;
  INSERT INTO public.review_issues
    (id, organization_id, business_id, workflow_run_id, transaction_id,
     issue_type, issue_group, severity,
     plain_language_title, plain_language_description,
     card_payload_json, card_content_tier_used, card_content_fallback_applied,
     status, created_at, updated_at)
  VALUES
    (v_review_id, v_tx.organization_id, v_tx.business_id, p_workflow_run_id, p_transaction_id,
     'classification.needs_confirmation',
     'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
     v_severity,
     'Confirm or adjust the classification of this transaction',
     format('The classifier suggests %s (confidence %s) but is below the auto-confirm threshold %s. Please confirm, override with a different type, or mark this suggestion as wrong.',
            p_chosen_type::text, p_merged_confidence, COALESCE(v_threshold::text, 'never auto-confirm')),
     jsonb_build_object(
       'transaction_id', p_transaction_id,
       'suggested_type', p_chosen_type::text, 'suggested_tag', p_chosen_tag,
       'merged_confidence', p_merged_confidence, 'threshold', v_threshold, 'gap', v_gap,
       'classification_method', p_classification_method::text),
     'NONE'::public.review_issue_card_content_tier_enum, false,
     'OPEN'::public.review_issue_status_enum,
     clock_timestamp(), clock_timestamp());
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_confidence';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'CLASSIFICATION_NEEDS_CONFIRMATION',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id, 'review_issue_id', v_review_id,
      'severity', v_severity::text,
      'chosen_type', p_chosen_type::text,
      'merged_confidence', p_merged_confidence,
      'threshold', v_threshold, 'gap', v_gap),
    p_reason => format('classification needs confirmation: tx=%s gap=%s severity=%s',
                       p_transaction_id, v_gap, v_severity::text));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id,
    'review_issue_id', v_review_id,
    'severity', v_severity::text, 'gap', v_gap,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_user_confirmed(p_review_issue_id uuid, p_transaction_id uuid, p_actor_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_review public.review_issues%ROWTYPE;
  v_audit_row audit.audit_events;
BEGIN
  IF p_review_issue_id IS NULL OR p_transaction_id IS NULL OR p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'record_classification_user_confirmed: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_user_confirmed: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  SELECT * INTO v_review FROM public.review_issues WHERE id = p_review_issue_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_user_confirmed: review_issue % not found', p_review_issue_id USING ERRCODE='02000';
  END IF;
  UPDATE public.transactions
    SET classification_status = 'CONFIRMED'::public.transaction_classification_status_enum,
        updated_at = clock_timestamp()
    WHERE id = p_transaction_id;
  UPDATE public.review_issues
    SET status = 'RESOLVED'::public.review_issue_status_enum,
        resolved_by = p_actor_user_id,
        resolved_at = clock_timestamp(),
        resolution_action = 'CONFIRM',
        updated_at = clock_timestamp()
    WHERE id = p_review_issue_id;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum,
    p_action => 'CLASSIFICATION_USER_CONFIRMED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'review_issue_id', p_review_issue_id,
      'confirmed_type', v_tx.transaction_type::text),
    p_reason => format('user confirmed classification: tx=%s', p_transaction_id));
  RETURN jsonb_build_object('ok', true, 'transaction_id', p_transaction_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_user_overridden(p_review_issue_id uuid, p_transaction_id uuid, p_new_type transaction_type_enum, p_actor_user_id uuid, p_new_tag text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_review public.review_issues%ROWTYPE;
  v_audit_row audit.audit_events;
  v_previous_type public.transaction_type_enum;
BEGIN
  IF p_review_issue_id IS NULL OR p_transaction_id IS NULL OR p_new_type IS NULL OR p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'record_classification_user_overridden: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_user_overridden: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  SELECT * INTO v_review FROM public.review_issues WHERE id = p_review_issue_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_user_overridden: review_issue % not found', p_review_issue_id USING ERRCODE='02000';
  END IF;
  v_previous_type := v_tx.transaction_type;
  UPDATE public.transactions
    SET transaction_type = p_new_type,
        user_tag = COALESCE(p_new_tag, user_tag),
        classification_status = 'CONFIRMED'::public.transaction_classification_status_enum,
        classification_method = 'MANUAL'::public.classification_method_enum,
        updated_at = clock_timestamp()
    WHERE id = p_transaction_id;
  UPDATE public.review_issues
    SET status = 'RESOLVED'::public.review_issue_status_enum,
        resolved_by = p_actor_user_id,
        resolved_at = clock_timestamp(),
        resolution_action = 'OVERRIDE',
        updated_at = clock_timestamp()
    WHERE id = p_review_issue_id;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum,
    p_action => 'CLASSIFICATION_USER_OVERRIDDEN',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_before_state => jsonb_build_object('transaction_type', v_previous_type::text),
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'review_issue_id', p_review_issue_id,
      'previous_type', v_previous_type::text,
      'new_type', p_new_type::text, 'new_tag', p_new_tag),
    p_reason => format('user overrode classification: tx=%s %s → %s',
                       p_transaction_id, v_previous_type::text, p_new_type::text));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id,
    'previous_type', v_previous_type::text,
    'new_type', p_new_type::text,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_classification_user_rejected(p_review_issue_id uuid, p_transaction_id uuid, p_actor_user_id uuid, p_vendor_memory_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_review public.review_issues%ROWTYPE;
  v_audit_row audit.audit_events;
  v_revoked jsonb;
BEGIN
  IF p_review_issue_id IS NULL OR p_transaction_id IS NULL OR p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'record_classification_user_rejected: required params missing' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_user_rejected: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  SELECT * INTO v_review FROM public.review_issues WHERE id = p_review_issue_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_classification_user_rejected: review_issue % not found', p_review_issue_id USING ERRCODE='02000';
  END IF;
  UPDATE public.review_issues
    SET status = 'RESOLVED'::public.review_issue_status_enum,
        resolved_by = p_actor_user_id,
        resolved_at = clock_timestamp(),
        resolution_action = 'REJECT',
        updated_at = clock_timestamp()
    WHERE id = p_review_issue_id;
  IF p_vendor_memory_id IS NOT NULL THEN
    v_revoked := public.revoke_vendor_memory(p_vendor_memory_id, p_actor_user_id);
  END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum,
    p_action => 'CLASSIFICATION_USER_REJECTED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'review_issue_id', p_review_issue_id,
      'vendor_memory_revoked_id', p_vendor_memory_id,
      'revoke_envelope', v_revoked),
    p_reason => format('user rejected classification: tx=%s (vendor_memory_revoked=%s)',
                       p_transaction_id, p_vendor_memory_id));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id,
    'vendor_memory_revoked', p_vendor_memory_id IS NOT NULL,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_multi_layer_agreement_boost(p_transaction_id uuid, p_agreeing_layers text[], p_base_confidence numeric, p_boosted_confidence numeric, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_agreeing_layers IS NULL OR p_base_confidence IS NULL OR p_boosted_confidence IS NULL THEN
    RAISE EXCEPTION 'record_multi_layer_agreement_boost: required params missing' USING ERRCODE='22000';
  END IF;
  IF COALESCE(array_length(p_agreeing_layers, 1), 0) < 2 THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'INSUFFICIENT_AGREEING_LAYERS');
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_multi_layer_agreement_boost: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_confidence';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'CLASSIFICATION_MULTI_LAYER_AGREEMENT_BOOST',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id,
      'agreeing_layers', to_jsonb(p_agreeing_layers),
      'base_confidence', p_base_confidence,
      'boosted_confidence', p_boosted_confidence),
    p_reason => format('multi-layer agreement boost: %s → %s', p_base_confidence, p_boosted_confidence));
  RETURN jsonb_build_object('ok', true, 'transaction_id', p_transaction_id, 'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_layer_disagreement_flagged(p_transaction_id uuid, p_workflow_run_id uuid, p_layer_decisions jsonb, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_tx public.transactions%ROWTYPE;
  v_review_id uuid := public.gen_uuid_v7();
  v_audit_row audit.audit_events;
  v_kind audit.actor_kind_enum; v_system text;
BEGIN
  IF p_transaction_id IS NULL OR p_workflow_run_id IS NULL OR p_layer_decisions IS NULL THEN
    RAISE EXCEPTION 'record_layer_disagreement_flagged: required params missing' USING ERRCODE='22000';
  END IF;
  IF jsonb_typeof(p_layer_decisions) <> 'object' THEN
    RAISE EXCEPTION 'record_layer_disagreement_flagged: layer_decisions must be a jsonb object' USING ERRCODE='22023';
  END IF;
  SELECT * INTO v_tx FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'record_layer_disagreement_flagged: transaction % not found', p_transaction_id USING ERRCODE='02000';
  END IF;
  INSERT INTO public.review_issues
    (id, organization_id, business_id, workflow_run_id, transaction_id,
     issue_type, issue_group, severity,
     plain_language_title, plain_language_description,
     card_payload_json, card_content_tier_used, card_content_fallback_applied,
     status, created_at, updated_at)
  VALUES
    (v_review_id, v_tx.organization_id, v_tx.business_id, p_workflow_run_id, p_transaction_id,
     'classification.layer_disagreement',
     'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
     'LOW'::public.review_issue_severity_enum,
     'Classifier layers disagreed on this transaction',
     'The deterministic rules, vendor memory, and AI classifier returned different types for this transaction. The run proceeded with the highest-confidence answer; you can review and optionally correct.',
     jsonb_build_object('transaction_id', p_transaction_id, 'layer_decisions', p_layer_decisions),
     'NONE'::public.review_issue_card_content_tier_enum, false,
     'OPEN'::public.review_issue_status_enum,
     clock_timestamp(), clock_timestamp());
  IF p_actor_user_id IS NULL THEN v_kind := 'SYSTEM'::audit.actor_kind_enum; v_system := 'classification_confidence';
  ELSE v_kind := 'USER'::audit.actor_kind_enum; v_system := NULL; END IF;
  v_audit_row := audit.emit_audit(
    p_actor_kind => v_kind, p_action => 'CLASSIFICATION_LAYER_DISAGREEMENT_FLAGGED',
    p_subject_type => 'TRANSACTION'::audit.subject_type_enum,
    p_subject_id => p_transaction_id,
    p_actor_user_id => p_actor_user_id, p_actor_system => v_system,
    p_organization_id => v_tx.organization_id, p_business_id => v_tx.business_id,
    p_after_state => jsonb_build_object(
      'transaction_id', p_transaction_id, 'review_issue_id', v_review_id,
      'layer_decisions', p_layer_decisions),
    p_reason => format('classifier layers disagreed on tx %s', p_transaction_id));
  RETURN jsonb_build_object('ok', true,
    'transaction_id', p_transaction_id, 'review_issue_id', v_review_id,
    'audit_event_id', v_audit_row.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.workflow_runs_snapshot_immutable_tg()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.classification_taxonomy_snapshot IS NOT NULL
     AND NEW.classification_taxonomy_snapshot IS DISTINCT FROM OLD.classification_taxonomy_snapshot THEN
    RAISE EXCEPTION 'workflow_runs.classification_taxonomy_snapshot is immutable once captured (run %)', OLD.id
      USING ERRCODE = '23514';
  END IF;
  RETURN NEW;
END$function$
;

CREATE OR REPLACE FUNCTION public.resolve_tag_name(p_workflow_run_id uuid, p_tag_id uuid)
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  WITH snap AS (
    SELECT classification_taxonomy_snapshot AS s
      FROM public.workflow_runs
     WHERE id = p_workflow_run_id
       AND classification_taxonomy_snapshot IS NOT NULL
  ),
  custom AS (
    SELECT (ct->>'name') AS name
      FROM snap, jsonb_array_elements((snap.s->'custom_tags')) ct
     WHERE (ct->>'id')::uuid = p_tag_id
     LIMIT 1
  ),
  defn AS (
    SELECT (tag->>'label') AS name
      FROM snap, jsonb_array_elements((snap.s->'taxonomy_definition')) tag
     WHERE (tag->>'id')::uuid = p_tag_id
     LIMIT 1
  )
  SELECT COALESCE((SELECT name FROM custom),
                  (SELECT name FROM defn),
                  '(unknown tag)');
$function$
;

CREATE OR REPLACE FUNCTION public.admin_create_default_taxonomy_version(p_version_label text, p_definition jsonb, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_new_id              uuid := public.gen_uuid_v7();
  v_prev_default        public.tag_taxonomy_versions%ROWTYPE;
  v_audit_created       audit.audit_events%ROWTYPE;
  v_audit_superseded    audit.audit_events%ROWTYPE;
BEGIN
  IF p_version_label IS NULL OR length(trim(p_version_label)) = 0 THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'VERSION_LABEL_REQUIRED');
  END IF;
  IF p_definition IS NULL OR jsonb_typeof(p_definition) <> 'array' THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'DEFINITION_MUST_BE_ARRAY');
  END IF;

  SELECT * INTO v_prev_default
    FROM public.tag_taxonomy_versions
   WHERE is_default = true
   LIMIT 1;

  IF FOUND THEN
    UPDATE public.tag_taxonomy_versions
       SET is_default = false,
           retired_at = COALESCE(retired_at, clock_timestamp())
     WHERE id = v_prev_default.id;

    v_audit_superseded := audit.emit_audit(
      p_actor_kind    => 'USER'::audit.actor_kind_enum,
      p_action        => 'TAG_TAXONOMY_VERSION_RETIRED',
      p_subject_type  => 'TAG_TAXONOMY_VERSION'::audit.subject_type_enum,
      p_subject_id    => v_prev_default.id,
      p_actor_user_id => p_user_id,
      p_after_state   => jsonb_build_object(
                           'version_label',       v_prev_default.version_label,
                           'superseded_by_label', p_version_label,
                           'reason',              'SUPERSEDED'
                         ),
      p_reason        => format('taxonomy version superseded: %s by %s', v_prev_default.version_label, p_version_label)
    );
  END IF;

  INSERT INTO public.tag_taxonomy_versions(id, version_label, definition, is_default, created_at)
  VALUES (v_new_id, p_version_label, p_definition, true, clock_timestamp());

  v_audit_created := audit.emit_audit(
    p_actor_kind    => 'USER'::audit.actor_kind_enum,
    p_action        => 'TAG_TAXONOMY_VERSION_CREATED',
    p_subject_type  => 'TAG_TAXONOMY_VERSION'::audit.subject_type_enum,
    p_subject_id    => v_new_id,
    p_actor_user_id => p_user_id,
    p_after_state   => jsonb_build_object(
                         'version_label',         p_version_label,
                         'superseded_version_id', v_prev_default.id
                       ),
    p_reason        => format('new default taxonomy created: %s', p_version_label)
  );

  RETURN jsonb_build_object(
    'ok',                        true,
    'taxonomy_version_id',       v_new_id,
    'superseded_version_id',     v_prev_default.id,
    'audit_event_id',            v_audit_created.id,
    'audit_superseded_event_id', v_audit_superseded.id
  );
END$function$
;

CREATE OR REPLACE FUNCTION public.snapshot_taxonomy(p_workflow_run_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run            public.workflow_runs%ROWTYPE;
  v_assignment     public.business_tag_taxonomy_assignments%ROWTYPE;
  v_version        public.tag_taxonomy_versions%ROWTYPE;
  v_custom_tags    jsonb;
  v_snapshot       jsonb;
  v_audit_row      audit.audit_events%ROWTYPE;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'WORKFLOW_RUN_NOT_FOUND');
  END IF;

  IF v_run.classification_taxonomy_snapshot IS NOT NULL THEN
    RETURN jsonb_build_object(
      'ok',                true,
      'already_captured',  true,
      'workflow_run_id',   v_run.id,
      'taxonomy_version_id', v_run.classification_taxonomy_snapshot->>'taxonomy_version_id'
    );
  END IF;

  SELECT * INTO v_assignment
    FROM public.business_tag_taxonomy_assignments
   WHERE business_id = v_run.business_id
   ORDER BY assigned_at DESC
   LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'NO_TAXONOMY_ASSIGNMENT_FOR_BUSINESS');
  END IF;

  SELECT * INTO v_version FROM public.tag_taxonomy_versions WHERE id = v_assignment.tag_taxonomy_version_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'TAXONOMY_VERSION_NOT_FOUND');
  END IF;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
                    'id',                      ct.id,
                    'name',                    ct.tag_name,
                    'mapped_transaction_type', ct.mapped_transaction_type
                  ) ORDER BY ct.tag_name), '[]'::jsonb)
    INTO v_custom_tags
    FROM public.business_custom_tags ct
   WHERE ct.business_id = v_run.business_id
     AND ct.retired_at IS NULL;

  v_snapshot := jsonb_build_object(
    'taxonomy_version_id',    v_version.id,
    'taxonomy_version_label', v_version.version_label,
    'taxonomy_definition',    v_version.definition,
    'custom_tags',            v_custom_tags,
    'captured_at',            clock_timestamp()
  );

  UPDATE public.workflow_runs
     SET classification_taxonomy_snapshot = v_snapshot,
         tag_taxonomy_version_id          = v_version.id,
         updated_at                       = clock_timestamp()
   WHERE id = v_run.id;

  v_audit_row := audit.emit_audit(
    p_actor_kind      => 'USER'::audit.actor_kind_enum,
    p_action          => 'TAG_TAXONOMY_SNAPSHOT_CAPTURED',
    p_subject_type    => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id      => v_run.id,
    p_actor_user_id   => p_user_id,
    p_organization_id => v_run.organization_id,
    p_business_id     => v_run.business_id,
    p_after_state     => jsonb_build_object(
                           'taxonomy_version_id',    v_version.id,
                           'taxonomy_version_label', v_version.version_label,
                           'custom_tag_count',       jsonb_array_length(v_custom_tags)
                         ),
    p_reason          => format('taxonomy snapshot captured: run=%s version=%s', v_run.id, v_version.version_label)
  );

  RETURN jsonb_build_object(
    'ok',                  true,
    'already_captured',    false,
    'workflow_run_id',     v_run.id,
    'taxonomy_version_id', v_version.id,
    'audit_event_id',      v_audit_row.id
  );
END$function$
;

CREATE OR REPLACE FUNCTION public.assign_taxonomy_version_to_business(p_organization_id uuid, p_business_id uuid, p_taxonomy_version_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_version        public.tag_taxonomy_versions%ROWTYPE;
  v_assignment_id  uuid;
  v_audit_row      audit.audit_events%ROWTYPE;
BEGIN
  SELECT * INTO v_version FROM public.tag_taxonomy_versions WHERE id = p_taxonomy_version_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'TAXONOMY_VERSION_NOT_FOUND');
  END IF;
  IF v_version.retired_at IS NOT NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'TAXONOMY_VERSION_RETIRED');
  END IF;

  SELECT id INTO v_assignment_id
    FROM public.business_tag_taxonomy_assignments
   WHERE business_id = p_business_id;

  IF FOUND THEN
    UPDATE public.business_tag_taxonomy_assignments
       SET tag_taxonomy_version_id = p_taxonomy_version_id,
           assigned_at             = clock_timestamp(),
           assigned_by_user_id     = p_user_id,
           organization_id         = p_organization_id
     WHERE id = v_assignment_id;
  ELSE
    v_assignment_id := public.gen_uuid_v7();
    INSERT INTO public.business_tag_taxonomy_assignments(
      id, organization_id, business_id, tag_taxonomy_version_id, assigned_at, assigned_by_user_id
    ) VALUES (
      v_assignment_id, p_organization_id, p_business_id, p_taxonomy_version_id, clock_timestamp(), p_user_id
    );
  END IF;

  v_audit_row := audit.emit_audit(
    p_actor_kind      => 'USER'::audit.actor_kind_enum,
    p_action          => 'TAG_TAXONOMY_VERSION_ASSIGNED_TO_BUSINESS',
    p_subject_type    => 'BUSINESS_TAG_TAXONOMY_ASSIGNMENT'::audit.subject_type_enum,
    p_subject_id      => v_assignment_id,
    p_actor_user_id   => p_user_id,
    p_organization_id => p_organization_id,
    p_business_id     => p_business_id,
    p_after_state     => jsonb_build_object(
                           'taxonomy_version_id',    p_taxonomy_version_id,
                           'taxonomy_version_label', v_version.version_label
                         ),
    p_reason          => format('assigned taxonomy %s to business %s', v_version.version_label, p_business_id)
  );

  RETURN jsonb_build_object(
    'ok', true,
    'assignment_id', v_assignment_id,
    'taxonomy_version_id', p_taxonomy_version_id,
    'audit_event_id', v_audit_row.id
  );
END$function$
;

CREATE OR REPLACE FUNCTION public.admin_retire_default_taxonomy_version(p_taxonomy_version_id uuid, p_user_id uuid, p_retirement_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_version    public.tag_taxonomy_versions%ROWTYPE;
  v_audit_row  audit.audit_events%ROWTYPE;
BEGIN
  SELECT * INTO v_version FROM public.tag_taxonomy_versions WHERE id = p_taxonomy_version_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'TAXONOMY_VERSION_NOT_FOUND');
  END IF;
  IF v_version.retired_at IS NOT NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'ALREADY_RETIRED');
  END IF;
  IF v_version.is_default THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'CANNOT_RETIRE_ACTIVE_DEFAULT');
  END IF;

  UPDATE public.tag_taxonomy_versions
     SET retired_at = clock_timestamp()
   WHERE id = p_taxonomy_version_id;

  v_audit_row := audit.emit_audit(
    p_actor_kind    => 'USER'::audit.actor_kind_enum,
    p_action        => 'TAG_TAXONOMY_VERSION_RETIRED',
    p_subject_type  => 'TAG_TAXONOMY_VERSION'::audit.subject_type_enum,
    p_subject_id    => p_taxonomy_version_id,
    p_actor_user_id => p_user_id,
    p_after_state   => jsonb_build_object(
                         'version_label',     v_version.version_label,
                         'retirement_reason', p_retirement_reason,
                         'reason',            'EXPLICIT_RETIRE'
                       ),
    p_reason        => COALESCE(p_retirement_reason, format('explicit retire of %s', v_version.version_label))
  );

  RETURN jsonb_build_object('ok', true, 'taxonomy_version_id', p_taxonomy_version_id, 'audit_event_id', v_audit_row.id);
END$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_classify_entry_gate(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run        public.workflow_runs%ROWTYPE;
  v_total      int;
  v_non_pending int;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('passes', false, 'reason', 'WORKFLOW_RUN_NOT_FOUND');
  END IF;

  SELECT count(*) FILTER (WHERE TRUE),
         count(*) FILTER (WHERE classification_status NOT IN ('PENDING'::public.transaction_classification_status_enum)
                            AND classification_status IS NOT NULL)
    INTO v_total, v_non_pending
    FROM public.transactions
   WHERE statement_upload_id IN (SELECT id FROM public.statement_uploads WHERE business_id = v_run.business_id);

  IF v_non_pending > 0 THEN
    RETURN jsonb_build_object(
      'passes', false,
      'reason', 'NON_PENDING_TX_EXISTS',
      'total_count', v_total,
      'non_pending_count', v_non_pending
    );
  END IF;

  RETURN jsonb_build_object('passes', true, 'total_count', v_total);
END$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_classify_exit_gate(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run                public.workflow_runs%ROWTYPE;
  v_total              int;
  v_unresolved         int;
  v_null_type          int;
  v_needs_conf         int;
  v_needs_conf_no_iss  int;
  v_status_counts      jsonb;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('passes', false, 'reason', 'WORKFLOW_RUN_NOT_FOUND');
  END IF;

  WITH tx AS (
    SELECT t.id, t.classification_status, t.transaction_type
      FROM public.transactions t
     WHERE t.statement_upload_id IN (SELECT id FROM public.statement_uploads WHERE business_id = v_run.business_id)
  )
  SELECT count(*) FILTER (WHERE TRUE),
         count(*) FILTER (WHERE classification_status NOT IN
                                ('CONFIRMED'::public.transaction_classification_status_enum,
                                 'NEEDS_CONFIRMATION'::public.transaction_classification_status_enum)
                            OR classification_status IS NULL),
         count(*) FILTER (WHERE transaction_type IS NULL),
         count(*) FILTER (WHERE classification_status = 'NEEDS_CONFIRMATION'::public.transaction_classification_status_enum)
    INTO v_total, v_unresolved, v_null_type, v_needs_conf
    FROM tx;

  SELECT count(*)
    INTO v_needs_conf_no_iss
    FROM public.transactions t
   WHERE t.statement_upload_id IN (SELECT id FROM public.statement_uploads WHERE business_id = v_run.business_id)
     AND t.classification_status = 'NEEDS_CONFIRMATION'::public.transaction_classification_status_enum
     AND NOT EXISTS (SELECT 1 FROM public.review_issues ri WHERE ri.transaction_id = t.id);

  SELECT jsonb_object_agg(coalesce(s::text, 'NULL'), c) INTO v_status_counts
    FROM (
      SELECT classification_status::text AS s, count(*) AS c
        FROM public.transactions
       WHERE statement_upload_id IN (SELECT id FROM public.statement_uploads WHERE business_id = v_run.business_id)
       GROUP BY classification_status
    ) z;

  IF v_unresolved > 0 THEN
    RETURN jsonb_build_object('passes', false, 'reason', 'UNRESOLVED_TX_EXISTS',
      'total_count', v_total, 'unresolved_count', v_unresolved, 'status_counts', v_status_counts);
  END IF;
  IF v_null_type > 0 THEN
    RETURN jsonb_build_object('passes', false, 'reason', 'NULL_TRANSACTION_TYPE',
      'total_count', v_total, 'null_type_count', v_null_type, 'status_counts', v_status_counts);
  END IF;
  IF v_needs_conf_no_iss > 0 THEN
    RETURN jsonb_build_object('passes', false, 'reason', 'NEEDS_CONFIRMATION_MISSING_REVIEW_ISSUE',
      'total_count', v_total, 'missing_review_issues_count', v_needs_conf_no_iss, 'status_counts', v_status_counts);
  END IF;

  RETURN jsonb_build_object('passes', true, 'total_count', v_total,
                            'needs_confirmation_count', v_needs_conf,
                            'status_counts', v_status_counts);
END$function$
;

