CREATE OR REPLACE FUNCTION public.get_classifier_fixture_drift_summary(p_fixture_name text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_fix      public.classifier_fixtures%ROWTYPE;
  v_last_run public.classifier_fixture_runs%ROWTYPE;
BEGIN
  SELECT * INTO v_fix FROM public.classifier_fixtures WHERE name = p_fixture_name;
  IF NOT FOUND THEN RETURN jsonb_build_object('ok', false, 'reason', 'FIXTURE_NOT_FOUND'); END IF;

  SELECT * INTO v_last_run FROM public.classifier_fixture_runs
   WHERE fixture_name = p_fixture_name ORDER BY ran_at DESC LIMIT 1;

  RETURN jsonb_build_object(
    'ok', true,
    'fixture_name', p_fixture_name,
    'registered_hash', v_fix.fixture_hash,
    'retired_at', v_fix.retired_at,
    'last_run_at', v_last_run.ran_at,
    'last_run_status', v_last_run.status::text,
    'last_actual_hash', v_last_run.actual_hash,
    'drift_detected', CASE
                        WHEN v_last_run.id IS NULL THEN false
                        WHEN v_last_run.actual_hash IS NULL THEN false
                        ELSE v_last_run.actual_hash <> v_fix.fixture_hash
                      END
  );
END$function$
;

CREATE OR REPLACE FUNCTION public.transition_document(p_document_id uuid, p_target_state document_extraction_status_enum, p_reason text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_from_state      public.document_extraction_status_enum;
  v_document_type   public.document_type_enum;
  v_organization_id uuid;
  v_business_id     uuid;
  v_is_stub_only    boolean;
  v_registry_hit    boolean;
BEGIN
  SELECT extraction_status, document_type, organization_id, business_id
    INTO v_from_state, v_document_type, v_organization_id, v_business_id
  FROM public.documents
  WHERE id = p_document_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'decision',     'REJECTED',
      'reason',       'DOCUMENT_NOT_FOUND',
      'document_id',  p_document_id,
      'attempted_to', p_target_state
    );
  END IF;

  IF v_from_state = p_target_state THEN
    RETURN jsonb_build_object(
      'decision',    'NOOP',
      'document_id', p_document_id,
      'from_state',  v_from_state,
      'to_state',    p_target_state
    );
  END IF;

  SELECT is_stub_only INTO v_is_stub_only
  FROM public.document_state_transitions
  WHERE from_state = v_from_state AND to_state = p_target_state;
  v_registry_hit := FOUND;

  IF NOT v_registry_hit THEN
    PERFORM audit.emit_audit(
      p_actor_kind       := 'SYSTEM'::audit.actor_kind_enum,
      p_action           := 'DOCUMENT_STATE_CHANGE_REJECTED',
      p_subject_type     := 'DOCUMENT'::audit.subject_type_enum,
      p_subject_id       := p_document_id,
      p_actor_user_id    := NULL,
      p_actor_role       := NULL,
      p_actor_session_id := NULL,
      p_actor_system     := 'document_lifecycle',
      p_organization_id  := v_organization_id,
      p_business_id      := v_business_id,
      p_before_state     := jsonb_build_object('extraction_status', v_from_state),
      p_after_state      := jsonb_build_object(
        'attempted_to', p_target_state,
        'rejection',    'ILLEGAL_TRANSITION'
      ),
      p_reason           := p_reason,
      p_request_context  := p_context
    );
    RETURN jsonb_build_object(
      'decision',     'REJECTED',
      'reason',       'ILLEGAL_TRANSITION',
      'document_id',  p_document_id,
      'from_state',   v_from_state,
      'attempted_to', p_target_state
    );
  END IF;

  IF v_is_stub_only AND v_document_type <> 'STUB' THEN
    PERFORM audit.emit_audit(
      p_actor_kind       := 'SYSTEM'::audit.actor_kind_enum,
      p_action           := 'DOCUMENT_STATE_CHANGE_REJECTED',
      p_subject_type     := 'DOCUMENT'::audit.subject_type_enum,
      p_subject_id       := p_document_id,
      p_actor_user_id    := NULL,
      p_actor_role       := NULL,
      p_actor_session_id := NULL,
      p_actor_system     := 'document_lifecycle',
      p_organization_id  := v_organization_id,
      p_business_id      := v_business_id,
      p_before_state     := jsonb_build_object(
        'extraction_status', v_from_state,
        'document_type',     v_document_type
      ),
      p_after_state      := jsonb_build_object(
        'attempted_to', p_target_state,
        'rejection',    'STUB_ONLY_TRANSITION'
      ),
      p_reason           := p_reason,
      p_request_context  := p_context
    );
    RETURN jsonb_build_object(
      'decision',     'REJECTED',
      'reason',       'STUB_ONLY_TRANSITION',
      'document_id',  p_document_id,
      'from_state',   v_from_state,
      'attempted_to', p_target_state
    );
  END IF;

  UPDATE public.documents
     SET extraction_status = p_target_state,
         updated_at        = clock_timestamp()
   WHERE id = p_document_id;

  PERFORM audit.emit_audit(
    p_actor_kind       := 'SYSTEM'::audit.actor_kind_enum,
    p_action           := 'DOCUMENT_STATE_CHANGED',
    p_subject_type     := 'DOCUMENT'::audit.subject_type_enum,
    p_subject_id       := p_document_id,
    p_actor_user_id    := NULL,
    p_actor_role       := NULL,
    p_actor_session_id := NULL,
    p_actor_system     := 'document_lifecycle',
    p_organization_id  := v_organization_id,
    p_business_id      := v_business_id,
    p_before_state     := jsonb_build_object('extraction_status', v_from_state),
    p_after_state      := jsonb_build_object('extraction_status', p_target_state),
    p_reason           := p_reason,
    p_request_context  := p_context
  );

  RETURN jsonb_build_object(
    'decision',    'APPLIED',
    'document_id', p_document_id,
    'from_state',  v_from_state,
    'to_state',    p_target_state
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_document_stub(p_organization_id uuid, p_business_id uuid, p_reason text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_document_id      uuid;
  v_dismiss_envelope jsonb;
BEGIN
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'STUB_REASON_REQUIRED'
      USING errcode = 'check_violation';
  END IF;

  INSERT INTO public.documents (
    organization_id, business_id, source, document_type,
    extraction_status, discovery_reason
  ) VALUES (
    p_organization_id, p_business_id,
    'MANUAL'::public.document_source_enum,
    'STUB'::public.document_type_enum,
    'DISCOVERED'::public.document_extraction_status_enum,
    p_reason
  )
  RETURNING id INTO v_document_id;

  PERFORM audit.emit_audit(
    p_actor_kind       := 'SYSTEM'::audit.actor_kind_enum,
    p_action           := 'DOCUMENT_STUB_CREATED',
    p_subject_type     := 'DOCUMENT'::audit.subject_type_enum,
    p_subject_id       := v_document_id,
    p_actor_user_id    := NULL,
    p_actor_role       := NULL,
    p_actor_session_id := NULL,
    p_actor_system     := 'document_lifecycle',
    p_organization_id  := p_organization_id,
    p_business_id      := p_business_id,
    p_before_state     := NULL,
    p_after_state      := jsonb_build_object(
      'document_type',     'STUB',
      'extraction_status', 'DISCOVERED',
      'discovery_reason',  p_reason
    ),
    p_reason           := p_reason,
    p_request_context  := p_context
  );

  v_dismiss_envelope := public.transition_document(
    p_document_id  => v_document_id,
    p_target_state => 'DISMISSED'::public.document_extraction_status_enum,
    p_reason       => p_reason,
    p_context      => p_context
  );

  RETURN jsonb_build_object(
    'document_id', v_document_id,
    'state',       (v_dismiss_envelope->>'to_state'),
    'transition',  v_dismiss_envelope
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.begin_document_ocr_run(p_document_id uuid, p_processor_id text, p_input_format document_input_format_enum, p_was_converted boolean DEFAULT false, p_ai_gateway_invocation_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_business_id     uuid;
  v_current_status  public.document_extraction_status_enum;
  v_run_id          uuid;
BEGIN
  SELECT organization_id, business_id, extraction_status
    INTO v_organization_id, v_business_id, v_current_status
  FROM public.documents
  WHERE id = p_document_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','DOCUMENT_NOT_FOUND','document_id',p_document_id);
  END IF;

  IF v_current_status <> 'INGESTED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','DOCUMENT_NOT_INGESTED',
      'document_id',p_document_id,'current_status',v_current_status
    );
  END IF;

  INSERT INTO public.document_ocr_runs (
    organization_id, business_id, document_id, processor_id,
    input_format, was_converted, status, ai_gateway_invocation_id
  ) VALUES (
    v_organization_id, v_business_id, p_document_id, p_processor_id,
    p_input_format, p_was_converted, 'STARTED', p_ai_gateway_invocation_id
  )
  RETURNING id INTO v_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_OCR_STARTED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=p_document_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='document_ocr',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',v_run_id,'processor_id',p_processor_id,
      'input_format',p_input_format,'was_converted',p_was_converted
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  IF p_was_converted THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='DOCUMENT_FORMAT_CONVERTED',
      p_subject_type:='DOCUMENT'::audit.subject_type_enum,
      p_subject_id:=p_document_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='document_ocr',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'run_id',v_run_id,'input_format',p_input_format,
        'note','attachment converted before OCR dispatch'
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
  END IF;

  RETURN jsonb_build_object('decision','STARTED','run_id',v_run_id,'document_id',p_document_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_document_ocr_run(p_run_id uuid, p_page_count integer, p_extracted_fields jsonb, p_confidence_per_field jsonb, p_confidence_summary jsonb, p_prompt_version text, p_cost_estimate numeric DEFAULT NULL::numeric, p_compute_seconds numeric DEFAULT NULL::numeric, p_cost_currency text DEFAULT NULL::text, p_ai_usage_record_id uuid DEFAULT NULL::uuid, p_ai_payload_artifact_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_business_id     uuid;
  v_document_id     uuid;
  v_current_status  public.document_ocr_run_status_enum;
  v_transition_env  jsonb;
BEGIN
  SELECT organization_id, business_id, document_id, status
    INTO v_organization_id, v_business_id, v_document_id, v_current_status
  FROM public.document_ocr_runs
  WHERE id = p_run_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','OCR_RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  IF v_current_status <> 'STARTED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','OCR_RUN_NOT_STARTED',
      'run_id',p_run_id,'current_status',v_current_status
    );
  END IF;

  UPDATE public.document_ocr_runs
     SET status                 = 'SUCCEEDED',
         page_count             = p_page_count,
         confidence_summary     = COALESCE(p_confidence_summary,'{}'::jsonb),
         cost_estimate          = p_cost_estimate,
         compute_seconds        = p_compute_seconds,
         cost_currency          = p_cost_currency,
         ai_usage_record_id     = p_ai_usage_record_id,
         ai_payload_artifact_id = p_ai_payload_artifact_id,
         prompt_version         = p_prompt_version,
         completed_at           = clock_timestamp()
   WHERE id = p_run_id;

  INSERT INTO public.document_extraction_results (
    organization_id, business_id, document_id, extraction_layer,
    extracted_fields, confidence_per_field, started_at, completed_at,
    prompt_version, succeeded
  ) VALUES (
    v_organization_id, v_business_id, v_document_id, 'TIER3_AI',
    COALESCE(p_extracted_fields,'{}'::jsonb),
    COALESCE(p_confidence_per_field,'{}'::jsonb),
    clock_timestamp(), clock_timestamp(),
    p_prompt_version, true
  );

  v_transition_env := public.transition_document(
    p_document_id  => v_document_id,
    p_target_state => 'EXTRACTED'::public.document_extraction_status_enum,
    p_reason       => 'ocr_completed',
    p_context      => jsonb_build_object('run_id',p_run_id) || COALESCE(p_context,'{}'::jsonb)
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_OCR_COMPLETED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=v_document_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='document_ocr',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'page_count',p_page_count,
      'confidence_summary',COALESCE(p_confidence_summary,'{}'::jsonb),
      'cost_estimate',p_cost_estimate,'compute_seconds',p_compute_seconds,
      'transition',v_transition_env
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','COMPLETED','run_id',p_run_id,
    'document_id',v_document_id,'transition',v_transition_env
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fail_document_ocr_run(p_run_id uuid, p_error_category document_ocr_error_category_enum, p_error_summary text, p_is_transient boolean, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_business_id     uuid;
  v_document_id     uuid;
  v_current_status  public.document_ocr_run_status_enum;
BEGIN
  IF p_error_summary IS NULL OR length(trim(p_error_summary)) = 0 THEN
    RAISE EXCEPTION 'OCR_ERROR_SUMMARY_REQUIRED' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id, document_id, status
    INTO v_organization_id, v_business_id, v_document_id, v_current_status
  FROM public.document_ocr_runs
  WHERE id = p_run_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','OCR_RUN_NOT_FOUND','run_id',p_run_id);
  END IF;
  IF v_current_status <> 'STARTED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','OCR_RUN_NOT_STARTED',
      'run_id',p_run_id,'current_status',v_current_status
    );
  END IF;

  UPDATE public.document_ocr_runs
     SET status             = 'FAILED',
         error_category     = p_error_category,
         error_summary      = p_error_summary,
         is_transient_error = p_is_transient,
         failed_at          = clock_timestamp()
   WHERE id = p_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_OCR_FAILED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=v_document_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='document_ocr',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'error_category',p_error_category,
      'error_summary',p_error_summary,'is_transient_error',p_is_transient
    ),
    p_reason:=p_error_summary, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','FAILED','run_id',p_run_id,
    'document_id',v_document_id,'is_transient_error',p_is_transient
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reject_document_format(p_document_id uuid, p_detected_format text, p_reason text, p_workflow_run_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_business_id     uuid;
  v_run_id          uuid;
  v_review_issue_id uuid;
BEGIN
  IF p_detected_format IS NULL OR length(trim(p_detected_format)) = 0 THEN
    RAISE EXCEPTION 'DETECTED_FORMAT_REQUIRED' USING errcode='check_violation';
  END IF;
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'REJECTION_REASON_REQUIRED' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id
    INTO v_organization_id, v_business_id
  FROM public.documents
  WHERE id = p_document_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','DOCUMENT_NOT_FOUND','document_id',p_document_id);
  END IF;

  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id, document_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action
  ) VALUES (
    v_organization_id, v_business_id, p_workflow_run_id, p_document_id,
    'DOCUMENT_FORMAT_UNSUPPORTED',
    'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
    'MEDIUM'::public.review_issue_severity_enum,
    'Document format not supported',
    'We could not run OCR on this file because its format (' || p_detected_format ||
    ') is not supported. Please re-upload as PDF, JPG, PNG, or HEIC.',
    'Re-upload the document as PDF or image'
  )
  RETURNING id INTO v_review_issue_id;

  INSERT INTO public.document_ocr_runs (
    organization_id, business_id, document_id, processor_id,
    input_format, status, detected_format, error_summary, failed_at, review_issue_id
  ) VALUES (
    v_organization_id, v_business_id, p_document_id, 'format_gate',
    'OTHER'::public.document_input_format_enum, 'FORMAT_REJECTED',
    p_detected_format, p_reason, clock_timestamp(), v_review_issue_id
  )
  RETURNING id INTO v_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_FORMAT_REJECTED_UNSUPPORTED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=p_document_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='document_ocr',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',v_run_id,'detected_format',p_detected_format,
      'review_issue_id',v_review_issue_id,'reason',p_reason
    ),
    p_reason:=p_reason, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','REJECTED','run_id',v_run_id,
    'document_id',p_document_id,'review_issue_id',v_review_issue_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_document_extraction_layer1(p_document_id uuid, p_template_name text, p_template_version text, p_extracted_fields jsonb, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_business_id     uuid;
  v_result_id       uuid;
  v_confidence      jsonb := '{}'::jsonb;
  v_key             text;
BEGIN
  IF p_extracted_fields IS NULL OR jsonb_typeof(p_extracted_fields) <> 'object' THEN
    RAISE EXCEPTION 'EXTRACTED_FIELDS_OBJECT_REQUIRED' USING errcode='check_violation';
  END IF;
  SELECT organization_id, business_id INTO v_organization_id, v_business_id
    FROM public.documents WHERE id = p_document_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','DOCUMENT_NOT_FOUND','document_id',p_document_id);
  END IF;

  FOR v_key IN SELECT jsonb_object_keys(p_extracted_fields) LOOP
    v_confidence := v_confidence || jsonb_build_object(v_key, 1.0);
  END LOOP;

  INSERT INTO public.document_extraction_results (
    organization_id, business_id, document_id, extraction_layer,
    extracted_fields, confidence_per_field, started_at, completed_at,
    prompt_version, succeeded
  ) VALUES (
    v_organization_id, v_business_id, p_document_id, 'DETERMINISTIC',
    p_extracted_fields, v_confidence, clock_timestamp(), clock_timestamp(),
    NULL, true
  )
  RETURNING id INTO v_result_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_EXTRACTION_LAYER1_MATCHED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=p_document_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='document_extraction',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'result_id',v_result_id,
      'template_name',p_template_name,
      'template_version',p_template_version,
      'field_count',(SELECT count(*) FROM jsonb_object_keys(p_extracted_fields))
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','RECORDED','result_id',v_result_id,
    'extraction_layer','DETERMINISTIC','document_id',p_document_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_document_extraction_tier2_attempt(p_document_id uuid, p_extracted_fields jsonb, p_confidence_per_field jsonb, p_avg_confidence numeric, p_prompt_version text, p_ai_gateway_invocation_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_business_id     uuid;
  v_threshold       numeric;
  v_result_id       uuid;
  v_below_threshold boolean;
BEGIN
  IF p_prompt_version IS NULL OR length(trim(p_prompt_version)) = 0 THEN
    RAISE EXCEPTION 'PROMPT_VERSION_REQUIRED' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id INTO v_organization_id, v_business_id
    FROM public.documents WHERE id = p_document_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','DOCUMENT_NOT_FOUND','document_id',p_document_id);
  END IF;

  SELECT extraction_layer2_confidence_threshold INTO v_threshold
    FROM public.business_ai_config WHERE business_id = v_business_id;
  IF v_threshold IS NULL THEN v_threshold := 0.75; END IF;

  INSERT INTO public.document_extraction_results (
    organization_id, business_id, document_id, extraction_layer,
    extracted_fields, confidence_per_field, started_at, completed_at,
    prompt_version, succeeded
  ) VALUES (
    v_organization_id, v_business_id, p_document_id, 'TIER2_AI',
    COALESCE(p_extracted_fields,'{}'::jsonb),
    COALESCE(p_confidence_per_field,'{}'::jsonb),
    clock_timestamp(), clock_timestamp(),
    p_prompt_version, true
  )
  RETURNING id INTO v_result_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_EXTRACTION_TIER2_INVOKED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=p_document_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='document_extraction',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'result_id',v_result_id,'prompt_version',p_prompt_version,
      'avg_confidence',p_avg_confidence,'threshold',v_threshold,
      'gateway_invocation_id',p_ai_gateway_invocation_id
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  v_below_threshold := (p_avg_confidence IS NOT NULL AND p_avg_confidence < v_threshold);
  IF v_below_threshold THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='DOCUMENT_EXTRACTION_TIER2_LOW_CONFIDENCE',
      p_subject_type:='DOCUMENT'::audit.subject_type_enum,
      p_subject_id:=p_document_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='document_extraction',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'result_id',v_result_id,'avg_confidence',p_avg_confidence,
        'threshold',v_threshold,
        'note','escalation to Tier 3 required (explicit, not silent)'
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
  END IF;

  RETURN jsonb_build_object(
    'decision','RECORDED','result_id',v_result_id,
    'extraction_layer','TIER2_AI','below_threshold',v_below_threshold,
    'threshold',v_threshold,'document_id',p_document_id
  );
END;
$function$
;

