    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'review_issue_id',v_review_issue_id,'field_name',p_field_name,'reason',p_reason
    ),
    p_reason:=p_reason, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','RECORDED','document_id',p_document_id,
    'field_name',p_field_name,'review_issue_id',v_review_issue_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.begin_email_finder_run(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_query_count integer DEFAULT 0, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
