CREATE OR REPLACE FUNCTION public.record_email_finder_result_found(p_run_id uuid, p_template_name text, p_gmail_message_id text, p_sender_address text, p_discovery_confidence numeric, p_attachment_filename text, p_document_type document_type_enum DEFAULT 'INVOICE'::document_type_enum, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_existing_doc uuid; v_source_extid text; v_new_doc_id uuid;
BEGIN
  IF p_gmail_message_id IS NULL OR length(trim(p_gmail_message_id)) = 0 THEN
    RAISE EXCEPTION 'GMAIL_MESSAGE_ID_REQUIRED' USING errcode='check_violation';
  END IF;
  IF p_discovery_confidence IS NULL OR p_discovery_confidence < 0 OR p_discovery_confidence > 1 THEN
    RAISE EXCEPTION 'DISCOVERY_CONFIDENCE_OUT_OF_RANGE' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id, transaction_id
    INTO v_organization_id, v_business_id, v_transaction_id
  FROM public.email_finder_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  v_source_extid := 'gmail:' || p_gmail_message_id;

  SELECT document_id INTO v_existing_doc
  FROM public.document_source_links
  WHERE business_id = v_business_id AND source_kind = 'EMAIL'
    AND source_external_id = v_source_extid
  LIMIT 1;

  IF FOUND THEN
    INSERT INTO public.email_finder_results (
      organization_id, business_id, run_id, template_name,
      gmail_message_id, sender_address, outcome, document_id
    ) VALUES (
      v_organization_id, v_business_id, p_run_id, p_template_name,
      p_gmail_message_id, p_sender_address, 'DUPLICATE_SOURCE', v_existing_doc
    );

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='EMAIL_FINDER_RESULT_DUPLICATE_SOURCE',
      p_subject_type:='DOCUMENT'::audit.subject_type_enum,
      p_subject_id:=v_existing_doc,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='email_finder',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'run_id',p_run_id,'gmail_message_id',p_gmail_message_id,
        'existing_document_id',v_existing_doc
      ),
      p_reason:=NULL, p_request_context:=p_context
    );

    RETURN jsonb_build_object(
      'decision','DUPLICATE_SOURCE','run_id',p_run_id,
      'document_id',v_existing_doc,'gmail_message_id',p_gmail_message_id
    );
  END IF;

  INSERT INTO public.documents (
    organization_id, business_id, source, document_type,
    original_filename, discovery_reason, discovery_confidence
  ) VALUES (
    v_organization_id, v_business_id, 'EMAIL', p_document_type,
    p_attachment_filename, 'email_finder:' || p_template_name, p_discovery_confidence
  ) RETURNING id INTO v_new_doc_id;

  INSERT INTO public.document_source_links (
    organization_id, business_id, document_id, source_kind,
    source_external_id, discovery_reason
  ) VALUES (
    v_organization_id, v_business_id, v_new_doc_id, 'EMAIL',
    v_source_extid, 'email_finder:' || p_template_name
  );

  INSERT INTO public.email_finder_results (
    organization_id, business_id, run_id, template_name,
    gmail_message_id, sender_address, outcome, document_id, discovery_confidence
  ) VALUES (
    v_organization_id, v_business_id, p_run_id, p_template_name,
    p_gmail_message_id, p_sender_address, 'FOUND', v_new_doc_id, p_discovery_confidence
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='EMAIL_FINDER_RESULT_FOUND',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=v_new_doc_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='email_finder',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'template_name',p_template_name,
      'gmail_message_id',p_gmail_message_id,'sender_address',p_sender_address,
      'discovery_confidence',p_discovery_confidence,'document_id',v_new_doc_id
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','FOUND','run_id',p_run_id,'document_id',v_new_doc_id,
    'gmail_message_id',p_gmail_message_id,'discovery_confidence',p_discovery_confidence
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fail_email_finder_run(p_run_id uuid, p_error_summary text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_status public.email_finder_run_status_enum;
BEGIN
  IF p_error_summary IS NULL OR length(trim(p_error_summary)) = 0 THEN
    RAISE EXCEPTION 'ERROR_SUMMARY_REQUIRED' USING errcode='check_violation';
  END IF;
  SELECT status INTO v_status FROM public.email_finder_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;
  IF v_status <> 'STARTED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','RUN_NOT_STARTED',
      'run_id',p_run_id,'current_status',v_status
    );
  END IF;

  UPDATE public.email_finder_runs
    SET status='FAILED', error_summary=p_error_summary, failed_at=clock_timestamp()
  WHERE id = p_run_id;

  RETURN jsonb_build_object(
    'decision','FAILED','run_id',p_run_id,'error_summary',p_error_summary
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_email_finder_result_rejected(p_run_id uuid, p_template_name text, p_gmail_message_id text, p_sender_address text, p_outcome email_finder_result_outcome_enum, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid; v_action text;
BEGIN
  IF p_outcome NOT IN ('REJECTED_SPAM','REJECTED_NOT_ALLOWLISTED') THEN
    RAISE EXCEPTION 'OUTCOME_MUST_BE_REJECTED_VARIANT' USING errcode='check_violation';
  END IF;
  IF p_gmail_message_id IS NULL OR length(trim(p_gmail_message_id)) = 0 THEN
    RAISE EXCEPTION 'GMAIL_MESSAGE_ID_REQUIRED' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id, transaction_id
    INTO v_organization_id, v_business_id, v_transaction_id
  FROM public.email_finder_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  INSERT INTO public.email_finder_results (
    organization_id, business_id, run_id, template_name,
    gmail_message_id, sender_address, outcome
  ) VALUES (
    v_organization_id, v_business_id, p_run_id, p_template_name,
    p_gmail_message_id, p_sender_address, p_outcome
  );

  IF p_outcome = 'REJECTED_SPAM' THEN v_action := 'EMAIL_FINDER_RESULT_REJECTED_SPAM';
  ELSE v_action := 'EMAIL_FINDER_RESULT_REJECTED_NOT_ALLOWLISTED'; END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:=v_action,
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=v_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='email_finder',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'template_name',p_template_name,
      'gmail_message_id',p_gmail_message_id,'sender_address',p_sender_address,
      'outcome',p_outcome
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','REJECTED','outcome',p_outcome,
    'run_id',p_run_id,'gmail_message_id',p_gmail_message_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_email_finder_run(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_status public.email_finder_run_status_enum;
  v_found int := 0; v_spam int := 0; v_notal int := 0; v_dup int := 0;
BEGIN
  SELECT status INTO v_status FROM public.email_finder_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;
  IF v_status <> 'STARTED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','RUN_NOT_STARTED',
      'run_id',p_run_id,'current_status',v_status
    );
  END IF;

  SELECT
    count(*) FILTER (WHERE outcome='FOUND'),
    count(*) FILTER (WHERE outcome='REJECTED_SPAM'),
    count(*) FILTER (WHERE outcome='REJECTED_NOT_ALLOWLISTED'),
    count(*) FILTER (WHERE outcome='DUPLICATE_SOURCE')
  INTO v_found, v_spam, v_notal, v_dup
  FROM public.email_finder_results WHERE run_id = p_run_id;

  UPDATE public.email_finder_runs
    SET status='COMPLETED', found_count=v_found, rejected_spam_count=v_spam,
        rejected_not_allowlisted_count=v_notal, duplicate_count=v_dup,
        completed_at=clock_timestamp()
  WHERE id = p_run_id;

  RETURN jsonb_build_object(
    'decision','COMPLETED','run_id',p_run_id,
    'found_count',v_found,'rejected_spam_count',v_spam,
    'rejected_not_allowlisted_count',v_notal,'duplicate_count',v_dup
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_drive_finder_non_convention_detected(p_run_id uuid, p_workflow_run_id uuid, p_detected_subfolder_names text[], p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_review_issue_id uuid;
BEGIN
  SELECT organization_id, business_id, transaction_id
    INTO v_organization_id, v_business_id, v_transaction_id
  FROM public.drive_finder_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id, transaction_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action,
    card_payload_json
  ) VALUES (
    v_organization_id, v_business_id, p_workflow_run_id, v_transaction_id,
    'drive.folder_naming_non_convention',
    'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
    'MEDIUM'::public.review_issue_severity_enum,
    'Drive subfolders do not follow the 2-week date-range convention',
    'We expected your Drive subfolders to be named like 2026-04-01_to_2026-04-14 so we can date-scope the search. Falling back to a flat search across the root folder for now.',
    'Rename subfolders to YYYY-MM-DD_to_YYYY-MM-DD ranges, or change the naming convention in Drive integration settings',
    jsonb_build_object(
      'run_id', p_run_id,
      'detected_subfolder_names', to_jsonb(p_detected_subfolder_names)
    )
  ) RETURNING id INTO v_review_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DRIVE_FINDER_NON_CONVENTION_DETECTED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum,
    p_subject_id:=v_business_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='drive_finder',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'run_id',p_run_id,'review_issue_id',v_review_issue_id,
      'detected_subfolder_names',to_jsonb(p_detected_subfolder_names)
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','REVIEW_ISSUE_RAISED','run_id',p_run_id,
    'review_issue_id',v_review_issue_id
  );
END;
$function$
;

