CREATE OR REPLACE FUNCTION public.create_transaction_stub(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_stub_reason stub_reason_enum, p_reason_text text, p_workflow_run_id uuid, p_actor_user_id uuid, p_step_up_token_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_requires_step_up boolean;
  v_consumed boolean; v_token_reason text;
  v_stub_envelope jsonb; v_doc_id uuid;
  v_action_id uuid := public.gen_uuid_v7();
BEGIN
  IF p_reason_text IS NULL OR length(trim(p_reason_text)) = 0 THEN
    RAISE EXCEPTION 'REASON_TEXT_REQUIRED' USING errcode='check_violation';
  END IF;

  v_requires_step_up := p_stub_reason IN ('NO_INVOICE_AVAILABLE','NON_DEDUCTIBLE');

  IF v_requires_step_up THEN
    IF p_step_up_token_id IS NULL THEN
      RETURN jsonb_build_object(
        'decision','REJECTED','reason','STEP_UP_REQUIRED','stub_reason',p_stub_reason
      );
    END IF;
    SELECT consumed, reason INTO v_consumed, v_token_reason
    FROM public.consume_step_up_token(
      p_step_up_token_id, p_business_id,
      'b09p07.create_transaction_stub', v_action_id
    );
    IF NOT COALESCE(v_consumed, false) THEN
      RETURN jsonb_build_object(
        'decision','REJECTED','reason','STEP_UP_TOKEN_NOT_CONSUMED',
        'token_reason',v_token_reason,'stub_reason',p_stub_reason
      );
    END IF;
  END IF;

  v_stub_envelope := public.create_document_stub(
    p_organization_id => p_organization_id,
    p_business_id     => p_business_id,
    p_reason          => p_reason_text,
    p_context         => jsonb_build_object(
                           'transaction_id', p_transaction_id,
                           'stub_reason',    p_stub_reason,
                           'workflow_run_id',p_workflow_run_id
                         ) || COALESCE(p_context,'{}'::jsonb)
  );

  v_doc_id := (v_stub_envelope->>'document_id')::uuid;

  UPDATE public.documents SET stub_reason = p_stub_reason WHERE id = v_doc_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_MANUAL_LINKED_TO_TRANSACTION',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=v_doc_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='manual_upload',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'document_id',v_doc_id,'transaction_id',p_transaction_id,
      'stub_reason',p_stub_reason,'origin','transaction_stub',
      'workflow_run_id',p_workflow_run_id,'step_up_required',v_requires_step_up
    ),
    p_reason:=p_reason_text, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','STUB_CREATED','document_id',v_doc_id,
    'transaction_id',p_transaction_id,'stub_reason',p_stub_reason,
    'step_up_required',v_requires_step_up,'stub_envelope',v_stub_envelope
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ingest_document_with_hash_check(p_document_id uuid, p_document_hash text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id   uuid;
  v_business_id       uuid;
  v_candidate_status  public.document_extraction_status_enum;
  v_candidate_source  public.document_source_enum;
  v_candidate_dc      numeric;
  v_canonical_id      uuid;
  v_canonical_dc      numeric;
  v_canonical_source  public.document_source_enum;
  v_n_before          int;
  v_n_after           int;
  v_new_dc            numeric;
  v_transition_env    jsonb;
  v_emit_boost        boolean := false;
  v_emit_third        boolean := false;
BEGIN
  IF p_document_hash IS NULL OR p_document_hash !~ '^[0-9a-f]{64}$' THEN
    RAISE EXCEPTION 'DOCUMENT_HASH_INVALID_FORMAT' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id, extraction_status, source, discovery_confidence
    INTO v_organization_id, v_business_id, v_candidate_status, v_candidate_source, v_candidate_dc
  FROM public.documents WHERE id = p_document_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','DOCUMENT_NOT_FOUND','document_id',p_document_id);
  END IF;
  IF v_candidate_status <> 'DISCOVERED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','DOCUMENT_NOT_DISCOVERED',
      'document_id',p_document_id,'current_status',v_candidate_status
    );
  END IF;

  SELECT id, discovery_confidence, source
    INTO v_canonical_id, v_canonical_dc, v_canonical_source
  FROM public.documents
  WHERE business_id = v_business_id
    AND document_hash = p_document_hash
    AND id <> p_document_id
  ORDER BY id ASC LIMIT 1;

  IF NOT FOUND THEN
    UPDATE public.documents
      SET document_hash = p_document_hash, updated_at = clock_timestamp()
    WHERE id = p_document_id;

    v_transition_env := public.transition_document(
      p_document_id  => p_document_id,
      p_target_state => 'INGESTED'::public.document_extraction_status_enum,
      p_reason       => 'cross_source_dedup_no_match',
      p_context      => jsonb_build_object('document_hash', p_document_hash)
                        || COALESCE(p_context,'{}'::jsonb)
    );

    RETURN jsonb_build_object(
      'decision','INGESTED','document_id',p_document_id,
      'document_hash',p_document_hash,'transition',v_transition_env,'is_new',true
    );
  END IF;

  PERFORM 1 FROM public.documents WHERE id = v_canonical_id FOR UPDATE;

  SELECT count(*) INTO v_n_before
    FROM public.document_source_links WHERE document_id = v_canonical_id;

  UPDATE public.document_source_links
    SET document_id = v_canonical_id
  WHERE document_id = p_document_id
    AND NOT EXISTS (
      SELECT 1 FROM public.document_source_links existing
      WHERE existing.business_id = v_business_id
        AND existing.source_kind = document_source_links.source_kind
        AND existing.source_external_id = document_source_links.source_external_id
        AND existing.document_id = v_canonical_id
    );
  DELETE FROM public.document_source_links WHERE document_id = p_document_id;

  SELECT count(*) INTO v_n_after
    FROM public.document_source_links WHERE document_id = v_canonical_id;

  IF v_n_before = 1 THEN
    v_new_dc := LEAST(0.95::numeric,
                      GREATEST(COALESCE(v_canonical_dc, 0), COALESCE(v_candidate_dc, 0))
                      + 0.10::numeric);
    UPDATE public.documents
      SET discovery_confidence = v_new_dc, updated_at = clock_timestamp()
    WHERE id = v_canonical_id;
    v_emit_boost := true;
  ELSIF v_n_before >= 2 THEN
    v_emit_third := true;
    v_new_dc := v_canonical_dc;
  ELSE
    v_new_dc := v_canonical_dc;
  END IF;

  DELETE FROM public.documents WHERE id = p_document_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='DOCUMENT_CROSS_SOURCE_DUPLICATE_DETECTED',
    p_subject_type:='DOCUMENT'::audit.subject_type_enum,
    p_subject_id:=v_canonical_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='cross_source_dedup',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object('sources_count', v_n_before),
    p_after_state:=jsonb_build_object(
      'canonical_document_id', v_canonical_id,
      'absorbed_document_id',  p_document_id,
      'document_hash',         p_document_hash,
      'canonical_source',      v_canonical_source,
      'candidate_source',      v_candidate_source,
      'sources_count_after',   v_n_after
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  IF v_emit_boost THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='DOCUMENT_CONFIDENCE_BOOSTED_VIA_CROSS_SOURCE',
      p_subject_type:='DOCUMENT'::audit.subject_type_enum,
      p_subject_id:=v_canonical_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='cross_source_dedup',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=jsonb_build_object('discovery_confidence', v_canonical_dc),
      p_after_state:=jsonb_build_object(
        'discovery_confidence', v_new_dc,
        'sources_count', v_n_after, 'boost_applied', 0.10
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
  END IF;

  IF v_emit_third THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='DOCUMENT_THIRD_SOURCE_OBSERVED',
      p_subject_type:='DOCUMENT'::audit.subject_type_enum,
      p_subject_id:=v_canonical_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='cross_source_dedup',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=jsonb_build_object('sources_count', v_n_before),
      p_after_state:=jsonb_build_object(
        'sources_count', v_n_after, 'discovery_confidence', v_new_dc,
        'note', 'cap reached at 2 sources; no further boost'
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
  END IF;

  RETURN jsonb_build_object(
    'decision','ABSORBED',
    'canonical_document_id', v_canonical_id,
    'absorbed_document_id',  p_document_id,
    'sources_count',         v_n_after,
    'discovery_confidence',  v_new_dc,
    'boost_applied',         v_emit_boost,
    'third_source_observed', v_emit_third
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_evidence_discovery_phase_started(p_workflow_run_id uuid, p_phase_name text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
