CREATE OR REPLACE FUNCTION public.evaluate_evidence_discovery_email_entry_gate(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_business_id uuid; v_period_start timestamptz; v_period_end timestamptz; v_out_expense_n int;
BEGIN
  SELECT business_id, period_start, period_end INTO v_business_id, v_period_start, v_period_end
  FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('satisfied', false, 'reason', 'WORKFLOW_RUN_NOT_FOUND'); END IF;
  SELECT count(*) INTO v_out_expense_n FROM public.transactions
  WHERE business_id = v_business_id AND transaction_type = 'OUT_EXPENSE'
    AND transaction_date >= v_period_start::date AND transaction_date <= v_period_end::date;
  IF v_out_expense_n = 0 THEN
    RETURN jsonb_build_object('satisfied', false, 'reason', 'NO_OUT_EXPENSE_TRANSACTIONS', 'out_expense_count', 0);
  END IF;
  RETURN jsonb_build_object('satisfied', true, 'reason', 'READY', 'out_expense_count', v_out_expense_n);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_evidence_discovery_email_exit_gate(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_business_id uuid; v_period_start timestamptz; v_period_end timestamptz;
        v_out_expense_n int; v_searched_n int;
BEGIN
  SELECT business_id, period_start, period_end INTO v_business_id, v_period_start, v_period_end
  FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('satisfied', false, 'reason', 'WORKFLOW_RUN_NOT_FOUND'); END IF;

  SELECT count(*) INTO v_out_expense_n FROM public.transactions
  WHERE business_id = v_business_id AND transaction_type = 'OUT_EXPENSE'
    AND transaction_date >= v_period_start::date AND transaction_date <= v_period_end::date;

  SELECT count(DISTINCT transaction_id) INTO v_searched_n
  FROM public.email_finder_runs efr
  WHERE efr.business_id = v_business_id AND efr.status = 'COMPLETED'
    AND efr.transaction_id IN (
      SELECT id FROM public.transactions
      WHERE business_id = v_business_id AND transaction_type = 'OUT_EXPENSE'
        AND transaction_date >= v_period_start::date AND transaction_date <= v_period_end::date
    );

  RETURN jsonb_build_object(
    'satisfied', (v_searched_n >= v_out_expense_n AND v_out_expense_n > 0),
    'reason', CASE WHEN v_searched_n >= v_out_expense_n THEN 'ALL_SEARCHED' ELSE 'INCOMPLETE_COVERAGE' END,
    'out_expense_count', v_out_expense_n, 'searched_count', v_searched_n
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_evidence_discovery_drive_entry_gate(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_email_exit jsonb;
BEGIN
  v_email_exit := public.evaluate_evidence_discovery_email_exit_gate(p_workflow_run_id);
  IF NOT COALESCE((v_email_exit->>'satisfied')::boolean, false) THEN
    RETURN jsonb_build_object('satisfied', false, 'reason', 'EMAIL_PHASE_INCOMPLETE', 'email_exit_envelope', v_email_exit);
  END IF;
  RETURN jsonb_build_object('satisfied', true, 'reason', 'READY', 'email_exit_envelope', v_email_exit);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_evidence_discovery_drive_exit_gate(p_workflow_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_business_id uuid; v_period_start timestamptz; v_period_end timestamptz;
        v_out_expense_n int; v_searched_n int;
BEGIN
  SELECT business_id, period_start, period_end INTO v_business_id, v_period_start, v_period_end
  FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('satisfied', false, 'reason', 'WORKFLOW_RUN_NOT_FOUND'); END IF;

  SELECT count(*) INTO v_out_expense_n FROM public.transactions
  WHERE business_id = v_business_id AND transaction_type = 'OUT_EXPENSE'
    AND transaction_date >= v_period_start::date AND transaction_date <= v_period_end::date;

  SELECT count(DISTINCT transaction_id) INTO v_searched_n
  FROM public.drive_finder_runs dfr
  WHERE dfr.business_id = v_business_id AND dfr.status = 'COMPLETED'
    AND dfr.transaction_id IN (
      SELECT id FROM public.transactions
      WHERE business_id = v_business_id AND transaction_type = 'OUT_EXPENSE'
        AND transaction_date >= v_period_start::date AND transaction_date <= v_period_end::date
    );

  RETURN jsonb_build_object(
    'satisfied', (v_searched_n >= v_out_expense_n AND v_out_expense_n > 0),
    'reason', CASE WHEN v_searched_n >= v_out_expense_n THEN 'ALL_SEARCHED' ELSE 'INCOMPLETE_COVERAGE' END,
    'out_expense_count', v_out_expense_n, 'searched_count', v_searched_n
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_vat_number_format(p_country character, p_canonical_vat text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_canonical_vat IS NULL THEN false
    WHEN p_country IS NULL THEN length(p_canonical_vat) >= 4  -- permissive when country unknown
    -- Stage-1 catalog (sub-doc finalizes):
    WHEN p_country = 'CY' THEN p_canonical_vat ~ '^CY[0-9]{8}[A-Z]$'
    WHEN p_country = 'GR' THEN p_canonical_vat ~ '^(EL|GR)[0-9]{9}$'
    WHEN p_country = 'DE' THEN p_canonical_vat ~ '^DE[0-9]{9}$'
    WHEN p_country = 'IE' THEN p_canonical_vat ~ '^IE[0-9]{7}[A-Z]{1,2}$'
    WHEN p_country IN ('GB','XI') THEN p_canonical_vat ~ '^(GB|XI)[0-9]{9}([0-9]{3})?$'
    -- Default EU permissive: country prefix + at least 4 alphanumerics
    ELSE p_canonical_vat ~ ('^' || p_country || '[A-Z0-9]{4,}$')
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_intake_fixture(p_fixture_name text, p_fixture_hash text, p_description text, p_manifest jsonb, p_registered_by_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_existing_hash text; v_run_count int;
BEGIN
  IF p_fixture_name IS NULL OR p_fixture_name !~ '^[a-z][a-z0-9_]+$' THEN
    RAISE EXCEPTION 'FIXTURE_NAME_INVALID_FORMAT' USING errcode='check_violation';
  END IF;
  IF p_fixture_hash IS NULL OR p_fixture_hash !~ '^[0-9a-f]{64}$' THEN
    RAISE EXCEPTION 'FIXTURE_HASH_INVALID_FORMAT' USING errcode='check_violation';
  END IF;
  SELECT fixture_hash INTO v_existing_hash
  FROM public.intake_fixtures WHERE name = p_fixture_name FOR UPDATE;
  IF FOUND THEN
    IF v_existing_hash = p_fixture_hash THEN
      UPDATE public.intake_fixtures SET description = p_description, manifest = p_manifest
      WHERE name = p_fixture_name;
      RETURN jsonb_build_object('decision','REGISTERED','fixture_name',p_fixture_name,
        'fixture_hash',p_fixture_hash,'is_new',false);
    END IF;
    SELECT count(*) INTO v_run_count FROM public.intake_fixture_runs WHERE fixture_name = p_fixture_name;
    IF v_run_count > 0 THEN
      RETURN jsonb_build_object('decision','REJECTED','reason','FIXTURE_LOCKED_BY_RUNS',
        'fixture_name',p_fixture_name,'existing_hash',v_existing_hash,
        'attempted_hash',p_fixture_hash,'run_count',v_run_count);
    END IF;
    UPDATE public.intake_fixtures
      SET fixture_hash = p_fixture_hash, description = p_description, manifest = p_manifest
    WHERE name = p_fixture_name;
    RETURN jsonb_build_object('decision','REGISTERED','fixture_name',p_fixture_name,
      'fixture_hash',p_fixture_hash,'is_new',false,'note','hash_changed_before_any_runs');
  END IF;
  INSERT INTO public.intake_fixtures (name, fixture_hash, description, manifest, registered_by_user_id)
  VALUES (p_fixture_name, p_fixture_hash, p_description, p_manifest, p_registered_by_user_id);
  RETURN jsonb_build_object('decision','REGISTERED','fixture_name',p_fixture_name,
    'fixture_hash',p_fixture_hash,'is_new',true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_intake_fixture_pass(p_fixture_name text, p_fixture_hash text, p_ran_by_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_registry_hash text; v_run_id uuid;
BEGIN
  SELECT fixture_hash INTO v_registry_hash FROM public.intake_fixtures WHERE name = p_fixture_name;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','FIXTURE_NOT_FOUND','fixture_name',p_fixture_name);
  END IF;
  IF v_registry_hash <> p_fixture_hash THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','FIXTURE_HASH_MISMATCH',
      'fixture_name',p_fixture_name,'registry_hash',v_registry_hash,'received_hash',p_fixture_hash);
  END IF;
  INSERT INTO public.intake_fixture_runs (fixture_name, fixture_hash, status, ran_by_user_id)
  VALUES (p_fixture_name, p_fixture_hash, 'PASSED', p_ran_by_user_id)
  RETURNING id INTO v_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='INTAKE_FIXTURE_RAN',
    p_subject_type:='INTAKE_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=NULL,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='intake_fixture',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('fixture_name',p_fixture_name,
      'fixture_hash',p_fixture_hash,'run_id',v_run_id,'status','PASSED'),
    p_reason:=NULL, p_request_context:=p_context
  );
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='INTAKE_FIXTURE_PASSED',
    p_subject_type:='INTAKE_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=NULL,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='intake_fixture',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('fixture_name',p_fixture_name,
      'fixture_hash',p_fixture_hash,'run_id',v_run_id),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object('decision','RECORDED','fixture_name',p_fixture_name,
    'run_id',v_run_id,'status','PASSED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_intake_fixture_failure(p_fixture_name text, p_fixture_hash text, p_diff_summary jsonb, p_ran_by_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_registry_hash text; v_run_id uuid;
BEGIN
  IF p_diff_summary IS NULL OR jsonb_typeof(p_diff_summary) <> 'object' THEN
    RAISE EXCEPTION 'DIFF_SUMMARY_MUST_BE_OBJECT' USING errcode='check_violation';
  END IF;
  SELECT fixture_hash INTO v_registry_hash FROM public.intake_fixtures WHERE name = p_fixture_name;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','FIXTURE_NOT_FOUND','fixture_name',p_fixture_name);
  END IF;
  IF v_registry_hash <> p_fixture_hash THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','FIXTURE_HASH_MISMATCH',
      'fixture_name',p_fixture_name,'registry_hash',v_registry_hash,'received_hash',p_fixture_hash);
  END IF;
  INSERT INTO public.intake_fixture_runs (fixture_name, fixture_hash, status, diff_summary, ran_by_user_id)
  VALUES (p_fixture_name, p_fixture_hash, 'FAILED', p_diff_summary, p_ran_by_user_id)
  RETURNING id INTO v_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='INTAKE_FIXTURE_RAN',
    p_subject_type:='INTAKE_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=NULL,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='intake_fixture',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('fixture_name',p_fixture_name,
      'fixture_hash',p_fixture_hash,'run_id',v_run_id,'status','FAILED'),
    p_reason:=NULL, p_request_context:=p_context
  );
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='INTAKE_FIXTURE_FAILED',
    p_subject_type:='INTAKE_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=NULL,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='intake_fixture',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('fixture_name',p_fixture_name,
      'fixture_hash',p_fixture_hash,'run_id',v_run_id,'diff_summary',p_diff_summary),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object('decision','RECORDED','fixture_name',p_fixture_name,
    'run_id',v_run_id,'status','FAILED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.retire_intake_fixture(p_fixture_name text, p_retired_reason text, p_retired_by_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_already_retired_at timestamptz;
BEGIN
  IF p_retired_reason IS NULL OR length(trim(p_retired_reason)) = 0 THEN
    RAISE EXCEPTION 'RETIRED_REASON_REQUIRED' USING errcode='check_violation';
  END IF;
  SELECT retired_at INTO v_already_retired_at
  FROM public.intake_fixtures WHERE name = p_fixture_name FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','FIXTURE_NOT_FOUND','fixture_name',p_fixture_name);
  END IF;
  IF v_already_retired_at IS NOT NULL THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','ALREADY_RETIRED',
      'fixture_name',p_fixture_name,'retired_at',v_already_retired_at);
  END IF;
  UPDATE public.intake_fixtures
    SET retired_at = clock_timestamp(), retired_by_user_id = p_retired_by_user_id,
        retired_reason = p_retired_reason
  WHERE name = p_fixture_name;
  RETURN jsonb_build_object('decision','RETIRED','fixture_name',p_fixture_name,'reason',p_retired_reason);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_intake_fixture_drift_summary()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_total int; v_active int; v_retired int;
        v_30d_pass int; v_30d_fail int; v_never_passed int;
BEGIN
  SELECT count(*) INTO v_total FROM public.intake_fixtures;
  SELECT count(*) INTO v_active FROM public.intake_fixtures WHERE retired_at IS NULL;
  SELECT count(*) INTO v_retired FROM public.intake_fixtures WHERE retired_at IS NOT NULL;
  SELECT count(*) INTO v_30d_pass FROM public.intake_fixture_runs
    WHERE status='PASSED' AND ran_at >= clock_timestamp() - interval '30 days';
  SELECT count(*) INTO v_30d_fail FROM public.intake_fixture_runs
    WHERE status='FAILED' AND ran_at >= clock_timestamp() - interval '30 days';
  SELECT count(*) INTO v_never_passed
  FROM public.intake_fixtures f
  WHERE f.retired_at IS NULL
    AND NOT EXISTS (SELECT 1 FROM public.intake_fixture_runs r
                    WHERE r.fixture_name = f.name AND r.status = 'PASSED');
  RETURN jsonb_build_object(
    'total_fixtures', v_total, 'active_count', v_active, 'retired_count', v_retired,
    'last_30d_pass', v_30d_pass, 'last_30d_fail', v_30d_fail,
    'fixtures_never_passed', v_never_passed
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.spg_maintain_member_count()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  IF (TG_OP = 'INSERT') THEN
    IF NEW.split_payment_group_id IS NOT NULL THEN
      UPDATE public.split_payment_groups SET member_count = member_count + 1
      WHERE id = NEW.split_payment_group_id;
    END IF;
    RETURN NEW;
  ELSIF (TG_OP = 'UPDATE') THEN
    IF NEW.split_payment_group_id IS DISTINCT FROM OLD.split_payment_group_id THEN
      IF OLD.split_payment_group_id IS NOT NULL THEN
        UPDATE public.split_payment_groups SET member_count = member_count - 1
        WHERE id = OLD.split_payment_group_id;
      END IF;
      IF NEW.split_payment_group_id IS NOT NULL THEN
        UPDATE public.split_payment_groups SET member_count = member_count + 1
        WHERE id = NEW.split_payment_group_id;
      END IF;
    END IF;
    RETURN NEW;
  ELSIF (TG_OP = 'DELETE') THEN
    IF OLD.split_payment_group_id IS NOT NULL THEN
      UPDATE public.split_payment_groups SET member_count = member_count - 1
      WHERE id = OLD.split_payment_group_id;
    END IF;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_vendor_memory_confirmation(p_organization_id uuid, p_business_id uuid, p_counterparty_signature text, p_source text, p_source_record_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_new_count int; v_inserted boolean;
BEGIN
  IF p_source NOT IN ('matching.auto_confirm','matching.user_confirm','classification.auto_confirm') THEN
    RAISE EXCEPTION 'VENDOR_MEMORY_SOURCE_INVALID' USING errcode='check_violation';
  END IF;
  IF p_counterparty_signature IS NULL OR length(trim(p_counterparty_signature)) = 0 THEN
    RAISE EXCEPTION 'COUNTERPARTY_SIGNATURE_REQUIRED' USING errcode='check_violation';
  END IF;
  BEGIN
    INSERT INTO public.vendor_memory_increment_log
      (organization_id, business_id, counterparty_signature, source, source_record_id)
    VALUES (p_organization_id, p_business_id, p_counterparty_signature, p_source, p_source_record_id);
    v_inserted := true;
  EXCEPTION WHEN unique_violation THEN v_inserted := false;
  END;
  IF NOT v_inserted THEN
    RETURN jsonb_build_object('decision','NOOP','reason','ALREADY_COUNTED',
      'counterparty_signature', p_counterparty_signature, 'source', p_source,
      'source_record_id', p_source_record_id);
  END IF;
  UPDATE public.recurring_vendor_memory
    SET confirmations_count = confirmations_count + 1,
        last_confirmation_at = clock_timestamp(), updated_at = clock_timestamp()
  WHERE business_id = p_business_id AND counterparty_signature = p_counterparty_signature
  RETURNING confirmations_count INTO v_new_count;
  IF v_new_count IS NULL THEN
    RETURN jsonb_build_object('decision','NOOP','reason','NO_VENDOR_MEMORY_ROW',
      'counterparty_signature', p_counterparty_signature, 'source', p_source);
  END IF;
  RETURN jsonb_build_object('decision','INCREMENTED',
    'counterparty_signature', p_counterparty_signature,
    'new_count', v_new_count, 'source', p_source);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_match_decision(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_document_id uuid, p_signal_breakdown jsonb, p_match_score numeric, p_match_level match_level_enum, p_workflow_run_id uuid, p_match_method match_method_enum DEFAULT 'DETERMINISTIC_RULE'::match_method_enum, p_match_reason_plain_language text DEFAULT NULL::text, p_matched_by_system text DEFAULT 'matching_engine'::text, p_counterparty_signature text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_score_env jsonb; v_match_record_id uuid;
  v_recurring numeric; v_amount_exact numeric;
  v_txn_type public.transaction_type_enum;
  v_severity public.review_issue_severity_enum;
  v_review_issue_id uuid;
  v_final_status public.match_record_status_enum;
  v_auto_confirmed boolean := false;
  v_vendor_env jsonb;
BEGIN
  v_score_env := public.apply_match_score(
    p_organization_id, p_business_id, p_transaction_id, p_document_id,
    p_signal_breakdown, p_match_score, p_match_level,
    p_match_method, p_match_reason_plain_language, p_matched_by_system, p_context
  );
  IF v_score_env->>'decision' = 'SUPPRESSED' THEN
    RETURN v_score_env;
  END IF;
  v_match_record_id := (v_score_env->>'match_record_id')::uuid;

  SELECT transaction_type INTO v_txn_type FROM public.transactions WHERE id = p_transaction_id;

  IF p_match_level = 'EXACT' THEN
    v_final_status := 'MATCHED_AUTO_HIGH_CONFIDENCE';
    v_auto_confirmed := true;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='MATCHING_AUTO_CONFIRMED',
      p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
      p_subject_id:=v_match_record_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='matching_engine',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'match_record_id', v_match_record_id,
        'match_level', p_match_level, 'transaction_id', p_transaction_id
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
    IF p_counterparty_signature IS NOT NULL THEN
      v_vendor_env := public.record_vendor_memory_confirmation(
        p_organization_id, p_business_id, p_counterparty_signature,
        'matching.auto_confirm', v_match_record_id, p_context
      );
    END IF;

  ELSIF p_match_level = 'STRONG_PROBABLE' THEN
    v_recurring    := COALESCE((p_signal_breakdown->>'recurring_vendor_signal')::numeric, 0);
    v_amount_exact := COALESCE((p_signal_breakdown->>'amount_exact_match')::numeric,    0);

    IF v_recurring >= 0.88 AND v_amount_exact = 1.0 THEN
      UPDATE public.match_records
        SET match_status = 'MATCHED_AUTO_HIGH_CONFIDENCE'::public.match_record_status_enum,
            requires_user_confirmation = false, updated_at = clock_timestamp()
      WHERE id = v_match_record_id;
      v_final_status := 'MATCHED_AUTO_HIGH_CONFIDENCE';
      v_auto_confirmed := true;
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
        p_action:='MATCHING_AUTO_CONFIRMED',
        p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
        p_subject_id:=v_match_record_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
        p_actor_system:='matching_engine',
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_before_state:=NULL,
        p_after_state:=jsonb_build_object(
          'match_record_id', v_match_record_id, 'match_level', p_match_level,
          'recurring_vendor_signal', v_recurring, 'amount_exact_match', v_amount_exact,
          'note', 'strong_probable_with_high_vendor_signal_and_amount_exact'
        ),
        p_reason:=NULL, p_request_context:=p_context
      );
      IF p_counterparty_signature IS NOT NULL THEN
        v_vendor_env := public.record_vendor_memory_confirmation(
          p_organization_id, p_business_id, p_counterparty_signature,
          'matching.auto_confirm', v_match_record_id, p_context
        );
      END IF;
    ELSE
      v_final_status := 'MATCHED_NEEDS_CONFIRMATION';
      INSERT INTO public.review_issues (
        organization_id, business_id, workflow_run_id, transaction_id, match_record_id,
        issue_type, issue_group, severity,
        plain_language_title, plain_language_description, recommended_action
      ) VALUES (
        p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id, v_match_record_id,
        'match.needs_confirmation',
        'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
        'MEDIUM'::public.review_issue_severity_enum,
        'A strong-probable match needs your confirmation',
        'We found a likely matching invoice but want you to confirm before booking it.',
        'Review the proposed match and confirm or reject'
      ) RETURNING id INTO v_review_issue_id;
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
        p_action:='MATCHING_NEEDS_CONFIRMATION_RAISED',
        p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
        p_subject_id:=v_match_record_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
        p_actor_system:='matching_engine',
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_before_state:=NULL,
        p_after_state:=jsonb_build_object(
          'match_record_id', v_match_record_id, 'review_issue_id', v_review_issue_id,
          'recurring_vendor_signal', v_recurring, 'amount_exact_match', v_amount_exact
        ),
        p_reason:=NULL, p_request_context:=p_context
      );
    END IF;

  ELSE
    v_final_status := 'POSSIBLE_MATCH';
    v_severity := CASE WHEN v_txn_type = 'OUT_EXPENSE'
                       THEN 'MEDIUM'::public.review_issue_severity_enum
                       ELSE 'LOW'::public.review_issue_severity_enum END;
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id, match_record_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id, v_match_record_id,
      'match.possible_weak',
      'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
      v_severity,
      'A weakly possible match needs your judgement',
      'We found a candidate document but signals are weak. Open the match card to compare.',
      'Review the candidate and confirm or reject'
    ) RETURNING id INTO v_review_issue_id;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='MATCHING_POSSIBLE_RAISED',
      p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
      p_subject_id:=v_match_record_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='matching_engine',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'match_record_id', v_match_record_id, 'review_issue_id', v_review_issue_id,
        'severity', v_severity, 'transaction_type', v_txn_type
      ),
      p_reason:=NULL, p_request_context:=p_context
    );
  END IF;

  RETURN jsonb_build_object(
    'decision','RECORDED','match_record_id', v_match_record_id,
    'match_level', p_match_level, 'final_status', v_final_status,
    'auto_confirmed', v_auto_confirmed, 'review_issue_id', v_review_issue_id,
    'vendor_memory_envelope', v_vendor_env
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_match_no_match(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_txn_type public.transaction_type_enum; v_review_issue_id uuid;
BEGIN
  SELECT transaction_type INTO v_txn_type FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','TRANSACTION_NOT_FOUND','transaction_id',p_transaction_id);
  END IF;
  IF v_txn_type = 'OUT_EXPENSE' THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
      'match.missing_documents',
      'MISSING_DOCUMENTS'::public.review_issue_group_enum,
      'HIGH'::public.review_issue_severity_enum,
      'No supporting document found for this expense',
      'The matching engine could not find an invoice or receipt for this OUT expense.',
      'Upload the document, or mark as no invoice available'
    ) RETURNING id INTO v_review_issue_id;
  END IF;
  RETURN jsonb_build_object(
    'decision','RECORDED','transaction_id',p_transaction_id,
    'transaction_type',v_txn_type,'review_issue_id',v_review_issue_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.user_confirm_match(p_match_record_id uuid, p_actor_user_id uuid, p_counterparty_signature text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_current_status public.match_record_status_enum; v_vendor_env jsonb;
BEGIN
  SELECT organization_id, business_id, transaction_id, match_status
    INTO v_organization_id, v_business_id, v_transaction_id, v_current_status
  FROM public.match_records WHERE id = p_match_record_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','MATCH_RECORD_NOT_FOUND','match_record_id',p_match_record_id);
  END IF;

  UPDATE public.match_records
    SET match_status = 'MATCHED_CONFIRMED'::public.match_record_status_enum,
        user_confirmation_status = 'CONFIRMED',
        confirmed_by = p_actor_user_id, confirmed_at = clock_timestamp(),
        requires_user_confirmation = false, updated_at = clock_timestamp()
  WHERE id = p_match_record_id;

  IF p_counterparty_signature IS NOT NULL THEN
    v_vendor_env := public.record_vendor_memory_confirmation(
      v_organization_id, v_business_id, p_counterparty_signature,
      'matching.user_confirm', p_match_record_id, p_context
    );
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='MATCHING_USER_CONFIRMED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object('match_status', v_current_status),
    p_after_state:=jsonb_build_object('match_status','MATCHED_CONFIRMED','transaction_id', v_transaction_id),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','CONFIRMED','match_record_id',p_match_record_id,
    'transaction_id',v_transaction_id,'vendor_memory_envelope',v_vendor_env
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.user_edit_and_confirm_match(p_original_match_record_id uuid, p_actor_user_id uuid, p_replacement_document_id uuid DEFAULT NULL::uuid, p_replacement_match_record_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_current_status public.match_record_status_enum;
BEGIN
  SELECT organization_id, business_id, transaction_id, match_status
    INTO v_organization_id, v_business_id, v_transaction_id, v_current_status
  FROM public.match_records WHERE id = p_original_match_record_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','MATCH_RECORD_NOT_FOUND','match_record_id',p_original_match_record_id);
  END IF;
  UPDATE public.match_records
    SET match_status = 'REJECTED_MATCH'::public.match_record_status_enum,
        user_confirmation_status = 'EDITED', updated_at = clock_timestamp()
  WHERE id = p_original_match_record_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='MATCHING_USER_EDITED_AND_CONFIRMED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_original_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object('match_status', v_current_status),
    p_after_state:=jsonb_build_object(
      'original_match_record_id', p_original_match_record_id,
      'replacement_document_id', p_replacement_document_id,
      'replacement_match_record_id', p_replacement_match_record_id,
      'transaction_id', v_transaction_id,
      'note', 'edit_does_not_add_to_rejection_memory'
    ),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN jsonb_build_object(
    'decision','EDITED','original_match_record_id',p_original_match_record_id,
    'replacement_document_id',p_replacement_document_id,
    'replacement_match_record_id',p_replacement_match_record_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.canonicalize_country_alpha2(p_raw text)
 RETURNS character
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_raw IS NULL OR length(trim(p_raw)) = 0 THEN NULL
    WHEN length(trim(p_raw)) = 2 THEN upper(trim(p_raw))::char(2)
    ELSE CASE upper(trim(p_raw))
      WHEN 'CYPRUS' THEN 'CY'::char(2)
      WHEN 'GERMANY' THEN 'DE'::char(2)
      WHEN 'GREECE' THEN 'GR'::char(2)
      WHEN 'IRELAND' THEN 'IE'::char(2)
      WHEN 'UNITED KINGDOM' THEN 'GB'::char(2)
      WHEN 'NORTHERN IRELAND' THEN 'XI'::char(2)
      WHEN 'NETHERLANDS' THEN 'NL'::char(2)
      WHEN 'FRANCE' THEN 'FR'::char(2)
      WHEN 'ITALY' THEN 'IT'::char(2)
      WHEN 'SPAIN' THEN 'ES'::char(2)
      WHEN 'UNITED STATES' THEN 'US'::char(2)
      ELSE NULL
    END
  END;
$function$
;

CREATE OR REPLACE FUNCTION public._construct_archive_bundle_stub(p_run_id uuid, p_business_id uuid, p_organization_id uuid, p_period_start date, p_period_end date, p_started_by uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'extensions', 'pg_temp'
AS $function$
DECLARE
  v_pkg_id uuid := public.gen_uuid_v7();
  v_manifest_id uuid := public.gen_uuid_v7();
  v_txns text; v_matches text; v_ledger text; v_issues text; v_evidx text;
  v_vat text; v_vies text; v_finsum text; v_pdf text;
  v_evidence_list jsonb;
  v_manifest_pass1 text; v_manifest_pass2 text;
  v_internal_hashes jsonb := '{}'::jsonb;
  v_file_list jsonb;
  v_anchor_pass1 text; v_anchor_final text;
  v_pkg_count int := 0;
BEGIN
  -- Compose all non-manifest file contents (canonical jsonb::text).
  v_txns    := public._compose_transactions_json(p_business_id, p_period_start, p_period_end)::text;
  v_matches := public._compose_matches_json(p_business_id, p_period_start, p_period_end)::text;
  v_ledger  := public._compose_ledger_entries_json(p_business_id, p_period_start, p_period_end)::text;
  v_issues  := public._compose_review_issues_json(p_run_id)::text;
  v_evidence_list := public._compose_evidence_index_json(p_business_id, p_period_start, p_period_end);
  v_evidx   := v_evidence_list::text;
  v_vat     := public._compose_vat_summary_json(p_business_id, p_period_start, p_period_end)::text;
  v_vies    := public._compose_vies_export_csv(p_business_id, p_period_start, p_period_end);
  v_finsum  := public._compose_finalization_summary_json(p_run_id, v_pkg_id)::text;
  v_pdf     := public._compose_period_report_pdf_stub(p_business_id, p_period_start, p_period_end, p_run_id);

  -- Build the internal_file_hashes dict (all files EXCEPT manifest_v1.json).
  v_internal_hashes := jsonb_build_object(
    'transactions.json',         public._hash_text(v_txns),
    'matches.json',              public._hash_text(v_matches),
    'ledger_entries.json',       public._hash_text(v_ledger),
    'review_issues.json',        public._hash_text(v_issues),
    'evidence_index.json',       public._hash_text(v_evidx),
    'vat_summary.json',          public._hash_text(v_vat),
    'vies_export.csv',           public._hash_text(v_vies),
    'finalization_summary.json', public._hash_text(v_finsum),
    'period_report.pdf',         public._hash_text(v_pdf));

  -- Add evidence/<hash> entries.
  SELECT v_internal_hashes ||
         COALESCE(jsonb_object_agg('evidence/' || (e->>'file_hash'),
                                    public._hash_text('evidence/' || (e->>'file_hash')
                                                       || ':' || (e->>'document_id'))),
                  '{}'::jsonb)
    INTO v_internal_hashes
    FROM jsonb_array_elements(v_evidence_list) AS e;

  -- Pass 1: manifest with placeholder anchor.
  v_manifest_pass1 := public._compose_manifest_v1_json(
    p_run_id, v_pkg_id, v_internal_hashes, 'PLACEHOLDER_BUNDLE_HASH')::text;

  -- Pass-1 file list = all files including pass-1 manifest.
  v_file_list := jsonb_build_array(
    jsonb_build_object('path','manifest_v1.json',          'hash', public._hash_text(v_manifest_pass1)),
    jsonb_build_object('path','transactions.json',         'hash', v_internal_hashes->>'transactions.json'),
    jsonb_build_object('path','matches.json',              'hash', v_internal_hashes->>'matches.json'),
    jsonb_build_object('path','ledger_entries.json',       'hash', v_internal_hashes->>'ledger_entries.json'),
    jsonb_build_object('path','review_issues.json',        'hash', v_internal_hashes->>'review_issues.json'),
    jsonb_build_object('path','evidence_index.json',       'hash', v_internal_hashes->>'evidence_index.json'),
    jsonb_build_object('path','vat_summary.json',          'hash', v_internal_hashes->>'vat_summary.json'),
    jsonb_build_object('path','vies_export.csv',           'hash', v_internal_hashes->>'vies_export.csv'),
    jsonb_build_object('path','finalization_summary.json', 'hash', v_internal_hashes->>'finalization_summary.json'),
    jsonb_build_object('path','period_report.pdf',         'hash', v_internal_hashes->>'period_report.pdf'));
  SELECT v_file_list ||
         COALESCE(jsonb_agg(jsonb_build_object(
           'path', 'evidence/' || (e->>'file_hash'),
           'hash', v_internal_hashes->>('evidence/' || (e->>'file_hash')))), '[]'::jsonb)
    INTO v_file_list
    FROM jsonb_array_elements(v_evidence_list) AS e;

  v_anchor_pass1 := public._compute_bundle_anchor(v_file_list);

  -- Pass 2: manifest with real anchor.
  v_manifest_pass2 := public._compose_manifest_v1_json(
    p_run_id, v_pkg_id, v_internal_hashes, v_anchor_pass1)::text;

  -- Replace the manifest entry in v_file_list with pass-2 hash.
  v_file_list := jsonb_build_array(
    jsonb_build_object('path','manifest_v1.json', 'hash', public._hash_text(v_manifest_pass2)))
    || (SELECT jsonb_agg(item) FROM jsonb_array_elements(v_file_list) item
        WHERE (item->>'path') <> 'manifest_v1.json');

  v_anchor_final := public._compute_bundle_anchor(v_file_list);

  -- Persist.
  INSERT INTO public.archive_packages (id, organization_id, business_id, workflow_run_id,
    period_start, period_end, package_storage_object_id, bundle_hash_anchor,
    created_by_user_id, step_up_auth_used, original_finalization)
  VALUES (v_pkg_id, p_organization_id, p_business_id, p_run_id,
          p_period_start, p_period_end,
          format('archive/%s/%s/bundle_v1.zip', p_business_id, p_run_id),
          v_anchor_final, p_started_by, true, true);

  INSERT INTO public.archive_manifests (id, organization_id, business_id, archive_package_id,
    manifest_version_number, manifest_storage_object_id, manifest_hash,
    produced_by_run_id, produced_by_approval_id)
  VALUES (v_manifest_id, p_organization_id, p_business_id, v_pkg_id,
          1, format('archive/%s/%s/manifest_v1.json', p_business_id, p_run_id),
          public._hash_text(v_manifest_pass2), p_run_id,
          public.latest_qualifying_step_up_approval(p_business_id, p_run_id));

  -- Populate archive_files (one row per relative_path).
  INSERT INTO public.archive_files (organization_id, business_id, archive_manifest_id,
    relative_path, file_hash, byte_size)
  SELECT p_organization_id, p_business_id, v_manifest_id,
         item.path, item.hash,
         CASE item.path
           WHEN 'manifest_v1.json'         THEN octet_length(v_manifest_pass2)
           WHEN 'transactions.json'        THEN octet_length(v_txns)
           WHEN 'matches.json'             THEN octet_length(v_matches)
           WHEN 'ledger_entries.json'      THEN octet_length(v_ledger)
           WHEN 'review_issues.json'       THEN octet_length(v_issues)
           WHEN 'evidence_index.json'      THEN octet_length(v_evidx)
           WHEN 'vat_summary.json'         THEN octet_length(v_vat)
           WHEN 'vies_export.csv'          THEN octet_length(v_vies)
           WHEN 'finalization_summary.json' THEN octet_length(v_finsum)
           WHEN 'period_report.pdf'        THEN octet_length(v_pdf)
           ELSE 1
         END
    FROM jsonb_to_recordset(v_file_list) AS item(path text, hash text);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_BUNDLE_CONSTRUCTED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_bundle_constructor',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object(
      'archive_package_id', v_pkg_id, 'manifest_version', 1,
      'bundle_hash_anchor', v_anchor_final,
      'file_count', jsonb_array_length(v_file_list)));
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_PERIOD_REPORT_GENERATED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_bundle_constructor',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('pdf_hash', v_internal_hashes->>'period_report.pdf'));
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_VIES_EXPORT_GENERATED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_bundle_constructor',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('vies_hash', v_internal_hashes->>'vies_export.csv',
                                       'byte_size', octet_length(v_vies)));

  RETURN v_pkg_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_split_payment_detector_ran(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_candidate_count integer, p_proposed_count integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  IF p_candidate_count < 0 OR p_proposed_count < 0 THEN
    RAISE EXCEPTION 'COUNTS_MUST_BE_NONNEGATIVE' USING errcode='check_violation';
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_SPLIT_PAYMENT_DETECTOR_RAN',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'transaction_id', p_transaction_id,
      'candidate_count', p_candidate_count, 'proposed_count', p_proposed_count
    ),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN jsonb_build_object(
    'decision','RECORDED','transaction_id',p_transaction_id,
    'candidate_count',p_candidate_count,'proposed_count',p_proposed_count
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_split_payment_candidate_set_truncated(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_full_count integer, p_truncated_to integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  IF p_truncated_to <= 0 OR p_full_count < p_truncated_to THEN
    RAISE EXCEPTION 'TRUNCATION_BOUNDS_INVALID' USING errcode='check_violation';
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_SPLIT_PAYMENT_CANDIDATE_SET_TRUNCATED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'transaction_id', p_transaction_id,
      'full_count', p_full_count, 'truncated_to', p_truncated_to
    ),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN jsonb_build_object(
    'decision','RECORDED','transaction_id',p_transaction_id,
    'full_count',p_full_count,'truncated_to',p_truncated_to
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.confirm_split_payment_group(p_group_id uuid, p_actor_user_id uuid, p_match_level match_level_enum DEFAULT 'STRONG_PROBABLE'::match_level_enum, p_match_method match_method_enum DEFAULT 'DETERMINISTIC_RULE'::match_method_enum, p_match_score numeric DEFAULT 0.85, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_current_status public.split_payment_group_status_enum;
  v_match_record_ids uuid[] := ARRAY[]::uuid[];
  v_new_mr_id uuid; v_constituent record;
  v_sibling_id uuid; v_siblings_rejected int := 0;
BEGIN
  SELECT organization_id, business_id, transaction_id, status
    INTO v_organization_id, v_business_id, v_transaction_id, v_current_status
  FROM public.split_payment_groups WHERE id = p_group_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','GROUP_NOT_FOUND','group_id',p_group_id);
  END IF;
  IF v_current_status <> 'PROPOSED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','GROUP_NOT_PROPOSED',
      'group_id',p_group_id,'current_status',v_current_status
    );
  END IF;

  UPDATE public.split_payment_groups
    SET status = 'CONFIRMED'::public.split_payment_group_status_enum,
        confirmed_by = p_actor_user_id, confirmed_at = clock_timestamp()
  WHERE id = p_group_id;

  FOR v_constituent IN
    SELECT document_id, per_pair_score
    FROM public.split_payment_group_constituents
    WHERE group_id = p_group_id ORDER BY position
  LOOP
    INSERT INTO public.match_records (
      organization_id, business_id, transaction_id, document_id,
      match_level, match_method, match_score, match_signals,
      match_status, requires_user_confirmation,
      split_payment_flag, split_payment_group_id,
      matched_by_user_id, confirmed_by, confirmed_at, user_confirmation_status
    ) VALUES (
      v_organization_id, v_business_id, v_transaction_id, v_constituent.document_id,
      p_match_level, p_match_method, p_match_score,
      jsonb_build_object('split_payment_member', true, 'per_pair_score', v_constituent.per_pair_score),
      'MATCHED_CONFIRMED'::public.match_record_status_enum, false,
      true, p_group_id,
      p_actor_user_id, p_actor_user_id, clock_timestamp(), 'CONFIRMED'
    )
    RETURNING id INTO v_new_mr_id;
    v_match_record_ids := array_append(v_match_record_ids, v_new_mr_id);
  END LOOP;

  FOR v_sibling_id IN
    SELECT id FROM public.split_payment_groups
    WHERE transaction_id = v_transaction_id
      AND status = 'PROPOSED'
      AND id <> p_group_id
  LOOP
    UPDATE public.split_payment_groups
      SET status = 'REJECTED'::public.split_payment_group_status_enum,
          rejected_by = p_actor_user_id, rejected_at = clock_timestamp()
    WHERE id = v_sibling_id;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='SPLIT_PAYMENT_GROUP_REJECTED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=v_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='matching_engine',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=jsonb_build_object('status', 'PROPOSED'),
      p_after_state:=jsonb_build_object(
        'split_payment_group_id', v_sibling_id, 'status', 'REJECTED',
        'reason', 'sibling_of_confirmed_group',
        'confirmed_sibling_group_id', p_group_id
      ),
      p_reason:='sibling cascade reject', p_request_context:=p_context
    );
    v_siblings_rejected := v_siblings_rejected + 1;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='SPLIT_PAYMENT_GROUP_CONFIRMED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=v_transaction_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object('status', 'PROPOSED'),
    p_after_state:=jsonb_build_object(
      'split_payment_group_id', p_group_id, 'status', 'CONFIRMED',
      'match_record_ids', to_jsonb(v_match_record_ids),
      'siblings_rejected', v_siblings_rejected
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','CONFIRMED', 'group_id', p_group_id,
    'transaction_id', v_transaction_id,
    'match_record_ids', to_jsonb(v_match_record_ids),
    'siblings_rejected', v_siblings_rejected
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.resolve_counterparty(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_workflow_run_id uuid, p_match_record_id uuid DEFAULT NULL::uuid, p_doc_country text DEFAULT NULL::text, p_doc_vat_number text DEFAULT NULL::text, p_doc_extraction_layer text DEFAULT NULL::text, p_iban_country_candidate character DEFAULT NULL::bpchar, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_signature text;
  v_match_status public.transaction_match_status_enum;
  v_doc_country_canon char(2);
  v_doc_vat_canon text;
  v_doc_vat_valid boolean;
  v_vm record;
  v_resolved_country char(2);
  v_resolved_vat text;
  v_resolved_source text;
  v_resolved_confidence text;
  v_review_ids uuid[] := ARRAY[]::uuid[];
  v_review_id uuid;
  v_writeback boolean := false;
BEGIN
  SELECT lower(trim(coalesce(counterparty_name, ''))) INTO v_signature
    FROM public.transactions WHERE id = p_transaction_id;
  IF p_match_record_id IS NOT NULL THEN
    SELECT match_status INTO v_match_status FROM public.transactions WHERE id = p_transaction_id;
  END IF;

  IF p_match_record_id IS NOT NULL AND (p_doc_country IS NOT NULL OR p_doc_vat_number IS NOT NULL) THEN
    v_doc_country_canon := public.canonicalize_country_alpha2(p_doc_country);
    IF p_doc_vat_number IS NOT NULL THEN
      v_doc_vat_canon := public.canonicalize_vat_number(v_doc_country_canon, p_doc_vat_number);
      v_doc_vat_valid := public.validate_vat_number_format(v_doc_country_canon, v_doc_vat_canon);
      IF v_doc_vat_canon IS NOT NULL AND NOT v_doc_vat_valid THEN
        INSERT INTO public.review_issues (
          organization_id, business_id, workflow_run_id, transaction_id,
          issue_type, issue_group, severity,
          plain_language_title, plain_language_description, recommended_action,
          card_payload_json
        ) VALUES (
          p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
          'counterparty.vat_number_invalid',
          'POSSIBLE_TAX_VAT_ISSUE'::public.review_issue_group_enum,
          'MEDIUM'::public.review_issue_severity_enum,
          'Counterparty VAT number format invalid',
          'The extracted VAT number does not match the expected format for the counterparty country. The value is stored but needs review.',
          'Verify and correct the VAT number',
          jsonb_build_object('country', v_doc_country_canon, 'raw_vat', p_doc_vat_number, 'canonical_vat', v_doc_vat_canon)
        ) RETURNING id INTO v_review_id;
        v_review_ids := array_append(v_review_ids, v_review_id);
      END IF;
    END IF;
    IF v_doc_country_canon IS NOT NULL OR v_doc_vat_canon IS NOT NULL THEN
      v_resolved_country := v_doc_country_canon;
      v_resolved_vat := v_doc_vat_canon;
      v_resolved_source := 'DOCUMENT';
      v_resolved_confidence := CASE
        WHEN p_doc_extraction_layer IN ('TIER3_AI','DETERMINISTIC') THEN 'HIGH'
        WHEN p_doc_extraction_layer = 'TIER2_AI' THEN 'MEDIUM'
        ELSE 'MEDIUM' END;
    END IF;
  END IF;

  IF v_signature IS NOT NULL AND length(v_signature) > 0 THEN
    SELECT counterparty_country, counterparty_vat_number, confirmations_count
      INTO v_vm FROM public.recurring_vendor_memory
     WHERE business_id = p_business_id AND counterparty_signature = v_signature
     ORDER BY last_confirmation_at DESC NULLS LAST LIMIT 1;

    IF v_resolved_source IS NULL AND v_vm.counterparty_country IS NOT NULL THEN
      v_resolved_country := v_vm.counterparty_country;
      v_resolved_vat := v_vm.counterparty_vat_number;
      v_resolved_source := 'VENDOR_MEMORY';
      v_resolved_confidence := CASE
        WHEN v_vm.confirmations_count >= 3 THEN 'HIGH'
        WHEN v_vm.confirmations_count >= 2 THEN 'MEDIUM'
        ELSE 'LOW' END;
    ELSIF v_resolved_country IS NOT NULL AND v_vm.counterparty_country IS NOT NULL
          AND v_resolved_country <> v_vm.counterparty_country THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
        p_action:='LEDGER_COUNTERPARTY_DISAGREEMENT_DETECTED',
        p_subject_type:='TRANSACTION'::audit.subject_type_enum,
        p_subject_id:=p_transaction_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
        p_actor_system:='counterparty_resolver',
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_before_state:=NULL,
        p_after_state:=jsonb_build_object('doc_country', v_resolved_country, 'vendor_memory_country', v_vm.counterparty_country, 'winner', 'DOCUMENT'),
        p_reason:=NULL, p_request_context:=p_context
      );
      INSERT INTO public.review_issues (
        organization_id, business_id, workflow_run_id, transaction_id,
        issue_type, issue_group, severity,
        plain_language_title, plain_language_description, recommended_action,
        card_payload_json
      ) VALUES (
        p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
        'counterparty.country_disagreement',
        'POSSIBLE_TAX_VAT_ISSUE'::public.review_issue_group_enum,
        'MEDIUM'::public.review_issue_severity_enum,
        'Counterparty country sources disagree',
        'The document and the vendor memory suggest different counterparty countries. The higher-confidence source was used; please confirm.',
        'Confirm the correct counterparty country',
        jsonb_build_object('doc_country', v_resolved_country, 'vendor_memory_country', v_vm.counterparty_country)
      ) RETURNING id INTO v_review_id;
      v_review_ids := array_append(v_review_ids, v_review_id);
    END IF;
  END IF;

  IF v_resolved_source IS NULL AND p_iban_country_candidate IS NOT NULL THEN
    v_resolved_country := p_iban_country_candidate;
    v_resolved_vat := NULL;
    v_resolved_source := 'TRANSACTION_METADATA';
    v_resolved_confidence := 'LOW';
  END IF;

  IF v_resolved_source IS NULL THEN
    v_resolved_source := 'UNRESOLVED';
    v_resolved_confidence := 'LOW';
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_COUNTERPARTY_UNRESOLVED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='counterparty_resolver',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('signature', v_signature, 'workflow_run_id', p_workflow_run_id),
      p_reason:=NULL, p_request_context:=p_context);
  ELSE
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_COUNTERPARTY_RESOLVED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='counterparty_resolver',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('country', v_resolved_country, 'vat_number', v_resolved_vat, 'source', v_resolved_source, 'confidence', v_resolved_confidence, 'workflow_run_id', p_workflow_run_id),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  IF v_resolved_source = 'DOCUMENT' AND v_resolved_confidence = 'HIGH'
     AND v_match_status IN ('MATCHED_AUTO_CONFIRMED','MATCHED_CONFIRMED') THEN
    v_writeback := public._writeback_counterparty_to_vendor_memory(
      p_business_id, v_signature, v_resolved_country, v_resolved_vat, 'HIGH');
  END IF;

  RETURN jsonb_build_object(
    'counterparty_country', v_resolved_country,
    'counterparty_vat_number', v_resolved_vat,
    'source', v_resolved_source,
    'confidence', v_resolved_confidence,
    'evidence_pointer', jsonb_build_object(
      'transaction_id', p_transaction_id,
      'match_record_id', p_match_record_id,
      'doc_extraction_layer', p_doc_extraction_layer),
    'review_issue_ids', to_jsonb(v_review_ids),
    'writeback_applied', v_writeback
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public._hash_text(p text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'extensions', 'pg_temp'
AS $function$ SELECT encode(extensions.digest(p, 'sha256'), 'hex'); $function$
;

CREATE OR REPLACE FUNCTION public._compose_transactions_json(p_business_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', t.id, 'transaction_date', t.transaction_date,
    'amount', t.amount, 'currency', t.currency,
    'direction', t.direction, 'transaction_type', t.transaction_type,
    'classification_status', t.classification_status,
    'match_status', t.match_status,
    'transaction_fingerprint', t.transaction_fingerprint
  ) ORDER BY t.id), '[]'::jsonb)
  FROM public.transactions t
  WHERE t.business_id = p_business_id
    AND t.transaction_date BETWEEN p_period_start AND p_period_end;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_matches_json(p_business_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', mr.id, 'transaction_id', mr.transaction_id,
    'document_id', mr.document_id, 'invoice_id', mr.invoice_id,
    'match_level', mr.match_level, 'match_method', mr.match_method,
    'match_score', mr.match_score, 'match_status', mr.match_status,
    'income_outcome', mr.income_outcome,
    'split_payment_flag', mr.split_payment_flag
  ) ORDER BY mr.id), '[]'::jsonb)
  FROM public.match_records mr
  JOIN public.transactions t ON t.id = mr.transaction_id
  WHERE t.business_id = p_business_id
    AND t.transaction_date BETWEEN p_period_start AND p_period_end;
$function$
;

CREATE OR REPLACE FUNCTION public.propose_split_payment_group(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_parent_target_kind split_payment_parent_target_kind_enum, p_parent_target_id uuid, p_proposed_total_amount numeric, p_currency character, p_constituent_document_ids uuid[], p_per_pair_scores numeric[], p_candidate_score numeric, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_group_id uuid; v_constituent_count int; v_i int;
BEGIN
  IF p_constituent_document_ids IS NULL OR array_length(p_constituent_document_ids, 1) IS NULL THEN
    RAISE EXCEPTION 'CONSTITUENT_DOCUMENT_IDS_REQUIRED' USING errcode='check_violation';
  END IF;
  v_constituent_count := array_length(p_constituent_document_ids, 1);
  IF v_constituent_count < 2 OR v_constituent_count > 5 THEN
    RAISE EXCEPTION 'CONSTITUENT_COUNT_OUT_OF_RANGE_2_5' USING errcode='check_violation';
  END IF;
  IF p_per_pair_scores IS NOT NULL
     AND array_length(p_per_pair_scores, 1) <> v_constituent_count THEN
    RAISE EXCEPTION 'PER_PAIR_SCORES_LENGTH_MISMATCH' USING errcode='check_violation';
  END IF;

  INSERT INTO public.split_payment_groups (
    organization_id, business_id, transaction_id,
    parent_target_kind, parent_target_id,
    proposed_total_amount, currency, status
  ) VALUES (
    p_organization_id, p_business_id, p_transaction_id,
    p_parent_target_kind, p_parent_target_id,
    p_proposed_total_amount, p_currency, 'PROPOSED'
  ) RETURNING id INTO v_group_id;

  FOR v_i IN 1 .. v_constituent_count LOOP
    INSERT INTO public.split_payment_group_constituents (
      group_id, document_id, per_pair_score, position
    ) VALUES (
      v_group_id, p_constituent_document_ids[v_i],
      CASE WHEN p_per_pair_scores IS NOT NULL THEN p_per_pair_scores[v_i] ELSE NULL END,
      v_i
    );
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='SPLIT_PAYMENT_GROUP_CREATED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'split_payment_group_id', v_group_id, 'transaction_id', p_transaction_id,
      'parent_target_kind', p_parent_target_kind,
      'proposed_total_amount', p_proposed_total_amount, 'currency', p_currency,
      'constituent_count', v_constituent_count, 'status', 'PROPOSED'
    ),
    p_reason:=NULL, p_request_context:=p_context
  );
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_SPLIT_PAYMENT_CANDIDATE_PROPOSED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'split_payment_group_id', v_group_id, 'transaction_id', p_transaction_id,
      'candidate_score', p_candidate_score, 'constituent_count', v_constituent_count
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','PROPOSED', 'group_id', v_group_id,
    'constituent_count', v_constituent_count, 'candidate_score', p_candidate_score
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.raise_split_payment_review_issue(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_workflow_run_id uuid, p_candidate_summary jsonb, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_review_issue_id uuid;
BEGIN
  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id, transaction_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action,
    card_payload_json
  ) VALUES (
    p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
    'matching.split_payment_proposal',
    'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
    'MEDIUM'::public.review_issue_severity_enum,
    'This transaction might cover several invoices',
    'We could not find a single invoice that matches this transaction amount, but we found a few combinations that add up to it.',
    'Review the proposed split-payment combinations',
    COALESCE(p_candidate_summary, '{}'::jsonb)
  ) RETURNING id INTO v_review_issue_id;
  RETURN jsonb_build_object(
    'decision','RAISED','review_issue_id',v_review_issue_id,
    'transaction_id',p_transaction_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reject_split_payment_group(p_group_id uuid, p_actor_user_id uuid, p_rejection_reason text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid; v_transaction_id uuid;
  v_current_status public.split_payment_group_status_enum;
BEGIN
  SELECT organization_id, business_id, transaction_id, status
    INTO v_organization_id, v_business_id, v_transaction_id, v_current_status
  FROM public.split_payment_groups WHERE id = p_group_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','GROUP_NOT_FOUND','group_id',p_group_id);
  END IF;
  IF v_current_status <> 'PROPOSED' THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','GROUP_NOT_PROPOSED',
      'group_id',p_group_id,'current_status',v_current_status
    );
  END IF;

  UPDATE public.split_payment_groups
    SET status = 'REJECTED'::public.split_payment_group_status_enum,
        rejected_by = p_actor_user_id, rejected_at = clock_timestamp()
  WHERE id = p_group_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='SPLIT_PAYMENT_GROUP_REJECTED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=v_transaction_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object('status', 'PROPOSED'),
    p_after_state:=jsonb_build_object(
      'split_payment_group_id', p_group_id, 'status', 'REJECTED',
      'reason', COALESCE(p_rejection_reason, 'user_rejected')
    ),
    p_reason:=p_rejection_reason, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','REJECTED','group_id',p_group_id,'transaction_id',v_transaction_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_duplicate_pattern_resolved(p_review_issue_id uuid, p_actor_user_id uuid, p_resolution_kind text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid;
  v_transaction_id uuid; v_document_id uuid;
  v_issue_type text;
  v_subject_type audit.subject_type_enum; v_subject_id uuid;
BEGIN
  IF p_resolution_kind NOT IN (
    'confirmed_as_split_payment','rejected_one_match','marked_as_duplicate',
    'picked_right_match','marked_legitimate_multi_match','edited_matches'
  ) THEN
    RAISE EXCEPTION 'RESOLUTION_KIND_INVALID' USING errcode='check_violation';
  END IF;

  SELECT organization_id, business_id, transaction_id, document_id, issue_type
    INTO v_organization_id, v_business_id, v_transaction_id, v_document_id, v_issue_type
  FROM public.review_issues WHERE id = p_review_issue_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','REVIEW_ISSUE_NOT_FOUND','review_issue_id',p_review_issue_id);
  END IF;

  IF v_document_id IS NOT NULL AND v_issue_type = 'matching.document_used_multiple_times' THEN
    v_subject_type := 'DOCUMENT'::audit.subject_type_enum;
    v_subject_id := v_document_id;
  ELSIF v_transaction_id IS NOT NULL THEN
    v_subject_type := 'TRANSACTION'::audit.subject_type_enum;
    v_subject_id := v_transaction_id;
  ELSE
    v_subject_type := 'TRANSACTION'::audit.subject_type_enum;
    v_subject_id := NULL;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='MATCHING_DUPLICATE_PATTERN_RESOLVED',
    p_subject_type:=v_subject_type,
    p_subject_id:=v_subject_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'review_issue_id', p_review_issue_id, 'issue_type', v_issue_type,
      'resolution_kind', p_resolution_kind
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','RECORDED', 'review_issue_id', p_review_issue_id,
    'resolution_kind', p_resolution_kind
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.detect_duplicate_pattern_a(p_business_id uuid, p_document_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_total int; v_distinct_txn int; v_distinct_group int;
  v_only_group_id uuid;
  v_group_status public.split_payment_group_status_enum;
  v_txn_ids uuid[]; v_mr_ids uuid[];
BEGIN
  SELECT
    count(*),
    count(DISTINCT transaction_id),
    count(DISTINCT split_payment_group_id) FILTER (WHERE split_payment_group_id IS NOT NULL),
    array_agg(DISTINCT transaction_id ORDER BY transaction_id),
    array_agg(id ORDER BY id)
  INTO v_total, v_distinct_txn, v_distinct_group, v_txn_ids, v_mr_ids
  FROM public.match_records
  WHERE business_id = p_business_id AND document_id = p_document_id
    AND match_status <> 'REJECTED_MATCH'::public.match_record_status_enum;

  IF v_total <= 1 OR v_distinct_txn <= 1 THEN
    RETURN jsonb_build_object('detected', false, 'reason', 'SINGLE_TRANSACTION',
      'document_id', p_document_id, 'total_match_records', COALESCE(v_total,0));
  END IF;

  IF v_distinct_group = 1 THEN
    SELECT DISTINCT split_payment_group_id INTO v_only_group_id
    FROM public.match_records
    WHERE business_id = p_business_id AND document_id = p_document_id
      AND match_status <> 'REJECTED_MATCH'::public.match_record_status_enum
      AND split_payment_group_id IS NOT NULL;
    PERFORM 1 FROM public.match_records
    WHERE business_id = p_business_id AND document_id = p_document_id
      AND match_status <> 'REJECTED_MATCH'::public.match_record_status_enum
      AND split_payment_group_id IS NULL
    LIMIT 1;
    IF NOT FOUND AND v_only_group_id IS NOT NULL THEN
      SELECT status INTO v_group_status FROM public.split_payment_groups WHERE id = v_only_group_id;
      IF v_group_status IN ('PROPOSED','CONFIRMED') THEN
        RETURN jsonb_build_object(
          'detected', false, 'reason', 'EXCLUDED_BY_SPLIT_PAYMENT_GROUP',
          'document_id', p_document_id,
          'split_payment_group_id', v_only_group_id, 'group_status', v_group_status
        );
      END IF;
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'detected', true, 'document_id', p_document_id,
    'transaction_ids', to_jsonb(v_txn_ids),
    'match_record_ids', to_jsonb(v_mr_ids),
    'total_match_records', v_total
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.detect_duplicate_pattern_b(p_business_id uuid, p_transaction_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_total int; v_distinct_doc int; v_distinct_group int;
  v_only_group_id uuid;
  v_group_status public.split_payment_group_status_enum;
  v_doc_ids uuid[]; v_mr_ids uuid[];
BEGIN
  SELECT
    count(*),
    count(DISTINCT document_id),
    count(DISTINCT split_payment_group_id) FILTER (WHERE split_payment_group_id IS NOT NULL),
    array_agg(DISTINCT document_id ORDER BY document_id),
    array_agg(id ORDER BY id)
  INTO v_total, v_distinct_doc, v_distinct_group, v_doc_ids, v_mr_ids
  FROM public.match_records
  WHERE business_id = p_business_id AND transaction_id = p_transaction_id
    AND match_status <> 'REJECTED_MATCH'::public.match_record_status_enum;

  IF v_total <= 1 OR v_distinct_doc <= 1 THEN
    RETURN jsonb_build_object('detected', false, 'reason', 'SINGLE_DOCUMENT',
      'transaction_id', p_transaction_id, 'total_match_records', COALESCE(v_total,0));
  END IF;

  IF v_distinct_group = 1 THEN
    SELECT DISTINCT split_payment_group_id INTO v_only_group_id
    FROM public.match_records
    WHERE business_id = p_business_id AND transaction_id = p_transaction_id
      AND match_status <> 'REJECTED_MATCH'::public.match_record_status_enum
      AND split_payment_group_id IS NOT NULL;
    PERFORM 1 FROM public.match_records
    WHERE business_id = p_business_id AND transaction_id = p_transaction_id
      AND match_status <> 'REJECTED_MATCH'::public.match_record_status_enum
      AND split_payment_group_id IS NULL
    LIMIT 1;
    IF NOT FOUND AND v_only_group_id IS NOT NULL THEN
      SELECT status INTO v_group_status FROM public.split_payment_groups WHERE id = v_only_group_id;
      IF v_group_status IN ('PROPOSED','CONFIRMED') THEN
        RETURN jsonb_build_object(
          'detected', false, 'reason', 'EXCLUDED_BY_SPLIT_PAYMENT_GROUP',
          'transaction_id', p_transaction_id,
          'split_payment_group_id', v_only_group_id, 'group_status', v_group_status
        );
      END IF;
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'detected', true, 'transaction_id', p_transaction_id,
    'document_ids', to_jsonb(v_doc_ids),
    'match_record_ids', to_jsonb(v_mr_ids),
    'total_match_records', v_total
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.user_reject_match(p_match_record_id uuid, p_actor_user_id uuid, p_rejection_reason text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid;
  v_transaction_id uuid; v_document_id uuid;
  v_current_status public.match_record_status_enum; v_rejection_id uuid;
BEGIN
  IF p_rejection_reason IS NULL OR length(trim(p_rejection_reason)) = 0 THEN
    RAISE EXCEPTION 'REJECTION_REASON_REQUIRED' USING errcode='check_violation';
  END IF;
  SELECT organization_id, business_id, transaction_id, document_id, match_status
    INTO v_organization_id, v_business_id, v_transaction_id, v_document_id, v_current_status
  FROM public.match_records WHERE id = p_match_record_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','MATCH_RECORD_NOT_FOUND','match_record_id',p_match_record_id);
  END IF;
  UPDATE public.match_records
    SET match_status = 'REJECTED_MATCH'::public.match_record_status_enum,
        user_confirmation_status = 'REJECTED', updated_at = clock_timestamp()
  WHERE id = p_match_record_id;
  INSERT INTO public.match_rejection_memory (
    organization_id, business_id, transaction_id, document_id,
    rejected_by, rejected_at, rejection_reason, original_match_record_id
  ) VALUES (
    v_organization_id, v_business_id, v_transaction_id, v_document_id,
    p_actor_user_id, clock_timestamp(), p_rejection_reason, p_match_record_id
  )
  ON CONFLICT (business_id, transaction_id, document_id) DO NOTHING
  RETURNING id INTO v_rejection_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='MATCHING_USER_REJECTED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object('match_status', v_current_status),
    p_after_state:=jsonb_build_object(
      'match_status','REJECTED_MATCH', 'transaction_id', v_transaction_id,
      'document_id', v_document_id, 'rejection_memory_id', v_rejection_id,
      'reason', p_rejection_reason
    ),
    p_reason:=p_rejection_reason, p_request_context:=p_context
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_REJECTION_RECORDED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_match_record_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'rejection_memory_id', v_rejection_id,
      'transaction_id', v_transaction_id,
      'document_id', v_document_id,
      'original_match_record_id', p_match_record_id,
      'rejected_by', p_actor_user_id
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','REJECTED','match_record_id',p_match_record_id,
    'rejection_memory_id',v_rejection_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.override_match_rejection_privileged(p_rejection_memory_id uuid, p_actor_user_id uuid, p_business_id uuid, p_reason text, p_step_up_token_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid;
  v_transaction_id uuid; v_document_id uuid;
  v_orig_match_record_id uuid;
  v_action_id uuid := public.gen_uuid_v7();
  v_consumed boolean; v_token_reason text;
BEGIN
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'OVERRIDE_REASON_REQUIRED' USING errcode='check_violation';
  END IF;
  IF p_step_up_token_id IS NULL THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','STEP_UP_REQUIRED',
      'rejection_memory_id', p_rejection_memory_id
    );
  END IF;
  SELECT consumed, reason INTO v_consumed, v_token_reason
  FROM public.consume_step_up_token(
    p_step_up_token_id, p_business_id,
    'b10p06.override_match_rejection', v_action_id
  );
  IF NOT COALESCE(v_consumed, false) THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','STEP_UP_TOKEN_NOT_CONSUMED',
      'token_reason', v_token_reason,
      'rejection_memory_id', p_rejection_memory_id
    );
  END IF;

  SELECT organization_id, transaction_id, document_id, original_match_record_id
    INTO v_organization_id, v_transaction_id, v_document_id, v_orig_match_record_id
  FROM public.match_rejection_memory
  WHERE id = p_rejection_memory_id AND business_id = p_business_id
  FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'decision','REJECTED','reason','REJECTION_NOT_FOUND',
      'rejection_memory_id', p_rejection_memory_id
    );
  END IF;

  DELETE FROM public.match_rejection_memory WHERE id = p_rejection_memory_id;

  IF v_orig_match_record_id IS NOT NULL THEN
    UPDATE public.match_records
      SET match_status = 'POSSIBLE_MATCH'::public.match_record_status_enum,
          user_confirmation_status = NULL,
          requires_user_confirmation = true, updated_at = clock_timestamp()
    WHERE id = v_orig_match_record_id;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='MATCHING_REJECTION_OVERRIDDEN_PRIVILEGED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=v_orig_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=p_business_id,
    p_before_state:=jsonb_build_object(
      'rejection_memory_id', p_rejection_memory_id,
      'original_match_record_status', 'REJECTED_MATCH'
    ),
    p_after_state:=jsonb_build_object(
      'rejection_memory_id', p_rejection_memory_id,
      'original_match_record_id', v_orig_match_record_id,
      'transaction_id', v_transaction_id, 'document_id', v_document_id,
      'reason', p_reason,
      'note', 'rejection_memory_deleted; original_match_record_status=POSSIBLE_MATCH'
    ),
    p_reason:=p_reason, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','OVERRIDDEN',
    'rejection_memory_id', p_rejection_memory_id,
    'original_match_record_id', v_orig_match_record_id,
    'transaction_id', v_transaction_id, 'document_id', v_document_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.build_match_reason_fallback(p_match_level match_level_enum, p_decision_factors text[])
 RETURNS text
 LANGUAGE sql
 IMMUTABLE PARALLEL SAFE
AS $function$
  SELECT
    CASE p_match_level
      WHEN 'EXACT'           THEN 'Exact match. '
      WHEN 'STRONG_PROBABLE' THEN 'Strong probable match. '
      WHEN 'WEAK_POSSIBLE'   THEN 'Possible match. '
    END
    || 'Decision factors: '
    || CASE
         WHEN p_decision_factors IS NULL OR array_length(p_decision_factors, 1) IS NULL
         THEN 'none recorded'
         ELSE array_to_string(p_decision_factors, ', ')
       END
    || '. Plain-language summary unavailable; structured signals only.';
$function$
;

CREATE OR REPLACE FUNCTION public.classify_vat_treatment(p_organization_id uuid, p_business_id uuid, p_draft_ledger_entry_id uuid, p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_existing_treatment public.vat_treatment_enum;
  v_existing_review boolean;
  v_manual_override_by uuid;
  v_parent_txn_id uuid;
  v_debit_code text;
  v_credit_code text;
  v_biz_country char(2);
  v_biz_vat_registered boolean;
  v_direction public.transaction_direction_enum;
  v_txn_type public.transaction_type_enum;
  v_counterparty_country char(2);
  v_counterparty_vat text;
  v_txn_tag text;
  v_category text;
  v_treatment public.vat_treatment_enum;
  v_rule_id text;
  v_review boolean := false;
  v_reason text;
  v_tag_branch text;
  v_signals jsonb;
  v_tag_mismatch boolean := false;
BEGIN
  -- Read counterparty_country/vat from draft_ledger_entries (Phase 04 populated them)
  SELECT vat_treatment, requires_accountant_review, manual_override_by, parent_transaction_id,
         debit_account_code, credit_account_code, counterparty_country, counterparty_vat_number
    INTO v_existing_treatment, v_existing_review, v_manual_override_by, v_parent_txn_id,
         v_debit_code, v_credit_code, v_counterparty_country, v_counterparty_vat
    FROM public.draft_ledger_entries WHERE id = p_draft_ledger_entry_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'DRAFT_LEDGER_ENTRY_NOT_FOUND' USING errcode='check_violation';
  END IF;

  IF v_manual_override_by IS NOT NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_VAT_TREATMENT_HONORED_MANUAL_OVERRIDE',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='vat_classifier',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('treatment', v_existing_treatment, 'rule_id','MANUAL_OVERRIDE'),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object(
      'treatment', v_existing_treatment,
      'decided_by_rule_id', 'MANUAL_OVERRIDE',
      'supporting_signals', jsonb_build_object('manual_override_by', v_manual_override_by),
      'requires_accountant_review', v_existing_review,
      'accountant_review_reason', NULL);
  END IF;

  SELECT country_code, vat_registered INTO v_biz_country, v_biz_vat_registered
    FROM public.business_entities WHERE id = p_business_id;

  IF v_parent_txn_id IS NOT NULL THEN
    SELECT direction, transaction_type, user_tag
      INTO v_direction, v_txn_type, v_txn_tag
      FROM public.transactions WHERE id = v_parent_txn_id;
  END IF;

  SELECT category INTO v_category FROM public.chart_of_accounts
    WHERE business_id = p_business_id
      AND code = COALESCE(
        CASE WHEN v_direction = 'IN' THEN v_credit_code ELSE v_debit_code END,
        v_debit_code, v_credit_code);

  v_tag_branch := public.infer_service_or_goods(v_txn_tag);

  IF v_biz_vat_registered IS NULL OR v_biz_vat_registered = false THEN
    IF v_direction = 'IN' THEN
      v_treatment := 'OUTSIDE_SCOPE'; v_rule_id := 'PRE-2-IN';
    ELSE
      v_treatment := 'NO_VAT'; v_rule_id := 'PRE-2-OUT';
    END IF;
  ELSIF v_counterparty_country IS NULL THEN
    v_treatment := 'UNKNOWN'; v_rule_id := 'PRE-3-COUNTRY_UNRESOLVED';
    v_review := true; v_reason := 'Counterparty country could not be determined.';
  ELSIF v_direction = 'OUT' THEN
    IF public.is_outside_scope_transaction_type(v_txn_type) THEN
      v_treatment := 'OUTSIDE_SCOPE'; v_rule_id := 'OUT-7';
    ELSIF public.is_exempt_category(v_category) THEN
      v_treatment := 'EXEMPT'; v_rule_id := 'OUT-6';
    ELSIF v_biz_country = 'CY' AND v_counterparty_country = 'CY'
          AND v_counterparty_vat IS NOT NULL
          AND public.validate_vat_number_format(v_counterparty_country, v_counterparty_vat) THEN
      v_treatment := 'DOMESTIC_CYPRUS_VAT'; v_rule_id := 'OUT-1';
    ELSIF v_biz_country = 'CY' AND public.is_eu_member_state(v_counterparty_country)
          AND v_counterparty_country <> 'CY' AND v_counterparty_vat IS NOT NULL
          AND public.validate_vat_number_format(v_counterparty_country, v_counterparty_vat)
          AND v_tag_branch IN ('SERVICE','UNKNOWN') THEN
      v_treatment := 'EU_REVERSE_CHARGE'; v_rule_id := 'OUT-2';
    ELSIF v_biz_country = 'CY' AND public.is_eu_member_state(v_counterparty_country)
          AND v_counterparty_country <> 'CY' AND v_counterparty_vat IS NOT NULL
          AND v_tag_branch = 'GOODS' THEN
      v_treatment := 'IMPORT_OR_ACQUISITION'; v_rule_id := 'OUT-3';
    ELSIF NOT public.is_eu_member_state(v_counterparty_country) AND v_tag_branch = 'SERVICE' THEN
      v_treatment := 'NON_EU_SERVICE'; v_rule_id := 'OUT-4';
    ELSIF NOT public.is_eu_member_state(v_counterparty_country) AND v_tag_branch = 'GOODS' THEN
      v_treatment := 'IMPORT_OR_ACQUISITION'; v_rule_id := 'OUT-5';
    ELSIF v_biz_country = 'CY' AND v_counterparty_country = 'CY'
          AND (v_counterparty_vat IS NULL
               OR NOT public.validate_vat_number_format(v_counterparty_country, v_counterparty_vat)) THEN
      v_treatment := 'NO_VAT'; v_rule_id := 'OUT-8';
    ELSE
      v_treatment := 'UNKNOWN'; v_rule_id := 'OUT-residual';
      v_review := true; v_reason := 'VAT treatment rules could not select a definite branch.';
    END IF;
  ELSE
    IF public.is_outside_scope_transaction_type(v_txn_type) THEN
      v_treatment := 'OUTSIDE_SCOPE'; v_rule_id := 'IN-5';
    ELSIF public.is_exempt_category(v_category) THEN
      v_treatment := 'EXEMPT'; v_rule_id := 'IN-4';
    ELSIF v_biz_vat_registered AND v_counterparty_country = 'CY' THEN
      v_treatment := 'DOMESTIC_CYPRUS_VAT'; v_rule_id := 'IN-1';
    ELSIF public.is_eu_member_state(v_counterparty_country) AND v_counterparty_country <> 'CY'
          AND v_tag_branch IN ('SERVICE','UNKNOWN') THEN
      IF v_counterparty_vat IS NOT NULL
         AND public.validate_vat_number_format(v_counterparty_country, v_counterparty_vat) THEN
        v_treatment := 'EU_REVERSE_CHARGE'; v_rule_id := 'IN-2';
      ELSE
        v_treatment := 'UNKNOWN'; v_rule_id := 'IN-2-residual';
        v_review := true;
        v_reason := 'EU IN-side reverse-charge plausible but counterparty VAT number is missing or invalid; cannot fire IN-2 definitively.';
      END IF;
    ELSIF NOT public.is_eu_member_state(v_counterparty_country) AND v_tag_branch = 'SERVICE' THEN
      v_treatment := 'NON_EU_SERVICE'; v_rule_id := 'IN-3';
    ELSE
      v_treatment := 'UNKNOWN'; v_rule_id := 'IN-residual';
      v_review := true; v_reason := 'IN-side VAT treatment rules could not select a definite branch.';
    END IF;
  END IF;

  IF v_treatment IN ('NON_EU_SERVICE','EU_REVERSE_CHARGE') AND v_tag_branch = 'GOODS' THEN
    v_tag_mismatch := true; v_review := true;
    v_reason := COALESCE(v_reason || '; ', '') ||
                'Rule selected a service treatment (' || v_treatment::text ||
                ') but transaction tag indicates goods (' || v_txn_tag || ').';
  ELSIF v_treatment = 'IMPORT_OR_ACQUISITION' AND v_tag_branch = 'SERVICE' THEN
    v_tag_mismatch := true; v_review := true;
    v_reason := COALESCE(v_reason || '; ', '') ||
                'Rule selected IMPORT_OR_ACQUISITION but tag indicates service (' || v_txn_tag || ').';
  END IF;

  v_signals := jsonb_build_object(
    'biz_country', v_biz_country, 'biz_vat_registered', v_biz_vat_registered,
    'direction', v_direction, 'transaction_type', v_txn_type,
    'counterparty_country', v_counterparty_country,
    'counterparty_vat_present', v_counterparty_vat IS NOT NULL,
    'tag', v_txn_tag, 'tag_branch', v_tag_branch,
    'category', v_category);

  UPDATE public.draft_ledger_entries
    SET vat_treatment = v_treatment,
        requires_accountant_review = v_review,
        accountant_review_reason = v_reason,
        last_recomputed_at = clock_timestamp()
   WHERE id = p_draft_ledger_entry_id;

  IF v_tag_mismatch THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_VAT_TREATMENT_TAG_MISMATCH_DETECTED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='vat_classifier',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('treatment', v_treatment, 'tag', v_txn_tag, 'tag_branch', v_tag_branch),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  IF v_treatment = 'UNKNOWN' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_VAT_TREATMENT_UNKNOWN_RAISED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='vat_classifier',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('rule_id', v_rule_id, 'reason', v_reason, 'signals', v_signals),
      p_reason:=v_reason, p_request_context:=p_context);
  ELSE
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_VAT_TREATMENT_DECIDED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='vat_classifier',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'treatment', v_treatment, 'rule_id', v_rule_id,
        'requires_accountant_review', v_review,
        'signals', v_signals),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'treatment', v_treatment,
    'decided_by_rule_id', v_rule_id,
    'supporting_signals', v_signals,
    'requires_accountant_review', v_review,
    'accountant_review_reason', v_reason
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_invoice_lifecycle_transition_failed(p_organization_id uuid, p_business_id uuid, p_invoice_id uuid, p_transaction_id uuid, p_error_payload jsonb, p_workflow_run_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_review_issue_id uuid;
BEGIN
  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id, transaction_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action,
    card_payload_json
  ) VALUES (
    p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
    'income_matching.invoice_lifecycle_failed',
    'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
    'HIGH'::public.review_issue_severity_enum,
    'Invoice could not be updated after match',
    'The matching engine identified the right invoice but the lifecycle update failed. Please review the match and the invoice state.',
    'Reconcile the match and the invoice state manually',
    jsonb_build_object('invoice_id',p_invoice_id,'transaction_id',p_transaction_id,'error',p_error_payload)
  ) RETURNING id INTO v_review_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='INVOICE_LIFECYCLE_TRANSITION_FAILED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum,
    p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='income_matching_engine',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('invoice_id',p_invoice_id,'transaction_id',p_transaction_id,
                                      'error',p_error_payload,'review_issue_id',v_review_issue_id,
                                      'workflow_run_id',p_workflow_run_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN jsonb_build_object('decision','RECORDED_FAILURE','invoice_id',p_invoice_id,'transaction_id',p_transaction_id,'review_issue_id',v_review_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_income_match_outcome(p_txn_amount numeric, p_invoice_total numeric, p_tolerance numeric DEFAULT 0.01, p_min_percent numeric DEFAULT 0.05)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_invoice_total IS NULL OR p_invoice_total <= 0 THEN 'NO_MATCH'
    WHEN abs(abs(p_txn_amount) - p_invoice_total) <= p_tolerance THEN 'FULL_MATCH'
    WHEN abs(p_txn_amount) > p_invoice_total + p_tolerance THEN 'OVERPAYMENT'
    WHEN abs(p_txn_amount) >= p_invoice_total * p_min_percent THEN 'PARTIAL_PAYMENT'
    ELSE 'NO_MATCH'
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.regenerate_match_reason(p_match_record_id uuid, p_new_signal_breakdown jsonb, p_new_plain_language_reason text, p_tier text, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid;
  v_old_signals jsonb; v_old_reason text;
BEGIN
  IF p_tier NOT IN ('tier2','tier3','deterministic_fallback') THEN
    RAISE EXCEPTION 'TIER_INVALID' USING errcode='check_violation';
  END IF;
  IF p_new_signal_breakdown IS NULL OR jsonb_typeof(p_new_signal_breakdown) <> 'object' THEN
    RAISE EXCEPTION 'SIGNAL_BREAKDOWN_MUST_BE_OBJECT' USING errcode='check_violation';
  END IF;
  SELECT organization_id, business_id, match_signals, match_reason_plain_language
    INTO v_organization_id, v_business_id, v_old_signals, v_old_reason
  FROM public.match_records WHERE id = p_match_record_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','MATCH_RECORD_NOT_FOUND','match_record_id',p_match_record_id);
  END IF;

  UPDATE public.match_records
    SET match_signals = p_new_signal_breakdown,
        match_reason_plain_language = p_new_plain_language_reason,
        updated_at = clock_timestamp()
  WHERE id = p_match_record_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='MATCHING_REASON_REGENERATED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=jsonb_build_object(
      'old_signals', v_old_signals, 'old_plain_language_reason', v_old_reason
    ),
    p_after_state:=jsonb_build_object(
      'tier', p_tier,
      'new_plain_language_reason', p_new_plain_language_reason,
      'reason_length', length(COALESCE(p_new_plain_language_reason, ''))
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','REGENERATED', 'match_record_id', p_match_record_id,
    'old_plain_language_reason', v_old_reason,
    'new_plain_language_reason', p_new_plain_language_reason
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_match_reason(p_match_record_id uuid, p_signal_breakdown_full jsonb, p_plain_language_reason text, p_tier text, p_was_cache_hit boolean DEFAULT false, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_organization_id uuid; v_business_id uuid;
BEGIN
  IF p_tier NOT IN ('tier2','tier3','deterministic_fallback') THEN
    RAISE EXCEPTION 'TIER_INVALID' USING errcode='check_violation';
  END IF;
  IF p_signal_breakdown_full IS NULL OR jsonb_typeof(p_signal_breakdown_full) <> 'object' THEN
    RAISE EXCEPTION 'SIGNAL_BREAKDOWN_MUST_BE_OBJECT' USING errcode='check_violation';
  END IF;
  SELECT organization_id, business_id INTO v_organization_id, v_business_id
  FROM public.match_records WHERE id = p_match_record_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','MATCH_RECORD_NOT_FOUND','match_record_id',p_match_record_id);
  END IF;

  UPDATE public.match_records
    SET match_signals = p_signal_breakdown_full,
        match_reason_plain_language = p_plain_language_reason,
        updated_at = clock_timestamp()
  WHERE id = p_match_record_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_REASON_GENERATED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_match_record_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'tier', p_tier, 'was_cache_hit', p_was_cache_hit,
      'reason_length', length(COALESCE(p_plain_language_reason, ''))
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  IF p_was_cache_hit THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='MATCHING_REASON_CACHE_HIT',
      p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
      p_subject_id:=p_match_record_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='matching_engine',
      p_organization_id:=v_organization_id, p_business_id:=v_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('tier', p_tier),
      p_reason:=NULL, p_request_context:=p_context
    );
  END IF;

  RETURN jsonb_build_object(
    'decision','APPLIED', 'match_record_id', p_match_record_id,
    'tier', p_tier, 'was_cache_hit', p_was_cache_hit
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_match_reason_fallback(p_match_record_id uuid, p_failure_category text, p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_organization_id uuid; v_business_id uuid;
  v_transaction_id uuid; v_match_level public.match_level_enum;
  v_existing_signals jsonb;
  v_decision_factors text[];
  v_fallback_text text;
  v_review_issue_id uuid;
BEGIN
  IF p_failure_category NOT IN ('AI_TIMEOUT','AI_SCHEMA_VALIDATION_FAILED','AI_RATE_LIMITED','AI_OTHER') THEN
    RAISE EXCEPTION 'FAILURE_CATEGORY_INVALID' USING errcode='check_violation';
  END IF;
  SELECT organization_id, business_id, transaction_id, match_level, match_signals
    INTO v_organization_id, v_business_id, v_transaction_id, v_match_level, v_existing_signals
  FROM public.match_records WHERE id = p_match_record_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','MATCH_RECORD_NOT_FOUND','match_record_id',p_match_record_id);
  END IF;

  IF v_existing_signals ? 'decision_factors'
     AND jsonb_typeof(v_existing_signals->'decision_factors') = 'array' THEN
    SELECT array_agg(value::text) INTO v_decision_factors
    FROM jsonb_array_elements_text(v_existing_signals->'decision_factors');
  END IF;

  v_fallback_text := public.build_match_reason_fallback(v_match_level, v_decision_factors);

  UPDATE public.match_records
    SET match_reason_plain_language = v_fallback_text, updated_at = clock_timestamp()
  WHERE id = p_match_record_id;

  INSERT INTO public.review_issues (
    organization_id, business_id, workflow_run_id,
    transaction_id, match_record_id,
    issue_type, issue_group, severity,
    plain_language_title, plain_language_description, recommended_action,
    card_payload_json
  ) VALUES (
    v_organization_id, v_business_id, p_workflow_run_id,
    v_transaction_id, p_match_record_id,
    'matching.reason_fallback_applied',
    'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
    'LOW'::public.review_issue_severity_enum,
    'Plain-language match reason fallback used',
    'The AI explanation step failed; the match details are still recorded but the user-friendly summary is a placeholder. You can ask the system to re-try the explanation.',
    'Regenerate the plain-language reason',
    jsonb_build_object(
      'failure_category', p_failure_category,
      'match_record_id', p_match_record_id,
      'fallback_text', v_fallback_text
    )
  ) RETURNING id INTO v_review_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_REASON_FALLBACK_APPLIED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum,
    p_subject_id:=p_match_record_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'failure_category', p_failure_category,
      'fallback_text', v_fallback_text,
      'review_issue_id', v_review_issue_id,
      'decision_factors', to_jsonb(v_decision_factors)
    ),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','FALLBACK_APPLIED', 'match_record_id', p_match_record_id,
    'failure_category', p_failure_category,
    'review_issue_id', v_review_issue_id, 'fallback_text', v_fallback_text
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_matching_phase_started(p_workflow_run_id uuid, p_event_family text, p_phase_name text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_organization_id uuid; v_business_id uuid;
BEGIN
  IF p_event_family NOT IN ('MATCHING','INCOME_MATCHING') THEN
    RAISE EXCEPTION 'EVENT_FAMILY_INVALID' USING errcode='check_violation'; END IF;
  SELECT organization_id, business_id INTO v_organization_id, v_business_id
    FROM public.workflow_runs WHERE id=p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','WORKFLOW_RUN_NOT_FOUND','workflow_run_id',p_workflow_run_id); END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:=p_event_family||'_PHASE_STARTED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id:=p_workflow_run_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('phase_name',p_phase_name),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','RECORDED','workflow_run_id',p_workflow_run_id,
    'event_family',p_event_family,'phase_name',p_phase_name);
END;
$function$
;

