CREATE OR REPLACE FUNCTION public.record_matching_phase_holding(p_workflow_run_id uuid, p_event_family text, p_phase_name text, p_reason text, p_review_issue_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
