    FROM public.workflow_runs WHERE id=p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','WORKFLOW_RUN_NOT_FOUND','workflow_run_id',p_workflow_run_id); END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:=p_event_family||'_PHASE_HOLDING',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id:=p_workflow_run_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_engine',
    p_organization_id:=v_organization_id, p_business_id:=v_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('phase_name',p_phase_name,'review_issue_id',p_review_issue_id,'hold_reason',p_reason),
    p_reason:=p_reason, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','RECORDED','workflow_run_id',p_workflow_run_id,
    'event_family',p_event_family,'phase_name',p_phase_name);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.infer_service_or_goods(p_tag text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_tag IS NULL THEN 'UNKNOWN'
    WHEN lower(p_tag) IN ('it_software','saas_subscription','professional_fees','marketing','subscriptions','consulting','service','digital_service') THEN 'SERVICE'
    WHEN lower(p_tag) IN ('office_supplies','inventory','goods','physical_goods_import','hardware','equipment') THEN 'GOODS'
    ELSE 'UNKNOWN'
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_exempt_category(p_category text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT lower(coalesce(p_category,'')) IN ('financial_services','education','healthcare','insurance');
$function$
;

CREATE OR REPLACE FUNCTION public.is_outside_scope_transaction_type(p_type transaction_type_enum)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT p_type IN ('INTERNAL_TRANSFER','LOAN_OR_SHAREHOLDER_MOVEMENT','TAX_PAYMENT','BANK_FEE');
$function$
;

CREATE OR REPLACE FUNCTION public.compute_vat_and_evidence_flags(p_organization_id uuid, p_business_id uuid, p_draft_ledger_entry_id uuid, p_workflow_run_id uuid, p_document_extracted_vat_amount numeric DEFAULT NULL::numeric, p_matched_evidence_kind text DEFAULT NULL::text, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_vat_treatment public.vat_treatment_enum;
  v_entry_kind public.ledger_entry_kind_enum;
  v_parent_txn_id uuid;
  v_debit_acct text; v_credit_acct text;
  v_debit_amount numeric; v_credit_amount numeric;
  v_vies_relevant boolean;
  v_existing_review boolean;
  v_existing_reason text;
  v_direction public.transaction_direction_enum;
  v_txn_type public.transaction_type_enum;
  v_tag text;
  v_gross numeric;
  v_biz_vat_registered boolean;
  v_category text;
  v_rate numeric;
  v_vat_amount numeric := 0;
  v_input_flag boolean := false;
  v_input_amt numeric := 0;
  v_output_flag boolean := false;
  v_output_amt numeric := 0;
  v_vies_value_basis numeric := NULL;
  v_evidence record;
  v_review boolean := false;
  v_reason text;
  v_review_issue_id uuid;
  v_missing_evidence_id uuid;
  v_is_primary boolean;
BEGIN
  SELECT vat_treatment, entry_kind, parent_transaction_id,
         debit_account_code, credit_account_code, debit_amount, credit_amount,
         vies_relevant, requires_accountant_review, accountant_review_reason
    INTO v_vat_treatment, v_entry_kind, v_parent_txn_id,
         v_debit_acct, v_credit_acct, v_debit_amount, v_credit_amount,
         v_vies_relevant, v_existing_review, v_existing_reason
    FROM public.draft_ledger_entries WHERE id = p_draft_ledger_entry_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'DRAFT_LEDGER_ENTRY_NOT_FOUND' USING errcode='check_violation';
  END IF;

  IF v_parent_txn_id IS NOT NULL THEN
    SELECT direction, transaction_type, user_tag, abs(amount)
      INTO v_direction, v_txn_type, v_tag, v_gross
      FROM public.transactions WHERE id = v_parent_txn_id;
  ELSE
    v_gross := COALESCE(v_debit_amount, v_credit_amount, 0);
  END IF;

  SELECT vat_registered INTO v_biz_vat_registered FROM public.business_entities WHERE id = p_business_id;
  SELECT category INTO v_category FROM public.chart_of_accounts
    WHERE business_id = p_business_id AND code = COALESCE(v_debit_acct, v_credit_acct);
  v_is_primary := (v_entry_kind = 'PRIMARY');

  -- VAT amount derivation
  IF v_vat_treatment IN ('EXEMPT','NO_VAT','OUTSIDE_SCOPE','UNKNOWN') THEN
    v_vat_amount := 0;
  ELSE
    IF p_document_extracted_vat_amount IS NOT NULL THEN
      v_vat_amount := public.round_half_up(p_document_extracted_vat_amount, 2);
    ELSE
      v_rate := public.cyprus_vat_rate_for_category(v_category);
      v_vat_amount := public.round_half_up(v_gross * v_rate, 2);
    END IF;
  END IF;

  -- Flag + amount placement rules
  IF v_vat_treatment = 'DOMESTIC_CYPRUS_VAT' THEN
    IF v_direction = 'OUT' AND v_is_primary AND v_biz_vat_registered THEN
      v_input_flag := true; v_input_amt := v_vat_amount;
    ELSIF v_direction = 'IN' AND v_is_primary AND v_biz_vat_registered THEN
      v_output_flag := true; v_output_amt := v_vat_amount;
    END IF;
  ELSIF v_vat_treatment IN ('EU_REVERSE_CHARGE','IMPORT_OR_ACQUISITION') AND v_direction = 'OUT' THEN
    IF v_entry_kind = 'VAT_RECLAIM' THEN
      v_input_flag := true; v_input_amt := v_vat_amount;
    ELSIF v_entry_kind = 'VAT_OUTPUT' THEN
      v_output_flag := true; v_output_amt := v_vat_amount;
    END IF;
    -- PRIMARY rows of EU_REVERSE_CHARGE / IMPORT_OR_ACQUISITION carry zero (placement rule)
  END IF;

  -- vies_value_basis_eur (Stage 1: bookkeeping EUR = gross amount)
  IF v_vies_relevant THEN
    v_vies_value_basis := v_gross;
  END IF;

  -- Evidence flags
  SELECT * INTO v_evidence FROM public.infer_evidence_flags(v_txn_type, v_gross);

  -- Accountant-review triggers
  v_review := v_existing_review;
  v_reason := v_existing_reason;
  IF v_vat_treatment = 'UNKNOWN' THEN
    v_review := true;
    v_reason := COALESCE(v_reason || '; ', '') || 'VAT treatment could not be determined.';
  END IF;

  -- Persist
  UPDATE public.draft_ledger_entries
    SET input_vat_reclaimable_flag = v_input_flag,
        input_vat_reclaimable_amount = v_input_amt,
        output_vat_due_flag = v_output_flag,
        output_vat_due_amount = v_output_amt,
        vies_value_basis_eur = v_vies_value_basis,
        requires_invoice = v_evidence.requires_invoice,
        requires_receipt = v_evidence.requires_receipt,
        requires_contract = v_evidence.requires_contract,
        requires_accountant_review = v_review,
        accountant_review_reason = v_reason,
        last_recomputed_at = clock_timestamp()
   WHERE id = p_draft_ledger_entry_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_VAT_AMOUNTS_COMPUTED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum, p_subject_id:=p_draft_ledger_entry_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='vat_amounts_evidence', p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('treatment',v_vat_treatment,'input_flag',v_input_flag,'input_amount',v_input_amt,
                                       'output_flag',v_output_flag,'output_amount',v_output_amt,
                                       'vies_value_basis_eur',v_vies_value_basis,'entry_kind',v_entry_kind),
    p_reason:=NULL, p_request_context:=p_context);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_EVIDENCE_FLAGS_SET',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum, p_subject_id:=p_draft_ledger_entry_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='vat_amounts_evidence', p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('requires_invoice',v_evidence.requires_invoice,
                                       'requires_receipt',v_evidence.requires_receipt,
                                       'requires_contract',v_evidence.requires_contract,
                                       'gross_amount',v_gross,'transaction_type',v_txn_type),
    p_reason:=NULL, p_request_context:=p_context);

  -- Review-flag → create review_issue
  IF v_review THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id, draft_ledger_entry_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action,
      card_payload_json
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, v_parent_txn_id, p_draft_ledger_entry_id,
      'ledger.requires_accountant_review',
      'POSSIBLE_TAX_VAT_ISSUE'::public.review_issue_group_enum,
      CASE WHEN v_vat_treatment = 'UNKNOWN' THEN 'HIGH'::public.review_issue_severity_enum
           ELSE 'MEDIUM'::public.review_issue_severity_enum END,
      'Ledger entry needs accountant review',
      'The VAT treatment or evidence requirements for this entry need accountant attention. Review the reason and confirm or correct.',
      'Review and confirm or correct the entry',
      jsonb_build_object('reason', v_reason, 'treatment', v_vat_treatment)
    ) RETURNING id INTO v_review_issue_id;

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_ACCOUNTANT_REVIEW_FLAGGED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum, p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='vat_amounts_evidence', p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('reason', v_reason, 'review_issue_id', v_review_issue_id),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  -- Evidence mismatch: requires_invoice=true + matched_evidence_kind not 'INVOICE'
  IF v_evidence.requires_invoice
     AND p_matched_evidence_kind IS NOT NULL
     AND upper(p_matched_evidence_kind) <> 'INVOICE' THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id, draft_ledger_entry_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action,
      card_payload_json
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, v_parent_txn_id, p_draft_ledger_entry_id,
      'ledger.missing_required_evidence',
      'MISSING_DOCUMENTS'::public.review_issue_group_enum,
      'HIGH'::public.review_issue_severity_enum,
      'Required invoice missing',
      'This entry requires an invoice but the matched evidence is a different document type. Upload or attach the correct invoice.',
      'Attach the required invoice',
      jsonb_build_object('required','INVOICE','matched',p_matched_evidence_kind)
    ) RETURNING id INTO v_missing_evidence_id;

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_MISSING_REQUIRED_EVIDENCE_RAISED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum, p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='vat_amounts_evidence', p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('required','INVOICE','matched',p_matched_evidence_kind,
                                         'review_issue_id', v_missing_evidence_id),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'input_vat_reclaimable_flag', v_input_flag,
    'input_vat_reclaimable_amount', v_input_amt,
    'output_vat_due_flag', v_output_flag,
    'output_vat_due_amount', v_output_amt,
    'vies_value_basis_eur', v_vies_value_basis,
    'requires_invoice', v_evidence.requires_invoice,
    'requires_receipt', v_evidence.requires_receipt,
    'requires_contract', v_evidence.requires_contract,
    'requires_accountant_review', v_review,
    'accountant_review_reason', v_reason,
    'review_issue_id', v_review_issue_id,
    'missing_evidence_review_issue_id', v_missing_evidence_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_matching_fixture(p_fixture_name text, p_side text, p_category text, p_description text, p_fixture_path text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_id uuid;
BEGIN
  INSERT INTO public.matching_fixtures
    (fixture_name, side, category, description, fixture_path, created_by)
  VALUES
    (p_fixture_name, p_side, p_category, p_description, p_fixture_path, p_actor_user_id)
  ON CONFLICT (fixture_name) DO NOTHING
  RETURNING id INTO v_id;
  IF v_id IS NULL THEN
    SELECT id INTO v_id FROM public.matching_fixtures WHERE fixture_name = p_fixture_name;
  END IF;
  RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_vat_treatment_manual_override(p_organization_id uuid, p_business_id uuid, p_draft_ledger_entry_id uuid, p_new_treatment vat_treatment_enum, p_reason text, p_actor_user_id uuid, p_workflow_run_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_old_treatment public.vat_treatment_enum;
BEGIN
  v_role := public._ledger_assert_owner_or_admin(p_actor_user_id, p_business_id);
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'REASON_REQUIRED' USING errcode='check_violation';
  END IF;

  SELECT vat_treatment INTO v_old_treatment
    FROM public.draft_ledger_entries WHERE id = p_draft_ledger_entry_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'DRAFT_LEDGER_ENTRY_NOT_FOUND' USING errcode='check_violation';
  END IF;

  UPDATE public.draft_ledger_entries
    SET vat_treatment = p_new_treatment,
        manual_override_by = p_actor_user_id,
        manual_override_reason = p_reason,
        manual_override_at = clock_timestamp(),
        last_recomputed_at = clock_timestamp()
   WHERE id = p_draft_ledger_entry_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='LEDGER_VAT_TREATMENT_MANUAL_OVERRIDE_APPLIED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
    p_subject_id:=p_draft_ledger_entry_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=jsonb_build_object('treatment', v_old_treatment),
    p_after_state:=jsonb_build_object('treatment', p_new_treatment, 'reason', p_reason,
                                       'workflow_run_id', p_workflow_run_id),
    p_reason:=p_reason, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','OVERRIDDEN','old_treatment',v_old_treatment,'new_treatment',p_new_treatment);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clear_vat_treatment_manual_override(p_organization_id uuid, p_business_id uuid, p_draft_ledger_entry_id uuid, p_actor_user_id uuid, p_workflow_run_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_was_overridden boolean;
BEGIN
  v_role := public._ledger_assert_owner_or_admin(p_actor_user_id, p_business_id);

  SELECT (manual_override_by IS NOT NULL) INTO v_was_overridden
    FROM public.draft_ledger_entries WHERE id = p_draft_ledger_entry_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'DRAFT_LEDGER_ENTRY_NOT_FOUND' USING errcode='check_violation';
  END IF;
  IF NOT v_was_overridden THEN
    RETURN jsonb_build_object('decision','NOOP','reason','not_overridden');
  END IF;

  UPDATE public.draft_ledger_entries
    SET manual_override_by = NULL,
        manual_override_reason = NULL,
        manual_override_at = NULL,
        last_recomputed_at = clock_timestamp()
   WHERE id = p_draft_ledger_entry_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='LEDGER_VAT_TREATMENT_MANUAL_OVERRIDE_CLEARED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
    p_subject_id:=p_draft_ledger_entry_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('cleared_by', p_actor_user_id, 'workflow_run_id', p_workflow_run_id),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','CLEARED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cyprus_vat_rate_for_category(p_category text)
 RETURNS numeric
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN lower(coalesce(p_category,'')) IN ('financial_services','education','healthcare','insurance') THEN 0
    WHEN lower(coalesce(p_category,'')) IN ('subscriptions','it_software') THEN 0.05
    ELSE 0.19
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.infer_evidence_flags(p_transaction_type transaction_type_enum, p_gross_amount numeric)
 RETURNS TABLE(requires_invoice boolean, requires_receipt boolean, requires_contract boolean)
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_transaction_type = 'OUT_EXPENSE'      AND p_gross_amount >= 15 THEN true
    WHEN p_transaction_type = 'IN_INCOME'                                 THEN true
    WHEN p_transaction_type = 'PAYROLL_OR_TEAM_PAYMENT'                  THEN true  -- contractor default; sub-doc per-business override
    ELSE false END AS requires_invoice,
  CASE
    WHEN p_transaction_type = 'OUT_EXPENSE' AND p_gross_amount < 15 THEN true
    ELSE false END AS requires_receipt,
  CASE
    WHEN p_transaction_type IN ('LOAN_OR_SHAREHOLDER_MOVEMENT','PAYROLL_OR_TEAM_PAYMENT') THEN true
    ELSE false END AS requires_contract;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_period_report_pdf_stub(p_business_id uuid, p_period_start date, p_period_end date, p_run_id uuid)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'extensions', 'pg_temp'
AS $function$
  -- Stage-1 stub: Block 16 owns the real generator. We emit a deterministic
  -- text payload derived from the canonical inputs so the hash is stable.
  SELECT '%PDF-1.4' || E'\n' ||
         'stub-period-report:' ||
         public._hash_text(p_run_id::text || '|' ||
                            p_period_start::text || '|' ||
                            p_period_end::text || '|' ||
                            p_business_id::text);
$function$
;

CREATE OR REPLACE FUNCTION public.record_matching_fixture_run_started(p_fixture_id uuid, p_triggered_by text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run_id uuid;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM public.matching_fixtures WHERE id = p_fixture_id) THEN
    RAISE EXCEPTION 'FIXTURE_NOT_FOUND' USING errcode='check_violation';
  END IF;

  INSERT INTO public.matching_fixture_runs (fixture_id, triggered_by)
  VALUES (p_fixture_id, p_triggered_by)
  RETURNING id INTO v_run_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_FIXTURE_RAN',
    p_subject_type:='MATCHING_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=p_fixture_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_fixture_runner',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('run_id', v_run_id, 'triggered_by', p_triggered_by),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN v_run_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_matching_fixture_run_passed(p_run_id uuid, p_actual_results_hash text, p_expected_results_hash text, p_duration_ms integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_fixture_id uuid;
BEGIN
  IF p_duration_ms IS NULL OR p_duration_ms < 0 THEN
    RAISE EXCEPTION 'DURATION_MUST_BE_NONNEG' USING errcode='check_violation';
  END IF;

  UPDATE public.matching_fixture_runs
    SET status='PASSED',
        actual_results_hash=p_actual_results_hash,
        expected_results_hash=p_expected_results_hash,
        duration_ms=p_duration_ms,
        run_completed_at=clock_timestamp()
  WHERE id = p_run_id
  RETURNING fixture_id INTO v_fixture_id;

  IF v_fixture_id IS NULL THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_FIXTURE_PASSED',
    p_subject_type:='MATCHING_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=v_fixture_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_fixture_runner',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('run_id', p_run_id, 'duration_ms', p_duration_ms,
                                       'actual_hash', p_actual_results_hash,
                                       'expected_hash', p_expected_results_hash),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object('decision','RECORDED','run_id',p_run_id,'fixture_id',v_fixture_id,'status','PASSED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_matching_fixture_run_failed(p_run_id uuid, p_actual_results_hash text, p_expected_results_hash text, p_diff_summary jsonb, p_duration_ms integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_fixture_id    uuid;
  v_fixture_name  text;
  v_triggered_by  text;
BEGIN
  IF p_duration_ms IS NULL OR p_duration_ms < 0 THEN
    RAISE EXCEPTION 'DURATION_MUST_BE_NONNEG' USING errcode='check_violation';
  END IF;
  IF p_diff_summary IS NULL OR jsonb_typeof(p_diff_summary) <> 'object' THEN
    RAISE EXCEPTION 'DIFF_SUMMARY_MUST_BE_OBJECT' USING errcode='check_violation';
  END IF;

  UPDATE public.matching_fixture_runs
    SET status='FAILED',
        actual_results_hash=p_actual_results_hash,
        expected_results_hash=p_expected_results_hash,
        diff_summary=p_diff_summary,
        duration_ms=p_duration_ms,
        run_completed_at=clock_timestamp()
  WHERE id = p_run_id
  RETURNING fixture_id, triggered_by INTO v_fixture_id, v_triggered_by;

  IF v_fixture_id IS NULL THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;

  SELECT fixture_name INTO v_fixture_name FROM public.matching_fixtures WHERE id = v_fixture_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='MATCHING_FIXTURE_FAILED',
    p_subject_type:='MATCHING_FIXTURE'::audit.subject_type_enum,
    p_subject_id:=v_fixture_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='matching_fixture_runner',
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('run_id', p_run_id, 'duration_ms', p_duration_ms,
                                       'fixture_name', v_fixture_name,
                                       'triggered_by', v_triggered_by,
                                       'diff_summary', p_diff_summary,
                                       'actual_hash', p_actual_results_hash,
                                       'expected_hash', p_expected_results_hash),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object('decision','RECORDED','run_id',p_run_id,'fixture_id',v_fixture_id,
                            'fixture_name',v_fixture_name,'status','FAILED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.coam_block_when_version_frozen()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE v_frozen_at timestamptz;
BEGIN
  SELECT frozen_at INTO v_frozen_at
    FROM public.chart_of_accounts_mapping_versions
   WHERE id = COALESCE(NEW.mapping_version_id, OLD.mapping_version_id);
  IF v_frozen_at IS NOT NULL THEN
    RAISE EXCEPTION 'MAPPING_VERSION_FROZEN' USING errcode='check_violation';
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._chart_assert_owner_or_admin(p_actor_user_id uuid, p_business_id uuid)
 RETURNS user_role
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_role public.user_role;
BEGIN
  SELECT role INTO v_role FROM public.business_user_roles
   WHERE user_id=p_actor_user_id AND business_id=p_business_id AND status='ACTIVE'
   LIMIT 1;
  IF v_role IS NULL OR v_role NOT IN ('OWNER','ADMIN') THEN
    RAISE EXCEPTION 'INSUFFICIENT_PRIVILEGE' USING errcode='42501';
  END IF;
  RETURN v_role;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.load_default_chart_for_business(p_organization_id uuid, p_business_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_catalog_version constant text := 'cyprus_default_chart_v1';
  v_existing_n      int;
  v_version_id      uuid;
  v_account_id      uuid;
  v_mapping_id      uuid;
  v_accounts_n      int := 0;
  v_mappings_n      int := 0;
  v_acct            record;
  v_map             record;
BEGIN
  SELECT count(*) INTO v_existing_n FROM public.chart_of_accounts WHERE business_id = p_business_id;
  IF v_existing_n > 0 THEN
    RETURN jsonb_build_object('decision','NOOP','reason','already_seeded','business_id',p_business_id,
                              'existing_account_count',v_existing_n);
  END IF;

  v_version_id := public.gen_uuid_v7();
  INSERT INTO public.chart_of_accounts_mapping_versions
    (id, organization_id, business_id, version_number, effective_from, created_by)
  VALUES (v_version_id, p_organization_id, p_business_id, 1, clock_timestamp(), p_actor_user_id);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='CHART_MAPPING_VERSION_CREATED',
    p_subject_type:='CHART_MAPPING_VERSION'::audit.subject_type_enum,
    p_subject_id:=v_version_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='chart_seed_loader',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('version_number',1,'catalog_version',v_catalog_version,
                                       'initiating_user_id',p_actor_user_id),
    p_reason:=NULL, p_request_context:=p_context
  );

  FOR v_acct IN
    SELECT * FROM (VALUES
      ('1000','Bank Accounts','ASSET',NULL::text,NULL::text,'NA'),
      ('1100','Trade Debtors','ASSET',NULL,'TRADE_DEBTORS','NA'),
      ('1110','Other Debtors','ASSET',NULL,'OTHER_DEBTORS','NA'),
      ('1200','VAT Receivable','ASSET',NULL,'VAT_RECEIVABLE','NA'),
      ('1300','Prepaid Expenses','ASSET',NULL,'PREPAID','NA'),
      ('1500','Fixed Assets','ASSET',NULL,'FIXED_ASSETS','NA'),
      ('2000','Trade Creditors','LIABILITY',NULL,'TRADE_CREDITORS','NA'),
      ('2010','Other Creditors','LIABILITY',NULL,'OTHER_CREDITORS','NA'),
      ('2100','VAT Payable','LIABILITY',NULL,'VAT_PAYABLE','NA'),
      ('2200','Accrued Expenses','LIABILITY',NULL,'ACCRUALS','NA'),
      ('2500','Director''s Loan Account','LIABILITY',NULL,'DIRECTORS_LOAN','NA'),
      ('2510','Shareholder Loan Account','LIABILITY',NULL,'SHAREHOLDER_LOAN','NA'),
      ('3000','Shareholder Capital','EQUITY',NULL,'SHAREHOLDER_CAPITAL','NA'),
      ('3100','Retained Earnings','EQUITY',NULL,'RETAINED_EARNINGS','NA'),
      ('3200','Current Year Earnings','EQUITY',NULL,'CURRENT_YEAR','NA'),
      ('4000','Sales — Cyprus','REVENUE',NULL,'SALES_CYPRUS','NA'),
      ('4100','Sales — EU','REVENUE',NULL,'SALES_EU','NA'),
      ('4200','Sales — Non-EU','REVENUE',NULL,'SALES_NON_EU','NA'),
      ('4500','Other Income','REVENUE',NULL,'OTHER_INCOME','NA'),
      ('4900','Refunds Received','REVENUE',NULL,'REFUNDS_IN','NA'),
      ('6010','Travel — deductible','EXPENSE',NULL,'TRAVEL','DEDUCTIBLE'),
      ('6019','Travel — non-deductible','EXPENSE','6010','TRAVEL','NON_DEDUCTIBLE'),
      ('6020','Meals & Entertainment — deductible','EXPENSE',NULL,'MEALS','DEDUCTIBLE'),
      ('6029','Meals & Entertainment — non-deductible','EXPENSE','6020','MEALS','NON_DEDUCTIBLE'),
      ('6030','IT & Software','EXPENSE',NULL,'IT_SOFTWARE','DEDUCTIBLE'),
      ('6040','Professional Fees','EXPENSE',NULL,'PROFESSIONAL_FEES','DEDUCTIBLE'),
      ('6050','Office Supplies','EXPENSE',NULL,'OFFICE_SUPPLIES','DEDUCTIBLE'),
      ('6060','Rent','EXPENSE',NULL,'RENT','DEDUCTIBLE'),
      ('6070','Utilities','EXPENSE',NULL,'UTILITIES','DEDUCTIBLE'),
      ('6080','Bank Charges','EXPENSE',NULL,'BANK_CHARGES','DEDUCTIBLE'),
      ('6090','Marketing','EXPENSE',NULL,'MARKETING','DEDUCTIBLE'),
      ('6100','Subscriptions','EXPENSE',NULL,'SUBSCRIPTIONS','DEDUCTIBLE'),
      ('6110','Salaries & Wages','EXPENSE',NULL,'SALARIES','DEDUCTIBLE'),
      ('6120','Contractor Payments','EXPENSE',NULL,'CONTRACTORS','DEDUCTIBLE'),
      ('6130','Tax Payments','EXPENSE',NULL,'TAX_PAYMENTS','NON_DEDUCTIBLE'),
      ('6900','Other Expenses','EXPENSE',NULL,'OTHER_EXPENSES','DEDUCTIBLE'),
      ('8000','Input VAT','CONTRA',NULL,'INPUT_VAT','NA'),
      ('8010','Output VAT','CONTRA',NULL,'OUTPUT_VAT','NA'),
      ('8100','FX Gains','CONTRA',NULL,'FX_GAINS','NA'),
      ('8110','FX Losses','CONTRA',NULL,'FX_LOSSES','NA'),
      ('8200','Rounding','CONTRA',NULL,'ROUNDING','NA')
    ) AS t(code,name,account_class,parent_code,category,deductibility)
    ORDER BY code
  LOOP
    v_account_id := public.gen_uuid_v7();
    INSERT INTO public.chart_of_accounts
      (id, organization_id, business_id, code, name, account_class, parent_code, category, deductibility, is_seeded)
    VALUES (v_account_id, p_organization_id, p_business_id,
            v_acct.code, v_acct.name,
            v_acct.account_class::public.account_class_enum,
            v_acct.parent_code, v_acct.category,
            v_acct.deductibility::public.account_deductibility_enum, true);

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='CHART_ACCOUNT_CREATED',
      p_subject_type:='CHART_OF_ACCOUNTS_ENTRY'::audit.subject_type_enum,
      p_subject_id:=v_account_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='chart_seed_loader',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('code',v_acct.code,'name',v_acct.name,
                                         'account_class',v_acct.account_class,
                                         'deductibility',v_acct.deductibility,
                                         'catalog_version',v_catalog_version,
                                         'initiating_user_id',p_actor_user_id),
      p_reason:=NULL, p_request_context:=p_context
    );
    v_accounts_n := v_accounts_n + 1;
  END LOOP;

  FOR v_map IN
    SELECT * FROM (VALUES
      ('OUT_EXPENSE',NULL::text,NULL::text,'DEBIT', '6900',100),
      ('OUT_EXPENSE',NULL,NULL,'CREDIT','2000',100),
      ('IN_INCOME',NULL,NULL,'DEBIT', '1100',100),
      ('IN_INCOME',NULL,NULL,'CREDIT','4000',100),
      ('INTERNAL_TRANSFER',NULL,NULL,'DEBIT', '1000',100),
      ('INTERNAL_TRANSFER',NULL,NULL,'CREDIT','1000',100),
      ('FX_EXCHANGE',NULL,NULL,'DEBIT', '8100',100),
      ('FX_EXCHANGE',NULL,NULL,'CREDIT','8110',100),
      ('BANK_FEE',NULL,NULL,'DEBIT', '6080',100),
      ('BANK_FEE',NULL,NULL,'CREDIT','2010',100),
      ('REFUND_IN',NULL,NULL,'DEBIT', '1100',100),
      ('REFUND_IN',NULL,NULL,'CREDIT','4900',100),
      ('REFUND_OUT',NULL,NULL,'DEBIT', '4900',100),
      ('REFUND_OUT',NULL,NULL,'CREDIT','2000',100),
      ('CHARGEBACK',NULL,NULL,'DEBIT', '2010',100),
      ('CHARGEBACK',NULL,NULL,'CREDIT','1100',100),
      ('LOAN_OR_SHAREHOLDER_MOVEMENT',NULL,NULL,'DEBIT', '2500',100),
      ('LOAN_OR_SHAREHOLDER_MOVEMENT',NULL,NULL,'CREDIT','1000',100),
      ('PAYROLL_OR_TEAM_PAYMENT',NULL,NULL,'DEBIT', '6110',100),
      ('PAYROLL_OR_TEAM_PAYMENT',NULL,NULL,'CREDIT','2000',100),
      ('TAX_PAYMENT',NULL,NULL,'DEBIT', '6130',100),
      ('TAX_PAYMENT',NULL,NULL,'CREDIT','2010',100),
      ('UNKNOWN',NULL,NULL,'DEBIT', '6900',100),
      ('UNKNOWN',NULL,NULL,'CREDIT','2010',100),
      ('OUT_EXPENSE','saas_subscription',NULL,'DEBIT','6030',200),
      ('OUT_EXPENSE','client_dinner',NULL,'DEBIT','6029',200),
      ('IN_INCOME',NULL,'EU_REVERSE_CHARGE','CREDIT','4100',150)
    ) AS t(transaction_type,tag,vat_treatment,direction,account_code,priority)
  LOOP
    v_mapping_id := public.gen_uuid_v7();
    INSERT INTO public.chart_of_accounts_mappings
      (id, organization_id, business_id, mapping_version_id,
       transaction_type, tag, vat_treatment, entry_kind, direction, account_code, priority, is_seeded)
    VALUES (v_mapping_id, p_organization_id, p_business_id, v_version_id,
            v_map.transaction_type::public.transaction_type_enum,
            v_map.tag,
            v_map.vat_treatment::public.vat_treatment_enum,
            'PRIMARY'::public.ledger_entry_kind_enum,
            v_map.direction::public.ledger_entry_type_enum,
            v_map.account_code, v_map.priority, true);

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='CHART_MAPPING_RULE_CREATED',
      p_subject_type:='CHART_MAPPING_RULE'::audit.subject_type_enum,
      p_subject_id:=v_mapping_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='chart_seed_loader',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('transaction_type',v_map.transaction_type,'tag',v_map.tag,
                                         'vat_treatment',v_map.vat_treatment,'direction',v_map.direction,
                                         'account_code',v_map.account_code,'priority',v_map.priority,
                                         'catalog_version',v_catalog_version,
                                         'initiating_user_id',p_actor_user_id),
      p_reason:=NULL, p_request_context:=p_context
    );
    v_mappings_n := v_mappings_n + 1;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='CHART_DEFAULT_SEEDED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum,
    p_subject_id:=p_business_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='chart_seed_loader',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('catalog_version',v_catalog_version,
                                       'accounts_count',v_accounts_n,
                                       'mappings_count',v_mappings_n,
                                       'mapping_version_id',v_version_id,
                                       'initiating_user_id',p_actor_user_id),
    p_reason:=NULL, p_request_context:=p_context
  );

  RETURN jsonb_build_object(
    'decision','SEEDED',
    'business_id',p_business_id,
    'catalog_version',v_catalog_version,
    'accounts_count',v_accounts_n,
    'mappings_count',v_mappings_n,
    'mapping_version_id',v_version_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public._chart_get_or_create_active_version(p_organization_id uuid, p_business_id uuid, p_active_version_id uuid, p_actor_user_id uuid, p_actor_role user_role, p_context jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_version_id  uuid;
  v_prev_number int;
  v_frozen_at   timestamptz;
BEGIN
  IF p_active_version_id IS NOT NULL THEN
    SELECT frozen_at INTO v_frozen_at FROM public.chart_of_accounts_mapping_versions
      WHERE id=p_active_version_id AND business_id=p_business_id;
    IF v_frozen_at IS NULL AND FOUND THEN
      RETURN p_active_version_id;
    END IF;
  END IF;

  SELECT COALESCE(max(version_number),0) INTO v_prev_number
    FROM public.chart_of_accounts_mapping_versions WHERE business_id=p_business_id;
  v_version_id := public.gen_uuid_v7();
  INSERT INTO public.chart_of_accounts_mapping_versions
    (id, organization_id, business_id, version_number, effective_from, created_by)
  VALUES (v_version_id, p_organization_id, p_business_id, v_prev_number+1, clock_timestamp(), p_actor_user_id);

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='CHART_MAPPING_VERSION_CREATED',
    p_subject_type:='CHART_MAPPING_VERSION'::audit.subject_type_enum,
    p_subject_id:=v_version_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=p_actor_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('version_number',v_prev_number+1),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN v_version_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_add_account(p_organization_id uuid, p_business_id uuid, p_code text, p_name text, p_account_class text, p_parent_code text DEFAULT NULL::text, p_category text DEFAULT NULL::text, p_deductibility text DEFAULT 'NA'::text, p_actor_user_id uuid DEFAULT NULL::uuid, p_active_version_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_version_id uuid;
  v_account_id uuid;
BEGIN
  v_role := public._chart_assert_owner_or_admin(p_actor_user_id, p_business_id);
  v_version_id := public._chart_get_or_create_active_version(
    p_organization_id, p_business_id, p_active_version_id, p_actor_user_id, v_role, p_context);

  v_account_id := public.gen_uuid_v7();
  INSERT INTO public.chart_of_accounts
    (id, organization_id, business_id, code, name, account_class, parent_code, category, deductibility, is_seeded)
  VALUES (v_account_id, p_organization_id, p_business_id,
          p_code, p_name, p_account_class::public.account_class_enum,
          p_parent_code, p_category, p_deductibility::public.account_deductibility_enum, false);

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='CHART_ACCOUNT_CREATED',
    p_subject_type:='CHART_OF_ACCOUNTS_ENTRY'::audit.subject_type_enum,
    p_subject_id:=v_account_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('code',p_code,'name',p_name,
                                       'account_class',p_account_class,
                                       'deductibility',p_deductibility,
                                       'mapping_version_id',v_version_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN v_account_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_ledger_fixture(p_fixture_name text, p_category text, p_description text, p_fixture_path text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_id uuid;
BEGIN
  INSERT INTO public.ledger_fixtures (fixture_name, category, description, fixture_path, created_by)
  VALUES (p_fixture_name, p_category, p_description, p_fixture_path, p_actor_user_id)
  ON CONFLICT (fixture_name) DO NOTHING
  RETURNING id INTO v_id;
  IF v_id IS NULL THEN
    SELECT id INTO v_id FROM public.ledger_fixtures WHERE fixture_name = p_fixture_name;
  END IF;
  RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ledger_fixture_run_started(p_fixture_id uuid, p_triggered_by text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_run_id uuid;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM public.ledger_fixtures WHERE id = p_fixture_id) THEN
    RAISE EXCEPTION 'FIXTURE_NOT_FOUND' USING errcode='check_violation';
  END IF;
  INSERT INTO public.ledger_fixture_runs (fixture_id, triggered_by)
  VALUES (p_fixture_id, p_triggered_by) RETURNING id INTO v_run_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_FIXTURE_RAN',
    p_subject_type:='LEDGER_FIXTURE'::audit.subject_type_enum, p_subject_id:=p_fixture_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='ledger_fixture_runner', p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('run_id', v_run_id, 'triggered_by', p_triggered_by),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN v_run_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ledger_fixture_run_passed(p_run_id uuid, p_actual_results_hash text, p_expected_results_hash text, p_duration_ms integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_fixture_id uuid;
BEGIN
  IF p_duration_ms IS NULL OR p_duration_ms < 0 THEN
    RAISE EXCEPTION 'DURATION_MUST_BE_NONNEG' USING errcode='check_violation';
  END IF;
  UPDATE public.ledger_fixture_runs
    SET status='PASSED', actual_results_hash=p_actual_results_hash, expected_results_hash=p_expected_results_hash,
        duration_ms=p_duration_ms, run_completed_at=clock_timestamp()
  WHERE id = p_run_id RETURNING fixture_id INTO v_fixture_id;
  IF v_fixture_id IS NULL THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_FIXTURE_PASSED',
    p_subject_type:='LEDGER_FIXTURE'::audit.subject_type_enum, p_subject_id:=v_fixture_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='ledger_fixture_runner', p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('run_id', p_run_id, 'duration_ms', p_duration_ms,
                                       'actual_hash', p_actual_results_hash, 'expected_hash', p_expected_results_hash),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','RECORDED','run_id',p_run_id,'fixture_id',v_fixture_id,'status','PASSED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_ledger_fixture_run_failed(p_run_id uuid, p_actual_results_hash text, p_expected_results_hash text, p_diff_summary jsonb, p_duration_ms integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_fixture_id uuid; v_fixture_name text; v_triggered_by text;
BEGIN
  IF p_duration_ms IS NULL OR p_duration_ms < 0 THEN
    RAISE EXCEPTION 'DURATION_MUST_BE_NONNEG' USING errcode='check_violation';
  END IF;
  IF p_diff_summary IS NULL OR jsonb_typeof(p_diff_summary) <> 'object' THEN
    RAISE EXCEPTION 'DIFF_SUMMARY_MUST_BE_OBJECT' USING errcode='check_violation';
  END IF;
  UPDATE public.ledger_fixture_runs
    SET status='FAILED', actual_results_hash=p_actual_results_hash, expected_results_hash=p_expected_results_hash,
        diff_summary=p_diff_summary, duration_ms=p_duration_ms, run_completed_at=clock_timestamp()
  WHERE id = p_run_id RETURNING fixture_id, triggered_by INTO v_fixture_id, v_triggered_by;
  IF v_fixture_id IS NULL THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','RUN_NOT_FOUND','run_id',p_run_id);
  END IF;
  SELECT fixture_name INTO v_fixture_name FROM public.ledger_fixtures WHERE id = v_fixture_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='LEDGER_FIXTURE_FAILED',
    p_subject_type:='LEDGER_FIXTURE'::audit.subject_type_enum, p_subject_id:=v_fixture_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='ledger_fixture_runner', p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('run_id', p_run_id, 'duration_ms', p_duration_ms,
                                       'fixture_name', v_fixture_name, 'triggered_by', v_triggered_by,
                                       'diff_summary', p_diff_summary,
                                       'actual_hash', p_actual_results_hash, 'expected_hash', p_expected_results_hash),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','RECORDED','run_id',p_run_id,'fixture_id',v_fixture_id,'fixture_name',v_fixture_name,'status','FAILED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_resolve_mapping_version(p_business_id uuid, p_period_start timestamp with time zone)
 RETURNS uuid
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT id FROM public.chart_of_accounts_mapping_versions
   WHERE business_id = p_business_id AND effective_from <= p_period_start
   ORDER BY effective_from DESC, version_number DESC
   LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_begin_batch(p_organization_id uuid, p_business_id uuid, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_role public.user_role;
BEGIN
  v_role := public._chart_assert_owner_or_admin(p_actor_user_id, p_business_id);
  RETURN public._chart_get_or_create_active_version(
    p_organization_id, p_business_id, NULL, p_actor_user_id, v_role, p_context);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_rename_account(p_organization_id uuid, p_business_id uuid, p_code text, p_new_name text, p_actor_user_id uuid, p_active_version_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_version_id uuid;
  v_account_id uuid;
  v_old_name text;
BEGIN
  v_role := public._chart_assert_owner_or_admin(p_actor_user_id, p_business_id);
  v_version_id := public._chart_get_or_create_active_version(
    p_organization_id, p_business_id, p_active_version_id, p_actor_user_id, v_role, p_context);

  SELECT id, name INTO v_account_id, v_old_name FROM public.chart_of_accounts
   WHERE business_id=p_business_id AND code=p_code FOR UPDATE;
  IF v_account_id IS NULL THEN
    RAISE EXCEPTION 'ACCOUNT_NOT_FOUND' USING errcode='check_violation';
  END IF;

  UPDATE public.chart_of_accounts SET name=p_new_name, updated_at=clock_timestamp()
    WHERE id=v_account_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='CHART_ACCOUNT_UPDATED',
    p_subject_type:='CHART_OF_ACCOUNTS_ENTRY'::audit.subject_type_enum,
    p_subject_id:=v_account_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=jsonb_build_object('name',v_old_name),
    p_after_state:=jsonb_build_object('name',p_new_name,'mapping_version_id',v_version_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN v_account_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_disable_account(p_organization_id uuid, p_business_id uuid, p_code text, p_actor_user_id uuid, p_active_version_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_version_id uuid;
  v_account_id uuid;
BEGIN
  v_role := public._chart_assert_owner_or_admin(p_actor_user_id, p_business_id);
  v_version_id := public._chart_get_or_create_active_version(
    p_organization_id, p_business_id, p_active_version_id, p_actor_user_id, v_role, p_context);

  SELECT id INTO v_account_id FROM public.chart_of_accounts
   WHERE business_id=p_business_id AND code=p_code FOR UPDATE;
  IF v_account_id IS NULL THEN
    RAISE EXCEPTION 'ACCOUNT_NOT_FOUND' USING errcode='check_violation';
  END IF;

  UPDATE public.chart_of_accounts SET disabled_at=clock_timestamp(), updated_at=clock_timestamp()
    WHERE id=v_account_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='CHART_ACCOUNT_DISABLED',
    p_subject_type:='CHART_OF_ACCOUNTS_ENTRY'::audit.subject_type_enum,
    p_subject_id:=v_account_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('code',p_code,'mapping_version_id',v_version_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN v_account_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_add_mapping_rule(p_organization_id uuid, p_business_id uuid, p_transaction_type text, p_tag text, p_vat_treatment text, p_entry_kind text, p_direction text, p_account_code text, p_priority integer, p_actor_user_id uuid, p_active_version_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_version_id uuid;
  v_mapping_id uuid;
  v_acct_disabled timestamptz;
BEGIN
  v_role := public._chart_assert_owner_or_admin(p_actor_user_id, p_business_id);

  -- Reject if target account is disabled
  SELECT disabled_at INTO v_acct_disabled FROM public.chart_of_accounts
   WHERE business_id=p_business_id AND code=p_account_code;
  IF v_acct_disabled IS NOT NULL THEN
    RAISE EXCEPTION 'ACCOUNT_DISABLED' USING errcode='check_violation';
  END IF;

  v_version_id := public._chart_get_or_create_active_version(
    p_organization_id, p_business_id, p_active_version_id, p_actor_user_id, v_role, p_context);

  v_mapping_id := public.gen_uuid_v7();
  INSERT INTO public.chart_of_accounts_mappings
    (id, organization_id, business_id, mapping_version_id,
     transaction_type, tag, vat_treatment, entry_kind, direction, account_code, priority, is_seeded)
  VALUES (v_mapping_id, p_organization_id, p_business_id, v_version_id,
          p_transaction_type::public.transaction_type_enum,
          p_tag,
          p_vat_treatment::public.vat_treatment_enum,
          COALESCE(p_entry_kind,'PRIMARY')::public.ledger_entry_kind_enum,
          p_direction::public.ledger_entry_type_enum,
          p_account_code, COALESCE(p_priority,100), false);

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='CHART_MAPPING_RULE_CREATED',
    p_subject_type:='CHART_MAPPING_RULE'::audit.subject_type_enum,
    p_subject_id:=v_mapping_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('transaction_type',p_transaction_type,'tag',p_tag,
                                       'vat_treatment',p_vat_treatment,'direction',p_direction,
                                       'account_code',p_account_code,'priority',p_priority,
                                       'mapping_version_id',v_version_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN v_mapping_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_disable_mapping_rule(p_organization_id uuid, p_business_id uuid, p_mapping_rule_id uuid, p_actor_user_id uuid, p_active_version_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_role public.user_role;
  v_version_id uuid;
BEGIN
  v_role := public._chart_assert_owner_or_admin(p_actor_user_id, p_business_id);
  v_version_id := public._chart_get_or_create_active_version(
    p_organization_id, p_business_id, p_active_version_id, p_actor_user_id, v_role, p_context);

  -- The frozen-version trigger on chart_of_accounts_mappings will block this
  -- UPDATE if the rule's version is frozen.
  UPDATE public.chart_of_accounts_mappings
    SET disabled_at=clock_timestamp(), updated_at=clock_timestamp()
   WHERE id=p_mapping_rule_id AND business_id=p_business_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'MAPPING_RULE_NOT_FOUND' USING errcode='check_violation';
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='CHART_MAPPING_RULE_DISABLED',
    p_subject_type:='CHART_MAPPING_RULE'::audit.subject_type_enum,
    p_subject_id:=p_mapping_rule_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=v_role, p_actor_session_id:=NULL,
    p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('mapping_rule_id',p_mapping_rule_id,'mapping_version_id',v_version_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN p_mapping_rule_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_freeze_version_for_period(p_organization_id uuid, p_business_id uuid, p_mapping_version_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_already timestamptz;
BEGIN
  SELECT frozen_at INTO v_already FROM public.chart_of_accounts_mapping_versions
   WHERE id=p_mapping_version_id AND business_id=p_business_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'MAPPING_VERSION_NOT_FOUND' USING errcode='check_violation';
  END IF;
  IF v_already IS NOT NULL THEN
    RETURN jsonb_build_object('decision','NOOP','reason','already_frozen',
                              'mapping_version_id',p_mapping_version_id,'frozen_at',v_already);
  END IF;

  UPDATE public.chart_of_accounts_mapping_versions
    SET frozen_at=clock_timestamp() WHERE id=p_mapping_version_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='CHART_MAPPING_VERSION_FROZEN',
    p_subject_type:='CHART_MAPPING_VERSION'::audit.subject_type_enum,
    p_subject_id:=p_mapping_version_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='block_15_finalizer',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('mapping_version_id',p_mapping_version_id,
                                       'initiating_user_id',p_actor_user_id),
    p_reason:=NULL, p_request_context:=p_context
  );
  RETURN jsonb_build_object('decision','FROZEN','mapping_version_id',p_mapping_version_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.canonicalize_vat_number(p_country character, p_raw text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_raw IS NULL OR length(trim(p_raw)) = 0 THEN NULL
    ELSE upper(regexp_replace(trim(p_raw), '[[:space:]\-]', '', 'g'))
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_eu_member_state(p_country character)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT p_country IN (
    'AT','BE','BG','CY','CZ','DE','DK','EE','ES','FI','FR','GR','HR','HU','IE',
    'IT','LT','LU','LV','MT','NL','PL','PT','RO','SE','SI','SK'
  );
$function$
;

CREATE OR REPLACE FUNCTION public.compute_reverse_charge_and_vies(p_organization_id uuid, p_business_id uuid, p_draft_ledger_entry_id uuid, p_workflow_run_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_vat_treatment public.vat_treatment_enum;
  v_counterparty_country char(2);
  v_counterparty_vat text;
  v_entry_period date;
  v_parent_txn_id uuid;
  v_debit_amount numeric;
  v_credit_amount numeric;
  v_direction public.transaction_direction_enum;
  v_biz_vat_registered boolean;
  v_reverse_charge boolean;
  v_vies boolean;
  v_vies_period text;
  v_vat_valid boolean;
  v_signals jsonb;
BEGIN
  SELECT vat_treatment, counterparty_country, counterparty_vat_number, entry_period,
         parent_transaction_id, debit_amount, credit_amount
    INTO v_vat_treatment, v_counterparty_country, v_counterparty_vat, v_entry_period,
         v_parent_txn_id, v_debit_amount, v_credit_amount
    FROM public.draft_ledger_entries WHERE id = p_draft_ledger_entry_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'DRAFT_LEDGER_ENTRY_NOT_FOUND' USING errcode='check_violation';
  END IF;

  IF v_parent_txn_id IS NOT NULL THEN
    SELECT direction INTO v_direction FROM public.transactions WHERE id = v_parent_txn_id;
  ELSE
    -- Adjustment entry without parent_transaction_id: derive direction from which side has the amount.
    -- An expense (debit_amount populated on the expense account) is OUT-side; a revenue (credit_amount
    -- populated on the revenue account) is IN-side. Heuristic — sub-doc finalises.
    v_direction := CASE WHEN v_debit_amount IS NOT NULL THEN 'OUT'::public.transaction_direction_enum
                        ELSE 'IN'::public.transaction_direction_enum END;
  END IF;

  SELECT vat_registered INTO v_biz_vat_registered FROM public.business_entities WHERE id = p_business_id;

  v_vat_valid := v_counterparty_vat IS NOT NULL
                AND public.validate_vat_number_format(v_counterparty_country, v_counterparty_vat);

  -- reverse_charge_relevant rule
  v_reverse_charge :=
    (v_vat_treatment IN ('EU_REVERSE_CHARGE','IMPORT_OR_ACQUISITION') AND v_direction = 'OUT')
    OR
    (v_vat_treatment = 'EU_REVERSE_CHARGE' AND v_direction = 'IN');

  -- vies_relevant rule
  v_vies := v_direction = 'IN'
            AND v_vat_treatment = 'EU_REVERSE_CHARGE'
            AND public.is_eu_member_state(v_counterparty_country)
            AND v_vat_valid
            AND v_biz_vat_registered = true;

  v_vies_period := CASE WHEN v_vies THEN to_char(v_entry_period, 'YYYY-MM') ELSE NULL END;

  -- Persist
  UPDATE public.draft_ledger_entries
    SET reverse_charge_relevant = v_reverse_charge,
        vies_relevant = v_vies,
        vies_period = v_vies_period,
        last_recomputed_at = clock_timestamp()
   WHERE id = p_draft_ledger_entry_id;

  v_signals := jsonb_build_object(
    'vat_treatment', v_vat_treatment, 'direction', v_direction,
    'counterparty_country', v_counterparty_country,
    'counterparty_vat_present', v_counterparty_vat IS NOT NULL,
    'counterparty_vat_format_valid', v_vat_valid,
    'business_vat_registered', v_biz_vat_registered);

  -- Audit: always emit FLAGGED + DECIDED
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='LEDGER_REVERSE_CHARGE_FLAGGED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
    p_subject_id:=p_draft_ledger_entry_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='reverse_charge_vies',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('reverse_charge_relevant', v_reverse_charge, 'signals', v_signals),
    p_reason:=NULL, p_request_context:=p_context);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='LEDGER_VIES_RELEVANCE_DECIDED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
    p_subject_id:=p_draft_ledger_entry_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='reverse_charge_vies',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('vies_relevant', v_vies, 'vies_period', v_vies_period, 'signals', v_signals),
    p_reason:=NULL, p_request_context:=p_context);

  -- Missing-VAT-on-potentially-VIES-eligible IN-side: emit dedicated audit
  IF v_direction = 'IN' AND v_vat_treatment = 'EU_REVERSE_CHARGE'
     AND public.is_eu_member_state(v_counterparty_country) AND v_biz_vat_registered = true
     AND NOT v_vat_valid THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_VIES_VAT_NUMBER_MISSING_RAISED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=p_draft_ledger_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='reverse_charge_vies',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'counterparty_country', v_counterparty_country,
        'counterparty_vat_raw', v_counterparty_vat,
        'reason', 'EU IN-side reverse-charge entry would be VIES-eligible but counterparty VAT number is missing or format-invalid'),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'reverse_charge_relevant', v_reverse_charge,
    'vies_relevant', v_vies,
    'vies_period', v_vies_period,
    'supporting_signals', v_signals
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.prepare_ledger_entries(p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_workflow_run_id uuid, p_match_record_id uuid DEFAULT NULL::uuid, p_input_vat_reclaimable boolean DEFAULT false, p_output_vat_due boolean DEFAULT false, p_vat_amount numeric DEFAULT NULL::numeric, p_entry_period date DEFAULT NULL::date, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_direction public.transaction_direction_enum;
  v_txn_type public.transaction_type_enum;
  v_user_tag text;
  v_amount numeric;
  v_currency text;
  v_txn_date date;
  v_biz_currency text := 'EUR';
  v_version_id uuid;
  v_entry_period date;
  v_deleted int;
  v_entry_id uuid;
  v_debit_acct text;
  v_credit_acct text;
  v_fallback_debit boolean;
  v_fallback_credit boolean;
  v_review_issue_id uuid;
  v_primary_count int := 0;
  v_derived_count int := 0;
  v_net_amount numeric;
  v_gross_amount numeric;
  v_reverse_charge boolean := false;
  v_entry_currency_original text;
  v_entry_amount_original numeric;
  v_res record;
BEGIN
  SELECT direction, transaction_type, user_tag, amount, currency, transaction_date
    INTO v_direction, v_txn_type, v_user_tag, v_amount, v_currency, v_txn_date
    FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'TRANSACTION_NOT_FOUND' USING errcode='check_violation';
  END IF;

  v_entry_period := COALESCE(p_entry_period, v_txn_date);
  v_version_id := public.chart_resolve_mapping_version(p_business_id, v_entry_period::timestamptz);
  IF v_version_id IS NULL THEN
    RAISE EXCEPTION 'NO_ACTIVE_MAPPING_VERSION_FOR_PERIOD' USING errcode='check_violation';
  END IF;

  -- Cross-currency annotation
  IF v_currency IS NOT NULL AND v_currency <> v_biz_currency THEN
    v_entry_currency_original := v_currency;
    v_entry_amount_original := abs(v_amount);
  END IF;
  v_gross_amount := abs(v_amount);

  -- UNKNOWN: no entries; emit HELD + HIGH review_issue
  IF v_txn_type = 'UNKNOWN' THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action,
      card_payload_json
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
      'ledger.held_pending_classification',
      'POSSIBLE_TAX_VAT_ISSUE'::public.review_issue_group_enum,
      'HIGH'::public.review_issue_severity_enum,
      'Transaction held pending classification',
      'This transaction has not been classified into one of the known types; ledger entries cannot be derived until it is reclassified.',
      'Reclassify the transaction',
      jsonb_build_object('transaction_id', p_transaction_id)
    ) RETURNING id INTO v_review_issue_id;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_HELD_PENDING_CLASSIFICATION',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('review_issue_id', v_review_issue_id),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','HELD','reason','UNKNOWN_TYPE',
      'entries_created',0,'primary_count',0,'derived_count',0,'review_issue_id',v_review_issue_id);
  END IF;

  -- Idempotent re-derive: delete prior entries for (txn, version)
  WITH del AS (
    DELETE FROM public.draft_ledger_entries
     WHERE parent_transaction_id = p_transaction_id
       AND chart_mapping_version_id = v_version_id
     RETURNING id)
  SELECT count(*) INTO v_deleted FROM del;
  IF v_deleted > 0 THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_DRAFT_ENTRY_RECOMPUTED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('replaced_entry_count', v_deleted, 'mapping_version_id', v_version_id),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  -- Resolve debit account for PRIMARY entry of this type
  v_debit_acct := NULL; v_credit_acct := NULL;
  v_fallback_debit := false; v_fallback_credit := false;
  FOR v_res IN SELECT * FROM public.chart_resolve_account_for_entry(
                       p_business_id, v_version_id, v_txn_type, v_user_tag, NULL,
                       'PRIMARY'::public.ledger_entry_kind_enum,
                       'DEBIT'::public.ledger_entry_type_enum) LOOP
    v_debit_acct := v_res.account_code; v_fallback_debit := v_res.fallback_used;
  END LOOP;
  FOR v_res IN SELECT * FROM public.chart_resolve_account_for_entry(
                       p_business_id, v_version_id, v_txn_type, v_user_tag, NULL,
                       'PRIMARY'::public.ledger_entry_kind_enum,
                       'CREDIT'::public.ledger_entry_type_enum) LOOP
    v_credit_acct := v_res.account_code; v_fallback_credit := v_res.fallback_used;
  END LOOP;

  IF v_debit_acct IS NULL OR v_credit_acct IS NULL THEN
    RAISE EXCEPTION 'MAPPING_RULE_NOT_FOUND' USING errcode='check_violation',
      DETAIL=format('txn_type=% tag=% debit=% credit=%', v_txn_type, v_user_tag, v_debit_acct, v_credit_acct);
  END IF;

  IF v_fallback_debit OR v_fallback_credit THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_MAPPING_RULE_FALLBACK_USED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('debit_fallback', v_fallback_debit, 'credit_fallback', v_fallback_credit,
                                         'debit_code', v_debit_acct, 'credit_code', v_credit_acct),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  -- VAT splitting: when reclaimable VAT, debit primary on expense for net amount,
  -- credit primary on bank for gross, VAT_RECLAIM debit Input VAT for vat_amount.
  IF p_vat_amount IS NOT NULL AND p_vat_amount > 0 AND p_input_vat_reclaimable AND v_direction='OUT' THEN
    v_net_amount := v_gross_amount - p_vat_amount;
  ELSE
    v_net_amount := v_gross_amount;
  END IF;

  -- Insert PRIMARY debit row
  INSERT INTO public.draft_ledger_entries (
    id, organization_id, business_id, parent_transaction_id, match_record_id,
    entry_kind, debit_account_code, debit_amount, currency, entry_period,
    chart_mapping_version_id, entry_currency_original, entry_amount_original)
  VALUES (public.gen_uuid_v7(), p_organization_id, p_business_id, p_transaction_id, p_match_record_id,
          'PRIMARY', v_debit_acct, v_net_amount, v_biz_currency, v_entry_period,
          v_version_id, v_entry_currency_original, v_entry_amount_original)
  RETURNING id INTO v_entry_id;
  v_primary_count := v_primary_count + 1;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='LEDGER_DRAFT_ENTRY_CREATED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
    p_subject_id:=v_entry_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='ledger_dispatcher',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('entry_kind','PRIMARY','direction','DEBIT','account_code',v_debit_acct,'amount',v_net_amount),
    p_reason:=NULL, p_request_context:=p_context);

  -- Insert PRIMARY credit row (gross)
  INSERT INTO public.draft_ledger_entries (
    id, organization_id, business_id, parent_transaction_id, match_record_id,
    entry_kind, credit_account_code, credit_amount, currency, entry_period,
    chart_mapping_version_id, entry_currency_original, entry_amount_original)
  VALUES (public.gen_uuid_v7(), p_organization_id, p_business_id, p_transaction_id, p_match_record_id,
          'PRIMARY', v_credit_acct, v_gross_amount, v_biz_currency, v_entry_period,
          v_version_id, v_entry_currency_original, v_entry_amount_original)
  RETURNING id INTO v_entry_id;
  v_primary_count := v_primary_count + 1;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='LEDGER_DRAFT_ENTRY_CREATED',
    p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
    p_subject_id:=v_entry_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='ledger_dispatcher',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('entry_kind','PRIMARY','direction','CREDIT','account_code',v_credit_acct,'amount',v_gross_amount),
    p_reason:=NULL, p_request_context:=p_context);

  -- VAT_RECLAIM derived (OUT-side with reclaimable VAT)
  IF v_direction='OUT' AND p_input_vat_reclaimable AND p_vat_amount IS NOT NULL AND p_vat_amount > 0 THEN
    INSERT INTO public.draft_ledger_entries (
      id, organization_id, business_id, parent_transaction_id, match_record_id,
      entry_kind, debit_account_code, debit_amount, currency, entry_period, chart_mapping_version_id)
    VALUES (public.gen_uuid_v7(), p_organization_id, p_business_id, p_transaction_id, p_match_record_id,
            'VAT_RECLAIM', '8000', p_vat_amount, v_biz_currency, v_entry_period, v_version_id)
    RETURNING id INTO v_entry_id;
    v_derived_count := v_derived_count + 1;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_DRAFT_ENTRY_CREATED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=v_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('entry_kind','VAT_RECLAIM','direction','DEBIT','account_code','8000','amount',p_vat_amount),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  -- Reverse-charge OUT-side: add paired VAT_RECLAIM + VAT_OUTPUT of equal vat_amount
  -- (per spec: when reverse_charge_relevant=true OUT-side)
  -- For Stage-1 we proxy reverse_charge via: txn_type=OUT_EXPENSE AND tag in reverse-charge-implying set OR caller-passed flag.
  -- Simpler: callers indicate by setting p_input_vat_reclaimable=true AND p_output_vat_due=true together (the dual-flag signature for OUT reverse charge).
  IF v_direction='OUT' AND p_output_vat_due AND p_vat_amount IS NOT NULL AND p_vat_amount > 0 THEN
    INSERT INTO public.draft_ledger_entries (
      id, organization_id, business_id, parent_transaction_id, match_record_id,
      entry_kind, credit_account_code, credit_amount, currency, entry_period, chart_mapping_version_id)
    VALUES (public.gen_uuid_v7(), p_organization_id, p_business_id, p_transaction_id, p_match_record_id,
            'VAT_OUTPUT', '8010', p_vat_amount, v_biz_currency, v_entry_period, v_version_id)
    RETURNING id INTO v_entry_id;
    v_derived_count := v_derived_count + 1;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_DRAFT_ENTRY_CREATED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=v_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('entry_kind','VAT_OUTPUT','direction','CREDIT','account_code','8010','amount',p_vat_amount),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  -- IN-side: VAT_OUTPUT derived when output_vat_due
  IF v_direction='IN' AND p_output_vat_due AND p_vat_amount IS NOT NULL AND p_vat_amount > 0 THEN
    INSERT INTO public.draft_ledger_entries (
      id, organization_id, business_id, parent_transaction_id, match_record_id,
      entry_kind, credit_account_code, credit_amount, currency, entry_period, chart_mapping_version_id)
    VALUES (public.gen_uuid_v7(), p_organization_id, p_business_id, p_transaction_id, p_match_record_id,
            'VAT_OUTPUT', '8010', p_vat_amount, v_biz_currency, v_entry_period, v_version_id)
    RETURNING id INTO v_entry_id;
    v_derived_count := v_derived_count + 1;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_DRAFT_ENTRY_CREATED',
      p_subject_type:='DRAFT_LEDGER_ENTRY'::audit.subject_type_enum,
      p_subject_id:=v_entry_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('entry_kind','VAT_OUTPUT','direction','CREDIT','account_code','8010','amount',p_vat_amount),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  -- Multi-line consolidation audit (placeholder: line_items_count=1 until B09 finalises)
  IF p_match_record_id IS NOT NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='LEDGER_MULTI_LINE_INVOICE_CONSOLIDATED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum,
      p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='ledger_dispatcher',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('line_items_count', 1, 'match_record_id', p_match_record_id,
                                         'note', 'Stage-1 placeholder; sub-doc finalises line-item extraction from documents.extracted_fields_json'),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'decision','PREPARED',
    'transaction_id', p_transaction_id,
    'mapping_version_id', v_version_id,
    'entries_created', v_primary_count + v_derived_count,
    'entries_replaced', v_deleted,
    'primary_count', v_primary_count,
    'derived_count', v_derived_count,
    'debit_account_code', v_debit_acct,
    'credit_account_code', v_credit_acct);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.chart_resolve_account_for_entry(p_business_id uuid, p_mapping_version_id uuid, p_transaction_type transaction_type_enum, p_tag text, p_vat_treatment vat_treatment_enum, p_entry_kind ledger_entry_kind_enum, p_direction ledger_entry_type_enum)
 RETURNS TABLE(account_code text, fallback_used boolean)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_code text;
  v_fallback boolean;
BEGIN
  -- Try the most specific match first: priority DESC; require direction + entry_kind to match;
  -- transaction_type/tag/vat_treatment may match either exactly or via NULL (wildcard) in the rule.
  SELECT m.account_code,
         (m.transaction_type IS NULL AND m.tag IS NULL AND m.vat_treatment IS NULL)
    INTO v_code, v_fallback
   FROM public.chart_of_accounts_mappings m
   WHERE m.business_id = p_business_id
     AND m.mapping_version_id = p_mapping_version_id
     AND m.direction = p_direction
     AND m.entry_kind = p_entry_kind
     AND m.disabled_at IS NULL
     AND (m.transaction_type IS NULL OR m.transaction_type = p_transaction_type)
     AND (m.tag IS NULL OR m.tag = p_tag)
     AND (m.vat_treatment IS NULL OR m.vat_treatment = p_vat_treatment)
   ORDER BY
     -- specificity: rules matching more keys outrank wildcard fallbacks at same priority
     (CASE WHEN m.transaction_type IS NOT NULL THEN 1 ELSE 0 END
      + CASE WHEN m.tag IS NOT NULL THEN 1 ELSE 0 END
      + CASE WHEN m.vat_treatment IS NOT NULL THEN 1 ELSE 0 END) DESC,
     m.priority DESC
   LIMIT 1;

  IF v_code IS NULL THEN
    RETURN; -- no row
  END IF;
  account_code := v_code;
  fallback_used := v_fallback;
  RETURN NEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._ledger_assert_owner_or_admin(p_actor_user_id uuid, p_business_id uuid)
 RETURNS user_role
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_role public.user_role;
BEGIN
  SELECT role INTO v_role FROM public.business_user_roles
   WHERE user_id = p_actor_user_id AND business_id = p_business_id AND status='ACTIVE'
   LIMIT 1;
  IF v_role IS NULL OR v_role NOT IN ('OWNER','ADMIN') THEN
    RAISE EXCEPTION 'INSUFFICIENT_PRIVILEGE' USING errcode='42501';
  END IF;
  RETURN v_role;
END;
$function$
;

