;

CREATE OR REPLACE FUNCTION public._insert_invoice_payment_allocation(p_invoice_id uuid, p_organization_id uuid, p_business_id uuid, p_transaction_id uuid, p_match_record_id uuid, p_amount numeric, p_kind invoice_payment_allocation_kind_enum, p_allocated_at timestamp with time zone, p_actor_user_id uuid, p_actor_system text, p_context jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_id uuid := gen_uuid_v7();
BEGIN
  INSERT INTO public.invoice_payment_allocations (
    id, organization_id, business_id, invoice_id, transaction_id, match_record_id,
    allocated_amount, allocation_kind, allocated_at, allocated_by, allocated_by_system
  ) VALUES (
    v_id, p_organization_id, p_business_id, p_invoice_id, p_transaction_id, p_match_record_id,
    p_amount, p_kind, p_allocated_at, p_actor_user_id, p_actor_system
  );
  PERFORM audit.emit_audit(
    p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
    p_action:='INVOICE_PAYMENT_ALLOCATION_CREATED',
    p_subject_type:='INVOICE_PAYMENT_ALLOCATION'::audit.subject_type_enum, p_subject_id:=v_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object('invoice_id', p_invoice_id, 'transaction_id', p_transaction_id,
                                       'amount', p_amount, 'kind', p_kind::text, 'allocation_id', v_id),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_paid(p_invoice_id uuid, p_transaction_id uuid, p_paid_amount numeric, p_paid_at timestamp with time zone, p_match_record_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'income_matcher'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv public.invoices%ROWTYPE;
  v_alloc_id uuid;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.invoice_type = 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'PAID','PRO_FORMA_NOT_PAYABLE', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_PAYABLE');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('PAYMENT_EXPECTED','PARTIALLY_PAID','SENT') THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'PAID','ILLEGAL_TRANSITION', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  v_alloc_id := public._insert_invoice_payment_allocation(
    p_invoice_id, v_inv.organization_id, v_inv.business_id,
    p_transaction_id, p_match_record_id, p_paid_amount,
    'FULL'::public.invoice_payment_allocation_kind_enum,
    COALESCE(p_paid_at, now()), p_actor_user_id, p_actor_system, p_context);
  UPDATE public.invoices
     SET lifecycle_status='PAID', lifecycle_status_changed_at=now(),
         lifecycle_status_changed_by=p_actor_user_id, updated_at=now()
   WHERE id = p_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
    p_action:='INVOICE_MARKED_PAID',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','PAID', 'allocation_id', v_alloc_id, 'paid_amount', p_paid_amount),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','PAID','allocation_id', v_alloc_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_partially_paid(p_invoice_id uuid, p_transaction_id uuid, p_partial_amount numeric, p_paid_at timestamp with time zone, p_match_record_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'income_matcher'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv public.invoices%ROWTYPE;
  v_alloc_id uuid;
  v_cumulative numeric(18,2);
  v_auto_promote boolean := false;
  v_tolerance numeric := 0.01;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.invoice_type = 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'PARTIALLY_PAID','PRO_FORMA_NOT_PAYABLE', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_PAYABLE');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('PAYMENT_EXPECTED','PARTIALLY_PAID','SENT') THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'PARTIALLY_PAID','ILLEGAL_TRANSITION', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  IF p_partial_amount IS NULL OR p_partial_amount <= 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVALID_AMOUNT');
  END IF;

  v_alloc_id := public._insert_invoice_payment_allocation(
    p_invoice_id, v_inv.organization_id, v_inv.business_id,
    p_transaction_id, p_match_record_id, p_partial_amount,
    'PARTIAL'::public.invoice_payment_allocation_kind_enum,
    COALESCE(p_paid_at, now()), p_actor_user_id, p_actor_system, p_context);

  SELECT COALESCE(SUM(allocated_amount), 0)::numeric(18,2) INTO v_cumulative
    FROM public.invoice_payment_allocations
   WHERE invoice_id = p_invoice_id
     AND allocation_kind NOT IN ('REFUND','OVERPAYMENT_SURPLUS');
  v_auto_promote := v_cumulative >= (v_inv.total_amount - v_tolerance);

  IF v_auto_promote THEN
    UPDATE public.invoices SET
      lifecycle_status='PAID', lifecycle_status_changed_at=now(),
      lifecycle_status_changed_by=p_actor_user_id, updated_at=now()
     WHERE id = p_invoice_id;
    PERFORM audit.emit_audit(
      p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
      p_action:='INVOICE_MARKED_PAID',
      p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
      p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
      p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text, 'cumulative_paid', v_cumulative - p_partial_amount),
      p_after_state :=jsonb_build_object('lifecycle_status','PAID', 'cumulative_paid', v_cumulative, 'auto_promoted_from_partial', true),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','PAID','allocation_id', v_alloc_id, 'cumulative_paid', v_cumulative, 'auto_promoted', true);
  ELSE
    UPDATE public.invoices SET
      lifecycle_status='PARTIALLY_PAID', lifecycle_status_changed_at=now(),
      lifecycle_status_changed_by=p_actor_user_id, updated_at=now()
     WHERE id = p_invoice_id;
    PERFORM audit.emit_audit(
      p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
      p_action:='INVOICE_MARKED_PARTIALLY_PAID',
      p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
      p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
      p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
      p_after_state :=jsonb_build_object('lifecycle_status','PARTIALLY_PAID', 'allocation_id', v_alloc_id, 'partial_amount', p_partial_amount, 'cumulative_paid', v_cumulative),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','PARTIALLY_PAID','allocation_id', v_alloc_id, 'cumulative_paid', v_cumulative);
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_overpaid(p_invoice_id uuid, p_transaction_id uuid, p_paid_amount numeric, p_paid_at timestamp with time zone, p_match_record_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'income_matcher'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv public.invoices%ROWTYPE;
  v_primary_id uuid;
  v_surplus_id uuid;
  v_surplus numeric(18,2);
  v_paid_at timestamptz := COALESCE(p_paid_at, now());
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.invoice_type = 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'OVERPAID','PRO_FORMA_NOT_PAYABLE', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_PAYABLE');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('PAYMENT_EXPECTED','SENT','PARTIALLY_PAID') THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'OVERPAID','ILLEGAL_TRANSITION', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  IF p_paid_amount IS NULL OR p_paid_amount <= v_inv.total_amount THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','NOT_AN_OVERPAYMENT','total_amount', v_inv.total_amount);
  END IF;
  v_surplus := (p_paid_amount - v_inv.total_amount)::numeric(18,2);

  v_primary_id := public._insert_invoice_payment_allocation(
    p_invoice_id, v_inv.organization_id, v_inv.business_id,
    p_transaction_id, p_match_record_id, v_inv.total_amount,
    'OVERPAYMENT_PRIMARY'::public.invoice_payment_allocation_kind_enum,
    v_paid_at, p_actor_user_id, p_actor_system, p_context);
  v_surplus_id := public._insert_invoice_payment_allocation(
    p_invoice_id, v_inv.organization_id, v_inv.business_id,
    p_transaction_id, p_match_record_id, v_surplus,
    'OVERPAYMENT_SURPLUS'::public.invoice_payment_allocation_kind_enum,
    v_paid_at, p_actor_user_id, p_actor_system, p_context);

  UPDATE public.invoices SET
    lifecycle_status='OVERPAID', lifecycle_status_changed_at=now(),
    lifecycle_status_changed_by=p_actor_user_id, updated_at=now()
   WHERE id = p_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
    p_action:='INVOICE_MARKED_OVERPAID',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','OVERPAID', 'paid_amount', p_paid_amount,
                                        'total_amount', v_inv.total_amount, 'surplus_amount', v_surplus,
                                        'primary_allocation_id', v_primary_id, 'surplus_allocation_id', v_surplus_id),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','OVERPAID',
    'primary_allocation_id', v_primary_id, 'surplus_allocation_id', v_surplus_id, 'surplus_amount', v_surplus);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_refunded(p_invoice_id uuid, p_refund_transaction_id uuid, p_refund_amount numeric, p_refunded_at timestamp with time zone, p_match_record_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'income_matcher'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_inv public.invoices%ROWTYPE; v_alloc_id uuid;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.invoice_type = 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'REFUNDED','PRO_FORMA_NOT_PAYABLE', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_PAYABLE');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('PAYMENT_EXPECTED','PARTIALLY_PAID','PAID','OVERPAID') THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'REFUNDED','ILLEGAL_TRANSITION', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  IF p_refund_amount IS NULL OR p_refund_amount <= 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVALID_AMOUNT');
  END IF;
  v_alloc_id := public._insert_invoice_payment_allocation(
    p_invoice_id, v_inv.organization_id, v_inv.business_id,
    p_refund_transaction_id, p_match_record_id, -p_refund_amount,
    'REFUND'::public.invoice_payment_allocation_kind_enum,
    COALESCE(p_refunded_at, now()), p_actor_user_id, p_actor_system, p_context);
  UPDATE public.invoices SET
    lifecycle_status='REFUNDED', lifecycle_status_changed_at=now(),
    lifecycle_status_changed_by=p_actor_user_id, updated_at=now()
   WHERE id = p_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
    p_action:='INVOICE_MARKED_REFUNDED',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','REFUNDED','refund_amount', p_refund_amount, 'allocation_id', v_alloc_id),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','REFUNDED','allocation_id', v_alloc_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_credited(p_invoice_id uuid, p_credit_note_id uuid, p_credited_at timestamp with time zone, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'credit_note_issuer'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_inv public.invoices%ROWTYPE;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.invoice_type = 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'CREDITED','PRO_FORMA_NOT_PAYABLE', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_PAYABLE');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('PAYMENT_EXPECTED','PARTIALLY_PAID','OVERPAID','SENT','PAID') THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'CREDITED','ILLEGAL_TRANSITION', p_actor_user_id, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  UPDATE public.invoices SET
    lifecycle_status='CREDITED', lifecycle_status_changed_at=now(),
    lifecycle_status_changed_by=p_actor_user_id, updated_at=now()
   WHERE id = p_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
    p_action:='INVOICE_MARKED_CREDITED',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','CREDITED','credit_note_id', p_credit_note_id, 'credited_at', COALESCE(p_credited_at, now())),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','CREDITED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_finalized(p_invoice_id uuid, p_finalized_in_run_id uuid, p_finalized_at timestamp with time zone, p_actor_system text DEFAULT 'finalization_pipeline'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_inv public.invoices%ROWTYPE;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.lifecycle_status = 'FINALIZED' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'FINALIZED','ALREADY_FINALIZED', NULL, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ALREADY_FINALIZED');
  END IF;
  IF v_inv.lifecycle_status = 'DRAFT' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'FINALIZED','ILLEGAL_TRANSITION', NULL, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status','DRAFT');
  END IF;
  UPDATE public.invoices SET
    lifecycle_status='FINALIZED', lifecycle_status_changed_at=now(),
    finalized_in_run_id = p_finalized_in_run_id, finalized_at = COALESCE(p_finalized_at, now()),
    updated_at=now()
   WHERE id = p_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='INVOICE_FINALIZED',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','FINALIZED','finalized_in_run_id', p_finalized_in_run_id),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','FINALIZED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_apply_action(p_actor_user_id uuid, p_token_id uuid, p_action_payload jsonb DEFAULT '{}'::jsonb, p_note text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_token         record;
  v_action        public.resolution_action_kind_enum;
  v_guard         jsonb;
  v_org           uuid;
  v_id            uuid;
  v_dispatch      jsonb;
  v_applied_ids   uuid[] := '{}';
  v_skipped       jsonb := '[]'::jsonb;
  v_failures      jsonb := '[]'::jsonb;
  v_requested     int;
  v_applied_count int := 0;
  v_skipped_count int := 0;
  v_failed_count  int := 0;
BEGIN
  v_guard := public._check_form_factor_guard('BULK_APPLY_ACTION', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  SELECT id, organization_id, business_id, actor_user_id, action_kind,
         affected_issue_ids, created_at, expires_at, consumed_at
    INTO v_token FROM public.bulk_preview_tokens WHERE id = p_token_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_NOT_FOUND'); END IF;
  IF v_token.actor_user_id <> p_actor_user_id THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_ACTOR_MISMATCH'); END IF;
  IF v_token.consumed_at IS NOT NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_BULK_CONFIRMATION_TOKEN_REPLAY_REJECTED',
      p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
      p_subject_id:=p_token_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_token.organization_id, p_business_id:=v_token.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('token_id', p_token_id, 'consumed_at', v_token.consumed_at),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_ALREADY_CONSUMED');
  END IF;
  IF v_token.expires_at <= clock_timestamp() THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_BULK_CONFIRMATION_TOKEN_EXPIRED',
      p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
      p_subject_id:=p_token_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_token.organization_id, p_business_id:=v_token.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('token_id', p_token_id, 'expires_at', v_token.expires_at),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_EXPIRED');
  END IF;

  v_action := v_token.action_kind::public.resolution_action_kind_enum;
  v_org    := v_token.organization_id;
  v_requested := cardinality(v_token.affected_issue_ids);
  UPDATE public.bulk_preview_tokens SET consumed_at = clock_timestamp() WHERE id = p_token_id;

  FOREACH v_id IN ARRAY v_token.affected_issue_ids LOOP
    BEGIN
      v_dispatch := public.apply_resolution_action(p_actor_user_id, v_id, v_action,
        COALESCE(p_action_payload, '{}'::jsonb), p_note, p_context);
      IF (v_dispatch->>'decision') = 'ALLOW' THEN
        v_applied_ids := v_applied_ids || v_id; v_applied_count := v_applied_count + 1;
      ELSE
        v_skipped := v_skipped || jsonb_build_object('issue_id', v_id, 'reason_code', v_dispatch->>'reason_code');
        v_skipped_count := v_skipped_count + 1;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_failures := v_failures || jsonb_build_object('issue_id', v_id, 'sqlstate', SQLSTATE, 'message', SQLERRM);
      v_failed_count := v_failed_count + 1;
    END;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_BULK_APPLIED',
    p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
    p_subject_id:=p_token_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_org, p_business_id:=v_token.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'token_id', p_token_id, 'action_kind', v_action::text,
      'requested', v_requested, 'applied', v_applied_count,
      'skipped', v_skipped_count, 'failed', v_failed_count),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW', 'token_id', p_token_id, 'action_kind', v_action::text,
    'requested', v_requested, 'applied', v_applied_count, 'applied_ids', to_jsonb(v_applied_ids),
    'skipped_count', v_skipped_count, 'skipped', v_skipped,
    'failed_count', v_failed_count, 'failures', v_failures);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_converted_to_tax_invoice(p_actor_user_id uuid, p_pro_forma_invoice_id uuid, p_tax_invoice_id uuid, p_converted_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv public.invoices%ROWTYPE;
  v_decision jsonb;
  v_when timestamptz := COALESCE(p_converted_at, now());
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_pro_forma_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id,'INVOICE_MANAGE','CONVERT_TO_TAX',
    jsonb_build_object('pro_forma_invoice_id', p_pro_forma_invoice_id, 'tax_invoice_id', p_tax_invoice_id),
    v_inv.business_id, v_inv.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF v_inv.invoice_type <> 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_pro_forma_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'CONVERTED_TO_TAX_INVOICE','NOT_PRO_FORMA', p_actor_user_id, NULL, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','NOT_PRO_FORMA');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('DRAFT','SENT') THEN
    PERFORM public._emit_invoice_transition_failed(p_pro_forma_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'CONVERTED_TO_TAX_INVOICE','ILLEGAL_TRANSITION', p_actor_user_id, NULL, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  UPDATE public.invoices SET
    lifecycle_status='CONVERTED_TO_TAX_INVOICE', lifecycle_status_changed_at=now(),
    lifecycle_status_changed_by=p_actor_user_id,
    converted_to_tax_invoice_id = p_tax_invoice_id,
    updated_at=now()
   WHERE id = p_pro_forma_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='INVOICE_PRO_FORMA_CONVERTED_TO_TAX',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_pro_forma_invoice_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','CONVERTED_TO_TAX_INVOICE',
                                        'converted_to_tax_invoice_id', p_tax_invoice_id,
                                        'converted_at', v_when),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','CONVERTED_TO_TAX_INVOICE','converted_to_tax_invoice_id', p_tax_invoice_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_vat_aware_text(p_vat_treatment vat_treatment_enum, p_language_code text, p_customer_vat_number text)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_lang text := COALESCE(p_language_code, 'en');
BEGIN
  IF v_lang <> 'en' THEN v_lang := 'en'; END IF;  -- Stage 1: only en
  CASE p_vat_treatment
    WHEN 'DOMESTIC_CYPRUS_VAT'   THEN RETURN jsonb_build_object('disclosure_text', NULL, 'requires_customer_vat_display', false);
    WHEN 'DOMESTIC_STANDARD'     THEN RETURN jsonb_build_object('disclosure_text', NULL, 'requires_customer_vat_display', false);
    WHEN 'DOMESTIC_REDUCED'      THEN RETURN jsonb_build_object('disclosure_text', NULL, 'requires_customer_vat_display', false);
    WHEN 'DOMESTIC_ZERO'         THEN RETURN jsonb_build_object('disclosure_text', 'Zero-rated supply.', 'requires_customer_vat_display', false);
    WHEN 'EU_REVERSE_CHARGE'     THEN RETURN jsonb_build_object(
      'disclosure_text', 'Reverse charge — Article 196 of Council Directive 2006/112/EC. The customer is liable for VAT.',
      'requires_customer_vat_display', true);
    WHEN 'NON_EU_SERVICE'        THEN RETURN jsonb_build_object(
      'disclosure_text', 'Outside the scope of Cyprus VAT — supply of services to a non-EU customer.',
      'requires_customer_vat_display', false);
    WHEN 'EXEMPT'                THEN RETURN jsonb_build_object(
      'disclosure_text', 'VAT exempt — [category reference].',
      'requires_customer_vat_display', false);
    WHEN 'NO_VAT'                THEN RETURN jsonb_build_object(
      'disclosure_text', 'No VAT charged.',
      'requires_customer_vat_display', false);
    WHEN 'OUTSIDE_SCOPE'         THEN RETURN jsonb_build_object(
      'disclosure_text', 'Outside the scope of Cyprus VAT.',
      'requires_customer_vat_display', false);
    -- IMPORT_OR_ACQUISITION + UNKNOWN are rejected upstream by the renderer
    ELSE RETURN jsonb_build_object('disclosure_text', NULL, 'requires_customer_vat_display', false);
  END CASE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._emit_invoice_pdf_render_rejected(p_invoice_id uuid, p_organization_id uuid, p_business_id uuid, p_action text, p_reason_code text, p_actor_user_id uuid, p_context jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  PERFORM audit.emit_audit(
    p_actor_kind      := CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
    p_action          := p_action,
    p_subject_type    := 'INVOICE'::audit.subject_type_enum,
    p_subject_id      := p_invoice_id,
    p_actor_user_id   := p_actor_user_id,
    p_actor_role      := NULL,
    p_actor_session_id:= NULL,
    p_actor_system    := CASE WHEN p_actor_user_id IS NULL THEN 'invoice_pdf_renderer' ELSE NULL END,
    p_organization_id := p_organization_id,
    p_business_id     := p_business_id,
    p_before_state    := NULL,
    p_after_state     := jsonb_build_object('reason_code', p_reason_code),
    p_reason          := p_reason_code,
    p_request_context := p_context
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_compute_pdf_render_payload(p_actor_user_id uuid, p_invoice_id uuid, p_render_kind invoice_render_kind_enum, p_language_code text, p_renderer_version text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv      public.invoices%ROWTYPE;
  v_client   public.clients%ROWTYPE;
  v_decision jsonb;
  v_lines    jsonb;
  v_line_count int;
  v_per_rate jsonb;
  v_header   jsonb;
  v_bill_to  jsonb;
  v_totals   jsonb;
  v_vat_text jsonb;
  v_payload  jsonb;
  v_hash     text;
  v_existing public.invoice_pdf_renders%ROWTYPE;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND');
  END IF;
  v_decision := public.can_perform(p_actor_user_id, 'INVOICE_MANAGE', 'RENDER_PDF',
    jsonb_build_object('invoice_id', p_invoice_id), v_inv.business_id, v_inv.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;

  -- DRAFT_PREVIEW requires DRAFT; FINAL requires non-DRAFT
  IF p_render_kind = 'DRAFT_PREVIEW' AND v_inv.lifecycle_status <> 'DRAFT' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','DRAFT_PREVIEW_REQUIRES_DRAFT');
  END IF;
  IF p_render_kind = 'FINAL' AND v_inv.lifecycle_status = 'DRAFT' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','FINAL_REQUIRES_NON_DRAFT');
  END IF;

  -- Line-count check (FINAL only — DRAFT_PREVIEW of empty invoice is allowed for UI)
  SELECT count(*) INTO v_line_count FROM public.invoice_lines WHERE invoice_id = p_invoice_id;
  IF p_render_kind = 'FINAL' AND v_line_count = 0 THEN
    PERFORM public._emit_invoice_pdf_render_rejected(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      'INVOICE_PDF_RENDER_REJECTED_NO_LINES','NO_LINES', p_actor_user_id, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','NO_LINES');
  END IF;

  -- VAT-treatment rejection (FINAL only)
  IF p_render_kind = 'FINAL' AND v_inv.vat_treatment_per_line = false
     AND v_inv.default_vat_treatment = 'UNKNOWN' THEN
    PERFORM public._emit_invoice_pdf_render_rejected(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      'INVOICE_PDF_RENDER_REJECTED_UNKNOWN_VAT_TREATMENT','UNKNOWN_VAT_TREATMENT', p_actor_user_id, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','UNKNOWN_VAT_TREATMENT');
  END IF;
  -- (IMPORT_OR_ACQUISITION already blocked at CHECK level — defensive double-check)
  IF v_inv.default_vat_treatment = 'IMPORT_OR_ACQUISITION' THEN
    PERFORM public._emit_invoice_pdf_render_rejected(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      'INVOICE_PDF_RENDER_REJECTED_INAPPLICABLE_VAT_TREATMENT','INAPPLICABLE_VAT_TREATMENT', p_actor_user_id, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','INAPPLICABLE_VAT_TREATMENT');
  END IF;
  -- Per-line: any line with UNKNOWN treatment under FINAL → reject
  IF p_render_kind = 'FINAL' AND v_inv.vat_treatment_per_line = true THEN
    PERFORM 1 FROM public.invoice_lines
     WHERE invoice_id = p_invoice_id AND vat_treatment = 'UNKNOWN';
    IF FOUND THEN
      PERFORM public._emit_invoice_pdf_render_rejected(p_invoice_id, v_inv.organization_id, v_inv.business_id,
        'INVOICE_PDF_RENDER_REJECTED_UNKNOWN_VAT_TREATMENT','UNKNOWN_VAT_TREATMENT_ON_LINE', p_actor_user_id, p_context);
      RETURN jsonb_build_object('decision','DENY','reason_code','UNKNOWN_VAT_TREATMENT_ON_LINE');
    END IF;
  END IF;

  -- Pull client for bill-to block
  SELECT * INTO v_client FROM public.clients WHERE id = v_inv.client_id;

  -- Assemble lines payload (ordered by line_number)
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'line_number', il.line_number,
    'description', il.description,
    'quantity',    il.quantity,
    'unit_price',  il.unit_price,
    'subtotal_amount', il.subtotal_amount,
    'vat_treatment', il.vat_treatment::text,
    'vat_rate_pct',  il.vat_rate_pct,
    'vat_amount',    il.vat_amount,
    'total_amount',  il.total_amount
  ) ORDER BY il.line_number), '[]'::jsonb) INTO v_lines
  FROM public.invoice_lines il WHERE il.invoice_id = p_invoice_id;

  -- Per-rate breakdown (only meaningful when vat_treatment_per_line)
  IF v_inv.vat_treatment_per_line THEN
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'vat_rate_pct', rate,
      'subtotal',     sub,
      'vat_amount',   vat
    ) ORDER BY rate), '[]'::jsonb)
    INTO v_per_rate
    FROM (
      SELECT COALESCE(vat_rate_pct, 0) AS rate,
             SUM(subtotal_amount)::numeric(18,2) AS sub,
             SUM(COALESCE(vat_amount,0))::numeric(18,2) AS vat
        FROM public.invoice_lines
       WHERE invoice_id = p_invoice_id
       GROUP BY COALESCE(vat_rate_pct, 0)
    ) g;
  ELSE
    v_per_rate := '[]'::jsonb;
  END IF;

  -- VAT-aware text (single block; per-line treatment list is in the lines)
  v_vat_text := public.invoice_vat_aware_text(
    COALESCE(v_inv.default_vat_treatment, 'UNKNOWN'::public.vat_treatment_enum),
    p_language_code,
    v_client.vat_number
  );

  -- Build the structured payload (deterministic key order via jsonb_build_object)
  v_header := jsonb_build_object(
    'business_id', v_inv.business_id,
    'business_display_name', (SELECT display_name FROM public.business_entities WHERE id = v_inv.business_id)
  );
  v_bill_to := jsonb_build_object(
    'client_id', v_client.id,
    'display_name', v_client.display_name,
    'legal_name', v_client.legal_name,
    'country', v_client.country,
    'vat_number', v_client.vat_number,
    'billing_address_line_1', v_client.billing_address_line_1,
    'billing_address_line_2', v_client.billing_address_line_2,
    'billing_city', v_client.billing_city,
    'billing_postal_code', v_client.billing_postal_code,
    'billing_country', v_client.billing_country,
    'billing_email', v_client.billing_email
  );
  v_totals := jsonb_build_object(
    'subtotal_amount', v_inv.subtotal_amount,
    'vat_amount', v_inv.vat_amount,
    'total_amount', v_inv.total_amount,
    'currency', v_inv.currency,
    'per_rate_breakdown', v_per_rate
  );

  v_payload := jsonb_build_object(
    'invoice_id', v_inv.id,
    'invoice_number', v_inv.invoice_number,
    'invoice_type', v_inv.invoice_type::text,
    'lifecycle_status', v_inv.lifecycle_status::text,
    'issue_date', v_inv.issue_date,
    'supply_date', v_inv.supply_date,
    'due_date', v_inv.due_date,
    'payment_terms_days', GREATEST(0, (v_inv.due_date - v_inv.issue_date)),
    'header', v_header,
    'bill_to', v_bill_to,
    'lines', v_lines,
    'totals', v_totals,
    'vat_aware_text', v_vat_text,
    'is_draft_watermark', p_render_kind = 'DRAFT_PREVIEW',
    'is_pro_forma_watermark', v_inv.invoice_type = 'PRO_FORMA',
    'pro_forma_footer_text', CASE WHEN v_inv.invoice_type = 'PRO_FORMA'
      THEN 'This document is a pro-forma invoice and does not constitute a tax invoice. A tax invoice will be issued upon payment.'
      ELSE NULL END,
    'language_code', COALESCE(p_language_code, 'en'),
    'renderer_version', p_renderer_version
  );

  v_hash := encode(sha256(v_payload::text::bytea), 'hex');

  -- Idempotency: check existing render registration (FINAL only)
  IF p_render_kind = 'FINAL' THEN
    SELECT * INTO v_existing
      FROM public.invoice_pdf_renders
     WHERE invoice_id = p_invoice_id
       AND render_kind = 'FINAL'
       AND render_hash = v_hash
       AND language_code = COALESCE(p_language_code, 'en')
       AND renderer_version = p_renderer_version
     LIMIT 1;
    IF FOUND THEN
      RETURN jsonb_build_object(
        'decision','ALLOW',
        'idempotent_hit', true,
        'render_hash', v_hash,
        'pdf_storage_object_id', v_existing.pdf_storage_object_id,
        'rendered_at', v_existing.rendered_at,
        'payload', v_payload
      );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'idempotent_hit', false,
    'render_hash', v_hash,
    'payload', v_payload
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_register_rendered_pdf(p_actor_user_id uuid, p_invoice_id uuid, p_render_kind invoice_render_kind_enum, p_render_hash text, p_language_code text, p_renderer_version text, p_pdf_storage_object_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_inv      public.invoices%ROWTYPE;
  v_decision jsonb;
  v_render_id uuid := gen_uuid_v7();
  v_existing public.invoice_pdf_renders%ROWTYPE;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id, 'INVOICE_MANAGE', 'REGISTER_PDF',
    jsonb_build_object('invoice_id', p_invoice_id), v_inv.business_id, v_inv.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF p_render_hash IS NULL OR p_render_hash !~ '^[0-9a-f]{64}$' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVALID_RENDER_HASH');
  END IF;
  IF p_render_kind = 'FINAL' AND p_pdf_storage_object_id IS NULL THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','FINAL_REQUIRES_STORAGE_OBJECT_ID');
  END IF;

  -- Idempotent on unique conflict
  BEGIN
    INSERT INTO public.invoice_pdf_renders (
      id, organization_id, business_id, invoice_id,
      render_kind, render_hash, language_code, renderer_version,
      pdf_storage_object_id, rendered_by, rendered_by_system
    ) VALUES (
      v_render_id, v_inv.organization_id, v_inv.business_id, p_invoice_id,
      p_render_kind, p_render_hash, COALESCE(p_language_code,'en'), p_renderer_version,
      p_pdf_storage_object_id, p_actor_user_id, NULL
    );
  EXCEPTION WHEN unique_violation THEN
    SELECT * INTO v_existing FROM public.invoice_pdf_renders
     WHERE invoice_id = p_invoice_id
       AND render_kind = p_render_kind
       AND render_hash = p_render_hash
       AND language_code = COALESCE(p_language_code,'en')
       AND renderer_version = p_renderer_version
     LIMIT 1;
    RETURN jsonb_build_object(
      'decision','ALLOW',
      'idempotent', true,
      'render_id', v_existing.id,
      'pdf_storage_object_id', v_existing.pdf_storage_object_id
    );
  END;

  -- FINAL: stamp invoices.pdf_storage_object_id + pdf_rendered_at
  IF p_render_kind = 'FINAL' THEN
    UPDATE public.invoices SET
      pdf_storage_object_id = p_pdf_storage_object_id,
      pdf_rendered_at = now(),
      updated_at = now()
     WHERE id = p_invoice_id;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='INVOICE_PDF_RENDERED',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'render_id', v_render_id,
      'render_kind', p_render_kind::text,
      'language_code', COALESCE(p_language_code,'en'),
      'renderer_version', p_renderer_version,
      'pdf_storage_object_id', p_pdf_storage_object_id,
      'render_hash', p_render_hash
    ),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'idempotent', false,
    'render_id', v_render_id,
    'pdf_storage_object_id', p_pdf_storage_object_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.credit_note_compute_pdf_render_payload(p_actor_user_id uuid, p_credit_note_id uuid, p_language_code text, p_renderer_version text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_cn       public.credit_notes%ROWTYPE;
  v_inv      public.invoices%ROWTYPE;
  v_client   public.clients%ROWTYPE;
  v_decision jsonb;
  v_payload  jsonb;
  v_hash     text;
  v_existing public.credit_note_pdf_renders%ROWTYPE;
BEGIN
  SELECT * INTO v_cn FROM public.credit_notes WHERE id = p_credit_note_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','CREDIT_NOTE_NOT_FOUND');
  END IF;
  SELECT * INTO v_inv FROM public.invoices WHERE id = v_cn.against_invoice_id;
  v_decision := public.can_perform(p_actor_user_id, 'INVOICE_MANAGE', 'RENDER_CN_PDF',
    jsonb_build_object('credit_note_id', p_credit_note_id), v_cn.business_id, v_cn.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  SELECT * INTO v_client FROM public.clients WHERE id = v_inv.client_id;

  v_payload := jsonb_build_object(
    'credit_note_id', v_cn.id,
    'credit_note_number', v_cn.credit_note_number,
    'against_invoice_id', v_cn.against_invoice_id,
    'against_invoice_number', v_inv.invoice_number,
    'issue_date', v_cn.issue_date,
    'currency', v_cn.currency,
    'amount', v_cn.amount,
    'reason', v_cn.reason,
    'bill_to', jsonb_build_object(
      'client_id', v_client.id,
      'display_name', v_client.display_name,
      'legal_name', v_client.legal_name,
      'country', v_client.country,
      'vat_number', v_client.vat_number
    ),
    'language_code', COALESCE(p_language_code,'en'),
    'renderer_version', p_renderer_version
  );
  v_hash := encode(sha256(v_payload::text::bytea), 'hex');

  SELECT * INTO v_existing FROM public.credit_note_pdf_renders
   WHERE credit_note_id = p_credit_note_id
     AND render_hash = v_hash
     AND language_code = COALESCE(p_language_code,'en')
     AND renderer_version = p_renderer_version
   LIMIT 1;
  IF FOUND THEN
    RETURN jsonb_build_object(
      'decision','ALLOW','idempotent_hit', true,
      'render_hash', v_hash,
      'pdf_storage_object_id', v_existing.pdf_storage_object_id,
      'payload', v_payload
    );
  END IF;
  RETURN jsonb_build_object(
    'decision','ALLOW','idempotent_hit', false,
    'render_hash', v_hash,
    'payload', v_payload
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.credit_note_register_rendered_pdf(p_actor_user_id uuid, p_credit_note_id uuid, p_render_hash text, p_language_code text, p_renderer_version text, p_pdf_storage_object_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_cn       public.credit_notes%ROWTYPE;
  v_decision jsonb;
  v_render_id uuid := gen_uuid_v7();
  v_existing public.credit_note_pdf_renders%ROWTYPE;
BEGIN
  SELECT * INTO v_cn FROM public.credit_notes WHERE id = p_credit_note_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','CREDIT_NOTE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id, 'INVOICE_MANAGE', 'REGISTER_CN_PDF',
    jsonb_build_object('credit_note_id', p_credit_note_id), v_cn.business_id, v_cn.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF p_render_hash IS NULL OR p_render_hash !~ '^[0-9a-f]{64}$' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVALID_RENDER_HASH');
  END IF;
  IF p_pdf_storage_object_id IS NULL THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','STORAGE_OBJECT_ID_REQUIRED');
  END IF;

  BEGIN
    INSERT INTO public.credit_note_pdf_renders (
      id, organization_id, business_id, credit_note_id,
      render_hash, language_code, renderer_version,
      pdf_storage_object_id, rendered_by, rendered_by_system
    ) VALUES (
      v_render_id, v_cn.organization_id, v_cn.business_id, p_credit_note_id,
      p_render_hash, COALESCE(p_language_code,'en'), p_renderer_version,
      p_pdf_storage_object_id, p_actor_user_id, NULL
    );
  EXCEPTION WHEN unique_violation THEN
    SELECT * INTO v_existing FROM public.credit_note_pdf_renders
     WHERE credit_note_id = p_credit_note_id
       AND render_hash = p_render_hash
       AND language_code = COALESCE(p_language_code,'en')
       AND renderer_version = p_renderer_version
     LIMIT 1;
    RETURN jsonb_build_object('decision','ALLOW','idempotent', true,
      'render_id', v_existing.id, 'pdf_storage_object_id', v_existing.pdf_storage_object_id);
  END;

  UPDATE public.credit_notes SET
    pdf_storage_object_id = p_pdf_storage_object_id,
    pdf_rendered_at = now()
   WHERE id = p_credit_note_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='CREDIT_NOTE_PDF_RENDERED',
    p_subject_type:='CREDIT_NOTE'::audit.subject_type_enum, p_subject_id:=p_credit_note_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_cn.organization_id, p_business_id:=v_cn.business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'render_id', v_render_id,
      'language_code', COALESCE(p_language_code,'en'),
      'renderer_version', p_renderer_version,
      'pdf_storage_object_id', p_pdf_storage_object_id,
      'render_hash', p_render_hash
    ),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW','idempotent', false,
    'render_id', v_render_id, 'pdf_storage_object_id', p_pdf_storage_object_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_default_pro_forma_expires_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.invoice_type = 'PRO_FORMA' AND NEW.pro_forma_expires_at IS NULL THEN
    NEW.pro_forma_expires_at := (NEW.issue_date + 30)::timestamptz;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_template_compute_next_due_date(p_cadence_kind recurring_cadence_kind_enum, p_base_date date, p_anchor_day integer)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_target_month_start date;
  v_days_in_month      int;
  v_effective_day      int;
  v_months_ahead       int;
BEGIN
  IF p_cadence_kind = 'WEEKLY' THEN
    RETURN p_base_date + 7;
  ELSIF p_cadence_kind = 'BIWEEKLY' THEN
    RETURN p_base_date + 14;
  END IF;

  v_months_ahead := CASE p_cadence_kind
    WHEN 'MONTHLY'     THEN 1
    WHEN 'QUARTERLY'   THEN 3
    WHEN 'SEMI_ANNUAL' THEN 6
    WHEN 'ANNUAL'      THEN 12
    ELSE 1
  END;

  v_target_month_start := (date_trunc('month', p_base_date) + (v_months_ahead || ' months')::interval)::date;
  v_days_in_month := EXTRACT(DAY FROM (v_target_month_start + interval '1 month - 1 day'))::int;
  v_effective_day := LEAST(p_anchor_day, v_days_in_month);

  RETURN make_date(
    EXTRACT(YEAR  FROM v_target_month_start)::int,
    EXTRACT(MONTH FROM v_target_month_start)::int,
    v_effective_day
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_template_create(p_actor_user_id uuid, p_organization_id uuid, p_business_id uuid, p_client_id uuid, p_template_name text, p_invoice_type invoice_type_enum, p_currency text, p_vat_treatment_per_line boolean, p_default_vat_treatment vat_treatment_enum, p_payment_terms_days integer, p_lines_payload jsonb, p_cadence_kind recurring_cadence_kind_enum, p_cadence_anchor_day_of_period integer, p_start_date date, p_end_date date, p_auto_send boolean, p_auto_send_target_email text, p_pro_forma_expiry_days integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_decision  jsonb;
  v_id        uuid := gen_uuid_v7();
BEGIN
  v_decision := public.can_perform(p_actor_user_id,'INVOICE_MANAGE','CREATE_RECURRING_TEMPLATE',
    jsonb_build_object('client_id', p_client_id), p_business_id, p_organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF p_lines_payload IS NULL OR jsonb_typeof(p_lines_payload) <> 'array' OR jsonb_array_length(p_lines_payload) = 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','LINES_PAYLOAD_REQUIRED');
  END IF;

  INSERT INTO public.recurring_invoice_templates (
    id, organization_id, business_id, client_id, template_name,
    invoice_type, currency, vat_treatment_per_line, default_vat_treatment,
    payment_terms_days, lines_payload,
    cadence_kind, cadence_anchor_day_of_period, next_due_date, start_date, end_date,
    auto_send, auto_send_target_email, pro_forma_expiry_days,
    status, created_by, updated_by
  ) VALUES (
    v_id, p_organization_id, p_business_id, p_client_id, p_template_name,
    p_invoice_type, p_currency, p_vat_treatment_per_line, p_default_vat_treatment,
    COALESCE(p_payment_terms_days, 30), p_lines_payload,
    p_cadence_kind, p_cadence_anchor_day_of_period, p_start_date, p_start_date, p_end_date,
    COALESCE(p_auto_send, false), p_auto_send_target_email, COALESCE(p_pro_forma_expiry_days, 30),
    'ACTIVE', p_actor_user_id, p_actor_user_id
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_TEMPLATE_CREATED',
    p_subject_type:='RECURRING_INVOICE_TEMPLATE'::audit.subject_type_enum, p_subject_id:=v_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object('template_id', v_id, 'client_id', p_client_id,
      'cadence_kind', p_cadence_kind::text, 'anchor_day', p_cadence_anchor_day_of_period,
      'start_date', p_start_date, 'end_date', p_end_date, 'auto_send', p_auto_send,
      'invoice_type', p_invoice_type::text),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW','template_id', v_id, 'next_due_date', p_start_date);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_template_update(p_actor_user_id uuid, p_template_id uuid, p_template_name text DEFAULT NULL::text, p_payment_terms_days integer DEFAULT NULL::integer, p_lines_payload jsonb DEFAULT NULL::jsonb, p_cadence_kind recurring_cadence_kind_enum DEFAULT NULL::recurring_cadence_kind_enum, p_cadence_anchor_day_of_period integer DEFAULT NULL::integer, p_end_date date DEFAULT NULL::date, p_auto_send boolean DEFAULT NULL::boolean, p_pro_forma_expiry_days integer DEFAULT NULL::integer, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_tpl public.recurring_invoice_templates%ROWTYPE;
  v_decision jsonb;
  v_diff jsonb := '{}'::jsonb;
  v_new_next_due date;
  v_cadence_changed boolean := false;
BEGIN
  SELECT * INTO v_tpl FROM public.recurring_invoice_templates WHERE id = p_template_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id,'INVOICE_MANAGE','UPDATE_RECURRING_TEMPLATE',
    jsonb_build_object('template_id', p_template_id), v_tpl.business_id, v_tpl.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF v_tpl.status = 'ENDED' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_ENDED');
  END IF;

  IF p_template_name IS NOT NULL AND p_template_name <> v_tpl.template_name THEN
    v_diff := v_diff || jsonb_build_object('template_name', jsonb_build_object('old', v_tpl.template_name, 'new', p_template_name));
  END IF;
  IF p_payment_terms_days IS NOT NULL AND p_payment_terms_days IS DISTINCT FROM v_tpl.payment_terms_days THEN
    v_diff := v_diff || jsonb_build_object('payment_terms_days', jsonb_build_object('old', v_tpl.payment_terms_days, 'new', p_payment_terms_days));
  END IF;
  IF p_lines_payload IS NOT NULL THEN
    v_diff := v_diff || jsonb_build_object('lines_payload_changed', true);
  END IF;
  IF p_cadence_kind IS NOT NULL AND p_cadence_kind <> v_tpl.cadence_kind THEN
    v_diff := v_diff || jsonb_build_object('cadence_kind', jsonb_build_object('old', v_tpl.cadence_kind::text, 'new', p_cadence_kind::text));
    v_cadence_changed := true;
  END IF;
  IF p_cadence_anchor_day_of_period IS NOT NULL AND p_cadence_anchor_day_of_period IS DISTINCT FROM v_tpl.cadence_anchor_day_of_period THEN
    v_diff := v_diff || jsonb_build_object('cadence_anchor_day_of_period', jsonb_build_object('old', v_tpl.cadence_anchor_day_of_period, 'new', p_cadence_anchor_day_of_period));
    v_cadence_changed := true;
  END IF;
  IF p_end_date IS NOT NULL AND p_end_date IS DISTINCT FROM v_tpl.end_date THEN
    v_diff := v_diff || jsonb_build_object('end_date', jsonb_build_object('old', v_tpl.end_date, 'new', p_end_date));
  END IF;
  IF p_auto_send IS NOT NULL AND p_auto_send IS DISTINCT FROM v_tpl.auto_send THEN
    v_diff := v_diff || jsonb_build_object('auto_send', jsonb_build_object('old', v_tpl.auto_send, 'new', p_auto_send));
  END IF;
  IF p_pro_forma_expiry_days IS NOT NULL AND p_pro_forma_expiry_days IS DISTINCT FROM v_tpl.pro_forma_expiry_days THEN
    v_diff := v_diff || jsonb_build_object('pro_forma_expiry_days', jsonb_build_object('old', v_tpl.pro_forma_expiry_days, 'new', p_pro_forma_expiry_days));
  END IF;

  IF v_diff <> '{}'::jsonb THEN
    -- Recompute next_due_date if cadence changed
    IF v_cadence_changed THEN
      v_new_next_due := public.recurring_template_compute_next_due_date(
        COALESCE(p_cadence_kind, v_tpl.cadence_kind),
        CURRENT_DATE,
        COALESCE(p_cadence_anchor_day_of_period, v_tpl.cadence_anchor_day_of_period)
      );
    ELSE
      v_new_next_due := v_tpl.next_due_date;
    END IF;

    UPDATE public.recurring_invoice_templates SET
      template_name = COALESCE(p_template_name, template_name),
      payment_terms_days = COALESCE(p_payment_terms_days, payment_terms_days),
      lines_payload = COALESCE(p_lines_payload, lines_payload),
      cadence_kind = COALESCE(p_cadence_kind, cadence_kind),
      cadence_anchor_day_of_period = COALESCE(p_cadence_anchor_day_of_period, cadence_anchor_day_of_period),
      next_due_date = v_new_next_due,
      end_date = CASE WHEN p_end_date IS NOT NULL THEN p_end_date ELSE end_date END,
      auto_send = COALESCE(p_auto_send, auto_send),
      pro_forma_expiry_days = COALESCE(p_pro_forma_expiry_days, pro_forma_expiry_days),
      updated_at = now(), updated_by = p_actor_user_id
    WHERE id = p_template_id;

    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_TEMPLATE_UPDATED',
      p_subject_type:='RECURRING_INVOICE_TEMPLATE'::audit.subject_type_enum, p_subject_id:=p_template_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('diff', v_diff, 'next_due_date', v_new_next_due),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'diff', v_diff);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_template_pause(p_actor_user_id uuid, p_template_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_tpl public.recurring_invoice_templates%ROWTYPE; v_decision jsonb;
BEGIN
  SELECT * INTO v_tpl FROM public.recurring_invoice_templates WHERE id = p_template_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id,'INVOICE_MANAGE','PAUSE_RECURRING_TEMPLATE',
    jsonb_build_object('template_id', p_template_id), v_tpl.business_id, v_tpl.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF v_tpl.status = 'PAUSED' THEN
    RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'reason_code','ALREADY_PAUSED');
  END IF;
  IF v_tpl.status = 'ENDED' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_ENDED');
  END IF;
  UPDATE public.recurring_invoice_templates SET
    status='PAUSED', paused_at=now(), paused_by=p_actor_user_id,
    updated_at=now(), updated_by=p_actor_user_id
   WHERE id = p_template_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_TEMPLATE_PAUSED',
    p_subject_type:='RECURRING_INVOICE_TEMPLATE'::audit.subject_type_enum, p_subject_id:=p_template_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
    p_before_state:=jsonb_build_object('status', v_tpl.status::text),
    p_after_state :=jsonb_build_object('status','PAUSED'),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'status','PAUSED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_template_resume(p_actor_user_id uuid, p_template_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_tpl public.recurring_invoice_templates%ROWTYPE; v_decision jsonb;
BEGIN
  SELECT * INTO v_tpl FROM public.recurring_invoice_templates WHERE id = p_template_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id,'INVOICE_MANAGE','RESUME_RECURRING_TEMPLATE',
    jsonb_build_object('template_id', p_template_id), v_tpl.business_id, v_tpl.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF v_tpl.status = 'ACTIVE' THEN
    RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'reason_code','ALREADY_ACTIVE');
  END IF;
  IF v_tpl.status = 'ENDED' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_ENDED');
  END IF;
  UPDATE public.recurring_invoice_templates SET
    status='ACTIVE', paused_at=NULL, paused_by=NULL,
    updated_at=now(), updated_by=p_actor_user_id
   WHERE id = p_template_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_TEMPLATE_RESUMED',
    p_subject_type:='RECURRING_INVOICE_TEMPLATE'::audit.subject_type_enum, p_subject_id:=p_template_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
    p_before_state:=jsonb_build_object('status','PAUSED'),
    p_after_state :=jsonb_build_object('status','ACTIVE'),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'status','ACTIVE');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_template_end(p_actor_user_id uuid, p_template_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_tpl public.recurring_invoice_templates%ROWTYPE; v_decision jsonb;
BEGIN
  SELECT * INTO v_tpl FROM public.recurring_invoice_templates WHERE id = p_template_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TEMPLATE_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id,'INVOICE_MANAGE','END_RECURRING_TEMPLATE',
    jsonb_build_object('template_id', p_template_id), v_tpl.business_id, v_tpl.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  IF v_tpl.status = 'ENDED' THEN
    RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'reason_code','ALREADY_ENDED');
  END IF;
  UPDATE public.recurring_invoice_templates SET
    status='ENDED', ended_at=now(), ended_by=p_actor_user_id,
    paused_at=NULL, paused_by=NULL,
    updated_at=now(), updated_by=p_actor_user_id
   WHERE id = p_template_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_TEMPLATE_ENDED',
    p_subject_type:='RECURRING_INVOICE_TEMPLATE'::audit.subject_type_enum, p_subject_id:=p_template_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
    p_before_state:=jsonb_build_object('status', v_tpl.status::text),
    p_after_state :=jsonb_build_object('status','ENDED'),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','template_id', p_template_id, 'status','ENDED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invoice_mark_pro_forma_expired(p_invoice_id uuid, p_actor_system text DEFAULT 'pro_forma_expiry_scheduler'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_inv public.invoices%ROWTYPE;
BEGIN
  SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND'); END IF;
  IF v_inv.invoice_type <> 'PRO_FORMA' THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'EXPIRED_UNCONVERTED','NOT_PRO_FORMA', NULL, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','NOT_PRO_FORMA');
  END IF;
  IF v_inv.lifecycle_status NOT IN ('DRAFT','SENT') THEN
    PERFORM public._emit_invoice_transition_failed(p_invoice_id, v_inv.organization_id, v_inv.business_id,
      v_inv.lifecycle_status::text,'EXPIRED_UNCONVERTED','ILLEGAL_TRANSITION', NULL, p_actor_system, p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ILLEGAL_TRANSITION','current_status', v_inv.lifecycle_status::text);
  END IF;
  UPDATE public.invoices SET
    lifecycle_status='EXPIRED_UNCONVERTED', lifecycle_status_changed_at=now(),
    updated_at=now()
   WHERE id = p_invoice_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='INVOICE_PRO_FORMA_EXPIRED',
    p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=p_invoice_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=v_inv.organization_id, p_business_id:=v_inv.business_id,
    p_before_state:=jsonb_build_object('lifecycle_status', v_inv.lifecycle_status::text),
    p_after_state :=jsonb_build_object('lifecycle_status','EXPIRED_UNCONVERTED','pro_forma_expires_at', v_inv.pro_forma_expires_at),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','lifecycle_status','EXPIRED_UNCONVERTED');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recurring_run_daily_scheduler(p_scheduled_at timestamp with time zone, p_actor_system text DEFAULT 'recurring_invoice_scheduler'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_tpl public.recurring_invoice_templates%ROWTYPE;
  v_due date := p_scheduled_at::date;
  v_inv_id uuid;
  v_run_id uuid;
  v_line jsonb;
  v_line_no int;
  v_sub numeric(18,2);
  v_vat numeric(18,2);
  v_tot numeric(18,2);
  v_already_done boolean;
  v_err text;
  v_new_next date;
  v_processed int := 0;
  v_generated int := 0;
  v_skipped   int := 0;
  v_failed    int := 0;
  v_ended     int := 0;
  v_alloc     jsonb;
BEGIN
  FOR v_tpl IN
    SELECT * FROM public.recurring_invoice_templates
     WHERE status = 'ACTIVE' AND next_due_date <= v_due
     ORDER BY business_id, next_due_date, id
  LOOP
    v_processed := v_processed + 1;

    -- Idempotency: skip if already GENERATED for this (template, due_date)
    SELECT EXISTS (
      SELECT 1 FROM public.recurring_invoice_runs
       WHERE template_id = v_tpl.id AND due_date = v_tpl.next_due_date AND outcome = 'GENERATED'
    ) INTO v_already_done;
    IF v_already_done THEN
      v_skipped := v_skipped + 1;
      CONTINUE;
    END IF;

    v_inv_id := gen_uuid_v7();

    -- Generation subblock with failure isolation
    BEGIN
      INSERT INTO public.invoices (
        id, organization_id, business_id, client_id,
        invoice_type, invoice_number,
        issue_date, supply_date, due_date,
        currency, subtotal_amount, vat_amount, total_amount,
        vat_treatment_per_line, default_vat_treatment,
        lifecycle_status, lifecycle_status_changed_at, lifecycle_status_changed_by,
        pro_forma_expires_at
      ) VALUES (
        v_inv_id, v_tpl.organization_id, v_tpl.business_id, v_tpl.client_id,
        v_tpl.invoice_type, NULL,
        v_tpl.next_due_date, NULL, (v_tpl.next_due_date + v_tpl.payment_terms_days),
        v_tpl.currency, 0, 0, 0,
        v_tpl.vat_treatment_per_line, v_tpl.default_vat_treatment,
        'DRAFT', now(), v_tpl.created_by,
        CASE WHEN v_tpl.invoice_type = 'PRO_FORMA'
             THEN (v_tpl.next_due_date + v_tpl.pro_forma_expiry_days)::timestamptz
             ELSE NULL END
      );

      v_line_no := 0;
      FOR v_line IN SELECT * FROM jsonb_array_elements(v_tpl.lines_payload) LOOP
        v_line_no := v_line_no + 1;
        v_sub := ((v_line->>'quantity')::numeric * (v_line->>'unit_price')::numeric)::numeric(18,2);
        v_vat := COALESCE(NULLIF(v_line->>'vat_amount','')::numeric, 0)::numeric(18,2);
        v_tot := (v_sub + v_vat)::numeric(18,2);
        INSERT INTO public.invoice_lines (
          organization_id, business_id, invoice_id, line_number,
          description, quantity, unit_price, currency,
          subtotal_amount, vat_treatment, vat_rate_pct, vat_amount, total_amount
        ) VALUES (
          v_tpl.organization_id, v_tpl.business_id, v_inv_id, v_line_no,
          v_line->>'description',
          (v_line->>'quantity')::numeric, (v_line->>'unit_price')::numeric,
          v_tpl.currency,
          v_sub,
          NULLIF(v_line->>'vat_treatment','')::public.vat_treatment_enum,
          NULLIF(v_line->>'vat_rate_pct','')::numeric,
          NULLIF(v_line->>'vat_amount','')::numeric,
          v_tot
        );
      END LOOP;

      PERFORM public.invoice_recompute_totals(v_inv_id, p_context);

      -- auto_send: inline allocate + lifecycle update (avoids re-checking INVOICE_MANAGE on a system path)
      IF v_tpl.auto_send THEN
        v_alloc := public.allocate_invoice_number(v_inv_id, p_context);
        UPDATE public.invoices SET
          lifecycle_status='SENT',
          lifecycle_status_changed_at=now(),
          sent_at=now(),
          sent_by=v_tpl.created_by,
          updated_at=now()
         WHERE id = v_inv_id;
        PERFORM audit.emit_audit(
          p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='INVOICE_SENT',
          p_subject_type:='INVOICE'::audit.subject_type_enum, p_subject_id:=v_inv_id,
          p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
          p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
          p_before_state:=jsonb_build_object('lifecycle_status','DRAFT'),
          p_after_state :=jsonb_build_object('lifecycle_status','SENT','invoice_number', v_alloc->'invoice_number',
                                              'via_recurring_template_id', v_tpl.id),
          p_reason:=NULL, p_request_context:=p_context);
      END IF;

      -- Record GENERATED run
      INSERT INTO public.recurring_invoice_runs (
        organization_id, business_id, template_id, due_date,
        generated_invoice_id, outcome, scheduled_at
      ) VALUES (
        v_tpl.organization_id, v_tpl.business_id, v_tpl.id, v_tpl.next_due_date,
        v_inv_id, 'GENERATED', p_scheduled_at
      ) RETURNING id INTO v_run_id;

      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_GENERATED',
        p_subject_type:='RECURRING_INVOICE_RUN'::audit.subject_type_enum, p_subject_id:=v_run_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
        p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
        p_before_state:=NULL,
        p_after_state :=jsonb_build_object('template_id', v_tpl.id, 'invoice_id', v_inv_id,
                                            'due_date', v_tpl.next_due_date, 'auto_send', v_tpl.auto_send),
        p_reason:=NULL, p_request_context:=p_context);

      -- Advance next_due_date
      v_new_next := public.recurring_template_compute_next_due_date(
        v_tpl.cadence_kind, v_tpl.next_due_date, v_tpl.cadence_anchor_day_of_period);

      IF v_tpl.end_date IS NOT NULL AND v_new_next > v_tpl.end_date THEN
        UPDATE public.recurring_invoice_templates SET
          next_due_date = v_new_next,
          status='ENDED', ended_at=now(), ended_by=v_tpl.created_by,
          updated_at=now(), updated_by=v_tpl.created_by
         WHERE id = v_tpl.id;
        PERFORM audit.emit_audit(
          p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_TEMPLATE_ENDED',
          p_subject_type:='RECURRING_INVOICE_TEMPLATE'::audit.subject_type_enum, p_subject_id:=v_tpl.id,
          p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
          p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
          p_before_state:=jsonb_build_object('status','ACTIVE'),
          p_after_state :=jsonb_build_object('status','ENDED','reason','past_end_date'),
          p_reason:=NULL, p_request_context:=p_context);
        v_ended := v_ended + 1;
      ELSE
        UPDATE public.recurring_invoice_templates SET
          next_due_date = v_new_next, updated_at=now()
         WHERE id = v_tpl.id;
      END IF;

      v_generated := v_generated + 1;
    EXCEPTION WHEN OTHERS THEN
      v_err := SQLERRM;
      -- Record FAILED run (outer-tx INSERT after savepoint rollback)
      INSERT INTO public.recurring_invoice_runs (
        organization_id, business_id, template_id, due_date,
        generated_invoice_id, outcome, error_message, scheduled_at
      ) VALUES (
        v_tpl.organization_id, v_tpl.business_id, v_tpl.id, v_tpl.next_due_date,
        NULL, 'FAILED', v_err, p_scheduled_at
      ) RETURNING id INTO v_run_id;
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_GENERATION_FAILED',
        p_subject_type:='RECURRING_INVOICE_RUN'::audit.subject_type_enum, p_subject_id:=v_run_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
        p_organization_id:=v_tpl.organization_id, p_business_id:=v_tpl.business_id,
        p_before_state:=NULL,
        p_after_state :=jsonb_build_object('template_id', v_tpl.id, 'due_date', v_tpl.next_due_date,
                                            'error', v_err),
        p_reason:=v_err, p_request_context:=p_context);
      v_failed := v_failed + 1;
    END;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='RECURRING_INVOICE_SCHEDULER_RAN',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=gen_uuid_v7(),
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'scheduled_at', p_scheduled_at,
      'templates_processed', v_processed,
      'generated', v_generated,
      'skipped', v_skipped,
      'failed', v_failed,
      'ended_after_run', v_ended),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','RAN',
    'templates_processed', v_processed,
    'generated', v_generated,
    'skipped', v_skipped,
    'failed', v_failed,
    'ended_after_run', v_ended);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_config_get(p_business_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_row jsonb;
BEGIN
  SELECT to_jsonb(c) INTO v_row FROM public.in_workflow_business_config c WHERE c.business_id = p_business_id;
  IF v_row IS NULL THEN RETURN jsonb_build_object('decision','DENY','reason_code','CONFIG_NOT_FOUND'); END IF;
  RETURN jsonb_build_object('decision','ALLOW','config', v_row);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_config_update(p_actor_user_id uuid, p_business_id uuid, p_auto_start_on_statement_upload boolean DEFAULT NULL::boolean, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_cfg public.in_workflow_business_config%ROWTYPE;
  v_decision jsonb;
  v_diff jsonb := '{}'::jsonb;
BEGIN
  SELECT * INTO v_cfg FROM public.in_workflow_business_config WHERE business_id = p_business_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','CONFIG_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id,'WORKFLOW_CONFIG_MANAGE','UPDATE',
    jsonb_build_object('business_id', p_business_id), p_business_id, v_cfg.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;

  IF p_auto_start_on_statement_upload IS NOT NULL
     AND p_auto_start_on_statement_upload IS DISTINCT FROM v_cfg.auto_start_on_statement_upload THEN
    v_diff := v_diff || jsonb_build_object('auto_start_on_statement_upload',
      jsonb_build_object('old', v_cfg.auto_start_on_statement_upload, 'new', p_auto_start_on_statement_upload));
  END IF;

  IF v_diff <> '{}'::jsonb THEN
    UPDATE public.in_workflow_business_config SET
      auto_start_on_statement_upload = COALESCE(p_auto_start_on_statement_upload, auto_start_on_statement_upload),
      updated_at = now(), last_updated_by = p_actor_user_id
     WHERE business_id = p_business_id;
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_WORKFLOW_CONFIG_UPDATED',
      p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_cfg.organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('diff', v_diff),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object('decision','ALLOW','business_id', p_business_id, 'diff', v_diff);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_in_monthly_type(p_actor_system text DEFAULT 'engine_bootstrap'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_count int;
  v_already_emitted boolean;
BEGIN
  SELECT count(*) INTO v_count FROM public.workflow_phase_definitions WHERE workflow_type='IN_MONTHLY';
  IF v_count <> 8 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','PHASE_SHAPE_INVALID','expected', 8, 'actual', v_count);
  END IF;

  SELECT EXISTS (SELECT 1 FROM audit.audit_events
                  WHERE action='IN_WORKFLOW_TYPE_REGISTERED' LIMIT 1) INTO v_already_emitted;
  IF v_already_emitted THEN
    RETURN jsonb_build_object('decision','ALLOW','idempotent', true, 'phase_count', v_count);
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_WORKFLOW_TYPE_REGISTERED',
    p_subject_type:='WORKFLOW_CONFIG'::audit.subject_type_enum, p_subject_id:=gen_uuid_v7(),
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object('workflow_type','IN_MONTHLY','phase_count', v_count),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','idempotent', false, 'phase_count', v_count);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._in_workflow_validate_period(p_business_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_finalized_exists boolean;
BEGIN
  IF p_period_start IS NULL OR p_period_end IS NULL OR p_period_start > p_period_end THEN
    RETURN jsonb_build_object('ok', false, 'reason_code','INVALID_PERIOD');
  END IF;
  IF p_period_end > CURRENT_DATE THEN
    RETURN jsonb_build_object('ok', false, 'reason_code','PERIOD_IN_FUTURE');
  END IF;
  IF p_period_end < (CURRENT_DATE - INTERVAL '6 years') THEN
    RETURN jsonb_build_object('ok', false, 'reason_code','RETENTION_EXPIRED');
  END IF;
  SELECT EXISTS (
    SELECT 1 FROM public.workflow_runs
     WHERE business_id = p_business_id
       AND workflow_type = 'IN_MONTHLY'
       AND status = 'FINALIZED'
       AND period_start = p_period_start::timestamptz
       AND period_end   = p_period_end::timestamptz
  ) INTO v_finalized_exists;
  IF v_finalized_exists THEN
    RETURN jsonb_build_object('ok', false, 'reason_code','PERIOD_FINALIZED');
  END IF;
  RETURN jsonb_build_object('ok', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_start_run_manually(p_actor_user_id uuid, p_organization_id uuid, p_business_id uuid, p_period_start date, p_period_end date, p_manual_trigger_note text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_decision    jsonb;
  v_period_check jsonb;
  v_run_id      uuid := gen_uuid_v7();
  v_active_exists boolean;
BEGIN
  v_decision := public.can_perform(p_actor_user_id,'WORKFLOW_TRIGGER','START_IN_MONTHLY',
    jsonb_build_object('business_id', p_business_id, 'period_start', p_period_start),
    p_business_id, p_organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;

  v_period_check := public._in_workflow_validate_period(p_business_id, p_period_start, p_period_end);
  IF (v_period_check->>'ok')::boolean <> true THEN
    IF (v_period_check->>'reason_code') = 'PERIOD_FINALIZED' THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_WORKFLOW_RUN_REJECTED_PERIOD_FINALIZED',
        p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
        p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_before_state:=NULL,
        p_after_state :=jsonb_build_object('period_start', p_period_start, 'period_end', p_period_end),
        p_reason:='PERIOD_FINALIZED', p_request_context:=p_context);
    ELSIF (v_period_check->>'reason_code') = 'RETENTION_EXPIRED' THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_WORKFLOW_RUN_REJECTED_RETENTION_EXPIRED',
        p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
        p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_before_state:=NULL,
        p_after_state :=jsonb_build_object('period_start', p_period_start, 'period_end', p_period_end),
        p_reason:='RETENTION_EXPIRED', p_request_context:=p_context);
    END IF;
    RETURN jsonb_build_object('decision','DENY','reason_code', v_period_check->>'reason_code');
  END IF;

  PERFORM pg_advisory_xact_lock(hashtext(p_business_id::text || p_period_start::text || p_period_end::text || 'IN_MONTHLY'));

  SELECT EXISTS (
    SELECT 1 FROM public.workflow_runs
     WHERE business_id = p_business_id
       AND workflow_type = 'IN_MONTHLY'
       AND period_start = p_period_start::timestamptz
       AND period_end   = p_period_end::timestamptz
       AND status IN ('CREATED','RUNNING','PAUSED','REVIEW_HOLD','AWAITING_APPROVAL','FINALIZING','COMPENSATING')
  ) INTO v_active_exists;
  IF v_active_exists THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_WORKFLOW_RUN_ALREADY_ACTIVE_REJECTED',
      p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('period_start', p_period_start, 'period_end', p_period_end),
      p_reason:='RUN_ALREADY_ACTIVE', p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','RUN_ALREADY_ACTIVE');
  END IF;

  INSERT INTO public.workflow_runs (
    id, organization_id, business_id, workflow_type,
    principal_snapshot, status, trigger_kind,
    period_start, period_end,
    triggered_by_user_id, manual_trigger_note
  ) VALUES (
    v_run_id, p_organization_id, p_business_id, 'IN_MONTHLY',
    jsonb_build_object('actor_user_id', p_actor_user_id::text, 'trigger_kind','MANUAL'),
    'CREATED', 'MANUAL',
    p_period_start::timestamptz, p_period_end::timestamptz,
    p_actor_user_id, p_manual_trigger_note
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_WORKFLOW_RUN_STARTED_MANUALLY',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=v_run_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object('run_id', v_run_id, 'workflow_type','IN_MONTHLY',
      'period_start', p_period_start, 'period_end', p_period_end, 'trigger_kind','MANUAL'),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW','run_id', v_run_id, 'workflow_type','IN_MONTHLY');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.load_in_workflow_config_for_business(p_organization_id uuid, p_business_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'business_provisioning'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_id uuid; v_inserted boolean := false;
BEGIN
  INSERT INTO public.in_workflow_business_config (
    organization_id, business_id, auto_start_on_statement_upload, last_updated_by
  ) VALUES (
    p_organization_id, p_business_id, true, p_actor_user_id
  )
  ON CONFLICT (business_id) DO NOTHING
  RETURNING id INTO v_id;
  IF v_id IS NOT NULL THEN
    v_inserted := true;
    PERFORM audit.emit_audit(
      p_actor_kind:=CASE WHEN p_actor_user_id IS NOT NULL THEN 'USER' ELSE 'SYSTEM' END::audit.actor_kind_enum,
      p_action:='IN_WORKFLOW_CONFIG_INITIALIZED',
      p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:=CASE WHEN p_actor_user_id IS NOT NULL THEN NULL ELSE p_actor_system END,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('config_id', v_id, 'auto_start_on_statement_upload', true),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;
  RETURN jsonb_build_object('decision','ALLOW','inserted', v_inserted);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_in_workflow_evidence_rule(p_transaction_type transaction_type_enum, p_direction transaction_direction_enum)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF p_transaction_type IN ('IN_INCOME','REFUND_IN','INTERNAL_TRANSFER') THEN
    RETURN jsonb_build_object('in_filter_includes', true, 'requires_blocking_review', false);
  END IF;
  IF p_transaction_type = 'LOAN_OR_SHAREHOLDER_MOVEMENT' THEN
    IF p_direction = 'IN' THEN
      RETURN jsonb_build_object('in_filter_includes', true, 'requires_blocking_review', false);
    END IF;
    RETURN jsonb_build_object('in_filter_includes', false, 'requires_blocking_review', false);
  END IF;
  IF p_transaction_type = 'UNKNOWN' THEN
    IF p_direction = 'IN' THEN
      RETURN jsonb_build_object('in_filter_includes', true, 'requires_blocking_review', true);
    END IF;
    RETURN jsonb_build_object('in_filter_includes', false, 'requires_blocking_review', false);
  END IF;
  RETURN jsonb_build_object('in_filter_includes', false, 'requires_blocking_review', false);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_in_workflow_in_filter_exit_v1(p_workflow_run_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run public.workflow_runs%ROWTYPE;
  v_undecided_count int;
  v_unresolved_blocker_count int;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','RUN_NOT_FOUND'); END IF;
  SELECT count(*) INTO v_undecided_count
    FROM public.transactions
   WHERE business_id = v_run.business_id
     AND transaction_date BETWEEN v_run.period_start::date AND v_run.period_end::date
     AND in_filter_decided_at IS NULL;
  IF v_undecided_count > 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','UNDECIDED_TRANSACTIONS',
      'undecided_count', v_undecided_count);
  END IF;
  SELECT count(*) INTO v_unresolved_blocker_count
    FROM public.review_issues
   WHERE workflow_run_id = p_workflow_run_id
     AND issue_type = 'in_filter.unknown_positive_blocker'
     AND status IN ('OPEN','SNOOZED');
  IF v_unresolved_blocker_count > 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','UNRESOLVED_UNKNOWN_BLOCKERS',
      'unresolved_count', v_unresolved_blocker_count);
  END IF;
  RETURN jsonb_build_object('decision','ALLOW');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.filter_in_transactions(p_organization_id uuid, p_business_id uuid, p_workflow_run_id uuid, p_period_start date, p_period_end date, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_txn record;
  v_rule jsonb;
  v_should_include boolean;
  v_requires_blocking boolean;
  v_prev_in_scope boolean;
  v_was_decided boolean;
  v_review_issue_id uuid;
  v_already_blocked boolean;
  v_included int := 0;
  v_excluded int := 0;
  v_unknown_blockers int := 0;
  v_transitioned int := 0;
  v_per_type jsonb := '{}'::jsonb;
  v_type_key text;
  v_current_count int;
  v_transitioned_ids uuid[] := '{}';
BEGIN
  FOR v_txn IN
    SELECT id, transaction_type, direction, in_workflow_in_scope, in_filter_decided_at
      FROM public.transactions
     WHERE business_id = p_business_id
       AND transaction_date BETWEEN p_period_start AND p_period_end
  LOOP
    v_rule := public.get_in_workflow_evidence_rule(v_txn.transaction_type, v_txn.direction);
    v_should_include    := COALESCE((v_rule->>'in_filter_includes')::boolean, false);
    v_requires_blocking := COALESCE((v_rule->>'requires_blocking_review')::boolean, false);
    v_prev_in_scope     := v_txn.in_workflow_in_scope;
    v_was_decided       := v_txn.in_filter_decided_at IS NOT NULL;

    IF v_requires_blocking THEN
      -- Dedup: skip if there's already an OPEN/SNOOZED blocker for this (txn, run)
      SELECT EXISTS (
        SELECT 1 FROM public.review_issues
         WHERE workflow_run_id = p_workflow_run_id
           AND transaction_id = v_txn.id
           AND issue_type = 'in_filter.unknown_positive_blocker'
           AND status IN ('OPEN','SNOOZED')
      ) INTO v_already_blocked;
      IF NOT v_already_blocked THEN
        INSERT INTO public.review_issues (
          organization_id, business_id, workflow_run_id, transaction_id,
          issue_type, issue_group, severity,
          plain_language_title, plain_language_description, recommended_action,
          card_payload_json
        ) VALUES (
          p_organization_id, p_business_id, p_workflow_run_id, v_txn.id,
          'in_filter.unknown_positive_blocker',
          'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
          'HIGH'::public.review_issue_severity_enum,
          'Incoming transaction needs reclassification',
          'This transaction has direction=IN (incoming money) but is classified as UNKNOWN. The IN workflow cannot match it against an invoice or produce ledger entries until it is reclassified into one of the known IN-side types.',
          'Reclassify the transaction (IN_INCOME, REFUND_IN, INTERNAL_TRANSFER, or LOAN_OR_SHAREHOLDER_MOVEMENT with IN direction).',
          jsonb_build_object('transaction_id', v_txn.id, 'workflow_run_id', p_workflow_run_id)
        ) RETURNING id INTO v_review_issue_id;
        PERFORM audit.emit_audit(
          p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_FILTER_UNKNOWN_POSITIVE_BLOCKER_RAISED',
          p_subject_type:='TRANSACTION'::audit.subject_type_enum, p_subject_id:=v_txn.id,
          p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:='in_filter',
          p_organization_id:=p_organization_id, p_business_id:=p_business_id,
          p_before_state:=NULL,
          p_after_state :=jsonb_build_object('review_issue_id', v_review_issue_id, 'workflow_run_id', p_workflow_run_id),
          p_reason:=NULL, p_request_context:=p_context);
        v_unknown_blockers := v_unknown_blockers + 1;
      END IF;
    END IF;

    IF v_was_decided AND v_prev_in_scope <> v_should_include THEN
      v_transitioned := v_transitioned + 1;
      v_transitioned_ids := v_transitioned_ids || v_txn.id;
    END IF;

    UPDATE public.transactions
       SET in_workflow_in_scope = v_should_include,
           in_filter_decided_at = clock_timestamp(),
           in_filter_decided_by_run_id = p_workflow_run_id,
           updated_at = clock_timestamp()
     WHERE id = v_txn.id;

    IF v_should_include THEN v_included := v_included + 1;
    ELSE v_excluded := v_excluded + 1; END IF;

    v_type_key := v_txn.transaction_type::text;
    v_current_count := COALESCE((v_per_type->>v_type_key)::int, 0);
    v_per_type := v_per_type || jsonb_build_object(v_type_key, v_current_count + 1);
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_FILTER_RAN',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_workflow_run_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:='in_filter',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'included_count', v_included, 'excluded_count', v_excluded,
      'unknown_blockers_raised', v_unknown_blockers, 'transitioned_count', v_transitioned,
      'per_type_counts', v_per_type,
      'period_start', p_period_start, 'period_end', p_period_end),
    p_reason:=NULL, p_request_context:=p_context);

  IF v_transitioned > 0 THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_FILTER_SCOPE_TRANSITIONED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_workflow_run_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:='in_filter',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object(
        'transitioned_count', v_transitioned,
        'transitioned_ids', to_jsonb(v_transitioned_ids)),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'decision','RAN',
    'included_count', v_included, 'excluded_count', v_excluded,
    'unknown_blockers_raised', v_unknown_blockers, 'transitioned_count', v_transitioned,
    'per_type_counts', v_per_type);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_in_workflow_ingestion_exit_v1(p_workflow_run_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
