CREATE OR REPLACE FUNCTION public.in_workflow_finalize_period_invoices(p_run_id uuid, p_actor_system text DEFAULT 'in_workflow_finalization'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run public.workflow_runs%ROWTYPE;
  v_inv record;
  v_result jsonb;
  v_finalized int := 0;
  v_skipped int := 0;
  v_failed int := 0;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','RUN_NOT_FOUND'); END IF;
  IF v_run.workflow_type <> 'IN_MONTHLY' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','NOT_IN_MONTHLY');
  END IF;
  FOR v_inv IN
    SELECT id, lifecycle_status FROM public.invoices
     WHERE business_id = v_run.business_id
       AND issue_date BETWEEN v_run.period_start::date AND v_run.period_end::date
       AND lifecycle_status NOT IN ('FINALIZED','EXPIRED_UNCONVERTED','CONVERTED_TO_TAX_INVOICE','DRAFT')
  LOOP
    v_result := public.invoice_mark_finalized(v_inv.id, p_run_id, clock_timestamp(), p_actor_system, p_context);
    IF (v_result->>'decision') = 'ALLOW' THEN v_finalized := v_finalized + 1;
    ELSE v_failed := v_failed + 1; END IF;
  END LOOP;
  RETURN jsonb_build_object('decision','RAN','finalized', v_finalized,
    'skipped', v_skipped, 'failed', v_failed);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_in_workflow_match_candidates(p_business_id uuid, p_period_start date, p_period_end date, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_txns jsonb;
  v_inv  jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'transaction_id', t.id, 'amount', t.amount, 'currency', t.currency,
    'transaction_date', t.transaction_date, 'transaction_type', t.transaction_type::text,
    'direction', t.direction::text
  ) ORDER BY t.transaction_date), '[]'::jsonb) INTO v_txns
  FROM public.transactions t
  WHERE t.business_id = p_business_id
    AND t.transaction_date BETWEEN p_period_start AND p_period_end
    AND t.in_workflow_in_scope = true
    AND t.transaction_type IN ('IN_INCOME','REFUND_IN');

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'invoice_id', i.id, 'invoice_number', i.invoice_number,
    'lifecycle_status', i.lifecycle_status::text,
    'currency', i.currency, 'total_amount', i.total_amount,
    'issue_date', i.issue_date, 'due_date', i.due_date,
    'client_id', i.client_id
  ) ORDER BY i.issue_date), '[]'::jsonb) INTO v_inv
  FROM public.invoices i
  WHERE i.business_id = p_business_id
    AND i.invoice_type = 'TAX'
    AND i.lifecycle_status IN ('SENT','PAYMENT_EXPECTED','PARTIALLY_PAID','OVERPAID');

  RETURN jsonb_build_object(
    'decision','RAN',
    'transactions', v_txns,
    'invoice_candidates', v_inv
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_apply_income_match_outcome(p_organization_id uuid, p_business_id uuid, p_workflow_run_id uuid, p_transaction_id uuid, p_invoice_id uuid, p_income_outcome income_outcome_enum, p_allocated_amount numeric, p_paid_at timestamp with time zone, p_match_score numeric DEFAULT 0.9, p_match_signals jsonb DEFAULT '{}'::jsonb, p_proposed_allocations jsonb DEFAULT NULL::jsonb, p_has_exact_reference boolean DEFAULT false, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'income_matcher'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_txn public.transactions%ROWTYPE;
  v_inv public.invoices%ROWTYPE;
  v_match_id uuid := gen_uuid_v7();
  v_review_id uuid;
  v_lifecycle_result jsonb;
  v_match_status public.match_record_status_enum;
  v_match_level public.match_level_enum := 'STRONG_PROBABLE';
  v_match_method public.match_method_enum := 'DETERMINISTIC_RULE';
BEGIN
  SELECT * INTO v_txn FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TRANSACTION_NOT_FOUND'); END IF;

  IF p_invoice_id IS NOT NULL THEN
    SELECT * INTO v_inv FROM public.invoices WHERE id = p_invoice_id;
    IF v_inv.invoice_type = 'PRO_FORMA' THEN
      RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_MATCHABLE');
    END IF;
  END IF;

  -- Per-outcome match_status + lifecycle handling
  IF p_income_outcome = 'FULL_MATCH' THEN
    IF p_has_exact_reference THEN
      v_match_status := 'MATCHED_AUTO_HIGH_CONFIDENCE'::public.match_record_status_enum;
      v_match_level  := 'EXACT'::public.match_level_enum;
    ELSE
      v_match_status := 'MATCHED_NEEDS_CONFIRMATION'::public.match_record_status_enum;
    END IF;
  ELSIF p_income_outcome IN ('PARTIAL_PAYMENT','OVERPAYMENT') THEN
    v_match_status := 'MATCHED_NEEDS_CONFIRMATION'::public.match_record_status_enum;
  ELSIF p_income_outcome IN ('MULTIPLE_INVOICES_ONE_PAYMENT','POSSIBLE_REFUND_OR_TRANSFER') THEN
    v_match_status := 'POSSIBLE_MATCH'::public.match_record_status_enum;
  ELSIF p_income_outcome = 'ONE_INVOICE_MULTIPLE_PAYMENTS' THEN
    v_match_status := 'MATCHED_AUTO_HIGH_CONFIDENCE'::public.match_record_status_enum;
  ELSIF p_income_outcome = 'NO_MATCH' THEN
    -- NO_MATCH path: no match_records row inserted; just review issue + audit
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id,
      issue_type, issue_group, severity, plain_language_title, plain_language_description, recommended_action
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id,
      'income_matching.no_match',
      'MISSING_DOCUMENTS'::public.review_issue_group_enum,
      'HIGH'::public.review_issue_severity_enum,
      'Incoming payment with no matching invoice',
      'A payment was received but no matching invoice could be located. Either create an invoice and re-match, or mark this as non-invoice income.',
      'Create an invoice for this payment or reclassify as non-invoice income.'
    ) RETURNING id INTO v_review_id;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_INCOME_MATCHING_INVOKED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum, p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('outcome','NO_MATCH','review_issue_id', v_review_id),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','ALLOW','outcome','NO_MATCH','review_issue_id', v_review_id);
  END IF;

  -- Insert match_records row (for non-NO_MATCH outcomes)
  IF p_invoice_id IS NULL THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_ID_REQUIRED_FOR_OUTCOME');
  END IF;
  INSERT INTO public.match_records (
    id, organization_id, business_id, transaction_id, invoice_id,
    match_level, match_method, match_score, match_signals, match_status,
    split_payment_flag, requires_user_confirmation,
    matched_by_system, income_outcome
  ) VALUES (
    v_match_id, p_organization_id, p_business_id, p_transaction_id, p_invoice_id,
    v_match_level, v_match_method, p_match_score, COALESCE(p_match_signals, '{}'::jsonb), v_match_status,
    (p_income_outcome = 'MULTIPLE_INVOICES_ONE_PAYMENT'),
    (v_match_status IN ('MATCHED_NEEDS_CONFIRMATION','POSSIBLE_MATCH')),
    p_actor_system, p_income_outcome
  );

  -- Per-outcome lifecycle + review_issues
  IF p_income_outcome = 'FULL_MATCH' AND p_has_exact_reference THEN
    v_lifecycle_result := public.invoice_mark_paid(
      p_invoice_id, p_transaction_id, p_allocated_amount, p_paid_at,
      v_match_id, p_actor_user_id, p_actor_system, p_context);
  ELSIF p_income_outcome = 'FULL_MATCH' OR p_income_outcome = 'PARTIAL_PAYMENT' OR p_income_outcome = 'OVERPAYMENT' THEN
    -- Needs Confirmation review_issue
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id, match_record_id, invoice_id,
      issue_type, issue_group, severity, plain_language_title, plain_language_description, recommended_action,
      card_payload_json
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id, v_match_id, p_invoice_id,
      'income_matching.' || lower(p_income_outcome::text),
      'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
      'MEDIUM'::public.review_issue_severity_enum,
      'Payment needs confirmation',
      format('Income match outcome: %s — please review and confirm.', p_income_outcome),
      'Confirm or reject the match.',
      jsonb_build_object(
        'outcome', p_income_outcome::text,
        'transaction_id', p_transaction_id,
        'invoice_id', p_invoice_id,
        'allocated_amount', p_allocated_amount,
        'match_record_id', v_match_id)
    ) RETURNING id INTO v_review_id;
    -- For OVERPAYMENT also raise a follow-up tax/vat issue
    IF p_income_outcome = 'OVERPAYMENT' THEN
      INSERT INTO public.review_issues (
        organization_id, business_id, workflow_run_id, transaction_id, match_record_id, invoice_id,
        issue_type, issue_group, severity, plain_language_title, plain_language_description, recommended_action
      ) VALUES (
        p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id, v_match_id, p_invoice_id,
        'income_matching.overpayment_credit_note_required',
        'POSSIBLE_TAX_VAT_ISSUE'::public.review_issue_group_enum,
        'HIGH'::public.review_issue_severity_enum,
        'Overpayment received — credit note required',
        'The payment exceeds the invoice total. Issue a credit note for the surplus or refund.',
        'Issue a credit note for the surplus.'
      );
    END IF;
  ELSIF p_income_outcome = 'MULTIPLE_INVOICES_ONE_PAYMENT' THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id, match_record_id, invoice_id,
      issue_type, issue_group, severity, plain_language_title, plain_language_description, recommended_action,
      card_payload_json
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id, v_match_id, p_invoice_id,
      'income_matching.multiple_invoices_one_payment',
      'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
      'MEDIUM'::public.review_issue_severity_enum,
      'Payment may cover multiple invoices',
      'One payment may be allocated across multiple invoices. Please confirm the allocation or reject.',
      'Confirm the proposed allocation or edit it.',
      jsonb_build_object(
        'outcome', 'MULTIPLE_INVOICES_ONE_PAYMENT',
        'transaction_id', p_transaction_id,
        'proposed_allocations', COALESCE(p_proposed_allocations, '[]'::jsonb),
        'match_record_id', v_match_id)
    ) RETURNING id INTO v_review_id;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_MULTI_INVOICE_ALLOCATION_PROPOSED',
      p_subject_type:='TRANSACTION'::audit.subject_type_enum, p_subject_id:=p_transaction_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('match_record_id', v_match_id,
                                          'proposed_allocations', COALESCE(p_proposed_allocations, '[]'::jsonb),
                                          'review_issue_id', v_review_id),
      p_reason:=NULL, p_request_context:=p_context);
  ELSIF p_income_outcome = 'POSSIBLE_REFUND_OR_TRANSFER' THEN
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id, transaction_id, match_record_id, invoice_id,
      issue_type, issue_group, severity, plain_language_title, plain_language_description, recommended_action
    ) VALUES (
      p_organization_id, p_business_id, p_workflow_run_id, p_transaction_id, v_match_id, p_invoice_id,
      'income_matching.possible_refund_or_transfer',
      'POSSIBLE_WRONG_MATCH'::public.review_issue_group_enum,
      'MEDIUM'::public.review_issue_severity_enum,
      'Payment may be a refund or transfer',
      'The matcher could not determine whether this is income, a refund, or a transfer. Please reclassify.',
      'Reclassify transaction (REFUND_IN, INTERNAL_TRANSFER, or confirm as IN_INCOME).'
    ) RETURNING id INTO v_review_id;
  ELSIF p_income_outcome = 'ONE_INVOICE_MULTIPLE_PAYMENTS' THEN
    -- Auto-apply partial payment; lifecycle auto-promotes to PAID on cumulative-hit
    v_lifecycle_result := public.invoice_mark_partially_paid(
      p_invoice_id, p_transaction_id, p_allocated_amount, p_paid_at,
      v_match_id, p_actor_user_id, p_actor_system, p_context);
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_INCOME_MATCHING_INVOKED',
    p_subject_type:='TRANSACTION'::audit.subject_type_enum, p_subject_id:=p_transaction_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'outcome', p_income_outcome::text,
      'match_record_id', v_match_id,
      'invoice_id', p_invoice_id,
      'allocated_amount', p_allocated_amount,
      'review_issue_id', v_review_id,
      'lifecycle_result', v_lifecycle_result),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'outcome', p_income_outcome::text,
    'match_record_id', v_match_id,
    'review_issue_id', v_review_id,
    'lifecycle_result', v_lifecycle_result);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_confirm_multi_invoice_allocation(p_actor_user_id uuid, p_transaction_id uuid, p_match_record_id uuid, p_allocations jsonb, p_was_edited boolean DEFAULT false, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_txn public.transactions%ROWTYPE;
  v_match public.match_records%ROWTYPE;
  v_decision jsonb;
  v_alloc jsonb;
  v_sum_allocated numeric(18,2) := 0;
  v_inv public.invoices%ROWTYPE;
  v_cumulative numeric(18,2);
  v_remaining numeric(18,2);
  v_lifecycle_result jsonb;
  v_applied jsonb := '[]'::jsonb;
  v_tolerance numeric := 0.02;
  v_action_name text;
BEGIN
  SELECT * INTO v_txn FROM public.transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TRANSACTION_NOT_FOUND'); END IF;
  SELECT * INTO v_match FROM public.match_records WHERE id = p_match_record_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','MATCH_RECORD_NOT_FOUND'); END IF;

  v_decision := public.can_perform(p_actor_user_id, 'INVOICE_MANAGE', 'CONFIRM_ALLOCATION',
    jsonb_build_object('transaction_id', p_transaction_id), v_txn.business_id, v_txn.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;

  IF p_allocations IS NULL OR jsonb_typeof(p_allocations) <> 'array' OR jsonb_array_length(p_allocations) = 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ALLOCATIONS_REQUIRED');
  END IF;

  -- First pass: validate
  FOR v_alloc IN SELECT * FROM jsonb_array_elements(p_allocations) LOOP
    v_sum_allocated := v_sum_allocated + (v_alloc->>'amount')::numeric;
    SELECT * INTO v_inv FROM public.invoices WHERE id = (v_alloc->>'invoice_id')::uuid;
    IF NOT FOUND THEN
      RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_FOUND','invoice_id', v_alloc->>'invoice_id');
    END IF;
    IF v_inv.invoice_type <> 'TAX' THEN
      RETURN jsonb_build_object('decision','DENY','reason_code','PRO_FORMA_NOT_MATCHABLE','invoice_id', v_inv.id);
    END IF;
    IF v_inv.lifecycle_status NOT IN ('SENT','PAYMENT_EXPECTED','PARTIALLY_PAID','OVERPAID') THEN
      RETURN jsonb_build_object('decision','DENY','reason_code','INVOICE_NOT_ELIGIBLE','invoice_id', v_inv.id, 'lifecycle_status', v_inv.lifecycle_status::text);
    END IF;
    -- Per-invoice cumulative paid check
    SELECT COALESCE(SUM(allocated_amount), 0)::numeric(18,2) INTO v_cumulative
      FROM public.invoice_payment_allocations
     WHERE invoice_id = v_inv.id
       AND allocation_kind NOT IN ('REFUND','OVERPAYMENT_SURPLUS');
    v_remaining := (v_inv.total_amount - v_cumulative)::numeric(18,2);
    IF (v_alloc->>'amount')::numeric > v_remaining + v_tolerance THEN
      RETURN jsonb_build_object('decision','DENY','reason_code','ALLOCATION_EXCEEDS_REMAINING',
        'invoice_id', v_inv.id, 'remaining', v_remaining, 'requested', (v_alloc->>'amount')::numeric);
    END IF;
  END LOOP;

  -- Sum tolerance check (allocations must sum to transaction.amount ±0.02)
  IF abs(v_sum_allocated - v_txn.amount) > v_tolerance THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ALLOCATION_SUM_MISMATCH',
      'sum_allocated', v_sum_allocated, 'transaction_amount', v_txn.amount);
  END IF;

  -- Second pass: apply
  FOR v_alloc IN SELECT * FROM jsonb_array_elements(p_allocations) LOOP
    SELECT * INTO v_inv FROM public.invoices WHERE id = (v_alloc->>'invoice_id')::uuid FOR UPDATE;
    SELECT COALESCE(SUM(allocated_amount), 0)::numeric(18,2) INTO v_cumulative
      FROM public.invoice_payment_allocations
     WHERE invoice_id = v_inv.id
       AND allocation_kind NOT IN ('REFUND','OVERPAYMENT_SURPLUS');
    v_remaining := (v_inv.total_amount - v_cumulative)::numeric(18,2);
    IF (v_alloc->>'amount')::numeric >= v_remaining - 0.01 THEN
      -- Mark fully paid (this allocation covers the residual)
      v_lifecycle_result := public.invoice_mark_paid(
        v_inv.id, p_transaction_id, (v_alloc->>'amount')::numeric, clock_timestamp(),
        p_match_record_id, p_actor_user_id, NULL, p_context);
    ELSE
      v_lifecycle_result := public.invoice_mark_partially_paid(
        v_inv.id, p_transaction_id, (v_alloc->>'amount')::numeric, clock_timestamp(),
        p_match_record_id, p_actor_user_id, NULL, p_context);
    END IF;
    v_applied := v_applied || jsonb_build_object(
      'invoice_id', v_inv.id, 'amount', (v_alloc->>'amount')::numeric,
      'lifecycle_result', v_lifecycle_result);
  END LOOP;

  -- Update match_records to MATCHED_CONFIRMED
  UPDATE public.match_records
     SET match_status = 'MATCHED_CONFIRMED'::public.match_record_status_enum,
         user_confirmation_status = 'CONFIRMED',
         confirmed_by = p_actor_user_id,
         confirmed_at = clock_timestamp(),
         updated_at = clock_timestamp()
   WHERE id = p_match_record_id;

  v_action_name := CASE WHEN p_was_edited THEN 'IN_MULTI_INVOICE_ALLOCATION_EDITED_AND_CONFIRMED'
                                          ELSE 'IN_MULTI_INVOICE_ALLOCATION_CONFIRMED' END;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:=v_action_name,
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum, p_subject_id:=p_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_txn.organization_id, p_business_id:=v_txn.business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'transaction_id', p_transaction_id,
      'match_record_id', p_match_record_id,
      'allocations_applied', v_applied,
      'was_edited', p_was_edited),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW','match_record_id', p_match_record_id,
    'allocations_applied', v_applied);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_reject_multi_invoice_allocation(p_actor_user_id uuid, p_match_record_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_match public.match_records%ROWTYPE;
  v_decision jsonb;
BEGIN
  SELECT * INTO v_match FROM public.match_records WHERE id = p_match_record_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','MATCH_RECORD_NOT_FOUND'); END IF;
  v_decision := public.can_perform(p_actor_user_id, 'INVOICE_MANAGE', 'REJECT_ALLOCATION',
    jsonb_build_object('match_record_id', p_match_record_id),
    v_match.business_id, v_match.organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision', 'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;
  UPDATE public.match_records
     SET match_status = 'REJECTED_MATCH'::public.match_record_status_enum,
         user_confirmation_status = 'REJECTED',
         confirmed_by = p_actor_user_id,
         confirmed_at = clock_timestamp(),
         updated_at = clock_timestamp()
   WHERE id = p_match_record_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_MULTI_INVOICE_ALLOCATION_REJECTED',
    p_subject_type:='MATCH_RECORD'::audit.subject_type_enum, p_subject_id:=p_match_record_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_match.organization_id, p_business_id:=v_match.business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object('match_record_id', p_match_record_id, 'status','REJECTED_MATCH'),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','match_record_id', p_match_record_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_check_adjustment_delta_kind_vs_parent_workflow()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_parent_workflow_type public.workflow_type_enum;
BEGIN
  SELECT workflow_type INTO v_parent_workflow_type
    FROM public.workflow_runs WHERE id = NEW.parent_run_id;
  IF v_parent_workflow_type IS NULL THEN
    RAISE EXCEPTION 'adjustment_records.parent_run_id refers to a missing workflow_runs row: %', NEW.parent_run_id
      USING ERRCODE='23503';
  END IF;
  IF v_parent_workflow_type = 'IN_MONTHLY' AND NEW.delta_kind IN ('ADD_EVIDENCE','ADJUST_AMOUNT') THEN
    RAISE EXCEPTION 'delta_kind % is OUT_MONTHLY-only; parent run is IN_MONTHLY (parent_run_id=%)',
      NEW.delta_kind, NEW.parent_run_id USING ERRCODE='23514';
  END IF;
  IF v_parent_workflow_type = 'OUT_MONTHLY' AND NEW.delta_kind IN
     ('RETROACTIVE_CREDIT_NOTE','CORRECT_PAYMENT_ALLOCATION','MARK_INVOICE_WRITTEN_OFF') THEN
    RAISE EXCEPTION 'delta_kind % is IN_MONTHLY-only; parent run is OUT_MONTHLY (parent_run_id=%)',
      NEW.delta_kind, NEW.parent_run_id USING ERRCODE='23514';
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.list_review_queue_fixtures(p_category text DEFAULT NULL::text)
 RETURNS SETOF review_queue_fixture_registry
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT * FROM public.review_queue_fixture_registry
   WHERE p_category IS NULL OR category = p_category
   ORDER BY category, fixture_name;
$function$
;

CREATE OR REPLACE FUNCTION public.register_in_adjustment_type(p_actor_system text DEFAULT 'engine_bootstrap'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_count int; v_emitted boolean;
BEGIN
  SELECT count(*) INTO v_count FROM public.workflow_phase_definitions WHERE workflow_type='IN_ADJUSTMENT';
  IF v_count <> 5 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','PHASE_SHAPE_INVALID','expected', 5, 'actual', v_count);
  END IF;
  SELECT EXISTS (SELECT 1 FROM audit.audit_events WHERE action='IN_ADJUSTMENT_TYPE_REGISTERED' LIMIT 1)
    INTO v_emitted;
  IF v_emitted THEN
    RETURN jsonb_build_object('decision','ALLOW','idempotent', true, 'phase_count', v_count);
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_ADJUSTMENT_TYPE_REGISTERED',
    p_subject_type:='WORKFLOW_CONFIG'::audit.subject_type_enum, p_subject_id:=gen_uuid_v7(),
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=p_actor_system,
    p_organization_id:=NULL, p_business_id:=NULL,
    p_before_state:=NULL, p_after_state:=jsonb_build_object('workflow_type','IN_ADJUSTMENT','phase_count', v_count),
    p_reason:=NULL, p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ALLOW','idempotent', false, 'phase_count', v_count);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_adjustment_intake(p_actor_user_id uuid, p_organization_id uuid, p_business_id uuid, p_parent_run_id uuid, p_reason text, p_delta_kind adjustment_delta_kind_enum, p_delta_payload jsonb, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_decision jsonb;
  v_parent public.workflow_runs%ROWTYPE;
  v_run_id uuid := gen_uuid_v7();
  v_adj_id uuid := gen_uuid_v7();
BEGIN
  v_decision := public.can_perform(p_actor_user_id,'WORKFLOW_TRIGGER','ADJUSTMENT_INTAKE',
    jsonb_build_object('parent_run_id', p_parent_run_id),
    p_business_id, p_organization_id);
  IF (v_decision->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision', v_decision->>'decision',
      'reason_code', COALESCE(v_decision->>'reason_code','PERMISSION_DENIED'));
  END IF;

  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','REASON_REQUIRED');
  END IF;
  IF p_delta_payload IS NULL OR jsonb_typeof(p_delta_payload) <> 'object' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','DELTA_PAYLOAD_REQUIRED');
  END IF;

  SELECT * INTO v_parent FROM public.workflow_runs WHERE id = p_parent_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','PARENT_RUN_NOT_FOUND');
  END IF;
  IF v_parent.workflow_type <> 'IN_MONTHLY' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','NOT_IN_MONTHLY_PARENT',
      'parent_workflow_type', v_parent.workflow_type::text);
  END IF;
  IF v_parent.status <> 'FINALIZED' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_ADJUSTMENT_REJECTED_PARENT_NOT_FINALIZED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_parent_run_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('parent_run_id', p_parent_run_id, 'parent_status', v_parent.status::text),
      p_reason:='PARENT_NOT_FINALIZED', p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','PARENT_NOT_FINALIZED');
  END IF;
  IF v_parent.period_start::date < (CURRENT_DATE - INTERVAL '6 years') THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_ADJUSTMENT_REJECTED_RETENTION_EXPIRED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_parent_run_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state :=jsonb_build_object('parent_run_id', p_parent_run_id,
                                          'parent_period_start', v_parent.period_start),
      p_reason:='RETENTION_EXPIRED', p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','RETENTION_EXPIRED');
  END IF;

  -- Create the IN_ADJUSTMENT workflow_runs row
  INSERT INTO public.workflow_runs (
    id, organization_id, business_id, workflow_type, parent_run_id,
    principal_snapshot, status, trigger_kind,
    period_start, period_end,
    triggered_by_user_id, manual_trigger_note
  ) VALUES (
    v_run_id, p_organization_id, p_business_id, 'IN_ADJUSTMENT', p_parent_run_id,
    jsonb_build_object('actor_user_id', p_actor_user_id::text, 'trigger_kind','MANUAL', 'delta_kind', p_delta_kind::text),
    'CREATED', 'MANUAL',
    v_parent.period_start, v_parent.period_end,
    p_actor_user_id, p_reason
  );

  -- INSERT adjustment_records row (BEFORE INSERT trigger validates delta_kind ↔ parent.workflow_type)
  INSERT INTO public.adjustment_records (
    id, organization_id, business_id, run_id, parent_run_id,
    parent_period_start, parent_period_end,
    reason, delta_kind, delta_payload, requesting_user_id
  ) VALUES (
    v_adj_id, p_organization_id, p_business_id, v_run_id, p_parent_run_id,
    v_parent.period_start::date, v_parent.period_end::date,
    p_reason, p_delta_kind, p_delta_payload, p_actor_user_id
  );

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_ADJUSTMENT_RUN_CREATED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=v_run_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'adjustment_run_id', v_run_id,
      'parent_run_id', p_parent_run_id,
      'period_start', v_parent.period_start, 'period_end', v_parent.period_end,
      'delta_kind', p_delta_kind::text),
    p_reason:=p_reason, p_request_context:=p_context);
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='IN_ADJUSTMENT_INTAKE_COMPLETED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=v_run_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state :=jsonb_build_object(
      'adjustment_record_id', v_adj_id, 'delta_kind', p_delta_kind::text,
      'delta_payload', p_delta_payload),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'adjustment_run_id', v_run_id,
    'adjustment_record_id', v_adj_id,
    'delta_kind', p_delta_kind::text,
    'parent_period', jsonb_build_object('start', v_parent.period_start, 'end', v_parent.period_end));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.list_in_workflow_fixtures(p_category text DEFAULT NULL::text)
 RETURNS SETOF in_workflow_fixture_registry
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT * FROM public.in_workflow_fixture_registry
   WHERE p_category IS NULL OR category = p_category
   ORDER BY category, fixture_name;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_run_fixture(p_fixture_name text, p_organization_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_row public.in_workflow_fixture_registry%ROWTYPE;
BEGIN
  SELECT * INTO v_row FROM public.in_workflow_fixture_registry
   WHERE fixture_name = p_fixture_name;
  IF v_row.id IS NULL THEN
    RAISE EXCEPTION 'in_workflow.run_fixture: unknown fixture %', p_fixture_name USING ERRCODE='02000';
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='IN_WORKFLOW_FIXTURE_RAN',
    p_subject_type:='BUSINESS'::audit.subject_type_enum,
    p_subject_id:=COALESCE(p_organization_id, v_row.id),
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='in_workflow_fixture_runner',
    p_organization_id:=p_organization_id, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'fixture_name', v_row.fixture_name,
      'category', v_row.category,
      'workflow_type', v_row.workflow_type::text,
      'expected_terminal_state', v_row.expected_terminal_state::text,
      'covers_invariants', v_row.covers_invariants,
      'initiating_user_id', p_actor_user_id),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'status','PENDING_IMPLEMENTATION',
    'reason','runtime executor lives in Block 03 app-layer engine (TS); DB-side stub records the audit only',
    'fixture_name', v_row.fixture_name,
    'category', v_row.category,
    'workflow_type', v_row.workflow_type::text,
    'expected_terminal_state', v_row.expected_terminal_state::text,
    'expected_audit_actions', v_row.expected_audit_actions);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._compute_card_content_tier(p_issue_id uuid)
 RETURNS review_issue_card_content_tier_enum
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_issue record;
  v_open_count int;
  v_biz_currency text;
  v_txn_currency text;
BEGIN
  SELECT id, severity, transaction_id, business_id, status
    INTO v_issue
    FROM public.review_issues
   WHERE id = p_issue_id;
  IF NOT FOUND THEN RETURN 'TIER_2_LOCAL_LLM'::public.review_issue_card_content_tier_enum; END IF;

  -- (a) severity = BLOCKING → TIER_3
  IF v_issue.severity = 'BLOCKING'::public.review_issue_severity_enum THEN
    RETURN 'TIER_3_EXTERNAL_LLM'::public.review_issue_card_content_tier_enum;
  END IF;

  -- (b) transaction with 2+ OPEN issues → TIER_3
  IF v_issue.transaction_id IS NOT NULL THEN
    SELECT count(*) INTO v_open_count FROM public.review_issues
     WHERE transaction_id = v_issue.transaction_id
       AND status = 'OPEN'::public.review_issue_status_enum;
    IF v_open_count >= 2 THEN
      RETURN 'TIER_3_EXTERNAL_LLM'::public.review_issue_card_content_tier_enum;
    END IF;
  END IF;

  -- (c) cross-currency proxy: transaction currency differs from business default
  IF v_issue.transaction_id IS NOT NULL THEN
    SELECT t.currency INTO v_txn_currency FROM public.transactions t WHERE t.id = v_issue.transaction_id;
    -- business_entities.default_currency may not always exist; tolerate missing column
    BEGIN
      EXECUTE 'SELECT default_currency FROM public.business_entities WHERE id = $1'
        INTO v_biz_currency USING v_issue.business_id;
    EXCEPTION WHEN undefined_column THEN v_biz_currency := NULL;
    END;
    IF v_biz_currency IS NOT NULL AND v_txn_currency IS NOT NULL AND v_txn_currency <> v_biz_currency THEN
      RETURN 'TIER_3_EXTERNAL_LLM'::public.review_issue_card_content_tier_enum;
    END IF;
  END IF;

  RETURN 'TIER_2_LOCAL_LLM'::public.review_issue_card_content_tier_enum;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_issue_type(p_issue_type text, p_default_group review_issue_group_enum, p_default_severity review_issue_severity_enum, p_allowed_resolution_actions text[], p_producing_block text, p_plain_language_template_ref text DEFAULT NULL::text, p_validity_check_fn_ref text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_before public.issue_type_registry%ROWTYPE;
  v_after  public.issue_type_registry%ROWTYPE;
  v_changed boolean := false;
BEGIN
  IF p_issue_type IS NULL OR length(trim(p_issue_type)) = 0 THEN
    RAISE EXCEPTION 'register_issue_type: issue_type required' USING ERRCODE = '22023';
  END IF;
  IF p_producing_block IS NULL OR length(trim(p_producing_block)) = 0 THEN
    RAISE EXCEPTION 'register_issue_type: producing_block required' USING ERRCODE = '22023';
  END IF;
  IF p_allowed_resolution_actions IS NULL OR cardinality(p_allowed_resolution_actions) < 1 THEN
    RAISE EXCEPTION 'register_issue_type: allowed_resolution_actions must be non-empty' USING ERRCODE = '22023';
  END IF;

  SELECT * INTO v_before FROM public.issue_type_registry WHERE issue_type = p_issue_type;

  INSERT INTO public.issue_type_registry (
    issue_type, default_group, default_severity, allowed_resolution_actions,
    producing_block, plain_language_template_ref, validity_check_fn_ref
  ) VALUES (
    p_issue_type, p_default_group, p_default_severity, p_allowed_resolution_actions,
    p_producing_block, p_plain_language_template_ref, p_validity_check_fn_ref
  )
  ON CONFLICT (issue_type) DO UPDATE
     SET default_group               = EXCLUDED.default_group,
         default_severity            = EXCLUDED.default_severity,
         allowed_resolution_actions  = EXCLUDED.allowed_resolution_actions,
         producing_block             = EXCLUDED.producing_block,
         plain_language_template_ref = EXCLUDED.plain_language_template_ref,
         validity_check_fn_ref       = EXCLUDED.validity_check_fn_ref
  RETURNING * INTO v_after;

  v_changed := v_before.issue_type IS NULL
            OR v_before.default_group               IS DISTINCT FROM v_after.default_group
            OR v_before.default_severity            IS DISTINCT FROM v_after.default_severity
            OR v_before.allowed_resolution_actions  IS DISTINCT FROM v_after.allowed_resolution_actions
            OR v_before.producing_block             IS DISTINCT FROM v_after.producing_block
            OR v_before.plain_language_template_ref IS DISTINCT FROM v_after.plain_language_template_ref
            OR v_before.validity_check_fn_ref       IS DISTINCT FROM v_after.validity_check_fn_ref;

  IF v_changed THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='REVIEW_ISSUE_TYPE_REGISTERED',
      p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
      p_subject_id:=public.gen_uuid_v7(),
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='issue_type_registry',
      p_organization_id:=NULL, p_business_id:=NULL,
      p_before_state:=CASE WHEN v_before.issue_type IS NULL THEN NULL ELSE row_to_json(v_before)::jsonb END,
      p_after_state:=row_to_json(v_after)::jsonb,
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'decision', 'ALLOW',
    'issue_type', p_issue_type,
    'changed', v_changed,
    'was_insert', v_before.issue_type IS NULL);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_and_persist_card_content(p_issue_id uuid, p_simulate_ai_failure boolean DEFAULT false, p_actor_system text DEFAULT 'review_queue'::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue   record;
  v_reg     record;
  v_tier    public.review_issue_card_content_tier_enum;
  v_title   text;
  v_desc    text;
  v_action  text;
BEGIN
  SELECT id, organization_id, business_id, transaction_id, document_id, match_record_id,
         draft_ledger_entry_id, invoice_id, client_id, issue_type, issue_group, severity,
         card_payload_json, status
    INTO v_issue
    FROM public.review_issues WHERE id = p_issue_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'generate_and_persist_card_content: issue % not found', p_issue_id USING ERRCODE='02000';
  END IF;

  SELECT issue_type, default_group, default_severity, allowed_resolution_actions,
         producing_block, plain_language_template_ref
    INTO v_reg
    FROM public.issue_type_registry WHERE issue_type = v_issue.issue_type;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'generate_and_persist_card_content: issue_type % not in registry', v_issue.issue_type USING ERRCODE='23503';
  END IF;

  IF p_simulate_ai_failure THEN
    -- Defer to the fallback handler — single source of truth for fallback shape.
    RETURN public.handle_card_content_failure(p_issue_id, 'simulated', p_context);
  END IF;

  v_tier := public._compute_card_content_tier(p_issue_id);

  -- Deterministic stub generation (full AI pipeline is app-layer Block 06 P10).
  v_title  := left(format('%s on %s', v_issue.issue_group::text, v_reg.producing_block), 80);
  v_desc   := left(format(
    'Issue %s (%s). Severity %s. Bucket: %s. Producing block: %s. Generated by %s pipeline.',
    v_issue.issue_type, v_reg.plain_language_template_ref, v_issue.severity::text,
    v_issue.issue_group::text, v_reg.producing_block, v_tier::text), 300);
  v_action := left(
    COALESCE(v_reg.allowed_resolution_actions[1], 'ACKNOWLEDGE') ||
    CASE WHEN v_issue.transaction_id IS NOT NULL
         THEN ' for transaction ' || substr(v_issue.transaction_id::text, 1, 8)
         ELSE '' END, 120);

  UPDATE public.review_issues
     SET plain_language_title         = v_title,
         plain_language_description   = v_desc,
         recommended_action           = v_action,
         card_content_generated_at    = clock_timestamp(),
         card_content_tier_used       = v_tier,
         card_content_fallback_applied = false,
         updated_at                   = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='REVIEW_CARD_CONTENT_GENERATED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:=p_actor_system,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'tier_used', v_tier::text,
      'fallback_applied', false,
      'title_len', length(v_title),
      'description_len', length(v_desc),
      'recommended_action_len', length(v_action)),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'tier_used', v_tier::text,
    'was_fallback', false,
    'issue_id', p_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_preview(p_actor_user_id uuid, p_business_id uuid, p_action_kind resolution_action_kind_enum, p_issue_ids uuid[], p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_perm           jsonb;
  v_org            uuid;
  v_action_text    text := p_action_kind::text;
  v_will_apply     uuid[] := '{}';
  v_summary        jsonb;
  v_token_id       uuid;
  v_bucket         public.review_issue_group_enum := NULL;
  v_cnt_will_apply         int := 0;
  v_cnt_skip_closed        int := 0;
  v_cnt_skip_diff_bucket   int := 0;
  v_cnt_skip_diff_business int := 0;
  v_cnt_skip_not_allowed   int := 0;
  v_cnt_skip_blocking      int := 0;
  v_cnt_not_found          int := 0;
  v_rec record;
  v_rec_business_id uuid;
  v_rec_issue_group public.review_issue_group_enum;
  v_rec_severity    public.review_issue_severity_enum;
  v_rec_status      public.review_issue_status_enum;
  v_rec_reg_actions text[];
BEGIN
  IF p_issue_ids IS NULL OR cardinality(p_issue_ids) = 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','EMPTY_ISSUE_IDS');
  END IF;

  -- Resolve org via business_entities
  SELECT organization_id INTO v_org FROM public.business_entities WHERE id = p_business_id;
  IF v_org IS NULL THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','UNKNOWN_BUSINESS');
  END IF;

  -- One-shot permission check for the bulk surface
  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_RESOLVE', 'EXECUTE',
                               '{}'::jsonb, p_business_id, v_org);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  -- First pass: derive the bucket from the first OPEN+same-business issue
  FOR v_rec IN
    SELECT ri.id, ri.business_id, ri.issue_group, ri.severity, ri.status,
           itr.allowed_resolution_actions
      FROM unnest(p_issue_ids) WITH ORDINALITY AS u(id, ord)
      JOIN public.review_issues ri ON ri.id = u.id
      LEFT JOIN public.issue_type_registry itr ON itr.issue_type = ri.issue_type
     WHERE ri.business_id = p_business_id
       AND ri.status = 'OPEN'::public.review_issue_status_enum
     ORDER BY u.ord
     LIMIT 1
  LOOP
    v_bucket := v_rec.issue_group;
  END LOOP;

  -- Main pass: classify each candidate
  FOR v_rec IN
    SELECT u.id AS candidate_id,
           ri.id AS ri_id,
           ri.business_id, ri.issue_group, ri.severity, ri.status,
           itr.allowed_resolution_actions
      FROM unnest(p_issue_ids) WITH ORDINALITY AS u(id, ord)
      LEFT JOIN public.review_issues ri ON ri.id = u.id
      LEFT JOIN public.issue_type_registry itr ON itr.issue_type = ri.issue_type
     ORDER BY u.ord
  LOOP
    IF v_rec.ri_id IS NULL THEN
      v_cnt_not_found := v_cnt_not_found + 1;
      CONTINUE;
    END IF;

    IF v_rec.business_id <> p_business_id THEN
      v_cnt_skip_diff_business := v_cnt_skip_diff_business + 1;
      CONTINUE;
    END IF;

    IF v_rec.status <> 'OPEN'::public.review_issue_status_enum THEN
      v_cnt_skip_closed := v_cnt_skip_closed + 1;
      CONTINUE;
    END IF;

    IF v_bucket IS NOT NULL AND v_rec.issue_group <> v_bucket THEN
      v_cnt_skip_diff_bucket := v_cnt_skip_diff_bucket + 1;
      CONTINUE;
    END IF;

    IF v_rec.allowed_resolution_actions IS NULL
       OR NOT (v_action_text = ANY(v_rec.allowed_resolution_actions)) THEN
      v_cnt_skip_not_allowed := v_cnt_skip_not_allowed + 1;
      CONTINUE;
    END IF;

    IF p_action_kind = 'IGNORE_WITH_REASON'::public.resolution_action_kind_enum
       AND v_rec.severity = 'BLOCKING'::public.review_issue_severity_enum THEN
      v_cnt_skip_blocking := v_cnt_skip_blocking + 1;
      CONTINUE;
    END IF;

    v_will_apply := v_will_apply || v_rec.ri_id;
    v_cnt_will_apply := v_cnt_will_apply + 1;
  END LOOP;

  v_summary := jsonb_build_object(
    'will_apply', v_cnt_will_apply,
    'skip_already_closed', v_cnt_skip_closed,
    'skip_different_bucket', v_cnt_skip_diff_bucket,
    'skip_different_business', v_cnt_skip_diff_business,
    'skip_not_allowed_for_issue_type', v_cnt_skip_not_allowed,
    'skip_blocking_dismissal', v_cnt_skip_blocking,
    'not_found', v_cnt_not_found);

  IF v_cnt_will_apply = 0 THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_BULK_PREVIEW_REQUESTED',
      p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
      p_subject_id:=public.gen_uuid_v7(),
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_org, p_business_id:=p_business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'action_kind', v_action_text, 'token_created', false, 'summary', v_summary),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','NO_APPLICABLE_ISSUES',
                              'summary', v_summary);
  END IF;

  INSERT INTO public.bulk_preview_tokens (
    organization_id, business_id, actor_user_id,
    action_kind, affected_issue_ids
  ) VALUES (
    v_org, p_business_id, p_actor_user_id,
    v_action_text, v_will_apply
  ) RETURNING id INTO v_token_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_BULK_PREVIEW_REQUESTED',
    p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
    p_subject_id:=v_token_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_org, p_business_id:=p_business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'action_kind', v_action_text, 'token_id', v_token_id,
      'bucket', v_bucket::text, 'summary', v_summary),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'token_id', v_token_id,
    'bucket', v_bucket::text,
    'will_apply_count', v_cnt_will_apply,
    'summary', v_summary);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notes_update(p_actor_user_id uuid, p_issue_id uuid, p_notes_text text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue   record;
  v_perm    jsonb;
  v_guard   jsonb;
  v_before  text;
  v_after   text;
BEGIN
  SELECT id, organization_id, business_id, resolution_note
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;

  v_guard := public._check_form_factor_guard('NOTES_UPDATE', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_RESOLVE', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  v_before := v_issue.resolution_note;
  v_after  := NULLIF(p_notes_text, '');

  UPDATE public.review_issues
     SET resolution_note = v_after, updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_NOTE_UPDATED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('resolution_note', v_before),
    p_after_state:=jsonb_build_object('resolution_note', v_after),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW',
                            'before', v_before, 'after', v_after, 'issue_id', p_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.dispatch_assignment_notification(p_issue_id uuid, p_assignee_user_id uuid, p_simulate_failure boolean DEFAULT false, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue       record;
  v_inbox_id    uuid;
  v_failure_id  uuid;
  v_owner       record;
BEGIN
  SELECT id, organization_id, business_id,
         transaction_id, document_id, match_record_id, draft_ledger_entry_id,
         invoice_id, client_id, workflow_run_id, issue_type
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;

  IF p_simulate_failure THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='REVIEW_ASSIGNMENT_NOTIFICATION_FAILED',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='notification_dispatcher',
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'channels_failed', ARRAY['in_app','email'],
        'attempted_assignee', p_assignee_user_id,
        'reason', 'simulated'),
      p_reason:=NULL, p_request_context:=p_context);

    -- Create the failure issue (anchor on the original issue's primary entity).
    INSERT INTO public.review_issues (
      organization_id, business_id, workflow_run_id,
      transaction_id, document_id, match_record_id, draft_ledger_entry_id,
      invoice_id, client_id,
      issue_type, issue_group, severity,
      plain_language_title, plain_language_description, recommended_action,
      card_payload_json, card_content_generated_at,
      card_content_tier_used, card_content_fallback_applied, status
    ) VALUES (
      v_issue.organization_id, v_issue.business_id, v_issue.workflow_run_id,
      v_issue.transaction_id, v_issue.document_id, v_issue.match_record_id, v_issue.draft_ledger_entry_id,
      v_issue.invoice_id, v_issue.client_id,
      'review_queue.notification_dispatch_failed',
      'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
      'HIGH'::public.review_issue_severity_enum,
      'Assignment notification failed',
      'A notification for an assignment could not be delivered. Re-run scan to retry, or document the cause.',
      'RERUN_SCAN_AFTER_CHANGE',
      jsonb_build_object('originating_issue_id', p_issue_id,
                         'attempted_assignee_user_id', p_assignee_user_id),
      clock_timestamp(),
      'NONE'::public.review_issue_card_content_tier_enum,
      false,
      'OPEN'::public.review_issue_status_enum
    ) RETURNING id INTO v_failure_id;

    -- Route to all Owner-role users via in-app inbox only.
    FOR v_owner IN
      SELECT bur.user_id
        FROM public.business_user_roles bur
       WHERE bur.business_id = v_issue.business_id
         AND bur.role = 'OWNER'::public.user_role
    LOOP
      INSERT INTO public.notification_inbox (
        recipient_user_id, organization_id, business_id,
        kind, payload
      ) VALUES (
        v_owner.user_id, v_issue.organization_id, v_issue.business_id,
        'REVIEW_NOTIFICATION_FAILURE',
        jsonb_build_object(
          'failure_issue_id', v_failure_id,
          'originating_issue_id', p_issue_id,
          'attempted_assignee_user_id', p_assignee_user_id));
    END LOOP;

    RETURN jsonb_build_object(
      'decision','ALLOW',
      'delivered', false,
      'failure_issue_id', v_failure_id);
  END IF;

  -- Happy path: write to in-app inbox.
  INSERT INTO public.notification_inbox (
    recipient_user_id, organization_id, business_id,
    kind, payload, delivered_at
  ) VALUES (
    p_assignee_user_id, v_issue.organization_id, v_issue.business_id,
    'REVIEW_ASSIGNMENT',
    jsonb_build_object('issue_id', p_issue_id, 'issue_type', v_issue.issue_type),
    clock_timestamp()
  ) RETURNING id INTO v_inbox_id;

  UPDATE public.review_issues
     SET assignment_notification_sent_at = clock_timestamp(),
         updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='REVIEW_ASSIGNMENT_NOTIFICATION_DISPATCHED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='notification_dispatcher',
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'inbox_id', v_inbox_id,
      'assignee_user_id', p_assignee_user_id,
      'channels_succeeded', ARRAY['in_app'],
      'channels_failed', ARRAY[]::text[]),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW', 'delivered', true, 'inbox_id', v_inbox_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._apply_object_lock_stub(p_archive_package_id uuid, p_attempt integer, p_context jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_mode text;
BEGIN
  v_mode := COALESCE(p_context->>'simulate_step_5_failure', '');
  IF v_mode = 'PERSISTENT' THEN
    RETURN jsonb_build_object('ok', false, 'mode', 'PERSISTENT');
  ELSIF v_mode = 'TRANSIENT' AND p_attempt = 1 THEN
    RETURN jsonb_build_object('ok', false, 'mode', 'TRANSIENT');
  END IF;
  RETURN jsonb_build_object('ok', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.review_queue_reassign(p_actor_user_id uuid, p_issue_id uuid, p_new_assignee_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_prior_assignee uuid;
BEGIN
  SELECT assigned_to INTO v_prior_assignee
    FROM public.review_issues WHERE id = p_issue_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;
  IF v_prior_assignee IS NULL THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','NO_PRIOR_ASSIGNMENT');
  END IF;

  RETURN public.review_queue_assign(p_actor_user_id, p_issue_id, p_new_assignee_user_id, p_context);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.execute_lock_sequence(p_run_id uuid, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'archive', 'pg_temp'
AS $function$
DECLARE
  v_run public.workflow_runs;
  v_pkg_id uuid;
  v_locked_count int;
  v_hash_check jsonb;
  v_lock_result jsonb;
  v_attempt int := 0;
  v_max_attempts constant int := 2;
  v_committed boolean := false;
  v_last_error text;
  v_failing_step int;
  v_t jsonb;
  v_period_start date;
  v_period_end date;
  v_issue_id uuid;
  v_anchor_txn_id uuid;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','ERROR','reason','RUN_NOT_FOUND'); END IF;

  IF v_run.status = 'FINALIZED'::public.workflow_run_status_enum THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_NO_OP_ALREADY_FINALIZED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_system:='finalization_lock_sequence',
      p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
      p_after_state:=jsonb_build_object('archive_package_id', v_run.archive_package_id));
    RETURN jsonb_build_object('decision','NO_OP','reason','ALREADY_FINALIZED',
                              'archive_package_id', v_run.archive_package_id);
  END IF;

  v_period_start := v_run.period_start::date;
  v_period_end   := v_run.period_end::date;
  SELECT id INTO v_anchor_txn_id FROM public.transactions
   WHERE business_id = v_run.business_id
     AND transaction_date BETWEEN v_period_start AND v_period_end
   ORDER BY id LIMIT 1;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_LOCK_STARTED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_lock_sequence',
    p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
    p_after_state:=jsonb_build_object('run_id', p_run_id,
      'period_start', v_period_start, 'period_end', v_period_end,
      'actor_user_id', p_actor_user_id),
    p_request_context:=p_context);

  v_hash_check := public._verify_evidence_hashes(p_run_id, v_run.business_id, v_run.period_start, v_run.period_end);
  IF NOT (v_hash_check->>'ok')::boolean THEN
    INSERT INTO public.review_issues (organization_id, business_id, workflow_run_id, transaction_id,
      client_id, issue_type, issue_group, severity, plain_language_title, plain_language_description,
      card_payload_json, status)
    VALUES (v_run.organization_id, v_run.business_id, p_run_id, v_anchor_txn_id, NULL,
            'finalization.evidence_hash_mismatch',
            'MISSING_DOCUMENTS'::public.review_issue_group_enum,
            'BLOCKING'::public.review_issue_severity_enum,
            'Evidence hashes failed verification',
            'One or more documents or evidence PDFs have missing or malformed file hashes; cannot finalize.',
            v_hash_check, 'OPEN'::public.review_issue_status_enum)
    RETURNING id INTO v_issue_id;
    PERFORM public._emit_finalization_failure(p_run_id, v_run.business_id, v_run.organization_id,
              2, 'evidence_hash_mismatch', false, p_context);
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_LOCK_ROLLED_BACK',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_system:='finalization_lock_sequence',
      p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
      p_after_state:=jsonb_build_object('failing_step', 2, 'reason', 'EVIDENCE_HASH_MISMATCH',
                                         'review_issue_id', v_issue_id, 'detail', v_hash_check));
    PERFORM public._emit_persistent_failure(p_run_id, v_run.business_id, v_run.organization_id,
              'evidence_hash_mismatch', 'BLOCKING', v_issue_id, p_context);
    RETURN jsonb_build_object('decision','BLOCKED','reason','EVIDENCE_HASH_MISMATCH',
                              'review_issue_id', v_issue_id, 'detail', v_hash_check);
  END IF;

  FOR v_attempt IN 1..v_max_attempts LOOP
    IF v_attempt = 2 THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_LOCK_RETRY_FIRED',
        p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
        p_actor_system:='finalization_lock_sequence',
        p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
        p_after_state:=jsonb_build_object('attempt', 2, 'last_error', v_last_error));
    END IF;
    BEGIN
      SELECT status INTO v_run.status FROM public.workflow_runs WHERE id = p_run_id;
      IF v_run.status = 'AWAITING_APPROVAL'::public.workflow_run_status_enum THEN
        v_t := public.transition_run(p_run_id, 'FINALIZING'::public.workflow_run_status_enum,
                                     p_actor_user_id, 'lock_sequence_started', true, p_context);
        IF NOT (v_t->>'ok')::boolean THEN
          RAISE EXCEPTION 'TRANSITION_FAILED: % %', v_t->>'reason', v_t->>'message' USING ERRCODE='P0001';
        END IF;
      END IF;
      v_pkg_id := public._construct_archive_bundle_stub(p_run_id, v_run.business_id,
                    v_run.organization_id, v_period_start, v_period_end, p_actor_user_id);
      v_locked_count := public._promote_to_locked_ledger(p_run_id, v_run.business_id,
                          v_run.organization_id, v_period_start, v_period_end, v_pkg_id);
      v_lock_result := public._apply_object_lock_stub(v_pkg_id, v_attempt, p_context);
      IF NOT (v_lock_result->>'ok')::boolean THEN
        v_failing_step := 5;
        RAISE EXCEPTION 'OBJECT_LOCK_FAILED: %', v_lock_result->>'mode' USING ERRCODE='P0001';
      END IF;
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_OBJECT_LOCK_APPLIED',
        p_subject_type:='ARCHIVE_PACKAGE'::audit.subject_type_enum, p_subject_id:=v_pkg_id,
        p_actor_system:='finalization_lock_sequence',
        p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
        p_after_state:=jsonb_build_object('archive_package_id', v_pkg_id, 'retention_window_years', 6));
      v_t := public.transition_run(p_run_id, 'FINALIZED'::public.workflow_run_status_enum,
                                   p_actor_user_id, 'lock_sequence_committed', true, p_context);
      IF NOT (v_t->>'ok')::boolean THEN
        v_failing_step := 6;
        RAISE EXCEPTION 'TRANSITION_FAILED: % %', v_t->>'reason', v_t->>'message' USING ERRCODE='P0001';
      END IF;
      PERFORM set_config('app.transition_run_active', 'true', true);
      UPDATE public.workflow_runs SET archive_package_id = v_pkg_id WHERE id = p_run_id;
      PERFORM set_config('app.transition_run_active', 'false', true);
      v_committed := true;
      EXIT;
    EXCEPTION WHEN OTHERS THEN
      v_last_error := SQLERRM;
      -- B15·P09: canonical FAILURE_DETECTED + existing ROLLED_BACK
      PERFORM public._emit_finalization_failure(p_run_id, v_run.business_id, v_run.organization_id,
                COALESCE(v_failing_step, 0),
                CASE COALESCE(v_failing_step, 0)
                  WHEN 5 THEN 'object_lock_failed'
                  WHEN 6 THEN 'state_transition_conflict'
                  ELSE 'lock_sequence_failed'
                END,
                true,
                p_context);
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_LOCK_ROLLED_BACK',
        p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
        p_actor_system:='finalization_lock_sequence',
        p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
        p_after_state:=jsonb_build_object('attempt', v_attempt,
                                           'failing_step', COALESCE(v_failing_step, 0),
                                           'error', v_last_error));
      SELECT status INTO v_run.status FROM public.workflow_runs WHERE id = p_run_id;
      IF v_run.status = 'FINALIZING'::public.workflow_run_status_enum THEN
        v_t := public.transition_run(p_run_id, 'AWAITING_APPROVAL'::public.workflow_run_status_enum,
                                     p_actor_user_id, 'lock_sequence_rolled_back', true, p_context);
      END IF;
      DELETE FROM public.archive_manifests WHERE archive_package_id = v_pkg_id;
      DELETE FROM public.archive_packages  WHERE id                = v_pkg_id;
      v_pkg_id := NULL;
    END;
  END LOOP;

  IF NOT v_committed THEN
    INSERT INTO public.review_issues (organization_id, business_id, workflow_run_id, transaction_id,
      client_id, issue_type, issue_group, severity, plain_language_title, plain_language_description,
      card_payload_json, status)
    VALUES (v_run.organization_id, v_run.business_id, p_run_id, v_anchor_txn_id,
            (SELECT id FROM public.clients WHERE business_id=v_run.business_id ORDER BY id LIMIT 1),
            'finalization.object_lock_failed',
            'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
            'HIGH'::public.review_issue_severity_enum,
            'Lock sequence failed after retry',
            'The finalization lock sequence failed twice; please contact support.',
            jsonb_build_object('last_error', v_last_error),
            'OPEN'::public.review_issue_status_enum)
    RETURNING id INTO v_issue_id;
    PERFORM public._emit_persistent_failure(p_run_id, v_run.business_id, v_run.organization_id,
              'object_lock_failed', 'HIGH', v_issue_id, p_context);
    RETURN jsonb_build_object('decision','FAILED','reason','LOCK_SEQUENCE_EXHAUSTED',
                              'last_error', v_last_error, 'review_issue_id', v_issue_id);
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_LOCK_COMMITTED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_lock_sequence',
    p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
    p_after_state:=jsonb_build_object('run_id', p_run_id, 'archive_package_id', v_pkg_id,
      'manifest_version', 1, 'principal_user_id', p_actor_user_id,
      'locked_ledger_count', v_locked_count));
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ARCHIVE_PROMOTION_COMPLETED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_lock_sequence',
    p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
    p_after_state:=jsonb_build_object('archive_package_id', v_pkg_id, 'manifest_version_number', 1,
      'business_id', v_run.business_id,
      'period_start', v_period_start, 'period_end', v_period_end));

  RETURN jsonb_build_object('decision','COMMITTED', 'archive_package_id', v_pkg_id,
                            'locked_ledger_count', v_locked_count, 'manifest_version', 1);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.request_export(p_business_id uuid, p_organization_id uuid, p_export_kind text, p_format export_format_enum, p_period_start date DEFAULT NULL::date, p_period_end date DEFAULT NULL::date, p_workflow_run_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_source_data_hash text DEFAULT NULL::text, p_force_regenerate boolean DEFAULT false, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_cat public.export_catalogue_definitions;
  v_can jsonb;
  v_existing public.exports;
  v_new_id uuid := public.gen_uuid_v7();
BEGIN
  IF p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'request_export: actor_user_id required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_cat FROM public.export_catalogue_definitions WHERE export_kind = p_export_kind;
  IF NOT FOUND THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='EXPORT_REQUEST_REJECTED_INVALID_FORMAT',
      p_subject_type:='USER'::audit.subject_type_enum, p_subject_id:=p_actor_user_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('export_kind', p_export_kind,
                                         'reason','UNKNOWN_EXPORT_KIND'),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','REJECTED','reason','UNKNOWN_EXPORT_KIND');
  END IF;

  -- Permission gate
  v_can := public.can_perform(p_actor_user_id, v_cat.permission_surface, 'EXPORT',
                               jsonb_build_object('export_kind', p_export_kind, 'format', p_format::text),
                               p_business_id, p_organization_id);
  IF v_can->>'decision' NOT IN ('ALLOW','STEP_UP','REQUIRE_STEP_UP') THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='EXPORT_REQUEST_REJECTED_PERMISSION',
      p_subject_type:='USER'::audit.subject_type_enum, p_subject_id:=p_actor_user_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('export_kind', p_export_kind,
                                         'format', p_format::text,
                                         'permission_surface', v_cat.permission_surface,
                                         'can_perform', v_can),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','REJECTED','reason','PERMISSION','can_perform', v_can);
  END IF;

  -- Format-validity gate
  IF NOT (p_format = ANY(v_cat.supported_formats)) THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='EXPORT_REQUEST_REJECTED_INVALID_FORMAT',
      p_subject_type:='USER'::audit.subject_type_enum, p_subject_id:=p_actor_user_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('export_kind', p_export_kind,
                                         'requested_format', p_format::text,
                                         'supported_formats', to_jsonb(v_cat.supported_formats)),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','REJECTED','reason','INVALID_FORMAT',
                              'supported_formats', to_jsonb(v_cat.supported_formats));
  END IF;

  -- Idempotency (data-hash dedup)
  IF p_source_data_hash IS NOT NULL AND NOT p_force_regenerate THEN
    SELECT * INTO v_existing FROM public.exports
     WHERE business_id  = p_business_id
       AND export_kind  = p_export_kind
       AND format       = p_format
       AND status       = 'COMPLETED'::public.export_status_enum
       AND source_data_hash = p_source_data_hash
     ORDER BY completed_at DESC LIMIT 1;
    IF FOUND THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='EXPORT_REQUESTED',
        p_subject_type:='USER'::audit.subject_type_enum, p_subject_id:=p_actor_user_id,
        p_actor_user_id:=p_actor_user_id,
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_after_state:=jsonb_build_object('export_id', v_existing.id,
                                           'export_kind', p_export_kind,
                                           'format', p_format::text,
                                           'cached', true,
                                           'source_data_hash', p_source_data_hash),
        p_request_context:=p_context);
      RETURN jsonb_build_object('decision','CACHED',
                                'export_id', v_existing.id,
                                'status', v_existing.status,
                                'source','CACHED');
    END IF;
  END IF;

  -- New export row
  INSERT INTO public.exports (id, organization_id, business_id, workflow_run_id,
    export_kind, format, period_start, period_end, requested_by_user_id,
    requested_at, status, source_data_hash)
  VALUES (v_new_id, p_organization_id, p_business_id, p_workflow_run_id,
          p_export_kind, p_format, p_period_start, p_period_end, p_actor_user_id,
          clock_timestamp(), 'PENDING'::public.export_status_enum, p_source_data_hash);

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='EXPORT_REQUESTED',
    p_subject_type:='USER'::audit.subject_type_enum, p_subject_id:=p_actor_user_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('export_id', v_new_id,
                                       'export_kind', p_export_kind,
                                       'format', p_format::text,
                                       'period_start', p_period_start,
                                       'period_end', p_period_end,
                                       'force_regenerate', p_force_regenerate,
                                       'cached', false),
    p_request_context:=p_context);

  RETURN jsonb_build_object('decision','QUEUED',
                            'export_id', v_new_id,
                            'status','PENDING');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_approval_recorded(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_approval record;
BEGIN
  SELECT id, approval_method::text AS m, revoked_at
    INTO v_approval FROM public.workflow_run_approvals
   WHERE run_id = p_run_id
   ORDER BY created_at DESC LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','approval_recorded',
      'payload', jsonb_build_object('reason','NO_APPROVAL_FOUND'));
  END IF;
  IF v_approval.revoked_at IS NOT NULL THEN
    RETURN jsonb_build_object('decision','HOLD','gate','approval_recorded',
      'payload', jsonb_build_object('reason','APPROVAL_REVOKED',
                                     'approval_id', v_approval.id));
  END IF;
  IF v_approval.m <> 'STEP_UP' THEN
    RETURN jsonb_build_object('decision','HOLD','gate','approval_recorded',
      'payload', jsonb_build_object('reason','APPROVAL_NOT_STEP_UP',
                                     'approval_method', v_approval.m));
  END IF;
  RETURN jsonb_build_object('decision','ADVANCE','gate','approval_recorded',
    'payload', jsonb_build_object('approval_id', v_approval.id));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.review_queue_clear_assignment(p_actor_user_id uuid, p_issue_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue       record;
  v_perm        jsonb;
BEGIN
  SELECT id, organization_id, business_id, assigned_to
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;
  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_ASSIGN', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;
  IF v_issue.assigned_to IS NULL THEN
    RETURN jsonb_build_object('decision','ALLOW','noop',true,'reason','ALREADY_UNASSIGNED');
  END IF;

  UPDATE public.review_issues
     SET assigned_to = NULL,
         assigned_by = NULL,
         assigned_at = NULL,
         assignment_notification_sent_at = NULL,
         updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_ASSIGNMENT_CLEARED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('assigned_to', v_issue.assigned_to),
    p_after_state:=jsonb_build_object('assigned_to', NULL),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW', 'prior_assignee', v_issue.assigned_to);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_resolution_action(p_actor_user_id uuid, p_issue_id uuid, p_action resolution_action_kind_enum, p_payload jsonb DEFAULT '{}'::jsonb, p_note text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue       record;
  v_reg         record;
  v_perm        jsonb;
  v_guard       jsonb;
  v_status_after public.review_issue_status_enum;
  v_keeps_open   boolean := false;
  v_terminal     public.review_issue_status_enum := 'RESOLVED'::public.review_issue_status_enum;
  v_downstream   text;
  v_action_text  text := p_action::text;
  v_assign_result jsonb;
  v_rescan_result jsonb;
BEGIN
  SELECT id, organization_id, business_id, transaction_id, document_id, match_record_id,
         draft_ledger_entry_id, invoice_id, client_id, workflow_run_id,
         issue_type, issue_group, severity, status, assigned_to
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND'); END IF;

  v_guard := public._check_form_factor_guard('APPLY_RESOLUTION_ACTION', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  SELECT issue_type, allowed_resolution_actions, producing_block
    INTO v_reg FROM public.issue_type_registry WHERE issue_type = v_issue.issue_type;

  IF v_issue.status IN ('RESOLVED'::public.review_issue_status_enum,
                        'DISMISSED'::public.review_issue_status_enum,
                        'AUTO_RESOLVED_BY_RESCAN'::public.review_issue_status_enum) THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_RESOLUTION_REJECTED_NOOP',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('attempted_action', v_action_text, 'current_status', v_issue.status::text),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_ALREADY_CLOSED',
                              'status_after', v_issue.status::text, 'noop', true);
  END IF;

  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_RESOLVE', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_RESOLUTION_REJECTED_PERMISSION',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('attempted_action', v_action_text, 'reason_code', v_perm->>'reason_code'),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  IF v_reg.allowed_resolution_actions IS NULL OR NOT (v_action_text = ANY(v_reg.allowed_resolution_actions)) THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_RESOLUTION_REJECTED_DISALLOWED_ACTION',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('attempted_action', v_action_text,
                                         'allowed', v_reg.allowed_resolution_actions),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','ACTION_NOT_ALLOWED_FOR_ISSUE_TYPE');
  END IF;

  IF p_action = 'IGNORE_WITH_REASON'::public.resolution_action_kind_enum
     AND v_issue.severity = 'BLOCKING'::public.review_issue_severity_enum THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_RESOLUTION_REJECTED_BLOCKING_DISMISSAL',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('severity', v_issue.severity::text),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','BLOCKING_CANNOT_BE_DISMISSED');
  END IF;

  CASE p_action
    WHEN 'CONFIRM_MATCH'::public.resolution_action_kind_enum THEN
      v_downstream := 'public.user_confirm_match';
      IF v_issue.match_record_id IS NOT NULL THEN
        PERFORM public.user_confirm_match(v_issue.match_record_id, p_actor_user_id,
                                          COALESCE(p_payload->>'counterparty_signature',''), p_context);
      END IF;
    WHEN 'REJECT_MATCH'::public.resolution_action_kind_enum THEN
      v_downstream := 'public.user_reject_match';
      IF v_issue.match_record_id IS NOT NULL THEN
        PERFORM public.user_reject_match(v_issue.match_record_id, p_actor_user_id,
                                         COALESCE(p_payload->>'rejection_reason','user_rejected'), p_context);
      END IF;
    WHEN 'MARK_AS_NO_INVOICE_AVAILABLE'::public.resolution_action_kind_enum THEN
      IF COALESCE(p_payload->>'reason','') = '' THEN
        RETURN jsonb_build_object('decision','DENY','reason_code','REASON_REQUIRED');
      END IF;
      v_downstream := 'public.out_workflow_document_exception';
      IF v_issue.workflow_run_id IS NOT NULL AND v_issue.transaction_id IS NOT NULL THEN
        PERFORM public.out_workflow_document_exception(
          v_issue.organization_id, v_issue.business_id, v_issue.workflow_run_id,
          v_issue.transaction_id, p_payload->>'reason', p_actor_user_id, p_context);
      END IF;
    WHEN 'CHANGE_TAG'::public.resolution_action_kind_enum THEN
      v_downstream := 'transactions.tag UPDATE (Block 08 path — Stage-1 stub)';
    WHEN 'CHANGE_TRANSACTION_TYPE'::public.resolution_action_kind_enum,
         'MARK_AS_INTERNAL_TRANSFER'::public.resolution_action_kind_enum,
         'MARK_AS_BANK_FEE'::public.resolution_action_kind_enum THEN
      v_downstream := 'transactions.transaction_type UPDATE (Block 08 path — Stage-1 stub)';
    WHEN 'MARK_AS_NON_DEDUCTIBLE'::public.resolution_action_kind_enum THEN
      v_downstream := 'draft_ledger_entries non-deductible UPDATE (Block 11 path — Stage-1 stub)';
    WHEN 'UPLOAD_DOCUMENT'::public.resolution_action_kind_enum THEN
      v_downstream := 'intake.manual_upload_handler (Block 09 — Stage-1 stub)';
    WHEN 'ADD_EXPLANATION_NOTE'::public.resolution_action_kind_enum THEN
      IF COALESCE(p_note,'') = '' THEN
        RETURN jsonb_build_object('decision','DENY','reason_code','NOTE_REQUIRED');
      END IF;
      v_keeps_open := true;
      v_downstream := 'review_issues.resolution_note UPDATE';
    WHEN 'SEND_TO_ACCOUNTANT_REVIEW'::public.resolution_action_kind_enum THEN
      IF (p_payload->>'assigned_to') IS NULL THEN
        RETURN jsonb_build_object('decision','DENY','reason_code','ASSIGNED_TO_REQUIRED');
      END IF;
      v_keeps_open := true;
      v_downstream := 'public.review_queue_assign';
      v_assign_result := public.review_queue_assign(
        p_actor_user_id, p_issue_id,
        (p_payload->>'assigned_to')::uuid, p_context);
      IF (v_assign_result->>'decision') <> 'ALLOW' THEN RETURN v_assign_result; END IF;
    WHEN 'IGNORE_WITH_REASON'::public.resolution_action_kind_enum THEN
      IF COALESCE(p_note,'') = '' THEN
        RETURN jsonb_build_object('decision','DENY','reason_code','REASON_REQUIRED');
      END IF;
      v_terminal := 'DISMISSED'::public.review_issue_status_enum;
      v_downstream := 'review_issues.status → DISMISSED';
    WHEN 'RERUN_SCAN_AFTER_CHANGE'::public.resolution_action_kind_enum THEN
      v_keeps_open := true;
      v_downstream := 'public.rescan_manually';
      IF v_issue.workflow_run_id IS NOT NULL THEN
        PERFORM public.rescan_manually(v_issue.workflow_run_id, p_actor_user_id, p_context);
      END IF;
  END CASE;

  IF v_keeps_open THEN
    v_status_after := v_issue.status;
    IF p_action = 'ADD_EXPLANATION_NOTE'::public.resolution_action_kind_enum THEN
      UPDATE public.review_issues
         SET resolution_note = p_note, updated_at = clock_timestamp()
       WHERE id = p_issue_id;
    END IF;
  ELSE
    v_status_after := v_terminal;
    UPDATE public.review_issues
       SET status            = v_terminal,
           resolution_action = p_action,
           resolution_note   = p_note,
           resolved_at       = clock_timestamp(),
           resolved_by       = p_actor_user_id,
           updated_at        = clock_timestamp()
     WHERE id = p_issue_id;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_RESOLUTION_APPLIED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('status', v_issue.status::text,
                                        'assigned_to', v_issue.assigned_to),
    p_after_state:=jsonb_build_object(
      'action', v_action_text, 'status', v_status_after::text,
      'downstream_rpc', v_downstream, 'payload', p_payload,
      'note_present', p_note IS NOT NULL,
      'actor_was_assignee', v_issue.assigned_to IS NOT NULL AND v_issue.assigned_to = p_actor_user_id),
    p_reason:=NULL, p_request_context:=p_context);

  IF NOT v_keeps_open THEN
    BEGIN
      v_rescan_result := public.rescan_for_resolved_issue(
        p_issue_id, v_issue.workflow_run_id, p_actor_user_id, p_context);
    EXCEPTION WHEN OTHERS THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
        p_action:='REVIEW_RESCAN_REVALIDATION_FAILED',
        p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
        p_subject_id:=p_issue_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
        p_actor_system:='review_queue_dispatcher',
        p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
        p_before_state:=NULL,
        p_after_state:=jsonb_build_object('sqlstate', SQLSTATE, 'message', SQLERRM,
          'context', 'invoked from apply_resolution_action terminal path'),
        p_reason:=NULL, p_request_context:=p_context);
    END;
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='REVIEW_GATE_REEVALUATION_REQUESTED',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='review_queue_dispatcher',
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('triggering_resolution_issue_id', p_issue_id,
                                         'triggering_workflow_run_id', v_issue.workflow_run_id),
      p_reason:=NULL, p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object(
    'decision', 'ALLOW', 'action', v_action_text,
    'status_after', v_status_after::text, 'downstream_rpc', v_downstream,
    'gate_reevaluation_triggered', NOT v_keeps_open, 'rescan', v_rescan_result);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_audit_log_quiescent(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_recent int;
BEGIN
  SELECT count(*) INTO v_recent FROM audit.audit_events
   WHERE subject_type = 'WORKFLOW_RUN'::audit.subject_type_enum
     AND subject_id = p_run_id
     AND created_at > clock_timestamp() - interval '5 seconds'
     AND action NOT LIKE 'FINALIZATION_%'
     AND action <> 'WORKFLOW_RUN_STATE_CHANGED'
     AND COALESCE(actor_system, '') NOT IN ('finalization_gate_composite', 'workflow_engine');
  IF v_recent = 0 THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','audit_log_quiescent');
  END IF;
  RETURN jsonb_build_object('decision','HOLD','gate','audit_log_quiescent',
    'payload', jsonb_build_object('recent_events_count', v_recent,
                                   'settle_window_seconds', 5));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_record_step_up_failure(p_user_id uuid, p_business_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_row public.step_up_lockouts%ROWTYPE;
  v_threshold constant int := 5;
  v_lock_window constant interval := '15 minutes';
BEGIN
  INSERT INTO public.step_up_lockouts (user_id, business_id, consecutive_failures, last_failure_at)
       VALUES (p_user_id, p_business_id, 1, clock_timestamp())
  ON CONFLICT (user_id, business_id) DO UPDATE
    SET consecutive_failures = step_up_lockouts.consecutive_failures + 1,
        last_failure_at      = clock_timestamp(),
        locked_until         = CASE
          WHEN step_up_lockouts.consecutive_failures + 1 >= v_threshold
          THEN clock_timestamp() + v_lock_window
          ELSE step_up_lockouts.locked_until
        END
  RETURNING * INTO v_row;
  RETURN jsonb_build_object(
    'consecutive_failures', v_row.consecutive_failures,
    'locked_until',          v_row.locked_until,
    'threshold',             v_threshold);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_reset_step_up_failures(p_user_id uuid, p_business_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  INSERT INTO public.step_up_lockouts (user_id, business_id, consecutive_failures, last_success_at)
       VALUES (p_user_id, p_business_id, 0, clock_timestamp())
  ON CONFLICT (user_id, business_id) DO UPDATE
    SET consecutive_failures = 0,
        locked_until         = NULL,
        last_success_at      = clock_timestamp();
END;
$function$
;

CREATE OR REPLACE FUNCTION public.snooze_apply(p_actor_user_id uuid, p_issue_id uuid, p_snooze_reason text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue   record;
  v_perm    jsonb;
  v_guard   jsonb;
BEGIN
  SELECT id, organization_id, business_id, severity, status
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;

  v_guard := public._check_form_factor_guard('SNOOZE_APPLY', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_RESOLVE', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  IF v_issue.status <> 'OPEN'::public.review_issue_status_enum THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','INVALID_STATUS',
                              'current_status', v_issue.status::text);
  END IF;

  IF v_issue.severity IN ('HIGH'::public.review_issue_severity_enum,
                          'BLOCKING'::public.review_issue_severity_enum) THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_SNOOZE_REJECTED_SEVERITY',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('severity', v_issue.severity::text),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','SEVERITY_NOT_SNOOZABLE',
                              'severity', v_issue.severity::text);
  END IF;

  IF COALESCE(trim(p_snooze_reason), '') = '' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_SNOOZE_REJECTED_REASON_REQUIRED',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL, p_after_state:=jsonb_build_object('reason_present', false),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','REASON_REQUIRED');
  END IF;

  UPDATE public.review_issues
     SET status = 'SNOOZED'::public.review_issue_status_enum,
         snoozed_at = clock_timestamp(),
         snoozed_by = p_actor_user_id,
         snooze_reason = trim(p_snooze_reason),
         snoozed_until = NULL,
         updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_SNOOZED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('status', v_issue.status::text),
    p_after_state:=jsonb_build_object('status', 'SNOOZED',
                                       'snooze_reason', trim(p_snooze_reason),
                                       'severity', v_issue.severity::text),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW', 'status_after','SNOOZED', 'issue_id', p_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.unsnooze_apply(p_actor_user_id uuid, p_issue_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue   record;
  v_perm    jsonb;
BEGIN
  SELECT id, organization_id, business_id, status, snooze_reason, snoozed_at, snoozed_by
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;
  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_RESOLVE', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;
  IF v_issue.status <> 'SNOOZED'::public.review_issue_status_enum THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','NOT_SNOOZED',
                              'current_status', v_issue.status::text);
  END IF;

  UPDATE public.review_issues
     SET status = 'OPEN'::public.review_issue_status_enum,
         snoozed_at = NULL, snoozed_by = NULL,
         snooze_reason = NULL, snoozed_until = NULL,
         updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_UNSNOOZED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('status','SNOOZED',
                                        'was_snoozed_at', v_issue.snoozed_at,
                                        'snooze_reason', v_issue.snooze_reason),
    p_after_state:=jsonb_build_object('status','OPEN', 'manual', true),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW', 'status_after','OPEN', 'manual', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_is_step_up_locked(p_user_id uuid, p_business_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT EXISTS (SELECT 1 FROM public.step_up_lockouts
                  WHERE user_id = p_user_id AND business_id = p_business_id
                    AND locked_until IS NOT NULL AND locked_until > clock_timestamp());
$function$
;

CREATE OR REPLACE FUNCTION public.unsnooze_at_run_start(p_workflow_run_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run   record;
  v_row   record;
  v_count int := 0;
BEGIN
  SELECT id, organization_id, business_id, workflow_type
    INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','WORKFLOW_RUN_NOT_FOUND');
  END IF;

  FOR v_row IN
    SELECT id, snoozed_at, snooze_reason, snoozed_by
      FROM public.review_issues
     WHERE business_id = v_run.business_id
       AND status = 'SNOOZED'::public.review_issue_status_enum
     ORDER BY snoozed_at NULLS LAST
     FOR UPDATE
  LOOP
    UPDATE public.review_issues
       SET status = 'OPEN'::public.review_issue_status_enum,
           snoozed_at = NULL, snoozed_by = NULL,
           snooze_reason = NULL, snoozed_until = NULL,
           updated_at = clock_timestamp()
     WHERE id = v_row.id;

    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
      p_action:='REVIEW_UNSNOOZED',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=v_row.id,
      p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
      p_actor_system:='review_queue_unsnooze_at_run_start',
      p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
      p_before_state:=jsonb_build_object('status','SNOOZED',
                                          'was_snoozed_at', v_row.snoozed_at,
                                          'snooze_reason', v_row.snooze_reason,
                                          'snoozed_by', v_row.snoozed_by),
      p_after_state:=jsonb_build_object('status','OPEN',
                                         'unsnoozed_by_run_id', p_workflow_run_id,
                                         'unsnoozed_at', clock_timestamp(),
                                         'manual', false),
      p_reason:=NULL, p_request_context:=p_context);
    v_count := v_count + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'unsnoozed_count', v_count,
    'workflow_run_id', p_workflow_run_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._consume_step_up_token_for_actor(p_token_id uuid, p_business_id uuid, p_surface text, p_user_id uuid, p_action_id uuid)
 RETURNS TABLE(consumed boolean, reason text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_row public.step_up_tokens%ROWTYPE;
BEGIN
  SELECT t.* INTO v_row FROM public.step_up_tokens t
   WHERE t.id = p_token_id AND t.user_id = p_user_id AND t.business_id = p_business_id
   FOR UPDATE;
  IF v_row.id IS NULL THEN RETURN QUERY SELECT false, 'TOKEN_NOT_FOUND'::text; RETURN; END IF;
  IF v_row.surface <> p_surface THEN RETURN QUERY SELECT false, 'TOKEN_SURFACE_MISMATCH'::text; RETURN; END IF;
  IF v_row.revoked_at IS NOT NULL THEN RETURN QUERY SELECT false, 'TOKEN_REVOKED'::text; RETURN; END IF;
  IF v_row.consumed_at IS NOT NULL THEN RETURN QUERY SELECT false, 'TOKEN_ALREADY_CONSUMED'::text; RETURN; END IF;
  IF v_row.expires_at <= clock_timestamp() THEN RETURN QUERY SELECT false, 'TOKEN_EXPIRED'::text; RETURN; END IF;
  UPDATE public.step_up_tokens
     SET consumed_at = clock_timestamp(), consumed_for_surface = p_surface, consumed_for_action_id = p_action_id
   WHERE id = p_token_id AND consumed_at IS NULL;
  IF NOT FOUND THEN RETURN QUERY SELECT false, 'TOKEN_RACE_LOST'::text; RETURN; END IF;
  RETURN QUERY SELECT true, 'OK'::text;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.latest_qualifying_step_up_approval(p_business_id uuid, p_run_id uuid)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT a.id FROM public.workflow_run_approvals a
   WHERE a.business_id = p_business_id AND a.run_id = p_run_id
     AND a.approval_method = 'STEP_UP'::public.workflow_approval_method_enum
     AND a.revoked_at IS NULL
   ORDER BY a.approved_at DESC
   LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.out_workflow_user_approval(p_organization_id uuid, p_business_id uuid, p_run_id uuid, p_approval_method workflow_approval_method_enum, p_approval_note text, p_actor_user_id uuid, p_context jsonb, p_step_up_token_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_surface text;
  v_can jsonb;
  v_approval_id uuid := public.gen_uuid_v7();
  v_now timestamptz := clock_timestamp();
  v_consume record;
  v_lock_state jsonb;
BEGIN
  IF p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'out_workflow.user_approval: actor_user_id required' USING ERRCODE='22000';
  END IF;

  v_surface := CASE p_approval_method
                 WHEN 'STANDARD' THEN 'APPROVAL_STANDARD'
                 WHEN 'STEP_UP'  THEN 'APPROVAL_STEP_UP'
               END;

  IF p_approval_method = 'STEP_UP' AND public.fn_is_step_up_locked(p_actor_user_id, p_business_id) THEN
    RETURN jsonb_build_object('decision','DENIED','reason','LOCKED_OUT');
  END IF;

  v_can := public.can_perform(p_actor_user_id, v_surface, 'RECORD', '{}'::jsonb, p_business_id, p_organization_id);
  IF p_approval_method = 'STANDARD' AND v_can->>'decision' <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENIED','reason','MATRIX_DENY','can_perform', v_can);
  END IF;
  IF p_approval_method = 'STEP_UP' AND v_can->>'decision' <> 'REQUIRE_STEP_UP' THEN
    RETURN jsonb_build_object('decision','DENIED','reason','MATRIX_DENY','can_perform', v_can);
  END IF;

  IF p_approval_method = 'STEP_UP' THEN
    IF p_step_up_token_id IS NULL THEN
      RETURN jsonb_build_object('decision','DENIED','reason','STEP_UP_TOKEN_REQUIRED');
    END IF;
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_STEP_UP_CHALLENGED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('token_id', p_step_up_token_id, 'surface', v_surface),
      p_request_context:=p_context);

    SELECT * INTO v_consume FROM public._consume_step_up_token_for_actor(
      p_step_up_token_id, p_business_id, v_surface, p_actor_user_id, v_approval_id);

    IF NOT v_consume.consumed THEN
      v_lock_state := public.fn_record_step_up_failure(p_actor_user_id, p_business_id);
      PERFORM audit.emit_audit(
        p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_STEP_UP_FAILED',
        p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
        p_actor_user_id:=p_actor_user_id,
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_after_state:=jsonb_build_object('reason', v_consume.reason, 'lockout', v_lock_state),
        p_request_context:=p_context);
      RETURN jsonb_build_object('decision','DENIED','reason','STEP_UP_TOKEN_INVALID',
                                'token_reason', v_consume.reason, 'lockout', v_lock_state);
    END IF;

    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_STEP_UP_PASSED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('token_id', p_step_up_token_id, 'approval_id', v_approval_id),
      p_request_context:=p_context);
    PERFORM public.fn_reset_step_up_failures(p_actor_user_id, p_business_id);
  END IF;

  INSERT INTO public.workflow_run_approvals (id, organization_id, business_id, run_id,
    approved_by, approved_at, approval_method, approval_note)
  VALUES (v_approval_id, p_organization_id, p_business_id, p_run_id,
          p_actor_user_id, v_now, p_approval_method, p_approval_note);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='OUT_HUMAN_REVIEW_APPROVAL_RECORDED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='out_workflow_human_review_hold',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object(
      'approval_id', v_approval_id, 'approved_by', p_actor_user_id,
      'approved_at', v_now, 'approval_method', p_approval_method::text,
      'approval_note', p_approval_note),
    p_request_context:=p_context);

  IF p_approval_method = 'STEP_UP' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_APPROVAL_QUALIFIED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('approval_id', v_approval_id),
      p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object('decision','APPROVED','approval_id', v_approval_id,
                            'approved_at', v_now, 'method', p_approval_method::text);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_clear_snooze_on_severity_elevation(p_issue_id uuid, p_new_severity review_issue_severity_enum, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue record;
BEGIN
  SELECT id, organization_id, business_id, status, severity, snoozed_at, snooze_reason, snoozed_by
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;
  IF v_issue.status <> 'SNOOZED'::public.review_issue_status_enum THEN
    RETURN jsonb_build_object('decision','ALLOW','noop',true,'reason','NOT_SNOOZED');
  END IF;
  IF p_new_severity NOT IN ('HIGH'::public.review_issue_severity_enum,
                            'BLOCKING'::public.review_issue_severity_enum) THEN
    RETURN jsonb_build_object('decision','ALLOW','noop',true,'reason','SEVERITY_NOT_ELEVATED_BEYOND_SNOOZABLE');
  END IF;

  UPDATE public.review_issues
     SET status = 'OPEN'::public.review_issue_status_enum,
         severity = p_new_severity,
         snoozed_at = NULL, snoozed_by = NULL,
         snooze_reason = NULL, snoozed_until = NULL,
         updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='REVIEW_SNOOZE_AUTO_CLEARED_SEVERITY_ELEVATED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='review_queue_snooze_auto_clear',
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('status','SNOOZED',
                                        'severity', v_issue.severity::text,
                                        'was_snoozed_at', v_issue.snoozed_at,
                                        'snooze_reason', v_issue.snooze_reason),
    p_after_state:=jsonb_build_object('status','OPEN',
                                       'severity', p_new_severity::text),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ALLOW',
                            'status_after','OPEN',
                            'severity_after', p_new_severity::text);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_preconditions_satisfied(p_run_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_result jsonb;
  v_gate_seq text[] := ARRAY[
    'gate_finalization_transactions_processed',
    'gate_finalization_no_unknown_types',
    'gate_finalization_evidence_satisfied',
    'gate_finalization_draft_ledger_entries_complete',
    'gate_finalization_vat_classifications_complete',
    'gate_finalization_zero_blocking_issues',
    'gate_finalization_approval_recorded',
    'gate_finalization_audit_log_quiescent'
  ];
  v_gate text;
BEGIN
  SELECT id, organization_id, business_id INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','failing_gate','run_not_found',
                              'failure_payload', jsonb_build_object('run_id', p_run_id));
  END IF;

  FOREACH v_gate IN ARRAY v_gate_seq LOOP
    EXECUTE format('SELECT public.%I($1)', v_gate) INTO v_result USING p_run_id;
    IF (v_result->>'decision') <> 'ADVANCE' THEN
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
        p_action:='FINALIZATION_PRECONDITIONS_FAILED',
        p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum,
        p_subject_id:=p_run_id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
        p_actor_system:='finalization_gate_composite',
        p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
        p_before_state:=NULL,
        p_after_state:=jsonb_build_object(
          'failing_gate', v_gate,
          'failure_payload', v_result->'payload'),
        p_reason:=NULL, p_request_context:=p_context);
      RETURN jsonb_build_object(
        'decision','HOLD',
        'failing_gate', v_gate,
        'failure_payload', v_result->'payload');
    END IF;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='FINALIZATION_PRECONDITIONS_PASSED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id:=p_run_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='finalization_gate_composite',
    p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('all_gates_passed', true,
                                       'gate_count', cardinality(v_gate_seq)),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object('decision','ADVANCE','all_gates_passed', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_snooze_preview(p_actor_user_id uuid, p_business_id uuid, p_snooze_reason text, p_issue_ids uuid[], p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_perm           jsonb;
  v_org            uuid;
  v_will_apply     uuid[] := '{}';
  v_summary        jsonb;
  v_token_id       uuid;
  v_cnt_will_apply         int := 0;
  v_cnt_skip_closed        int := 0;
  v_cnt_skip_diff_business int := 0;
  v_cnt_skip_severity      int := 0;
  v_cnt_not_found          int := 0;
  v_rec record;
BEGIN
  IF p_issue_ids IS NULL OR cardinality(p_issue_ids) = 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','EMPTY_ISSUE_IDS');
  END IF;
  IF COALESCE(trim(p_snooze_reason), '') = '' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','REASON_REQUIRED');
  END IF;
  SELECT organization_id INTO v_org FROM public.business_entities WHERE id = p_business_id;
  IF v_org IS NULL THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','UNKNOWN_BUSINESS');
  END IF;
  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_RESOLVE', 'EXECUTE',
                               '{}'::jsonb, p_business_id, v_org);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  FOR v_rec IN
    SELECT u.id AS candidate_id, ri.id AS ri_id, ri.business_id, ri.severity, ri.status
      FROM unnest(p_issue_ids) WITH ORDINALITY AS u(id, ord)
      LEFT JOIN public.review_issues ri ON ri.id = u.id
     ORDER BY u.ord
  LOOP
    IF v_rec.ri_id IS NULL THEN v_cnt_not_found := v_cnt_not_found + 1; CONTINUE; END IF;
    IF v_rec.business_id <> p_business_id THEN v_cnt_skip_diff_business := v_cnt_skip_diff_business + 1; CONTINUE; END IF;
    IF v_rec.status <> 'OPEN'::public.review_issue_status_enum THEN v_cnt_skip_closed := v_cnt_skip_closed + 1; CONTINUE; END IF;
    IF v_rec.severity IN ('HIGH'::public.review_issue_severity_enum,
                          'BLOCKING'::public.review_issue_severity_enum) THEN
      v_cnt_skip_severity := v_cnt_skip_severity + 1; CONTINUE;
    END IF;
    v_will_apply := v_will_apply || v_rec.ri_id;
    v_cnt_will_apply := v_cnt_will_apply + 1;
  END LOOP;

  v_summary := jsonb_build_object(
    'will_apply', v_cnt_will_apply,
    'skip_already_closed', v_cnt_skip_closed,
    'skip_different_business', v_cnt_skip_diff_business,
    'skip_snooze_severity_restricted', v_cnt_skip_severity,
    'not_found', v_cnt_not_found);

  IF v_cnt_will_apply = 0 THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','NO_APPLICABLE_ISSUES','summary', v_summary);
  END IF;

  INSERT INTO public.bulk_preview_tokens (
    organization_id, business_id, actor_user_id, action_kind, affected_issue_ids
  ) VALUES (v_org, p_business_id, p_actor_user_id, 'SNOOZE', v_will_apply)
  RETURNING id INTO v_token_id;

  RETURN jsonb_build_object(
    'decision','ALLOW', 'token_id', v_token_id,
    'will_apply_count', v_cnt_will_apply,
    'summary', v_summary, 'snooze_reason', trim(p_snooze_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public._revalidate_issue_default(p_issue_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  RETURN jsonb_build_object('still_valid', true, 'reason', 'default_check_no_auto_close');
END;
$function$
;

CREATE OR REPLACE FUNCTION public._revalidate_issue_classification_unknown(p_issue_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_txn_id uuid;
  v_status text;
BEGIN
  SELECT transaction_id INTO v_txn_id FROM public.review_issues WHERE id = p_issue_id;
  IF v_txn_id IS NULL THEN
    RETURN jsonb_build_object('still_valid', true, 'reason', 'no_transaction_anchor');
  END IF;
  SELECT classification_status::text INTO v_status FROM public.transactions WHERE id = v_txn_id;
  IF v_status IS NULL THEN
    RETURN jsonb_build_object('still_valid', true, 'reason', 'transaction_not_found');
  END IF;
  IF v_status = 'PENDING' OR v_status = 'NEEDS_CONFIRMATION' THEN
    RETURN jsonb_build_object('still_valid', true, 'classification_status', v_status);
  END IF;
  RETURN jsonb_build_object(
    'still_valid', false,
    'action', 'AUTO_CLOSE',
    'reason', 'classification_status_no_longer_unknown',
    'classification_status', v_status);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._dispatch_validity_check(p_issue_id uuid, p_fn_ref text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  IF p_fn_ref IS NULL OR p_fn_ref = 'default' THEN
    RETURN public._revalidate_issue_default(p_issue_id, p_context);
  ELSIF p_fn_ref = 'classification.unknown_type_validity' THEN
    RETURN public._revalidate_issue_classification_unknown(p_issue_id, p_context);
  END IF;
  RETURN jsonb_build_object('still_valid', true, 'reason', 'unknown_validity_fn_ref',
                            'fn_ref', p_fn_ref);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rescan_for_resolved_issue(p_resolved_issue_id uuid, p_run_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_resolved      record;
  v_affected_ids  uuid[] := '{}';
  v_aff           record;
  v_check         jsonb;
  v_rescanned     int := 0;
  v_auto_closed   int := 0;
  v_severity_chg  int := 0;
  v_failures      int := 0;
  v_new_severity  public.review_issue_severity_enum;
  v_fail_id       uuid;
BEGIN
  IF COALESCE((p_context->>'is_rescan_recursion')::boolean, false) THEN
    RETURN jsonb_build_object('decision','ALLOW','noop',true,'reason','RECURSION_GUARD');
  END IF;

  SELECT id, organization_id, business_id,
         transaction_id, document_id, match_record_id, workflow_run_id
    INTO v_resolved FROM public.review_issues WHERE id = p_resolved_issue_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','RESOLVED_ISSUE_NOT_FOUND');
  END IF;

  SELECT array_agg(id) INTO v_affected_ids
    FROM (
      SELECT DISTINCT id FROM public.review_issues
       WHERE business_id = v_resolved.business_id
         AND status = 'OPEN'::public.review_issue_status_enum
         AND id <> p_resolved_issue_id
         AND (
           (v_resolved.transaction_id IS NOT NULL AND transaction_id = v_resolved.transaction_id) OR
           (v_resolved.document_id    IS NOT NULL AND document_id    = v_resolved.document_id) OR
           (v_resolved.match_record_id IS NOT NULL AND match_record_id = v_resolved.match_record_id)
         )
    ) sub;
  v_affected_ids := COALESCE(v_affected_ids, '{}');

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='REVIEW_RESCAN_TRIGGERED_AUTOMATICALLY',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_resolved_issue_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='review_queue_rescan',
    p_organization_id:=v_resolved.organization_id, p_business_id:=v_resolved.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'triggering_resolved_issue_id', p_resolved_issue_id,
      'workflow_run_id', COALESCE(p_run_id, v_resolved.workflow_run_id),
      'affected_count', cardinality(v_affected_ids)),
    p_reason:=NULL, p_request_context:=p_context);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='REVIEW_RESCAN_AFFECTED_SET_COMPUTED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_resolved_issue_id,
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='review_queue_rescan',
    p_organization_id:=v_resolved.organization_id, p_business_id:=v_resolved.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'affected_issue_ids', to_jsonb(v_affected_ids),
      'count', cardinality(v_affected_ids)),
    p_reason:=NULL, p_request_context:=p_context);

  FOR v_aff IN
    SELECT ri.id, ri.organization_id, ri.business_id, ri.issue_type,
           ri.status, ri.severity,
           itr.validity_check_fn_ref
      FROM public.review_issues ri
      LEFT JOIN public.issue_type_registry itr ON itr.issue_type = ri.issue_type
     WHERE ri.id = ANY(v_affected_ids)
     FOR UPDATE OF ri
  LOOP
    BEGIN
      v_rescanned := v_rescanned + 1;
      IF COALESCE((p_context->>'simulate_revalidation_failure')::boolean, false) THEN
        RAISE EXCEPTION 'simulated revalidation failure' USING ERRCODE = 'XX000';
      END IF;
      v_check := public._dispatch_validity_check(v_aff.id, v_aff.validity_check_fn_ref, p_context);

      IF (v_check->>'still_valid')::boolean = false
         AND (v_check->>'action') = 'AUTO_CLOSE' THEN
        UPDATE public.review_issues
           SET status = 'AUTO_RESOLVED_BY_RESCAN'::public.review_issue_status_enum,
               auto_resolution_trigger_issue_id = p_resolved_issue_id,
               resolved_at = clock_timestamp(),
               updated_at  = clock_timestamp()
         WHERE id = v_aff.id;
        v_auto_closed := v_auto_closed + 1;
        PERFORM audit.emit_audit(
          p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
          p_action:='REVIEW_RESCAN_ISSUE_AUTO_RESOLVED',
          p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
          p_subject_id:=v_aff.id,
          p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
          p_actor_system:='review_queue_rescan',
          p_organization_id:=v_aff.organization_id, p_business_id:=v_aff.business_id,
          p_before_state:=jsonb_build_object('status', v_aff.status::text),
          p_after_state:=jsonb_build_object(
            'status','AUTO_RESOLVED_BY_RESCAN',
            'triggering_resolved_issue_id', p_resolved_issue_id,
            'check_result', v_check),
          p_reason:=NULL, p_request_context:=p_context);
      ELSIF (v_check ? 'new_severity') THEN
        v_new_severity := (v_check->>'new_severity')::public.review_issue_severity_enum;
        IF v_new_severity <> v_aff.severity THEN
          IF v_aff.status = 'SNOOZED'::public.review_issue_status_enum
             AND v_new_severity IN ('HIGH'::public.review_issue_severity_enum,
                                    'BLOCKING'::public.review_issue_severity_enum) THEN
            PERFORM public.auto_clear_snooze_on_severity_elevation(v_aff.id, v_new_severity, p_context);
          ELSE
            UPDATE public.review_issues
               SET severity = v_new_severity, updated_at = clock_timestamp()
             WHERE id = v_aff.id;
          END IF;
          v_severity_chg := v_severity_chg + 1;
          PERFORM audit.emit_audit(
            p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
            p_action:='REVIEW_RESCAN_ISSUE_SEVERITY_CHANGED',
            p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
            p_subject_id:=v_aff.id,
            p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
            p_actor_system:='review_queue_rescan',
            p_organization_id:=v_aff.organization_id, p_business_id:=v_aff.business_id,
            p_before_state:=jsonb_build_object('severity', v_aff.severity::text),
            p_after_state:=jsonb_build_object(
              'severity', v_new_severity::text,
              'triggering_resolved_issue_id', p_resolved_issue_id),
            p_reason:=NULL, p_request_context:=p_context);
        END IF;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_failures := v_failures + 1;
      PERFORM audit.emit_audit(
        p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
        p_action:='REVIEW_RESCAN_REVALIDATION_FAILED',
        p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
        p_subject_id:=v_aff.id,
        p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
        p_actor_system:='review_queue_rescan',
        p_organization_id:=v_aff.organization_id, p_business_id:=v_aff.business_id,
        p_before_state:=NULL,
        p_after_state:=jsonb_build_object(
          'sqlstate', SQLSTATE, 'message', SQLERRM,
          'triggering_resolved_issue_id', p_resolved_issue_id),
        p_reason:=NULL, p_request_context:=p_context);
      INSERT INTO public.review_issues (
        organization_id, business_id, workflow_run_id,
        transaction_id, document_id, match_record_id, draft_ledger_entry_id,
        invoice_id, client_id,
        issue_type, issue_group, severity,
        plain_language_title, plain_language_description, recommended_action,
        card_payload_json, card_content_generated_at,
        card_content_tier_used, card_content_fallback_applied, status
      ) SELECT
        ri.organization_id, ri.business_id, ri.workflow_run_id,
        ri.transaction_id, ri.document_id, ri.match_record_id, ri.draft_ledger_entry_id,
        ri.invoice_id, ri.client_id,
        'review_queue.rescan_revalidation_failed',
        'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
        'LOW'::public.review_issue_severity_enum,
        'Rescan revalidation failed',
        'A targeted rescan could not revalidate this issue. Re-run scan manually or document via note.',
        'RERUN_SCAN_AFTER_CHANGE',
        jsonb_build_object('failed_issue_id', v_aff.id, 'sqlstate', SQLSTATE),
        clock_timestamp(),
        'NONE'::public.review_issue_card_content_tier_enum,
        false,
        'OPEN'::public.review_issue_status_enum
        FROM public.review_issues ri WHERE ri.id = v_aff.id
        RETURNING id INTO v_fail_id;
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'triggering_resolved_issue_id', p_resolved_issue_id,
    'affected_count', cardinality(v_affected_ids),
    'rescanned', v_rescanned,
    'auto_resolved', v_auto_closed,
    'severity_changes', v_severity_chg,
    'failures', v_failures);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rescan_manually(p_run_id uuid, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run         record;
  v_aff         record;
  v_check       jsonb;
  v_rescanned   int := 0;
  v_auto_closed int := 0;
  v_severity_chg int := 0;
  v_failures    int := 0;
BEGIN
  SELECT id, organization_id, business_id INTO v_run
    FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','WORKFLOW_RUN_NOT_FOUND'); END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_RESCAN_TRIGGERED_MANUALLY',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id:=p_run_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object('workflow_run_id', p_run_id, 'mode', 'manual_widened'),
    p_reason:=NULL, p_request_context:=p_context);

  FOR v_aff IN
    SELECT ri.id, ri.organization_id, ri.business_id, ri.issue_type,
           ri.status, ri.severity,
           itr.validity_check_fn_ref
      FROM public.review_issues ri
      LEFT JOIN public.issue_type_registry itr ON itr.issue_type = ri.issue_type
     WHERE ri.workflow_run_id = p_run_id
       AND ri.status = 'OPEN'::public.review_issue_status_enum
     FOR UPDATE OF ri
  LOOP
    BEGIN
      v_rescanned := v_rescanned + 1;
      v_check := public._dispatch_validity_check(v_aff.id, v_aff.validity_check_fn_ref, p_context);
      IF (v_check->>'still_valid')::boolean = false
         AND (v_check->>'action') = 'AUTO_CLOSE' THEN
        UPDATE public.review_issues
           SET status = 'AUTO_RESOLVED_BY_RESCAN'::public.review_issue_status_enum,
               auto_resolution_trigger_issue_id = v_aff.id,
               resolved_at = clock_timestamp(),
               updated_at = clock_timestamp()
         WHERE id = v_aff.id;
        v_auto_closed := v_auto_closed + 1;
        PERFORM audit.emit_audit(
          p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
          p_action:='REVIEW_RESCAN_ISSUE_AUTO_RESOLVED',
          p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
          p_subject_id:=v_aff.id,
          p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
          p_actor_system:='review_queue_rescan_manual',
          p_organization_id:=v_aff.organization_id, p_business_id:=v_aff.business_id,
          p_before_state:=jsonb_build_object('status', v_aff.status::text),
          p_after_state:=jsonb_build_object('status','AUTO_RESOLVED_BY_RESCAN',
                                             'mode','manual_widened',
                                             'check_result', v_check),
          p_reason:=NULL, p_request_context:=p_context);
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_failures := v_failures + 1;
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'workflow_run_id', p_run_id,
    'rescanned', v_rescanned,
    'auto_resolved', v_auto_closed,
    'severity_changes', v_severity_chg,
    'failures', v_failures);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._check_form_factor_guard(p_action_kind text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF p_context IS NOT NULL
     AND (p_context->>'client_form_factor') = 'MOBILE' THEN
    RETURN jsonb_build_object(
      'decision', 'DENY',
      'reason_code', 'MOBILE_FORM_FACTOR_WRITE_REJECTED',
      'attempted_action', p_action_kind,
      'form_factor', 'MOBILE');
  END IF;
  RETURN jsonb_build_object('decision','ALLOW');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.send_issue_link_to_inbox(p_actor_user_id uuid, p_issue_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue   record;
  v_perm    jsonb;
  v_inbox_id uuid;
BEGIN
  SELECT id, organization_id, business_id, issue_type
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;
  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_QUEUE_VIEW', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  INSERT INTO public.notification_inbox (
    recipient_user_id, organization_id, business_id, kind, payload, delivered_at
  ) VALUES (
    p_actor_user_id, v_issue.organization_id, v_issue.business_id,
    'REVIEW_ISSUE_DESKTOP_LINK',
    jsonb_build_object('issue_id', p_issue_id, 'issue_type', v_issue.issue_type,
                       'sent_from_form_factor', COALESCE(p_context->>'client_form_factor','UNKNOWN')),
    clock_timestamp()
  ) RETURNING id INTO v_inbox_id;

  RETURN jsonb_build_object('decision','ALLOW', 'inbox_id', v_inbox_id, 'issue_id', p_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.review_queue_assign(p_actor_user_id uuid, p_issue_id uuid, p_assignee_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue            record;
  v_perm             jsonb;
  v_guard            jsonb;
  v_assignee_role    public.user_role;
  v_prior_assignee   uuid;
  v_audit_action     text;
  v_disp             jsonb;
BEGIN
  SELECT id, organization_id, business_id, assigned_to
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;

  v_guard := public._check_form_factor_guard('REVIEW_QUEUE_ASSIGN', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_ASSIGN', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  SELECT bur.role INTO v_assignee_role
    FROM public.business_user_roles bur
   WHERE bur.user_id = p_assignee_user_id
     AND bur.business_id = v_issue.business_id;
  IF v_assignee_role IS NULL OR v_assignee_role NOT IN ('BOOKKEEPER'::public.user_role, 'ACCOUNTANT'::public.user_role) THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_ASSIGNMENT_REJECTED_INVALID_ASSIGNEE',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object(
        'attempted_assignee', p_assignee_user_id,
        'attempted_assignee_role', v_assignee_role::text),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code','INVALID_ASSIGNEE',
                              'assignee_role', v_assignee_role::text);
  END IF;

  v_prior_assignee := v_issue.assigned_to;
  v_audit_action := CASE WHEN v_prior_assignee IS NULL
                         THEN 'REVIEW_ASSIGNMENT_CREATED'
                         ELSE 'REVIEW_ASSIGNMENT_REASSIGNED' END;

  UPDATE public.review_issues
     SET assigned_to = p_assignee_user_id,
         assigned_by = p_actor_user_id,
         assigned_at = clock_timestamp(),
         assignment_notification_sent_at = NULL,
         updated_at = clock_timestamp()
   WHERE id = p_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:=v_audit_action,
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object('assigned_to', v_prior_assignee),
    p_after_state:=jsonb_build_object('assigned_to', p_assignee_user_id,
                                       'assignee_role', v_assignee_role::text),
    p_reason:=NULL, p_request_context:=p_context);

  v_disp := public.dispatch_assignment_notification(
    p_issue_id, p_assignee_user_id,
    COALESCE((p_context->>'simulate_notification_failure')::boolean, false),
    p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'audit_action', v_audit_action,
    'prior_assignee', v_prior_assignee,
    'new_assignee', p_assignee_user_id,
    'notification', v_disp);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.regenerate_card_content(p_actor_user_id uuid, p_issue_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue   record;
  v_perm    jsonb;
  v_guard   jsonb;
  v_before  record;
  v_gen     jsonb;
BEGIN
  SELECT id, organization_id, business_id, plain_language_title,
         plain_language_description, recommended_action,
         card_content_tier_used, card_content_fallback_applied, status
    INTO v_issue FROM public.review_issues WHERE id = p_issue_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','DENY','reason_code','ISSUE_NOT_FOUND');
  END IF;

  v_guard := public._check_form_factor_guard('REGENERATE_CARD_CONTENT', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  v_perm := public.can_perform(p_actor_user_id, 'REVIEW_REGENERATE', 'EXECUTE',
                               '{}'::jsonb, v_issue.business_id, v_issue.organization_id);
  IF (v_perm->>'decision') <> 'ALLOW' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum,
      p_action:='REVIEW_CARD_CONTENT_REGENERATE_DENIED',
      p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
      p_subject_id:=p_issue_id,
      p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
      p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
      p_before_state:=NULL,
      p_after_state:=jsonb_build_object('reason_code', v_perm->>'reason_code'),
      p_reason:=NULL, p_request_context:=p_context);
    RETURN jsonb_build_object('decision','DENY','reason_code', v_perm->>'reason_code');
  END IF;

  v_before := v_issue;
  v_gen := public.generate_and_persist_card_content(p_issue_id, false, 'review_queue_regenerate', p_context);

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_CARD_CONTENT_REGENERATED',
    p_subject_type:='REVIEW_ISSUE'::audit.subject_type_enum,
    p_subject_id:=p_issue_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_issue.organization_id, p_business_id:=v_issue.business_id,
    p_before_state:=jsonb_build_object(
      'plain_language_title', v_before.plain_language_title,
      'plain_language_description', v_before.plain_language_description,
      'recommended_action', v_before.recommended_action,
      'card_content_tier_used', v_before.card_content_tier_used::text,
      'card_content_fallback_applied', v_before.card_content_fallback_applied),
    p_after_state:=jsonb_build_object(
      'tier_used', v_gen->>'tier_used',
      'was_fallback', (v_gen->>'was_fallback')::boolean),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'tier_used', v_gen->>'tier_used',
    'was_fallback', (v_gen->>'was_fallback')::boolean,
    'issue_id', p_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_snooze_apply(p_actor_user_id uuid, p_token_id uuid, p_snooze_reason text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_token         record;
  v_guard         jsonb;
  v_id            uuid;
  v_disp          jsonb;
  v_applied_ids   uuid[] := '{}';
  v_skipped       jsonb := '[]'::jsonb;
  v_failures      jsonb := '[]'::jsonb;
  v_requested     int;
  v_applied_count int := 0;
  v_skipped_count int := 0;
  v_failed_count  int := 0;
BEGIN
  v_guard := public._check_form_factor_guard('BULK_SNOOZE_APPLY', p_context);
  IF (v_guard->>'decision') = 'DENY' THEN RETURN v_guard; END IF;

  SELECT id, organization_id, business_id, actor_user_id, action_kind,
         affected_issue_ids, created_at, expires_at, consumed_at
    INTO v_token FROM public.bulk_preview_tokens WHERE id = p_token_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_NOT_FOUND'); END IF;
  IF v_token.action_kind <> 'SNOOZE' THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_NOT_SNOOZE'); END IF;
  IF v_token.actor_user_id <> p_actor_user_id THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_ACTOR_MISMATCH'); END IF;
  IF v_token.consumed_at IS NOT NULL THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_ALREADY_CONSUMED'); END IF;
  IF v_token.expires_at <= clock_timestamp() THEN RETURN jsonb_build_object('decision','DENY','reason_code','TOKEN_EXPIRED'); END IF;
  IF COALESCE(trim(p_snooze_reason), '') = '' THEN RETURN jsonb_build_object('decision','DENY','reason_code','REASON_REQUIRED'); END IF;

  v_requested := cardinality(v_token.affected_issue_ids);
  UPDATE public.bulk_preview_tokens SET consumed_at = clock_timestamp() WHERE id = p_token_id;

  FOREACH v_id IN ARRAY v_token.affected_issue_ids LOOP
    BEGIN
      v_disp := public.snooze_apply(p_actor_user_id, v_id, p_snooze_reason, p_context);
      IF (v_disp->>'decision') = 'ALLOW' THEN
        v_applied_ids := v_applied_ids || v_id; v_applied_count := v_applied_count + 1;
      ELSE
        v_skipped := v_skipped || jsonb_build_object('issue_id', v_id, 'reason_code', v_disp->>'reason_code');
        v_skipped_count := v_skipped_count + 1;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_failures := v_failures || jsonb_build_object('issue_id', v_id, 'sqlstate', SQLSTATE, 'message', SQLERRM);
      v_failed_count := v_failed_count + 1;
    END;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum,
    p_action:='REVIEW_BULK_SNOOZE_APPLIED',
    p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
    p_subject_id:=p_token_id,
    p_actor_user_id:=p_actor_user_id, p_actor_role:=NULL, p_actor_session_id:=NULL, p_actor_system:=NULL,
    p_organization_id:=v_token.organization_id, p_business_id:=v_token.business_id,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'token_id', p_token_id, 'requested', v_requested,
      'applied', v_applied_count, 'skipped', v_skipped_count, 'failed', v_failed_count),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'decision','ALLOW',
    'requested', v_requested, 'applied', v_applied_count, 'applied_ids', to_jsonb(v_applied_ids),
    'skipped_count', v_skipped_count, 'skipped', v_skipped,
    'failed_count', v_failed_count, 'failures', v_failures);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_evidence_satisfied(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_unmatched int;
BEGIN
  SELECT business_id, period_start, period_end
    INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','evidence_satisfied',
                              'payload', jsonb_build_object('reason','RUN_NOT_FOUND'));
  END IF;

  -- Count OUT-side rows lacking confirmed match or documented exception
  SELECT count(*) INTO v_unmatched
    FROM public.transactions
   WHERE business_id = v_run.business_id
     AND transaction_date BETWEEN v_run.period_start AND v_run.period_end
     AND direction = 'OUT'
     AND transaction_type = 'OUT_EXPENSE'::public.transaction_type_enum
     AND COALESCE(out_workflow_in_scope, true) = true
     AND match_status NOT IN (
       'MATCHED_CONFIRMED'::public.transaction_match_status_enum,
       'MATCHED_AUTO_CONFIRMED'::public.transaction_match_status_enum,
       'MATCHED_AUTO_HIGH_CONFIDENCE'::public.transaction_match_status_enum,
       'EXCEPTION_DOCUMENTED'::public.transaction_match_status_enum,
       'NO_MATCH_REQUIRED'::public.transaction_match_status_enum);

  IF v_unmatched = 0 THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','evidence_satisfied');
  END IF;
  RETURN jsonb_build_object('decision','HOLD','gate','evidence_satisfied',
    'payload', jsonb_build_object('unmatched_out_expense_count', v_unmatched));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.review_queue_run_fixture(p_fixture_name text, p_organization_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_row public.review_queue_fixture_registry%ROWTYPE;
BEGIN
  SELECT * INTO v_row FROM public.review_queue_fixture_registry
   WHERE fixture_name = p_fixture_name;
  IF v_row.id IS NULL THEN
    RAISE EXCEPTION 'review_queue.run_fixture: unknown fixture %', p_fixture_name USING ERRCODE='02000';
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum,
    p_action:='REVIEW_QUEUE_FIXTURE_RAN',
    p_subject_type:='ACCESS_DECISION'::audit.subject_type_enum,
    p_subject_id:=COALESCE(p_organization_id, v_row.id),
    p_actor_user_id:=NULL, p_actor_role:=NULL, p_actor_session_id:=NULL,
    p_actor_system:='review_queue_fixture_runner',
    p_organization_id:=p_organization_id, p_business_id:=NULL,
    p_before_state:=NULL,
    p_after_state:=jsonb_build_object(
      'fixture_name', v_row.fixture_name,
      'category', v_row.category,
      'covers_phases', v_row.covers_phases,
      'covers_invariants', v_row.covers_invariants,
      'initiating_user_id', p_actor_user_id),
    p_reason:=NULL, p_request_context:=p_context);

  RETURN jsonb_build_object(
    'status','PENDING_IMPLEMENTATION',
    'reason','runtime executor lives in app-layer engine (Stage 6); DB-side stub records the audit only',
    'fixture_name', v_row.fixture_name,
    'category', v_row.category,
    'covers_phases', v_row.covers_phases,
    'expected_audit_actions', v_row.expected_audit_actions);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_transactions_processed(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_pending int;
  v_failed  int;
BEGIN
  SELECT business_id, workflow_type::text AS wtype, period_start, period_end
    INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','transactions_processed',
                              'payload', jsonb_build_object('reason','RUN_NOT_FOUND'));
  END IF;

  SELECT
    count(*) FILTER (WHERE classification_status = 'PENDING'),
    count(*) FILTER (WHERE classification_status = 'FAILED')
    INTO v_pending, v_failed
    FROM public.transactions
   WHERE business_id = v_run.business_id
     AND transaction_date BETWEEN v_run.period_start AND v_run.period_end;

  IF v_pending = 0 AND v_failed = 0 THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','transactions_processed');
  END IF;
  RETURN jsonb_build_object('decision','HOLD','gate','transactions_processed',
    'payload', jsonb_build_object('pending', v_pending, 'failed', v_failed));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_no_unknown_types(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_unknown int;
BEGIN
  SELECT business_id, period_start, period_end
    INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','no_unknown_types',
                              'payload', jsonb_build_object('reason','RUN_NOT_FOUND'));
  END IF;

  SELECT count(*) INTO v_unknown
    FROM public.transactions
   WHERE business_id = v_run.business_id
     AND transaction_date BETWEEN v_run.period_start AND v_run.period_end
     AND transaction_type = 'UNKNOWN'::public.transaction_type_enum;

  IF v_unknown = 0 THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','no_unknown_types');
  END IF;
  RETURN jsonb_build_object('decision','HOLD','gate','no_unknown_types',
    'payload', jsonb_build_object('unknown_count', v_unknown));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_draft_ledger_entries_complete(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_txns_without_entries int;
BEGIN
  SELECT business_id, period_start, period_end
    INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','draft_ledger_entries_complete',
                              'payload', jsonb_build_object('reason','RUN_NOT_FOUND'));
  END IF;

  -- Count in-scope txns with no draft_ledger_entries row.
  -- UNKNOWN-typed are excluded (held by gate 2).
  SELECT count(*) INTO v_txns_without_entries
    FROM public.transactions t
   WHERE t.business_id = v_run.business_id
     AND t.transaction_date BETWEEN v_run.period_start AND v_run.period_end
     AND t.transaction_type <> 'UNKNOWN'::public.transaction_type_enum
     AND NOT EXISTS (
       SELECT 1 FROM public.draft_ledger_entries dle
        WHERE dle.parent_transaction_id = t.id);

  IF v_txns_without_entries = 0 THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','draft_ledger_entries_complete');
  END IF;
  RETURN jsonb_build_object('decision','HOLD','gate','draft_ledger_entries_complete',
    'payload', jsonb_build_object('txns_without_entries_count', v_txns_without_entries));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.in_workflow_user_approval(p_organization_id uuid, p_business_id uuid, p_run_id uuid, p_approval_method workflow_approval_method_enum, p_approval_note text, p_actor_user_id uuid, p_context jsonb, p_step_up_token_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_surface text;
  v_can jsonb;
  v_approval_id uuid := public.gen_uuid_v7();
  v_now timestamptz := clock_timestamp();
  v_consume record;
  v_lock_state jsonb;
BEGIN
  IF p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'in_workflow.user_approval: actor_user_id required' USING ERRCODE='22000';
  END IF;

  v_surface := CASE p_approval_method
                 WHEN 'STANDARD' THEN 'APPROVAL_STANDARD'
                 WHEN 'STEP_UP'  THEN 'APPROVAL_STEP_UP'
               END;

  IF p_approval_method = 'STEP_UP' AND public.fn_is_step_up_locked(p_actor_user_id, p_business_id) THEN
    RETURN jsonb_build_object('decision','DENIED','reason','LOCKED_OUT');
  END IF;

  v_can := public.can_perform(p_actor_user_id, v_surface, 'RECORD', '{}'::jsonb, p_business_id, p_organization_id);
  IF p_approval_method = 'STANDARD' AND v_can->>'decision' <> 'ALLOW' THEN
    RETURN jsonb_build_object('decision','DENIED','reason','MATRIX_DENY','can_perform', v_can);
  END IF;
  IF p_approval_method = 'STEP_UP' AND v_can->>'decision' <> 'REQUIRE_STEP_UP' THEN
    RETURN jsonb_build_object('decision','DENIED','reason','MATRIX_DENY','can_perform', v_can);
  END IF;

  IF p_approval_method = 'STEP_UP' THEN
    IF p_step_up_token_id IS NULL THEN
      RETURN jsonb_build_object('decision','DENIED','reason','STEP_UP_TOKEN_REQUIRED');
    END IF;
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_STEP_UP_CHALLENGED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('token_id', p_step_up_token_id, 'surface', v_surface),
      p_request_context:=p_context);

    SELECT * INTO v_consume FROM public._consume_step_up_token_for_actor(
      p_step_up_token_id, p_business_id, v_surface, p_actor_user_id, v_approval_id);

    IF NOT v_consume.consumed THEN
      v_lock_state := public.fn_record_step_up_failure(p_actor_user_id, p_business_id);
      PERFORM audit.emit_audit(
        p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_STEP_UP_FAILED',
        p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
        p_actor_user_id:=p_actor_user_id,
        p_organization_id:=p_organization_id, p_business_id:=p_business_id,
        p_after_state:=jsonb_build_object('reason', v_consume.reason, 'lockout', v_lock_state),
        p_request_context:=p_context);
      RETURN jsonb_build_object('decision','DENIED','reason','STEP_UP_TOKEN_INVALID',
                                'token_reason', v_consume.reason, 'lockout', v_lock_state);
    END IF;

    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_STEP_UP_PASSED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('token_id', p_step_up_token_id, 'approval_id', v_approval_id),
      p_request_context:=p_context);
    PERFORM public.fn_reset_step_up_failures(p_actor_user_id, p_business_id);
  END IF;

  INSERT INTO public.workflow_run_approvals (id, organization_id, business_id, run_id,
    approved_by, approved_at, approval_method, approval_note)
  VALUES (v_approval_id, p_organization_id, p_business_id, p_run_id,
          p_actor_user_id, v_now, p_approval_method, p_approval_note);

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='IN_HUMAN_REVIEW_APPROVAL_RECORDED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='in_workflow_human_review_hold',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object(
      'approval_id', v_approval_id, 'approved_by', p_actor_user_id,
      'approved_at', v_now, 'approval_method', p_approval_method::text,
      'approval_note', p_approval_note),
    p_request_context:=p_context);

  IF p_approval_method = 'STEP_UP' THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='FINALIZATION_APPROVAL_QUALIFIED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('approval_id', v_approval_id),
      p_request_context:=p_context);
  END IF;

  RETURN jsonb_build_object('decision','APPROVED','approval_id', v_approval_id,
                            'approved_at', v_now, 'method', p_approval_method::text);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_approval_present_and_step_up(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_any record;
BEGIN
  SELECT business_id, organization_id INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','approval_present_and_step_up',
                              'payload', jsonb_build_object('reason','RUN_NOT_FOUND'));
  END IF;
  SELECT a.approval_method, a.revoked_at INTO v_any
    FROM public.workflow_run_approvals a
   WHERE a.run_id = p_run_id
   ORDER BY a.approved_at DESC LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','approval_present_and_step_up',
                              'payload', jsonb_build_object('reason','NO_APPROVAL_FOUND'));
  END IF;
  IF v_any.revoked_at IS NOT NULL THEN
    RETURN jsonb_build_object('decision','HOLD','gate','approval_present_and_step_up',
                              'payload', jsonb_build_object('reason','APPROVAL_REVOKED'));
  END IF;
  IF public.latest_qualifying_step_up_approval(v_run.business_id, p_run_id) IS NOT NULL THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','approval_present_and_step_up');
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_APPROVAL_NOT_QUALIFIED',
    p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=p_run_id,
    p_actor_system:='finalization_gate_composite',
    p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
    p_after_state:=jsonb_build_object('reason','APPROVAL_NOT_STEP_UP'));
  RETURN jsonb_build_object('decision','HOLD','gate','approval_present_and_step_up',
                            'payload', jsonb_build_object('reason','APPROVAL_NOT_STEP_UP'));
END;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_ledger_entries_json(p_business_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  -- Read from draft_ledger_entries: at bundle-construction time (P04 step 3)
  -- locked_ledger_entries does not yet exist (promotion is P04 step 4).
  -- The dle rows carry the same shape as the locked rows by design.
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', dle.id, 'parent_transaction_id', dle.parent_transaction_id,
    'match_record_id', dle.match_record_id, 'entry_kind', dle.entry_kind,
    'debit_account_code', dle.debit_account_code, 'credit_account_code', dle.credit_account_code,
    'debit_amount', dle.debit_amount, 'credit_amount', dle.credit_amount,
    'currency', dle.currency, 'entry_period', dle.entry_period,
    'vat_treatment', dle.vat_treatment,
    'input_vat_reclaimable_flag', dle.input_vat_reclaimable_flag,
    'input_vat_reclaimable_amount', dle.input_vat_reclaimable_amount,
    'output_vat_due_flag', dle.output_vat_due_flag,
    'output_vat_due_amount', dle.output_vat_due_amount,
    'reverse_charge_relevant', dle.reverse_charge_relevant,
    'vies_relevant', dle.vies_relevant, 'status', dle.status
  ) ORDER BY dle.id), '[]'::jsonb)
  FROM public.draft_ledger_entries dle
  JOIN public.transactions t ON t.id = dle.parent_transaction_id
  WHERE t.business_id = p_business_id
    AND t.transaction_date BETWEEN p_period_start AND p_period_end;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_review_issues_json(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', ri.id, 'issue_type', ri.issue_type,
    'issue_group', ri.issue_group, 'severity', ri.severity,
    'status', ri.status,
    'plain_language_title', ri.plain_language_title,
    'resolved_at', ri.resolved_at, 'resolved_by', ri.resolved_by,
    'snoozed_until', ri.snoozed_until
  ) ORDER BY ri.id), '[]'::jsonb)
  FROM public.review_issues ri
  WHERE ri.workflow_run_id = p_run_id;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_evidence_index_json(p_business_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  WITH refs AS (
    SELECT DISTINCT d.id, d.document_hash, d.original_filename
      FROM public.match_records mr
      JOIN public.documents d ON d.id = mr.document_id
      JOIN public.transactions t ON t.id = mr.transaction_id
     WHERE t.business_id = p_business_id
       AND t.transaction_date BETWEEN p_period_start AND p_period_end
       AND mr.document_id IS NOT NULL
  )
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'document_id', refs.id,
    'file_hash',   refs.document_hash,
    'original_filename', refs.original_filename,
    'evidence_storage_relative_path',
       'evidence/' || refs.document_hash
  ) ORDER BY refs.document_hash), '[]'::jsonb)
  FROM refs;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_vat_summary_json(p_business_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  WITH agg AS (
    SELECT dle.vat_treatment::text AS treatment,
           SUM(COALESCE(dle.input_vat_reclaimable_amount, 0))::numeric AS total_in,
           SUM(COALESCE(dle.output_vat_due_amount, 0))::numeric        AS total_out,
           count(*)::int                                                AS cnt
      FROM public.draft_ledger_entries dle
      JOIN public.transactions t ON t.id = dle.parent_transaction_id
     WHERE t.business_id = p_business_id
       AND t.transaction_date BETWEEN p_period_start AND p_period_end
     GROUP BY dle.vat_treatment
  )
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'treatment', agg.treatment,
    'total_input_vat_reclaimable', agg.total_in,
    'total_output_vat_due', agg.total_out,
    'count_of_entries', agg.cnt
  ) ORDER BY agg.treatment), '[]'::jsonb)
  FROM agg;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_finalization_summary_json(p_run_id uuid, p_archive_package_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run public.workflow_runs;
  v_appr public.workflow_run_approvals;
BEGIN
  SELECT * INTO v_run  FROM public.workflow_runs WHERE id = p_run_id;
  SELECT * INTO v_appr FROM public.workflow_run_approvals
    WHERE run_id = p_run_id
      AND approval_method = 'STEP_UP'::public.workflow_approval_method_enum
      AND revoked_at IS NULL
    ORDER BY approved_at DESC LIMIT 1;
  RETURN jsonb_build_object(
    'run_id', v_run.id,
    'period_start', v_run.period_start::date,
    'period_end', v_run.period_end::date,
    'business_id', v_run.business_id,
    'organization_id', v_run.organization_id,
    'approval_id', v_appr.id,
    'approver_user_id', v_appr.approved_by,
    'approval_method', v_appr.approval_method,
    'approved_at', v_appr.approved_at,
    'finalization_started_at', v_run.started_at,
    'archive_package_id', p_archive_package_id,
    'manifest_version', 1);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._compose_ledger_entries_adjustment_json(p_business_id uuid, p_archive_package_id uuid, p_period_start date, p_period_end date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'archive', 'pg_temp'
AS $function$
  -- dle rows in the period that have NOT yet been promoted into the package.
  -- Excludes any dle.id already present as a locked entry for this package.
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', dle.id, 'parent_transaction_id', dle.parent_transaction_id,
    'match_record_id', dle.match_record_id, 'entry_kind', dle.entry_kind,
    'debit_account_code', dle.debit_account_code, 'credit_account_code', dle.credit_account_code,
    'debit_amount', dle.debit_amount, 'credit_amount', dle.credit_amount,
    'currency', dle.currency, 'entry_period', dle.entry_period,
    'vat_treatment', dle.vat_treatment,
    'input_vat_reclaimable_amount', dle.input_vat_reclaimable_amount,
    'output_vat_due_amount', dle.output_vat_due_amount,
    'vies_relevant', dle.vies_relevant, 'status', dle.status
  ) ORDER BY dle.id), '[]'::jsonb)
  FROM public.draft_ledger_entries dle
  JOIN public.transactions t ON t.id = dle.parent_transaction_id
 WHERE t.business_id = p_business_id
   AND t.transaction_date BETWEEN p_period_start AND p_period_end
   AND NOT EXISTS (
     SELECT 1 FROM archive.locked_ledger_entries lle
      WHERE lle.id = dle.id AND lle.archive_package_id = p_archive_package_id);
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_zero_blocking_issues(p_run_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run record;
  v_blocking int;
  v_tamper int;
BEGIN
  SELECT business_id INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','zero_blocking_issues',
                              'payload', jsonb_build_object('reason','RUN_NOT_FOUND'));
  END IF;

  -- Run-scoped blocking issues
  SELECT count(*) INTO v_blocking FROM public.v_blocking_issues
   WHERE workflow_run_id = p_run_id;

  -- Business-wide tamper-detected issues (any package; any age)
  SELECT count(*) INTO v_tamper FROM public.review_issues
   WHERE business_id = v_run.business_id
     AND issue_type  = 'archive.tamper_detected'
     AND status      = 'OPEN'::public.review_issue_status_enum;

  IF v_blocking = 0 AND v_tamper = 0 THEN
    RETURN jsonb_build_object('decision','ADVANCE','gate','zero_blocking_issues');
  END IF;
  RETURN jsonb_build_object('decision','HOLD','gate','zero_blocking_issues',
    'payload', jsonb_build_object('blocking_count', v_blocking,
                                   'tamper_count',   v_tamper,
                                   'reason', CASE WHEN v_tamper > 0
                                                  THEN 'BUSINESS_TAMPER_DETECTED'
                                                  ELSE 'RUN_BLOCKING_ISSUES' END));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_archive_data_read(p_archive_package_id uuid, p_actor_user_id uuid, p_session_id text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_pkg public.archive_packages;
BEGIN
  SELECT * INTO v_pkg FROM public.archive_packages WHERE id = p_archive_package_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'log_archive_data_read: package % not found', p_archive_package_id USING ERRCODE='P0002';
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='ARCHIVE_DATA_READ',
    p_subject_type:='ARCHIVE_PACKAGE'::audit.subject_type_enum, p_subject_id:=p_archive_package_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=v_pkg.organization_id, p_business_id:=v_pkg.business_id,
    p_after_state:=jsonb_build_object('archive_package_id', p_archive_package_id,
                                       'session_id', p_session_id),
    p_request_context:=p_context);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.accept_archive_tamper(p_archive_package_id uuid, p_actor_user_id uuid, p_reason text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_pkg public.archive_packages;
  v_role public.user_role;
  v_cleared int;
BEGIN
  IF p_reason IS NULL OR length(btrim(p_reason)) < 8 THEN
    RETURN jsonb_build_object('decision','DENIED','reason','REASON_TOO_SHORT');
  END IF;
  SELECT * INTO v_pkg FROM public.archive_packages WHERE id = p_archive_package_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','ERROR','reason','PACKAGE_NOT_FOUND');
  END IF;
  SELECT role INTO v_role FROM public.business_user_roles
   WHERE user_id = p_actor_user_id AND business_id = v_pkg.business_id
     AND status = 'ACTIVE'::public.account_status LIMIT 1;
  IF v_role IS NULL OR v_role <> 'OWNER'::public.user_role THEN
    RETURN jsonb_build_object('decision','DENIED','reason','OWNER_ROLE_REQUIRED');
  END IF;

  UPDATE public.review_issues
     SET status = 'DISMISSED'::public.review_issue_status_enum,
         resolved_by = p_actor_user_id,
         resolved_at = clock_timestamp(),
         resolution_note = p_reason,
         updated_at = clock_timestamp()
   WHERE business_id = v_pkg.business_id
     AND issue_type  = 'archive.tamper_detected'
     AND status      = 'OPEN'::public.review_issue_status_enum;
  GET DIAGNOSTICS v_cleared = ROW_COUNT;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='ARCHIVE_TAMPER_FORMALLY_ACCEPTED',
    p_subject_type:='ARCHIVE_PACKAGE'::audit.subject_type_enum, p_subject_id:=p_archive_package_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=v_pkg.organization_id, p_business_id:=v_pkg.business_id,
    p_reason:=p_reason,
    p_after_state:=jsonb_build_object('cleared_issues', v_cleared,
                                       'archive_package_id', p_archive_package_id),
    p_request_context:=p_context);
  RETURN jsonb_build_object('decision','ACCEPTED','cleared_issues', v_cleared);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.verify_archive_package(p_archive_package_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_pkg public.archive_packages;
  v_stored_anchor text;
  v_recomputed text;
  v_issue_id uuid;
  v_anchor_txn_id uuid;
  v_anchor_client_id uuid;
BEGIN
  SELECT * INTO v_pkg FROM public.archive_packages WHERE id = p_archive_package_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','ERROR','reason','PACKAGE_NOT_FOUND');
  END IF;

  v_stored_anchor := v_pkg.bundle_hash_anchor;

  SELECT public._compute_bundle_anchor(
           jsonb_agg(jsonb_build_object('path', af.relative_path, 'hash', af.file_hash)))
    INTO v_recomputed
    FROM public.archive_files af
    JOIN public.archive_manifests am ON am.id = af.archive_manifest_id
   WHERE am.archive_package_id = p_archive_package_id
     AND am.manifest_version_number = 1;

  IF v_recomputed = v_stored_anchor THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ARCHIVE_VERIFICATION_PASSED',
      p_subject_type:='ARCHIVE_PACKAGE'::audit.subject_type_enum, p_subject_id:=p_archive_package_id,
      p_actor_system:='finalization_layer3_verifier',
      p_organization_id:=v_pkg.organization_id, p_business_id:=v_pkg.business_id,
      p_after_state:=jsonb_build_object('bundle_hash_anchor', v_stored_anchor,
                                         'requested_by_user_id', p_actor_user_id),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','PASSED',
      'archive_package_id', p_archive_package_id,
      'bundle_hash_anchor', v_stored_anchor);
  END IF;

  SELECT id INTO v_anchor_txn_id FROM public.transactions
   WHERE business_id = v_pkg.business_id
     AND transaction_date BETWEEN v_pkg.period_start AND v_pkg.period_end
   ORDER BY id LIMIT 1;
  SELECT id INTO v_anchor_client_id FROM public.clients
   WHERE business_id = v_pkg.business_id ORDER BY id LIMIT 1;

  INSERT INTO public.review_issues (organization_id, business_id, workflow_run_id, transaction_id,
    client_id, issue_type, issue_group, severity, plain_language_title, plain_language_description,
    card_payload_json, status)
  VALUES (v_pkg.organization_id, v_pkg.business_id, v_pkg.workflow_run_id, v_anchor_txn_id,
          v_anchor_client_id, 'archive.tamper_detected',
          'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
          'BLOCKING'::public.review_issue_severity_enum,
          'Archive tamper detected — operations halted',
          'A discrepancy was detected between the recorded bundle hash and the recomputed file inventory. Finalization is halted for this business until an Owner formally accepts the situation.',
          jsonb_build_object('archive_package_id', p_archive_package_id,
                              'stored_anchor', v_stored_anchor,
                              'recomputed_anchor', v_recomputed),
          'OPEN'::public.review_issue_status_enum)
  RETURNING id INTO v_issue_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ARCHIVE_VERIFICATION_FAILED',
    p_subject_type:='ARCHIVE_PACKAGE'::audit.subject_type_enum, p_subject_id:=p_archive_package_id,
    p_actor_system:='finalization_layer3_verifier',
    p_organization_id:=v_pkg.organization_id, p_business_id:=v_pkg.business_id,
    p_after_state:=jsonb_build_object('stored_anchor', v_stored_anchor,
                                       'recomputed_anchor', v_recomputed,
                                       'requested_by_user_id', p_actor_user_id));
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ARCHIVE_TAMPER_DETECTED',
    p_subject_type:='ARCHIVE_PACKAGE'::audit.subject_type_enum, p_subject_id:=p_archive_package_id,
    p_actor_system:='finalization_layer3_verifier',
    p_organization_id:=v_pkg.organization_id, p_business_id:=v_pkg.business_id,
    p_after_state:=jsonb_build_object('review_issue_id', v_issue_id,
                                       'stored_anchor', v_stored_anchor,
                                       'recomputed_anchor', v_recomputed,
                                       'business_id', v_pkg.business_id));

  RETURN jsonb_build_object('decision','FAILED',
    'archive_package_id', p_archive_package_id,
    'stored_anchor', v_stored_anchor,
    'recomputed_anchor', v_recomputed,
    'review_issue_id', v_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gate_finalization_adjustment_preconditions_satisfied(p_adjustment_run_id uuid, p_parent_archive_package_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run public.workflow_runs;
  v_parent public.workflow_runs;
  v_pkg public.archive_packages;
  v_adj public.adjustment_records;
  v_age interval;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_adjustment_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','adjustment_preconditions_satisfied',
                              'payload', jsonb_build_object('reason','ADJUSTMENT_RUN_NOT_FOUND'));
  END IF;

  -- 4.1 — adjustment record present + non-empty reason
  SELECT * INTO v_adj FROM public.adjustment_records WHERE run_id = p_adjustment_run_id LIMIT 1;
  IF NOT FOUND OR v_adj.reason IS NULL OR length(btrim(v_adj.reason)) = 0 THEN
    RETURN jsonb_build_object('decision','HOLD','gate','adjustment_preconditions_satisfied',
                              'payload', jsonb_build_object('reason','REASON_MISSING_OR_EMPTY'));
  END IF;

  -- 4.2 — parent archive package exists
  SELECT * INTO v_pkg FROM public.archive_packages WHERE id = p_parent_archive_package_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','HOLD','gate','adjustment_preconditions_satisfied',
                              'payload', jsonb_build_object('reason','PARENT_PACKAGE_NOT_FOUND'));
  END IF;

  -- 4.3 — parent workflow_run is FINALIZED
  SELECT * INTO v_parent FROM public.workflow_runs WHERE id = v_adj.parent_run_id;
  IF NOT FOUND OR v_parent.status <> 'FINALIZED'::public.workflow_run_status_enum THEN
    RETURN jsonb_build_object('decision','HOLD','gate','adjustment_preconditions_satisfied',
                              'payload', jsonb_build_object('reason','PARENT_NOT_FINALIZED',
                                                              'parent_status', v_parent.status));
  END IF;

  -- 4.4 — within 6-year retention window from parent_period_start
  v_age := clock_timestamp() - v_adj.parent_period_start;
  IF v_age > interval '6 years' THEN
    RETURN jsonb_build_object('decision','HOLD','gate','adjustment_preconditions_satisfied',
                              'payload', jsonb_build_object('reason','RETENTION_EXPIRED',
                                                              'age_seconds', extract(epoch FROM v_age)));
  END IF;

  RETURN jsonb_build_object('decision','ADVANCE','gate','adjustment_preconditions_satisfied');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.dashboard_trigger_manual_refresh(p_business_id uuid, p_organization_id uuid, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  INSERT INTO public.dashboard_refresh_state (business_id, organization_id, currently_refreshing, updated_at)
       VALUES (p_business_id, p_organization_id, true, clock_timestamp())
  ON CONFLICT (business_id) DO UPDATE
    SET currently_refreshing = true, updated_at = clock_timestamp();
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='DASHBOARD_REFRESH_TRIGGERED_MANUALLY',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('triggered_by', p_actor_user_id),
    p_request_context:=p_context);
  UPDATE public.dashboard_refresh_state
     SET currently_refreshing = false,
         last_refreshed_at = clock_timestamp(),
         updated_at = clock_timestamp()
   WHERE business_id = p_business_id;
  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='DASHBOARD_REFRESH_COMPLETED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('trigger','manual', 'cards_refreshed', 11));
  RETURN jsonb_build_object('decision','REFRESHED','cards_count', 11);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.dashboard_record_refresh_failure(p_business_id uuid, p_organization_id uuid, p_attempt_n integer, p_error_message text, p_actor_user_id uuid DEFAULT NULL::uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_issue_id uuid;
  v_anchor_client_id uuid;
BEGIN
  UPDATE public.dashboard_refresh_state
     SET currently_refreshing = false,
         last_failure_at      = clock_timestamp(),
         last_failure_message = p_error_message,
         updated_at           = clock_timestamp()
   WHERE business_id = p_business_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='DASHBOARD_REFRESH_FAILED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
    p_actor_system:='dashboard_archive_promotion_subscriber',
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('attempt_n', p_attempt_n,
                                       'error', p_error_message,
                                       'requested_by_user_id', p_actor_user_id),
    p_request_context:=p_context);

  IF p_attempt_n >= 3 THEN
    SELECT id INTO v_anchor_client_id FROM public.clients
     WHERE business_id = p_business_id ORDER BY id LIMIT 1;
    INSERT INTO public.review_issues (organization_id, business_id, workflow_run_id, client_id,
      issue_type, issue_group, severity, plain_language_title, plain_language_description,
      card_payload_json, status)
    VALUES (p_organization_id, p_business_id, NULL,
            COALESCE(v_anchor_client_id,
                     (SELECT id FROM public.clients WHERE business_id=p_business_id LIMIT 1)),
            'dashboard.refresh_failed',
            'NEEDS_CONFIRMATION'::public.review_issue_group_enum,
            'HIGH'::public.review_issue_severity_enum,
            'Dashboard refresh persistently failing',
            'The dashboard materialized-view refresh has failed several times. Operator attention required.',
            jsonb_build_object('attempt_n', p_attempt_n, 'error', p_error_message),
            'OPEN'::public.review_issue_status_enum)
    RETURNING id INTO v_issue_id;
  END IF;

  RETURN jsonb_build_object('decision','RECORDED',
                            'attempt_n', p_attempt_n,
                            'review_issue_id', v_issue_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._drill_down_operational(p_card_id text, p_business_ids uuid[], p_filters jsonb DEFAULT '{}'::jsonb, p_page_size integer DEFAULT 50)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT COALESCE(jsonb_agg(row ORDER BY row->>'id'), '[]'::jsonb) FROM (
    SELECT jsonb_build_object(
      'id', t.id, 'business_id', t.business_id, 'source', 'OPERATIONAL',
      'payload', jsonb_build_object(
        'transaction_date', t.transaction_date,
        'amount', t.amount, 'currency', t.currency,
        'direction', t.direction, 'transaction_type', t.transaction_type)
    ) AS row
    FROM public.transactions t
    WHERE t.business_id = ANY(p_business_ids)
    ORDER BY t.transaction_date DESC, t.id
    LIMIT p_page_size) sub;
$function$
;

CREATE OR REPLACE FUNCTION public._drill_down_archive(p_card_id text, p_business_ids uuid[], p_filters jsonb DEFAULT '{}'::jsonb, p_page_size integer DEFAULT 50)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'archive', 'pg_temp'
AS $function$
  SELECT jsonb_build_object(
    'rows', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', lle.id, 'business_id', lle.business_id, 'source', 'ARCHIVE',
        'payload', jsonb_build_object(
          'archive_package_id', lle.archive_package_id,
          'archive_manifest_version', lle.archive_manifest_version,
          'entry_kind', lle.entry_kind,
          'debit_amount', lle.debit_amount, 'credit_amount', lle.credit_amount,
          'currency', lle.currency, 'vat_treatment', lle.vat_treatment))
        ORDER BY lle.id)
        FROM (SELECT * FROM archive.locked_ledger_entries
              WHERE business_id = ANY(p_business_ids)
              ORDER BY locked_at DESC LIMIT p_page_size) lle
    ), '[]'::jsonb),
    'touched_packages', COALESCE((
      SELECT jsonb_agg(DISTINCT archive_package_id)
        FROM archive.locked_ledger_entries
       WHERE business_id = ANY(p_business_ids)
    ), '[]'::jsonb));
$function$
;

CREATE OR REPLACE FUNCTION public._drill_down_analytics(p_card_id text, p_business_ids uuid[])
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('id', null, 'business_id', null,
                       'source', 'ANALYTICS',
                       'payload', jsonb_build_object('stage', 'STAGE_1_STUB',
                                                      'card_id', p_card_id,
                                                      'note', 'real MV reads pending Block 04 P09')));
$function$
;

CREATE OR REPLACE FUNCTION public.mark_export_completed(p_export_id uuid, p_storage_object_id text, p_byte_size bigint, p_file_hash text, p_source_data_hash text, p_signed_url_expires_at timestamp with time zone, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_e public.exports;
BEGIN
  UPDATE public.exports
     SET status                = 'COMPLETED'::public.export_status_enum,
         completed_at          = clock_timestamp(),
         storage_object_id     = p_storage_object_id,
         byte_size             = p_byte_size,
         file_hash             = p_file_hash,
         source_data_hash      = COALESCE(p_source_data_hash, source_data_hash),
         signed_url_expires_at = p_signed_url_expires_at
   WHERE id = p_export_id
   RETURNING * INTO v_e;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('decision','ERROR','reason','EXPORT_NOT_FOUND');
  END IF;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='EXPORT_COMPLETED',
    p_subject_type:='USER'::audit.subject_type_enum, p_subject_id:=v_e.requested_by_user_id,
    p_actor_system:='export_dispatcher',
    p_organization_id:=v_e.organization_id, p_business_id:=v_e.business_id,
    p_after_state:=jsonb_build_object('export_id', v_e.id,
                                       'export_kind', v_e.export_kind,
                                       'format', v_e.format::text,
                                       'byte_size', p_byte_size,
                                       'file_hash', p_file_hash),
    p_request_context:=p_context);
  RETURN jsonb_build_object('decision','OK','export_id', v_e.id);
END;
$function$
;

