CREATE OR REPLACE FUNCTION public.register_pdf_generator(p_name text, p_export_kind text, p_output_format pdf_output_format_enum, p_description text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_existed boolean;
BEGIN
  INSERT INTO public.pdf_generator_registry (name, export_kind, output_format, description)
       VALUES (p_name, p_export_kind, p_output_format, p_description)
  ON CONFLICT (name) DO UPDATE
    SET export_kind   = EXCLUDED.export_kind,
        output_format = EXCLUDED.output_format,
        description   = EXCLUDED.description
  RETURNING (xmax = 0) INTO v_existed;
  PERFORM audit.emit_audit(
    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='PDF_GENERATOR_REGISTERED',
    p_subject_type:='TOOL_REGISTRY'::audit.subject_type_enum, p_subject_id:=NULL,
    p_actor_system:='pdf_generator_registry',
    p_after_state:=jsonb_build_object(
      'name', p_name,
      'export_kind', p_export_kind,
      'output_format', p_output_format::text,
      'is_new_registration', v_existed),
    p_request_context:=p_context);
  RETURN jsonb_build_object('decision','OK','name', p_name,
                            'is_new_registration', v_existed);
END;
$function$
;

