CREATE OR REPLACE FUNCTION public.validate_accountant_pack_request(p_business_id uuid, p_organization_id uuid, p_period_start date, p_period_end date, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_can jsonb;
  v_unfinalized int;
  v_tamper int;
  v_enabled_components jsonb;
BEGIN
  v_can := public.can_perform(p_actor_user_id, 'REPORT_EXPORT_FULL', 'EXPORT',
                               jsonb_build_object('export_kind','accountant_export_pack'),
                               p_business_id, p_organization_id);
  IF v_can->>'decision' NOT IN ('ALLOW','STEP_UP','REQUIRE_STEP_UP') THEN
    RETURN jsonb_build_object('decision','REJECTED','reason','PERMISSION_DENIED',
                              'can_perform', v_can);
  END IF;

  -- Check every period in scope is FINALIZED.
  -- We check via archive_packages presence — at least one package whose period covers each month in scope.
  -- For Stage 1 we approximate with a workflow_runs existence check.
  SELECT count(*) INTO v_unfinalized
    FROM public.workflow_runs
   WHERE business_id = p_business_id
     AND period_start::date >= p_period_start
     AND period_end::date   <= p_period_end
     AND status <> 'FINALIZED'::public.workflow_run_status_enum
     AND workflow_type IN ('OUT_MONTHLY','IN_MONTHLY');
  IF v_unfinalized > 0 THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ACCOUNTANT_PACK_REJECTED_PERIOD_NOT_FINALIZED',
      p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
      p_actor_system:='accountant_pack_composer',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('period_start', p_period_start,
                                         'period_end', p_period_end,
                                         'unfinalized_run_count', v_unfinalized,
                                         'requested_by', p_actor_user_id),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','REJECTED','reason','PERIOD_NOT_FINALIZED',
                              'unfinalized_run_count', v_unfinalized);
  END IF;

  -- Tamper check
  SELECT count(*) INTO v_tamper FROM public.review_issues
   WHERE business_id = p_business_id
     AND issue_type  = 'archive.tamper_detected'
     AND status      = 'OPEN'::public.review_issue_status_enum;
  IF v_tamper > 0 THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ACCOUNTANT_PACK_REJECTED_TAMPER_DETECTED',
      p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
      p_actor_system:='accountant_pack_composer',
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('open_tamper_issue_count', v_tamper,
                                         'requested_by', p_actor_user_id),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','REJECTED','reason','TAMPER_DETECTED',
                              'open_tamper_issue_count', v_tamper);
  END IF;

  -- Resolve enabled components from config (default-all-enabled if missing or empty)
  SELECT component_visibility INTO v_enabled_components
    FROM public.accountant_pack_config WHERE business_id = p_business_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='ACCOUNTANT_PACK_GENERATION_STARTED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('period_start', p_period_start,
                                       'period_end', p_period_end,
                                       'component_visibility', COALESCE(v_enabled_components, '{}'::jsonb)),
    p_request_context:=p_context);

  RETURN jsonb_build_object('decision','OK',
                            'period_start', p_period_start,
                            'period_end', p_period_end,
                            'component_visibility', COALESCE(v_enabled_components, '{}'::jsonb));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_accountant_pack_completed(p_export_id uuid, p_bundle_hash_anchor text, p_component_count integer, p_storage_object_id text, p_byte_size bigint, p_signed_url_expires_at timestamp with time zone, p_context jsonb DEFAULT '{}'::jsonb)
