    p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='ACCOUNTANT_PACK_GENERATION_COMPLETED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=v_e.business_id,
    p_actor_system:='accountant_pack_composer',
    p_organization_id:=v_e.organization_id, p_business_id:=v_e.business_id,
    p_after_state:=jsonb_build_object('export_id', v_e.id,
                                       'bundle_hash_anchor', p_bundle_hash_anchor,
                                       'component_count', p_component_count,
                                       'byte_size', p_byte_size),
    p_request_context:=p_context);
  RETURN jsonb_build_object('decision','OK','export_id', v_e.id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_dashboard_performance_violation(p_metric text, p_observed_value numeric, p_threshold numeric, p_route text, p_ci_run_id text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_id uuid;
BEGIN
  IF p_metric NOT IN ('CLS', 'LCP', 'INP') THEN
    RAISE EXCEPTION 'INVALID_METRIC: %', p_metric USING ERRCODE = 'P0001';
  END IF;

  INSERT INTO public.dashboard_performance_violations
    (metric, observed_value, threshold, route, ci_run_id)
  VALUES
    (p_metric, p_observed_value, p_threshold, p_route, p_ci_run_id)
  RETURNING id INTO v_id;

  PERFORM audit.emit_audit(
    p_actor_kind      := 'SYSTEM'::audit.actor_kind_enum,
    p_action          := 'DASHBOARD_PERFORMANCE_BUDGET_VIOLATION_DETECTED',
    p_subject_type    := 'SYSTEM_OBSERVABILITY'::audit.subject_type_enum,
    p_subject_id      := v_id,
    p_actor_system    := 'ci_runner',
    p_after_state     := jsonb_build_object(
      'metric', p_metric,
      'observed_value', p_observed_value,
      'threshold', p_threshold,
      'route', p_route,
      'ci_run_id', p_ci_run_id
    ),
    p_request_context := p_context
  );

  RETURN v_id;
END $function$
;

CREATE OR REPLACE FUNCTION public.update_user_dashboard_locale(p_actor_user_id uuid, p_target_user_id uuid, p_new_locale dashboard_locale_enum, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_old_locale public.dashboard_locale_enum;
BEGIN
  IF p_actor_user_id IS DISTINCT FROM p_target_user_id THEN
    RAISE EXCEPTION 'LOCALE_UPDATE_REJECTED_NOT_SELF' USING ERRCODE = 'P0001';
  END IF;

  IF p_new_locale = 'el' THEN
    RAISE EXCEPTION 'LOCALE_NOT_YET_AVAILABLE: el deferred to Stage 2+' USING ERRCODE = 'P0001';
  END IF;

  SELECT dashboard_locale INTO v_old_locale FROM public.users WHERE id = p_target_user_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'USER_NOT_FOUND' USING ERRCODE = 'P0001';
  END IF;

  UPDATE public.users
     SET dashboard_locale = p_new_locale,
         updated_at = clock_timestamp()
   WHERE id = p_target_user_id;

  PERFORM audit.emit_audit(
    p_actor_kind      := 'USER'::audit.actor_kind_enum,
    p_action          := 'DASHBOARD_LOCALE_SWITCHED',
    p_subject_type    := 'USER'::audit.subject_type_enum,
    p_subject_id      := p_target_user_id,
    p_actor_user_id   := p_actor_user_id,
    p_after_state     := jsonb_build_object(
      'old_locale', v_old_locale,
      'new_locale', p_new_locale
    ),
    p_request_context := p_context
  );

  RETURN jsonb_build_object('decision', 'OK', 'old_locale', v_old_locale, 'new_locale', p_new_locale);
END $function$
;

CREATE OR REPLACE FUNCTION public.dashboard_update_preferences(p_user_id uuid, p_business_id uuid, p_organization_id uuid, p_card_visibility jsonb, p_sidebar_collapsed boolean, p_drilldown_mode dashboard_drilldown_mode_enum, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_id uuid;
BEGIN
  PERFORM public._reject_mobile_write(p_context, 'dashboard.update_preferences');

  INSERT INTO public.dashboard_user_preferences (
    organization_id, business_id, user_id,
    card_visibility, sidebar_collapsed, drilldown_mode, updated_at)
     VALUES (p_organization_id, p_business_id, p_user_id,
             COALESCE(p_card_visibility, '{}'::jsonb),
             COALESCE(p_sidebar_collapsed, false),
             COALESCE(p_drilldown_mode, 'DRAWER'::public.dashboard_drilldown_mode_enum),
             clock_timestamp())
  ON CONFLICT (business_id, user_id) DO UPDATE
    SET card_visibility   = EXCLUDED.card_visibility,
        sidebar_collapsed = EXCLUDED.sidebar_collapsed,
        drilldown_mode    = EXCLUDED.drilldown_mode,
        updated_at        = clock_timestamp()
  RETURNING id INTO v_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='DASHBOARD_PREFERENCES_UPDATED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
    p_actor_user_id:=p_user_id,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('preference_id', v_id,
                                       'card_visibility', COALESCE(p_card_visibility, '{}'::jsonb),
                                       'sidebar_collapsed', COALESCE(p_sidebar_collapsed, false),
                                       'drilldown_mode', p_drilldown_mode),
    p_request_context:=p_context);
  RETURN jsonb_build_object('decision','OK', 'preference_id', v_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._reject_mobile_write(p_context jsonb, p_surface_label text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  IF (p_context ->> 'client_form_factor') = 'MOBILE' THEN
    RAISE EXCEPTION 'MOBILE_WRITE_REJECTED: surface=% is desktop-only', p_surface_label
      USING ERRCODE = 'P0001';
  END IF;
END $function$
;

