CREATE OR REPLACE FUNCTION public.update_accountant_pack_config(p_business_id uuid, p_organization_id uuid, p_component_id text, p_enabled boolean, p_actor_user_id uuid, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE v_can jsonb;
BEGIN
  PERFORM public._reject_mobile_write(p_context, 'accountant_pack.update_config');

  v_can := public.can_perform(p_actor_user_id, 'BUSINESS_SETTINGS_EDIT', 'EDIT',
                               jsonb_build_object('component_id', p_component_id),
                               p_business_id, p_organization_id);
  IF v_can->>'decision' NOT IN ('ALLOW','STEP_UP','REQUIRE_STEP_UP') THEN
    PERFORM audit.emit_audit(
      p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='ACCOUNTANT_PACK_CONFIG_UPDATE_REJECTED',
      p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
      p_actor_user_id:=p_actor_user_id,
      p_organization_id:=p_organization_id, p_business_id:=p_business_id,
      p_after_state:=jsonb_build_object('component_id', p_component_id,
                                         'reason','PERMISSION_DENIED',
                                         'can_perform', v_can),
      p_request_context:=p_context);
    RETURN jsonb_build_object('decision','REJECTED','reason','PERMISSION_DENIED');
  END IF;

  INSERT INTO public.accountant_pack_config (business_id, organization_id,
    component_visibility, updated_at, last_updated_by)
     VALUES (p_business_id, p_organization_id,
             jsonb_build_object(p_component_id, p_enabled),
             clock_timestamp(), p_actor_user_id)
  ON CONFLICT (business_id) DO UPDATE
    SET component_visibility = accountant_pack_config.component_visibility
                              || jsonb_build_object(p_component_id, p_enabled),
        updated_at           = clock_timestamp(),
        last_updated_by      = p_actor_user_id;

  PERFORM audit.emit_audit(
    p_actor_kind:='USER'::audit.actor_kind_enum, p_action:='ACCOUNTANT_PACK_CONFIG_UPDATED',
    p_subject_type:='BUSINESS'::audit.subject_type_enum, p_subject_id:=p_business_id,
    p_actor_user_id:=p_actor_user_id,
    p_organization_id:=p_organization_id, p_business_id:=p_business_id,
    p_after_state:=jsonb_build_object('component_id', p_component_id,
                                       'enabled', p_enabled),
    p_request_context:=p_context);
  RETURN jsonb_build_object('decision','OK','component_id', p_component_id,
                            'enabled', p_enabled);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_dashboard_fixture(p_fixture_name text, p_category dashboard_fixture_category_enum, p_description text, p_sub_doc_ref text, p_producing_phase text, p_is_baseline_only boolean DEFAULT false, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_inserted boolean;
BEGIN
  INSERT INTO public.dashboard_fixture_registry
    (fixture_name, category, description, sub_doc_ref, producing_phase, is_baseline_only)
  VALUES
    (p_fixture_name, p_category, p_description, p_sub_doc_ref, p_producing_phase, p_is_baseline_only)
  ON CONFLICT (fixture_name) DO UPDATE
    SET category         = EXCLUDED.category,
        description      = EXCLUDED.description,
        sub_doc_ref      = EXCLUDED.sub_doc_ref,
        producing_phase  = EXCLUDED.producing_phase,
        is_baseline_only = EXCLUDED.is_baseline_only;

  RETURN jsonb_build_object('decision', 'OK', 'fixture_name', p_fixture_name);
END $function$
;

CREATE OR REPLACE FUNCTION public.list_dashboard_fixtures(p_category dashboard_fixture_category_enum DEFAULT NULL::dashboard_fixture_category_enum)
 RETURNS SETOF dashboard_fixture_registry
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT *
    FROM public.dashboard_fixture_registry
   WHERE p_category IS NULL OR category = p_category
   ORDER BY category, fixture_name;
$function$
;

CREATE OR REPLACE FUNCTION public.run_dashboard_fixture(p_fixture_name text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM public.dashboard_fixture_registry WHERE fixture_name = p_fixture_name) THEN
    RAISE EXCEPTION 'FIXTURE_NOT_FOUND: %', p_fixture_name USING ERRCODE = 'P0001';
  END IF;

  RETURN jsonb_build_object(
    'status',       'NOT_IMPLEMENTED',
    'fixture_name', p_fixture_name,
    'message',      'harness lives in app layer (tests/dashboard/runDashboardFixture.ts)'
  );
END $function$
;

CREATE OR REPLACE FUNCTION public.sweep_unaudited_finalizations(p_window_minutes integer DEFAULT 60)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run public.workflow_runs;
  v_count int := 0;
  v_recovered jsonb := '[]'::jsonb;
BEGIN
  FOR v_run IN
    SELECT * FROM public.workflow_runs
     WHERE status = 'FINALIZED'::public.workflow_run_status_enum
       AND COALESCE(finalized_at, completed_at) > clock_timestamp() - make_interval(mins => p_window_minutes)
       AND NOT EXISTS (
         SELECT 1 FROM audit.audit_events ae
          WHERE ae.action     = 'FINALIZATION_LOCK_COMMITTED'
            AND ae.subject_id = workflow_runs.id)
  LOOP
    v_count := v_count + 1;
    v_recovered := v_recovered || jsonb_build_object('run_id', v_run.id);
    PERFORM audit.emit_audit(
      p_actor_kind:='SYSTEM'::audit.actor_kind_enum, p_action:='FINALIZATION_LOCK_AUDIT_RECOVERED',
      p_subject_type:='WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id:=v_run.id,
      p_actor_system:='finalization_failure_handler',
      p_organization_id:=v_run.organization_id, p_business_id:=v_run.business_id,
      p_after_state:=jsonb_build_object('run_id', v_run.id,
                                         'recovered_at', clock_timestamp(),
                                         'reason', 'missing_FINALIZATION_LOCK_COMMITTED_audit'));
  END LOOP;
  RETURN jsonb_build_object('count', v_count, 'recovered', v_recovered);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.latest_step_up_for(p_business_id uuid, p_surface text)
 RETURNS timestamp with time zone
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
  SELECT t.issued_at FROM public.step_up_tokens t
  JOIN public.users u ON u.id = t.user_id
  WHERE u.auth_user_id = auth.uid()
    AND t.business_id = p_business_id AND t.surface = p_surface
    AND t.consumed_at IS NULL AND t.revoked_at IS NULL AND t.expires_at > now()
  ORDER BY t.issued_at DESC LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.processing_artifact_default_expiry(p_run_status workflow_run_status_enum, p_finalized_at timestamp with time zone)
 RETURNS timestamp with time zone
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT CASE
    WHEN p_run_status = 'FINALIZED'
      THEN COALESCE(p_finalized_at, now()) + interval '24 hours'
    WHEN p_run_status IN ('FAILED','CANCELLED')
      THEN COALESCE(p_finalized_at, now()) + interval '30 days'
    ELSE NULL
  END
$function$
;

CREATE OR REPLACE FUNCTION public.current_user_role(p_business_id uuid)
 RETURNS user_role
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
  SELECT bur.role
  FROM public.business_user_roles bur
  JOIN public.users u ON u.id = bur.user_id
  WHERE u.auth_user_id = auth.uid()
    AND bur.business_id = p_business_id
    AND bur.organization_id = public.current_org()
    AND bur.status = 'ACTIVE'
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_auth_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
BEGIN
  IF EXISTS (SELECT 1 FROM public.users WHERE auth_user_id = NEW.id) THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.users (
    auth_user_id, email, email_verified, email_verified_at, display_name, is_active
  ) VALUES (
    NEW.id,
    NEW.email,
    NEW.email_confirmed_at IS NOT NULL,
    NEW.email_confirmed_at,
    COALESCE(NEW.raw_user_meta_data->>'display_name', NULL),
    true
  );

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_auth_user_updated()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
BEGIN
  UPDATE public.users
  SET
    email             = NEW.email,
    email_verified    = NEW.email_confirmed_at IS NOT NULL,
    email_verified_at = NEW.email_confirmed_at,
    is_active         = CASE
                          WHEN NEW.banned_until IS NOT NULL AND NEW.banned_until > now()
                          THEN false
                          ELSE is_active
                        END
  WHERE auth_user_id = NEW.id;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_mfa_factor_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
BEGIN
  IF (TG_OP = 'DELETE') THEN
    PERFORM public.refresh_user_mfa_state(OLD.user_id);
    RETURN OLD;
  END IF;
  PERFORM public.refresh_user_mfa_state(NEW.user_id);
  IF (TG_OP = 'UPDATE' AND OLD.user_id IS DISTINCT FROM NEW.user_id) THEN
    PERFORM public.refresh_user_mfa_state(OLD.user_id);
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.refresh_user_mfa_state(p_auth_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_count integer;
BEGIN
  SELECT count(*) INTO v_count
  FROM auth.mfa_factors
  WHERE user_id = p_auth_user_id
    AND status = 'verified';

  UPDATE public.users
  SET
    mfa_factors_count = v_count,
    mfa_enabled       = (v_count > 0)
  WHERE auth_user_id = p_auth_user_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.consume_step_up_token(p_token_id uuid, p_business_id uuid, p_surface text, p_action_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(consumed boolean, reason text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE
  v_user_id uuid;
  v_row     public.step_up_tokens%ROWTYPE;
BEGIN
  SELECT u.id INTO v_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_user_id IS NULL THEN RETURN QUERY SELECT false, 'NOT_AUTHENTICATED'; RETURN; END IF;

  SELECT t.* INTO v_row FROM public.step_up_tokens t
  WHERE t.id = p_token_id AND t.user_id = v_user_id AND t.business_id = p_business_id
  FOR UPDATE;

  IF v_row.id IS NULL THEN RETURN QUERY SELECT false, 'TOKEN_NOT_FOUND'; RETURN; END IF;
  IF v_row.surface <> p_surface THEN RETURN QUERY SELECT false, 'TOKEN_SURFACE_MISMATCH'; RETURN; END IF;
  IF v_row.revoked_at IS NOT NULL THEN RETURN QUERY SELECT false, 'TOKEN_REVOKED'; RETURN; END IF;
  IF v_row.consumed_at IS NOT NULL THEN RETURN QUERY SELECT false, 'TOKEN_ALREADY_CONSUMED'; RETURN; END IF;
  IF v_row.expires_at <= now() THEN RETURN QUERY SELECT false, 'TOKEN_EXPIRED'; RETURN; END IF;

  UPDATE public.step_up_tokens
  SET consumed_at = now(), consumed_for_surface = p_surface, consumed_for_action_id = p_action_id
  WHERE id = p_token_id AND consumed_at IS NULL;
  IF NOT FOUND THEN RETURN QUERY SELECT false, 'TOKEN_RACE_LOST'; RETURN; END IF;

  RETURN QUERY SELECT true, 'OK'::text;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.redeem_mfa_recovery_code(submitted_code text)
 RETURNS TABLE(redeemed boolean, codes_remaining integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'extensions'
AS $function$
DECLARE
  v_auth_user_id uuid;
  v_user_id      uuid;
  v_match_id     uuid;
  v_batch_id     uuid;
  v_normalized   text;
  v_remaining    integer;
BEGIN
  v_auth_user_id := auth.uid();
  IF v_auth_user_id IS NULL THEN
    redeemed := false; codes_remaining := 0; RETURN NEXT; RETURN;
  END IF;

  SELECT id INTO v_user_id FROM public.users WHERE auth_user_id = v_auth_user_id;
  IF v_user_id IS NULL THEN
    redeemed := false; codes_remaining := 0; RETURN NEXT; RETURN;
  END IF;

  v_normalized := upper(regexp_replace(coalesce(submitted_code, ''), '\s', '', 'g'));
  IF length(v_normalized) = 10 AND position('-' IN v_normalized) = 0 THEN
    v_normalized := substring(v_normalized FROM 1 FOR 5) || '-' || substring(v_normalized FROM 6);
  END IF;

  SELECT id, batch_id INTO v_match_id, v_batch_id
  FROM public.mfa_recovery_codes
  WHERE user_id = v_user_id
    AND consumed_at IS NULL
    AND code_hash = extensions.crypt(v_normalized, code_hash)
  FOR UPDATE
  LIMIT 1;

  IF v_match_id IS NULL THEN
    SELECT count(*) INTO v_remaining
    FROM public.mfa_recovery_codes
    WHERE user_id = v_user_id AND consumed_at IS NULL;
    redeemed := false; codes_remaining := v_remaining; RETURN NEXT; RETURN;
  END IF;

  UPDATE public.mfa_recovery_codes
  SET consumed_at = now()
  WHERE batch_id = v_batch_id
    AND consumed_at IS NULL;

  DELETE FROM auth.mfa_factors WHERE user_id = v_auth_user_id;

  SELECT count(*) INTO v_remaining
  FROM public.mfa_recovery_codes
  WHERE user_id = v_user_id AND consumed_at IS NULL;
  redeemed := true; codes_remaining := v_remaining; RETURN NEXT; RETURN;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.has_permission(p_role user_role, p_surface text)
 RETURNS boolean
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT EXISTS(
    SELECT 1 FROM public.permission_matrix
    WHERE role = p_role AND surface = p_surface
      AND decision IN ('ALLOW', 'REQUIRE_STEP_UP')
  );
$function$
;

CREATE OR REPLACE FUNCTION public.current_user_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
  SELECT u.id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.issue_step_up_token(p_business_id uuid, p_surface text, p_factor_id uuid DEFAULT NULL::uuid, p_window interval DEFAULT '00:05:00'::interval)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE
  v_user_id         uuid;
  v_organization_id uuid;
  v_token_id        uuid;
BEGIN
  SELECT u.id INTO v_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'STEP_UP_NOT_AUTHENTICATED' USING ERRCODE = '28000';
  END IF;

  SELECT bur.organization_id INTO v_organization_id
  FROM public.business_user_roles bur
  WHERE bur.user_id = v_user_id AND bur.business_id = p_business_id AND bur.status = 'ACTIVE'
  LIMIT 1;
  IF v_organization_id IS NULL THEN
    RAISE EXCEPTION 'STEP_UP_NO_ROLE_ON_BUSINESS' USING ERRCODE = '42501';
  END IF;

  v_token_id := public.gen_uuid_v7();
  INSERT INTO public.step_up_tokens (
    id, user_id, organization_id, business_id, surface, factor_id,
    issued_at, expires_at
  ) VALUES (
    v_token_id, v_user_id, v_organization_id, p_business_id,
    p_surface, p_factor_id, now(), now() + p_window
  );

  RETURN v_token_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.gen_uuid_v7()
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  ts_ms        bigint;
  unix_ts_ms   bytea;
  uuid_bytes   bytea;
BEGIN
  ts_ms      := (extract(epoch FROM clock_timestamp()) * 1000)::bigint;
  unix_ts_ms := substring(int8send(ts_ms) FROM 3);

  uuid_bytes := unix_ts_ms || extensions.gen_random_bytes(10);

  uuid_bytes := set_byte(
    uuid_bytes, 6,
    ((get_byte(uuid_bytes, 6) & 15) | 112)
  );

  uuid_bytes := set_byte(
    uuid_bytes, 8,
    ((get_byte(uuid_bytes, 8) & 63) | 128)
  );

  RETURN encode(uuid_bytes, 'hex')::uuid;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.current_org()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
  SELECT COALESCE(
    NULLIF(
      NULLIF(current_setting('request.jwt.claims', true), '')::jsonb ->> 'org_id',
      ''
    )::uuid,
    (
      SELECT ou.organization_id
      FROM public.organization_users ou
      JOIN public.users u ON u.id = ou.user_id
      WHERE u.auth_user_id = auth.uid()
        AND ou.status = 'ACTIVE'
        AND ou.deleted_at IS NULL
      ORDER BY ou.joined_at ASC
      LIMIT 1
    )
  );
$function$
;

CREATE OR REPLACE FUNCTION public.current_user_businesses()
 RETURNS uuid[]
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
  SELECT array_agg(bur.business_id)
  FROM public.business_user_roles bur
  JOIN public.users u ON u.id = bur.user_id
  WHERE u.auth_user_id = auth.uid()
    AND bur.organization_id = public.current_org()
    AND bur.status = 'ACTIVE';
$function$
;

CREATE OR REPLACE FUNCTION public.create_invitation(p_organization_id uuid, p_email text, p_assignments jsonb, p_token_hash text, p_ttl interval DEFAULT '7 days'::interval)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE
  v_caller_user_id uuid;
  v_invitation_id uuid;
  v_assignment jsonb;
  v_business_id uuid;
  v_role public.user_role;
  v_owner_admin_count integer;
  v_normalized_email text;
BEGIN
  SELECT u.id INTO v_caller_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN RAISE EXCEPTION 'INVITATION_NOT_AUTHENTICATED' USING ERRCODE = '28000'; END IF;

  SELECT count(*) INTO v_owner_admin_count
  FROM public.business_user_roles bur
  JOIN public.business_entities be ON be.id = bur.business_id
  WHERE bur.user_id = v_caller_user_id AND bur.status = 'ACTIVE'
    AND bur.role IN ('OWNER','ADMIN') AND be.organization_id = p_organization_id;
  IF v_owner_admin_count = 0 THEN
    RAISE EXCEPTION 'INVITATION_REQUIRES_OWNER_OR_ADMIN' USING ERRCODE = '42501';
  END IF;

  IF jsonb_typeof(p_assignments) <> 'array' OR jsonb_array_length(p_assignments) = 0 THEN
    RAISE EXCEPTION 'INVITATION_ASSIGNMENTS_EMPTY' USING ERRCODE = '22023';
  END IF;
  FOR v_assignment IN SELECT jsonb_array_elements(p_assignments) LOOP
    v_business_id := (v_assignment ->> 'business_id')::uuid;
    v_role := (v_assignment ->> 'role')::public.user_role;
    PERFORM 1 FROM public.business_entities WHERE id = v_business_id AND organization_id = p_organization_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'INVITATION_BUSINESS_NOT_IN_ORG' USING ERRCODE = '22023'; END IF;
  END LOOP;

  v_normalized_email := lower(trim(p_email));
  v_invitation_id := public.gen_uuid_v7();
  INSERT INTO public.organization_invitations (
    id, organization_id, email, invited_role_per_business,
    invited_by, token_hash, expires_at, status
  ) VALUES (
    v_invitation_id, p_organization_id, v_normalized_email, p_assignments,
    v_caller_user_id, p_token_hash, now() + p_ttl, 'PENDING'
  );
  RETURN v_invitation_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.accept_invitation(p_token_hash text)
 RETURNS TABLE(success boolean, reason text, organization_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE
  v_caller_user_id uuid; v_caller_email text;
  v_row public.organization_invitations%ROWTYPE;
  v_assignment jsonb; v_business_id uuid; v_role public.user_role;
BEGIN
  SELECT u.id, u.email INTO v_caller_user_id, v_caller_email
  FROM public.users u WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN
    RETURN QUERY SELECT false, 'NOT_AUTHENTICATED'::text, NULL::uuid; RETURN;
  END IF;

  SELECT * INTO v_row FROM public.organization_invitations WHERE token_hash = p_token_hash FOR UPDATE;
  IF v_row.id IS NULL THEN
    RETURN QUERY SELECT false, 'INVITATION_NOT_FOUND'::text, NULL::uuid; RETURN;
  END IF;
  IF v_row.status = 'REVOKED' THEN
    RETURN QUERY SELECT false, 'INVITATION_REVOKED'::text, v_row.organization_id; RETURN;
  END IF;
  IF v_row.status = 'ACCEPTED' THEN
    RETURN QUERY SELECT false, 'INVITATION_ALREADY_ACCEPTED'::text, v_row.organization_id; RETURN;
  END IF;
  IF v_row.status = 'EXPIRED' OR v_row.expires_at <= now() THEN
    UPDATE public.organization_invitations SET status='EXPIRED' WHERE id = v_row.id AND status='PENDING';
    RETURN QUERY SELECT false, 'INVITATION_EXPIRED'::text, v_row.organization_id; RETURN;
  END IF;
  IF lower(v_row.email) <> lower(coalesce(v_caller_email,'')) THEN
    RETURN QUERY SELECT false, 'INVITATION_EMAIL_MISMATCH'::text, v_row.organization_id; RETURN;
  END IF;

  INSERT INTO public.organization_users (organization_id, user_id, status, joined_at)
  VALUES (v_row.organization_id, v_caller_user_id, 'ACTIVE', now())
  ON CONFLICT ON CONSTRAINT organization_users_unique
  DO UPDATE SET status='ACTIVE', deleted_at=NULL;

  FOR v_assignment IN SELECT jsonb_array_elements(v_row.invited_role_per_business) LOOP
    v_business_id := (v_assignment ->> 'business_id')::uuid;
    v_role := (v_assignment ->> 'role')::public.user_role;
    INSERT INTO public.business_user_roles
      (organization_id, business_id, user_id, role, assigned_by, status, assigned_at)
    VALUES (v_row.organization_id, v_business_id, v_caller_user_id, v_role, v_row.invited_by, 'ACTIVE', now())
    ON CONFLICT ON CONSTRAINT business_user_roles_business_user_unique
    DO UPDATE SET role = EXCLUDED.role, status='ACTIVE', assigned_at = now();
  END LOOP;

  UPDATE public.organization_invitations
     SET status='ACCEPTED', accepted_at=now(), accepted_by_user_id=v_caller_user_id
   WHERE id = v_row.id;
  RETURN QUERY SELECT true, 'OK'::text, v_row.organization_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.revoke_invitation(p_invitation_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE
  v_caller_user_id uuid; v_organization_id uuid; v_owner_admin_count integer;
BEGIN
  SELECT u.id INTO v_caller_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN RAISE EXCEPTION 'INVITATION_NOT_AUTHENTICATED' USING ERRCODE = '28000'; END IF;

  SELECT organization_id INTO v_organization_id FROM public.organization_invitations
  WHERE id = p_invitation_id AND status = 'PENDING';
  IF v_organization_id IS NULL THEN RETURN false; END IF;

  SELECT count(*) INTO v_owner_admin_count
  FROM public.business_user_roles bur JOIN public.business_entities be ON be.id = bur.business_id
  WHERE bur.user_id = v_caller_user_id AND bur.status='ACTIVE'
    AND bur.role IN ('OWNER','ADMIN') AND be.organization_id = v_organization_id;
  IF v_owner_admin_count = 0 THEN
    RAISE EXCEPTION 'INVITATION_REQUIRES_OWNER_OR_ADMIN' USING ERRCODE = '42501';
  END IF;

  UPDATE public.organization_invitations
     SET status='REVOKED', revoked_at=now(), revoked_by=v_caller_user_id
   WHERE id = p_invitation_id AND status='PENDING';
  RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.change_member_role(p_business_id uuid, p_target_user_id uuid, p_new_role user_role, p_step_up_token uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_caller_user_id uuid; v_caller_role public.user_role; v_consumed boolean; v_reason text;
BEGIN
  SELECT u.id INTO v_caller_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN RAISE EXCEPTION 'MEMBER_NOT_AUTHENTICATED' USING ERRCODE = '28000'; END IF;

  SELECT role INTO v_caller_role FROM public.business_user_roles
  WHERE user_id = v_caller_user_id AND business_id = p_business_id AND status='ACTIVE';
  IF v_caller_role IS NULL OR v_caller_role NOT IN ('OWNER','ADMIN') THEN
    RAISE EXCEPTION 'MEMBER_CHANGE_REQUIRES_OWNER_OR_ADMIN' USING ERRCODE = '42501';
  END IF;

  SELECT consumed, reason INTO v_consumed, v_reason
  FROM public.consume_step_up_token(p_step_up_token, p_business_id, 'USER_INVITE', NULL);
  IF NOT v_consumed THEN
    RAISE EXCEPTION 'MEMBER_STEP_UP_REJECTED:%', v_reason USING ERRCODE = '42501';
  END IF;

  UPDATE public.business_user_roles SET role = p_new_role, updated_at = now()
  WHERE user_id = p_target_user_id AND business_id = p_business_id AND status='ACTIVE';
  RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.remove_member(p_business_id uuid, p_target_user_id uuid, p_step_up_token uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE
  v_caller_user_id uuid; v_caller_role public.user_role; v_target_role public.user_role;
  v_consumed boolean; v_reason text;
BEGIN
  SELECT u.id INTO v_caller_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN RAISE EXCEPTION 'MEMBER_NOT_AUTHENTICATED' USING ERRCODE = '28000'; END IF;
  IF v_caller_user_id = p_target_user_id THEN
    RAISE EXCEPTION 'MEMBER_CANNOT_REMOVE_SELF' USING ERRCODE = '42501';
  END IF;

  SELECT role INTO v_caller_role FROM public.business_user_roles
  WHERE user_id = v_caller_user_id AND business_id = p_business_id AND status='ACTIVE';
  IF v_caller_role IS NULL OR v_caller_role NOT IN ('OWNER','ADMIN') THEN
    RAISE EXCEPTION 'MEMBER_CHANGE_REQUIRES_OWNER_OR_ADMIN' USING ERRCODE = '42501';
  END IF;

  SELECT role INTO v_target_role FROM public.business_user_roles
  WHERE user_id = p_target_user_id AND business_id = p_business_id AND status='ACTIVE';
  IF v_target_role = 'OWNER' THEN
    RAISE EXCEPTION 'MEMBER_CANNOT_REMOVE_OWNER' USING ERRCODE = '42501';
  END IF;

  SELECT consumed, reason INTO v_consumed, v_reason
  FROM public.consume_step_up_token(p_step_up_token, p_business_id, 'USER_INVITE', NULL);
  IF NOT v_consumed THEN
    RAISE EXCEPTION 'MEMBER_STEP_UP_REJECTED:%', v_reason USING ERRCODE = '42501';
  END IF;

  UPDATE public.business_user_roles SET status='INACTIVE', updated_at=now()
  WHERE user_id = p_target_user_id AND business_id = p_business_id AND status='ACTIVE';
  RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.list_organization_members(p_organization_id uuid)
 RETURNS TABLE(user_id uuid, email text, display_name text, business_id uuid, business_name text, role user_role, role_status text, joined_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_caller_user_id uuid; v_owner_admin_count integer;
BEGIN
  SELECT u.id INTO v_caller_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN RAISE EXCEPTION 'MEMBERS_NOT_AUTHENTICATED' USING ERRCODE = '28000'; END IF;
  SELECT count(*) INTO v_owner_admin_count
  FROM public.business_user_roles bur JOIN public.business_entities be ON be.id = bur.business_id
  WHERE bur.user_id = v_caller_user_id AND bur.status='ACTIVE'
    AND bur.role IN ('OWNER','ADMIN') AND be.organization_id = p_organization_id;
  IF v_owner_admin_count = 0 THEN
    RAISE EXCEPTION 'MEMBERS_REQUIRES_OWNER_OR_ADMIN' USING ERRCODE = '42501';
  END IF;
  RETURN QUERY
  SELECT u.id, u.email, u.display_name, be.id, be.display_name,
         bur.role, bur.status::text, bur.assigned_at
  FROM public.business_user_roles bur
  JOIN public.users u ON u.id = bur.user_id
  JOIN public.business_entities be ON be.id = bur.business_id
  WHERE be.organization_id = p_organization_id
  ORDER BY u.email ASC, be.display_name ASC;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._integration_assert_owner_admin(p_business_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_caller_user_id uuid; v_role public.user_role;
BEGIN
  SELECT u.id INTO v_caller_user_id FROM public.users u
  WHERE u.auth_user_id = auth.uid() AND u.is_active = true;
  IF v_caller_user_id IS NULL THEN RAISE EXCEPTION 'INTEGRATION_NOT_AUTHENTICATED' USING ERRCODE = '28000'; END IF;
  SELECT role INTO v_role FROM public.business_user_roles
  WHERE user_id = v_caller_user_id AND business_id = p_business_id AND status='ACTIVE';
  IF v_role IS NULL OR v_role NOT IN ('OWNER','ADMIN') THEN
    RAISE EXCEPTION 'INTEGRATION_REQUIRES_OWNER_OR_ADMIN' USING ERRCODE = '42501';
  END IF;
  RETURN v_caller_user_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_integration_connect(p_business_id uuid, p_provider integration_provider, p_scope text[], p_encrypted_access_token text, p_encrypted_refresh_token text, p_access_token_expires_at timestamp with time zone)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_caller_user_id uuid; v_organization_id uuid; v_integration_id uuid;
BEGIN
  v_caller_user_id := public._integration_assert_owner_admin(p_business_id);
  SELECT organization_id INTO v_organization_id FROM public.business_entities WHERE id = p_business_id;
  IF v_organization_id IS NULL THEN RAISE EXCEPTION 'INTEGRATION_BUSINESS_NOT_FOUND' USING ERRCODE = '22023'; END IF;

  v_integration_id := public.gen_uuid_v7();
  INSERT INTO public.business_integrations (
    id, organization_id, business_id, provider, status, connected_user_id,
    oauth_access_token_encrypted, oauth_refresh_token_encrypted, scope,
    access_token_expires_at, connected_at, last_refreshed_at, last_error,
    disconnected_at, disconnected_by
  ) VALUES (
    v_integration_id, v_organization_id, p_business_id, p_provider, 'ACTIVE',
    v_caller_user_id, p_encrypted_access_token, p_encrypted_refresh_token,
    p_scope, p_access_token_expires_at, now(), now(), NULL, NULL, NULL
  )
  ON CONFLICT ON CONSTRAINT business_integrations_business_provider_unique
  DO UPDATE SET
    status='ACTIVE', connected_user_id=v_caller_user_id,
    oauth_access_token_encrypted=EXCLUDED.oauth_access_token_encrypted,
    oauth_refresh_token_encrypted=EXCLUDED.oauth_refresh_token_encrypted,
    scope=EXCLUDED.scope, access_token_expires_at=EXCLUDED.access_token_expires_at,
    connected_at=now(), last_refreshed_at=now(),
    last_error=NULL, disconnected_at=NULL, disconnected_by=NULL
  RETURNING id INTO v_integration_id;
  RETURN v_integration_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_integration_refresh(p_integration_id uuid, p_encrypted_access_token text, p_encrypted_refresh_token text, p_access_token_expires_at timestamp with time zone)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_business_id uuid;
BEGIN
  SELECT business_id INTO v_business_id FROM public.business_integrations
  WHERE id = p_integration_id AND status IN ('ACTIVE','ERROR');
  IF v_business_id IS NULL THEN RETURN false; END IF;
  PERFORM public._integration_assert_owner_admin(v_business_id);
  UPDATE public.business_integrations SET
    oauth_access_token_encrypted = p_encrypted_access_token,
    oauth_refresh_token_encrypted = COALESCE(p_encrypted_refresh_token, oauth_refresh_token_encrypted),
    access_token_expires_at = p_access_token_expires_at,
    status='ACTIVE', last_refreshed_at=now(), last_error=NULL
  WHERE id = p_integration_id;
  RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_integration_refresh_failed(p_integration_id uuid, p_error_message text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_business_id uuid;
BEGIN
  SELECT business_id INTO v_business_id FROM public.business_integrations WHERE id = p_integration_id;
  IF v_business_id IS NULL THEN RETURN false; END IF;
  PERFORM public._integration_assert_owner_admin(v_business_id);
  UPDATE public.business_integrations SET status='ERROR', last_error=p_error_message WHERE id = p_integration_id;
  RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_integration_disconnect(p_integration_id uuid, p_step_up_token uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_caller_user_id uuid; v_business_id uuid; v_consumed boolean; v_reason text;
BEGIN
  SELECT business_id INTO v_business_id FROM public.business_integrations
  WHERE id = p_integration_id AND status <> 'DISCONNECTED';
  IF v_business_id IS NULL THEN RETURN false; END IF;
  v_caller_user_id := public._integration_assert_owner_admin(v_business_id);
  SELECT consumed, reason INTO v_consumed, v_reason
  FROM public.consume_step_up_token(p_step_up_token, v_business_id, 'EXTERNAL_INTEGRATION', NULL);
  IF NOT v_consumed THEN RAISE EXCEPTION 'INTEGRATION_STEP_UP_REJECTED:%', v_reason USING ERRCODE = '42501'; END IF;
  UPDATE public.business_integrations SET
    status='DISCONNECTED', disconnected_at=now(), disconnected_by=v_caller_user_id,
    oauth_access_token_encrypted=NULL, oauth_refresh_token_encrypted=NULL
  WHERE id = p_integration_id;
  RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.save_drive_folder_mapping(p_business_id uuid, p_root_folder_id text, p_root_folder_name text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'pg_temp'
AS $function$
DECLARE v_organization_id uuid;
BEGIN
  PERFORM public._integration_assert_owner_admin(p_business_id);
  SELECT organization_id INTO v_organization_id FROM public.business_entities WHERE id = p_business_id;
  IF v_organization_id IS NULL THEN RAISE EXCEPTION 'INTEGRATION_BUSINESS_NOT_FOUND' USING ERRCODE = '22023'; END IF;
  INSERT INTO public.drive_folder_mappings (
    business_id, organization_id, root_folder_id, root_folder_name,
    subfolder_naming_convention, connected_at
  ) VALUES (
    p_business_id, v_organization_id, p_root_folder_id, p_root_folder_name, '2_week_date_ranges', now()
  )
  ON CONFLICT (business_id) DO UPDATE SET
    root_folder_id=EXCLUDED.root_folder_id, root_folder_name=EXCLUDED.root_folder_name, connected_at=now();
  RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.hash_text_sha256(p_text text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'extensions', 'pg_temp'
AS $function$
  SELECT encode(extensions.digest(convert_to(p_text, 'UTF8'), 'sha256'), 'hex');
$function$
;

CREATE OR REPLACE FUNCTION public.hash_chain_append(p_prev_hash text, p_canonical_event_text text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'extensions', 'pg_temp'
AS $function$
  SELECT encode(
    extensions.digest(
      convert_to(p_prev_hash || p_canonical_event_text, 'UTF8'),
      'sha256'
    ),
    'hex'
  );
$function$
;

CREATE OR REPLACE FUNCTION public.raw_upload_size_limit(p_entity upload_entity_type_enum)
 RETURNS bigint
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT CASE p_entity
    WHEN 'STATEMENT'    THEN 52428800::bigint
    WHEN 'INVOICE'      THEN 26214400::bigint
    WHEN 'RECEIPT'      THEN 26214400::bigint
    WHEN 'CONTRACT'     THEN 26214400::bigint
    WHEN 'EVIDENCE_PDF' THEN 10485760::bigint
  END
$function$
;

CREATE OR REPLACE FUNCTION public.raw_upload_allowed_content_types(p_entity upload_entity_type_enum)
 RETURNS text[]
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT CASE p_entity
    WHEN 'STATEMENT'    THEN ARRAY['text/csv','application/pdf']
    WHEN 'INVOICE'      THEN ARRAY['application/pdf','image/jpeg','image/png','image/heic',
                                    'application/vnd.openxmlformats-officedocument.wordprocessingml.document']
    WHEN 'RECEIPT'      THEN ARRAY['application/pdf','image/jpeg','image/png','image/heic']
    WHEN 'CONTRACT'     THEN ARRAY['application/pdf',
                                    'application/vnd.openxmlformats-officedocument.wordprocessingml.document']
    WHEN 'EVIDENCE_PDF' THEN ARRAY['application/pdf']
  END
$function$
;

CREATE OR REPLACE FUNCTION public.request_raw_upload(p_business_id uuid, p_entity_type upload_entity_type_enum, p_original_filename text, p_declared_size_bytes bigint, p_declared_content_type text, p_grant_ttl_seconds integer DEFAULT 900)
 RETURNS TABLE(raw_upload_file_id uuid, storage_bucket text, storage_path text, grant_expires_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_user_id    uuid := public.current_user_id();
  v_org_id     uuid;
  v_size_cap   bigint;
  v_allowed    text[];
  v_file_id    uuid;
  v_path       text;
  v_expires_at timestamptz;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'unauthenticated' USING ERRCODE = '28000';
  END IF;
  IF NOT EXISTS (
    SELECT 1
    FROM public.business_user_roles bur
    JOIN public.business_entities be ON be.id = bur.business_id
    WHERE bur.user_id = v_user_id
      AND bur.business_id = p_business_id
      AND bur.status = 'ACTIVE'
      AND be.is_active = true
  ) THEN
    RAISE EXCEPTION 'business access denied' USING ERRCODE = '42501';
  END IF;

  SELECT organization_id INTO v_org_id
    FROM public.business_entities WHERE id = p_business_id;

  v_size_cap := public.raw_upload_size_limit(p_entity_type);
  v_allowed  := public.raw_upload_allowed_content_types(p_entity_type);

  -- Request-time validation just raises; the API layer owns the
  -- request-time FILE_UPLOAD_REJECTED audit (audit-then-raise inside the
  -- DEFINER function would roll back with the exception).
  IF p_declared_size_bytes <= 0 OR p_declared_size_bytes > v_size_cap THEN
    RAISE EXCEPTION 'declared size % exceeds cap % for %', p_declared_size_bytes, v_size_cap, p_entity_type
      USING ERRCODE = '22000';
  END IF;

  IF NOT (p_declared_content_type = ANY (v_allowed)) THEN
    RAISE EXCEPTION 'content type % not allowed for %', p_declared_content_type, p_entity_type
      USING ERRCODE = '22000';
  END IF;

  IF p_grant_ttl_seconds < 60 OR p_grant_ttl_seconds > 3600 THEN
    RAISE EXCEPTION 'grant TTL must be 60..3600 seconds' USING ERRCODE = '22000';
  END IF;

  v_file_id    := public.gen_uuid_v7();
  v_path       := v_org_id::text || '/' || p_business_id::text || '/'
                  || p_entity_type::text || '/' || v_file_id::text;
  v_expires_at := now() + make_interval(secs => p_grant_ttl_seconds);

  INSERT INTO public.raw_upload_files (
    id, organization_id, business_id, entity_type,
    storage_bucket, storage_path, original_filename,
    declared_size_bytes, declared_content_type,
    status, grant_expires_at, requested_by
  ) VALUES (
    v_file_id, v_org_id, p_business_id, p_entity_type,
    'raw-uploads', v_path, p_original_filename,
    p_declared_size_bytes, p_declared_content_type,
    'PENDING', v_expires_at, v_user_id
  );

  INSERT INTO public.file_audit_events (
    organization_id, business_id, event_type, raw_upload_file_id, storage_path,
    actor_user_id, payload
  ) VALUES (
    v_org_id, p_business_id, 'FILE_UPLOAD_REQUESTED', v_file_id, v_path,
    v_user_id,
    jsonb_build_object(
      'entity_type', p_entity_type::text,
      'declared_size_bytes', p_declared_size_bytes,
      'declared_content_type', p_declared_content_type,
      'grant_ttl_seconds', p_grant_ttl_seconds
    )
  );

  RETURN QUERY SELECT v_file_id, 'raw-uploads'::text, v_path, v_expires_at;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sweep_orphaned_raw_uploads(p_now timestamp with time zone DEFAULT now())
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_orphan record;
  v_count  integer := 0;
BEGIN
  FOR v_orphan IN
    SELECT id, organization_id, business_id, storage_path
      FROM public.raw_upload_files
     WHERE status = 'PENDING' AND grant_expires_at < p_now
     FOR UPDATE SKIP LOCKED
  LOOP
    UPDATE public.raw_upload_files
       SET status = 'ORPHANED', orphaned_at = p_now
     WHERE id = v_orphan.id;
    INSERT INTO public.file_audit_events (
      organization_id, business_id, event_type, raw_upload_file_id, storage_path,
      actor_system, payload
    ) VALUES (
      v_orphan.organization_id, v_orphan.business_id, 'FILE_UPLOAD_ORPHANED',
      v_orphan.id, v_orphan.storage_path, 'orphan-sweep',
      jsonb_build_object('swept_at', p_now)
    );
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_processing_artifact_source_ref()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_ok boolean := false;
BEGIN
  CASE NEW.source_reference_type
    WHEN 'TRANSACTION' THEN
      SELECT EXISTS (SELECT 1 FROM public.transactions
        WHERE id = NEW.source_reference_id AND organization_id = NEW.organization_id AND business_id = NEW.business_id) INTO v_ok;
    WHEN 'DOCUMENT' THEN
      SELECT EXISTS (SELECT 1 FROM public.documents
        WHERE id = NEW.source_reference_id AND organization_id = NEW.organization_id AND business_id = NEW.business_id) INTO v_ok;
    WHEN 'MATCH_RECORD' THEN
      SELECT EXISTS (SELECT 1 FROM public.match_records
        WHERE id = NEW.source_reference_id AND organization_id = NEW.organization_id AND business_id = NEW.business_id) INTO v_ok;
    WHEN 'STATEMENT_UPLOAD' THEN
      SELECT EXISTS (SELECT 1 FROM public.statement_uploads
        WHERE id = NEW.source_reference_id AND organization_id = NEW.organization_id AND business_id = NEW.business_id) INTO v_ok;
    WHEN 'RAW_UPLOAD_FILE' THEN
      SELECT EXISTS (SELECT 1 FROM public.raw_upload_files
        WHERE id = NEW.source_reference_id AND organization_id = NEW.organization_id AND business_id = NEW.business_id) INTO v_ok;
  END CASE;

  IF NOT v_ok THEN
    RAISE EXCEPTION 'processing artifact source_reference (%, %) not found in tenant (%, %)',
      NEW.source_reference_type, NEW.source_reference_id, NEW.organization_id, NEW.business_id
      USING ERRCODE = '23503';
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_raw_upload_view(p_raw_upload_file_id uuid, p_event_type file_audit_event_type_enum DEFAULT 'FILE_VIEWED'::file_audit_event_type_enum)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_row     public.raw_upload_files;
  v_user_id uuid := public.current_user_id();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'unauthenticated' USING ERRCODE = '28000';
  END IF;
  IF p_event_type NOT IN ('FILE_VIEWED','FILE_DOWNLOADED') THEN
    RAISE EXCEPTION 'invalid event type %', p_event_type USING ERRCODE = '22000';
  END IF;

  SELECT * INTO v_row FROM public.raw_upload_files WHERE id = p_raw_upload_file_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'raw upload not found' USING ERRCODE = 'P0002';
  END IF;
  IF v_row.status <> 'CONFIRMED' THEN
    RAISE EXCEPTION 'file not in CONFIRMED state' USING ERRCODE = '22023';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.business_user_roles bur
    WHERE bur.user_id = v_user_id
      AND bur.business_id = v_row.business_id
      AND bur.status = 'ACTIVE'
  ) THEN
    RAISE EXCEPTION 'business access denied' USING ERRCODE = '42501';
  END IF;

  INSERT INTO public.file_audit_events (
    organization_id, business_id, event_type, raw_upload_file_id, storage_path,
    actor_user_id, payload
  ) VALUES (
    v_row.organization_id, v_row.business_id, p_event_type,
    v_row.id, v_row.storage_path, v_user_id, '{}'::jsonb
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.confirm_raw_upload(p_raw_upload_file_id uuid, p_file_hash text, p_actual_size_bytes bigint, p_actual_content_type text, p_confirmed_by_system text DEFAULT NULL::text)
 RETURNS raw_upload_files
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_row     public.raw_upload_files;
  v_user_id uuid := public.current_user_id();
  v_actor   text;
  v_allowed text[];
BEGIN
  v_actor := COALESCE(p_confirmed_by_system, 'service-role');

  SELECT * INTO v_row FROM public.raw_upload_files
    WHERE id = p_raw_upload_file_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'raw upload not found' USING ERRCODE = 'P0002';
  END IF;

  IF v_row.status <> 'PENDING' THEN
    RAISE EXCEPTION 'raw upload already in terminal state %', v_row.status
      USING ERRCODE = '22023';
  END IF;

  IF v_row.grant_expires_at < now() THEN
    UPDATE public.raw_upload_files
       SET status = 'ORPHANED', orphaned_at = now()
     WHERE id = p_raw_upload_file_id
     RETURNING * INTO v_row;
    INSERT INTO public.file_audit_events (
      organization_id, business_id, event_type, raw_upload_file_id, storage_path,
      actor_system, payload
    ) VALUES (
      v_row.organization_id, v_row.business_id, 'FILE_UPLOAD_ORPHANED',
      v_row.id, v_row.storage_path, v_actor,
      jsonb_build_object('reason','grant_ttl_expired_at_confirm')
    );
    RETURN v_row;
  END IF;

  IF p_file_hash IS NULL OR p_file_hash !~ '^[0-9a-f]{64}$' THEN
    UPDATE public.raw_upload_files
       SET status = 'REJECTED', rejected_at = now(),
           reject_reason = 'HASH_MISMATCH',
           reject_detail = 'malformed file_hash'
     WHERE id = p_raw_upload_file_id
     RETURNING * INTO v_row;
    INSERT INTO public.file_audit_events (
      organization_id, business_id, event_type, raw_upload_file_id, storage_path,
      actor_system, payload
    ) VALUES (
      v_row.organization_id, v_row.business_id, 'FILE_UPLOAD_REJECTED',
      v_row.id, v_row.storage_path, v_actor,
      jsonb_build_object('reason','HASH_MISMATCH','detail','malformed file_hash')
    );
    RETURN v_row;
  END IF;

  IF p_actual_size_bytes IS NULL OR p_actual_size_bytes <= 0
     OR p_actual_size_bytes > public.raw_upload_size_limit(v_row.entity_type) THEN
    UPDATE public.raw_upload_files
       SET status = 'REJECTED', rejected_at = now(),
           reject_reason = 'SIZE_LIMIT_EXCEEDED',
           reject_detail = format('actual_size=%s cap=%s',
                                   p_actual_size_bytes,
                                   public.raw_upload_size_limit(v_row.entity_type))
     WHERE id = p_raw_upload_file_id
     RETURNING * INTO v_row;
    INSERT INTO public.file_audit_events (
      organization_id, business_id, event_type, raw_upload_file_id, storage_path,
      actor_system, payload
    ) VALUES (
      v_row.organization_id, v_row.business_id, 'FILE_UPLOAD_REJECTED',
      v_row.id, v_row.storage_path, v_actor,
      jsonb_build_object('reason','SIZE_LIMIT_EXCEEDED',
                         'actual_size_bytes', p_actual_size_bytes)
    );
    RETURN v_row;
  END IF;

  v_allowed := public.raw_upload_allowed_content_types(v_row.entity_type);
  IF NOT (p_actual_content_type = ANY (v_allowed)) THEN
    UPDATE public.raw_upload_files
       SET status = 'REJECTED', rejected_at = now(),
           reject_reason = 'CONTENT_TYPE_NOT_ALLOWED',
           reject_detail = format('actual=%s', p_actual_content_type)
     WHERE id = p_raw_upload_file_id
     RETURNING * INTO v_row;
    INSERT INTO public.file_audit_events (
      organization_id, business_id, event_type, raw_upload_file_id, storage_path,
      actor_system, payload
    ) VALUES (
      v_row.organization_id, v_row.business_id, 'FILE_UPLOAD_REJECTED',
      v_row.id, v_row.storage_path, v_actor,
      jsonb_build_object('reason','CONTENT_TYPE_NOT_ALLOWED',
                         'actual_content_type', p_actual_content_type)
    );
    RETURN v_row;
  END IF;

  IF p_actual_content_type <> v_row.declared_content_type THEN
    UPDATE public.raw_upload_files
       SET status = 'REJECTED', rejected_at = now(),
           reject_reason = 'CONTENT_SNIFF_MISMATCH',
           reject_detail = format('declared=%s actual=%s',
                                   v_row.declared_content_type, p_actual_content_type)
     WHERE id = p_raw_upload_file_id
     RETURNING * INTO v_row;
    INSERT INTO public.file_audit_events (
      organization_id, business_id, event_type, raw_upload_file_id, storage_path,
      actor_system, payload
    ) VALUES (
      v_row.organization_id, v_row.business_id, 'FILE_UPLOAD_REJECTED',
      v_row.id, v_row.storage_path, v_actor,
      jsonb_build_object('reason','CONTENT_SNIFF_MISMATCH',
                         'declared_content_type', v_row.declared_content_type,
                         'actual_content_type', p_actual_content_type)
    );
    RETURN v_row;
  END IF;

  UPDATE public.raw_upload_files
     SET status               = 'CONFIRMED',
         file_hash            = p_file_hash,
         actual_size_bytes    = p_actual_size_bytes,
         actual_content_type  = p_actual_content_type,
         confirmed_at         = now(),
         confirmed_by_user_id = CASE WHEN p_confirmed_by_system IS NULL THEN v_user_id ELSE NULL END,
         confirmed_by_system  = p_confirmed_by_system
   WHERE id = p_raw_upload_file_id
   RETURNING * INTO v_row;

  INSERT INTO public.file_audit_events (
    organization_id, business_id, event_type, raw_upload_file_id, storage_path,
    actor_user_id, actor_system, payload
  ) VALUES (
    v_row.organization_id, v_row.business_id, 'FILE_UPLOADED',
    v_row.id, v_row.storage_path,
    CASE WHEN p_confirmed_by_system IS NULL THEN v_user_id ELSE NULL END,
    p_confirmed_by_system,
    jsonb_build_object(
      'file_hash', p_file_hash,
      'actual_size_bytes', p_actual_size_bytes,
      'actual_content_type', p_actual_content_type
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.write_processing_artifact(p_workflow_run_id uuid, p_artifact_type processing_artifact_type_enum, p_source_reference_type processing_artifact_source_ref_type_enum, p_source_reference_id uuid, p_payload_inline jsonb, p_payload_storage_path text, p_payload_size_bytes bigint, p_payload_hash text, p_actor_system text DEFAULT 'processing-writer'::text)
 RETURNS processing_artifacts
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run     public.workflow_runs;
  v_artifact public.processing_artifacts;
  v_expires timestamptz;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'workflow run % not found', p_workflow_run_id USING ERRCODE = 'P0002';
  END IF;

  v_expires := public.processing_artifact_default_expiry(v_run.status, v_run.finalized_at);

  INSERT INTO public.processing_artifacts (
    organization_id, business_id, workflow_run_id, artifact_type,
    source_reference_type, source_reference_id,
    payload_inline, payload_storage_bucket, payload_storage_path,
    payload_size_bytes, payload_hash, expires_at
  ) VALUES (
    v_run.organization_id, v_run.business_id, v_run.id, p_artifact_type,
    p_source_reference_type, p_source_reference_id,
    p_payload_inline,
    CASE WHEN p_payload_storage_path IS NULL THEN NULL ELSE 'processing-zone' END,
    p_payload_storage_path,
    p_payload_size_bytes, p_payload_hash, v_expires
  )
  RETURNING * INTO v_artifact;

  INSERT INTO public.processing_artifact_events (
    organization_id, business_id, event_type, processing_artifact_id,
    workflow_run_id, actor_system, payload
  ) VALUES (
    v_run.organization_id, v_run.business_id, 'PROCESSING_ARTIFACT_CREATED',
    v_artifact.id, v_run.id, p_actor_system,
    jsonb_build_object(
      'artifact_type', p_artifact_type::text,
      'source_reference_type', p_source_reference_type::text,
      'source_reference_id', p_source_reference_id,
      'storage_mode', CASE WHEN p_payload_storage_path IS NULL THEN 'INLINE' ELSE 'STORAGE' END,
      'payload_hash', p_payload_hash,
      'payload_size_bytes', p_payload_size_bytes,
      'expires_at', v_expires
    )
  );

  RETURN v_artifact;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recompute_processing_ttl_for_run(p_workflow_run_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run     public.workflow_runs;
  v_expires timestamptz;
  v_count   integer;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'workflow run % not found', p_workflow_run_id USING ERRCODE = 'P0002';
  END IF;

  v_expires := public.processing_artifact_default_expiry(v_run.status, v_run.finalized_at);

  UPDATE public.processing_artifacts
     SET expires_at = v_expires
   WHERE workflow_run_id = p_workflow_run_id
     AND (expires_at IS NULL OR (v_expires IS NOT NULL AND v_expires > expires_at));
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.archive_record(p_archive_run_id uuid, p_entity_type archive.archive_entity_type_enum, p_entity_id uuid, p_payload jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE v_run archive.archive_runs;
BEGIN
  SELECT * INTO v_run FROM archive.archive_runs WHERE id = p_archive_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'archive run % not found', p_archive_run_id USING ERRCODE='P0002'; END IF;
  IF v_run.status <> 'PENDING' THEN
    RAISE EXCEPTION 'archive run % not in PENDING state (status=%)', p_archive_run_id, v_run.status USING ERRCODE='22023';
  END IF;

  CASE p_entity_type
    WHEN 'TRANSACTION'  THEN INSERT INTO archive.transactions  (id,organization_id,business_id,archive_run_id,payload) VALUES (p_entity_id,v_run.organization_id,v_run.business_id,v_run.id,p_payload);
    WHEN 'MATCH_RECORD' THEN INSERT INTO archive.match_records (id,organization_id,business_id,archive_run_id,payload) VALUES (p_entity_id,v_run.organization_id,v_run.business_id,v_run.id,p_payload);
    WHEN 'DOCUMENT'     THEN INSERT INTO archive.documents     (id,organization_id,business_id,archive_run_id,payload) VALUES (p_entity_id,v_run.organization_id,v_run.business_id,v_run.id,p_payload);
    WHEN 'EVIDENCE_PDF' THEN INSERT INTO archive.evidence_pdfs (id,organization_id,business_id,archive_run_id,payload) VALUES (p_entity_id,v_run.organization_id,v_run.business_id,v_run.id,p_payload);
    WHEN 'LEDGER_ENTRY' THEN INSERT INTO archive.ledger_entries(id,organization_id,business_id,archive_run_id,payload) VALUES (p_entity_id,v_run.organization_id,v_run.business_id,v_run.id,p_payload);
    WHEN 'REVIEW_ISSUE' THEN INSERT INTO archive.review_issues (id,organization_id,business_id,archive_run_id,payload) VALUES (p_entity_id,v_run.organization_id,v_run.business_id,v_run.id,p_payload);
  END CASE;

  INSERT INTO archive.archive_events (
    organization_id, business_id, event_type, archive_run_id,
    archived_entity_type, archived_entity_id, actor_system, payload
  ) VALUES (
    v_run.organization_id, v_run.business_id, 'ARCHIVE_RECORD_INSERTED', v_run.id,
    p_entity_type, p_entity_id, v_run.archive_writer,
    jsonb_build_object('entity_type',p_entity_type::text,'entity_id',p_entity_id)
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.complete_archive_run(p_archive_run_id uuid, p_bundle_storage_path text)
 RETURNS archive.archive_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE v_run archive.archive_runs;
BEGIN
  SELECT * INTO v_run FROM archive.archive_runs WHERE id = p_archive_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'archive run % not found', p_archive_run_id USING ERRCODE='P0002'; END IF;
  IF v_run.status <> 'PENDING' THEN
    RAISE EXCEPTION 'archive run % not PENDING (status=%)', p_archive_run_id, v_run.status USING ERRCODE='22023';
  END IF;

  EXECUTE 'ALTER TABLE archive.archive_runs DISABLE TRIGGER trg_archive_runs_block_update';
  UPDATE archive.archive_runs
     SET status='COMPLETE', completed_at=now(),
         bundle_storage_bucket='archive-bundles', bundle_storage_path=p_bundle_storage_path
   WHERE id = p_archive_run_id RETURNING * INTO v_run;
  EXECUTE 'ALTER TABLE archive.archive_runs ENABLE TRIGGER trg_archive_runs_block_update';

  INSERT INTO archive.archive_events (
    organization_id, business_id, event_type, archive_run_id, actor_system, payload
  ) VALUES (
    v_run.organization_id, v_run.business_id, 'ARCHIVE_BUNDLE_WRITTEN', v_run.id,
    v_run.archive_writer,
    jsonb_build_object('phase','sealed','bundle_storage_path',p_bundle_storage_path,'manifest_hash',v_run.manifest_hash)
  );
  RETURN v_run;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.fn_block_update()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
BEGIN
  RAISE EXCEPTION 'archive rows are immutable (table %.%)', TG_TABLE_SCHEMA, TG_TABLE_NAME
    USING ERRCODE = '42501';
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.fn_guard_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
BEGIN
  IF COALESCE(current_setting('archive.allow_delete', true), 'off') <> 'on' THEN
    RAISE EXCEPTION 'archive deletes are only allowed via the retention engine (table %.%)',
      TG_TABLE_SCHEMA, TG_TABLE_NAME USING ERRCODE = '42501';
  END IF;
  RETURN OLD;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.has_export_step_up(p_business_id uuid, p_surface text DEFAULT 'archive_export'::text)
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'archive', 'pg_temp'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.step_up_tokens t JOIN public.users u ON u.id = t.user_id
    WHERE u.auth_user_id = auth.uid()
      AND t.business_id = p_business_id AND t.surface = p_surface
      AND t.expires_at > now() AND t.consumed_at IS NULL AND t.revoked_at IS NULL
  );
$function$
;

CREATE OR REPLACE FUNCTION archive.append_archive_run(p_business_id uuid, p_workflow_run_id uuid, p_period_start date, p_period_end date, p_manifest_version integer, p_manifest_payload jsonb, p_manifest_hash text, p_prev_manifest_hash text, p_finalized_by_user_id uuid DEFAULT NULL::uuid, p_archive_writer text DEFAULT 'promotion-pipeline'::text)
 RETURNS archive.archive_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_run archive.archive_runs; v_org uuid; v_wf public.workflow_runs; v_expected_prev text;
BEGIN
  SELECT * INTO v_wf FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND OR v_wf.business_id <> p_business_id THEN
    RAISE EXCEPTION 'workflow run % not found or wrong tenant', p_workflow_run_id USING ERRCODE='P0002';
  END IF;
  IF v_wf.status <> 'FINALIZED' THEN
    RAISE EXCEPTION 'workflow run % must be FINALIZED, got %', p_workflow_run_id, v_wf.status USING ERRCODE='22023';
  END IF;
  v_org := v_wf.organization_id;

  SELECT manifest_hash INTO v_expected_prev FROM archive.archive_runs
   WHERE business_id = p_business_id AND status = 'COMPLETE'
   ORDER BY started_at DESC LIMIT 1;
  IF v_expected_prev IS NULL THEN v_expected_prev := repeat('0', 64); END IF;
  IF p_prev_manifest_hash <> v_expected_prev THEN
    RAISE EXCEPTION 'prev_manifest_hash chain mismatch (expected %, got %)',
      v_expected_prev, p_prev_manifest_hash USING ERRCODE='22023';
  END IF;

  INSERT INTO archive.archive_runs (
    organization_id, business_id, workflow_run_id, status,
    period_start, period_end, manifest_version, manifest_hash, prev_manifest_hash, manifest_payload,
    started_at, finalized_by_user_id, archive_writer
  ) VALUES (
    v_org, p_business_id, p_workflow_run_id, 'PENDING',
    p_period_start, p_period_end, p_manifest_version, p_manifest_hash, p_prev_manifest_hash, p_manifest_payload,
    now(), p_finalized_by_user_id, p_archive_writer
  ) RETURNING * INTO v_run;

  INSERT INTO archive.archive_events (
    organization_id, business_id, event_type, archive_run_id,
    actor_user_id, actor_system, payload
  ) VALUES (
    v_org, p_business_id, 'ARCHIVE_BUNDLE_WRITTEN', v_run.id,
    p_finalized_by_user_id,
    CASE WHEN p_finalized_by_user_id IS NULL THEN p_archive_writer ELSE NULL END,
    jsonb_build_object('phase','opened','manifest_version',p_manifest_version,'manifest_hash',p_manifest_hash,'prev_manifest_hash',p_prev_manifest_hash)
  );
  RETURN v_run;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.retention_delete_archive_run(p_archive_run_id uuid, p_reason text DEFAULT 'retention_window_elapsed'::text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE v_run archive.archive_runs; v_total integer := 0; v_count integer;
BEGIN
  SELECT * INTO v_run FROM archive.archive_runs WHERE id = p_archive_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'archive run % not found', p_archive_run_id USING ERRCODE='P0002'; END IF;

  PERFORM set_config('archive.allow_delete', 'on', true);

  DELETE FROM archive.transactions       WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.match_records      WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.documents          WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.evidence_pdfs      WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.ledger_entries     WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.review_issues      WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.workflow_runs_summary WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.archive_runs       WHERE id = p_archive_run_id;             GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;

  PERFORM set_config('archive.allow_delete', 'off', true);

  INSERT INTO archive.archive_events (
    organization_id, business_id, event_type, archive_run_id, actor_system, payload
  ) VALUES (
    v_run.organization_id, v_run.business_id, 'ARCHIVE_BUNDLE_WRITTEN', NULL,
    'retention-engine',
    jsonb_build_object('phase','deleted','reason',p_reason,'rows_deleted',v_total,'archive_run_id',p_archive_run_id)
  );
  RETURN v_total;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.record_archive_view(p_business_id uuid, p_archive_run_id uuid, p_event_type archive.archive_event_type_enum)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_user uuid := public.current_user_id();
  v_org  uuid;
BEGIN
  IF v_user IS NULL THEN RAISE EXCEPTION 'unauthenticated' USING ERRCODE='28000'; END IF;
  IF p_event_type NOT IN ('ARCHIVE_RECORD_VIEWED','ARCHIVE_BUNDLE_EXPORTED') THEN
    RAISE EXCEPTION 'invalid event %', p_event_type USING ERRCODE='22000';
  END IF;

  SELECT organization_id INTO v_org FROM public.business_entities WHERE id=p_business_id;

  IF NOT EXISTS (
    SELECT 1 FROM public.business_user_roles bur
    WHERE bur.user_id = v_user AND bur.business_id = p_business_id AND bur.status='ACTIVE'
      AND bur.role IN ('OWNER','ADMIN','ACCOUNTANT','REVIEWER','READ_ONLY','BOOKKEEPER')
  ) THEN
    INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_user_id, reject_reason, payload)
    VALUES (v_org, p_business_id, 'ARCHIVE_WRITE_REJECTED', p_archive_run_id, v_user,
            'WRONG_ROLE', jsonb_build_object('attempted',p_event_type::text));
    RETURN 'REJECTED:WRONG_ROLE';
  END IF;

  IF p_event_type = 'ARCHIVE_BUNDLE_EXPORTED' AND NOT archive.has_export_step_up(p_business_id) THEN
    INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_user_id, reject_reason, payload)
    VALUES (v_org, p_business_id, 'ARCHIVE_WRITE_REJECTED', p_archive_run_id, v_user,
            'MISSING_STEP_UP', jsonb_build_object('attempted','ARCHIVE_BUNDLE_EXPORTED'));
    RETURN 'REJECTED:MISSING_STEP_UP';
  END IF;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_user_id, payload)
  VALUES (v_org, p_business_id, p_event_type, p_archive_run_id, v_user, '{}'::jsonb);
  RETURN 'OK';
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.promote_workflow_run(p_workflow_run_id uuid, p_period_start date, p_period_end date, p_manifest_payload jsonb, p_manifest_hash text, p_prev_manifest_hash text, p_manifest_version integer DEFAULT 1, p_adjustment_of_archive_run_id uuid DEFAULT NULL::uuid, p_finalized_by_user_id uuid DEFAULT NULL::uuid, p_archive_writer text DEFAULT 'promotion-pipeline'::text)
 RETURNS archive.archive_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_wf           public.workflow_runs;
  v_run          archive.archive_runs;
  v_org          uuid;
  v_biz          uuid;
  v_tx_ct        integer := 0;
  v_match_ct     integer := 0;
  v_doc_ct       integer := 0;
  v_ledger_ct    integer := 0;
  v_issue_ct     integer := 0;
  v_locked_ids   uuid[];
  v_proc_ct      integer := 0;
  v_row          record;
  v_is_adjustment boolean := (p_adjustment_of_archive_run_id IS NOT NULL);
BEGIN
  SELECT * INTO v_wf FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'workflow run % not found', p_workflow_run_id USING ERRCODE='P0002'; END IF;
  IF v_wf.status <> 'FINALIZED' THEN
    RAISE EXCEPTION 'workflow run % must be FINALIZED (got %)', p_workflow_run_id, v_wf.status USING ERRCODE='22023';
  END IF;
  v_org := v_wf.organization_id;
  v_biz := v_wf.business_id;

  IF v_is_adjustment THEN
    PERFORM 1 FROM archive.archive_runs
      WHERE id = p_adjustment_of_archive_run_id
        AND business_id = v_biz AND period_start = p_period_start
        AND period_end = p_period_end AND status = 'COMPLETE';
    IF NOT FOUND THEN
      RAISE EXCEPTION 'adjustment parent % not found / wrong tenant / period mismatch',
        p_adjustment_of_archive_run_id USING ERRCODE='22023';
    END IF;
  END IF;

  v_run := archive.append_archive_run(
    v_biz, p_workflow_run_id, p_period_start, p_period_end,
    p_manifest_version, p_manifest_payload, p_manifest_hash, p_prev_manifest_hash,
    p_finalized_by_user_id, p_archive_writer, p_adjustment_of_archive_run_id
  );

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_user_id, actor_system, payload)
  VALUES (v_org, v_biz, 'ARCHIVE_PROMOTION_STARTED', v_run.id, p_finalized_by_user_id,
          CASE WHEN p_finalized_by_user_id IS NULL THEN p_archive_writer ELSE NULL END,
          jsonb_build_object('workflow_run_id', p_workflow_run_id,'is_adjustment',v_is_adjustment,'manifest_version',p_manifest_version,'adjustment_of_archive_run_id', p_adjustment_of_archive_run_id));

  FOR v_row IN
    SELECT t.id, to_jsonb(t) AS payload FROM public.transactions t
     WHERE t.business_id = v_biz
       AND EXISTS (SELECT 1 FROM public.draft_ledger_entries dle
                   WHERE dle.workflow_run_id = p_workflow_run_id AND dle.transaction_id = t.id
                     AND (NOT v_is_adjustment OR dle.parent_finalized_run_id IS NOT NULL))
  LOOP
    PERFORM archive.archive_record(v_run.id, 'TRANSACTION', v_row.id, v_row.payload);
    v_tx_ct := v_tx_ct + 1;
  END LOOP;

  FOR v_row IN
    SELECT d.id, to_jsonb(d) AS payload FROM public.documents d
     WHERE d.business_id = v_biz
       AND EXISTS (SELECT 1 FROM public.draft_ledger_entries dle
                   JOIN public.match_records mr ON mr.id = dle.match_record_id
                   WHERE dle.workflow_run_id = p_workflow_run_id AND mr.document_id = d.id
                     AND (NOT v_is_adjustment OR dle.parent_finalized_run_id IS NOT NULL))
  LOOP
    PERFORM archive.archive_record(v_run.id, 'DOCUMENT', v_row.id, v_row.payload);
    v_doc_ct := v_doc_ct + 1;
  END LOOP;

  FOR v_row IN
    SELECT mr.id, to_jsonb(mr) AS payload FROM public.match_records mr
     WHERE mr.business_id = v_biz
       AND EXISTS (SELECT 1 FROM public.draft_ledger_entries dle
                   WHERE dle.workflow_run_id = p_workflow_run_id AND dle.match_record_id = mr.id
                     AND (NOT v_is_adjustment OR dle.parent_finalized_run_id IS NOT NULL))
  LOOP
    PERFORM archive.archive_record(v_run.id, 'MATCH_RECORD', v_row.id, v_row.payload);
    v_match_ct := v_match_ct + 1;
  END LOOP;

  FOR v_row IN
    SELECT dle.id, to_jsonb(dle) AS payload FROM public.draft_ledger_entries dle
     WHERE dle.workflow_run_id = p_workflow_run_id AND dle.business_id = v_biz
       AND dle.approval_status = 'APPROVED'
       AND (NOT v_is_adjustment OR dle.parent_finalized_run_id IS NOT NULL)
  LOOP
    PERFORM archive.archive_record(v_run.id, 'LEDGER_ENTRY', v_row.id, v_row.payload);
    v_locked_ids := array_append(v_locked_ids, v_row.id);
    v_ledger_ct := v_ledger_ct + 1;
  END LOOP;

  FOR v_row IN
    SELECT ri.id, to_jsonb(ri) AS payload FROM public.review_issues ri
     WHERE ri.workflow_run_id = p_workflow_run_id AND ri.business_id = v_biz
       AND ri.status IN ('RESOLVED','DISMISSED','AUTO_RESOLVED_BY_RESCAN')
  LOOP
    PERFORM archive.archive_record(v_run.id, 'REVIEW_ISSUE', v_row.id, v_row.payload);
    v_issue_ct := v_issue_ct + 1;
  END LOOP;

  INSERT INTO archive.workflow_runs_summary (id, organization_id, business_id, archive_run_id, payload)
  VALUES (v_wf.id, v_org, v_biz, v_run.id, to_jsonb(v_wf));

  IF v_locked_ids IS NOT NULL AND cardinality(v_locked_ids) > 0 THEN
    UPDATE public.draft_ledger_entries SET approval_status='LOCKED' WHERE id = ANY(v_locked_ids);
  END IF;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_user_id, actor_system, payload)
  VALUES (v_org, v_biz, 'ARCHIVE_PROMOTION_RECORDS_WRITTEN', v_run.id, p_finalized_by_user_id,
          CASE WHEN p_finalized_by_user_id IS NULL THEN p_archive_writer ELSE NULL END,
          jsonb_build_object('transactions',v_tx_ct,'documents',v_doc_ct,'match_records',v_match_ct,
                             'ledger_entries',v_ledger_ct,'review_issues',v_issue_ct,'workflow_summary',1,
                             'locked_ledger_entry_ids', to_jsonb(v_locked_ids)));

  PERFORM public.recompute_processing_ttl_for_run(p_workflow_run_id);
  SELECT count(*) INTO v_proc_ct FROM public.processing_artifacts
    WHERE workflow_run_id = p_workflow_run_id AND expires_at IS NOT NULL;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
  VALUES (v_org, v_biz, 'PROCESSING_PRUNE_SCHEDULED', v_run.id, p_archive_writer,
          jsonb_build_object('workflow_run_id',p_workflow_run_id,'processing_artifacts_scheduled',v_proc_ct));

  RETURN v_run;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_tool_registration_rejected(p_tool_name text, p_reason text, p_error_detail text DEFAULT NULL::text)
 RETURNS audit.audit_events
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_row audit.audit_events;
BEGIN
  IF p_tool_name IS NULL OR length(btrim(p_tool_name)) = 0 THEN
    RAISE EXCEPTION 'record_tool_registration_rejected: tool_name required' USING ERRCODE='22000';
  END IF;
  v_row := audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'TOOL_REGISTRY_REJECTED',
    p_subject_type => 'TOOL_REGISTRY'::audit.subject_type_enum,
    p_actor_system => 'engine.registerTool',
    p_reason       => format('tool %s registration rejected: %s', p_tool_name, p_reason),
    p_after_state  => jsonb_build_object('tool_name', p_tool_name, 'reason', p_reason, 'error_detail', p_error_detail)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.rollback_promotion(p_archive_run_id uuid, p_reason text DEFAULT 'rollback_requested'::text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_run archive.archive_runs; v_locked_ids uuid[]; v_total integer := 0; v_count integer;
BEGIN
  SELECT * INTO v_run FROM archive.archive_runs WHERE id = p_archive_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'archive run % not found', p_archive_run_id USING ERRCODE='P0002'; END IF;
  IF v_run.status <> 'PENDING' THEN
    RAISE EXCEPTION 'cannot rollback archive_run % in status %', p_archive_run_id, v_run.status USING ERRCODE='22023';
  END IF;

  SELECT array_agg(id) INTO v_locked_ids FROM archive.ledger_entries WHERE archive_run_id = p_archive_run_id;
  IF v_locked_ids IS NOT NULL AND cardinality(v_locked_ids) > 0 THEN
    UPDATE public.draft_ledger_entries SET approval_status='APPROVED'
     WHERE id = ANY(v_locked_ids) AND approval_status='LOCKED';
  END IF;

  PERFORM set_config('archive.allow_delete', 'on', true);
  DELETE FROM archive.transactions       WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.match_records      WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.documents          WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.evidence_pdfs      WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.ledger_entries     WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.review_issues      WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.workflow_runs_summary WHERE archive_run_id = p_archive_run_id; GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  DELETE FROM archive.archive_runs       WHERE id = p_archive_run_id;             GET DIAGNOSTICS v_count=ROW_COUNT; v_total := v_total + v_count;
  PERFORM set_config('archive.allow_delete', 'off', true);

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
  VALUES (v_run.organization_id, v_run.business_id, 'ARCHIVE_PROMOTION_ROLLED_BACK', NULL,
          'promotion-pipeline',
          jsonb_build_object('archive_run_id',p_archive_run_id,'workflow_run_id',v_run.workflow_run_id,
                             'reason',p_reason,'rows_deleted',v_total,
                             'unlocked_ledger_entry_ids', to_jsonb(v_locked_ids)));
  RETURN v_total;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_audit_workflow_run_creation()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
BEGIN
  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_RUN_STATE_CHANGED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => NEW.id,
    p_business_id    => NEW.business_id,
    p_organization_id=> NEW.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => 'workflow_run created (null → CREATED)',
    p_after_state    => jsonb_build_object(
      'run_id',         NEW.id,
      'transition_name','create',
      'from_state',     NULL,
      'to_state',       NEW.status::text,
      'workflow_type',  NEW.workflow_type::text,
      'started_by',     NEW.started_by
    )
  );
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.record_promotion_failure(p_business_id uuid, p_workflow_run_id uuid, p_reason text, p_error_payload jsonb DEFAULT '{}'::jsonb, p_archive_writer text DEFAULT 'promotion-pipeline'::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE v_org uuid;
BEGIN
  SELECT organization_id INTO v_org FROM public.business_entities WHERE id = p_business_id;
  IF v_org IS NULL THEN RAISE EXCEPTION 'business % not found', p_business_id USING ERRCODE='P0002'; END IF;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
  VALUES (v_org, p_business_id, 'ARCHIVE_PROMOTION_FAILED', NULL, p_archive_writer,
          jsonb_build_object('workflow_run_id',p_workflow_run_id,'reason',p_reason,'error',p_error_payload));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.list_legal_transitions(p_current_state workflow_run_status_enum)
 RETURNS SETOF workflow_run_state_transitions
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT *
    FROM public.workflow_run_state_transitions
   WHERE (NOT from_state_is_wildcard AND from_state = p_current_state)
      OR (from_state_is_wildcard AND p_current_state IS NOT NULL AND p_current_state NOT IN ('FINALIZED','ABORTED','FAILED','CANCELLED'))
   ORDER BY transition_name;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_block_direct_status_update()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  IF NEW.status IS DISTINCT FROM OLD.status THEN
    IF COALESCE(current_setting('app.transition_run_active', true),'') <> 'true' THEN
      RAISE EXCEPTION 'workflow_runs.status: direct UPDATE forbidden — use public.transition_run (% → %)', OLD.status, NEW.status
        USING ERRCODE='42501';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.append_archive_run(p_business_id uuid, p_workflow_run_id uuid, p_period_start date, p_period_end date, p_manifest_version integer, p_manifest_payload jsonb, p_manifest_hash text, p_prev_manifest_hash text, p_finalized_by_user_id uuid DEFAULT NULL::uuid, p_archive_writer text DEFAULT 'promotion-pipeline'::text, p_adjustment_of_archive_run_id uuid DEFAULT NULL::uuid)
 RETURNS archive.archive_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_run archive.archive_runs; v_org uuid; v_wf public.workflow_runs; v_expected_prev text;
BEGIN
  SELECT * INTO v_wf FROM public.workflow_runs WHERE id = p_workflow_run_id;
  IF NOT FOUND OR v_wf.business_id <> p_business_id THEN
    RAISE EXCEPTION 'workflow run % not found or wrong tenant', p_workflow_run_id USING ERRCODE='P0002';
  END IF;
  IF v_wf.status <> 'FINALIZED' THEN
    RAISE EXCEPTION 'workflow run % must be FINALIZED, got %', p_workflow_run_id, v_wf.status USING ERRCODE='22023';
  END IF;
  v_org := v_wf.organization_id;

  SELECT manifest_hash INTO v_expected_prev FROM archive.archive_runs
   WHERE business_id = p_business_id AND status = 'COMPLETE'
   ORDER BY started_at DESC LIMIT 1;
  IF v_expected_prev IS NULL THEN v_expected_prev := repeat('0', 64); END IF;
  IF p_prev_manifest_hash <> v_expected_prev THEN
    RAISE EXCEPTION 'prev_manifest_hash chain mismatch (expected %, got %)',
      v_expected_prev, p_prev_manifest_hash USING ERRCODE='22023';
  END IF;

  INSERT INTO archive.archive_runs (
    organization_id, business_id, workflow_run_id, status,
    period_start, period_end, manifest_version, manifest_hash, prev_manifest_hash, manifest_payload,
    started_at, finalized_by_user_id, archive_writer, adjustment_of_archive_run_id
  ) VALUES (
    v_org, p_business_id, p_workflow_run_id, 'PENDING',
    p_period_start, p_period_end, p_manifest_version, p_manifest_hash, p_prev_manifest_hash, p_manifest_payload,
    now(), p_finalized_by_user_id, p_archive_writer, p_adjustment_of_archive_run_id
  ) RETURNING * INTO v_run;

  INSERT INTO archive.archive_events (
    organization_id, business_id, event_type, archive_run_id,
    actor_user_id, actor_system, payload
  ) VALUES (
    v_org, p_business_id, 'ARCHIVE_BUNDLE_WRITTEN', v_run.id,
    p_finalized_by_user_id,
    CASE WHEN p_finalized_by_user_id IS NULL THEN p_archive_writer ELSE NULL END,
    jsonb_build_object('phase','opened','manifest_version',p_manifest_version,'manifest_hash',p_manifest_hash,'prev_manifest_hash',p_prev_manifest_hash)
  );
  RETURN v_run;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.transition_run(p_run_id uuid, p_target_state workflow_run_status_enum, p_actor_user_id uuid, p_reason text DEFAULT NULL::text, p_step_up_verified boolean DEFAULT false, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run         public.workflow_runs;
  v_trans       public.workflow_run_state_transitions;
  v_perm        jsonb;
  v_perm_dec    text;
  v_audit       audit.audit_events;
  v_set_clauses text := '';
  v_sql         text;
  v_reject_code text;
  v_reject_msg  text;
  v_is_system   boolean;
BEGIN
  IF p_run_id IS NULL OR p_target_state IS NULL THEN
    RAISE EXCEPTION 'transition_run: run_id and target_state are required' USING ERRCODE='22000';
  END IF;
  v_is_system := (p_actor_user_id IS NULL);
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'transition_run: run_id % not found', p_run_id USING ERRCODE='P0002'; END IF;
  IF public.is_terminal_state(v_run.status) THEN
    v_reject_code := 'TERMINAL_STATE';
    v_reject_msg  := format('run is in terminal state %s; no transitions permitted', v_run.status);
  ELSE
    SELECT * INTO v_trans FROM public.workflow_run_state_transitions
     WHERE to_state = p_target_state
       AND ((NOT from_state_is_wildcard AND from_state = v_run.status) OR from_state_is_wildcard)
     ORDER BY from_state_is_wildcard ASC LIMIT 1;
    IF NOT FOUND THEN
      v_reject_code := 'ILLEGAL_TRANSITION';
      v_reject_msg  := format('no transition defined: %s → %s', v_run.status, p_target_state);
    END IF;
  END IF;
  IF v_reject_code IS NULL AND v_is_system AND v_trans.requires_permission_surface IS NOT NULL THEN
    v_reject_code := 'SYSTEM_FORBIDDEN_FOR_PRIVILEGED_TRANSITION';
    v_reject_msg  := format('SYSTEM actor cannot perform privileged transition %s', v_trans.transition_name);
  END IF;
  IF v_reject_code IS NULL AND v_trans.requires_step_up AND NOT COALESCE(p_step_up_verified, false) THEN
    v_reject_code := 'STEP_UP_REQUIRED';
    v_reject_msg  := format('transition %s requires step-up MFA verification', v_trans.transition_name);
  END IF;
  IF v_reject_code IS NULL AND v_trans.requires_reason AND (p_reason IS NULL OR length(btrim(p_reason)) = 0) THEN
    v_reject_code := 'REASON_REQUIRED';
    v_reject_msg  := format('transition %s requires a non-empty reason', v_trans.transition_name);
  END IF;
  IF v_reject_code IS NULL AND NOT v_is_system AND v_trans.requires_permission_surface IS NOT NULL THEN
    v_perm := public.can_perform(
      p_actor_user_id   => p_actor_user_id,
      p_surface         => v_trans.requires_permission_surface,
      p_action          => v_trans.requires_permission_action,
      p_resource        => jsonb_build_object('run_id', v_run.id, 'workflow_type', v_run.workflow_type),
      p_business_id     => v_run.business_id,
      p_organization_id => v_run.organization_id);
    v_perm_dec := v_perm->>'decision';
    IF v_perm_dec = 'DENY' THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg  := format('actor lacks permission %s:%s (reason=%s)',
                              v_trans.requires_permission_surface, v_trans.requires_permission_action,
                              v_perm->>'reason_code');
    ELSIF v_perm_dec IN ('STEP_UP','REQUIRE_STEP_UP') AND NOT COALESCE(p_step_up_verified, false) THEN
      v_reject_code := 'STEP_UP_REQUIRED';
      v_reject_msg  := format('permission %s:%s requires step-up MFA',
                              v_trans.requires_permission_surface, v_trans.requires_permission_action);
    ELSIF v_perm_dec NOT IN ('ALLOW','STEP_UP','REQUIRE_STEP_UP') THEN
      v_reject_code := 'PERMISSION_DENIED';
      v_reject_msg  := format('unexpected can_perform decision: %s', v_perm_dec);
    END IF;
  END IF;
  IF v_reject_code IS NOT NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind     => CASE WHEN v_is_system THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action         => 'WORKFLOW_RUN_STATE_CHANGE_REJECTED',
      p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_run.id,
      p_business_id    => v_run.business_id, p_organization_id=> v_run.organization_id,
      p_actor_user_id  => CASE WHEN v_is_system THEN NULL ELSE p_actor_user_id END,
      p_actor_system   => CASE WHEN v_is_system THEN 'workflow_engine' ELSE NULL END,
      p_reason         => v_reject_msg,
      p_after_state    => jsonb_build_object('run_id', v_run.id, 'from_state', v_run.status::text,
        'attempted_to', p_target_state::text, 'rejection_code', v_reject_code, 'context', p_context));
    RETURN jsonb_build_object('ok', false, 'run_id', v_run.id,
      'from_state', v_run.status::text, 'to_state', v_run.status::text,
      'reason', v_reject_code, 'message', v_reject_msg);
  END IF;
  v_set_clauses := format('status = %L::public.workflow_run_status_enum', p_target_state);
  IF v_trans.side_effect_columns ? 'started_at'    THEN v_set_clauses := v_set_clauses || ', started_at = clock_timestamp()'; END IF;
  IF v_trans.side_effect_columns ? 'finalized_at'  THEN v_set_clauses := v_set_clauses || ', finalized_at = clock_timestamp()'; END IF;
  IF v_trans.side_effect_columns ? 'finalized_by'  THEN v_set_clauses := v_set_clauses || format(', finalized_by = %L::uuid', p_actor_user_id); END IF;
  IF v_trans.side_effect_columns ? 'aborted_at'    THEN v_set_clauses := v_set_clauses || ', aborted_at = clock_timestamp()'; END IF;
  IF v_trans.side_effect_columns ? 'aborted_by'    THEN v_set_clauses := v_set_clauses || format(', aborted_by = %L::uuid', p_actor_user_id); END IF;
  IF v_trans.side_effect_columns ? 'abort_reason'  THEN v_set_clauses := v_set_clauses || format(', abort_reason = %L', p_reason); END IF;
  IF v_trans.side_effect_columns ? 'completed_at'  THEN v_set_clauses := v_set_clauses || ', completed_at = clock_timestamp()'; END IF;
  v_set_clauses := v_set_clauses || ', updated_at = clock_timestamp()';
  PERFORM set_config('app.transition_run_active', 'true', true);
  v_sql := format('UPDATE public.workflow_runs SET %s WHERE id = %L', v_set_clauses, p_run_id);
  EXECUTE v_sql;
  PERFORM set_config('app.transition_run_active', 'false', true);
  v_audit := audit.emit_audit(
    p_actor_kind     => CASE WHEN v_is_system THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
    p_action         => 'WORKFLOW_RUN_STATE_CHANGED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_run.id,
    p_business_id    => v_run.business_id, p_organization_id=> v_run.organization_id,
    p_actor_user_id  => CASE WHEN v_is_system THEN NULL ELSE p_actor_user_id END,
    p_actor_system   => CASE WHEN v_is_system THEN 'workflow_engine' ELSE NULL END,
    p_reason         => format('transition %s: %s → %s', v_trans.transition_name, v_run.status, p_target_state),
    p_before_state   => jsonb_build_object('status', v_run.status::text),
    p_after_state    => jsonb_build_object('run_id', v_run.id, 'transition_name', v_trans.transition_name,
      'from_state', v_run.status::text, 'to_state', p_target_state::text,
      'reason', p_reason, 'context', p_context));
  IF v_trans.transition_name = 'pause' THEN
    PERFORM audit.emit_audit(
      p_actor_kind => CASE WHEN v_is_system THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action => 'WORKFLOW_RUN_PAUSED',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_run.id,
      p_business_id => v_run.business_id, p_organization_id => v_run.organization_id,
      p_actor_user_id => CASE WHEN v_is_system THEN NULL ELSE p_actor_user_id END,
      p_actor_system  => CASE WHEN v_is_system THEN 'workflow_engine' ELSE NULL END,
      p_reason => format('run %s paused', v_run.id),
      p_before_state => jsonb_build_object('status', v_run.status::text),
      p_after_state  => jsonb_build_object('status', p_target_state::text));
  ELSIF v_trans.transition_name = 'resume' THEN
    PERFORM audit.emit_audit(
      p_actor_kind => CASE WHEN v_is_system THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action => 'WORKFLOW_RUN_RESUMED',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_run.id,
      p_business_id => v_run.business_id, p_organization_id => v_run.organization_id,
      p_actor_user_id => CASE WHEN v_is_system THEN NULL ELSE p_actor_user_id END,
      p_actor_system  => CASE WHEN v_is_system THEN 'workflow_engine' ELSE NULL END,
      p_reason => format('run %s resumed', v_run.id),
      p_before_state => jsonb_build_object('status', v_run.status::text),
      p_after_state  => jsonb_build_object('status', p_target_state::text));
  ELSIF v_trans.transition_name = 'abort' THEN
    PERFORM audit.emit_audit(
      p_actor_kind => CASE WHEN v_is_system THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action => 'WORKFLOW_RUN_ABORTED',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_run.id,
      p_business_id => v_run.business_id, p_organization_id => v_run.organization_id,
      p_actor_user_id => CASE WHEN v_is_system THEN NULL ELSE p_actor_user_id END,
      p_actor_system  => CASE WHEN v_is_system THEN 'workflow_engine' ELSE NULL END,
      p_reason => format('run %s aborted: %s', v_run.id, p_reason),
      p_before_state => jsonb_build_object('status', v_run.status::text),
      p_after_state  => jsonb_build_object('status', p_target_state::text, 'abort_reason', p_reason));
  ELSIF v_trans.transition_name = 'finalize_complete' THEN
    PERFORM audit.emit_audit(
      p_actor_kind => CASE WHEN v_is_system THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action => 'WORKFLOW_RUN_FINALIZED',
      p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_run.id,
      p_business_id => v_run.business_id, p_organization_id => v_run.organization_id,
      p_actor_user_id => CASE WHEN v_is_system THEN NULL ELSE p_actor_user_id END,
      p_actor_system  => CASE WHEN v_is_system THEN 'workflow_engine' ELSE NULL END,
      p_reason => format('run %s finalized', v_run.id),
      p_before_state => jsonb_build_object('status', v_run.status::text),
      p_after_state  => jsonb_build_object('status', p_target_state::text));
  END IF;
  RETURN jsonb_build_object('ok', true, 'run_id', v_run.id,
    'from_state', v_run.status::text, 'to_state', p_target_state::text,
    'transition_name', v_trans.transition_name, 'audit_event_id', v_audit.event_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.fn_seed_retention_policy()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
BEGIN
  INSERT INTO archive.retention_policies (business_id, organization_id, retention_years)
  VALUES (NEW.id, NEW.organization_id, 6)
  ON CONFLICT (business_id) DO NOTHING;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.retention_threshold(p_business_id uuid, p_now timestamp with time zone DEFAULT now())
 RETURNS timestamp with time zone
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
  SELECT p_now - make_interval(years => COALESCE((
    SELECT retention_years FROM archive.retention_policies WHERE business_id = p_business_id
  ), 6))
$function$
;

CREATE OR REPLACE FUNCTION archive.legal_hold_status(p_business_id uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
  WITH active AS (
    SELECT hold_reason FROM archive.legal_holds
     WHERE business_id = p_business_id AND status = 'ACTIVE'
  )
  SELECT jsonb_build_object(
    'on_hold',      EXISTS (SELECT 1 FROM active),
    'hold_reasons', COALESCE((SELECT jsonb_agg(hold_reason) FROM active), '[]'::jsonb)
  )
$function$
;

CREATE OR REPLACE FUNCTION archive.record_retention_inconsistency(p_business_id uuid, p_archive_run_id uuid, p_storage_path text, p_reason text, p_error_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE v_org uuid;
BEGIN
  SELECT organization_id INTO v_org FROM public.business_entities WHERE id = p_business_id;
  IF v_org IS NULL THEN RAISE EXCEPTION 'business % not found', p_business_id USING ERRCODE='P0002'; END IF;
  INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, reject_reason, payload)
  VALUES (v_org, p_business_id, 'RETENTION_DELETION_INCONSISTENT', p_archive_run_id,
          'retention-engine', 'OTHER',
          jsonb_build_object('storage_path', p_storage_path, 'reason', p_reason, 'error', p_error_payload));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enter_phase(p_run_id uuid, p_phase_name text)
 RETURNS workflow_phase_states
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_run         public.workflow_runs;
  v_def         public.workflow_phase_definitions;
  v_state       public.workflow_phase_states;
  v_max_order   integer;
BEGIN
  IF p_run_id IS NULL OR p_phase_name IS NULL OR length(btrim(p_phase_name))=0 THEN
    RAISE EXCEPTION 'enter_phase: run_id and phase_name required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'enter_phase: run % not found', p_run_id USING ERRCODE='P0002'; END IF;
  IF public.is_terminal_state(v_run.status) THEN
    RAISE EXCEPTION 'enter_phase: run % is terminal (%)', p_run_id, v_run.status USING ERRCODE='P0001';
  END IF;

  SELECT * INTO v_def
    FROM public.workflow_phase_definitions
   WHERE workflow_type = v_run.workflow_type AND phase_name = p_phase_name
   LIMIT 1;

  SELECT * INTO v_state
    FROM public.workflow_phase_states
   WHERE workflow_run_id = p_run_id AND phase_name = p_phase_name
   ORDER BY phase_order DESC LIMIT 1;

  IF FOUND THEN
    IF v_state.status = 'RUNNING' THEN
      RETURN v_state;
    ELSIF v_state.status = 'PENDING' THEN
      UPDATE public.workflow_phase_states
         SET status = 'RUNNING'::public.phase_state_status_enum,
             started_at = COALESCE(started_at, clock_timestamp()),
             updated_at = clock_timestamp()
       WHERE id = v_state.id
       RETURNING * INTO v_state;
    ELSE
      RAISE EXCEPTION 'enter_phase: phase % already in status % (cannot re-enter)', p_phase_name, v_state.status USING ERRCODE='P0001';
    END IF;
  ELSE
    SELECT COALESCE(MAX(phase_order), 0) INTO v_max_order
      FROM public.workflow_phase_states WHERE workflow_run_id = p_run_id;
    INSERT INTO public.workflow_phase_states (workflow_run_id, phase_name, phase_order, status, started_at)
    VALUES (
      p_run_id, p_phase_name,
      COALESCE(v_def.phase_order, v_max_order + 1),
      'RUNNING'::public.phase_state_status_enum,
      clock_timestamp()
    )
    RETURNING * INTO v_state;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
    p_action         => 'WORKFLOW_PHASE_ENTERED',
    p_subject_type   => 'WORKFLOW_RUN'::audit.subject_type_enum,
    p_subject_id     => v_run.id,
    p_business_id    => v_run.business_id,
    p_organization_id=> v_run.organization_id,
    p_actor_system   => 'workflow_engine',
    p_reason         => format('phase %s entered (RUNNING)', p_phase_name),
    p_after_state    => jsonb_build_object(
      'run_id', v_run.id, 'phase_state_id', v_state.id,
      'phase_name', p_phase_name, 'phase_order', v_state.phase_order
    )
  );

  RETURN v_state;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.run_retention_pass(p_now timestamp with time zone DEFAULT now(), p_dry_run boolean DEFAULT false, p_business_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT 'retention-engine'::text)
 RETURNS TABLE(planned integer, executed integer, skipped integer, failed integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_biz             record;
  v_root            record;
  v_chain_member    record;
  v_planned         integer := 0;
  v_executed        integer := 0;
  v_skipped         integer := 0;
  v_failed          integer := 0;
  v_threshold       timestamptz;
  v_hold            jsonb;
  v_lock_key        bigint := hashtext('archive.run_retention_pass')::bigint;
  v_max_completed   timestamptz;
BEGIN
  IF NOT pg_try_advisory_lock(v_lock_key) THEN
    RETURN QUERY SELECT 0, 0, 0, 0; RETURN;
  END IF;

  BEGIN
    FOR v_biz IN
      SELECT rp.business_id, rp.organization_id, rp.retention_years
        FROM archive.retention_policies rp
       WHERE p_business_id IS NULL OR rp.business_id = p_business_id
    LOOP
      v_threshold := p_now - make_interval(years => v_biz.retention_years);

      INSERT INTO archive.archive_events (organization_id, business_id, event_type, actor_system, payload)
      VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_PASS_STARTED', p_actor_system,
              jsonb_build_object('threshold', v_threshold, 'retention_years', v_biz.retention_years, 'dry_run', p_dry_run));

      v_hold := archive.legal_hold_status(v_biz.business_id);

      -- Only iterate ROOT runs (adjustment_of_archive_run_id IS NULL) past
      -- threshold. The chain (root + adjustments) is processed together so
      -- the bundle family stays consistent.
      FOR v_root IN
        SELECT id, period_start, period_end, completed_at, status, bundle_storage_path
          FROM archive.archive_runs
         WHERE business_id = v_biz.business_id
           AND status = 'COMPLETE'
           AND adjustment_of_archive_run_id IS NULL
           AND completed_at IS NOT NULL
           AND completed_at < v_threshold
         ORDER BY completed_at ASC
      LOOP
        IF COALESCE((v_hold->>'on_hold')::boolean, false) THEN
          INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
          VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_DELETION_SKIPPED_LEGAL_HOLD',
                  v_root.id, p_actor_system,
                  jsonb_build_object('period_start', v_root.period_start, 'period_end', v_root.period_end,
                                     'hold_reasons', COALESCE(v_hold->'hold_reasons','[]'::jsonb)));
          v_skipped := v_skipped + 1; CONTINUE;
        END IF;

        -- Skip the chain if the newest member of its adjustment chain is
        -- still within retention. completed_at of the newest member is the
        -- effective "last touched" timestamp for the bundle family.
        SELECT max(ar.completed_at) INTO v_max_completed
          FROM archive.archive_runs ar
          JOIN archive.archive_run_chain(v_root.id) c ON c.id = ar.id;

        IF v_max_completed >= v_threshold THEN
          INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
          VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_DELETION_SKIPPED_NEWER_ADJUSTMENT',
                  v_root.id, p_actor_system,
                  jsonb_build_object('period_start', v_root.period_start, 'period_end', v_root.period_end,
                                     'root_completed_at', v_root.completed_at,
                                     'chain_max_completed_at', v_max_completed,
                                     'threshold', v_threshold));
          v_skipped := v_skipped + 1; CONTINUE;
        END IF;

        IF p_dry_run THEN
          -- Plan one PLANNED event per chain member (informative).
          FOR v_chain_member IN
            SELECT ar.id, ar.period_start, ar.period_end, ar.bundle_storage_path, ar.completed_at
              FROM archive.archive_runs ar
              JOIN archive.archive_run_chain(v_root.id) c ON c.id = ar.id
             ORDER BY c.depth DESC  -- leaves first (informational)
          LOOP
            INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
            VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_DELETION_PLANNED',
                    v_chain_member.id, p_actor_system,
                    jsonb_build_object('period_start', v_chain_member.period_start, 'period_end', v_chain_member.period_end,
                                       'storage_path', v_chain_member.bundle_storage_path,
                                       'threshold', v_threshold,
                                       'root_id', v_root.id));
            v_planned := v_planned + 1;
          END LOOP;
          CONTINUE;
        END IF;

        -- Delete the whole chain leaves-first to respect the
        -- adjustment_of_archive_run_id RESTRICT FK.
        FOR v_chain_member IN
          SELECT ar.id, ar.period_start, ar.period_end, ar.bundle_storage_path, ar.completed_at
            FROM archive.archive_runs ar
            JOIN archive.archive_run_chain(v_root.id) c ON c.id = ar.id
           ORDER BY c.depth DESC
        LOOP
          BEGIN
            INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
            VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_DELETION_EXECUTED',
                    v_chain_member.id, p_actor_system,
                    jsonb_build_object('period_start', v_chain_member.period_start, 'period_end', v_chain_member.period_end,
                                       'storage_path', v_chain_member.bundle_storage_path,
                                       'storage_cleanup_pending', (v_chain_member.bundle_storage_path IS NOT NULL),
                                       'root_id', v_root.id));
            PERFORM archive.retention_delete_archive_run(v_chain_member.id, 'retention_window_elapsed');
            v_executed := v_executed + 1;
          EXCEPTION WHEN OTHERS THEN
            INSERT INTO archive.archive_events (organization_id, business_id, event_type, archive_run_id, actor_system, payload)
            VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_DELETION_INCONSISTENT',
                    v_chain_member.id, p_actor_system,
                    jsonb_build_object('period_start', v_chain_member.period_start, 'period_end', v_chain_member.period_end,
                                       'storage_path', v_chain_member.bundle_storage_path,
                                       'error', SQLERRM, 'root_id', v_root.id));
            v_failed := v_failed + 1;
          END;
        END LOOP;
      END LOOP;

      INSERT INTO archive.archive_events (organization_id, business_id, event_type, actor_system, payload)
      VALUES (v_biz.organization_id, v_biz.business_id, 'RETENTION_PASS_COMPLETED', p_actor_system,
              jsonb_build_object('planned', v_planned, 'executed', v_executed, 'skipped', v_skipped, 'failed', v_failed, 'dry_run', p_dry_run));
    END LOOP;
  EXCEPTION WHEN OTHERS THEN
    PERFORM pg_advisory_unlock(v_lock_key);
    RAISE;
  END;

  PERFORM pg_advisory_unlock(v_lock_key);
  RETURN QUERY SELECT v_planned, v_executed, v_skipped, v_failed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._resolve_phase_state_context(p_phase_state_id uuid)
 RETURNS TABLE(run_id uuid, business_id uuid, organization_id uuid)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT wr.id, wr.business_id, wr.organization_id
    FROM public.workflow_phase_states wps
    JOIN public.workflow_runs wr ON wr.id = wps.workflow_run_id
   WHERE wps.id = p_phase_state_id;
$function$
;

CREATE OR REPLACE FUNCTION archive.set_legal_hold(p_business_id uuid, p_hold_reason text, p_step_up_token uuid)
 RETURNS archive.legal_holds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_user     uuid := public.current_user_id();
  v_org      uuid;
  v_role     public.user_role;
  v_row      archive.legal_holds;
  v_consumed boolean;
  v_reason   text;
BEGIN
  IF v_user IS NULL THEN RAISE EXCEPTION 'unauthenticated' USING ERRCODE='28000'; END IF;
  IF p_hold_reason IS NULL OR length(btrim(p_hold_reason)) = 0 THEN
    RAISE EXCEPTION 'hold_reason must be non-empty' USING ERRCODE='22000';
  END IF;
  SELECT bur.role INTO v_role FROM public.business_user_roles bur
    WHERE bur.user_id = v_user AND bur.business_id = p_business_id AND bur.status='ACTIVE';
  IF v_role IS NULL OR v_role <> 'OWNER' THEN
    RAISE EXCEPTION 'role does not grant legal hold management (got %); OWNER only', v_role USING ERRCODE='42501';
  END IF;

  SELECT consumed, reason INTO v_consumed, v_reason
    FROM public.consume_step_up_token(p_step_up_token, p_business_id, 'legal_hold_set', NULL);
  IF NOT v_consumed THEN
    RAISE EXCEPTION 'LEGAL_HOLD_SET_STEP_UP_REJECTED:%', v_reason USING ERRCODE='42501';
  END IF;

  SELECT organization_id INTO v_org FROM public.business_entities WHERE id = p_business_id;

  INSERT INTO archive.legal_holds (organization_id, business_id, status, hold_reason, set_by, set_at)
  VALUES (v_org, p_business_id, 'ACTIVE', btrim(p_hold_reason), v_user, now())
  RETURNING * INTO v_row;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, actor_user_id, payload)
  VALUES (v_org, p_business_id, 'LEGAL_HOLD_SET', v_user,
          jsonb_build_object('legal_hold_id', v_row.id, 'hold_reason', v_row.hold_reason, 'set_at', v_row.set_at));
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.update_retention_policy(p_business_id uuid, p_retention_years integer, p_step_up_token uuid)
 RETURNS archive.retention_policies
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_user     uuid := public.current_user_id();
  v_org      uuid;
  v_role     public.user_role;
  v_row      archive.retention_policies;
  v_old      integer;
  v_consumed boolean;
  v_reason   text;
BEGIN
  IF v_user IS NULL THEN RAISE EXCEPTION 'unauthenticated' USING ERRCODE='28000'; END IF;
  IF p_retention_years < 6 THEN
    RAISE EXCEPTION 'retention_years % below legal minimum (6)', p_retention_years USING ERRCODE='22000';
  END IF;
  SELECT bur.role INTO v_role FROM public.business_user_roles bur
    WHERE bur.user_id = v_user AND bur.business_id = p_business_id AND bur.status='ACTIVE';
  IF v_role IS NULL OR v_role NOT IN ('OWNER','ADMIN') THEN
    RAISE EXCEPTION 'role does not grant retention policy update (got %)', v_role USING ERRCODE='42501';
  END IF;

  -- Step-up consumption: enforce the token's (consumed, reason) result.
  SELECT consumed, reason INTO v_consumed, v_reason
    FROM public.consume_step_up_token(p_step_up_token, p_business_id, 'retention_policy_update', NULL);
  IF NOT v_consumed THEN
    RAISE EXCEPTION 'RETENTION_POLICY_STEP_UP_REJECTED:%', v_reason USING ERRCODE='42501';
  END IF;

  SELECT organization_id INTO v_org FROM public.business_entities WHERE id = p_business_id;
  SELECT retention_years INTO v_old FROM archive.retention_policies WHERE business_id = p_business_id;
  INSERT INTO archive.retention_policies (business_id, organization_id, retention_years, updated_at, updated_by)
  VALUES (p_business_id, v_org, p_retention_years, now(), v_user)
  ON CONFLICT (business_id) DO UPDATE
    SET retention_years = EXCLUDED.retention_years,
        updated_at      = now(),
        updated_by      = EXCLUDED.updated_by
  RETURNING * INTO v_row;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, actor_user_id, payload)
  VALUES (v_org, p_business_id, 'RETENTION_POLICY_UPDATED', v_user,
          jsonb_build_object('old_retention_years', v_old, 'new_retention_years', p_retention_years));
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.lift_legal_hold(p_legal_hold_id uuid, p_lift_reason text, p_step_up_token uuid)
 RETURNS archive.legal_holds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
DECLARE
  v_user     uuid := public.current_user_id();
  v_role     public.user_role;
  v_row      archive.legal_holds;
  v_consumed boolean;
  v_reason   text;
BEGIN
  IF v_user IS NULL THEN RAISE EXCEPTION 'unauthenticated' USING ERRCODE='28000'; END IF;
  IF p_lift_reason IS NULL OR length(btrim(p_lift_reason)) = 0 THEN
    RAISE EXCEPTION 'lift_reason must be non-empty' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_row FROM archive.legal_holds WHERE id = p_legal_hold_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'legal hold % not found', p_legal_hold_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'ACTIVE' THEN
    RAISE EXCEPTION 'legal hold % is not ACTIVE (got %)', p_legal_hold_id, v_row.status USING ERRCODE='22023';
  END IF;
  SELECT bur.role INTO v_role FROM public.business_user_roles bur
    WHERE bur.user_id = v_user AND bur.business_id = v_row.business_id AND bur.status='ACTIVE';
  IF v_role IS NULL OR v_role <> 'OWNER' THEN
    RAISE EXCEPTION 'role does not grant legal hold management (got %); OWNER only', v_role USING ERRCODE='42501';
  END IF;

  SELECT consumed, reason INTO v_consumed, v_reason
    FROM public.consume_step_up_token(p_step_up_token, v_row.business_id, 'legal_hold_lift', NULL);
  IF NOT v_consumed THEN
    RAISE EXCEPTION 'LEGAL_HOLD_LIFT_STEP_UP_REJECTED:%', v_reason USING ERRCODE='42501';
  END IF;

  UPDATE archive.legal_holds
     SET status='LIFTED', lift_reason=btrim(p_lift_reason), lifted_by=v_user, lifted_at=now()
   WHERE id = p_legal_hold_id
  RETURNING * INTO v_row;

  INSERT INTO archive.archive_events (organization_id, business_id, event_type, actor_user_id, payload)
  VALUES (v_row.organization_id, v_row.business_id, 'LEGAL_HOLD_LIFTED', v_user,
          jsonb_build_object('legal_hold_id', v_row.id, 'hold_reason', v_row.hold_reason,
                             'lift_reason', v_row.lift_reason, 'set_at', v_row.set_at, 'lifted_at', v_row.lifted_at));
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION archive.archive_run_chain(p_root_id uuid)
 RETURNS TABLE(id uuid, depth integer)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'archive', 'public', 'pg_temp'
AS $function$
  WITH RECURSIVE chain AS (
    SELECT ar.id, 0 AS depth FROM archive.archive_runs ar WHERE ar.id = p_root_id
    UNION ALL
    SELECT ar.id, c.depth + 1
      FROM archive.archive_runs ar
      JOIN chain c ON ar.adjustment_of_archive_run_id = c.id
  )
  SELECT id, depth FROM chain ORDER BY depth ASC
$function$
;

CREATE OR REPLACE FUNCTION public.prune_expired_processing_artifacts(p_now timestamp with time zone DEFAULT now(), p_limit integer DEFAULT 1000)
 RETURNS TABLE(pruned integer, skipped integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'archive', 'pg_temp'
AS $function$
DECLARE
  v_artifact record;
  v_run      public.workflow_runs;
  v_pruned   integer := 0;
  v_skipped  integer := 0;
  v_skip     public.processing_prune_skip_reason_enum;
  v_hold     jsonb;
BEGIN
  FOR v_artifact IN
    SELECT * FROM public.processing_artifacts
     WHERE expires_at IS NOT NULL AND expires_at <= p_now
     ORDER BY expires_at
     LIMIT p_limit
     FOR UPDATE SKIP LOCKED
  LOOP
    SELECT * INTO v_run FROM public.workflow_runs WHERE id = v_artifact.workflow_run_id;
    v_skip := NULL;

    -- Per-run flag (B04·P06 forward declaration).
    IF v_run.legal_hold_active THEN
      v_skip := 'LEGAL_HOLD';
    END IF;

    -- Per-business hold (B04·P11). Either signal blocks deletion.
    IF v_skip IS NULL THEN
      v_hold := archive.legal_hold_status(v_artifact.business_id);
      IF COALESCE((v_hold->>'on_hold')::boolean, false) THEN
        v_skip := 'LEGAL_HOLD';
      END IF;
    END IF;

    IF v_skip IS NULL AND v_run.status NOT IN ('FINALIZED','FAILED','CANCELLED') THEN
      v_skip := 'RUN_NOT_TERMINAL';
    END IF;

    IF v_skip IS NOT NULL THEN
      INSERT INTO public.processing_artifact_events (
        organization_id, business_id, event_type, processing_artifact_id,
        workflow_run_id, actor_system, skip_reason, payload
      ) VALUES (
        v_artifact.organization_id, v_artifact.business_id,
        'PROCESSING_ARTIFACT_PRUNE_SKIPPED', v_artifact.id,
        v_artifact.workflow_run_id, 'prune-job', v_skip,
        jsonb_build_object(
          'artifact_type',     v_artifact.artifact_type::text,
          'run_status',        v_run.status::text,
          'expires_at',        v_artifact.expires_at,
          'business_on_hold',  COALESCE(v_hold->>'on_hold','false')::boolean,
          'hold_reasons',      COALESCE(v_hold->'hold_reasons','[]'::jsonb)
        )
      );
      v_skipped := v_skipped + 1;
      CONTINUE;
    END IF;

    INSERT INTO public.processing_artifact_events (
      organization_id, business_id, event_type, processing_artifact_id,
      workflow_run_id, actor_system, payload
    ) VALUES (
      v_artifact.organization_id, v_artifact.business_id,
      'PROCESSING_ARTIFACT_PRUNED', v_artifact.id,
      v_artifact.workflow_run_id, 'prune-job',
      jsonb_build_object(
        'artifact_type',          v_artifact.artifact_type::text,
        'storage_bucket',         v_artifact.payload_storage_bucket,
        'storage_path',           v_artifact.payload_storage_path,
        'expired_at',             v_artifact.expires_at,
        'storage_cleanup_pending',(v_artifact.payload_storage_path IS NOT NULL)
      )
    );
    DELETE FROM public.processing_artifacts WHERE id = v_artifact.id;
    v_pruned := v_pruned + 1;
  END LOOP;
  RETURN QUERY SELECT v_pruned, v_skipped;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_shared_phase_can_dedup(p_run_id uuid, p_phase_name text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_run          public.workflow_runs;
  v_is_shared    boolean;
  v_sibling      public.workflow_runs;
  v_sibling_ps   public.workflow_phase_states;
  v_invocations  jsonb := '[]'::jsonb;
BEGIN
  SELECT * INTO v_run FROM public.workflow_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('is_shared', false, 'sibling_run_id', NULL, 'sibling_phase_state_id', NULL,
                              'sibling_phase_completed', false, 'sibling_tool_invocations', '[]'::jsonb);
  END IF;

  SELECT COALESCE(wpd.is_shared_with_pair, false) INTO v_is_shared
    FROM public.workflow_phase_definitions wpd
   WHERE wpd.workflow_type = v_run.workflow_type
     AND wpd.phase_name = p_phase_name;

  IF NOT COALESCE(v_is_shared, false) THEN
    RETURN jsonb_build_object('is_shared', false, 'sibling_run_id', NULL, 'sibling_phase_state_id', NULL,
                              'sibling_phase_completed', false, 'sibling_tool_invocations', '[]'::jsonb);
  END IF;

  IF v_run.trigger_event_id IS NULL THEN
    RETURN jsonb_build_object('is_shared', true, 'sibling_run_id', NULL, 'sibling_phase_state_id', NULL,
                              'sibling_phase_completed', false, 'sibling_tool_invocations', '[]'::jsonb);
  END IF;

  SELECT * INTO v_sibling FROM public.workflow_runs
   WHERE trigger_event_id = v_run.trigger_event_id AND id <> v_run.id
   LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('is_shared', true, 'sibling_run_id', NULL, 'sibling_phase_state_id', NULL,
                              'sibling_phase_completed', false, 'sibling_tool_invocations', '[]'::jsonb);
  END IF;

  SELECT * INTO v_sibling_ps FROM public.workflow_phase_states
   WHERE workflow_run_id = v_sibling.id AND phase_name = p_phase_name
   ORDER BY phase_order DESC LIMIT 1;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('is_shared', true, 'sibling_run_id', v_sibling.id, 'sibling_phase_state_id', NULL,
                              'sibling_phase_completed', false, 'sibling_tool_invocations', '[]'::jsonb);
  END IF;

  IF v_sibling_ps.status = 'COMPLETED' THEN
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'id', ti.id, 'tool_name', ti.tool_name, 'dedup_key', ti.dedup_key,
      'output_hash', ti.output_hash, 'status', ti.status::text, 'attempt_number', ti.attempt_number
    )), '[]'::jsonb)
    INTO v_invocations
      FROM public.tool_invocations ti
     WHERE ti.phase_state_id = v_sibling_ps.id AND ti.status = 'SUCCESS';
  END IF;

  RETURN jsonb_build_object(
    'is_shared',                  true,
    'sibling_run_id',             v_sibling.id,
    'sibling_phase_state_id',     v_sibling_ps.id,
    'sibling_phase_completed',    v_sibling_ps.status = 'COMPLETED',
    'sibling_tool_invocations',   v_invocations
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.at_rest_encryption_status()
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'storage', 'pg_temp'
AS $function$
  WITH expected_buckets AS (
    SELECT unnest(ARRAY['raw-uploads','processing-zone','archive-bundles']) AS id
  ),
  bucket_state AS (
    SELECT
      eb.id,
      b.id IS NOT NULL                AS exists,
      COALESCE(NOT b.public, false)   AS is_private,
      b.file_size_limit               AS size_limit,
      cardinality(b.allowed_mime_types) AS allowed_mime_count
    FROM expected_buckets eb
    LEFT JOIN storage.buckets b ON b.id = eb.id
  )
  SELECT jsonb_build_object(
    'all_ok', (
      SELECT bool_and(exists AND is_private)
        FROM bucket_state
    ),
    'buckets', (
      SELECT jsonb_agg(jsonb_build_object(
        'id',           id,
        'exists',       exists,
        'is_private',   is_private,
        'size_limit',   size_limit,
        'allowed_mime_count', allowed_mime_count
      ))
      FROM bucket_state
    ),
    'note',
      'Postgres at-rest encryption is enforced by Supabase platform default (AES-256). '
      'Bucket-level encryption is also Supabase platform default. TLS 1.3 + HSTS + '
      'certificate pinning are enforced by the application HTTP clients '
      '(api/secure_http and web/src/lib/secure-http).'
  )
$function$
;

