CREATE OR REPLACE FUNCTION audit.emit_audit(p_actor_kind audit.actor_kind_enum, p_action text, p_subject_type audit.subject_type_enum, p_subject_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid, p_actor_role user_role DEFAULT NULL::user_role, p_actor_session_id uuid DEFAULT NULL::uuid, p_actor_system text DEFAULT NULL::text, p_organization_id uuid DEFAULT NULL::uuid, p_business_id uuid DEFAULT NULL::uuid, p_before_state jsonb DEFAULT NULL::jsonb, p_after_state jsonb DEFAULT NULL::jsonb, p_reason text DEFAULT NULL::text, p_request_context jsonb DEFAULT '{}'::jsonb)
 RETURNS audit.audit_events
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_event_id      bigint;
  v_occurred_at   timestamptz := clock_timestamp();
  v_actor_system  text        := NULLIF(btrim(COALESCE(p_actor_system, '')), '');
  v_action        text        := btrim(p_action);
  v_req_ctx       jsonb       := COALESCE(p_request_context, '{}'::jsonb);
  v_chain_id      uuid;
  v_prev_hash     text;
  v_canonical     text;
  v_event_hash    text;
  v_row           audit.audit_events;
  SYSTEM_CHAIN_ID constant uuid := '00000000-0000-0000-0000-000000000000';
  GENESIS_HASH    constant text := repeat('0', 64);
BEGIN
  IF p_action IS NULL OR length(btrim(p_action)) = 0 THEN
    RAISE EXCEPTION 'emit_audit: action is required' USING ERRCODE = '22000';
  END IF;
  IF p_actor_kind = 'USER' AND p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'emit_audit: USER actor requires actor_user_id' USING ERRCODE = '22000';
  END IF;
  IF p_actor_kind = 'SYSTEM' AND (p_actor_system IS NULL OR length(btrim(p_actor_system)) = 0) THEN
    RAISE EXCEPTION 'emit_audit: SYSTEM actor requires actor_system principal name' USING ERRCODE = '22000';
  END IF;

  v_event_id := nextval('audit.audit_event_id_seq');
  v_chain_id := COALESCE(p_organization_id, SYSTEM_CHAIN_ID);

  INSERT INTO audit.chain_heads (
    chain_id, latest_event_id, latest_event_hash, latest_event_at, chain_started_at, updated_at
  ) VALUES (
    v_chain_id, 0, GENESIS_HASH, v_occurred_at, v_occurred_at, v_occurred_at
  )
  ON CONFLICT (chain_id) DO NOTHING;

  SELECT latest_event_hash INTO v_prev_hash
    FROM audit.chain_heads
   WHERE chain_id = v_chain_id
   FOR UPDATE;

  v_canonical := audit.canonical_event_payload(
    p_event_id        => v_event_id,
    p_occurred_at     => v_occurred_at,
    p_actor_kind      => p_actor_kind,
    p_actor_user_id   => p_actor_user_id,
    p_actor_role      => p_actor_role,
    p_actor_session_id=> p_actor_session_id,
    p_actor_system    => v_actor_system,
    p_organization_id => p_organization_id,
    p_business_id     => p_business_id,
    p_subject_type    => p_subject_type,
    p_subject_id      => p_subject_id,
    p_action          => v_action,
    p_before_state    => p_before_state,
    p_after_state     => p_after_state,
    p_reason          => p_reason,
    p_request_context => v_req_ctx
  );

  v_event_hash := public.hash_chain_append(v_prev_hash, v_canonical);

  INSERT INTO audit.audit_events (
    event_id, occurred_at,
    actor_kind, actor_user_id, actor_role, actor_session_id, actor_system,
    organization_id, business_id,
    subject_type, subject_id,
    action, before_state, after_state, reason, request_context,
    prev_event_hash, event_hash
  ) VALUES (
    v_event_id, v_occurred_at,
    p_actor_kind, p_actor_user_id, p_actor_role, p_actor_session_id,
    v_actor_system,
    p_organization_id, p_business_id,
    p_subject_type, p_subject_id,
    v_action, p_before_state, p_after_state, p_reason, v_req_ctx,
    v_prev_hash, v_event_hash
  )
  RETURNING * INTO v_row;

  UPDATE audit.chain_heads SET
    latest_event_id   = v_event_id,
    latest_event_hash = v_event_hash,
    latest_event_at   = v_occurred_at,
    updated_at        = clock_timestamp()
  WHERE chain_id = v_chain_id;

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION audit.canonical_jsonb(p jsonb)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'pg_temp'
AS $function$
DECLARE
  v_typeof  text;
  v_parts   text[] := ARRAY[]::text[];
  v_elem    jsonb;
  v_key     text;
  v_keys    text[];
BEGIN
  IF p IS NULL THEN
    RETURN 'null';
  END IF;
  v_typeof := jsonb_typeof(p);
  IF v_typeof = 'null'    THEN RETURN 'null'; END IF;
  IF v_typeof = 'boolean' THEN RETURN p::text; END IF;
  IF v_typeof = 'number'  THEN RETURN p::text; END IF;
  IF v_typeof = 'string'  THEN RETURN p::text; END IF;
  IF v_typeof = 'array' THEN
    FOR v_elem IN SELECT * FROM jsonb_array_elements(p) LOOP
      v_parts := v_parts || audit.canonical_jsonb(v_elem);
    END LOOP;
    RETURN '[' || array_to_string(v_parts, ',') || ']';
  END IF;
  IF v_typeof = 'object' THEN
    SELECT array_agg(k ORDER BY k) INTO v_keys
      FROM jsonb_object_keys(p) AS k;
    IF v_keys IS NULL THEN RETURN '{}'; END IF;
    FOREACH v_key IN ARRAY v_keys LOOP
      v_parts := v_parts || (to_jsonb(v_key)::text || ':' || audit.canonical_jsonb(p -> v_key));
    END LOOP;
    RETURN '{' || array_to_string(v_parts, ',') || '}';
  END IF;
  RAISE EXCEPTION 'canonical_jsonb: unsupported jsonb type %', v_typeof;
END;
$function$
;

CREATE OR REPLACE FUNCTION audit.canonical_event_payload(p_event_id bigint, p_occurred_at timestamp with time zone, p_actor_kind audit.actor_kind_enum, p_actor_user_id uuid, p_actor_role user_role, p_actor_session_id uuid, p_actor_system text, p_organization_id uuid, p_business_id uuid, p_subject_type audit.subject_type_enum, p_subject_id uuid, p_action text, p_before_state jsonb, p_after_state jsonb, p_reason text, p_request_context jsonb)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_iso         text;
  v_actor       text;
  v_subject     text;
BEGIN
  v_iso := to_char(p_occurred_at AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.US"Z"');

  v_actor := '{' ||
    '"kind":'       || to_jsonb(p_actor_kind::text)::text || ',' ||
    '"role":'       || COALESCE(to_jsonb(p_actor_role::text)::text, 'null') || ',' ||
    '"session_id":' || COALESCE(to_jsonb(p_actor_session_id::text)::text, 'null') || ',' ||
    '"system":'     || COALESCE(to_jsonb(p_actor_system)::text, 'null') || ',' ||
    '"user_id":'    || COALESCE(to_jsonb(p_actor_user_id::text)::text, 'null') ||
    '}';

  v_subject := '{' ||
    '"id":'   || COALESCE(to_jsonb(p_subject_id::text)::text, 'null') || ',' ||
    '"type":' || to_jsonb(p_subject_type::text)::text ||
    '}';

  RETURN '{' ||
    '"action":'          || to_jsonb(p_action)::text || ',' ||
    '"actor":'           || v_actor || ',' ||
    '"after_state":'     || audit.canonical_jsonb(p_after_state) || ',' ||
    '"before_state":'    || audit.canonical_jsonb(p_before_state) || ',' ||
    '"business_id":'     || COALESCE(to_jsonb(p_business_id::text)::text, 'null') || ',' ||
    '"event_id":'        || p_event_id::text || ',' ||
    '"occurred_at":'     || to_jsonb(v_iso)::text || ',' ||
    '"organization_id":' || COALESCE(to_jsonb(p_organization_id::text)::text, 'null') || ',' ||
    '"reason":'          || COALESCE(to_jsonb(p_reason)::text, 'null') || ',' ||
    '"request_context":' || audit.canonical_jsonb(p_request_context) || ',' ||
    '"subject":'         || v_subject ||
    '}';
END;
$function$
;

CREATE OR REPLACE FUNCTION audit.checkpoint_chain(p_chain_id uuid)
 RETURNS audit.chain_checkpoints
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_head        audit.chain_heads;
  v_token       bytea;
  v_provider    text := 'PLACEHOLDER_LOCAL';
  v_status      text := 'PLACEHOLDER_OK';
  v_checkpoint  audit.chain_checkpoints;
  SYSTEM_CHAIN_ID constant uuid := '00000000-0000-0000-0000-000000000000';
BEGIN
  SELECT * INTO v_head FROM audit.chain_heads WHERE chain_id = p_chain_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'checkpoint_chain: chain % does not exist', p_chain_id USING ERRCODE = 'P0002';
  END IF;

  v_token := convert_to(
    format(
      '{"placeholder":true,"chain_id":"%s","event_hash":"%s","event_id":%s,"stamped_at":"%s"}',
      p_chain_id, v_head.latest_event_hash, v_head.latest_event_id, clock_timestamp()::text
    ),
    'UTF8'
  );

  INSERT INTO audit.chain_checkpoints (
    chain_id, event_id, event_hash, timestamp_token, tsa_provider, tsa_response_status
  ) VALUES (
    p_chain_id, v_head.latest_event_id, v_head.latest_event_hash,
    v_token, v_provider, v_status
  )
  RETURNING * INTO v_checkpoint;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'CHAIN_CHECKPOINTED',
    p_subject_type => 'CHAIN_CHECKPOINT'::audit.subject_type_enum,
    p_subject_id   => v_checkpoint.id,
    p_actor_system => 'audit.checkpoint_chain',
    p_organization_id => CASE WHEN p_chain_id = SYSTEM_CHAIN_ID THEN NULL ELSE p_chain_id END,
    p_reason       => format('Checkpoint anchored via %s at event_id=%s', v_provider, v_head.latest_event_id),
    p_after_state  => jsonb_build_object(
      'checkpoint_id', v_checkpoint.id,
      'chain_id',      p_chain_id,
      'event_id',      v_head.latest_event_id,
      'event_hash',    v_head.latest_event_hash,
      'tsa_provider',  v_provider
    )
  );

  RETURN v_checkpoint;
END;
$function$
;

CREATE OR REPLACE FUNCTION audit._verify_chain_walk(p_chain_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_rec               record;
  v_prev_hash         text := repeat('0', 64);
  v_canonical         text;
  v_recomputed        text;
  v_break_event_id    bigint := NULL;
  v_break_reason      text   := NULL;
  v_count             integer := 0;
  v_mismatched        jsonb := '[]'::jsonb;
  v_checkpoint        record;
  SYSTEM_CHAIN_ID constant uuid := '00000000-0000-0000-0000-000000000000';
BEGIN
  FOR v_rec IN
    SELECT * FROM audit.audit_events
     WHERE COALESCE(organization_id, SYSTEM_CHAIN_ID) = p_chain_id
     ORDER BY event_id ASC
  LOOP
    v_count := v_count + 1;
    v_canonical := audit.canonical_event_payload(
      p_event_id        => v_rec.event_id,
      p_occurred_at     => v_rec.occurred_at,
      p_actor_kind      => v_rec.actor_kind,
      p_actor_user_id   => v_rec.actor_user_id,
      p_actor_role      => v_rec.actor_role,
      p_actor_session_id=> v_rec.actor_session_id,
      p_actor_system    => v_rec.actor_system,
      p_organization_id => v_rec.organization_id,
      p_business_id     => v_rec.business_id,
      p_subject_type    => v_rec.subject_type,
      p_subject_id      => v_rec.subject_id,
      p_action          => v_rec.action,
      p_before_state    => v_rec.before_state,
      p_after_state     => v_rec.after_state,
      p_reason          => v_rec.reason,
      p_request_context => v_rec.request_context
    );
    v_recomputed := public.hash_chain_append(v_prev_hash, v_canonical);

    IF v_rec.prev_event_hash IS DISTINCT FROM v_prev_hash THEN
      v_break_event_id := v_rec.event_id;
      v_break_reason   := 'prev_event_hash_mismatch';
      EXIT;
    END IF;
    IF v_recomputed IS DISTINCT FROM v_rec.event_hash THEN
      v_break_event_id := v_rec.event_id;
      v_break_reason   := 'event_hash_mismatch';
      EXIT;
    END IF;
    v_prev_hash := v_rec.event_hash;
  END LOOP;

  IF v_break_event_id IS NULL THEN
    FOR v_checkpoint IN
      SELECT cp.id          AS checkpoint_id,
             cp.event_id    AS checkpoint_event_id,
             cp.event_hash  AS stored_hash,
             ev.event_hash  AS actual_hash
        FROM audit.chain_checkpoints cp
        LEFT JOIN audit.audit_events ev ON ev.event_id = cp.event_id
       WHERE cp.chain_id = p_chain_id
       ORDER BY cp.event_id ASC
    LOOP
      IF v_checkpoint.stored_hash IS DISTINCT FROM v_checkpoint.actual_hash THEN
        v_mismatched := v_mismatched || jsonb_build_object(
          'checkpoint_id', v_checkpoint.checkpoint_id,
          'event_id',      v_checkpoint.checkpoint_event_id,
          'stored_hash',   v_checkpoint.stored_hash,
          'actual_hash',   v_checkpoint.actual_hash
        );
      END IF;
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'chain_id',               p_chain_id,
    'verified',               (v_break_event_id IS NULL AND jsonb_array_length(v_mismatched) = 0),
    'events_walked',          v_count,
    'break_at_event_id',      v_break_event_id,
    'break_reason',           v_break_reason,
    'mismatched_checkpoints', v_mismatched
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION audit.verify_chain(p_chain_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_result jsonb;
  v_org_id uuid;
  SYSTEM_CHAIN_ID constant uuid := '00000000-0000-0000-0000-000000000000';
BEGIN
  v_result := audit._verify_chain_walk(p_chain_id);
  v_org_id := CASE WHEN p_chain_id = SYSTEM_CHAIN_ID THEN NULL ELSE p_chain_id END;

  IF (v_result->>'verified')::boolean THEN
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'CHAIN_VERIFIED',
      p_subject_type    => 'CHAIN_HEAD'::audit.subject_type_enum,
      p_actor_system    => 'audit.verify_chain',
      p_organization_id => v_org_id,
      p_reason          => format('chain %s verified across %s events', p_chain_id, v_result->>'events_walked'),
      p_after_state     => v_result
    );
  ELSE
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'CHAIN_VERIFICATION_FAILED',
      p_subject_type    => 'CHAIN_HEAD'::audit.subject_type_enum,
      p_actor_system    => 'audit.verify_chain',
      p_organization_id => v_org_id,
      p_reason          => format('chain %s verification failed', p_chain_id),
      p_after_state     => v_result
    );
  END IF;

  RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION audit.verify_restored_chain(p_chain_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_result jsonb;
  v_org_id uuid;
  SYSTEM_CHAIN_ID constant uuid := '00000000-0000-0000-0000-000000000000';
BEGIN
  v_result := audit._verify_chain_walk(p_chain_id);
  v_org_id := CASE WHEN p_chain_id = SYSTEM_CHAIN_ID THEN NULL ELSE p_chain_id END;

  IF (v_result->>'verified')::boolean THEN
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'CHAIN_RESTORED_AND_VERIFIED',
      p_subject_type    => 'CHAIN_HEAD'::audit.subject_type_enum,
      p_actor_system    => 'audit.verify_restored_chain',
      p_organization_id => v_org_id,
      p_reason          => format('chain %s restored + verified across %s events', p_chain_id, v_result->>'events_walked'),
      p_after_state     => v_result
    );
  ELSE
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'CHAIN_VERIFICATION_FAILED',
      p_subject_type    => 'CHAIN_HEAD'::audit.subject_type_enum,
      p_actor_system    => 'audit.verify_restored_chain',
      p_organization_id => v_org_id,
      p_reason          => format('restored chain %s verification failed', p_chain_id),
      p_after_state     => v_result
    );
  END IF;

  RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION audit.current_chain_anchor(p_business_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_org_id     uuid;
  v_head       audit.chain_heads;
  v_checkpoint audit.chain_checkpoints;
BEGIN
  SELECT organization_id INTO v_org_id
    FROM public.business_entities WHERE id = p_business_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'current_chain_anchor: business % not found', p_business_id USING ERRCODE = 'P0002';
  END IF;

  SELECT * INTO v_head FROM audit.chain_heads WHERE chain_id = v_org_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'chain_id',        v_org_id,
      'event_hash',      repeat('0', 64),
      'event_id',        0,
      'event_at',        NULL,
      'checkpointed_at', NULL,
      'tsa_provider',    NULL
    );
  END IF;

  SELECT * INTO v_checkpoint FROM audit.chain_checkpoints
   WHERE chain_id = v_org_id AND event_id <= v_head.latest_event_id
   ORDER BY event_id DESC, created_at DESC LIMIT 1;

  RETURN jsonb_build_object(
    'chain_id',        v_org_id,
    'event_hash',      v_head.latest_event_hash,
    'event_id',        v_head.latest_event_id,
    'event_at',        v_head.latest_event_at,
    'checkpointed_at', v_checkpoint.created_at,
    'tsa_provider',    v_checkpoint.tsa_provider
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION keys._get_kek_material(p_kek_id uuid)
 RETURNS bytea
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'public', 'pg_temp'
AS $function$
DECLARE
  v_secret_id uuid;
  v_b64       text;
BEGIN
  SELECT vault_secret_id INTO v_secret_id
    FROM keys.organization_keks
   WHERE kek_id = p_kek_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION '_get_kek_material: kek_id % not found', p_kek_id USING ERRCODE = 'P0002';
  END IF;

  SELECT decrypted_secret INTO v_b64
    FROM vault.decrypted_secrets
   WHERE id = v_secret_id;
  IF v_b64 IS NULL THEN
    RAISE EXCEPTION '_get_kek_material: vault secret % not found / not readable', v_secret_id USING ERRCODE = 'P0002';
  END IF;

  RETURN decode(v_b64, 'base64');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_run_from_event(p_event_id text, p_event_kind text, p_business_id uuid, p_organization_id uuid, p_period_start timestamp with time zone, p_period_end timestamp with time zone, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_existing    public.trigger_events_processed;
  v_out_run_id  uuid;
  v_in_run_id   uuid;
  v_run_ids     uuid[];
  v_principal   jsonb;
  v_reject_code text;
  v_reject_msg  text;
  v_active_out  integer;
  v_active_in   integer;
BEGIN
  IF p_event_id IS NULL OR p_event_kind IS NULL OR p_business_id IS NULL OR p_organization_id IS NULL
     OR p_period_start IS NULL OR p_period_end IS NULL THEN
    RAISE EXCEPTION 'trigger_run_from_event: required params missing' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_existing FROM public.trigger_events_processed WHERE event_id = p_event_id;
  IF FOUND THEN
    RETURN jsonb_build_object('ok', true, 'idempotent_replay', true,
                              'created_run_ids', to_jsonb(v_existing.created_run_ids), 'event_id', p_event_id);
  END IF;

  IF p_event_kind <> 'STATEMENT_UPLOAD_COMPLETED' THEN
    v_reject_code := 'UNSUPPORTED_EVENT_KIND';
    v_reject_msg  := format('event_kind %s not supported by trigger engine (MVP supports STATEMENT_UPLOAD_COMPLETED only)', p_event_kind);
    PERFORM audit.emit_audit(
      p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
      p_action         => 'WORKFLOW_RUN_TRIGGER_REJECTED',
      p_subject_type   => 'TRIGGER_EVENT'::audit.subject_type_enum,
      p_business_id    => p_business_id,
      p_organization_id=> p_organization_id,
      p_actor_system   => 'event_pipeline',
      p_reason         => v_reject_msg,
      p_after_state    => jsonb_build_object(
        'rejection_code', v_reject_code, 'event_id', p_event_id, 'event_kind', p_event_kind,
        'business_id', p_business_id, 'payload', p_payload
      )
    );
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code, 'message', v_reject_msg);
  END IF;

  -- Advisory locks (both types — different keys, no deadlock risk)
  PERFORM public._acquire_trigger_lock(p_business_id, 'OUT_MONTHLY'::public.workflow_type_enum);
  PERFORM public._acquire_trigger_lock(p_business_id, 'IN_MONTHLY'::public.workflow_type_enum);

  -- Defensive duplicate check (event may fire with new event_id but same business+period)
  SELECT count(*) INTO v_active_out FROM public.workflow_runs
   WHERE business_id = p_business_id AND workflow_type = 'OUT_MONTHLY'
     AND status NOT IN ('FINALIZED','ABORTED','FAILED','CANCELLED');
  SELECT count(*) INTO v_active_in FROM public.workflow_runs
   WHERE business_id = p_business_id AND workflow_type = 'IN_MONTHLY'
     AND status NOT IN ('FINALIZED','ABORTED','FAILED','CANCELLED');

  IF v_active_out > 0 OR v_active_in > 0 THEN
    v_reject_code := 'DUPLICATE_ACTIVE';
    v_reject_msg  := format('active monthly run exists for business %s (OUT=%s, IN=%s)',
                            p_business_id, v_active_out, v_active_in);
    PERFORM audit.emit_audit(
      p_actor_kind     => 'SYSTEM'::audit.actor_kind_enum,
      p_action         => 'WORKFLOW_RUN_REJECTED_DUPLICATE',
      p_subject_type   => 'TRIGGER_EVENT'::audit.subject_type_enum,
      p_business_id    => p_business_id,
      p_organization_id=> p_organization_id,
      p_actor_system   => 'event_pipeline',
      p_reason         => v_reject_msg,
      p_after_state    => jsonb_build_object(
        'rejection_code', v_reject_code, 'event_id', p_event_id, 'event_kind', p_event_kind,
        'active_out', v_active_out, 'active_in', v_active_in
      )
    );
    RETURN jsonb_build_object('ok', false, 'reason', v_reject_code, 'message', v_reject_msg);
  END IF;

  v_principal := jsonb_build_object('kind','SYSTEM','system','event_pipeline',
                                    'event_id', p_event_id, 'event_kind', p_event_kind);

  INSERT INTO public.workflow_runs (organization_id, business_id, principal_snapshot, workflow_type,
                                    period_start, period_end, trigger_kind, trigger_event_id)
  VALUES (p_organization_id, p_business_id, v_principal, 'OUT_MONTHLY'::public.workflow_type_enum,
          p_period_start, p_period_end, 'EVENT'::public.trigger_kind_enum, p_event_id)
  RETURNING id INTO v_out_run_id;

  INSERT INTO public.workflow_runs (organization_id, business_id, principal_snapshot, workflow_type,
                                    period_start, period_end, trigger_kind, trigger_event_id)
  VALUES (p_organization_id, p_business_id, v_principal, 'IN_MONTHLY'::public.workflow_type_enum,
          p_period_start, p_period_end, 'EVENT'::public.trigger_kind_enum, p_event_id)
  RETURNING id INTO v_in_run_id;

  v_run_ids := ARRAY[v_out_run_id, v_in_run_id];

  INSERT INTO public.trigger_events_processed (event_id, event_kind, business_id, organization_id, period_start, period_end, created_run_ids, payload)
  VALUES (p_event_id, p_event_kind, p_business_id, p_organization_id, p_period_start, p_period_end, v_run_ids, p_payload);

  -- Per-run triggered audits
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'WORKFLOW_RUN_TRIGGERED_BY_EVENT',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_out_run_id,
    p_business_id => p_business_id, p_organization_id => p_organization_id, p_actor_system => 'event_pipeline',
    p_reason => format('event-triggered OUT_MONTHLY run from %s (%s)', p_event_kind, p_event_id),
    p_after_state => jsonb_build_object(
      'run_id', v_out_run_id, 'workflow_type', 'OUT_MONTHLY',
      'event_id', p_event_id, 'event_kind', p_event_kind, 'trigger_kind', 'EVENT'
    )
  );
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'WORKFLOW_RUN_TRIGGERED_BY_EVENT',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_in_run_id,
    p_business_id => p_business_id, p_organization_id => p_organization_id, p_actor_system => 'event_pipeline',
    p_reason => format('event-triggered IN_MONTHLY run from %s (%s)', p_event_kind, p_event_id),
    p_after_state => jsonb_build_object(
      'run_id', v_in_run_id, 'workflow_type', 'IN_MONTHLY',
      'event_id', p_event_id, 'event_kind', p_event_kind, 'trigger_kind', 'EVENT'
    )
  );

  -- P10: emit COORDINATED audit on the pair
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'WORKFLOW_SHARED_PHASE_COORDINATED',
    p_subject_type => 'WORKFLOW_RUN'::audit.subject_type_enum, p_subject_id => v_out_run_id,
    p_business_id => p_business_id, p_organization_id => p_organization_id, p_actor_system => 'event_pipeline',
    p_reason => format('coordinated pair created from event %s', p_event_id),
    p_after_state => jsonb_build_object(
      'run_id', v_out_run_id, 'sibling_run_id', v_in_run_id,
      'event_id', p_event_id, 'phase_name', NULL,
      'note', 'pair created; shared-phase coordination occurs at phase-entry time'
    )
  );

  RETURN jsonb_build_object('ok', true, 'idempotent_replay', false,
                            'created_run_ids', to_jsonb(v_run_ids), 'event_id', p_event_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.create_org_kek(p_organization_id uuid)
 RETURNS keys.organization_keks
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_kek_bytes bytea;
  v_kek_b64   text;
  v_secret_id uuid;
  v_row       keys.organization_keks;
BEGIN
  IF p_organization_id IS NULL THEN
    RAISE EXCEPTION 'create_org_kek: organization_id is required' USING ERRCODE = '22000';
  END IF;
  IF EXISTS (SELECT 1 FROM keys.organization_keks WHERE organization_id = p_organization_id AND status = 'ACTIVE') THEN
    RAISE EXCEPTION 'create_org_kek: org % already has an ACTIVE KEK', p_organization_id USING ERRCODE = '23505';
  END IF;

  v_kek_bytes := extensions.gen_random_bytes(32);
  v_kek_b64   := encode(v_kek_bytes, 'base64');
  v_secret_id := vault.create_secret(
    new_secret      => v_kek_b64,
    new_name        => 'kek-' || p_organization_id::text,
    new_description => 'B05P04 KEK for organization ' || p_organization_id::text
  );

  INSERT INTO keys.organization_keks (organization_id, vault_secret_id, status, generation)
  VALUES (p_organization_id, v_secret_id, 'ACTIVE', 1)
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'KEK_CREATED',
    p_subject_type    => 'KEK'::audit.subject_type_enum,
    p_subject_id      => v_row.kek_id,
    p_actor_system    => 'keys.create_org_kek',
    p_organization_id => p_organization_id,
    p_reason          => 'KEK auto-generated on organization creation',
    p_after_state     => jsonb_build_object(
      'kek_id', v_row.kek_id,
      'organization_id', p_organization_id,
      'vault_secret_id', v_secret_id,
      'generation', 1
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.encrypt_field(p_business_id uuid, p_plaintext text)
 RETURNS bytea
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_dek       bytea;
  v_dek_b64   text;
BEGIN
  IF p_business_id IS NULL THEN
    RAISE EXCEPTION 'encrypt_field: business_id is required' USING ERRCODE = '22000';
  END IF;
  IF p_plaintext IS NULL THEN RETURN NULL; END IF;
  v_dek := keys.get_active_dek_material(p_business_id);
  IF v_dek IS NULL THEN RETURN NULL; END IF;
  v_dek_b64 := encode(v_dek, 'base64');
  RETURN extensions.pgp_sym_encrypt(p_plaintext, v_dek_b64);
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.create_business_dek(p_business_id uuid)
 RETURNS keys.business_deks
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_org_id      uuid;
  v_parent_kek  keys.organization_keks;
  v_kek_bytes   bytea;
  v_kek_b64     text;
  v_dek_bytes   bytea;
  v_ciphertext  bytea;
  v_row         keys.business_deks;
BEGIN
  IF p_business_id IS NULL THEN
    RAISE EXCEPTION 'create_business_dek: business_id is required' USING ERRCODE = '22000';
  END IF;
  SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_business_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'create_business_dek: business % not found', p_business_id USING ERRCODE = 'P0002';
  END IF;
  IF EXISTS (SELECT 1 FROM keys.business_deks WHERE business_id = p_business_id AND status = 'ACTIVE') THEN
    RAISE EXCEPTION 'create_business_dek: business % already has an ACTIVE DEK', p_business_id USING ERRCODE = '23505';
  END IF;

  SELECT * INTO v_parent_kek
    FROM keys.organization_keks
   WHERE organization_id = v_org_id AND status = 'ACTIVE';
  IF NOT FOUND THEN
    RAISE EXCEPTION 'create_business_dek: no ACTIVE KEK for org % (run create_org_kek first)', v_org_id USING ERRCODE = 'P0002';
  END IF;

  v_kek_bytes  := keys._get_kek_material(v_parent_kek.kek_id);
  v_kek_b64    := encode(v_kek_bytes, 'base64');
  v_dek_bytes  := extensions.gen_random_bytes(32);
  v_ciphertext := extensions.pgp_sym_encrypt_bytea(v_dek_bytes, v_kek_b64);

  INSERT INTO keys.business_deks (business_id, parent_kek_id, dek_ciphertext, status, generation)
  VALUES (p_business_id, v_parent_kek.kek_id, v_ciphertext, 'ACTIVE', 1)
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'DEK_CREATED',
    p_subject_type    => 'DEK'::audit.subject_type_enum,
    p_subject_id      => v_row.dek_id,
    p_actor_system    => 'keys.create_business_dek',
    p_organization_id => v_org_id,
    p_business_id     => p_business_id,
    p_reason          => 'DEK auto-generated on business creation',
    p_after_state     => jsonb_build_object(
      'dek_id', v_row.dek_id,
      'business_id', p_business_id,
      'parent_kek_id', v_parent_kek.kek_id,
      'generation', 1
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.get_active_dek_material(p_business_id uuid)
 RETURNS bytea
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_org_id      uuid;
  v_dek_row     keys.business_deks;
  v_kek_bytes   bytea;
  v_kek_b64     text;
  v_dek_bytes   bytea;
BEGIN
  IF p_business_id IS NULL THEN
    RAISE EXCEPTION 'get_active_dek_material: business_id is required' USING ERRCODE = '22000';
  END IF;

  SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_business_id;
  IF v_org_id IS NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'KEY_ACCESS_DENIED',
      p_subject_type => 'DEK'::audit.subject_type_enum,
      p_actor_system => 'keys.get_active_dek_material',
      p_reason       => format('business %s not found', p_business_id),
      p_after_state  => jsonb_build_object('business_id', p_business_id, 'reason_code', 'BUSINESS_NOT_FOUND')
    );
    RETURN NULL;
  END IF;

  SELECT * INTO v_dek_row
    FROM keys.business_deks
   WHERE business_id = p_business_id AND status = 'ACTIVE';
  IF NOT FOUND THEN
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'KEY_ACCESS_DENIED',
      p_subject_type    => 'DEK'::audit.subject_type_enum,
      p_actor_system    => 'keys.get_active_dek_material',
      p_organization_id => v_org_id,
      p_business_id     => p_business_id,
      p_reason          => 'no ACTIVE DEK for business',
      p_after_state     => jsonb_build_object('business_id', p_business_id, 'reason_code', 'NO_ACTIVE_DEK')
    );
    RETURN NULL;
  END IF;

  v_kek_bytes := keys._get_kek_material(v_dek_row.parent_kek_id);
  v_kek_b64   := encode(v_kek_bytes, 'base64');
  v_dek_bytes := extensions.pgp_sym_decrypt_bytea(v_dek_row.dek_ciphertext, v_kek_b64);

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'KEY_ACCESSED',
    p_subject_type    => 'DEK'::audit.subject_type_enum,
    p_subject_id      => v_dek_row.dek_id,
    p_actor_system    => 'keys.get_active_dek_material',
    p_organization_id => v_org_id,
    p_business_id     => p_business_id,
    p_reason          => 'DEK material fetched for field-level encryption',
    p_after_state     => jsonb_build_object('dek_id', v_dek_row.dek_id, 'business_id', p_business_id, 'generation', v_dek_row.generation)
  );

  RETURN v_dek_bytes;
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.rotate_dek(p_business_id uuid)
 RETURNS keys.business_deks
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_old_dek      keys.business_deks;
  v_new_dek      keys.business_deks;
  v_org_id       uuid;
  v_parent_kek   keys.organization_keks;
  v_kek_bytes    bytea;
  v_kek_b64      text;
  v_new_bytes    bytea;
  v_ciphertext   bytea;
BEGIN
  IF p_business_id IS NULL THEN
    RAISE EXCEPTION 'rotate_dek: business_id is required' USING ERRCODE = '22000';
  END IF;

  SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_business_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'rotate_dek: business % not found', p_business_id USING ERRCODE = 'P0002';
  END IF;

  SELECT * INTO v_old_dek
    FROM keys.business_deks
   WHERE business_id = p_business_id AND status = 'ACTIVE'
   FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'rotate_dek: no ACTIVE DEK for business %', p_business_id USING ERRCODE = 'P0002';
  END IF;

  SELECT * INTO v_parent_kek
    FROM keys.organization_keks
   WHERE organization_id = v_org_id AND status = 'ACTIVE';
  IF NOT FOUND THEN
    RAISE EXCEPTION 'rotate_dek: no ACTIVE KEK for org %', v_org_id USING ERRCODE = 'P0002';
  END IF;

  UPDATE keys.business_deks
     SET status = 'RETIRED', retired_at = clock_timestamp()
   WHERE dek_id = v_old_dek.dek_id;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'DEK_RETIRED',
    p_subject_type    => 'DEK'::audit.subject_type_enum,
    p_subject_id      => v_old_dek.dek_id,
    p_actor_system    => 'keys.rotate_dek',
    p_organization_id => v_org_id,
    p_business_id     => p_business_id,
    p_reason          => 'rotation: superseded by new generation'
  );

  v_kek_bytes  := keys._get_kek_material(v_parent_kek.kek_id);
  v_kek_b64    := encode(v_kek_bytes, 'base64');
  v_new_bytes  := extensions.gen_random_bytes(32);
  v_ciphertext := extensions.pgp_sym_encrypt_bytea(v_new_bytes, v_kek_b64);

  INSERT INTO keys.business_deks (business_id, parent_kek_id, dek_ciphertext, status, generation)
  VALUES (p_business_id, v_parent_kek.kek_id, v_ciphertext, 'ACTIVE', v_old_dek.generation + 1)
  RETURNING * INTO v_new_dek;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'DEK_ROTATED',
    p_subject_type    => 'DEK'::audit.subject_type_enum,
    p_subject_id      => v_new_dek.dek_id,
    p_actor_system    => 'keys.rotate_dek',
    p_organization_id => v_org_id,
    p_business_id     => p_business_id,
    p_reason          => format('rotation generation %s -> %s', v_old_dek.generation, v_new_dek.generation),
    p_after_state     => jsonb_build_object(
      'old_dek_id', v_old_dek.dek_id,
      'new_dek_id', v_new_dek.dek_id,
      'business_id', p_business_id,
      'generation', v_new_dek.generation
    )
  );

  RETURN v_new_dek;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ai_gateway_invoke_finalize(p_invocation_id uuid, p_dispatch_status text, p_raw_response jsonb DEFAULT NULL::jsonb, p_dispatch_error_detail jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_inv          public.ai_gateway_invocations%ROWTYPE;
  v_biz          public.business_entities%ROWTYPE;
  v_validate     jsonb;
  v_variant      public.ai_gateway_result_variant_enum;
  v_status       public.ai_gateway_invocation_status_enum;
  v_audit_kind   audit.actor_kind_enum;
  v_actor_system text;
  v_audit_row    audit.audit_events;
  v_audit_event_id uuid;
BEGIN
  IF p_invocation_id IS NULL OR p_dispatch_status IS NULL THEN
    RAISE EXCEPTION 'ai_gateway_invoke_finalize: p_invocation_id and p_dispatch_status required'
      USING ERRCODE = '22000';
  END IF;
  IF p_dispatch_status NOT IN ('OK','ERROR') THEN
    RAISE EXCEPTION 'ai_gateway_invoke_finalize: p_dispatch_status must be OK or ERROR (got %)',
      p_dispatch_status USING ERRCODE = '22000';
  END IF;

  SELECT * INTO v_inv FROM public.ai_gateway_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'ok', false, 'decision', 'ERROR',
      'error_code', 'INVOCATION_NOT_FOUND',
      'message', format('gateway invocation %s not found', p_invocation_id)
    );
  END IF;
  IF v_inv.status <> 'PREPARED'::public.ai_gateway_invocation_status_enum THEN
    RETURN jsonb_build_object(
      'ok', false, 'decision', 'ERROR',
      'error_code', 'ALREADY_FINALIZED',
      'message', format('gateway invocation %s already in status %s', p_invocation_id, v_inv.status),
      'current_status', v_inv.status::text
    );
  END IF;

  SELECT * INTO v_biz FROM public.business_entities WHERE id = v_inv.business_id;

  IF p_dispatch_status = 'ERROR' THEN
    v_variant := 'MODEL_ERROR'::public.ai_gateway_result_variant_enum;
    v_status  := 'COMPLETED_MODEL_ERROR'::public.ai_gateway_invocation_status_enum;
    UPDATE public.ai_gateway_invocations
       SET status = v_status, result_variant = v_variant,
           raw_response = p_raw_response,
           error_detail = COALESCE(p_dispatch_error_detail,
                                   jsonb_build_object('code','MODEL_ERROR')),
           finalized_at = clock_timestamp()
     WHERE id = p_invocation_id;
    RETURN jsonb_build_object(
      'ok',             false,
      'invocation_id',  p_invocation_id,
      'result_variant', 'MODEL_ERROR',
      'error_detail',   COALESCE(p_dispatch_error_detail,
                                 jsonb_build_object('code','MODEL_ERROR'))
    );
  END IF;

  IF p_raw_response IS NULL THEN
    v_validate := jsonb_build_object('valid', false,
                    'errors', jsonb_build_array(jsonb_build_object(
                                'code','NULL_RESPONSE',
                                'message','dispatch_status=OK requires non-null raw_response')));
  ELSE
    v_validate := public.validate_tool_output(v_inv.tool_name, p_raw_response);
  END IF;

  IF NOT (v_validate->>'valid')::boolean THEN
    v_variant := 'SCHEMA_VIOLATION_OUTPUT'::public.ai_gateway_result_variant_enum;
    v_status  := 'COMPLETED_SCHEMA_VIOLATION_OUTPUT'::public.ai_gateway_invocation_status_enum;
    UPDATE public.ai_gateway_invocations
       SET status = v_status, result_variant = v_variant,
           raw_response = p_raw_response,
           error_detail = v_validate->'errors',
           finalized_at = clock_timestamp()
     WHERE id = p_invocation_id;

    IF v_inv.actor_user_id IS NULL THEN
      v_audit_kind := 'SYSTEM'::audit.actor_kind_enum;
      v_actor_system := 'ai_gateway';
    ELSE
      v_audit_kind := 'USER'::audit.actor_kind_enum;
      v_actor_system := NULL;
    END IF;

    v_audit_row := audit.emit_audit(
      p_actor_kind      => v_audit_kind,
      p_action          => 'AI_GATEWAY_RESPONSE_INVALID',
      p_subject_type    => 'AI_GATEWAY_INVOCATION'::audit.subject_type_enum,
      p_subject_id      => p_invocation_id,
      p_actor_user_id   => v_inv.actor_user_id,
      p_actor_system    => v_actor_system,
      p_organization_id => v_biz.organization_id,
      p_business_id     => v_inv.business_id,
      p_reason          => format('model output failed schema for tool %s', v_inv.tool_name),
      p_after_state     => jsonb_build_object(
        'invocation_id', p_invocation_id,
        'tool_name',     v_inv.tool_name,
        'variant',       'SCHEMA_VIOLATION_OUTPUT',
        'errors',        v_validate->'errors'
      )
    );
    v_audit_event_id := v_audit_row.id;

    RETURN jsonb_build_object(
      'ok',             false,
      'invocation_id',  p_invocation_id,
      'result_variant', 'SCHEMA_VIOLATION_OUTPUT',
      'errors',         v_validate->'errors',
      'audit_event_id', v_audit_event_id
    );
  END IF;

  v_variant := 'SUCCESS'::public.ai_gateway_result_variant_enum;
  v_status  := 'COMPLETED_SUCCESS'::public.ai_gateway_invocation_status_enum;
  UPDATE public.ai_gateway_invocations
     SET status = v_status, result_variant = v_variant,
         raw_response = p_raw_response,
         validated_output = p_raw_response,
         finalized_at = clock_timestamp()
   WHERE id = p_invocation_id;

  RETURN jsonb_build_object(
    'ok',               true,
    'invocation_id',    p_invocation_id,
    'result_variant',   'SUCCESS',
    'validated_output', p_raw_response,
    'tier',             v_inv.tier::text,
    'tier_label',       v_inv.tier_label,
    'model_id',         v_inv.model_id,
    'prompt_version',   v_inv.prompt_version
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.rotate_kek(p_organization_id uuid)
 RETURNS keys.organization_keks
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_old_kek     keys.organization_keks;
  v_new_kek     keys.organization_keks;
  v_old_bytes   bytea;
  v_new_bytes   bytea;
  v_new_b64     text;
  v_old_b64     text;
  v_secret_id   uuid;
  v_dek_row     record;
  v_dek_bytes   bytea;
  v_new_ct      bytea;
  v_rewrapped   integer := 0;
BEGIN
  IF p_organization_id IS NULL THEN
    RAISE EXCEPTION 'rotate_kek: organization_id is required' USING ERRCODE = '22000';
  END IF;

  SELECT * INTO v_old_kek
    FROM keys.organization_keks
   WHERE organization_id = p_organization_id AND status = 'ACTIVE'
   FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'rotate_kek: no ACTIVE KEK for org %', p_organization_id USING ERRCODE = 'P0002';
  END IF;

  v_old_bytes := keys._get_kek_material(v_old_kek.kek_id);
  v_old_b64   := encode(v_old_bytes, 'base64');
  v_new_bytes := extensions.gen_random_bytes(32);
  v_new_b64   := encode(v_new_bytes, 'base64');

  v_secret_id := vault.create_secret(
    new_secret      => v_new_b64,
    new_name        => 'kek-' || p_organization_id::text || '-g' || (v_old_kek.generation + 1)::text,
    new_description => format('B05P04 rotated KEK for org %s (gen %s)', p_organization_id, v_old_kek.generation + 1)
  );

  UPDATE keys.organization_keks
     SET status = 'ROTATED', rotated_at = clock_timestamp()
   WHERE kek_id = v_old_kek.kek_id;

  INSERT INTO keys.organization_keks (organization_id, vault_secret_id, status, generation)
  VALUES (p_organization_id, v_secret_id, 'ACTIVE', v_old_kek.generation + 1)
  RETURNING * INTO v_new_kek;

  FOR v_dek_row IN
    SELECT bd.* FROM keys.business_deks bd
     JOIN public.business_entities be ON be.id = bd.business_id
     WHERE be.organization_id = p_organization_id
       AND bd.status IN ('ACTIVE','RETIRED')
       AND bd.parent_kek_id = v_old_kek.kek_id
  LOOP
    v_dek_bytes := extensions.pgp_sym_decrypt_bytea(v_dek_row.dek_ciphertext, v_old_b64);
    v_new_ct    := extensions.pgp_sym_encrypt_bytea(v_dek_bytes, v_new_b64);
    UPDATE keys.business_deks
       SET dek_ciphertext = v_new_ct,
           parent_kek_id  = v_new_kek.kek_id
     WHERE dek_id = v_dek_row.dek_id;
    v_rewrapped := v_rewrapped + 1;
  END LOOP;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'KEK_ROTATED',
    p_subject_type    => 'KEK'::audit.subject_type_enum,
    p_subject_id      => v_new_kek.kek_id,
    p_actor_system    => 'keys.rotate_kek',
    p_organization_id => p_organization_id,
    p_reason          => format('KEK rotated generation %s -> %s; %s DEKs re-wrapped', v_old_kek.generation, v_new_kek.generation, v_rewrapped),
    p_after_state     => jsonb_build_object(
      'old_kek_id', v_old_kek.kek_id,
      'new_kek_id', v_new_kek.kek_id,
      'organization_id', p_organization_id,
      'generation', v_new_kek.generation,
      'deks_rewrapped', v_rewrapped
    )
  );

  RETURN v_new_kek;
END;
$function$
;

