CREATE OR REPLACE FUNCTION keys.get_dek_by_id(p_dek_id uuid)
 RETURNS bytea
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_dek_row   keys.business_deks;
  v_org_id    uuid;
  v_kek_bytes bytea;
  v_kek_b64   text;
  v_dek_bytes bytea;
BEGIN
  IF p_dek_id IS NULL THEN
    RAISE EXCEPTION 'get_dek_by_id: dek_id is required' USING ERRCODE = '22000';
  END IF;

  SELECT * INTO v_dek_row FROM keys.business_deks WHERE dek_id = p_dek_id;
  IF NOT FOUND THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'KEY_ACCESS_DENIED',
      p_subject_type => 'DEK'::audit.subject_type_enum,
      p_actor_system => 'keys.get_dek_by_id',
      p_reason       => format('dek %s not found', p_dek_id),
      p_after_state  => jsonb_build_object('dek_id', p_dek_id, 'reason_code', 'DEK_NOT_FOUND')
    );
    RETURN NULL;
  END IF;

  SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = v_dek_row.business_id;

  IF v_dek_row.status = 'DESTROYED' THEN
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'KEY_ACCESS_DENIED',
      p_subject_type    => 'DEK'::audit.subject_type_enum,
      p_subject_id      => p_dek_id,
      p_actor_system    => 'keys.get_dek_by_id',
      p_organization_id => v_org_id,
      p_business_id     => v_dek_row.business_id,
      p_reason          => 'DEK has been DESTROYED — cryptographic erasure',
      p_after_state     => jsonb_build_object('dek_id', p_dek_id, 'reason_code', 'DEK_DESTROYED')
    );
    RETURN NULL;
  END IF;

  v_kek_bytes := keys._get_kek_material(v_dek_row.parent_kek_id);
  v_kek_b64   := encode(v_kek_bytes, 'base64');
  v_dek_bytes := extensions.pgp_sym_decrypt_bytea(v_dek_row.dek_ciphertext, v_kek_b64);

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'KEY_ACCESSED',
    p_subject_type    => 'DEK'::audit.subject_type_enum,
    p_subject_id      => p_dek_id,
    p_actor_system    => 'keys.get_dek_by_id',
    p_organization_id => v_org_id,
    p_business_id     => v_dek_row.business_id,
    p_reason          => format('historical DEK material fetched (status=%s)', v_dek_row.status),
    p_after_state     => jsonb_build_object('dek_id', p_dek_id, 'status', v_dek_row.status, 'generation', v_dek_row.generation)
  );

  RETURN v_dek_bytes;
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.destroy_dek(p_business_id uuid, p_dek_id uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_dek_row keys.business_deks;
  v_org_id  uuid;
BEGIN
  IF p_business_id IS NULL OR p_dek_id IS NULL OR p_reason IS NULL OR length(btrim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'destroy_dek: business_id, dek_id, reason all required' USING ERRCODE = '22000';
  END IF;

  -- Guard check: return-on-fail (Mitigation A of audit-then-raise hazard).
  -- We emit the KEY_ACCESS_DENIED audit and RETURN a denial envelope so the
  -- audit row survives. Caller branches on success.
  IF COALESCE(current_setting('keys.allow_destroy', true), 'off') <> 'on' THEN
    SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_business_id;
    PERFORM audit.emit_audit(
      p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
      p_action          => 'KEY_ACCESS_DENIED',
      p_subject_type    => 'DEK'::audit.subject_type_enum,
      p_subject_id      => p_dek_id,
      p_actor_system    => 'keys.destroy_dek',
      p_organization_id => v_org_id,
      p_business_id     => p_business_id,
      p_reason          => 'destroy_dek invoked without keys.allow_destroy=on guard',
      p_after_state     => jsonb_build_object('dek_id', p_dek_id, 'reason_code', 'GUARD_NOT_SET', 'requested_reason', p_reason)
    );
    RETURN jsonb_build_object(
      'success',        false,
      'denial_reason',  'GUARD_NOT_SET',
      'dek_id',         p_dek_id,
      'business_id',    p_business_id,
      'message',        'destroy_dek requires keys.allow_destroy=on set by retention or multi-party ops procedure'
    );
  END IF;

  SELECT * INTO v_dek_row
    FROM keys.business_deks
   WHERE dek_id = p_dek_id AND business_id = p_business_id
   FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success',        false,
      'denial_reason',  'DEK_NOT_FOUND',
      'dek_id',         p_dek_id,
      'business_id',    p_business_id
    );
  END IF;
  IF v_dek_row.status = 'DESTROYED' THEN
    RETURN jsonb_build_object(
      'success',        false,
      'denial_reason',  'ALREADY_DESTROYED',
      'dek_id',         p_dek_id,
      'business_id',    p_business_id
    );
  END IF;

  SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_business_id;

  -- Emit BEFORE nulling: even if the subsequent UPDATE fails, the destruction
  -- attempt is forensically recorded.
  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'DEK_DESTROYED',
    p_subject_type    => 'DEK'::audit.subject_type_enum,
    p_subject_id      => p_dek_id,
    p_actor_system    => 'keys.destroy_dek',
    p_organization_id => v_org_id,
    p_business_id     => p_business_id,
    p_reason          => p_reason,
    p_before_state    => jsonb_build_object('dek_id', p_dek_id, 'status', v_dek_row.status, 'generation', v_dek_row.generation),
    p_after_state     => jsonb_build_object('dek_id', p_dek_id, 'status', 'DESTROYED', 'destruction_reason', p_reason)
  );

  UPDATE keys.business_deks
     SET status             = 'DESTROYED',
         dek_ciphertext     = NULL,
         destroyed_at       = clock_timestamp(),
         destruction_reason = p_reason,
         retired_at         = COALESCE(retired_at, clock_timestamp())
   WHERE dek_id = p_dek_id
  RETURNING * INTO v_dek_row;

  RETURN jsonb_build_object(
    'success',            true,
    'dek_id',             p_dek_id,
    'business_id',        p_business_id,
    'status',             v_dek_row.status,
    'destroyed_at',       v_dek_row.destroyed_at,
    'destruction_reason', v_dek_row.destruction_reason
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.mask_field(p_plaintext text, p_kind keys.field_kind_enum)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'pg_temp'
AS $function$
DECLARE
  v_clean text;
  v_len   int;
BEGIN
  IF p_plaintext IS NULL THEN RETURN NULL; END IF;
  IF p_kind = 'OAUTH_TOKEN' THEN RETURN '***'; END IF;
  v_clean := regexp_replace(p_plaintext, '\s', '', 'g');
  v_len   := length(v_clean);
  IF p_kind = 'IBAN' OR p_kind = 'ACCOUNT_NUMBER' THEN
    IF v_len <= 4 THEN RETURN '***'; END IF;
    RETURN '***' || right(v_clean, 4);
  END IF;
  IF p_kind = 'VAT_NUMBER' THEN
    IF v_len <= 4 THEN RETURN '***'; END IF;
    RETURN left(v_clean, 2) || '***' || right(v_clean, 2);
  END IF;
  RAISE EXCEPTION 'mask_field: unsupported kind %', p_kind USING ERRCODE = '22023';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.current_prompt_version(p_prompt_id text, p_environment prompt_environment_enum)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT version FROM public.prompt_deployments
    WHERE prompt_id = p_prompt_id AND environment = p_environment AND is_current = true;
$function$
;

CREATE OR REPLACE FUNCTION auth_runtime.check_access(p_actor_user_id uuid, p_surface text, p_action text, p_resource jsonb, p_business_id uuid DEFAULT NULL::uuid, p_organization_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'auth_runtime', 'public', 'audit', 'pg_temp'
AS $function$
DECLARE
  v_decision_jsonb       jsonb;
  v_decision             text;
  v_is_sensitive         boolean;
  v_step_up_window       interval;
  v_mfa_recent_at        timestamptz;
  v_reason_code          text;
  v_cross_tenant         boolean := false;
  v_resource_fingerprint text;
  v_canonical            text;
  v_err_state            text;
  v_err_msg              text;
BEGIN
  IF p_actor_user_id IS NULL THEN
    RAISE EXCEPTION 'check_access: actor_user_id is required' USING ERRCODE = '22000';
  END IF;
  IF p_surface IS NULL OR length(btrim(p_surface)) = 0 THEN
    RAISE EXCEPTION 'check_access: surface is required' USING ERRCODE = '22000';
  END IF;
  IF p_action IS NULL OR length(btrim(p_action)) = 0 THEN
    RAISE EXCEPTION 'check_access: action is required' USING ERRCODE = '22000';
  END IF;

  v_canonical := audit.canonical_jsonb(COALESCE(p_resource, '{}'::jsonb));
  v_resource_fingerprint := public.hash_text_sha256(v_canonical);
  v_is_sensitive := auth_runtime.is_sensitive_surface(p_surface);

  BEGIN
    v_decision_jsonb := public.can_perform(
      p_actor_user_id, p_surface, p_action,
      COALESCE(p_resource, '{}'::jsonb),
      p_business_id, p_organization_id
    );
  EXCEPTION WHEN OTHERS THEN
    GET STACKED DIAGNOSTICS v_err_state = RETURNED_SQLSTATE, v_err_msg = MESSAGE_TEXT;
    PERFORM audit.emit_audit(
      p_actor_kind      => 'USER'::audit.actor_kind_enum,
      p_action          => 'ACCESS_DECISION_THREW',
      p_subject_type    => 'ACCESS_DECISION'::audit.subject_type_enum,
      p_actor_user_id   => p_actor_user_id,
      p_organization_id => p_organization_id,
      p_business_id     => p_business_id,
      p_reason          => format('can_perform threw: %s', v_err_msg),
      p_after_state     => jsonb_build_object(
        'surface',              p_surface,
        'action',               p_action,
        'resource_fingerprint', v_resource_fingerprint,
        'error_class',          v_err_state,
        'error_message',        v_err_msg,
        'alert',                'CRITICAL'
      )
    );
    RETURN jsonb_build_object('decision','DENY','reason_code','decision_threw','alert','CRITICAL');
  END;

  v_decision := v_decision_jsonb->>'decision';

  IF v_decision = 'ALLOW' THEN
    IF v_is_sensitive THEN
      PERFORM audit.emit_audit(
        p_actor_kind      => 'USER'::audit.actor_kind_enum,
        p_action          => 'ACCESS_ALLOWED',
        p_subject_type    => 'ACCESS_DECISION'::audit.subject_type_enum,
        p_actor_user_id   => p_actor_user_id,
        p_organization_id => p_organization_id,
        p_business_id     => p_business_id,
        p_reason          => format('%s/%s allowed', p_surface, p_action),
        p_after_state     => jsonb_build_object(
          'surface',              p_surface,
          'action',               p_action,
          'resource_fingerprint', v_resource_fingerprint,
          'sensitive',            true
        )
      );
    END IF;
    RETURN jsonb_build_object('decision','ALLOW');
  END IF;

  IF v_decision = 'DENY' THEN
    v_reason_code  := COALESCE(v_decision_jsonb->>'reason_code', 'denied');
    v_cross_tenant := COALESCE((v_decision_jsonb->>'cross_tenant')::boolean, false);
    PERFORM audit.emit_audit(
      p_actor_kind      => 'USER'::audit.actor_kind_enum,
      p_action          => 'ACCESS_DENIED',
      p_subject_type    => 'ACCESS_DECISION'::audit.subject_type_enum,
      p_actor_user_id   => p_actor_user_id,
      p_organization_id => p_organization_id,
      p_business_id     => p_business_id,
      p_reason          => format('%s/%s denied: %s', p_surface, p_action, v_reason_code),
      p_after_state     => jsonb_build_object(
        'surface',              p_surface,
        'action',               p_action,
        'resource_fingerprint', v_resource_fingerprint,
        'reason_code',          v_reason_code,
        'cross_tenant',         v_cross_tenant
      )
    );
    RETURN jsonb_build_object('decision','DENY','reason_code',v_reason_code,'cross_tenant',v_cross_tenant);
  END IF;

  IF v_decision IN ('STEP_UP', 'REQUIRE_STEP_UP') THEN
    SELECT step_up_window INTO v_step_up_window
      FROM auth_runtime.sensitive_surfaces WHERE surface = p_surface;
    IF v_step_up_window IS NULL THEN
      v_step_up_window := '5 minutes'::interval;
    END IF;
    SELECT mfa_recent_at INTO v_mfa_recent_at FROM public.users WHERE id = p_actor_user_id;

    IF v_mfa_recent_at IS NOT NULL AND (now() - v_mfa_recent_at) <= v_step_up_window THEN
      IF v_is_sensitive THEN
        PERFORM audit.emit_audit(
          p_actor_kind      => 'USER'::audit.actor_kind_enum,
          p_action          => 'ACCESS_ALLOWED',
          p_subject_type    => 'ACCESS_DECISION'::audit.subject_type_enum,
          p_actor_user_id   => p_actor_user_id,
          p_organization_id => p_organization_id,
          p_business_id     => p_business_id,
          p_reason          => format('%s/%s allowed via recent MFA', p_surface, p_action),
          p_after_state     => jsonb_build_object(
            'surface',              p_surface,
            'action',               p_action,
            'resource_fingerprint', v_resource_fingerprint,
            'via',                  'recent_mfa',
            'sensitive',            true
          )
        );
      END IF;
      RETURN jsonb_build_object('decision','ALLOW','via','recent_mfa');
    END IF;

    PERFORM audit.emit_audit(
      p_actor_kind      => 'USER'::audit.actor_kind_enum,
      p_action          => 'ACCESS_STEP_UP_TRIGGERED',
      p_subject_type    => 'ACCESS_DECISION'::audit.subject_type_enum,
      p_actor_user_id   => p_actor_user_id,
      p_organization_id => p_organization_id,
      p_business_id     => p_business_id,
      p_reason          => format('%s/%s requires step-up', p_surface, p_action),
      p_after_state     => jsonb_build_object(
        'surface',                p_surface,
        'action',                 p_action,
        'resource_fingerprint',   v_resource_fingerprint,
        'step_up_window_seconds', extract(epoch from v_step_up_window)::int
      )
    );
    RETURN jsonb_build_object('decision','STEP_UP','step_up_surface',p_surface,'step_up_window_seconds',extract(epoch from v_step_up_window)::int);
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'USER'::audit.actor_kind_enum,
    p_action          => 'ACCESS_DENIED',
    p_subject_type    => 'ACCESS_DECISION'::audit.subject_type_enum,
    p_actor_user_id   => p_actor_user_id,
    p_organization_id => p_organization_id,
    p_business_id     => p_business_id,
    p_reason          => format('unknown decision from can_perform: %s', v_decision),
    p_after_state     => jsonb_build_object(
      'surface',              p_surface,
      'action',               p_action,
      'resource_fingerprint', v_resource_fingerprint,
      'reason_code',          'unknown_decision',
      'raw_decision',         v_decision_jsonb
    )
  );
  RETURN jsonb_build_object('decision','DENY','reason_code','unknown_decision');
END;
$function$
;

CREATE OR REPLACE FUNCTION keys.decrypt_field(p_business_id uuid, p_ciphertext bytea, p_field_name text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'keys', 'vault', 'extensions', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_dek         bytea;
  v_dek_b64     text;
  v_plaintext   text;
  v_fingerprint text;
  v_org_id      uuid;
BEGIN
  IF p_business_id IS NULL THEN
    RAISE EXCEPTION 'decrypt_field: business_id is required' USING ERRCODE = '22000';
  END IF;
  IF p_field_name IS NULL OR length(btrim(p_field_name)) = 0 THEN
    RAISE EXCEPTION 'decrypt_field: field_name is required' USING ERRCODE = '22000';
  END IF;
  IF p_ciphertext IS NULL THEN RETURN NULL; END IF;

  v_dek := keys.get_active_dek_material(p_business_id);
  IF v_dek IS NULL THEN RETURN NULL; END IF;

  v_dek_b64 := encode(v_dek, 'base64');

  BEGIN
    v_plaintext := extensions.pgp_sym_decrypt(p_ciphertext, v_dek_b64);
  EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
  END;

  v_fingerprint := public.hash_text_sha256(encode(p_ciphertext, 'base64'));
  SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_business_id;

  PERFORM audit.emit_audit(
    p_actor_kind      => 'SYSTEM'::audit.actor_kind_enum,
    p_action          => 'FIELD_DECRYPTED',
    p_subject_type    => 'ENCRYPTED_FIELD'::audit.subject_type_enum,
    p_actor_system    => 'keys.decrypt_field',
    p_organization_id => v_org_id,
    p_business_id     => p_business_id,
    p_reason          => format('field %s decrypted', p_field_name),
    p_after_state     => jsonb_build_object(
      'field_name',             p_field_name,
      'business_id',            p_business_id,
      'ciphertext_fingerprint', v_fingerprint,
      'ciphertext_bytes',       octet_length(p_ciphertext)
    )
  );

  RETURN v_plaintext;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.record_backup_completed(p_backup_id uuid, p_bytes bigint, p_backup_hash text, p_location text)
 RETURNS backups.backup_records
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row backups.backup_records;
BEGIN
  IF p_backup_id IS NULL THEN RAISE EXCEPTION 'record_backup_completed: backup_id required' USING ERRCODE='22000'; END IF;
  IF p_bytes IS NULL OR p_bytes < 0 THEN RAISE EXCEPTION 'record_backup_completed: bytes >= 0 required' USING ERRCODE='22000'; END IF;
  IF p_backup_hash IS NULL OR p_backup_hash !~ '^[0-9a-f]{64}$' THEN
    RAISE EXCEPTION 'record_backup_completed: backup_hash must be 64-hex' USING ERRCODE='22000';
  END IF;
  IF p_location IS NULL OR length(btrim(p_location)) = 0 THEN
    RAISE EXCEPTION 'record_backup_completed: location required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_row FROM backups.backup_records WHERE id = p_backup_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_backup_completed: backup % not found', p_backup_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'STARTED' THEN
    RAISE EXCEPTION 'record_backup_completed: backup % not in STARTED (got %)', p_backup_id, v_row.status USING ERRCODE='23514';
  END IF;

  UPDATE backups.backup_records
     SET status       = 'COMPLETED',
         bytes        = p_bytes,
         backup_hash  = p_backup_hash,
         location     = p_location,
         completed_at = clock_timestamp()
   WHERE id = p_backup_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'BACKUP_COMPLETED',
    p_subject_type => 'BACKUP'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.record_backup_completed',
    p_reason       => format('backup %s completed (%s bytes)', p_backup_id, p_bytes),
    p_after_state  => jsonb_build_object(
      'backup_id', v_row.id, 'bytes', p_bytes, 'backup_hash', p_backup_hash, 'location', p_location
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION secrets._derive_expires_at(p_category text, p_rotated_at timestamp with time zone)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'secrets', 'pg_temp'
AS $function$
DECLARE
  v_interval interval;
BEGIN
  SELECT rotation_interval INTO v_interval FROM secrets.secret_policies WHERE category = p_category;
  IF v_interval IS NULL THEN
    RAISE EXCEPTION '_derive_expires_at: unknown category %', p_category USING ERRCODE = '22023';
  END IF;
  RETURN p_rotated_at + v_interval;
END;
$function$
;

CREATE OR REPLACE FUNCTION auth_runtime.is_sensitive_surface(p_surface text)
 RETURNS boolean
 LANGUAGE sql
 STABLE
 SET search_path TO 'auth_runtime', 'pg_temp'
AS $function$
  SELECT EXISTS (SELECT 1 FROM auth_runtime.sensitive_surfaces WHERE surface = p_surface);
$function$
;

CREATE OR REPLACE FUNCTION secrets.register_secret(p_name text, p_category text, p_initial_value text, p_owner text, p_description text DEFAULT NULL::text)
 RETURNS secrets.managed_secrets
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'secrets', 'vault', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_secret_id  uuid;
  v_now        timestamptz := clock_timestamp();
  v_expires_at timestamptz;
  v_row        secrets.managed_secrets;
BEGIN
  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN
    RAISE EXCEPTION 'register_secret: name is required' USING ERRCODE = '22000'; END IF;
  IF p_category IS NULL OR length(btrim(p_category)) = 0 THEN
    RAISE EXCEPTION 'register_secret: category is required' USING ERRCODE = '22000'; END IF;
  IF p_initial_value IS NULL OR length(p_initial_value) = 0 THEN
    RAISE EXCEPTION 'register_secret: initial_value is required' USING ERRCODE = '22000'; END IF;
  IF p_owner IS NULL OR length(btrim(p_owner)) = 0 THEN
    RAISE EXCEPTION 'register_secret: owner is required' USING ERRCODE = '22000'; END IF;
  IF NOT EXISTS (SELECT 1 FROM secrets.secret_policies WHERE category = p_category) THEN
    RAISE EXCEPTION 'register_secret: unknown category %', p_category USING ERRCODE = '23514'; END IF;

  v_secret_id  := vault.create_secret(
    new_secret      => p_initial_value,
    new_name        => 'app-secret-' || p_name,
    new_description => COALESCE(p_description, format('B05P07 managed secret %s (%s)', p_name, p_category))
  );
  v_expires_at := secrets._derive_expires_at(p_category, v_now);

  INSERT INTO secrets.managed_secrets (
    secret_name, vault_secret_id, category, owner, description,
    status, generation, created_at, rotated_at, expires_at
  ) VALUES (
    p_name, v_secret_id, p_category, p_owner, p_description,
    'ACTIVE', 1, v_now, v_now, v_expires_at
  )
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'SECRET_CREATED',
    p_subject_type => 'SECRET'::audit.subject_type_enum,
    p_subject_id   => v_row.secret_id,
    p_actor_system => 'secrets.register_secret',
    p_reason       => format('secret %s registered under category %s', p_name, p_category),
    p_after_state  => jsonb_build_object(
      'secret_id', v_row.secret_id, 'secret_name', p_name, 'category', p_category,
      'owner', p_owner, 'vault_secret_id', v_secret_id, 'generation', 1, 'expires_at', v_expires_at
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION secrets.get_secret(p_name text, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'secrets', 'vault', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row    secrets.managed_secrets;
  v_value  text;
  v_err    text;
BEGIN
  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN
    RAISE EXCEPTION 'get_secret: name is required' USING ERRCODE = '22000'; END IF;

  SELECT * INTO v_row FROM secrets.managed_secrets WHERE secret_name = p_name;
  IF NOT FOUND THEN
    PERFORM audit.emit_audit(
      p_actor_kind    => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action        => 'SECRET_ACCESS_DENIED',
      p_subject_type  => 'SECRET'::audit.subject_type_enum,
      p_actor_user_id => p_actor_user_id,
      p_actor_system  => CASE WHEN p_actor_user_id IS NULL THEN 'secrets.get_secret' ELSE NULL END,
      p_reason        => format('secret %s not found', p_name),
      p_after_state   => jsonb_build_object('secret_name', p_name, 'reason_code', 'SECRET_NOT_FOUND')
    );
    RETURN NULL;
  END IF;

  IF v_row.status = 'DESTROYED' THEN
    PERFORM audit.emit_audit(
      p_actor_kind    => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action        => 'SECRET_ACCESS_DENIED',
      p_subject_type  => 'SECRET'::audit.subject_type_enum,
      p_subject_id    => v_row.secret_id,
      p_actor_user_id => p_actor_user_id,
      p_actor_system  => CASE WHEN p_actor_user_id IS NULL THEN 'secrets.get_secret' ELSE NULL END,
      p_reason        => format('secret %s is DESTROYED', p_name),
      p_after_state   => jsonb_build_object('secret_name', p_name, 'secret_id', v_row.secret_id, 'reason_code', 'SECRET_DESTROYED')
    );
    RETURN NULL;
  END IF;

  BEGIN
    SELECT decrypted_secret INTO v_value FROM vault.decrypted_secrets WHERE id = v_row.vault_secret_id;
  EXCEPTION WHEN OTHERS THEN
    GET STACKED DIAGNOSTICS v_err = MESSAGE_TEXT;
    PERFORM audit.emit_audit(
      p_actor_kind    => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action        => 'SECRET_ACCESS_FAILED',
      p_subject_type  => 'SECRET'::audit.subject_type_enum,
      p_subject_id    => v_row.secret_id,
      p_actor_user_id => p_actor_user_id,
      p_actor_system  => CASE WHEN p_actor_user_id IS NULL THEN 'secrets.get_secret' ELSE NULL END,
      p_reason        => format('vault read failed for %s', p_name),
      p_after_state   => jsonb_build_object('secret_name', p_name, 'secret_id', v_row.secret_id, 'reason_code', 'VAULT_READ_FAILED', 'error_message', v_err)
    );
    RETURN NULL;
  END;

  IF v_value IS NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind    => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
      p_action        => 'SECRET_ACCESS_FAILED',
      p_subject_type  => 'SECRET'::audit.subject_type_enum,
      p_subject_id    => v_row.secret_id,
      p_actor_user_id => p_actor_user_id,
      p_actor_system  => CASE WHEN p_actor_user_id IS NULL THEN 'secrets.get_secret' ELSE NULL END,
      p_reason        => format('vault row missing for %s', p_name),
      p_after_state   => jsonb_build_object('secret_name', p_name, 'secret_id', v_row.secret_id, 'reason_code', 'VAULT_ROW_MISSING')
    );
    RETURN NULL;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind    => CASE WHEN p_actor_user_id IS NULL THEN 'SYSTEM'::audit.actor_kind_enum ELSE 'USER'::audit.actor_kind_enum END,
    p_action        => 'SECRET_ACCESSED',
    p_subject_type  => 'SECRET'::audit.subject_type_enum,
    p_subject_id    => v_row.secret_id,
    p_actor_user_id => p_actor_user_id,
    p_actor_system  => CASE WHEN p_actor_user_id IS NULL THEN 'secrets.get_secret' ELSE NULL END,
    p_reason        => format('secret %s accessed', p_name),
    p_after_state   => jsonb_build_object(
      'secret_name', p_name, 'secret_id', v_row.secret_id, 'category', v_row.category,
      'generation', v_row.generation, 'vault_secret_id', v_row.vault_secret_id
    )
  );

  RETURN v_value;
END;
$function$
;

CREATE OR REPLACE FUNCTION secrets.rotate_secret(p_name text, p_new_value text, p_reason text)
 RETURNS secrets.managed_secrets
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'secrets', 'vault', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row              secrets.managed_secrets;
  v_old_vault_id     uuid;
  v_new_vault_id     uuid;
  v_now              timestamptz := clock_timestamp();
  v_new_expires_at   timestamptz;
  v_keep_previous    boolean;
BEGIN
  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN
    RAISE EXCEPTION 'rotate_secret: name is required' USING ERRCODE = '22000'; END IF;
  IF p_new_value IS NULL OR length(p_new_value) = 0 THEN
    RAISE EXCEPTION 'rotate_secret: new_value is required' USING ERRCODE = '22000'; END IF;
  IF p_reason IS NULL OR length(btrim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'rotate_secret: reason is required' USING ERRCODE = '22000'; END IF;

  SELECT * INTO v_row FROM secrets.managed_secrets WHERE secret_name = p_name FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'rotate_secret: secret % not found', p_name USING ERRCODE = 'P0002'; END IF;
  IF v_row.status = 'DESTROYED' THEN
    RAISE EXCEPTION 'rotate_secret: secret % is DESTROYED', p_name USING ERRCODE = '23514'; END IF;

  v_old_vault_id := v_row.vault_secret_id;
  v_keep_previous := (v_row.category = 'BACKUP_ENCRYPTION');

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'SECRET_ROTATION_STARTED',
    p_subject_type => 'SECRET'::audit.subject_type_enum,
    p_subject_id   => v_row.secret_id,
    p_actor_system => 'secrets.rotate_secret',
    p_reason       => format('rotation started for %s: %s', p_name, p_reason),
    p_before_state => jsonb_build_object('generation', v_row.generation, 'vault_secret_id', v_old_vault_id),
    p_after_state  => jsonb_build_object('secret_name', p_name, 'category', v_row.category, 'keep_previous_for_overlap', v_keep_previous)
  );

  v_new_vault_id := vault.create_secret(
    new_secret      => p_new_value,
    new_name        => format('app-secret-%s-g%s', p_name, (v_row.generation + 1)::text),
    new_description => format('B05P07 rotated secret %s generation %s', p_name, v_row.generation + 1)
  );

  v_new_expires_at := secrets._derive_expires_at(v_row.category, v_now);

  UPDATE secrets.managed_secrets
     SET vault_secret_id          = v_new_vault_id,
         previous_vault_secret_id = CASE WHEN v_keep_previous THEN v_old_vault_id ELSE NULL END,
         generation               = v_row.generation + 1,
         rotated_at               = v_now,
         expires_at               = v_new_expires_at,
         status                   = 'ACTIVE',
         stale_detected_at        = NULL,
         last_stale_reason        = NULL
   WHERE secret_id = v_row.secret_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'SECRET_ROTATED',
    p_subject_type => 'SECRET'::audit.subject_type_enum,
    p_subject_id   => v_row.secret_id,
    p_actor_system => 'secrets.rotate_secret',
    p_reason       => format('secret %s rotated to generation %s', p_name, v_row.generation),
    p_after_state  => jsonb_build_object(
      'secret_name', p_name, 'category', v_row.category, 'generation', v_row.generation,
      'vault_secret_id', v_new_vault_id, 'previous_vault_secret_id', v_row.previous_vault_secret_id,
      'rotated_at', v_now, 'expires_at', v_new_expires_at, 'overlap_active', v_keep_previous
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION secrets.record_rotation_failure(p_name text, p_error_class text, p_error_detail text)
 RETURNS audit.audit_events
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'secrets', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row     secrets.managed_secrets;
  v_audit   audit.audit_events;
  v_found   boolean := false;
BEGIN
  SELECT * INTO v_row FROM secrets.managed_secrets WHERE secret_name = p_name;
  IF FOUND THEN
    v_found := true;
    IF v_row.status NOT IN ('DESTROYED','RETIRED') THEN
      UPDATE secrets.managed_secrets
         SET status            = 'STALE_SUSPECT',
             stale_detected_at = clock_timestamp(),
             last_stale_reason = format('rotation failed: %s', p_error_class)
       WHERE secret_id = v_row.secret_id;
    END IF;
  END IF;

  v_audit := audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'SECRET_ROTATION_FAILED',
    p_subject_type => 'SECRET'::audit.subject_type_enum,
    p_subject_id   => CASE WHEN v_found THEN v_row.secret_id ELSE NULL END,
    p_actor_system => 'secrets.record_rotation_failure',
    p_reason       => format('rotation of %s failed: %s', p_name, p_error_class),
    p_after_state  => jsonb_build_object('secret_name', p_name, 'error_class', p_error_class, 'error_detail', p_error_detail)
  );
  RETURN v_audit;
END;
$function$
;

CREATE OR REPLACE FUNCTION secrets.flag_stale(p_name text, p_detection_reason text)
 RETURNS secrets.managed_secrets
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'secrets', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row secrets.managed_secrets;
BEGIN
  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN
    RAISE EXCEPTION 'flag_stale: name is required' USING ERRCODE = '22000'; END IF;
  IF p_detection_reason IS NULL OR length(btrim(p_detection_reason)) = 0 THEN
    RAISE EXCEPTION 'flag_stale: detection_reason is required' USING ERRCODE = '22000'; END IF;

  SELECT * INTO v_row FROM secrets.managed_secrets WHERE secret_name = p_name FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'flag_stale: secret % not found', p_name USING ERRCODE = 'P0002'; END IF;
  IF v_row.status = 'DESTROYED' THEN
    RAISE EXCEPTION 'flag_stale: secret % is DESTROYED', p_name USING ERRCODE = '23514'; END IF;

  UPDATE secrets.managed_secrets
     SET status            = 'STALE_SUSPECT',
         stale_detected_at = clock_timestamp(),
         last_stale_reason = p_detection_reason
   WHERE secret_id = v_row.secret_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'SECRET_STALE_DETECTED',
    p_subject_type => 'SECRET'::audit.subject_type_enum,
    p_subject_id   => v_row.secret_id,
    p_actor_system => 'secrets.flag_stale',
    p_reason       => format('secret %s flagged STALE_SUSPECT: %s', p_name, p_detection_reason),
    p_after_state  => jsonb_build_object(
      'secret_name', p_name, 'category', v_row.category,
      'detection_reason', p_detection_reason, 'stale_detected_at', v_row.stale_detected_at
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.record_backup_started(p_source backups.backup_source_enum, p_source_name text, p_period_start timestamp with time zone, p_period_end timestamp with time zone, p_encryption_key_id uuid)
 RETURNS backups.backup_records
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'vault', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row     backups.backup_records;
  v_key_ok  boolean;
BEGIN
  IF p_source IS NULL THEN RAISE EXCEPTION 'record_backup_started: source required' USING ERRCODE='22000'; END IF;
  IF p_source_name IS NULL OR length(btrim(p_source_name)) = 0 THEN RAISE EXCEPTION 'record_backup_started: source_name required' USING ERRCODE='22000'; END IF;
  IF p_period_start IS NULL OR p_period_end IS NULL OR p_period_end <= p_period_start THEN
    RAISE EXCEPTION 'record_backup_started: invalid period (% .. %)', p_period_start, p_period_end USING ERRCODE='22000';
  END IF;
  IF p_encryption_key_id IS NULL THEN RAISE EXCEPTION 'record_backup_started: encryption_key_id required' USING ERRCODE='22000'; END IF;

  SELECT EXISTS (SELECT 1 FROM vault.secrets WHERE id = p_encryption_key_id) INTO v_key_ok;
  IF NOT v_key_ok THEN
    RAISE EXCEPTION 'record_backup_started: encryption_key_id % not found in vault.secrets', p_encryption_key_id USING ERRCODE='P0002';
  END IF;

  INSERT INTO backups.backup_records (source, source_name, period_start, period_end, encryption_key_id, status)
  VALUES (p_source, p_source_name, p_period_start, p_period_end, p_encryption_key_id, 'STARTED')
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'BACKUP_STARTED',
    p_subject_type => 'BACKUP'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.record_backup_started',
    p_reason       => format('%s backup of %s started for period %s .. %s', p_source, p_source_name, p_period_start, p_period_end),
    p_after_state  => jsonb_build_object(
      'backup_id', v_row.id,
      'source', p_source, 'source_name', p_source_name,
      'period_start', p_period_start, 'period_end', p_period_end,
      'encryption_key_id', p_encryption_key_id
    )
  );

  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION secrets.list_due_for_rotation()
 RETURNS SETOF secrets.managed_secrets
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'secrets', 'pg_temp'
AS $function$
  SELECT * FROM secrets.managed_secrets
   WHERE status = 'ACTIVE' AND expires_at <= now()
   ORDER BY expires_at ASC;
$function$
;

CREATE OR REPLACE FUNCTION backups.record_backup_failed(p_backup_id uuid, p_failure_reason text)
 RETURNS backups.backup_records
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row backups.backup_records;
BEGIN
  IF p_backup_id IS NULL THEN RAISE EXCEPTION 'record_backup_failed: backup_id required' USING ERRCODE='22000'; END IF;
  IF p_failure_reason IS NULL OR length(btrim(p_failure_reason)) = 0 THEN
    RAISE EXCEPTION 'record_backup_failed: failure_reason required' USING ERRCODE='22000';
  END IF;

  SELECT * INTO v_row FROM backups.backup_records WHERE id = p_backup_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_backup_failed: backup % not found', p_backup_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'STARTED' THEN
    RAISE EXCEPTION 'record_backup_failed: backup % not in STARTED (got %)', p_backup_id, v_row.status USING ERRCODE='23514';
  END IF;

  UPDATE backups.backup_records
     SET status         = 'FAILED',
         failed_at      = clock_timestamp(),
         failure_reason = p_failure_reason
   WHERE id = p_backup_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'BACKUP_FAILED',
    p_subject_type => 'BACKUP'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.record_backup_failed',
    p_reason       => format('backup %s failed: %s', p_backup_id, p_failure_reason),
    p_after_state  => jsonb_build_object('backup_id', v_row.id, 'failure_reason', p_failure_reason)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.report_replication_lag(p_source_key text, p_source_region text, p_replica_region text, p_lag_seconds integer, p_threshold_seconds integer)
 RETURNS backups.replication_status
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row    backups.replication_status;
  v_status backups.replication_lag_status_enum;
BEGIN
  IF p_source_key IS NULL OR length(btrim(p_source_key)) = 0 THEN
    RAISE EXCEPTION 'report_replication_lag: source_key required' USING ERRCODE='22000'; END IF;
  IF p_source_region IS NULL OR p_replica_region IS NULL OR p_source_region = p_replica_region THEN
    RAISE EXCEPTION 'report_replication_lag: source/replica regions must differ' USING ERRCODE='22000'; END IF;
  IF p_lag_seconds IS NULL OR p_lag_seconds < 0 THEN
    RAISE EXCEPTION 'report_replication_lag: lag_seconds >= 0 required' USING ERRCODE='22000'; END IF;
  IF p_threshold_seconds IS NULL OR p_threshold_seconds <= 0 THEN
    RAISE EXCEPTION 'report_replication_lag: threshold_seconds > 0 required' USING ERRCODE='22000'; END IF;

  v_status := CASE WHEN p_lag_seconds > p_threshold_seconds THEN 'EXCEEDED' ELSE 'OK' END;

  INSERT INTO backups.replication_status (source_key, source_region, replica_region, lag_seconds, threshold_seconds, lag_status, last_observed_at)
  VALUES (p_source_key, p_source_region, p_replica_region, p_lag_seconds, p_threshold_seconds, v_status, clock_timestamp())
  ON CONFLICT (source_key) DO UPDATE SET
    source_region     = EXCLUDED.source_region,
    replica_region    = EXCLUDED.replica_region,
    lag_seconds       = EXCLUDED.lag_seconds,
    threshold_seconds = EXCLUDED.threshold_seconds,
    lag_status        = EXCLUDED.lag_status,
    last_observed_at  = EXCLUDED.last_observed_at
  RETURNING * INTO v_row;

  IF v_status = 'EXCEEDED' THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'BACKUP_REPLICATION_LAG_EXCEEDED',
      p_subject_type => 'BACKUP'::audit.subject_type_enum,
      p_actor_system => 'backups.report_replication_lag',
      p_reason       => format('replication lag %ss exceeds threshold %ss for %s', p_lag_seconds, p_threshold_seconds, p_source_key),
      p_after_state  => jsonb_build_object(
        'source_key', p_source_key, 'source_region', p_source_region, 'replica_region', p_replica_region,
        'lag_seconds', p_lag_seconds, 'threshold_seconds', p_threshold_seconds, 'alert', 'WARNING'
      )
    );
  END IF;
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.record_identity_verified(p_request_id uuid)
 RETURNS gdpr.data_subject_requests
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'record_identity_verified: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_identity_verified: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'RECEIVED' THEN
    RAISE EXCEPTION 'record_identity_verified: % not in RECEIVED (got %)', p_request_id, v_row.status USING ERRCODE='23514';
  END IF;
  UPDATE gdpr.data_subject_requests SET status = 'IN_PROGRESS', identity_verified_at = clock_timestamp()
   WHERE id = p_request_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_REQUEST_IDENTITY_VERIFIED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.record_identity_verified',
    p_reason => format('identity verified for request %s', p_request_id),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'identity_verified_at', v_row.identity_verified_at)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.get_backup_decryption_key(p_backup_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'vault', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row    backups.backup_records;
  v_value  text;
BEGIN
  IF p_backup_id IS NULL THEN
    RAISE EXCEPTION 'get_backup_decryption_key: backup_id required' USING ERRCODE='22000';
  END IF;
  SELECT * INTO v_row FROM backups.backup_records WHERE id = p_backup_id;
  IF NOT FOUND THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'SECRET_ACCESS_DENIED',
      p_subject_type => 'BACKUP'::audit.subject_type_enum,
      p_actor_system => 'backups.get_backup_decryption_key',
      p_reason       => format('backup %s not found', p_backup_id),
      p_after_state  => jsonb_build_object('backup_id', p_backup_id, 'reason_code', 'BACKUP_NOT_FOUND')
    );
    RETURN NULL;
  END IF;

  BEGIN
    SELECT decrypted_secret INTO v_value FROM vault.decrypted_secrets WHERE id = v_row.encryption_key_id;
  EXCEPTION WHEN OTHERS THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'SECRET_ACCESS_FAILED',
      p_subject_type => 'BACKUP'::audit.subject_type_enum,
      p_subject_id   => v_row.id,
      p_actor_system => 'backups.get_backup_decryption_key',
      p_reason       => format('vault read failed for backup %s', p_backup_id),
      p_after_state  => jsonb_build_object('backup_id', p_backup_id, 'encryption_key_id', v_row.encryption_key_id, 'reason_code', 'VAULT_READ_FAILED')
    );
    RETURN NULL;
  END;

  IF v_value IS NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'SECRET_ACCESS_DENIED',
      p_subject_type => 'BACKUP'::audit.subject_type_enum,
      p_subject_id   => v_row.id,
      p_actor_system => 'backups.get_backup_decryption_key',
      p_reason       => format('vault row missing for backup %s', p_backup_id),
      p_after_state  => jsonb_build_object('backup_id', p_backup_id, 'encryption_key_id', v_row.encryption_key_id, 'reason_code', 'VAULT_ROW_MISSING')
    );
    RETURN NULL;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'SECRET_ACCESSED',
    p_subject_type => 'BACKUP'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.get_backup_decryption_key',
    p_reason       => format('backup %s decryption key fetched', p_backup_id),
    p_after_state  => jsonb_build_object('backup_id', p_backup_id, 'encryption_key_id', v_row.encryption_key_id)
  );
  RETURN v_value;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.record_export_generated(p_request_id uuid, p_export_location text, p_export_bundle_hash text)
 RETURNS gdpr.data_subject_requests
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'record_export_generated: id required' USING ERRCODE='22000'; END IF;
  IF p_export_location IS NULL OR length(btrim(p_export_location)) = 0 THEN
    RAISE EXCEPTION 'record_export_generated: export_location required' USING ERRCODE='22000'; END IF;
  IF p_export_bundle_hash IS NULL OR p_export_bundle_hash !~ '^[0-9a-f]{64}$' THEN
    RAISE EXCEPTION 'record_export_generated: bundle_hash must be 64-hex' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_export_generated: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.request_type <> 'ACCESS' THEN
    RAISE EXCEPTION 'record_export_generated: only ACCESS (got %)', v_row.request_type USING ERRCODE='23514'; END IF;
  IF v_row.status <> 'IN_PROGRESS' THEN
    RAISE EXCEPTION 'record_export_generated: % not in IN_PROGRESS (got %)', p_request_id, v_row.status USING ERRCODE='23514'; END IF;

  UPDATE gdpr.data_subject_requests
     SET status='FULFILLED', export_location=p_export_location, export_bundle_hash=p_export_bundle_hash, fulfilled_at=clock_timestamp()
   WHERE id = p_request_id RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_EXPORT_GENERATED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.record_export_generated',
    p_reason => format('export generated for request %s', p_request_id),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'export_location', p_export_location, 'export_bundle_hash', p_export_bundle_hash)
  );
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_REQUEST_FULFILLED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.record_export_generated',
    p_reason => format('ACCESS request %s fulfilled', p_request_id),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'fulfilled_at', v_row.fulfilled_at)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.initiate_restore(p_backup_record_id uuid, p_initiated_by_user_id uuid, p_second_authoriser_user_id uuid, p_restore_type backups.restore_type_enum, p_quarantine_namespace text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'auth_runtime', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_backup     backups.backup_records;
  v_window     interval;
  v_now        timestamptz := clock_timestamp();
  v_init_mfa   timestamptz;
  v_sec_mfa    timestamptz;
  v_init_owner boolean;
  v_sec_owner  boolean;
  v_row        backups.restore_runs;
  v_denial     text;
BEGIN
  IF p_backup_record_id IS NULL THEN RAISE EXCEPTION 'initiate_restore: backup_record_id required' USING ERRCODE='22000'; END IF;
  IF p_initiated_by_user_id IS NULL OR p_second_authoriser_user_id IS NULL THEN
    RAISE EXCEPTION 'initiate_restore: both user ids required' USING ERRCODE='22000'; END IF;
  IF p_initiated_by_user_id = p_second_authoriser_user_id THEN
    RAISE EXCEPTION 'initiate_restore: initiator and second_authoriser must differ' USING ERRCODE='22000'; END IF;
  IF p_restore_type IS NULL THEN RAISE EXCEPTION 'initiate_restore: restore_type required' USING ERRCODE='22000'; END IF;
  IF p_quarantine_namespace IS NULL OR length(btrim(p_quarantine_namespace)) = 0 THEN
    RAISE EXCEPTION 'initiate_restore: quarantine_namespace required' USING ERRCODE='22000'; END IF;

  SELECT * INTO v_backup FROM backups.backup_records WHERE id = p_backup_record_id;
  IF NOT FOUND THEN v_denial := 'BACKUP_NOT_FOUND';
  ELSIF v_backup.status <> 'COMPLETED' THEN v_denial := 'BACKUP_NOT_COMPLETED';
  END IF;

  IF v_denial IS NULL THEN
    SELECT step_up_window INTO v_window FROM auth_runtime.sensitive_surfaces WHERE surface = 'PRODUCTION_RESTORE';
    IF v_window IS NULL THEN v_window := '60 seconds'::interval; END IF;

    SELECT EXISTS (
      SELECT 1 FROM public.business_user_roles
       WHERE user_id = p_initiated_by_user_id AND status = 'ACTIVE' AND role = 'OWNER'
    ) INTO v_init_owner;
    SELECT mfa_recent_at INTO v_init_mfa FROM public.users WHERE id = p_initiated_by_user_id;

    SELECT EXISTS (
      SELECT 1 FROM public.business_user_roles
       WHERE user_id = p_second_authoriser_user_id AND status = 'ACTIVE' AND role = 'OWNER'
    ) INTO v_sec_owner;
    SELECT mfa_recent_at INTO v_sec_mfa FROM public.users WHERE id = p_second_authoriser_user_id;

    IF NOT v_init_owner THEN v_denial := 'INITIATOR_NOT_OWNER';
    ELSIF NOT v_sec_owner THEN v_denial := 'SECOND_AUTHORISER_NOT_OWNER';
    ELSIF v_init_mfa IS NULL OR (v_now - v_init_mfa) > v_window THEN v_denial := 'INITIATOR_MFA_STALE';
    ELSIF v_sec_mfa IS NULL OR (v_now - v_sec_mfa) > v_window THEN v_denial := 'SECOND_AUTHORISER_MFA_STALE';
    END IF;
  END IF;

  IF v_denial IS NOT NULL THEN
    PERFORM audit.emit_audit(
      p_actor_kind     => 'USER'::audit.actor_kind_enum,
      p_action         => 'RESTORE_REJECTED',
      p_subject_type   => 'RESTORE_RUN'::audit.subject_type_enum,
      p_actor_user_id  => p_initiated_by_user_id,
      p_reason         => format('restore initiation rejected: %s', v_denial),
      p_after_state    => jsonb_build_object(
        'backup_record_id', p_backup_record_id,
        'initiated_by',     p_initiated_by_user_id,
        'second_authoriser', p_second_authoriser_user_id,
        'restore_type',     p_restore_type,
        'denial_reason',    v_denial,
        'phase',            'initiation'
      )
    );
    RETURN jsonb_build_object(
      'success', false, 'denial_reason', v_denial,
      'backup_record_id', p_backup_record_id,
      'message', format('restore initiation rejected: %s', v_denial)
    );
  END IF;

  INSERT INTO backups.restore_runs (
    restore_type, backup_record_id, initiated_by_user_id, second_authoriser_user_id,
    quarantine_namespace, status, initiated_at
  ) VALUES (
    p_restore_type, p_backup_record_id, p_initiated_by_user_id, p_second_authoriser_user_id,
    p_quarantine_namespace, 'INITIATED', v_now
  )
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'USER'::audit.actor_kind_enum,
    p_action         => 'RESTORE_INITIATED',
    p_subject_type   => 'RESTORE_RUN'::audit.subject_type_enum,
    p_subject_id     => v_row.id,
    p_actor_user_id  => p_initiated_by_user_id,
    p_reason         => format('restore %s initiated (%s)', v_row.id, p_restore_type),
    p_after_state    => jsonb_build_object(
      'restore_run_id', v_row.id,
      'backup_record_id', p_backup_record_id,
      'initiated_by',     p_initiated_by_user_id,
      'second_authoriser', p_second_authoriser_user_id,
      'restore_type',     p_restore_type,
      'quarantine_namespace', p_quarantine_namespace
    )
  );

  RETURN jsonb_build_object(
    'success', true,
    'restore_run_id', v_row.id,
    'status', v_row.status,
    'quarantine_namespace', v_row.quarantine_namespace
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.record_quarantine_loaded(p_restore_run_id uuid)
 RETURNS backups.restore_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row backups.restore_runs;
BEGIN
  IF p_restore_run_id IS NULL THEN RAISE EXCEPTION 'record_quarantine_loaded: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM backups.restore_runs WHERE id = p_restore_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_quarantine_loaded: % not found', p_restore_run_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'INITIATED' THEN
    RAISE EXCEPTION 'record_quarantine_loaded: % not in INITIATED (got %)', p_restore_run_id, v_row.status USING ERRCODE='23514';
  END IF;

  UPDATE backups.restore_runs
     SET status = 'QUARANTINE_LOADED', quarantine_loaded_at = clock_timestamp()
   WHERE id = p_restore_run_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'RESTORE_QUARANTINE_LOADED',
    p_subject_type => 'RESTORE_RUN'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.record_quarantine_loaded',
    p_reason       => format('restore %s loaded into quarantine namespace %s', v_row.id, v_row.quarantine_namespace),
    p_after_state  => jsonb_build_object('restore_run_id', v_row.id, 'quarantine_namespace', v_row.quarantine_namespace)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.verify_restored_data(p_restore_run_id uuid, p_chain_id uuid, p_archive_hashes_verified boolean, p_archive_details jsonb DEFAULT NULL::jsonb)
 RETURNS backups.restore_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row          backups.restore_runs;
  v_chain_result jsonb;
  v_chain_ok     boolean;
  v_overall_ok   boolean;
  v_now          timestamptz := clock_timestamp();
  v_new_status   backups.restore_status_enum;
BEGIN
  IF p_restore_run_id IS NULL THEN RAISE EXCEPTION 'verify_restored_data: id required' USING ERRCODE='22000'; END IF;
  IF p_chain_id IS NULL THEN RAISE EXCEPTION 'verify_restored_data: chain_id required' USING ERRCODE='22000'; END IF;
  IF p_archive_hashes_verified IS NULL THEN RAISE EXCEPTION 'verify_restored_data: archive_hashes_verified required' USING ERRCODE='22000'; END IF;

  SELECT * INTO v_row FROM backups.restore_runs WHERE id = p_restore_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'verify_restored_data: % not found', p_restore_run_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'QUARANTINE_LOADED' THEN
    RAISE EXCEPTION 'verify_restored_data: % must be in QUARANTINE_LOADED (got %)', p_restore_run_id, v_row.status USING ERRCODE='23514';
  END IF;

  v_chain_result := audit.verify_restored_chain(p_chain_id);
  v_chain_ok     := (v_chain_result->>'verified')::boolean;
  v_overall_ok   := v_chain_ok AND p_archive_hashes_verified;
  v_new_status   := (CASE WHEN v_overall_ok THEN 'VERIFICATION_PASSED' ELSE 'VERIFICATION_FAILED' END)::backups.restore_status_enum;

  UPDATE backups.restore_runs
     SET status                  = v_new_status,
         audit_chain_verified    = v_chain_ok,
         archive_hashes_verified = p_archive_hashes_verified,
         verification_details    = jsonb_build_object(
            'audit_chain', v_chain_result,
            'archive', COALESCE(p_archive_details, jsonb_build_object('verified', p_archive_hashes_verified))
         ),
         verification_at         = v_now
   WHERE id = p_restore_run_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => CASE WHEN v_overall_ok THEN 'RESTORE_VERIFICATION_PASSED' ELSE 'RESTORE_VERIFICATION_FAILED' END,
    p_subject_type => 'RESTORE_RUN'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.verify_restored_data',
    p_reason       => format('restore %s verification %s', v_row.id, CASE WHEN v_overall_ok THEN 'PASSED' ELSE 'FAILED' END),
    p_after_state  => jsonb_build_object(
      'restore_run_id', v_row.id,
      'audit_chain_verified', v_chain_ok,
      'archive_hashes_verified', p_archive_hashes_verified,
      'verified', v_overall_ok
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.promote_restore_to_production(p_restore_run_id uuid)
 RETURNS backups.restore_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row backups.restore_runs;
BEGIN
  IF p_restore_run_id IS NULL THEN RAISE EXCEPTION 'promote_restore: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM backups.restore_runs WHERE id = p_restore_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'promote_restore: % not found', p_restore_run_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'VERIFICATION_PASSED' THEN
    RAISE EXCEPTION 'promote_restore: % must be in VERIFICATION_PASSED (got %)', p_restore_run_id, v_row.status USING ERRCODE='23514';
  END IF;

  UPDATE backups.restore_runs
     SET status = 'PROMOTED_TO_PRODUCTION', promoted_at = clock_timestamp()
   WHERE id = p_restore_run_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind     => 'USER'::audit.actor_kind_enum,
    p_action         => 'RESTORE_PROMOTED_TO_PRODUCTION',
    p_subject_type   => 'RESTORE_RUN'::audit.subject_type_enum,
    p_subject_id     => v_row.id,
    p_actor_user_id  => v_row.initiated_by_user_id,
    p_reason         => format('restore %s promoted to production', v_row.id),
    p_after_state    => jsonb_build_object(
      'restore_run_id', v_row.id, 'restore_type', v_row.restore_type, 'promoted_at', v_row.promoted_at, 'alert', 'WARNING'
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.record_export_downloaded(p_request_id uuid, p_downloaded_by_user_id uuid)
 RETURNS audit.audit_events
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests; v_audit audit.audit_events;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'record_export_downloaded: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'record_export_downloaded: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'FULFILLED' OR v_row.request_type <> 'ACCESS' THEN
    RAISE EXCEPTION 'record_export_downloaded: % not a fulfilled ACCESS', p_request_id USING ERRCODE='23514'; END IF;
  v_audit := audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_EXPORT_DOWNLOADED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_user_id => p_downloaded_by_user_id,
    p_reason => format('export download for request %s', p_request_id),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'downloaded_by', p_downloaded_by_user_id, 'export_bundle_hash', v_row.export_bundle_hash)
  );
  RETURN v_audit;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.reject_restore(p_restore_run_id uuid, p_reason text)
 RETURNS backups.restore_runs
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row backups.restore_runs;
BEGIN
  IF p_restore_run_id IS NULL THEN RAISE EXCEPTION 'reject_restore: id required' USING ERRCODE='22000'; END IF;
  IF p_reason IS NULL OR length(btrim(p_reason)) = 0 THEN RAISE EXCEPTION 'reject_restore: reason required' USING ERRCODE='22000'; END IF;

  SELECT * INTO v_row FROM backups.restore_runs WHERE id = p_restore_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'reject_restore: % not found', p_restore_run_id USING ERRCODE='P0002'; END IF;
  IF v_row.status IN ('PROMOTED_TO_PRODUCTION','REJECTED') THEN
    RAISE EXCEPTION 'reject_restore: % already in terminal status %', p_restore_run_id, v_row.status USING ERRCODE='23514';
  END IF;

  UPDATE backups.restore_runs
     SET status = 'REJECTED', rejected_at = clock_timestamp(), rejection_reason = p_reason
   WHERE id = p_restore_run_id
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => 'RESTORE_REJECTED',
    p_subject_type => 'RESTORE_RUN'::audit.subject_type_enum,
    p_subject_id   => v_row.id,
    p_actor_system => 'backups.reject_restore',
    p_reason       => format('restore %s rejected: %s', v_row.id, p_reason),
    p_after_state  => jsonb_build_object('restore_run_id', v_row.id, 'rejection_reason', p_reason)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION backups.record_restore_test_outcome(p_test_type backups.restore_type_enum, p_backup_record_id uuid, p_passed boolean, p_details jsonb DEFAULT '{}'::jsonb)
 RETURNS audit.audit_events
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'backups', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_audit  audit.audit_events;
  v_action text;
BEGIN
  IF p_test_type IS NULL THEN RAISE EXCEPTION 'record_restore_test_outcome: test_type required' USING ERRCODE='22000'; END IF;
  IF p_passed IS NULL THEN RAISE EXCEPTION 'record_restore_test_outcome: passed required' USING ERRCODE='22000'; END IF;
  IF p_test_type NOT IN ('WEEKLY_TEST','MONTHLY_DR_DRILL') THEN
    RAISE EXCEPTION 'record_restore_test_outcome: test_type must be WEEKLY_TEST or MONTHLY_DR_DRILL (got %)', p_test_type USING ERRCODE='22000'; END IF;

  v_action := CASE WHEN p_passed THEN 'RESTORE_TEST_PASSED' ELSE 'RESTORE_TEST_FAILED' END;
  v_audit := audit.emit_audit(
    p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
    p_action       => v_action,
    p_subject_type => 'BACKUP'::audit.subject_type_enum,
    p_subject_id   => p_backup_record_id,
    p_actor_system => 'backups.record_restore_test_outcome',
    p_reason       => format('%s %s', p_test_type, CASE WHEN p_passed THEN 'PASSED' ELSE 'FAILED' END),
    p_after_state  => jsonb_build_object(
      'test_type', p_test_type, 'backup_record_id', p_backup_record_id, 'passed', p_passed, 'details', p_details
    )
  );
  IF p_test_type = 'MONTHLY_DR_DRILL' THEN
    PERFORM audit.emit_audit(
      p_actor_kind   => 'SYSTEM'::audit.actor_kind_enum,
      p_action       => 'DR_DRILL_COMPLETED',
      p_subject_type => 'BACKUP'::audit.subject_type_enum,
      p_subject_id   => p_backup_record_id,
      p_actor_system => 'backups.record_restore_test_outcome',
      p_reason       => format('monthly DR drill completed: %s', CASE WHEN p_passed THEN 'PASSED' ELSE 'FAILED' END),
      p_after_state  => jsonb_build_object('backup_record_id', p_backup_record_id, 'passed', p_passed, 'details', p_details)
    );
  END IF;
  RETURN v_audit;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr._registry_key_value()
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'gdpr', 'secrets', 'public', 'pg_temp'
AS $function$
DECLARE v_key text;
BEGIN
  v_key := secrets.get_secret('pseudonym_registry_key');
  IF v_key IS NULL THEN
    RAISE EXCEPTION '_registry_key_value: pseudonym_registry_key not available' USING ERRCODE='P0002';
  END IF;
  RETURN v_key;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.submit_request(p_request_type gdpr.request_type_enum, p_subject_user_id uuid, p_subject_business_id uuid, p_requester_user_id uuid)
 RETURNS gdpr.data_subject_requests
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row gdpr.data_subject_requests;
  v_org_id uuid;
BEGIN
  IF p_request_type IS NULL THEN RAISE EXCEPTION 'submit_request: request_type required' USING ERRCODE='22000'; END IF;
  IF p_requester_user_id IS NULL THEN RAISE EXCEPTION 'submit_request: requester_user_id required' USING ERRCODE='22000'; END IF;
  IF (p_subject_user_id IS NULL) = (p_subject_business_id IS NULL) THEN
    RAISE EXCEPTION 'submit_request: exactly one of subject_user_id / subject_business_id must be set' USING ERRCODE='22000';
  END IF;

  INSERT INTO gdpr.data_subject_requests (request_type, subject_user_id, subject_business_id, requester_user_id, status, submitted_at)
  VALUES (p_request_type, p_subject_user_id, p_subject_business_id, p_requester_user_id, 'RECEIVED', clock_timestamp())
  RETURNING * INTO v_row;

  IF p_subject_business_id IS NOT NULL THEN
    SELECT organization_id INTO v_org_id FROM public.business_entities WHERE id = p_subject_business_id;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_REQUEST_RECEIVED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_user_id => p_requester_user_id, p_organization_id => v_org_id, p_business_id => p_subject_business_id,
    p_reason => format('GDPR %s request received', p_request_type),
    p_after_state => jsonb_build_object(
      'request_id', v_row.id, 'request_type', p_request_type,
      'subject_user_id', p_subject_user_id, 'subject_business_id', p_subject_business_id,
      'requester_user_id', p_requester_user_id
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.defer_for_legal_hold(p_request_id uuid, p_reason text)
 RETURNS gdpr.data_subject_requests
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'defer_for_legal_hold: id required' USING ERRCODE='22000'; END IF;
  IF p_reason IS NULL OR length(btrim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'defer_for_legal_hold: reason required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'defer_for_legal_hold: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.status IN ('FULFILLED','REJECTED') THEN
    RAISE EXCEPTION 'defer_for_legal_hold: % already terminal %', p_request_id, v_row.status USING ERRCODE='23514'; END IF;
  UPDATE gdpr.data_subject_requests SET status='DEFERRED_LEGAL_HOLD', deferral_reason=p_reason
   WHERE id = p_request_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_REQUEST_DEFERRED_LEGAL_HOLD',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.defer_for_legal_hold',
    p_reason => format('request %s deferred (legal hold): %s', p_request_id, p_reason),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'deferral_reason', p_reason)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.pseudonymize_subject(p_request_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'secrets', 'archive', 'audit', 'extensions', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row             gdpr.data_subject_requests;
  v_user            public.users;
  v_registry_key    text;
  v_pseudo_email    text;
  v_pseudo_name     text;
  v_orig_email_ct   bytea;
  v_orig_name_ct    bytea;
  v_fields          int := 0;
  v_biz             record;
  v_hold_status     jsonb;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'pseudonymize_subject: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'pseudonymize_subject: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.request_type <> 'ERASURE' THEN
    RAISE EXCEPTION 'pseudonymize_subject: only ERASURE (got %)', v_row.request_type USING ERRCODE='23514'; END IF;
  IF v_row.status NOT IN ('RECEIVED','IN_PROGRESS') THEN
    RAISE EXCEPTION 'pseudonymize_subject: % must be RECEIVED or IN_PROGRESS (got %)', p_request_id, v_row.status USING ERRCODE='23514'; END IF;
  IF v_row.subject_user_id IS NULL THEN
    RAISE EXCEPTION 'pseudonymize_subject: business-subject erasure not yet implemented (MVP user-subject only)' USING ERRCODE='0A000'; END IF;

  FOR v_biz IN
    SELECT DISTINCT bur.business_id FROM public.business_user_roles bur
     WHERE bur.user_id = v_row.subject_user_id AND bur.status = 'ACTIVE'
  LOOP
    v_hold_status := archive.legal_hold_status(v_biz.business_id);
    IF (v_hold_status->>'on_hold')::boolean THEN
      PERFORM gdpr.defer_for_legal_hold(p_request_id,
        format('business %s under legal hold (hold_reasons: %s)', v_biz.business_id, v_hold_status->'hold_reasons'));
      RETURN jsonb_build_object(
        'success', false, 'denial_reason', 'LEGAL_HOLD',
        'request_id', p_request_id, 'business_id', v_biz.business_id,
        'message', format('erasure deferred — business %s under legal hold', v_biz.business_id)
      );
    END IF;
  END LOOP;

  SELECT * INTO v_user FROM public.users WHERE id = v_row.subject_user_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'pseudonymize_subject: subject user % not found', v_row.subject_user_id USING ERRCODE='P0002'; END IF;
  v_registry_key := gdpr._registry_key_value();

  v_pseudo_email := 'pseudo_' || substr(public.hash_text_sha256(p_request_id::text || ':email'), 1, 16) || '@erased.invalid';
  v_pseudo_name  := 'Pseudonymous Subject ' || substr(public.hash_text_sha256(p_request_id::text || ':name'), 1, 8);

  IF v_user.email IS NOT NULL AND v_user.email <> v_pseudo_email THEN
    v_orig_email_ct := extensions.pgp_sym_encrypt_bytea(convert_to(v_user.email, 'UTF8'), v_registry_key);
    INSERT INTO gdpr.pseudonym_registry (request_id, identifier_kind, original_ciphertext, pseudonym)
    VALUES (p_request_id, 'email', v_orig_email_ct, v_pseudo_email)
    ON CONFLICT (request_id, identifier_kind) DO NOTHING;
    UPDATE public.users SET email = v_pseudo_email WHERE id = v_user.id;
    v_fields := v_fields + 1;
  END IF;
  IF v_user.display_name IS NOT NULL AND v_user.display_name <> v_pseudo_name THEN
    v_orig_name_ct := extensions.pgp_sym_encrypt_bytea(convert_to(v_user.display_name, 'UTF8'), v_registry_key);
    INSERT INTO gdpr.pseudonym_registry (request_id, identifier_kind, original_ciphertext, pseudonym)
    VALUES (p_request_id, 'display_name', v_orig_name_ct, v_pseudo_name)
    ON CONFLICT (request_id, identifier_kind) DO NOTHING;
    UPDATE public.users SET display_name = v_pseudo_name WHERE id = v_user.id;
    v_fields := v_fields + 1;
  END IF;

  IF v_row.status = 'RECEIVED' THEN
    UPDATE gdpr.data_subject_requests SET status = 'IN_PROGRESS' WHERE id = p_request_id;
  END IF;

  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_PSEUDONYMIZED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.pseudonymize_subject',
    p_reason => format('subject pseudonymized for request %s (%s fields)', p_request_id, v_fields),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'subject_user_id', v_row.subject_user_id, 'fields_pseudonymized', v_fields)
  );
  RETURN jsonb_build_object('success', true, 'request_id', v_row.id, 'fields_pseudonymized', v_fields);
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.schedule_anonymization(p_request_id uuid)
 RETURNS gdpr.data_subject_requests
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests; v_scheduled_at timestamptz;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'schedule_anonymization: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'schedule_anonymization: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.request_type <> 'ERASURE' THEN
    RAISE EXCEPTION 'schedule_anonymization: only ERASURE (got %)', v_row.request_type USING ERRCODE='23514'; END IF;
  IF v_row.status NOT IN ('IN_PROGRESS','DEFERRED_LEGAL_HOLD','DEFERRED_RETENTION') THEN
    RAISE EXCEPTION 'schedule_anonymization: % must be IN_PROGRESS/DEFERRED_* (got %)', p_request_id, v_row.status USING ERRCODE='23514'; END IF;
  v_scheduled_at := clock_timestamp() + interval '6 years';
  UPDATE gdpr.data_subject_requests SET scheduled_anonymization_at = v_scheduled_at
   WHERE id = p_request_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_ANONYMIZATION_SCHEDULED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.schedule_anonymization',
    p_reason => format('anonymization scheduled for request %s at %s', p_request_id, v_scheduled_at),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'scheduled_anonymization_at', v_scheduled_at)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.reject_request(p_request_id uuid, p_reason text)
 RETURNS gdpr.data_subject_requests
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'reject_request: id required' USING ERRCODE='22000'; END IF;
  IF p_reason IS NULL OR length(btrim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'reject_request: reason required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'reject_request: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.status = 'FULFILLED' THEN
    RAISE EXCEPTION 'reject_request: % already FULFILLED', p_request_id USING ERRCODE='23514'; END IF;
  UPDATE gdpr.data_subject_requests SET status='REJECTED', rejection_reason=p_reason
   WHERE id = p_request_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_REQUEST_REJECTED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.reject_request',
    p_reason => format('request %s rejected: %s', p_request_id, p_reason),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'rejection_reason', p_reason)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.run_scheduled_anonymization(p_request_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'gdpr', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_row             gdpr.data_subject_requests;
  v_anonymized_rows int := 0;
  v_anon_marker     text := '[anonymized]';
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'run_scheduled_anonymization: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'run_scheduled_anonymization: % not found', p_request_id USING ERRCODE='P0002'; END IF;
  IF v_row.request_type <> 'ERASURE' THEN
    RAISE EXCEPTION 'run_scheduled_anonymization: only ERASURE (got %)', v_row.request_type USING ERRCODE='23514'; END IF;
  IF v_row.status NOT IN ('IN_PROGRESS','DEFERRED_RETENTION','DEFERRED_LEGAL_HOLD') THEN
    RAISE EXCEPTION 'run_scheduled_anonymization: % must be IN_PROGRESS or DEFERRED_* (got %)', p_request_id, v_row.status USING ERRCODE='23514'; END IF;
  IF v_row.subject_user_id IS NULL THEN
    RAISE EXCEPTION 'run_scheduled_anonymization: business-subject erasure not implemented' USING ERRCODE='0A000'; END IF;

  WITH updated AS (
    UPDATE public.users
       SET email        = v_anon_marker || '+' || substr(public.hash_text_sha256(p_request_id::text), 1, 8) || '@erased.invalid',
           display_name = v_anon_marker
     WHERE id = v_row.subject_user_id
    RETURNING 1
  )
  SELECT count(*) INTO v_anonymized_rows FROM updated;

  UPDATE gdpr.data_subject_requests SET status='FULFILLED', fulfilled_at=clock_timestamp()
   WHERE id = p_request_id RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_ANONYMIZED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.run_scheduled_anonymization',
    p_reason => format('subject anonymized for request %s (%s rows updated)', p_request_id, v_anonymized_rows),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'subject_user_id', v_row.subject_user_id, 'anonymized_rows', v_anonymized_rows)
  );
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'DATA_SUBJECT_REQUEST_FULFILLED',
    p_subject_type => 'DATA_SUBJECT_REQUEST'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'gdpr.run_scheduled_anonymization',
    p_reason => format('ERASURE request %s fulfilled', p_request_id),
    p_after_state => jsonb_build_object('request_id', v_row.id, 'fulfilled_at', v_row.fulfilled_at)
  );
  RETURN jsonb_build_object('success', true, 'request_id', v_row.id, 'anonymized_rows', v_anonymized_rows, 'fulfilled_at', v_row.fulfilled_at);
END;
$function$
;

CREATE OR REPLACE FUNCTION gdpr.get_request_status(p_request_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'gdpr', 'public', 'pg_temp'
AS $function$
DECLARE v_row gdpr.data_subject_requests;
BEGIN
  IF p_request_id IS NULL THEN RAISE EXCEPTION 'get_request_status: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM gdpr.data_subject_requests WHERE id = p_request_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('found', false, 'request_id', p_request_id); END IF;
  RETURN jsonb_build_object(
    'found', true, 'request_id', v_row.id, 'request_type', v_row.request_type, 'status', v_row.status,
    'subject_user_id', v_row.subject_user_id, 'subject_business_id', v_row.subject_business_id,
    'requester_user_id', v_row.requester_user_id, 'submitted_at', v_row.submitted_at,
    'identity_verified_at', v_row.identity_verified_at, 'fulfilled_at', v_row.fulfilled_at,
    'scheduled_anonymization_at', v_row.scheduled_anonymization_at,
    'deferral_reason', v_row.deferral_reason, 'rejection_reason', v_row.rejection_reason
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION alerts._route_hint(p_severity alerts.severity_enum)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'pg_temp'
AS $function$
  SELECT CASE WHEN p_severity = 'CRITICAL' THEN 'page_on_call'
              WHEN p_severity = 'HIGH'     THEN 'security_channel'
              WHEN p_severity = 'MEDIUM'   THEN 'daily_digest'
              ELSE 'daily_digest' END;
$function$
;

CREATE OR REPLACE FUNCTION alerts.fire_alert(p_rule_name text, p_subject_kind alerts.subject_kind_enum, p_subject_id uuid, p_subject_descriptor text, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS alerts.alerts
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'alerts', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE
  v_rule       alerts.alert_rules;
  v_existing   alerts.alerts;
  v_row        alerts.alerts;
  v_route      text;
BEGIN
  IF p_rule_name IS NULL OR length(btrim(p_rule_name)) = 0 THEN
    RAISE EXCEPTION 'fire_alert: rule_name required' USING ERRCODE='22000'; END IF;
  IF p_subject_kind IS NULL THEN RAISE EXCEPTION 'fire_alert: subject_kind required' USING ERRCODE='22000'; END IF;
  IF p_subject_kind = 'SYSTEM' AND p_subject_id IS NOT NULL THEN
    RAISE EXCEPTION 'fire_alert: SYSTEM subject must not have subject_id' USING ERRCODE='22000'; END IF;
  IF p_subject_kind <> 'SYSTEM' AND p_subject_id IS NULL THEN
    RAISE EXCEPTION 'fire_alert: % subject requires subject_id', p_subject_kind USING ERRCODE='22000'; END IF;

  SELECT * INTO v_rule FROM alerts.alert_rules WHERE name = p_rule_name;
  IF NOT FOUND THEN RAISE EXCEPTION 'fire_alert: rule % not found', p_rule_name USING ERRCODE='P0002'; END IF;
  IF NOT v_rule.enabled THEN RAISE EXCEPTION 'fire_alert: rule % is disabled', p_rule_name USING ERRCODE='42501'; END IF;

  v_route := alerts._route_hint(v_rule.severity);

  SELECT * INTO v_existing
    FROM alerts.alerts
   WHERE rule_id = v_rule.id
     AND subject_kind = p_subject_kind
     AND ((p_subject_id IS NULL AND subject_id IS NULL) OR subject_id = p_subject_id)
     AND status IN ('FIRED','ACKNOWLEDGED')
     AND fired_at > clock_timestamp() - v_rule.dedup_window
   ORDER BY fired_at DESC
   LIMIT 1
   FOR UPDATE;

  IF FOUND THEN
    UPDATE alerts.alerts
       SET dedup_count   = v_existing.dedup_count + 1,
           last_fired_at = clock_timestamp(),
           payload       = v_existing.payload || jsonb_build_object('last_event_payload', p_payload)
     WHERE id = v_existing.id
    RETURNING * INTO v_row;

    PERFORM audit.emit_audit(
      p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'SECURITY_ALERT_DEDUPLICATED',
      p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
      p_actor_system => 'alerts.fire_alert',
      p_reason => format('alert %s deduplicated (count now %s)', v_row.id, v_row.dedup_count),
      p_after_state => jsonb_build_object(
        'alert_id', v_row.id, 'rule_name', p_rule_name, 'severity', v_rule.severity,
        'dedup_count', v_row.dedup_count, 'subject_kind', p_subject_kind, 'subject_id', p_subject_id
      )
    );
    RETURN v_row;
  END IF;

  INSERT INTO alerts.alerts (rule_id, severity, subject_kind, subject_id, subject_descriptor, payload, status, fired_at, last_fired_at)
  VALUES (v_rule.id, v_rule.severity, p_subject_kind, p_subject_id, p_subject_descriptor,
          COALESCE(p_payload, '{}'::jsonb), 'FIRED', clock_timestamp(), clock_timestamp())
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'SECURITY_ALERT_FIRED',
    p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'alerts.fire_alert',
    p_reason => format('%s alert fired: %s (subject %s)', v_rule.severity, p_rule_name, COALESCE(p_subject_descriptor, p_subject_id::text, 'SYSTEM')),
    p_after_state => jsonb_build_object(
      'alert_id', v_row.id, 'rule_name', p_rule_name, 'rule_id', v_rule.id,
      'severity', v_rule.severity, 'subject_kind', p_subject_kind, 'subject_id', p_subject_id,
      'subject_descriptor', p_subject_descriptor, 'route', v_route, 'payload', p_payload
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_workflow_config(p_workflow_type workflow_type_enum, p_enabled_phases jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_errors           jsonb := '[]'::jsonb;
  v_enabled_names    text[];
  v_unknown          text[];
  v_missing_required text[];
BEGIN
  IF p_workflow_type IS NULL THEN
    RAISE EXCEPTION 'validate_workflow_config: workflow_type required' USING ERRCODE='22000';
  END IF;
  -- NULL enabled_phases is "all default" → always valid
  IF p_enabled_phases IS NULL THEN
    RETURN jsonb_build_object('valid', true, 'errors', '[]'::jsonb);
  END IF;
  IF jsonb_typeof(p_enabled_phases) <> 'array' THEN
    RETURN jsonb_build_object('valid', false, 'errors', jsonb_build_array(jsonb_build_object('code','NOT_ARRAY','message','enabled_phases must be a JSON array')));
  END IF;

  SELECT array_agg(value) INTO v_enabled_names
    FROM jsonb_array_elements_text(p_enabled_phases) AS t(value);
  v_enabled_names := COALESCE(v_enabled_names, ARRAY[]::text[]);

  -- (a) unknown phase names
  SELECT array_agg(name) INTO v_unknown FROM (
    SELECT n.name FROM unnest(v_enabled_names) AS n(name)
     WHERE NOT EXISTS (
       SELECT 1 FROM public.workflow_phase_definitions wpd
        WHERE wpd.workflow_type = p_workflow_type AND wpd.phase_name = n.name
     )
  ) sub;
  IF v_unknown IS NOT NULL THEN
    v_errors := v_errors || jsonb_build_object(
      'code', 'UNKNOWN_PHASE',
      'message', format('phases not in registry for %s: %s', p_workflow_type, array_to_string(v_unknown, ', ')),
      'phases', to_jsonb(v_unknown)
    );
  END IF;

  -- (b) non-optional phases that are NOT in the enabled list
  SELECT array_agg(wpd.phase_name) INTO v_missing_required
    FROM public.workflow_phase_definitions wpd
   WHERE wpd.workflow_type = p_workflow_type
     AND wpd.optional = false
     AND NOT (wpd.phase_name = ANY(v_enabled_names));
  IF v_missing_required IS NOT NULL THEN
    v_errors := v_errors || jsonb_build_object(
      'code', 'MANDATORY_PHASE_DISABLED',
      'message', format('mandatory phases missing: %s', array_to_string(v_missing_required, ', ')),
      'phases', to_jsonb(v_missing_required)
    );
  END IF;

  RETURN jsonb_build_object('valid', jsonb_array_length(v_errors) = 0, 'errors', v_errors);
END;
$function$
;

CREATE OR REPLACE FUNCTION alerts.acknowledge_alert(p_alert_id uuid, p_user_id uuid)
 RETURNS alerts.alerts
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'alerts', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row alerts.alerts;
BEGIN
  IF p_alert_id IS NULL THEN RAISE EXCEPTION 'acknowledge_alert: id required' USING ERRCODE='22000'; END IF;
  IF p_user_id IS NULL THEN RAISE EXCEPTION 'acknowledge_alert: user_id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM alerts.alerts WHERE id = p_alert_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'acknowledge_alert: % not found', p_alert_id USING ERRCODE='P0002'; END IF;
  IF v_row.status <> 'FIRED' THEN
    RAISE EXCEPTION 'acknowledge_alert: % not in FIRED (got %)', p_alert_id, v_row.status USING ERRCODE='23514'; END IF;
  UPDATE alerts.alerts SET status='ACKNOWLEDGED', acknowledged_at=clock_timestamp(), acknowledged_by=p_user_id
   WHERE id = p_alert_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'SECURITY_ALERT_ACKNOWLEDGED',
    p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_user_id => p_user_id,
    p_reason => format('alert %s acknowledged', p_alert_id),
    p_after_state => jsonb_build_object('alert_id', v_row.id, 'acknowledged_by', p_user_id)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION alerts.resolve_alert(p_alert_id uuid, p_user_id uuid, p_resolution_notes text)
 RETURNS alerts.alerts
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'alerts', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row alerts.alerts;
BEGIN
  IF p_alert_id IS NULL THEN RAISE EXCEPTION 'resolve_alert: id required' USING ERRCODE='22000'; END IF;
  IF p_user_id IS NULL THEN RAISE EXCEPTION 'resolve_alert: user_id required' USING ERRCODE='22000'; END IF;
  IF p_resolution_notes IS NULL OR length(btrim(p_resolution_notes)) = 0 THEN
    RAISE EXCEPTION 'resolve_alert: resolution_notes required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_row FROM alerts.alerts WHERE id = p_alert_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'resolve_alert: % not found', p_alert_id USING ERRCODE='P0002'; END IF;
  IF v_row.status = 'RESOLVED' THEN RAISE EXCEPTION 'resolve_alert: % already RESOLVED', p_alert_id USING ERRCODE='23514'; END IF;
  UPDATE alerts.alerts
     SET status='RESOLVED', resolved_at=clock_timestamp(), resolved_by=p_user_id, resolution_notes=p_resolution_notes
   WHERE id = p_alert_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'USER'::audit.actor_kind_enum, p_action => 'SECURITY_ALERT_RESOLVED',
    p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_user_id => p_user_id,
    p_reason => format('alert %s resolved: %s', p_alert_id, p_resolution_notes),
    p_after_state => jsonb_build_object('alert_id', v_row.id, 'resolved_by', p_user_id, 'resolution_notes', p_resolution_notes)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION alerts.add_rule(p_name text, p_severity alerts.severity_enum, p_dedup_window interval, p_description text, p_evaluator_hint jsonb DEFAULT '{}'::jsonb)
 RETURNS alerts.alert_rules
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'alerts', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row alerts.alert_rules;
BEGIN
  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN RAISE EXCEPTION 'add_rule: name required' USING ERRCODE='22000'; END IF;
  IF p_severity IS NULL THEN RAISE EXCEPTION 'add_rule: severity required' USING ERRCODE='22000'; END IF;
  IF p_dedup_window IS NULL OR p_dedup_window <= '0'::interval THEN
    RAISE EXCEPTION 'add_rule: dedup_window must be > 0' USING ERRCODE='22000'; END IF;
  IF p_description IS NULL OR length(btrim(p_description)) = 0 THEN
    RAISE EXCEPTION 'add_rule: description required' USING ERRCODE='22000'; END IF;

  INSERT INTO alerts.alert_rules (name, severity, dedup_window, description, evaluator_hint, enabled)
  VALUES (p_name, p_severity, p_dedup_window, p_description, COALESCE(p_evaluator_hint, '{}'::jsonb), true)
  RETURNING * INTO v_row;

  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'ALERT_RULE_ADDED',
    p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'alerts.add_rule',
    p_reason => format('alert rule %s added (%s)', p_name, p_severity),
    p_after_state => jsonb_build_object(
      'rule_id', v_row.id, 'name', p_name, 'severity', p_severity,
      'dedup_window_seconds', extract(epoch from p_dedup_window)::int,
      'evaluator_hint', v_row.evaluator_hint
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION alerts.update_rule(p_rule_id uuid, p_severity alerts.severity_enum DEFAULT NULL::alerts.severity_enum, p_dedup_window interval DEFAULT NULL::interval, p_description text DEFAULT NULL::text, p_evaluator_hint jsonb DEFAULT NULL::jsonb)
 RETURNS alerts.alert_rules
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'alerts', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_before alerts.alert_rules; v_row alerts.alert_rules;
BEGIN
  IF p_rule_id IS NULL THEN RAISE EXCEPTION 'update_rule: id required' USING ERRCODE='22000'; END IF;
  SELECT * INTO v_before FROM alerts.alert_rules WHERE id = p_rule_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'update_rule: % not found', p_rule_id USING ERRCODE='P0002'; END IF;
  UPDATE alerts.alert_rules
     SET severity       = COALESCE(p_severity,       severity),
         dedup_window   = COALESCE(p_dedup_window,   dedup_window),
         description    = COALESCE(p_description,    description),
         evaluator_hint = COALESCE(p_evaluator_hint, evaluator_hint),
         updated_at     = clock_timestamp()
   WHERE id = p_rule_id RETURNING * INTO v_row;
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'ALERT_RULE_UPDATED',
    p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'alerts.update_rule',
    p_reason => format('alert rule %s updated', v_row.name),
    p_before_state => jsonb_build_object(
      'severity', v_before.severity, 'dedup_window_seconds', extract(epoch from v_before.dedup_window)::int,
      'description', v_before.description, 'evaluator_hint', v_before.evaluator_hint
    ),
    p_after_state => jsonb_build_object(
      'rule_id', v_row.id, 'name', v_row.name, 'severity', v_row.severity,
      'dedup_window_seconds', extract(epoch from v_row.dedup_window)::int,
      'description', v_row.description, 'evaluator_hint', v_row.evaluator_hint
    )
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.list_workflow_phases(p_workflow_type workflow_type_enum)
 RETURNS SETOF workflow_phase_definitions
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT * FROM public.workflow_phase_definitions
   WHERE workflow_type = p_workflow_type
   ORDER BY phase_order ASC;
$function$
;

CREATE OR REPLACE FUNCTION alerts.disable_rule(p_rule_id uuid)
 RETURNS alerts.alert_rules
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'alerts', 'audit', 'public', 'pg_temp'
AS $function$
DECLARE v_row alerts.alert_rules;
BEGIN
  IF p_rule_id IS NULL THEN RAISE EXCEPTION 'disable_rule: id required' USING ERRCODE='22000'; END IF;
  UPDATE alerts.alert_rules SET enabled=false, updated_at=clock_timestamp()
   WHERE id = p_rule_id RETURNING * INTO v_row;
  IF NOT FOUND THEN RAISE EXCEPTION 'disable_rule: % not found', p_rule_id USING ERRCODE='P0002'; END IF;
  PERFORM audit.emit_audit(
    p_actor_kind => 'SYSTEM'::audit.actor_kind_enum, p_action => 'ALERT_RULE_DISABLED',
    p_subject_type => 'SECURITY_ALERT'::audit.subject_type_enum, p_subject_id => v_row.id,
    p_actor_system => 'alerts.disable_rule',
    p_reason => format('alert rule %s disabled', v_row.name),
    p_after_state => jsonb_build_object('rule_id', v_row.id, 'name', v_row.name, 'enabled', false)
  );
  RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_check_parent_run_finalized()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_parent_status public.workflow_run_status_enum;
BEGIN
  IF NEW.parent_run_id IS NULL THEN RETURN NEW; END IF;
  SELECT status INTO v_parent_status FROM public.workflow_runs WHERE id = NEW.parent_run_id;
  IF v_parent_status IS NULL THEN
    RAISE EXCEPTION 'workflow_runs: parent_run_id % does not exist', NEW.parent_run_id USING ERRCODE='P0002';
  END IF;
  IF v_parent_status <> 'FINALIZED' THEN
    RAISE EXCEPTION 'workflow_runs: parent_run_id % must be FINALIZED (got %)', NEW.parent_run_id, v_parent_status USING ERRCODE='23514';
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_workflow_type(p_workflow_type workflow_type_enum)
 RETURNS workflow_type_definitions
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT * FROM public.workflow_type_definitions WHERE workflow_type = p_workflow_type;
$function$
;

CREATE OR REPLACE FUNCTION public.get_effective_phase_sequence(p_business_id uuid, p_workflow_type workflow_type_enum)
 RETURNS TABLE(phase_order integer, phase_name text, optional boolean)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_enabled_phases jsonb;
BEGIN
  IF p_business_id IS NULL THEN RAISE EXCEPTION 'get_effective_phase_sequence: business_id required' USING ERRCODE='22000'; END IF;
  IF p_workflow_type IS NULL THEN RAISE EXCEPTION 'get_effective_phase_sequence: workflow_type required' USING ERRCODE='22000'; END IF;

  SELECT bwc.enabled_phases INTO v_enabled_phases
    FROM public.business_workflow_config bwc
   WHERE bwc.business_id = p_business_id AND bwc.workflow_type = p_workflow_type;

  IF v_enabled_phases IS NULL THEN
    -- No config row OR enabled_phases is NULL → return all phases
    RETURN QUERY
      SELECT wpd.phase_order, wpd.phase_name, wpd.optional
        FROM public.workflow_phase_definitions wpd
       WHERE wpd.workflow_type = p_workflow_type
       ORDER BY wpd.phase_order ASC;
  ELSE
    -- Return ordered subset that intersects enabled_phases
    RETURN QUERY
      SELECT wpd.phase_order, wpd.phase_name, wpd.optional
        FROM public.workflow_phase_definitions wpd
       WHERE wpd.workflow_type = p_workflow_type
         AND wpd.phase_name = ANY(
           SELECT jsonb_array_elements_text(v_enabled_phases)
         )
       ORDER BY wpd.phase_order ASC;
  END IF;
END;
$function$
;

CREATE TABLE alerts.alert_rules (
  id uuid DEFAULT gen_uuid_v7() NOT NULL,
  name text NOT NULL,
  severity alerts.severity_enum NOT NULL,
  dedup_window interval DEFAULT '00:15:00'::interval NOT NULL,
  enabled boolean DEFAULT true NOT NULL,
  description text NOT NULL,
  evaluator_hint jsonb DEFAULT '{}'::jsonb NOT NULL,
  created_at timestamp with time zone DEFAULT clock_timestamp() NOT NULL,
  updated_at timestamp with time zone DEFAULT clock_timestamp() NOT NULL
);

CREATE TABLE alerts.alerts (
  id uuid DEFAULT gen_uuid_v7() NOT NULL,
  rule_id uuid NOT NULL,
  severity alerts.severity_enum NOT NULL,
  subject_kind alerts.subject_kind_enum NOT NULL,
  subject_id uuid,
  subject_descriptor text,
  payload jsonb DEFAULT '{}'::jsonb NOT NULL,
  status alerts.alert_status_enum DEFAULT 'FIRED'::alerts.alert_status_enum NOT NULL,
  dedup_count integer DEFAULT 1 NOT NULL,
  fired_at timestamp with time zone DEFAULT clock_timestamp() NOT NULL,
  last_fired_at timestamp with time zone DEFAULT clock_timestamp() NOT NULL,
  acknowledged_at timestamp with time zone,
  acknowledged_by uuid,
  resolved_at timestamp with time zone,
  resolved_by uuid,
  resolution_notes text
);

CREATE TABLE archive.archive_runs (
