  business_id uuid NOT NULL,
  workflow_run_id uuid NOT NULL,
  status archive.archive_run_status_enum DEFAULT 'PENDING'::archive.archive_run_status_enum NOT NULL,
  period_start date NOT NULL,
  period_end date NOT NULL,
  manifest_version integer DEFAULT 1 NOT NULL,
  manifest_hash text NOT NULL,
  prev_manifest_hash text NOT NULL,
  manifest_payload jsonb NOT NULL,
  bundle_storage_bucket text,
  bundle_storage_path text,
  started_at timestamp with time zone DEFAULT now() NOT NULL,
  completed_at timestamp with time zone,
  finalized_by_user_id uuid,
  archive_writer text NOT NULL,
  adjustment_of_archive_run_id uuid
);

CREATE TABLE archive.workflow_runs_summary (
  id uuid NOT NULL,
