CREATE OR REPLACE VIEW public.ai_usage_run_totals AS  SELECT workflow_run_id,
    ai_tier,
    count(*) AS call_count,
    (COALESCE(sum(input_tokens), (0)::bigint))::integer AS total_input_tokens,
    (COALESCE(sum(output_tokens), (0)::bigint))::integer AS total_output_tokens,
    COALESCE(sum(compute_seconds), (0)::numeric) AS total_compute_seconds,
    COALESCE(sum(latency_ms), (0)::bigint) AS total_latency_ms,
    COALESCE(sum(cost_estimate), (0)::numeric) AS total_cost_estimate,
    max(cost_estimate_currency) AS currency
   FROM ai_usage_records
  WHERE (workflow_run_id IS NOT NULL)
  GROUP BY workflow_run_id, ai_tier;

CREATE OR REPLACE VIEW public.v_archive_package_latest_manifest AS  SELECT DISTINCT ON (archive_package_id) archive_package_id,
    id AS latest_manifest_id,
    manifest_version_number AS latest_version,
    manifest_hash,
    produced_at,
    produced_by_run_id
   FROM archive_manifests am
  ORDER BY archive_package_id, manifest_version_number DESC;

CREATE OR REPLACE VIEW public.v_blocking_issues AS  SELECT id,
    organization_id,
    business_id,
    workflow_run_id,
    transaction_id,
    document_id,
    match_record_id,
    draft_ledger_entry_id,
    issue_type,
    issue_group,
    severity,
    plain_language_title,
    plain_language_description,
    recommended_action,
    card_payload_json,
    card_content_generated_at,
    card_content_tier_used,
    card_content_fallback_applied,
    status,
    resolution_action,
    resolution_note,
    assigned_to,
    assigned_by,
    assigned_at,
    assignment_notification_sent_at,
    snoozed_at,
    snoozed_by,
    snoozed_until,
    snooze_reason,
    auto_resolution_trigger_issue_id,
    resolved_by,
    resolved_at,
    created_at,
    updated_at,
    invoice_id,
    client_id
   FROM review_issues
  WHERE ((severity = ANY (ARRAY['HIGH'::review_issue_severity_enum, 'BLOCKING'::review_issue_severity_enum])) AND (status = 'OPEN'::review_issue_status_enum));

CREATE OR REPLACE VIEW public.v_ready_to_finalize_runs AS  SELECT id AS workflow_run_id,
    organization_id,
    business_id,
    workflow_type,
    status AS workflow_run_status,
    period_start,
    period_end,
    (NOT (EXISTS ( SELECT 1
           FROM v_blocking_issues bi
          WHERE (bi.workflow_run_id = wr.id)))) AS is_ready_to_finalize,
    ( SELECT (count(*))::integer AS count
           FROM v_blocking_issues bi
          WHERE (bi.workflow_run_id = wr.id)) AS blocking_issue_count
   FROM workflow_runs wr;

CREATE OR REPLACE VIEW public.v_review_issue_card AS  SELECT ri.id,
    ri.organization_id,
    ri.business_id,
    ri.workflow_run_id,
    ri.transaction_id,
    ri.document_id,
    ri.match_record_id,
    ri.draft_ledger_entry_id,
    ri.invoice_id,
    ri.client_id,
    ri.issue_type,
    ri.issue_group,
    ri.severity,
    ri.status,
    ri.plain_language_title,
    ri.plain_language_description,
    ri.recommended_action,
    ri.card_payload_json,
    ri.card_content_generated_at,
    ri.card_content_tier_used,
    ri.card_content_fallback_applied,
    ri.assigned_to,
    ri.assigned_at,
    ri.assigned_by,
    ri.snoozed_at,
    ri.snoozed_until,
    ri.snooze_reason,
    ri.created_at,
    ri.updated_at,
    ri.resolved_at,
    ri.resolved_by,
    ri.resolution_action,
    ri.resolution_note,
    ri.auto_resolution_trigger_issue_id,
    itr.producing_block,
    itr.plain_language_template_ref,
    itr.allowed_resolution_actions,
    itr.default_severity,
    itr.default_group
   FROM (review_issues ri
     LEFT JOIN issue_type_registry itr ON ((itr.issue_type = ri.issue_type)));

CREATE OR REPLACE VIEW public.v_issue_resolution_options AS  SELECT ri.id AS review_issue_id,
    ri.organization_id,
    ri.business_id,
    ri.issue_type,
    ri.issue_group,
    ri.severity,
    ri.status,
    itr.allowed_resolution_actions,
        CASE
            WHEN (ri.severity = 'BLOCKING'::review_issue_severity_enum) THEN array_remove(itr.allowed_resolution_actions, 'IGNORE_WITH_REASON'::text)
            ELSE itr.allowed_resolution_actions
        END AS effective_actions_for_severity
   FROM (review_issues ri
     LEFT JOIN issue_type_registry itr ON ((itr.issue_type = ri.issue_type)))
  WHERE (ri.status = 'OPEN'::review_issue_status_enum);

CREATE OR REPLACE VIEW public.v_invoices_with_adjustments AS  SELECT i.id,
    i.organization_id,
    i.business_id,
    i.client_id,
    i.invoice_type,
    i.invoice_number,
    i.issue_date,
    i.supply_date,
    i.due_date,
    i.currency,
    i.subtotal_amount,
    i.vat_amount,
    i.total_amount,
    i.vat_treatment_per_line,
    i.default_vat_treatment,
    i.lifecycle_status,
    i.lifecycle_status_changed_at,
    i.lifecycle_status_changed_by,
    i.converted_from_pro_forma_id,
    i.converted_to_tax_invoice_id,
    i.pdf_storage_object_id,
    i.pdf_rendered_at,
    i.finalized_in_run_id,
    i.finalized_at,
    i.created_at,
    i.updated_at,
    i.sent_at,
    i.sent_by,
    i.written_off_at,
    i.written_off_by,
    i.written_off_reason,
    i.pro_forma_expires_at,
        CASE
            WHEN (ar.delta_kind = 'MARK_INVOICE_WRITTEN_OFF'::adjustment_delta_kind_enum) THEN 'WRITTEN_OFF'::text
            ELSE (i.lifecycle_status)::text
        END AS adjusted_lifecycle_status,
    ar.run_id AS adjustment_run_id,
    ar.created_at AS adjusted_at
   FROM (invoices i
     LEFT JOIN LATERAL ( SELECT ar2.run_id,
            ar2.delta_kind,
            ar2.created_at
           FROM (adjustment_records ar2
             JOIN workflow_runs wr ON ((wr.id = ar2.run_id)))
          WHERE ((wr.workflow_type = 'IN_ADJUSTMENT'::workflow_type_enum) AND (wr.status = 'FINALIZED'::workflow_run_status_enum) AND (ar2.delta_kind = 'MARK_INVOICE_WRITTEN_OFF'::adjustment_delta_kind_enum) AND (((ar2.delta_payload ->> 'invoice_id'::text))::uuid = i.id))
          ORDER BY ar2.created_at DESC
         LIMIT 1) ar ON (true));

CREATE OR REPLACE VIEW public.v_in_workflow_fixture_coverage AS  SELECT category,
    count(*) AS fixture_count,
    count(*) FILTER (WHERE (workflow_type IS NOT NULL)) AS workflow_fixture_count,
    count(DISTINCT workflow_type) AS distinct_workflow_types,
    count(*) FILTER (WHERE (expected_terminal_state = 'FINALIZED'::workflow_run_status_enum)) AS finalizing_fixture_count
   FROM in_workflow_fixture_registry
  GROUP BY category
  ORDER BY category;

CREATE OR REPLACE VIEW public.v_issue_type_coverage AS  SELECT producing_block,
    count(*) AS issue_type_count,
    count(*) FILTER (WHERE (default_severity = 'BLOCKING'::review_issue_severity_enum)) AS blocking_count,
    count(*) FILTER (WHERE (default_severity = 'HIGH'::review_issue_severity_enum)) AS high_count,
    count(*) FILTER (WHERE (default_severity = 'MEDIUM'::review_issue_severity_enum)) AS medium_count,
    count(*) FILTER (WHERE (default_severity = 'LOW'::review_issue_severity_enum)) AS low_count,
    array_agg(DISTINCT (default_group)::text ORDER BY (default_group)::text) AS distinct_groups
   FROM issue_type_registry
  GROUP BY producing_block
  ORDER BY producing_block;

CREATE OR REPLACE VIEW public.v_bulk_preview_token_status AS  SELECT id,
    organization_id,
    business_id,
    actor_user_id,
    action_kind,
    affected_issue_ids,
    created_at,
    expires_at,
    consumed_at,
    cardinality(affected_issue_ids) AS affected_count,
        CASE
            WHEN (consumed_at IS NOT NULL) THEN 'CONSUMED'::text
            WHEN (expires_at <= clock_timestamp()) THEN 'EXPIRED'::text
            ELSE 'PENDING'::text
        END AS status
   FROM bulk_preview_tokens bpt;

CREATE OR REPLACE VIEW public.v_assignee_inbox AS  SELECT ri.id AS review_issue_id,
    ri.organization_id,
    ri.business_id,
    ri.assigned_to,
    ri.assigned_at,
    ri.assigned_by,
    ri.issue_type,
    ri.issue_group,
    ri.severity,
    ri.status,
    ri.plain_language_title,
    ri.plain_language_description,
    ri.recommended_action,
    ri.created_at,
    ri.updated_at,
    itr.allowed_resolution_actions
   FROM (review_issues ri
     LEFT JOIN issue_type_registry itr ON ((itr.issue_type = ri.issue_type)))
  WHERE ((ri.assigned_to IS NOT NULL) AND (ri.status = 'OPEN'::review_issue_status_enum));

CREATE OR REPLACE VIEW public.v_active_review_queue AS  SELECT ri.id,
    ri.organization_id,
    ri.business_id,
    ri.workflow_run_id,
    ri.issue_type,
    ri.issue_group,
    ri.severity,
    ri.status,
    ri.plain_language_title,
    ri.plain_language_description,
    ri.recommended_action,
    ri.assigned_to,
    ri.assigned_at,
    ri.assigned_by,
    ri.created_at,
    ri.updated_at,
    itr.allowed_resolution_actions
   FROM (review_issues ri
     LEFT JOIN issue_type_registry itr ON ((itr.issue_type = ri.issue_type)))
  WHERE (ri.status = 'OPEN'::review_issue_status_enum);

CREATE OR REPLACE VIEW public.v_snoozed_review_queue AS  SELECT id,
    organization_id,
    business_id,
    workflow_run_id,
    issue_type,
    issue_group,
    severity,
    snoozed_at,
    snoozed_by,
    snooze_reason,
    snoozed_until,
    plain_language_title,
    plain_language_description,
    recommended_action,
    created_at,
    updated_at
   FROM review_issues ri
  WHERE (status = 'SNOOZED'::review_issue_status_enum);

CREATE OR REPLACE VIEW public.v_review_queue_fixture_coverage AS  SELECT category,
    count(*) AS fixture_count,
    ( SELECT array_agg(DISTINCT p.p ORDER BY p.p) AS array_agg
           FROM review_queue_fixture_registry r2,
            LATERAL unnest(r2.covers_phases) p(p)
          WHERE (r2.category = r.category)) AS distinct_phases,
    count(*) FILTER (WHERE ('P02'::text = ANY (covers_phases))) AS covers_p02,
    count(*) FILTER (WHERE ('P03'::text = ANY (covers_phases))) AS covers_p03,
    count(*) FILTER (WHERE ('P04'::text = ANY (covers_phases))) AS covers_p04,
    count(*) FILTER (WHERE ('P05'::text = ANY (covers_phases))) AS covers_p05,
    count(*) FILTER (WHERE ('P06'::text = ANY (covers_phases))) AS covers_p06,
    count(*) FILTER (WHERE ('P07'::text = ANY (covers_phases))) AS covers_p07,
    count(*) FILTER (WHERE ('P08'::text = ANY (covers_phases))) AS covers_p08,
    count(*) FILTER (WHERE ('P09'::text = ANY (covers_phases))) AS covers_p09
   FROM review_queue_fixture_registry r
  GROUP BY category
  ORDER BY category;

CREATE OR REPLACE VIEW public.v_finalization_readiness AS  SELECT id AS workflow_run_id,
    organization_id,
    business_id,
    (workflow_type)::text AS workflow_type,
    period_start,
    period_end,
    (status)::text AS run_status,
    ((gate_finalization_preconditions_satisfied(id) ->> 'decision'::text) = 'ADVANCE'::text) AS is_ready_to_finalize,
    (gate_finalization_preconditions_satisfied(id) ->> 'failing_gate'::text) AS failing_gate
   FROM workflow_runs wr;

CREATE OR REPLACE VIEW public.v_finalization_fixture_coverage AS  SELECT category,
    count(*) AS fixture_count,
    ( SELECT array_agg(DISTINCT p.p ORDER BY p.p) AS array_agg
           FROM finalization_fixture_registry r2,
            LATERAL unnest(r2.covers_phases) p(p)
          WHERE (r2.category = r.category)) AS distinct_phases,
    count(*) FILTER (WHERE ('P01'::text = ANY (covers_phases))) AS covers_p01,
    count(*) FILTER (WHERE ('P02'::text = ANY (covers_phases))) AS covers_p02,
    count(*) FILTER (WHERE ('P03'::text = ANY (covers_phases))) AS covers_p03,
    count(*) FILTER (WHERE ('P04'::text = ANY (covers_phases))) AS covers_p04,
    count(*) FILTER (WHERE ('P05'::text = ANY (covers_phases))) AS covers_p05,
    count(*) FILTER (WHERE ('P06'::text = ANY (covers_phases))) AS covers_p06,
    count(*) FILTER (WHERE ('P07'::text = ANY (covers_phases))) AS covers_p07,
    count(*) FILTER (WHERE ('P08'::text = ANY (covers_phases))) AS covers_p08,
    count(*) FILTER (WHERE ('P09'::text = ANY (covers_phases))) AS covers_p09
   FROM finalization_fixture_registry r
  GROUP BY category
  ORDER BY category;

CREATE OR REPLACE VIEW public.v_dashboard_fixture_coverage AS  SELECT category,
    count(*) AS fixture_count,
    count(*) FILTER (WHERE is_baseline_only) AS baseline_count
   FROM dashboard_fixture_registry
  GROUP BY category
  ORDER BY category;

