CREATE POLICY transactions_select ON archive.transactions AS PERMISSIVE FOR SELECT TO authenticated USING (((organization_id = current_org()) AND (business_id = ANY (current_user_businesses())) AND (EXISTS ( SELECT 1
   FROM (business_user_roles bur
     JOIN users u ON ((u.id = bur.user_id)))
  WHERE ((u.auth_user_id = auth.uid()) AND (bur.business_id = transactions.business_id) AND (bur.status = 'ACTIVE'::account_status) AND (bur.role = ANY (ARRAY['OWNER'::user_role, 'ADMIN'::user_role, 'ACCOUNTANT'::user_role, 'REVIEWER'::user_role, 'READ_ONLY'::user_role, 'BOOKKEEPER'::user_role])))))));

